gameforge.collect_quest_lv94._060_say = "\220dv\246z\246llek! Teh\225t megkaptad a levelem? Remek,[ENTER]akkor tudod, hogy sz\252ks\233gem van a seg\237ts\233gedre a[ENTER]fegyver kutat\225sommal kapcsolatban. Miut\225n \250jra[ENTER]felfedeztem a barlangot, egyre t\246bb igazs\225g[ENTER]der\252lt ki. Most m\225r r\225j\246ttem, hogy a hegyekben[ENTER]\233l\245 l\233nyek m\225sf\233le \233kszereket is csiszolnak a[ENTER]k\245b\245l. "
gameforge.collect_quest_lv94._070_say = "Ezek a gy\246ny\246r\251 B\246lcsess\233g \201kk\246vek - k\252l\246n\246sen[ENTER]tiszta \233s vil\225gos gy\233m\225ntok, amik val\243sz\237n\251leg[ENTER]tartalmazz\225k a meg\246lt Bahar-Taraji istenn\245[ENTER]esszenci\225j\225t. Keress ilyen \233kk\246veket, amikor a[ENTER]barlangban j\225rsz.[ENTER]Sz\252ks\233gem van 20 t\246k\233letes darabra.[ENTER]Sok szerencs\233t, \233s ne v\225rass sok\225ig! "
gameforge.collect_quest_lv94._080_say_title = "\201kk\246vek Seon-Pyeong-nak "
gameforge.collect_quest_lv94._090_say = "A fegyverkov\225cs \233s kutat\243 Seon-Pyeong-nak[ENTER]sz\252ks\233ge van 20 B\246lcsess\233g \233kk\245re a fegyver[ENTER]kutat\225s\225hoz. Vidd el ezeket neki k\252l\246n-k\252l\246n,[ENTER]hogy megvizsg\225lhassa \245ket. Megszerezheted ezeket[ENTER]a k\246veket Setaou \205j\225szokt\243l \233s Setaou[ENTER]Parancsnokokt\243l. "
gameforge.collect_quest_lv94._100_sayReward = "Eddig lesz\225ll\237tott\225l %s \233kk\246vet. "
gameforge.collect_quest_lv94._110_say = "M\233g nem haszn\225lhatod a Kutat\243k Elix\237rj\233t. "
gameforge.collect_quest_lv94._120_say = "M\225r haszn\225lt\225l egy elix\237rt! "
gameforge.collect_quest_lv94._130_say = "Haszn\225lhatod az elix\237rt, amint tal\225lt\225l egy[ENTER]\233kk\246vet. "
gameforge.collect_quest_lv94._140_send_letter = "Megtal\225ltad az \233kk\246vet "
gameforge.collect_quest_lv94._150_npcChat = "B\246lcsess\233g \233kk\245 (94) "
gameforge.collect_quest_lv94._160_say = "Megint te? Sajn\225lom, de m\233g nem fejeztem be az[ENTER]utols\243 \233kk\245 tanulm\225nyoz\225s\225t. Gyere vissza k\233s\245bb! "
gameforge.collect_quest_lv94._170_say = "M\233g nem tal\225lt\225l semmit? Bocsi, de akkor mi\233rt[ENTER]vagy itt? Gyer\252nk, csipkedd magad! Akkor gyere[ENTER]vissza, ha tal\225lt\225l \233kk\246vet! "
gameforge.collect_quest_lv94._180_say = "Tal\225lt\225l egy \233kk\246vet? Csod\225s! V\225rj egy percet,[ENTER]hadd vessem szem\252gyre... "
gameforge.collect_quest_lv94._190_say = "Oh ez egy gy\246ny\246r\251 kavics. \201rzed a melegs\233ged a[ENTER]sz\237vedben? A b\233kess\233get? Ezt mind az \233kk\245[ENTER]teszi... Nagyon k\246sz\246n\246m! "
gameforge.collect_quest_lv94._200_say = "De mint azt m\225r tudod, m\233g sz\252ks\233gem van %s ilyen[ENTER]j\243 min\245s\233g\251 \233kk\245re. Adj nekem egy napot, hogy[ENTER]jobban megvizsg\225ljam ezt a darabot. Majd azt\225n[ENTER]hozhatod nekem a k\246vetkez\245t. "
gameforge.collect_quest_lv94._210_say = "Sok szerencs\233t! "
gameforge.collect_quest_lv94._230_1_select = "\201leter\245 +1100 "
gameforge.collect_quest_lv94._230_2_select = "V\233dekez\233s +140 "
gameforge.collect_quest_lv94._230_3_select = "T\225mad\225s +60 "
gameforge.collect_quest_lv94._240_say = "Hmm... ez egy sz\233p gy\233m\225nt, semmi k\233ts\233g. De nem[ENTER]\250gy t\251nik, mintha isteni aur\225ja lenne. Att\243l[ENTER]tartok, hogy ez nem seg\237t nekem. Hozz egy[ENTER]m\225sikat! \201s ne feledd, id\245re van sz\252ks\233gem, hogy[ENTER]megvizsg\225ljam. "
gameforge.collect_quest_lv94._250_say = "Megcsin\225ltad! 20 b\246lcsess\233g \233kk\245... leny\251g\246z\245![ENTER]De sajnos ez m\233g nem el\233g. Ahhoz, hogy igaz\225n[ENTER]meg\233rtsem ezen gy\233m\225ntok erej\233nek term\233szet\233t,[ENTER]sz\252ks\233gem van egy l\233lekk\245re: a Barlang Nagyur\225nak[ENTER]- Beran-Setaou s\225rk\225nynak a l\233lekk\246v\233re. "
gameforge.collect_quest_lv94._260_send_letter = "Seon-Pyeong k\233r\233se "
gameforge.collect_quest_lv94._270_say_title = "A s\225rk\225ny l\233lekk\246ve "
gameforge.collect_quest_lv94._280_say = "Siker\252lt megszerezned a s\225rk\225ny l\233lekk\246v\233t. Vidd[ENTER]el Seon-Pyeong-nak a Sz\225m\251z\246tt Barlangja[ENTER]bej\225rat\225hoz. "
gameforge.collect_quest_lv94._290_say_title = "A s\225rk\225ny l\233lekk\246ve "
gameforge.collect_quest_lv94._300_say = "Elvitt\233l 20 b\246lcsess\233g \233kk\246vet Seon-Pyeong-nak a[ENTER]Seungryong-v\246lgybe. Most a s\225rk\225ny l\233lekk\246ve kell[ENTER]neki! "
gameforge.collect_quest_lv94._310_say = "Beran-Setaou-t\243l szerezheted meg. "
gameforge.collect_quest_lv94._320_send_letter = "Megszerezted a s\225rk\225ny l\233lekk\246v\233t. "
gameforge.collect_quest_lv94._330_npcChat = "Megszereztem a s\225rk\225ny l\233lekk\246v\233t! "
gameforge.collect_quest_lv94._340_say = "Ez... hihetetlen. A s\225rk\225ny l\233lekk\246ve![ENTER]Meghajlok hatalmass\225god el\245tt! Most m\225r semmi sem[ENTER]\225ll a kutat\225som \250tj\225ba - \233s most rendesen[ENTER]megjutalmazlak. V\225lassz! "
gameforge.collect_quest_lv94._350_say = "Megvan a l\233lekk\245? Mi\233rt nem l\225tom akkor? Ne akarj[ENTER]f\233lrevezetni engem... tudom, hogy neh\233z feladatot[ENTER]adtam, de biztos vagyok benne, hogy megcsin\225lod! "
gameforge.couple_ring = {}
gameforge.couple_ring._100_sendLetter = "Gy\245zd le Jin-Hee-t "
gameforge.couple_ring._10_npcChat = "Bossz\250 a Gy\251r\251keresked\245\233rt "
gameforge.couple_ring._110_sayReward = "Az \214regasszony a seg\237ts\233ged k\233rte: a bar\225tj\225t, a[ENTER]Gy\251r\251keresked\245t meg\246lte a Jin-Hee, a Feh\233r esk\252[ENTER]specialista. Gy\245zz le 30 Jin-Hee-t a[ENTER]Gy\251r\251keresked\245 hal\225l\225nak megbosszul\225sak\233nt! "
gameforge.couple_ring._120_sayReward = "A marad\233k Jin-Hee-k sz\225ma "
gameforge.couple_ring._130_say = "Oh, l\225tom, k\252zd\246tt\233l a Jin-Hee-k ellen. \201s[ENTER]nyilv\225nval\243an nem tudtad legy\245zni mindegyiket.[ENTER]Tudok az erej\252kr\245l \233s a k\233pess\233geikr\245l - ez nem[ENTER]k\246nny\251 munka.  "
gameforge.couple_ring._140_say = "A Gy\251r\251keresked\245 csal\225dja meg akarja bosszulni a[ENTER]hal\225l\225t. Ha egy kis er\245fesz\237t\233ssel enyh\237teni[ENTER]tudod f\225jdalmukat, tedd meg! "
gameforge.couple_ring._150_say = "K\225r, hogy nem akarsz bossz\250t \225llni a[ENTER]Gy\251r\251keresked\245 hal\225l\233rt. De term\233szetesen minden[ENTER]\233let \233rt\233kes, \237gy a saj\225t \233leted is. "
gameforge.couple_ring._160_say = "Amint elfordult, megpillantott\225l valamit az[ENTER]\214regasszony kez\233ben. Egy csillog\243 t\225rgyat -[ENTER]\233rt\233kes k\245 lehetett. "
gameforge.couple_ring._170_select = "\218jra megpr\243b\225lom. "
gameforge.couple_ring._180_say = "Az \233rt\233kes k\246vek nem \233rdekelnek. Azt akarom, hogy[ENTER]a Gy\251r\251keresked\245 hal\225la a csal\225dja b\233k\233j\233\233rt meg[ENTER]legyen bosszulva. J\243, hogy m\233g egyszer[ENTER]\225tgondoltad, \233s teljes\237teni akarod a k\252ldet\233st. "
gameforge.couple_ring._190_say = "Sajn\225lom a Gy\251r\251keresked\245 csal\225dj\225t. K\225r, hogy[ENTER]nem v\225llaltad a kih\237v\225st. "
gameforge.couple_ring._200_sendLetter = "Vissza az \214regasszonyhoz "
gameforge.couple_ring._20_sayTitle = "\214regasszony "
gameforge.couple_ring._210_say = "T\233rj vissza az \214regasszonyhoz \233s \233rtes\237tsd, hogy[ENTER]megbosszultad a Gy\251r\251keresked\245 hal\225l\225t a[ENTER]Jin-Hee-k hal\225la \225ltal. "
gameforge.couple_ring._220_npcChat = "Legy\245zt\233l 30 Jin-Hee-t! "
gameforge.couple_ring._230_say = "Minden Jin-Hee-t legy\245zt\233l. J\243l csin\225ltad! A[ENTER]Gy\251r\251keresked\245 m\225r b\233k\233ben nyugodhat. Itt a[ENTER]gy\251r\251, amit r\225m b\237zott - egy k\252l\246nleges[ENTER]eljegyz\233si gy\251r\251. M\225r a ti\233d. Ez a jutalom[ENTER]hal\225l\225nak bossz\250j\225\233rt.[ENTER]Biztos vagyok benne, hogy \245 is \237gy akarn\225. "
gameforge.couple_ring._240_sayReward = "Eljegyz\233si gy\251r\251t kapt\225l. "
gameforge.couple_ring._250_sayItem = "Eljegyz\233si gy\251r\251 "
gameforge.couple_ring._255_sayItem = "Ez a gy\251r\251 jelk\233pezi a k\246zelg\245 esk\252v\245t. "
gameforge.couple_ring._30_say = "Most te vagy az egyik harcos a faluban.[ENTER]Azt hiszem, tudom, hogyan hasznos\237thatn\225d[ENTER]\250jdons\252lt k\233pess\233geidet. Hallott\225l m\225r a[ENTER]Jin-Hee-r\245l? Ez egy nagyon vesz\233lyes elit[ENTER]harcosokb\243l \225ll\243 csoport. Egyik\252k meg\246lte falunk[ENTER]Gy\251r\251keresked\245j\233t. A keresked\245 nem csak j\243[ENTER]bar\225tom volt, hanem egy nagyon tisztess\233ges ember[ENTER]is, akik \233kszereket \225rult a h\225zasuland\243 fiatal[ENTER]p\225roknak. K\233szen \225llsz megbosszulni a hal\225l\225t?[ENTER]Ennek \233rdek\233ben meg kell \246ln\246d 30 Jin-Hee-t... "
gameforge.couple_ring._40_select = "Megbosszulom a Gy\251r\251keresked\245t. "
gameforge.couple_ring._50_select = "Nem, a Jin-Hee-k t\250l er\245sek nekem. "
gameforge.couple_ring._60_say = "Ez egy nagyon b\246lcs \233s becs\252letes d\246nt\233s! De ne[ENTER]feledd - 30 Jin-Hee-t kell meg\246ln\246d. L\233gy nagyon[ENTER]\243vatos, ravaszak, \233s rendk\237v\252l j\243l el tudnak[ENTER]rejt\245zni! "
gameforge.couple_ring._70_say = "Nos, ez egy sajn\225latos d\246nt\233s, de csak t\245led[ENTER]f\252gg. V\233gt\233re is, a t\250lzott \246nbizalom hal\225los[ENTER]lehet. Vigy\225zz magadra! "
gameforge.couple_ring._75_say = "A marad\233k Jin-Hee-k sz\225ma "
gameforge.couple_ring._80_sayTitle = "Legy\245zt\233l minden Jin-Hee-t. "
gameforge.couple_ring._90_say = "Most m\225r meg lett bosszulva a Gy\251r\251keresked\245[ENTER]hal\225la, befejezted a k\252ldet\233sed. "
