gameforge.dragon_soul._010_sayTitle = "S\225rk\225nyk\245-szil\225nk?! "
gameforge.dragon_soul._020_say = "Kezeidben nyugszik egy k\245darab. Titkokkal telve[ENTER]csillog, \233s \233rzed, amint ereje \225t\225ramlik rajtad.[ENTER]Mif\233le k\245 ez? Vidd el az Alkimist\225nak. \213 tud[ENTER]neked seg\237teni a tov\225bbiakban. "
gameforge.dragon_soul._030_npcChat = "S\225rk\225nyk\245-szil\225nk?! "
gameforge.dragon_soul._040_say = "Az egy S\225rk\225nyk\245 t\246red\233ke - egy \243ri\225si hatalommal[ENTER]b\237r\243, rendk\237v\252l ritka \233s \233rt\233kes krist\225ly r\233sze.[ENTER]Azt mondj\225k, ilyen k\245 a s\225rk\225nyok lelke.[ENTER]Hihetetlen\252l gy\246ny\246r\251![ENTER]\201rzed az erej\233t, ahogy \225t\225ramlik rajtad, amint[ENTER]felveszed \233s tartod?[ENTER]Hozz nekem \246sszesen t\237zet ezekb\245l a[ENTER]S\225rk\225nyk\245-szil\225nkokb\243l. Akkor \225t tudom alak\237tani[ENTER]\245ket egy teljes k\245v\233. "
gameforge.dragon_soul._050_npcChat = "S\225rk\225nyk\245 \225talak\237t\225s "
gameforge.dragon_soul._060_say = "Ne l\233gy ilyen t\252relmetlen. Csak t\237z szil\225nkot[ENTER]tudok \225talak\237tani egy S\225rk\225nyk\245v\233. Folytasd a[ENTER]kutat\225st! "
gameforge.dragon_soul._070_say = "Ah, nagyon j\243! Tal\225lt\225l t\237z S\225rk\225nyk\245-szil\225nkot.[ENTER]K\233rlek, v\225rj egy pillanatot.[ENTER]...[ENTER]K\233sz! Nah\225t, mi ezzel az elj\225r\225ssal egy Cor[ENTER]Draconist \225ll\237tottunk el\245 - egy[ENTER]megkrist\225lyosodott s\225rk\225nysz\237vet, mely beburkolja[ENTER]\233s v\233di a S\225rk\225nyk\246vet.[ENTER]T\246rd fel, hogy megtudd, melyik k\246vet tartalmazza.[ENTER]Az k\246zvetlen\252l a S\225rk\225nyk\245 Alk\237mia t\225rol\243dba fog[ENTER]ker\252lni.[ENTER]Tudtad, hogy a S\225rk\225nyk\246veket tov\225bb lehet[ENTER]finom\237tani? "
gameforge.dragon_soul._080_say = "Szeretn\233l m\225sik Cor Draconis-t? Bah, m\225r[ENTER]meglehet\245sen \246reg vagyok \233s egy ilyen komplex[ENTER]t\225gy elviszi minden er\245met. De megpr\243b\225lom neked.[ENTER]Ugyanakkor legjobb tud\225sommal sem fogok tudni egy[ENTER]nap t\237zn\233l t\246bbet el\245\225ll\237tani. "
gameforge.dragon_soul._090_say = "Ennyi el\233g volt m\225ra. Egyszer\251en nem tudok egy[ENTER]nap t\237zn\233l t\246bbet el\245\225ll\237tani. Er\245m v\233g\233n j\225rok,[ENTER]pihennem kell. Gyere vissza holnap. "
gameforge.dragon_soul._100_npcChat = "Bolt megnyit\225sa "
gameforge.dragon_soul._1010_sendLetter = "A S\225rk\225nyk\245-szil\225nk \233rkez\233se "
gameforge.dragon_soul._1020_say = "Az eg\233sz birodalom legszakavatottabb alkimist\225ja[ENTER]keres. Menj el hozz\225, amilyen gyorsan csak tudsz! "
gameforge.dragon_soul._1030_npcChat = "S\225rk\225nyk\245-szil\225nk?! "
gameforge.dragon_soul._1040_say = "Ah, te ott! Felfedeztem valami eg\233szen[ENTER]figyelemrem\233lt\243t: A S\225rk\225nyk\245 egy szil\225nkj\225t! A[ENTER]S\225rk\225nyk\245 egy rendk\237v\252l ritka \233s \233rt\233kes krist\225ly[ENTER]hatalmas er\245vel. Azt tartj\225k, egyszer ezek egy[ENTER]s\225rk\225ny lelk\233t k\233pezt\233k. Hihetetlen\252l gy\246ny\246r\251![ENTER]Neked adom a S\225rk\225nyszem erej\233t, amivel te is[ENTER]\233rz\233kelheted a szil\225nkokat. Hozz nekem \246sszesen[ENTER]t\237z S\225rk\225nyk\245-szil\225nkot. Akkor k\233pes leszek[ENTER]\225talak\237tani azokat egy teljes k\245v\233. "
