gameforge.dragon_soul._1060_say = "Vigy\233l 10 S\225rk\225nyk\245-szil\225nkot az Alkimist\225nak. "
gameforge.dragon_soul._1070_say = "Ah, nagyon j\243! Tal\225lt\225l t\237z S\225rk\225nyk\245-szil\225nkot.[ENTER]K\233rlek, v\225rj egy pillanatot.[ENTER]...[ENTER]Hihetetlen! Az \225talak\237t\225s eredm\233nyek\233nt egy Cor[ENTER]Draconis j\246tt l\233tre - egy megkrist\225lyosodott[ENTER]s\225rk\225nysz\237v, mely v\233delmez\245en veszi k\246rbe a[ENTER]S\225rk\225nyk\246vet. Amikor felnyitod, a S\225rk\225nyk\245[ENTER]k\246zvetlen\252l a S\225rk\225nyk\245-alk\237mia lelt\225radba ker\252l.[ENTER]Ahhoz, hogy S\225rk\225nyk\245-szil\225nkokat tal\225lj,[ENTER]sz\252ks\233ged lesz a S\225rk\225nyszem erej\233re. \201n tudok[ENTER]egyet adni k\246lcs\246nbe - csak gyere el hozz\225m[ENTER]minden nap, \233s akkor te is k\233pes leszel[ENTER]S\225rk\225nyk\246veket \225talak\237tani! Egyet m\225r[ENTER]megcsin\225ltam neked m\225ra, a marad\233k %d-t pedig te[ENTER]magad is l\233tre tudod hozni. "
