gameforge.energy_system._001_npcChat = "Egy \250j technol\243gia! "
gameforge.energy_system._010_say = "Megcsin\225ltam![ENTER]V\233gre siker\252lt kidolgoznom egy teljesen \250j[ENTER]technol\243gi\225t.[ENTER]Siker\252lt feldolgoznom a t\225rgyakat \233s tiszta[ENTER]energi\225t nyerni ki bel\245l\252k. Ez teljesen[ENTER]zseni\225lis! "
gameforge.energy_system._020_say = "Ha az \233n \250j technol\243gi\225m seg\237ts\233g\233vel semmis\237tesz[ENTER]meg egy t\225rgyat, kapsz egy Energia-t\246red\233ket. Ha[ENTER]egyes\237tesz 30 ilyen t\246red\233ket, kapsz egy[ENTER]er\245teljes Energia-krist\225lyt! Tiszta, sz\251retlen[ENTER]energi\225t egy dr\225gak\245be csomagolva. Ez az energia[ENTER]\225tj\225rja a teljes felszerel\233sed.[ENTER]\201rdekel? "
gameforge.energy_system._030_say = "Hozz nekem olyan felszerel\233si t\225rgyakat, mint[ENTER]fegyverek, \233kszerek \233s ruh\225zat, amiket a[ENTER]vad\225szatod sor\225n tal\225lsz. \193talak\237tom[ENTER]Energia-t\246red\233kk\233.[ENTER]Birodalmunk j\246v\245je \233s rem\233nye van ebben a[ENTER]technol\243gi\225ban. Legy\245zhetetlenek lesz\252nk! "
gameforge.energy_system._035_npcChat = "Energia-t\246red\233k kinyer\233se "
gameforge.energy_system._040_say = "M\251k\246d\246tt? Kapt\225l Energia-t\246red\233keket?[ENTER]Hozz t\246bb t\225rgyat \233s szil\225nkokra z\250zom az alk\237mia[ENTER]seg\237ts\233g\233vel. Technol\243gi\225m m\233g nem teljesen[ENTER]t\246k\233letes. Ez\233rt soha nem tudom garant\225lni,[ENTER]mennyi t\246red\233ket fogsz kapni. "
gameforge.energy_system._050_say = "Egy felt\233tel van: saj\225t szintednek \233s a t\225rgy[ENTER]szintj\233nek is legal\225bb 35-\246snek kell lennie.[ENTER]Hmm, l\225ssuk... "
gameforge.energy_system._060_say = "M\233g nem vagy el\233g er\245s! Gyere vissza, ha m\225r[ENTER]el\233rted legal\225bb a 35-\246s szintet. "
gameforge.energy_system._070_say = "Ah, kit\251n\245! El\233g er\245s \233s tapasztalt vagy![ENTER]Add nekem a t\225rgyat, amit szeretn\233d, hogy[ENTER]feldolgozzak. "
gameforge.energy_system._080_say = "Nem vagy el\233g er\245s, hogy ir\225ny\237tani tudd az[ENTER]Energia-t\246red\233kek belsej\233ben rejl\245 er\245t. Gyere[ENTER]vissza, amikor m\225r el\233rted a minimum 35-\246s[ENTER]szintet. "
gameforge.energy_system._090_say = "Ez a t\225rgy nem felel meg a technol\243gi\225mnak.[ENTER]Hozz valami m\225st. "
gameforge.energy_system._100_say = "Ennek a t\225rgynak nincs el\233g energi\225ja. Hozz nekem[ENTER]egy minimum 35-\246s szint\251t - csak \237gy leszek k\233pes[ENTER]kivonni az energi\225j\225t a technol\243gi\225mmal. "
gameforge.energy_system._110_say = "Megsemmis\237thetem ezt a t\225rgyat? "
gameforge.energy_system._120_select = "Igen "
gameforge.energy_system._130_select = "Nem, m\233g nem! "
gameforge.energy_system._140_say = "Hib\225ztam - sajnos nem siker\252lt Energia-t\246red\233ket[ENTER]kinyernem. K\246vetkez\245 alkalommal tal\225n[ENTER]szerencs\233sebb leszek. "
gameforge.energy_system._150_say = "Csod\225latos! Siker\252lt %d Energia-t\246red\233ket[ENTER]tal\225lnom. Tess\233k. "
gameforge.energy_system._160_npcChat = "Energia-krist\225ly k\233sz\237t\233se "
gameforge.energy_system._170_say = "M\225r felhaszn\225ltad az \246sszes er\245tartal\233kod?[ENTER]Nem kellene olyan kem\233nyen dolgoznod \233s ilyen[ENTER]gondtalanul elpazarolnod az \233leted. Sz\252ks\233gem[ENTER]lesz %d Energia-t\246red\233kre egy Energia-krist\225ly[ENTER]el\245\225ll\237t\225s\225hoz. "
gameforge.energy_system._180_say = "Nincs el\233g Energia-t\246red\233ked.[ENTER]Ebb\245l nem tudok el\245\225ll\237tani Energia-krist\225lyt.[ENTER]Gyere vissza, ha m\225r \246sszegy\251jt\246tt\233l legal\225bb %d[ENTER]t\246red\233ket. "
gameforge.energy_system._190_say = "Nagyon j\243, megszerezted a sz\252ks\233ges %d[ENTER]Energia-t\246red\233ket. Ebb\245l el\245 tudok \225ll\237tani egy[ENTER]Energia-krist\225lyt. K\233rlek, v\225rj egy percet.[ENTER]Megpr\243b\225lom, de nem tudom garant\225lni, hogy[ENTER]m\251k\246dik. "
gameforge.energy_system._200_say = "Minden k\233szen \225ll a t\246red\233kek Energia-krist\225lly\225[ENTER]olvaszt\225s\225hoz. Ugyanakkor nekem is \233lnem kell[ENTER]valamib\245l, \233s az eszk\246zeim nem az \233gb\245l[ENTER]potyognak. K\246lts\233geim fedez\233s\233hez sz\252ks\233gem van[ENTER]%d Yangra. Hajland\243 vagy kifizetni? "
gameforge.energy_system._210_select = "Term\233szetesen. "
gameforge.energy_system._220_select = "K\246sz\246n\246m, most nem. "
gameforge.energy_system._230_say = "Rendben, tiszteletben tartom a d\246nt\233sed.[ENTER]Gyere vissza, ha meggondoltad magad \233s m\233gis[ENTER]sz\252ks\233ged van egy Energia-krist\225lyra. "
gameforge.energy_system._240_say = "Sajn\225lom, el\245bb fizetned kell. Nem vagyok[ENTER]j\243t\233konys\225gi szolg\225lat.[ENTER]Ez csak \252zlet - add \225t a p\233nzt, ut\225na elv\233gzem a[ENTER]munk\225m. "
gameforge.energy_system._250_say = "Itt az Energia-krist\225lyod. De ez csak az els\245[ENTER]sikeres pr\243b\225lkoz\225s volt. Az alk\237mia egy[ENTER]kisz\225m\237thatatlan tudom\225ny - m\225r egy apr\243 hiba is[ENTER]sikertelens\233ghez vezet. Mindig van egy kis es\233ly[ENTER]arra, hogy a k\237s\233rlet meghi\250sulhat. "
gameforge.energy_system._260_say = "Sajnos a k\237s\233rlet nem siker\252lt. Nem tudtam[ENTER]Energia-krist\225lyt el\245\225ll\237tani. A technol\243gi\225m[ENTER]ragyog\243 - de a folyamat teli van kock\225zattal.[ENTER]A dolgok nem mindig m\251k\246dnek a tervek szerint.[ENTER]Biztos vagyok benne, hogy a k\246vetkez\245 alkalommal[ENTER]sikeres leszek! "
gameforge.energy_system._270_say = "Tudtam! Kiv\225l\243 a technol\243gi\225m![ENTER]Itt az Energia-krist\225lyod. K\233ts\233gtelen\252l egy sz\233p[ENTER]p\233ld\225ny! \201rzed az erej\233t? "
