gameforge.fortune_telling = {}
gameforge.fortune_telling._100_sayTitle = "\214regasszony "
gameforge.fortune_telling._10_npcChat = "Hallottam, hogy \214n j\243sn\245. "
gameforge.fortune_telling._110_say = "T\250l fiatal vagy, hogy ilyen nagyokat s\243hajts![ENTER]Szeretn\233l vetni egy pillant\225st a j\246v\245be? Tudnod[ENTER]kell, van n\233mi lehet\245s\233g v\225laszokat kapni a[ENTER]k\233rd\233seidre, hogy \250jra rem\233nykedhess. "
gameforge.fortune_telling._120_select = "J\243solj nekem "
gameforge.fortune_telling._130_select = "Ne j\243solj "
gameforge.fortune_telling._140_say = "\205gy igaz. A legfontosabb az \233letben a saj\225t[ENTER]akarat k\246vet\233se \233s az igyekezet. \201g veled! "
gameforge.fortune_telling._150_select = "Igen, szeretn\233m. "
gameforge.fortune_telling._160_select = "Nem, k\246sz\246n\246m. "
gameforge.fortune_telling._170_say = "Hab\225r rendes vagyok, nem tudok nektek Talizm\225nt[ENTER]aj\225nd\233kozni. Ha a szerencs\233tlens\233get el akarod[ENTER]ker\252lni, fizetned kell nekem \233rte.[ENTER]%s Yangba ker\252l. "
gameforge.fortune_telling._180_say = "M\233gy? Tal\225n igazad van. A szerencs\233tlens\233g \233s[ENTER]f\225jdalom is hozz\225tartozik az \233lethez. Vigy\225zz[ENTER]magadra \233s Isten veled! Ha megv\225ltozik a[ENTER]v\233lem\233nyed, l\225togass meg \250jra. "
gameforge.fortune_telling._20_say = "Az arcodra vetett pillant\225s arr\243l \225rulkodik[ENTER]nekem, nagyon fiatal vagy. Mi\233rt szeretn\233d ilyen[ENTER]kor\225n megtudni a sorsod? Probl\233m\225id vannak? A[ENTER]sorsod nagyon sok mindent tartogat sz\225modra.[ENTER]Gyere vissza k\233s\245bb. "
gameforge.fortune_telling._30_say = "Szeretn\233d \250gy \233lni az \233leted, ahogy a j\243sn\245[ENTER]mondta? A j\243slatokat igaz\225b\243l nem kellene[ENTER]komolyan venned. A t\233nylegesen fontos a[ENTER]viselked\233sed \233s a felfog\225sod. Ha mindkett\245[ENTER]pozit\237v, minden j\243l megy. Ha m\233g mindig szeretn\233l[ENTER]j\243soltatni, gyere vissza holnap. "
gameforge.fortune_telling._40_sayTitle = "\214regasszony "
gameforge.fortune_telling._50_say = "Amint m\225r mondtam, a mai napra sz\243l\243 j\243slatod a[ENTER]k\246vetkez\245: "
gameforge.fortune_telling._60_say = "Szerencs\233tlens\233g fog \233rni, \233s m\233g nem vett\233l[ENTER]talizm\225nt a gonosz t\225vol tart\225s\225ra. Megvenn\233d[ENTER]esetleg az \233n j\243l\233t-talizm\225nomat? "
gameforge.fortune_telling._70_select = "Igen, megveszem. "
gameforge.fortune_telling._80_select = "Nem, k\246sz\246n\246m. "
gameforge.fortune_telling._90_say = "Hab\225r rendes vagyok, m\233gsem adhatom neked ingyen.[ENTER]Ha el akarod ker\252lni a pechet \233s[ENTER]szerencs\233tlens\233get, j\243 \225rat kell fizetned a[ENTER]talizm\225n\233rt. "
