gameforge.ghost_story = {}
gameforge.ghost_story._010_sayTitle = "Egy sura szelleme: "
gameforge.ghost_story._020_npcChat = "Szellem vagy? "
gameforge.ghost_story._030_say = "Nem, a nagyany\225d vagyok... Persze hogy szellem[ENTER]vagyok! Fejre ejtettek gyerekkorodban? "
gameforge.ghost_story._040_npcChat = "Seg\237ts\233g, egy szellem! "
gameforge.ghost_story._050_say = "L\225m n\233zz\233tek, egy b\225tor harcos! Booo!! "
gameforge.ghost_story._060_npcChat = "Ki vagy te? "
gameforge.ghost_story._070_say = "A nevem Akuma. Valamikor nagy harcos voltam,[ENTER]n\233h\225nyan azt mondt\225k a legjobb. M\233g \233n is[ENTER]elhittem! De n\233zz r\225m most. N\233zd mi lett bel\245lem[ENTER]miut\225n megtal\225ltam a barlangot... \233s elvesztem. "
gameforge.ghost_story._080_npcChat = "Ismered ennek a helynek a t\246rt\233net\233t? "
gameforge.ghost_story._090_say = "Oh, akkor tudom, mi t\246rt\233nt. Sok\225ig kutattam,[ENTER]pr\243b\225ltam kital\225lni az okot \233s megtal\225lni a[ENTER]barlangot. A hal\225lom \243ta nagyon sok id\245m volt[ENTER]gondolkodni rajta. Csak k\233rdezz, mit akarsz[ENTER]tudni? "
gameforge.ghost_story._100_npcChat = "Milyen \225tj\225r\243 az? "
gameforge.ghost_story._110_say = "Ez az \225tj\225r\243 a s\246t\233t s\225rk\225ny kamr\225j\225hoz vezet, a[ENTER]bukott Istenhez, Beran-Setaou-hoz. Aktiv\225lhatod a[ENTER]m\225gikus kulccsal, melyet csak Beran-Setaou[ENTER]csapatai kapnak... "
gameforge.ghost_story._120_npcChat = "A h\225rom Isten "
gameforge.ghost_story._130_say = "Egyszer r\233gen h\225rom vall\225sos testv\233r alkotta a[ENTER]l\233t alapjait.[ENTER]Bahar-Taraji, a teremt\233s Istenn\245je volt a[ENTER]legfiatalabb k\246zt\252k. Az \245 feladata volt teremteni[ENTER]\233l\245l\233nyeket - amerre csak j\225rt a vir\225gok[ENTER]kivir\225gzottak \233s \233letek teremt\245dtek. "
gameforge.ghost_story._140_say = "A legid\245sebb testv\233r volt Beran-Setaou. \213 volt az[ENTER]\233let v\233g\233nek \233s a puszt\237t\225snak a felel\245se. Amint[ENTER]egy \233letciklus a v\233g\233hez k\246zeledett,[ENTER]elv\225lasztotta a lelket a testt\245l.[ENTER]\205gy j\246tt l\233tre a sz\252let\233s \233s meghal\225s k\246rforg\225sa[ENTER]- minden \233let alapja. "
gameforge.ghost_story._150_say = "A k\246z\233ps\245 testv\233r Baljit-Elvedin volt. A meg\245rz\233s[ENTER]Istenek\233nt a k\233t testv\233re k\246z\246tt \225llt \233s[ENTER]biztos\237totta az \246r\246k k\246rforg\225st a vil\225gban.[ENTER]P\233ld\225ul \245 volt a felel\245s az \233vszakok[ENTER]v\225ltakoz\225s\225\233rt. "
gameforge.ghost_story._160_npcChat = "A vita "
gameforge.ghost_story._170_say = "Amikor sz\252ks\233g\252k volt r\225, az emberek k\246ny\246r\246gtek[ENTER]az Istenekhez. B\225r sajnos f\233ltek[ENTER]Beran-Setaou-t\243l, nem \233rtett\233k meg, hogy ahogyan[ENTER]l\233tezik s\246t\233t \233s vil\225gos, neki is l\233teznie kell a[ENTER]teremt\233s ellent\233tek\233nt. "
gameforge.ghost_story._180_say = "Hossz\250 ideig az Isten nem vett r\243la tudom\225st, de[ENTER]az \233vek alatt az irigys\233g el\233rte \245t is, ami[ENTER]lassan ut\225latba \233s rosszakaratba ment \225t. El\245sz\246r[ENTER]a haragj\225t az embereken vezette le, h\225bor\250kat \233s[ENTER]betegs\233get adva nekik. B\225r ezzel azt \233rte el,[ENTER]hogy m\233g jobban im\225dkoztak Bahar-Taraji-hoz, az[ENTER]\250jonnan keletkez\245 \233let Istenn\245j\233hez. \201s v\233g\252l ez[ENTER]vezetett a pusztul\225shoz. "
gameforge.ghost_story._190_say = "\201s mivel az Isten haragja egyre intenz\237vebb lett,[ENTER]nem tudta kontroll\225lni m\225r, \233s valami hihetetlen[ENTER]t\246rt\233nt: meg\246lte a testv\233r\233t, a nemzet kedvenc\233t.[ENTER]Ez a tett egy\225ltal\225n nem kiprovok\225lt volt, aznap[ENTER]is ugyanolyan szeretettel \233s bizalommal n\233zett a[ENTER]b\225tyj\225ra, mint addig mindig. \201s \245, belen\233zve sz\233p[ENTER]szemeibe m\233gis elvette az \233let\233t. "
gameforge.ghost_story._200_npcChat = "A k\246vetkezm\233ny "
gameforge.ghost_story._210_say = "Bahar-Taraji hal\225la komoly k\246vetkezm\233nyekkel j\225rt[ENTER]az Istenek vil\225g\225ban \233s az emberek\233ben is: hossz\250[ENTER]\233s kegyetlen t\233l j\246tt, f\246ld\246n-v\237zben meg\246lve[ENTER]l\233nyeket. A f\246ld \250gy megfagyott, hogy a szikl\225k[ENTER]elt\246rtek \233s a legid\245sebb \233s leger\245sebb f\225k sem[ENTER]\233lt\233k t\250l. "
gameforge.ghost_story._220_say = "A fiatal \225llatok \233s emberek meghaltak, \233s mikor[ENTER]kicsit melegebb lett a sz\252let\233sek sz\225ma mindent[ENTER]alulm\250lt. A meggyeng\252lt f\246ld nem termelt el\233g[ENTER]nyersanyagot a popul\225ci\243nak \233s az \250j \233leteknek. A[ENTER]rem\233ny meghalt az \233lettel \233s nagyon hossz\250 id\245[ENTER]kellett a javul\225shoz. "
gameforge.ghost_story._230_say = "M\233g az Istenek is k\237nl\243dtak, az id\245 m\233g lassabban[ENTER]telt nekik, mint a f\246ldieknek.[ENTER]Beran-Setaou visszavonult \233s mag\225nyra v\225gyott.[ENTER]Puszt\237t\243 sajn\225lat \233s m\233ly el\233gedetts\233g lett \250rr\225[ENTER]rajta - am\237g az ut\243bbi meg nem nyerte a csat\225t. A[ENTER]sz\237ve j\233gg\233 v\225lt \233s az elm\250l\225s Istene a j\233g[ENTER]Istene lett, az ut\225lat \233s f\233lelem Istene. "
gameforge.ghost_story._240_npcChat = "A harc "
gameforge.ghost_story._250_say = "Baljit-Elvedin, a meg\245rz\233s Istene sok\225ig[ENTER]b\225nk\243dott a n\245v\233re miatt. Miut\225n a szenved\233s[ENTER]sz\233les karmai laz\237tottak a szor\237t\225son a sz\237ve[ENTER]k\246r\252l, elindult megkeresni a b\225tyj\225t.[ENTER]A b\246lcsess\233g tov\225bbra is domin\225ns volt az[ENTER]\233let\233ben \237gy felismerte, hogy a szomor\250s\225g[ENTER]ellen\233re nem folytat\243dhat az \233let \237gy. "
gameforge.ghost_story._260_say = "K\246vette a b\225tyja nyomait sok-sok \233ven \225t, v\233g\252l[ENTER]megtal\225lta egy j\233gbarlangban, ut\225lat \233s mag\225ny[ENTER]volt ott, messze-messze minden \233l\245l\233nyt\245l.[ENTER]Baljit-Elvedin megtette, amit meg kellett tennie[ENTER]annak ellen\233re, hogy ez m\233g egy sebet t\233pett a[ENTER]sz\237v\233n: kih\237vta b\225tyj\225t egy p\225rbajra.[ENTER]Beran-Setaou olyannyira let\233rt m\225r az igazs\225g[ENTER]\250tj\225r\243l, hogy egy m\225sodpercig sem gondolkodott[ENTER]rajta... "
gameforge.ghost_story._270_say = "A harc sz\246rny\251 volt \233s minden v\225rakoz\225st[ENTER]fel\252lm\250lt. Baljit-Elvedin nyerte meg.[ENTER]\201s h\251en term\233szet\233hez, nem \246lte meg b\225tyj\225t, de[ENTER]elvette az erej\233t \233s a barlangba sz\225m\251zte. \205gy[ENTER]Beran-Setaou ott maradt \233vsz\225zadokon \225t az \225ltala[ENTER]az\243ta kre\225lt teremtm\233nyekkel... "
gameforge.ghost_story._280_npcChat = "Eleget hallottam. "
gameforge.ghost_story._290_say = "Tal\225n a te v\233gzeted k\252l\246nb\246zik az eny\233mt\245l. Sok[ENTER]szerencs\233t! "
gameforge.ghost_story._300_sayTitle = "Egy harcos szelleme: "
gameforge.ghost_story._310_npcChat = "Mi\233rt vagy \225tl\225tsz\243? "
gameforge.ghost_story._320_say = "Mit gondolsz?! \201n egy szellem vagyok \233s csapd\225ba[ENTER]estem ebben a szikl\225ban ezer \233vekre... "
gameforge.ghost_story._330_say = "Seg\237ts\233g, egy szellem! "
gameforge.ghost_story._340_say = "Igen, egy szellem. Fuss el gyorsan, k\252l\246nben[ENTER]megeszlek! "
gameforge.ghost_story._350_npcChat = "Ki vagy te? "
gameforge.ghost_story._360_say = "Egy keresked\245 volt egyszer, egy egyszer\251 ember. A[ENTER]sz\252leim farmerek voltak. Nem akartam ugyanott[ENTER]dolgozni eg\233sz \233letemben \250gyhogy csatlakoztam a[ENTER]hadsereghez. Er\245s \233s v\233reskez\251 voltam, de nem[ENTER]annyira rossz. Azt\225n elegem lett az eg\233szb\245l \233s[ENTER]otthagytam \245ket. Ezut\225n a sors ide vezetett erre[ENTER]a s\246t\233t helyre. "
gameforge.ghost_story._370_npcChat = "Ismered a barlang t\246rt\233net\233t? "
gameforge.ghost_story._380_say = "Nem, nemtudom, azt hiszem nem volt szerencs\233m.[ENTER]Miut\225n dezert\225ltam, a hegyekben akartam elb\250jni[ENTER]\233s belebotlottam ebbe a barlangba. Furcs\225nak t\251nt[ENTER]egy kicsit az elej\233n, de k\233nyelmes volt \233s[ENTER]l\225tsz\243lag teljesen lakatlan. P\225r nappal k\233s\245bb[ENTER]egy hihetetlen harc \225ldozata lettem. Ha[ENTER]szeretn\233d, mes\233lek r\243la. "
gameforge.ghost_story._390_npcChat = "A harc kezdete "
gameforge.ghost_story._400_say = "Egy napon - \233pp gomb\225kat gy\251jt\246ttem a hegyoldalon[ENTER]- egy ez\252st s\225rk\225ny jelent meg a felh\245k k\246z\246tt.[ENTER]Azt hittem, \233rtem j\246tt, de \233szre sem vett - csak[ENTER]a barlang bej\225rat\225ra koncentr\225lt. Lass\237t\225s n\233lk\252l[ENTER]sz\225llt a v\246lgybe \233s be a barlangba. "
gameforge.ghost_story._410_say = "Azt\225n csend lett egy ideig \233s \233n nem tudtam, mit[ENTER]csin\225ljak. Minden felszerel\233sem a barlangban[ENTER]volt, de nem akartam a s\225rk\225nyba botlani! Azt\225n a[ENTER]f\246ld mozogni kezdett \233s \252v\246lt\233sek hallatszottak a[ENTER]barlangb\243l. De nem egy, hanem kett\245! R\246viddel[ENTER]ezut\225n k\233t s\225rk\225ny rep\252lt ki a barlangb\243l - az[ENTER]ez\252st\246t k\246vette egy k\233k. "
gameforge.ghost_story._420_say = "Egy szinte le\237rhatatlan harc kezd\245d\246tt a k\233t[ENTER]s\225rk\225ny k\246z\246tt. Egym\225s test\233nek rep\252ltek,[ENTER]hatalmas fogaikat egym\225sba m\233lyesztett\233k...[ENTER]v\233res\245 hullott... de egyik sem engedett a[ENTER]szor\237t\225sb\243l egy m\225sodpercre sem. "
gameforge.ghost_story._430_npcChat = "A harc v\233ge "
gameforge.ghost_story._440_say = "Mindk\233t s\225rk\225ny v\233gigs\246p\246rt a hegyeken ak\225r egy[ENTER]vihar, k\225oszt hagyva maguk m\246g\246tt. Vill\225m \233gette[ENTER]a k\233k sz\225j\225t, jeges vill\225m az ez\252st sz\225rny\225t. A[ENTER]v\233kony j\233gr\233teg \233vekig bor\237totta a f\246ldet azon a[ENTER]helyen. \201n egy szikla m\246g\233 b\250jtam, megdermedtem. "
gameforge.ghost_story._450_say = "\211r\225kig tartott, mire az er\245k cs\246kkenni kezdtek[ENTER]Azt\225n l\225ttam egy es\233lyt hogy elhagyjam a helyet,[ENTER]elkezdtem rohanni a felszerel\233sem\233rt a barlangba.[ENTER]\201s akkor \233rt el a v\233gzetem. M\225r kifel\233 tartottam[ENTER]a cuccaimmal, mikor mindk\233t s\225rk\225ny megjelent. A[ENTER]k\233k \243ri\225si sebet kapott. "
gameforge.ghost_story._460_say = "Miel\245tt elt\251nt volna a barlangban, az ez\252st[ENTER]s\225rk\225ny elkapta \233s valami nagyon furcsa t\246rt\233nt:[ENTER]az \233g villogni kezdett, nagyon s\246t\233t lett \233s egy[ENTER]energia\246rv\233ny csapd\225ba ejtette a k\233k s\225rk\225nyt.[ENTER]Ord\237tani kezdett... azt\225n cs\246ndesedett \233s a[ENTER]v\233g\233re teljesen elcsendesedett, elvesztette a[ENTER]ragyog\225s\225t \233s sz\237ntelenn\233 v\225lt... "
gameforge.ghost_story._470_say = "A v\233g\233n az ez\252st s\225rk\225ny elengedte a m\225sikat a[ENTER]barlangba. Az utols\243 erej\233vel a vesztes[ENTER]megragadta az ez\252st\246t \233s ber\225ntotta a hegy al\225.[ENTER]\193m az kiszabadult, \233s egy er\245s m\225gikus vihart[ENTER]kavart, amely lez\225rta a barlangot \233s[ENTER]beomlasztotta a hegy egy r\233sz\233t. A s\246t\233t s\225rk\225ny[ENTER]\233s \233n csapd\225ba est\252nk. Ezzel \233hhal\225lra \237t\233lve[ENTER]minket... "
gameforge.ghost_story._480_npcChat = "Eleget hallottam. "
gameforge.ghost_story._490_say = "K\246sz\246n\246m hogy meghallgatt\225l. Az utols\243 ezer \233vben[ENTER]nagyon mag\225nyos voltam... "
gameforge.goldbar = {}
gameforge.goldbar._100_say = "Miel\245tt megmenek\252ltem a Fekete Sz\233l Band\225t\243l,[ENTER]megtal\225ltam, hol rejtegetik az aranyukat. Egy[ENTER]eg\233sz halom aranyr\250djuk van! Ezek az \245r\252ltek[ENTER]\233szre sem venn\233k, ha elt\251nne egy. Ha megfizetsz,[ENTER]odamegyek \233s hozok neked aranyrudat. Egyszerre[ENTER]azonban csak egyet tudok elhozni. "
gameforge.goldbar._104_say = "Id\245 "
gameforge.goldbar._108_say = "Perc(ek) "
gameforge.goldbar._10_npcChat = "A Feketesz\233l banda \225ldozata "
gameforge.goldbar._110_say = "K\246r\252lbel\252l %s %s-ig tart egy aranyrudat elhozni. "
gameforge.goldbar._120_say = "Mondd meg, ha \233rdekel. "
gameforge.goldbar._130_say = "T\233nyleg? Akkor \252zletel\252nk? Csak mondanod kell \233s[ENTER]\233n hozok neked egyet! "
gameforge.goldbar._140_npcChat = "Szeretn\233k venni egy Aranyrudat. "
gameforge.goldbar._150_say = "Mir\245l besz\233lsz? Err\245l nem tudok semmit. "
gameforge.goldbar._160_say = "Micsoda? Aranyrudat akarsz venni? Nem, most nem.[ENTER]A Feketesz\233l bizalmatlannak t\251nik.[ENTER]A fejemet kock\225ztatom, ha nem vigy\225zok. \218jra meg[ENTER]fogjuk pr\243b\225lni, ha megnyugodott a helyzet. "
gameforge.goldbar._170_sayReward = "Nem vehetsz most aranyrudat. "
gameforge.goldbar._180_say = "Nem voltam m\233g olyan helyzetben, hogy tudjak[ENTER]aranyrudat hozni. "
gameforge.goldbar._190_say = "K\246r\252lbel\252l %s %s-t kell v\225rnunk. "
gameforge.goldbar._200_say = "Hoztam magammal egy Aranyrudat. 2,2 milli\243 Yangba[ENTER]ker\252l, 200.000 Yang az \233n fizets\233gem. Hogy[ENTER]tetszik? \201rdekel az aj\225nlat? "
gameforge.goldbar._20_sayTitle = "\193rul\243 Balso: "
gameforge.goldbar._210_say = "Tess\233k, egy Aranyr\250d! B\246lcs d\246nt\233st hozt\225l.[ENTER]Mindig j\243 d\246nt\233s a befektet\233s. "
gameforge.goldbar._220_say = "Nincs el\233g Yangod! 2,2 milli\243 Yangba ker\252l. "
gameforge.goldbar._230_say = "Minek vagy itt, ha nem akarsz venni semmit? Csak[ENTER]az id\245met rabolod. "
gameforge.goldbar._240_npcChat = "GM: Aranyr\250d elad\225si id\245t vissza\225ll\237tani "
gameforge.goldbar._250_say = "Az aranyr\250d elad\225si id\245 vissza\225llt. "
gameforge.goldbar._260_npcChat = "Eladni egy Aranyrudat "
gameforge.goldbar._270_say = "Mir\245l besz\233lsz? Err\245l nem tudok semmit. "
gameforge.goldbar._280_say = "Mi? El akarod adni az aranyrudat? Nem hallottad?[ENTER]A Feketesz\233l harcosok nagyon gyanakv\243k mostan\225ban[ENTER]\233s nyitva tartj\225k a szem\252ket. Ha most eladod az[ENTER]aranyrudat, nagy bajba ker\252lsz. Legjobb lenne, ha[ENTER]ott hagyn\225d, ahol van. Rejtsd el j\243l! "
gameforge.goldbar._290_sayReward = "Most nem eladhatsz el aranyrudat. "
gameforge.goldbar._300_say = "Ha vissza akarod hozni az aranyrudat, "
gameforge.goldbar._30_say = "Mi? A Feketesz\233l banda \225ldozata? Hahaha! Gyerek[ENTER]vagy m\233g. Hol hallottad ezt? Ink\225bb menj \233s[ENTER]j\225tssz a vadkuty\225kkal! "
gameforge.goldbar._310_say = "kb. %s %s-t kell v\225rnod. "
gameforge.goldbar._320_say = "Nincs Aranyrudad. Ha hozol nekem Aranyrudat,[ENTER]Yangot adok neked \233rte. "
gameforge.goldbar._330_say = "Mi? Vissza akarod adni az aranyrudadat? Mi\233rt[ENTER]vetted meg egy\225ltal\225n? Ha mindenk\233ppen vissza[ENTER]akarod adni, nem \225llhatok ellen. A Fekete Sz\233l[ENTER]banda nagyon j\243l \245rzi kincseit; sz\243val nem tudom[ENTER]t\250l gyakran megtenni. M\233g mindig vissza akarod[ENTER]adni? "
gameforge.goldbar._340_select = "Visszaadni "
gameforge.goldbar._350_select = "Nem adni vissza "
gameforge.goldbar._360_say = "Itt a Yangod! Fen\233be! Most vissza kell adnom! "
gameforge.goldbar._370_say = "Van egy\225ltal\225n Aranyrudad? Nagyon elfoglalt[ENTER]vagyok![ENTER]Sz\243val ne gyere ide, ha nem akarsz \252zletelni! "
gameforge.goldbar._40_sayReward = "A 'Feketesz\233l banda \225ldozata' feladat csak a[ENTER]legal\225bb 30-as szinten \225ll\243 karaktereknek[ENTER]lehets\233ges. "
gameforge.goldbar._50_say = "L\233gy \243vatos! A Feketesz\233l banda harcosai[ENTER]bizalmatlanok. A legjobb, ha abszol\250t nyugodtan[ENTER]viselkedik az ember. Isten veled! "
gameforge.goldbar._60_sayReward = "A 'Feketesz\233l banda \225ldozata' feladat[ENTER]pillanatnyilag nem el\233rhet\245. "
gameforge.goldbar._70_say = "Pszt! Valahol elb\250jhatott n\233h\225ny Feketesz\233l[ENTER]bandatag. Hol hallott\225l err\245l?[ENTER]Nem, m\225r rendben van. Nem olyan fontos. Tudod[ENTER]m\225r, hogy mi a helyzet? "
gameforge.goldbar._80_select = "Nem, nem igaz\225n. "
gameforge.goldbar._90_select = "Igen, mindent tudok. "
