gameforge.guild_building_npc._10_sayTitle = "Fegyverkov\225cs: "
gameforge.guild_building_npc._20_say = "Oh, a c\233hem tagja vagy! Ha fejleszteni szeretn\233d[ENTER]a fegyvered, nekem hozd el, \233s ne azoknak a[ENTER]tanul\243knak a faluban. Az \233n sikeress\233gi r\225t\225m[ENTER]10%-kal magasabb. A c\233hem tagjai 5% kedvezm\233nyt[ENTER]is kapnak. Most add ide a fegyvert, amit[ENTER]szeretn\233l, hogy fejlesszek, \233s megcsin\225lom. "
gameforge.guild_building_npc._30_say = "A nevem Stanley, \233n vagyok a felel\245s a fegyverek[ENTER]jav\237t\225s\225\233rt. Sokkal jobb vagyok, mint a falusi[ENTER]kov\225cs! Ha hozz\225m j\246ssz, a siker \233rt\233kedet[ENTER]10%-kal n\246velheted. Add nekem a fegyvereket,[ENTER]amiket jav\237tani kell. "
gameforge.guild_building_npc._40_sayTitle = "Fegyverkov\225cs: "
gameforge.guild_building_npc._50_say = "Oh, a c\233hem tagja vagy! Ha fejleszteni szeretn\233d[ENTER]a v\233rted, pajzsod, cip\245d vagy sisakod, nekem hozd[ENTER]el. Az \233n sikeress\233gi r\225t\225m 10%-kal magasabb,[ENTER]mint a falusi kov\225csnak! A c\233hem tagjai 5%[ENTER]kedvezm\233nyt is kapnak. Most add ide a[ENTER]felszerel\233si t\225rgyat, amit fejleszteni szeretn\233l. "
