gameforge.heavens_cave_keyquest = {}
gameforge.heavens_cave_keyquest._010_target = "Seon-Hae "
gameforge.heavens_cave_keyquest._020_npcChat = "A Barlangban "
gameforge.heavens_cave_keyquest._030_say = "J\243l figyelj r\225m, fi\250! Csak egyszer mondom el ezt[ENTER]a t\246rt\233netet... "
gameforge.heavens_cave_keyquest._040_say = "L\233gy figyelmes, le\225nyz\243! Csak egyszer mondom el[ENTER]ezt a t\246rt\233netet... "
gameforge.heavens_cave_keyquest._050_say = "Napjainkban csak egy istent, a S\225rk\225ny istent[ENTER]ismer\252nk, de r\233gen, h\225rom istens\233g vigy\225zott[ENTER]r\225nk. Viszont Bahar-Taraji-t, a Teremt\233s[ENTER]Istenn\245j\233t meggyilkolta az \245 f\233lt\233keny testv\233re,[ENTER]Beran-Setaou. A harmadik istens\233g,[ENTER]Baljit-Elvedin, akit ma S\225rk\225nyistenk\233nt[ENTER]ismer\252nk, m\233lyen gy\225szolja a meggyilkolt n\245v\233r\233t. "
gameforge.heavens_cave_keyquest._060_say = "Egy harc t\246rt ki a k\233t testv\233r k\246z\246tt, amit a[ENTER]S\225rk\225nyisten nyert meg. A sz\243besz\233d szerint a[ENTER]csata nyomai ma is megtal\225lhat\243ak a harc volt[ENTER]helysz\237n\233n. Beran-Setaou el lett z\225rva egy[ENTER]barlangba a veres\233ge ut\225n, ami k\233s\245bb a Sz\225m\251z\246tt[ENTER]Barlangjak\233nt lett ismert. "
gameforge.heavens_cave_keyquest._070_say = "A barlang el van z\225rva \233s a Baljit-Elvedin rend[ENTER]tagjai v\233dik. \193t kell nekik adnod egy V\233rk\246vet,[ENTER]hogy beengedjenek. Tudom, hogyan lehet ilyen[ENTER]k\246veket csin\225lni, de nem k\246nny\251. "
gameforge.heavens_cave_keyquest._080_say = "Minden azokkal a k\246nnyekkel kezd\245d\246tt, amiket a[ENTER]S\225rk\225nyisten hullajtott a n\245v\233re miatt, amik[ENTER]azt\225n k\246vekk\233 v\225ltak \233s a f\246ldre estek. Most is[ENTER]tal\225lhatsz bel\245l\252k a Doyyumhwan T\251zf\246ldj\233n. Szedj[ENTER]\246ssze ezekb\245l hetet \233s n\233gy darab Obszidi\225nt a[ENTER]L\225ngokb\243l, amik azon a t\225jon \233lnek, \233s hozd el[ENTER]\245ket ide. "
gameforge.heavens_cave_keyquest._090_say_reward = "Gy\251jts \246ssze 7 Fossziliz\225l\243dott K\246nnyet \233s 4[ENTER]darab Obszidi\225nt Doyyumhwan-ban. "
gameforge.heavens_cave_keyquest._100_say = "V\233rk\245re van sz\252ks\233ged hogy \225tjuss a Rend \213rein?[ENTER]Akkor gy\251jts \246ssze \250jabb h\233t k\246nnycseppet \233s n\233gy[ENTER]darab Obszidi\225n darabot a Doyyumhwan T\251zf\246ldr\245l. "
gameforge.heavens_cave_keyquest._110_say = "Sz\252ks\233ged van m\233g egy V\233rk\245re? Koe-Pung nem a[ENTER]legokosabb, de v\225rnod k\233ne egy kicsit, k\252l\246nben[ENTER]\233szreveheti, hogy nem tartozol a rendj\233be. "
gameforge.heavens_cave_keyquest._120_say = "N\233h\225ny \243ra, azt mondan\225m: %s "
gameforge.heavens_cave_keyquest._130_say = "Egy \243ra \233s %s perc. "
gameforge.heavens_cave_keyquest._140_say = "V\225rj m\233g %s percet. "
gameforge.heavens_cave_keyquest._150_say_title = "Fossziliz\225l\243dott K\246nny "
gameforge.heavens_cave_keyquest._160_say = "Itt van egy a S\225rk\225nyisten Fossziliz\225l\243dott[ENTER]K\246nnyeib\245l, amik a f\246ldre estek. "
gameforge.heavens_cave_keyquest._170_1_select = "Vedd el a k\246nnyet "
gameforge.heavens_cave_keyquest._170_2_select = "Folytasd a k\246nnyek keres\233s\233t itt "
gameforge.heavens_cave_keyquest._170_3_select = "Ne csin\225lj semmit "
gameforge.heavens_cave_keyquest._180_say = "Kapt\225l egy Fossziliz\225l\243dott K\246nnyet. "
gameforge.heavens_cave_keyquest._190_say_title = "Fossziliz\225l\243dott K\246nny "
gameforge.heavens_cave_keyquest._200_say = "\218gy d\246ntesz, hogy pr\243b\225lsz m\233g keresni k\246nnyeket[ENTER]\233s a k\246vetkez\245t tal\225lod: %s "
gameforge.heavens_cave_keyquest._210_say = "A ter\252leten l\233v\245 l\233nyek most m\225r figyelnek r\225d! "
gameforge.heavens_cave_keyquest._220_say = "Menj a Doyyumhwan T\251zf\246ldjeire \233s keresd[ENTER]Baljit-Elvedin, a S\225rk\225nyisten Fossziliz\225l\243dott[ENTER]K\246nnyeit. Tov\225bb\225 keresned k\233ne Obszidi\225nt is a[ENTER]L\225ngok le\246l\233s\233vel. "
gameforge.heavens_cave_keyquest._230_say = "Ennyi Fossziliz\225l\243dott K\246nny kell m\233g: %s "
gameforge.heavens_cave_keyquest._240_say = "Obszidi\225n sz\252ks\233ges: %s "
gameforge.heavens_cave_keyquest._250_notice = "El\233g k\246nnyet szerezt\233l m\225r be. "
gameforge.heavens_cave_keyquest._260_notice = "Obszidi\225nt tal\225lt\225l emellett a l\225ng mellett! "
gameforge.heavens_cave_keyquest._270_notice = "\214sszegy\251jt\246tted az \246sszes sz\252ks\233ges Obszidi\225nt! "
gameforge.heavens_cave_keyquest._280_say = "Menj vissza Seon-Hae-hez a k\246nnyekkel \233s az[ENTER]Obszidi\225nnal. "
gameforge.heavens_cave_keyquest._290_say = "Seon-Hae itt van: %s "
gameforge.heavens_cave_keyquest._300_say = "Baljit-Elvedin k\246nnyei! Visszav\225ltoztatom \245ket[ENTER]foly\233kony form\225jukba \233s belerakom \245ket az[ENTER]Obszidi\225nba. Az erej\252k lehet\245v\233 teszi, hogy h\237vd[ENTER]Bahar-Taraji istenn\245t! "
gameforge.heavens_cave_keyquest._310_say = "A lelke m\233g mindig a f\246ldet j\225rja. A hangja[ENTER]sz\243lni fog hozz\225d ha magaddal viszed a k\246nnyeket.[ENTER]Keresd \245t Lungsam V\246r\246s Erdej\233ben! "
gameforge.heavens_cave_keyquest._320_say = "Tess\233k, vidd ezt a v\225z\225t magaddal \233s keresd[ENTER]Bahar-Taraji hangj\225t. "
gameforge.heavens_cave_keyquest._330_say = "Keresd Bahar-Taraji hangj\225t Lungsam V\246r\246s[ENTER]erdej\233nek ter\252let\233n. M\233g ha nem is l\225tod az[ENTER]istenn\245 szellem\233t, \233rezni fogod a jelenl\233t\233t. "
gameforge.heavens_cave_keyquest._335_say = "Egy cs\246ndes hang suttog a sz\233lben: Menj egy[ENTER]biztons\225gos helyre... Itt nem besz\233lhet\252nk...[ENTER]Kattints a k\252ldet\233stekercsre, hogy besz\233lhess a[ENTER]szellemmel. "
gameforge.heavens_cave_keyquest._340_say = "A messzes\233gb\245l hallatszik a meggyilkolt istenn\245,[ENTER]Bahar-Taraji hangja... "
gameforge.heavens_cave_keyquest._350_say = "A testv\233rem k\246nnyei... olyan hosszan gy\225szolt[ENTER]engem, \233s m\233gsem tudta megb\252ntetni Beran-Setaou-t[ENTER]a tett\233\233rt. "
gameforge.heavens_cave_keyquest._360_say = "Nem tudott szembesz\225llni a testv\233r\233vel,[ENTER]Beran-Setaouval, a puszt\237t\243val, akit\245l mindenki[ENTER]f\233l. "
gameforge.heavens_cave_keyquest._370_say = "De te... Ki vagy te? Te m\225s vagy![ENTER]Te nem f\233lsz t\245le. \201pp ellenkez\245leg, azt l\225tom,[ENTER]hogy te a harcot keresed. "
gameforge.heavens_cave_keyquest._380_say = "%s! Vidd el a v\233rem n\233h\225ny cseppj\233t. Hozz l\233tre[ENTER]egy V\233rk\246vet \233s b\252ntesd meg Beran-Setaou-t a[ENTER]tett\233\233rt. A Sz\225m\251z\246tt Barlangja nincs messze[ENTER]innen. "
gameforge.heavens_cave_keyquest._390_say = "A messzes\233gb\245l hallatszik a meggyilkolt istenn\245,[ENTER]Bahar-Taraji hangja... "
gameforge.heavens_cave_keyquest._400_say = "%s! Felismerlek t\233ged! "
gameforge.heavens_cave_keyquest._410_say = "Hozt\225l nekem a testv\233rem k\246nnyeib\245l, hogy[ENTER]vigasztalj. Cser\233be kapsz n\233h\225ny cseppet a[ENTER]v\233remb\245l, hogy folytathasd a harcot. "
gameforge.heavens_cave_keyquest._420_say = "Menj vissza Seon-Hae-hez Bahar-Taraji v\233r\233vel. "
gameforge.heavens_cave_keyquest._430_say = "Seon-Hae szemei k\246nnyezni kezdenek, ahogy \225tveszi[ENTER]t\245led a v\233rcseppeket... "
gameforge.heavens_cave_keyquest._440_say = "Egy igazi istenn\245 v\233re! Gyorsan, hadd csin\225lok[ENTER]bel\245le egy V\233rk\246vet miel\245tt felsz\225rad. "
gameforge.heavens_cave_keyquest._450_say = "Az \245r Koe-Pung megengedi, hogy haszn\225ld a[ENTER]port\225lt, ami a Sz\225m\251z\246tt Barlangj\225ba vezet, ha[ENTER]van n\225lad egy V\233rk\245. De ez csak egyszer fog[ENTER]m\251k\246dni. Ha sz\252ks\233ged van m\233g V\233rk\245re, gyere[ENTER]vissza hozz\225m. Sajnos egy nap csak egy V\233rk\246vet[ENTER]tudok l\233trehozni, hogy ne kelts\252k fel a Rend[ENTER]\233rdekl\245d\233s\233t. "
gameforge.heavens_cave_keyquest._460_say_reward = "Seon-Hae t\246bb V\233rk\246vet is tud k\233sz\237teni neked, de[ENTER]egy napon csak egyet. "
gameforge.heavens_cave_keyquest._470_say = "\193tv\225ltoztatom Bahar-Taraji v\233r\233t egy V\233rk\245v\233.[ENTER]Vedd j\243 haszn\225t neki. "
gameforge.heavens_cave_keyquest._480_say_reward = "Egy nap csak egy v\233rk\246vet k\233sz\237thetek neked.[ENTER]M\225sk\233ppen Koe-Pung gyanakodni kezdene. "
