gameforge.horse_guard._30_say = "3 szint\251 l\243 van a lovasok sz\225m\225ra: kezd\245, k\246zepes[ENTER]\233s profi.[ENTER]Ha eleget gyakorolt\225l, \233s szeretn\233l a k\246vetkez\245[ENTER]szintre l\233pni, le kell tenned egy vizsg\225t. "
gameforge.horse_guard._40_say = "A lovaknak fejletts\233gi szakaszukt\243l f\252gg\245en,[ENTER]k\252l\246nb\246z\245 abrakra van sz\252ks\233g\252k. A kezd\245 lovak[ENTER]Sz\233n\225t, a k\246zepesek R\233p\225t, a profik kiz\225r\243lag[ENTER]V\246r\246s ginzenget esznek.[ENTER]Ha \233telr\245l van sz\243, a lovak meglehet\245sen[ENTER]v\225logat\243sak. "
gameforge.horse_guard._50_say = "Ha a l\243 eg\233szs\233ges, z\246ldk\233nt jelenik meg, ha[ENTER]\233hes, akkor s\225rgak\233nt, ha alult\225pl\225lt, akkor[ENTER]pirosk\233nt. Etetned kell, hogy a s\225rg\225b\243l, vagy[ENTER]pirosb\243l z\246ld tartom\225nyba ker\252lj\246n. Ez egy komoly[ENTER]dolog, mikor megd\246glik a lovad. "
gameforge.horse_guard._60_say = "Mialatt lovagolsz, lassan cs\246kken az eg\233szs\233ge \233s[ENTER]kimer\252ltt\233 v\225lik. Nem lovagolhatsz beteg lovon.[ENTER]Ez\233rt n\233ha pihentetned kell. "
gameforge.horse_guard._70_say = "\218gy h\237rlik, egy d\246gl\246tt l\243 Majomn\246v\233nnyel[ENTER]felt\225maszthat\243. Ezt a n\246v\233nyt azonban nagyon[ENTER]v\233dik a majmok \233s ez\233rt nagyon neh\233z hozz\225jutni.[ENTER]Ez azt jelenti, hogy ha elfognak a majmok, akkor[ENTER]meg\225tkoznak \233s majomm\225 v\225ltoztatnak. "
gameforge.horse_guard._80_say = "K\252l\246nb\246z\245 lovagl\243 k\233szs\233gek l\233teznek. Ha van egy[ENTER]L\243 med\225lod, fejleszteni tudod a h\225tasod szintj\233t. "
