gameforge.horse_upgrade2._340_sayReward = "Menj a Lov\225szinashoz, \233s hozd el a Katonai l\243[ENTER]k\246nyvet. Ehhez sz\252ks\233ged van a Felfegyverzett l\243[ENTER]k\246nyvre \233s 1.000.000 Yangra. "
gameforge.horse_upgrade2._350_npcChat = "Szeretn\233m megkapni a Katonai l\243 k\246nyvet. "
gameforge.horse_upgrade2._360_say = "Ha meg van a Katonai l\243 k\246nyv, a lovad k\233pes lesz[ENTER]k\252l\246nb\246z\245 harci st\237lusok alkalmaz\225s\225ra.[ENTER]Egy ehhez hasonl\243 k\246nyv nagyon ritka, \233s nem is[ENTER]valami olcs\243. 1.000.000 Yangra van sz\252ks\233ged[ENTER]egyetlen p\233ld\225ny megv\225s\225rl\225s\225hoz.[ENTER]Val\243ban fejleszteni akarod a lovad? "
gameforge.horse_upgrade2._370_select = "L\243 fejleszt\233se "
gameforge.horse_upgrade2._380_select = "Ne fejleszd a lovat "
gameforge.horse_upgrade2._385_select = "Oh, mindegy. Felejtsd el! "
gameforge.horse_upgrade2._390_say = "Ha meg van a Katonai l\243 k\246nyv, b\225rmikor h\237vhatod[ENTER]a lovad, \233s j\246nni fog. Sz\243val j\243l vigy\225zz r\225![ENTER]Ezek az alapok; innent\245l kezdve csak rajtad[ENTER]m\250lik. "
gameforge.horse_upgrade2._400_say = "Sz\252ks\233ged van a Felfegyverzett l\243 k\246nyvre, hogy[ENTER]megkapd a Katonai l\243 k\246nyvet. "
gameforge.horse_upgrade2._40_say = "A lovad szintje t\250l alacsony a fejleszt\233shez.[ENTER]Menj \233s gyakorold m\233g a lovagl\225st. Ha a lovad[ENTER]el\233ri a 20-as szintet, visszaj\246hetsz. "
gameforge.horse_upgrade2._410_say = "Nem hozt\225l magaddal 1.000.000 Yangot. "
gameforge.horse_upgrade2._420_say = "Gyere vissza, ha szeretn\233d megszerezni a Katonai[ENTER]l\243 k\246nyvet. "
gameforge.horse_upgrade2._430_say = "Biztos vagy benne? Ha most feladod, akkor az[ENTER]eg\233sz feladatot csin\225lhatod el\246lr\245l. "
gameforge.horse_upgrade2._440_makequestbutton = "Lej\225rt az id\245! "
gameforge.horse_upgrade2._450_sayReward = "Nem \246lt\233l meg 300 D\233mon \237j\225szt, ez\233rt nem \225lltad[ENTER]ki a pr\243b\225t. "
gameforge.horse_upgrade2._460_sayReward = "Ha \250jra meg akarod pr\243b\225lni, szerezz m\225sik L\243[ENTER]med\225lt \233s menj a Lov\225szinashoz. "
gameforge.horse_upgrade2._50_say = "Ha fejleszteni szeretn\233d a lovad, ki kell \225llnod[ENTER]egy alkalmass\225gi vizsg\225t. Mint legut\243bb,[ENTER]sz\252ks\233ged van egy L\243 med\225lra a pr\243b\225hoz. A majom[ENTER]kazamat\225ban juthatsz hozz\225. Term\233szetesen az ott[ENTER]\233l\245 majmok nem fogj\225k harc n\233lk\252l \225tengedni, \233s[ENTER]nagyon er\245szakosak... "
gameforge.horse_upgrade2._60_say = "T\233nyleg musz\225j \250jra elmondanom? Ha lovagolni[ENTER]akarsz, n\225lad kell lennie a Felfegyverzett l\243[ENTER]k\246nyvednek. "
gameforge.horse_upgrade2._70_say = "Csak a leger\245sebbek kapj\225k meg a Katonai l\243[ENTER]k\246nyvet. Menj a D\233mon-toronyba \233s \246lj meg 300[ENTER]D\233mon \237j\225szt. Ha megcsin\225lod, senki sem tud[ENTER]megakad\225lyozni, hogy megkapd t\245lem a Katonai l\243[ENTER]k\246nyvet. Term\233szetesen ez neh\233z feladat. Egy[ENTER]csoporttal is mehetsz, de NEKED kell lenni a[ENTER]csoportvezet\245nek. "
gameforge.horse_upgrade2._80_say = "H\225t akkor gyere k\233s\245bb. "
gameforge.horse_upgrade2._90_say = "Nem hiszem, hogy volna olyan ok, ami\233rt ne[ENTER]szerezhetn\233d meg a Katonai l\243 k\246nyvet. (K\233rdezz[ENTER]meg err\245l egy J\225t\233k Mestert (GM)). "
