gameforge.locale.bookworm.accept_failure_info_text_2 = "T\233rj vissza a faluba \233s mondd el Soon-nak, hogy[ENTER]meg tudod tal\225lni a Milgyo k\246nyvet. "
gameforge.locale.bookworm.accept_failure_say_1 = "Visszat\233r\233s a faluba. "
gameforge.locale.bookworm.accept_failure_say_2 = "\218gy t\251nik, lehagyott a szerencs\233m - nem tal\225lom a[ENTER]Milgyo k\246nyvet. Egyetlen dolgot tehetek, hogy[ENTER]visszat\233rek a faluba. "
