gameforge.locale.bookworm.accept_success_say_1 = "Itt van... a Milgyo k\246nyv! "
gameforge.locale.bookworm.accept_success_say_2 = "Ott a Milgyo k\246nyv! Vidd el Soon-nak a faluba! "
gameforge.locale.bookworm.aranyeo_complete_say = "Melyik f\233lkegyelm\251 adta a f\233rjemnek ezt a k\252l\246n\246s[ENTER]k\246nyvet?[ENTER]Eg\233sz nap ezt b\225mulja \233s k\252l\246n\246s \233nekeket tanul[ENTER]meg k\237v\252lr\245l. A kisujj\225t sem mozd\237tja! \214sszet\246r\246m[ENTER]minden csontj\225t, ha elkapom! "
gameforge.locale.bookworm.aranyeo_complete_say2 = "Mi t\246rt\233nt? Mi ez a hideg izzadts\225g? "
gameforge.locale.bookworm.aranyeo_start_say = "Most meg hov\225 lett? Felideges\237t a viselked\233se![ENTER]Ell\243gja a napot k\246nyvek olvas\225s\225val, an\233lk\252l,[ENTER]hogy egyetlen \225rva Yangot is keresne! \201s m\233g csak[ENTER]nem is sz\233gyenkezik, hogy milyen rossz p\233ld\225t[ENTER]mutat a gyerekeknek! "
gameforge.locale.bookworm.aranyeo_start_say2 = "Tudnak a k\246nyvek \233telt tenni az asztalodra, vagy[ENTER]fel tudnak ruh\225zni? \214sszet\246r\246m az \246sszes[ENTER]csontj\225t, ha elkapom! "
gameforge.locale.bookworm.aranyeo_talk = "Besz\233lni. "
gameforge.locale.bookworm.complete_say = "\211! Igen, l\225tom! L\225tom! L\225tom az \250j vil\225got! "
gameforge.locale.bookworm.do_you_find_the_book = "Megtal\225ltad a Milgyo k\246nyvet? "
gameforge.locale.bookworm.do_you_mean_this_book = "Erre a k\246nyvre gondolt\225l? "
gameforge.locale.bookworm.etc_shop_start_say = "Itt j\225rt tegnap, \233s Milgyo k\246nyv\233r\245l \233rdekl\245d\246tt.[ENTER]Nem volt n\225la Yang, m\233gis folyamatosan arr\243l[ENTER]k\233rdez\245sk\246d\246tt. Milgyo-nak tal\225n volt valami[ENTER]dolga ezekkel a Seungryong-v\246lgyi brut\225lis[ENTER]l\233nyekkel. Fogalmam sincs, mi\233rt t\225madt n\225la ez a[ENTER]hirtelen \233rdekl\245d\233s ezen l\233nyek ir\225nt. "
gameforge.locale.bookworm.etc_shop_start_say2 = "Aranyeo b\225natos lehet. Mi\233rt h\225zas m\233g egy ilyen[ENTER]emberrel? "
gameforge.locale.bookworm.etc_shop_talk_about_bookworm = "A tanult Soonr\243l. "
gameforge.locale.bookworm.order_accept = "J\243! Megszerzem neked! "
gameforge.locale.bookworm.order_accept_answer = "K\246sz\246n\246m! Sz\225m\237tok r\225d. "
gameforge.locale.bookworm.order_find_book_label = "\214ld meg Milgyo tan\237tv\225nyait! "
gameforge.locale.bookworm.order_find_book_text_1 = "\214ld meg Milgyo tan\237tv\225nyait! "
gameforge.locale.bookworm.order_find_book_text_2 = "Vedd el Milgyo tan\237tv\225nyait\243l a Milgyo k\246nyvet. "
gameforge.locale.bookworm.order_refuse = "El\233g neh\233z lehet. "
gameforge.locale.bookworm.order_refuse_answer = "Mi\233rt nem pr\243b\225lod meg? Tudom, hogy k\233pes vagy r\225! "
gameforge.locale.bookworm.order_say1 = "Akarsz hallani valami \233rdekeset? Elmondhatom[ENTER]magamr\243l, hogy a vil\225gon l\233tez\245 \246sszes k\246nyvet[ENTER]olvastam. Most szent \237r\225sokat olvasok, amiket[ENTER]szentek \237rtak. \218gy h\237rlik, hogy a Milgyo k\246nyv[ENTER]arr\243l tartalmaz inform\225ci\243kat \233s utal\225sokat, hogy[ENTER]hogyan v\225lhat az ember szentt\233. "
gameforge.locale.bookworm.order_say2 = "Szeretn\233m megszerezni ezt a k\246nyvet \233s elolvasni![ENTER]Mit gondolsz, meg tudod nekem szerezni? Ha[ENTER]megszerzed, megjutalmazlak! "
gameforge.locale.bookworm.order_too_late = "Valaki m\225s m\225r elhozta nekem a Milgyo k\246nyvet.[ENTER]Nem kell m\225r megtenned. "
gameforge.locale.bookworm.start_find_bookworm_label = "Menj Soonhoz "
gameforge.locale.bookworm.start_find_bookworm_text_1 = "Menj Soonhoz "
gameforge.locale.bookworm.start_find_bookworm_text_2 = "Menj Soon-hoz \233s k\233rdezz r\225 a Milgyo k\246nyvre. "
gameforge.locale.bookworm.start_say = "L\225tod a m\233ly b\246lcsess\233get ebben a dokumentumban?[ENTER]A szavak mondatokat alkotnak \233s \237gy keletkezik[ENTER]egy csod\225latos t\246rt\233net. Meg kell szoknod, hogy[ENTER]m\225s emberek k\233pzelete vezet, \233s ez nem[ENTER]mindenkinek tetszik, de \233n szeretem. "
gameforge.locale.bookworm.start_say2 = "Min\233l t\246bbed van, ann\225l t\246bbet kapsz.[ENTER]Min\233l t\246bbet tudsz, ann\225l jobban \233lvezed az[ENTER]\233letet.[ENTER]Ah, b\225rcsak olvashatn\233k \233letem v\233g\233ig... "
