gameforge.locale.forked_condition = "Meg kell tal\225lnunk az \225tj\225r\243 \245r\233t, miel\245tt egy[ENTER]m\225sik birodalom teszi meg.[ENTER]Bizony\237tsuk birodalmunk erej\233t \233s terjessz\252k ki[ENTER]hatalm\225t! "
gameforge.locale.forked_condition2 = "Most m\233g ki kell pucolnunk mindenkit, akik[ENTER]megszents\233gtelen\237tik a Szentf\246ldet. T\225mad\225s! "
gameforge.locale.forked_enter = "R\233szt venni "
gameforge.locale.forked_kill_boss = "\201n Thorr Sarch vagyok! Mit akartok t\245lem? Nem[ENTER]haltam meg, felt\225madok. Harcosok l\233gi\243i fognak[ENTER]k\246vetni![ENTER]Befejezt\233tek a birodalmi h\225bor\250t. Mindenki[ENTER]visszaker\252l a faluba. "
gameforge.locale.forked_man_chat = "R\233szt venni a Birodalmi csat\225ban "
gameforge.locale.forked_man_say = "Egy \250j ter\252letet fedeztek fel, ami a kontinens[ENTER]k\246zep\233n van. Lehets\233ges, hogy kapcsol\243dik[ENTER]mindh\225rom birodalomhoz. Ny\252zs\246gnek benne a s\246t\233t[ENTER]teremtm\233nyek. Esetleg oda tudn\225l menni, hogy[ENTER]szemben\233zz vel\252k? Puszt\237tsd el \245ket, hogy[ENTER]helyre\225lljon birodalmunk b\233k\233je! "
gameforge.locale.forked_man_say_cant = "H\233! Egy \250j ter\252letet fedeztek fel a kontinens[ENTER]belsej\233ben. Lehets\233ges, hogy az \246sszes birodalmat[ENTER]\246sszek\246ti. Amint v\233get \233rnek ott a kutat\225sok,[ENTER]bel\233phetsz a ter\252letre. "
gameforge.locale.forked_no_enter = "Nem venni r\233szt "
gameforge.locale.forked_open_gate = "Az eddig z\225rva lev\245 kapu kiny\237lt. Menj\252nk az \250j[ENTER]ter\252letre! H\243d\237tsuk meg! Mindenki a Szentf\246ldre[ENTER]lesz teleport\225lva. "
gameforge.locale.forked_rule = "A Birodalmi csat\225ba l\233p\233s szab\225lyai:[ENTER]1. Mindenki, aki meghal ezen a ter\252leten,[ENTER]visszaker\252l a faluba, de a Csata ir\225ny\237t\243 azonnal[ENTER]vissza tudja juttatni.[ENTER]2. Ha egyszer megny\237lik a Szentf\246ld kapuja, ez a[ENTER]ter\252let lez\225rul.[ENTER]3. A Szentf\246ldre t\246rt\233n\245 bel\233p\233shez meg kell[ENTER]tal\225lni a megfelel\245 kulcsot. "
gameforge.locale.forked_rule_sungzi = "A Birodalmi csata szab\225lyai:[ENTER]1. Az a birodalom esik ki els\245k\233nt, amelynek a[ENTER]legkevesebb gy\245zelme van m\225sok felett.[ENTER]2. Ellens\233ges sz\246rnyek jelennek meg. Az a[ENTER]birodalom nyer, amelyik el\245sz\246r \246l meg egy[ENTER]bizonyos mennyis\233g\251 sz\246rnyet.[ENTER]3. Ha meg\246lik a Kilencfark\250t, befejez\245dik a csata.4. A birodalmi csata alatt nem lehet t\225rgyakat[ENTER]szerezni.[ENTER]5. Aki h\225romszor meghal a Szentf\246ld\246n, visszat\233r[ENTER]a faluba, \233s sz\225m\225ra megsz\251nik a Birodalmi csata. "
gameforge.locale.fortune_words_1_body = "Igaz! A szerencse r\225d mosolygott![ENTER]Ny\250jtozz egyet \233s \233rezd, hogy \225t\225ramlik testeden.[ENTER]Ma \"Nagy Szerencs\233d\" van![ENTER]A harmonikus chi-\225ramlatoknak h\225la, ma valami j\243[ENTER]t\246rt\233nik veled. "
gameforge.locale.fortune_words_1_title = "Nagyon nagy szerencse! "
gameforge.locale.fortune_words_2_body = "Ez j\243. Hogy is mondj\225k ezt? Ki mint vet, \250gy[ENTER]arat. Ma \"Szerencs\233s\" vagy![ENTER]\214r\252l\246k neked. Kicsid er\245ltesd meg magad, \233s[ENTER]sokkal t\246bbet fogsz kapni, mint valaha. "
gameforge.locale.fortune_words_2_title = "Nagy szerencse! "
gameforge.locale.fortune_words_3_body = "Nem rossz! Ma \"n\233mi Szerencs\233d\" lesz. Kicsit jobb[ENTER]lesz, mind m\225skor szokott, de ne sz\225m\237ts nagy[ENTER]aj\225nd\233kokra! "
gameforge.locale.fortune_words_3_title = "Egy kis szerencse "
gameforge.locale.fortune_words_4_body = "Nem k\252l\246n\246sebben j\243, de nem is olyan rossz! Ma[ENTER]\"\225tlagos szerencs\233d\" lesz. Ez nem igaz\225n seg\237t a[ENTER]tov\225bbiakban, de jobb a pech-n\233l. \193tlagos napokon[ENTER]ne panaszkodj, ink\225bb \246r\252lj neki. "
gameforge.locale.fortune_words_4_title = "Szokv\225nyos szerencse "
gameforge.locale.fortune_words_5_body = "Ma nem r\225d mosolygott a szerencse.[ENTER]\201s ha m\233g egy h\225l\243t is kivetsz, csak kev\233s halat[ENTER]fogsz fogni \233s csak kev\233ss\233 \233hezni.[ENTER]Ma \"Valamennyi Peched\" van.[ENTER]De semmi sem jobb a felk\233sz\252lts\233gn\233l.[ENTER]Ha akarod, \237rok neked egy talizm\225nt, ami[ENTER]elh\225r\237tja a legrosszabbat.[ENTER]Mi legyen, akarsz venni egy talizm\225nt? "
gameforge.locale.fortune_words_5_title = "Egy kis szerencs\233tlens\233g "
gameforge.locale.fortune_words_6_body = "Rossz nap a mai. Egy nap, amikor legjobb, ha[ENTER]ink\225bb nem teszel semmit. Ma \"peched\" van, sz\243val[ENTER]l\233gy \243vatos, hov\225 m\233gy, vagy mit teszel. Azonban[ENTER]lehet, hogy tudok neked seg\237teni, tudn\233k adni egy[ENTER]talizm\225nt, amivel elker\252lheted a k\225rokat.[ENTER]\201rdekel? "
gameforge.locale.fortune_words_6_title = "Pech. "
gameforge.locale.fortune_words_7_body = "A mai nap \233leted egyik lehet\245 legrosszabb napja.[ENTER]Az Istenek \233gen-f\246ld\246n elfordultak t\245led. Ma[ENTER]semmi sem siker\252l neked. Ha t\252zet akarsz[ENTER]gy\250jtani, esni fog; ha szomjas vagy, t\251zni fog a[ENTER]nap. Kem\233nyen fogsz dolgozni, mint mindenki m\225s,[ENTER]de nem lesz t\250l sok eredm\233nye. \"Nagyon nagy[ENTER]balszerencs\233r\245l\" szenvedsz![ENTER]Talizm\225n n\233lk\252l neh\233z id\245k j\225rnak r\225d.[ENTER]\201rdekel, szeretn\233l v\225s\225rolni egyet? "
gameforge.locale.fortune_words_7_title = "Eg\233szen nagy pech "
