gameforge.locale.make_wonso.how_make = "Hogyan tudok rizs gomb\243cot csin\225lni? "
gameforge.locale.make_wonso.how_make_detail = "Ha sz\246rnyre vad\225szol, gyakran tal\225lsz mindenf\233le[ENTER]\246sszetev\245t a rizs gomb\243choz: babkr\233m, cukorkr\233m,[ENTER]gy\252m\246lcskr\233m \233s \233des rizs. Ha elhozol nekem egy[ENTER]adag kr\233met \233s egy adag \233des rizst, akkor tudok[ENTER]neked csin\225lni rizs gomb\243cot. Azt mondj\225k ha[ENTER]megeszed, speci\225lis hat\225sa van... "
gameforge.locale.make_wonso.make_msg1 = "Megvannak az \246sszetev\245k? Rendben. Elveszem a[ENTER]babkr\233met \233s az \233des rizst \233s csin\225lok neked...[ENTER]egy bab s\252tem\233nyt! J\243 \233tv\225gyat! "
gameforge.locale.make_wonso.make_msg2 = "Megvannak az \246sszetev\245k? Rendben. Elveszem a[ENTER]cukorkr\233met \233s az \233des rizst \233s csin\225lok neked...[ENTER]egy cukortort\225t! J\243 \233tv\225gyat! "
