gameforge.locale.monster_chat = {}
gameforge.locale.monster_chat_1001_1 = "Mindenki meg fog halni! "
gameforge.locale.monster_chat_1001_2 = "Kicsi, kicsi, kicsi darabok... "
gameforge.locale.monster_chat_1001_3 = "Nem menek\252lhetsz! "
gameforge.locale.monster_chat_1001_4 = "A padl\243t \225titatja majd a v\233red. Halj meg! "
gameforge.locale.monster_chat_1001_5 = "K\246ny\246r\246ghetsz, de nem \233r semmit! "
gameforge.locale.monster_chat_1001_6 = "Nem tudod elrejteni el\245lem a retteg\233sed! "
gameforge.locale.monster_chat_1002_1 = "Hal\225l! Hal\225l minden emberre... "
gameforge.locale.monster_chat_1002_2 = "Ti nyomorult f\233rgek! "
gameforge.locale.monster_chat_1002_3 = "T\233nyleg kezdtek feld\252h\237teni... "
gameforge.locale.monster_chat_1002_4 = {}
gameforge.locale.monster_chat_1002_5 = "V\233r fog folyni, ember. "
gameforge.locale.monster_chat_1003_1 = "Hal\225l \233s k\225rhozat...! "
gameforge.locale.monster_chat_1003_2 = "L\225ttad a l\225ndzsa \225ltal okozott sebet a b\245r\246d\246n? "
gameforge.locale.monster_chat_1003_3 = "Igen, gyer\252nk, menek\252lj! Majd megl\225tjuk, milyen messzire jutsz... "
gameforge.locale.monster_chat_1003_4 = "A l\225tv\225ny, ahogy remeg a kezed, m\225r meg\233rte... "
gameforge.locale.monster_chat_1003_5 = "Te s\246pred\233k, te mersz kih\237vni? "
gameforge.locale.monster_chat_1003_6 = "A hal\225l lesz az egyetlen t\225rsad ezent\250l! "
gameforge.locale.monster_chat_1004_1 = "Eny\233m lesz a lelked, ember! "
gameforge.locale.monster_chat_1004_2 = "Ah, friss v\233r! "
gameforge.locale.monster_chat_1004_3 = "\218gy t\251nik, \250jabb szem\233ly akar itt megismerkedni a hal\225llal! "
gameforge.locale.monster_chat_1004_4 = "Szenvedned kellene, \252v\246ltened a k\237nt\243l... "
gameforge.locale.monster_chat_1004_5 = "Te t\233nyleg azt hiszed, hogy meg tudod v\233deni magad azzal a nevets\233ges fegyverrel a kezedben? "
gameforge.locale.monster_chat_1004_6 = "A b\225tors\225god vezetett ide hozz\225m. \201s most el fog hagyni... "
gameforge.locale.monster_chat_1035_1 = "Ha meghalok, bossz\250m \252ld\246zni fog az \246r\246kk\233val\243s\225gig! "
gameforge.locale.monster_chat_1035_2 = "Hagylak szenvedni, lassan, nagyon lassan fogsz meghalni... "
gameforge.locale.monster_chat_1035_3 = "\214r\246met okoz, ha l\225tlak majd szenvedni. "
gameforge.locale.monster_chat_1035_4 = "Tested reszket, mint a ny\225rfalev\233l! "
gameforge.locale.monster_chat_1035_5 = "\201rzem a f\233lelmed, kicsim. "
gameforge.locale.monster_chat_1035_6 = "Azt hiszem, elj\246tt az ideje, hogy megszabadulj n\233h\225ny testr\233szedt\245l. "
gameforge.locale.monster_chat_1036_1 = "Saj\225t szem\233lyes poklodba k\252ldelek! "
gameforge.locale.monster_chat_1036_2 = "Az \245r\252letbe fog kergetni a f\225jdalmad, miel\245tt meghalsz... "
gameforge.locale.monster_chat_1036_3 = "Jajgathatsz! K\246ny\246r\246ghetsz! De semmi nem seg\237thet rajtad. "
gameforge.locale.monster_chat_1036_4 = "Megtapasztalod az elk\233pzelhet\245 legrosszabb hal\225lt! "
gameforge.locale.monster_chat_1036_5 = {}
gameforge.locale.monster_chat_1036_6 = "Egyre gyeng\252l az er\245d. M\225r a hal\225l szakad\233k\225nak sz\233l\233n \225llsz... "
gameforge.locale.monster_chat_1037_1 = "K\233szen \225llsz a v\233gtelens\233gig tart\243 s\233t\225ra a hal\225l csarnok\225ban? "
gameforge.locale.monster_chat_1037_2 = "Bar\225tkozz a gondolattal, hogyan fogadod az \246r\246k s\246t\233ts\233get... "
gameforge.locale.monster_chat_1037_3 = "\220dv a pokolban! "
gameforge.locale.monster_chat_1037_4 = "Kiab\225lhatsz, amennyit csak akarsz! Senki nem fog meghallani! "
gameforge.locale.monster_chat_1037_5 = "Ha azt hitted, ez meg\246lhet engem... akkor naivabb vagy, mint gondoltam! "
gameforge.locale.monster_chat_1037_6 = "Nem rossz, de m\233g mindig ez sem menthet meg a hal\225lt\243l. "
gameforge.locale.monster_chat_1038_1 = "N\233zz k\246r\252l, ez a pokol! "
gameforge.locale.monster_chat_1038_2 = "Leny\250zom a b\245rt r\243lad. "
gameforge.locale.monster_chat_1038_3 = "Hallani akarom a hal\225lh\246rg\233sed. "
gameforge.locale.monster_chat_1038_4 = "Ugye, tudod, hogy itt nincs rem\233ny? "
gameforge.locale.monster_chat_1038_5 = {}
gameforge.locale.monster_chat_1038_6 = "Nem, m\233g nem halsz meg. El\245tte m\233g tudni akarom, h\225ny kardd\246f\233st k\233pes elviselni a tested... "
gameforge.locale.monster_chat_1039_1 = "Am\237g j\246n egy \250j... "
gameforge.locale.monster_chat_1039_2 = "Val\243ban azt hiszed, hogy a legkisebb es\233lyed is van a menek\252l\233sre? "
gameforge.locale.monster_chat_1039_3 = "Nem a padl\243 mozog... A t\233rdeid reszketnek a f\233lelemt\245l! "
gameforge.locale.monster_chat_1039_4 = "\220dv\246zl\252nk a helyen, ahol k\246ny\246r\246gni fogsz a hal\225lod\233rt! "
gameforge.locale.monster_chat_1039_5 = "L\225tom a f\233lelmet a szemeidben. "
gameforge.locale.monster_chat_1039_6 = "Oh, milyen fiatal \233s v\233dtelen... "
gameforge.locale.monster_chat_1040_1 = "L\225tjuk minden l\233p\233sed. "
gameforge.locale.monster_chat_1040_2 = "Sietsz? T\233nyleg meg akarsz halni? "
gameforge.locale.monster_chat_1040_3 = "A hal\225l m\225r elfoglalta a hely\233t az oldaladon... "
gameforge.locale.monster_chat_1040_4 = "Hallod a harangom kong\225s\225t? Ez lesz az utols\243 dolog, amit hallasz! "
gameforge.locale.monster_chat_1040_5 = "Ha nem \225ll el ennek a sebnek a v\233rz\233se, vesz\233lyes lesz. "
gameforge.locale.monster_chat_1040_6 = "Harcolhatsz... vagy hagyd, hogy a hal\225l \225t\246leljen... "
gameforge.locale.monster_chat_1041_1 = "Mi\233rt vagy itt, ha \233lni akarsz? "
gameforge.locale.monster_chat_1041_2 = "Ah, \250j testek, amiket elpuszt\237thatok! "
gameforge.locale.monster_chat_1041_3 = "Te d\246nt\246tt\233l \250gy, hogy ide j\246ssz, ember! \233s most neked kell egy\252tt \233lned a k\246vetkezm\233nyekkel... "
gameforge.locale.monster_chat_1041_4 = "Felt\225madunk, nem tudunk meghalni. "
gameforge.locale.monster_chat_1041_5 = "\201rtelmetlen minket megt\225madni. Kudarcra vagy \237t\233lve... "
gameforge.locale.monster_chat_1041_6 = "Mi v\225r r\225d: kimer\252l\233s, vagy hal\225l? "
gameforge.locale.monster_chat_1091_1 = "M\225r megtetted itt... \233s most elk\252ldelek a hal\225lba. "
gameforge.locale.monster_chat_1091_2 = "\193ldozd fel a lelked, \233s l\233gy egy k\246z\252l\252nk! "
gameforge.locale.monster_chat_1091_3 = "N\233zd meg magad! Gyenge \233s lass\250... "
gameforge.locale.monster_chat_1091_4 = "A tested \233s a lelked is az eny\233m. (Kacaj) "
gameforge.locale.monster_chat_1091_5 = "Remegnek a l\225baid! N\233zz szembe vele, nem k\233sz\252lt\233l fel erre... "
gameforge.locale.monster_chat_1091_6 = "Meddig b\237rod m\233g? "
gameforge.locale.monster_chat_1093_1 = "Ki gondolta volna, hogy van rosszabb a hal\225ln\225l? "
gameforge.locale.monster_chat_1093_2 = "\220dv\246zl\252nk, \233hhal\225l. "
gameforge.locale.monster_chat_1093_3 = "Fizetni fogsz a tolakod\225sod\233rt. A v\233reddel \233s a lelkeddel. "
gameforge.locale.monster_chat_1093_4 = "Miut\225n megsemmis\237tettem a tested, a lelked az eny\233m lesz! "
gameforge.locale.monster_chat_1093_5 = "Mit gondolsz, meddig tudsz m\233g k\252zdeni ellenem? "
gameforge.locale.monster_chat_1093_6 = "Mulattatsz. A f\233lelem \233s a siets\233g nagyon sz\243rakoztat\243... "
gameforge.locale.monster_chat_11000_1 = "Figyeljen ide mindenki, aki agg\243dik a fejl\245d\233s\233\233rt! "
gameforge.locale.monster_chat_11000_10 = "Ha a term\233szet hatalm\225t, k\252l\246n\246sen a vill\225ml\225st akarod uralni, aj\225nlom neked a Gy\243gy\237t\225s tan\225t! "
gameforge.locale.monster_chat_11000_11 = "A harcosban az a jellegzetes a harcmodora. Koncentr\225ljatok testetek ac\233los\237t\225s\225ra. "
gameforge.locale.monster_chat_11000_12 = "A Sura ereje a m\225gia. Dolgozzatok az intelligenci\225tokon, gyorsas\225gotokon \233s testi er\245t\246k\246n! "
gameforge.locale.monster_chat_11000_13 = "Haszn\225ld a nindzs\225k tulajdons\225gait! Koncentr\225lj a gyorsas\225gra \233s a testi er\245re! "
gameforge.locale.monster_chat_11000_14 = "A s\225m\225nok regener\225l\243, t\225mogat\243 \233s t\225vharc-var\225zslatokat alkalmaznak. Az intelligencia elengedhetetlen! "
gameforge.locale.monster_chat_11000_15 = "Ne feledd, hogy szakmai gyakorlaton vagy! "
gameforge.locale.monster_chat_11000_16 = "Tanulj, ha a k\233szs\233geidet gyakorolni akarod! "
gameforge.locale.monster_chat_11000_17 = "K\233szs\233gek? A mesterek szintj\233ig felmehetsz a 17 \233s 21 szintek k\246z\246tti v\233letlen eloszl\225ssal. "
gameforge.locale.monster_chat_11000_18 = "Szeretn\233l nagymester lenni? Akkor egy k\252l\246nleges k\233szs\233gk\246nyvre van sz\252ks\233ged! "
gameforge.locale.monster_chat_11000_19 = "Amint elolvast\225l egy k\233szs\233gk\246nyvet, elt\251nik! "
gameforge.locale.monster_chat_11000_2 = "Minden harcos az 5. szint alatt, figyeljen ide! "
gameforge.locale.monster_chat_11000_20 = "Szeretn\233l \250jra m\225sik K\233szs\233gk\246nyvet olvasni? Akkor v\225rj egy napot. "
gameforge.locale.monster_chat_11000_21 = "Fejleszd az intelligenci\225d, hogy n\246veld Sura k\233pess\233geid! "
gameforge.locale.monster_chat_11000_22 = "\201ld \225t a Sura nagy hatalm\225t a harcban! "
gameforge.locale.monster_chat_11000_23 = "Tudod hol van az ezoterikus szekta temploma? A Seungryong-v\246lgy k\246zep\233n tal\225lhat\243! "
gameforge.locale.monster_chat_11000_24 = "A p\243k\252regek ism\233t megjelentek. A Yongbi sivatagban tal\225lhat\243k a bej\225rataik! "
gameforge.locale.monster_chat_11000_25 = "Fejezd be a megb\237z\225said, \233s haszn\225ld fejleszt\233shez a jutalmakat! "
gameforge.locale.monster_chat_11000_26 = "Horg\225szni? J\243l hangzik! Neked van m\225r horg\225szbotod \233s csalid egy hal\225szt\243l, nem? "
gameforge.locale.monster_chat_11000_27 = "Szeretn\233l valami er\245sebbet tal\225lni a vad\225szathoz? Keress egy kaput! Menj egy vad\225szhelyre, ami megfelel a szintednek. "
gameforge.locale.monster_chat_11000_28 = "Figyelj a m\225s birodalmakb\243l erkez\245 ellens\233gekre. Soha nem tudhatod, hogy mik\246r d\246fnek h\225tba. "
gameforge.locale.monster_chat_11000_29 = "Szeretn\233d meg\250j\237tani a k\233szs\233geidet? Akkor menj az \246regasszonyhoz! Gondoskodj r\243la, hogy el\233g Yang legyen n\225lad. "
gameforge.locale.monster_chat_11000_3 = "Keresd fel a t\245rharc oktat\243t k\233pz\233s\233rt, ha nagyszer\251 t\225mad\243 harcos akarsz lenni! "
gameforge.locale.monster_chat_11000_30 = "T\246rekedj a t\246k\233letes mester szintre. \205gy lehetsz igazi h\245s! "
gameforge.locale.monster_chat_11000_31 = "Ha egy m\225sik v\225rosba vagy harcmez\245re szeretn\233l l\233pni, akkor keress fel \246reg embereket a kontinensen! "
gameforge.locale.monster_chat_11000_4 = "Ha szeretn\233l j\225rtass\225 v\225lni a harcos k\233pess\233gekben, menj, \233s tanulj a harcm\251v\233szet mester\233t\245l! "
gameforge.locale.monster_chat_11000_5 = "Ha a m\225gikus kardokhoz \233rt\245 Sura szeretn\233l lenni, v\225laszd a fegyveres k\233pz\233st! "
gameforge.locale.monster_chat_11000_6 = "Ha s\246t\233t var\225zslatok bevet\233s\233ben szeretn\233l t\252nd\246k\246lni, akkor jelentkezz a fekete m\225gia oktat\243n\225l! "
gameforge.locale.monster_chat_11000_7 = "Az \237j\225sz k\233pz\233s 5. szint feletti nindzs\225k sz\225m\225ra van fenntartva! "
gameforge.locale.monster_chat_11000_8 = "V\225laszd a t\245rharc-k\233pz\233st, ha a nindzs\225k titkos tanait k\246vet\245k k\246zt akarsz felemelkedni. "
gameforge.locale.monster_chat_11000_9 = "Ha harcosk\233nt a s\225rk\225ny isten m\233sz\225rl\225st szeretn\233d tudni, akkor tanuld a s\225rk\225ny hatalom tan\225t! "
gameforge.locale.monster_chat_11002_1 = "Figyeljen ide, aki agg\243dik az eg\233szs\233g\233\233rt! "
gameforge.locale.monster_chat_11002_10 = "Ha a term\233szet er\245it \233s a vill\225mot akarod uralni, jelentkezz a Gy\243gy\237t\243 er\245 k\233pz\233sre! "
gameforge.locale.monster_chat_11002_11 = "A harcosban az a jellegzetes a harcmodora. Koncentr\225ljatok testetek ac\233los\237t\225s\225ra. "
gameforge.locale.monster_chat_11002_12 = "A Sura ereje a m\225gia. Dolgozzatok az intelligenci\225tokon, gyorsas\225gotokon \233s testi er\245t\246k\246n! "
gameforge.locale.monster_chat_11002_13 = "Fejleszd a norm\225l nindzsa k\233pess\233geid magasabb szintre! Koncentr\225lj a gyorsas\225godra \233s a fizikai er\245dre! "
gameforge.locale.monster_chat_11002_14 = "A s\225m\225nok regener\225l\243, t\225mogat\243- \233s t\225mad\243 var\225zslatokat alkalmaznak a csat\225ban. Ehhez az intelligencia elengedhetetlen! "
gameforge.locale.monster_chat_11002_15 = "Ne felejtsd el a tan\237t\225st! "
gameforge.locale.monster_chat_11002_16 = "Tanulj, ha a k\233szs\233geidet gyakorolni akarod! "
gameforge.locale.monster_chat_11002_17 = "K\233szs\233gek? A mesterek szintj\233ig felmehetsz a 17 \233s 21 szintek k\246z\246tti v\233letlen eloszl\225ssal. "
gameforge.locale.monster_chat_11002_18 = "Szeretn\233l nagymester lenni? Akkor egy k\252l\246nleges k\233szs\233gk\246nyvre van sz\252ks\233ged! "
gameforge.locale.monster_chat_11002_19 = "Amint elolvast\225l egy k\233szs\233gk\246nyvet, elt\251nik! "
gameforge.locale.monster_chat_11002_2 = "Minden harcos az 5. szint alatt, figyeljen ide! "
gameforge.locale.monster_chat_11002_20 = "Szeretn\233l \250jra m\225sik K\233szs\233gk\246nyvet olvasni? Akkor v\225rj egy napot. "
gameforge.locale.monster_chat_11002_21 = "Fejleszd az intelligenci\225d, hogy n\246veld Sura k\233pess\233geid! "
gameforge.locale.monster_chat_11002_22 = "\201ld \225t a Sura nagy hatalm\225t a harcban! "
gameforge.locale.monster_chat_11002_23 = "Tudod hol van az ezoterikus szekta temploma? A Seungryong-v\246lgy k\246zep\233n tal\225lhat\243! "
gameforge.locale.monster_chat_11002_24 = "A p\243k\252regek ism\233t megjelentek. A Yongbi sivatagban tal\225lhat\243k a bej\225rataik! "
gameforge.locale.monster_chat_11002_25 = "Fejezd be a megb\237z\225said, \233s haszn\225ld fejleszt\233shez a jutalmakat! "
gameforge.locale.monster_chat_11002_26 = "Horg\225szni? J\243l hangzik! Neked van m\225r horg\225szbotod \233s csalid egy hal\225szt\243l, nem? "
gameforge.locale.monster_chat_11002_27 = "Szeretn\233l valami er\245sebbet tal\225lni a vad\225szathoz? Keress egy kaput! Menj egy vad\225szhelyre, ami megfelel a szintednek. "
