gameforge.locale.monster_chat_11004_1 = "Figyeljen ide, aki agg\243dik az eg\233szs\233g\233\233rt! "
gameforge.locale.monster_chat_11004_10 = "Ha a term\233szet hatalm\225t, k\252l\246n\246sen a vill\225ml\225st uralni akarod, aj\225nlom neked a gy\243gy\237t\225s tan\225t! "
