gameforge.locale.monster_chat_11004_12 = "A Sura ereje a m\225gia. Dolgozzatok az intelligenci\225tokon, gyorsas\225gotokon \233s testi er\245t\246k\246n! "
gameforge.locale.monster_chat_11004_13 = "Fejleszd a nindzs\225k tulajdons\225gait magasabb szintre! Koncentr\225lj a gyorsas\225gra \233s a testi er\245re! "
gameforge.locale.monster_chat_11004_14 = "A s\225m\225nok regener\225l\243, t\225mogat\243- \233s t\225mad\243 var\225zslatokat alkalmaznak a csat\225ban. Ehhez az intelligencia elengedhetetlen! "
