gameforge.locale.monster_chat_11004_19 = "Amint elolvast\225l egy k\233szs\233gk\246nyvet, elt\251nik! "
gameforge.locale.monster_chat_11004_2 = "Minden harcos az 5. szint alatt, figyeljen ide! "
gameforge.locale.monster_chat_11004_20 = "Szeretn\233l olvasni egy m\225sik k\233szs\233gk\246nyvet is? Akkor v\225rnod kell egy napot. "
gameforge.locale.monster_chat_11004_21 = "Fejleszd az intelligenci\225d, hogy n\246veld Sura k\233pess\233geid! "
gameforge.locale.monster_chat_11004_22 = "\201ld \225t a Sura nagy hatalm\225t a harcban! "
gameforge.locale.monster_chat_11004_23 = "Tudod hol van az ezoterikus szekta temploma? A Seungryong-v\246lgy k\246zep\233n tal\225lhat\243! "
gameforge.locale.monster_chat_11004_24 = "A p\243k\252regek ism\233t megjelentek. A Yongbi sivatagban tal\225lhat\243k a bej\225rataik! "
gameforge.locale.monster_chat_11004_25 = "Fejezd be a megb\237z\225said, \233s haszn\225ld fejleszt\233shez a jutalmakat! "
