gameforge.locale.monster_chat_11004_28 = "Figyelj a m\225s birodalmakb\243l erkez\245 ellens\233gekre. Soha nem tudhatod, hogy mik\246r d\246fnek h\225tba. "
gameforge.locale.monster_chat_11004_29 = "Szeretn\233d meg\250j\237tani a k\233szs\233geidet? Akkor menj az \246regasszonyhoz! Gondoskodj r\243la, hogy el\233g Yang legyen n\225lad. "
gameforge.locale.monster_chat_11004_3 = "Keresd fel a t\245rharc oktat\243t k\233pz\233s\233rt, ha nagyszer\251 t\225mad\243 harcos akarsz lenni! "
gameforge.locale.monster_chat_11004_30 = "T\246rekedj a t\246k\233letes mester szintre. \205gy lehetsz igazi h\245s! "
gameforge.locale.monster_chat_11004_31 = "Ha egy m\225sik v\225rosba vagy harcmez\245re szeretn\233l l\233pni, akkor keress fel \246reg embereket a kontinensen! "
gameforge.locale.monster_chat_11004_4 = "Ha szeretn\233l j\225rtass\225 v\225lni a harcos k\233pess\233gekben, menj, \233s tanulj a harcm\251v\233szet mester\233t\245l! "
gameforge.locale.monster_chat_11004_5 = "Ha a m\225gikus kardokhoz \233rt\245 Sura szeretn\233l lenni, v\225laszd a fegyveres k\233pz\233st! "
gameforge.locale.monster_chat_11004_6 = "Ha s\246t\233t var\225zslatok bevet\233s\233ben szeretn\233l t\252nd\246k\246lni, akkor jelentkezz a fekete m\225gia oktat\243n\225l! "
gameforge.locale.monster_chat_11004_7 = "Az \237j\225sz k\233pz\233s 5. szint feletti nindzs\225k sz\225m\225ra van fenntartva! "
gameforge.locale.monster_chat_11004_8 = "V\225laszd a t\245rharc-k\233pz\233st, ha a nindzs\225k titkos tanait k\246vet\245k k\246zt akarsz felemelkedni. "
gameforge.locale.monster_chat_11004_9 = "Ha a S\225rk\225nyisten harcosak\233nt szeretn\233d ellen\245rz\233s alatt tartani a csat\225kat, v\225laszd a S\225rk\225ny hatalom k\233pz\233st! "
gameforge.locale.monster_chat_1105_1 = "A fagyott \225llapot j\243... nekem! "
gameforge.locale.monster_chat_1105_2 = "Biztos, hogy a Sohan-hegy a legjobb hely! "
gameforge.locale.monster_chat_1105_3 = "Micsoda sz\233p id\245. "
gameforge.locale.monster_chat_1105_4 = "A v\233g\233n olyan hideg leszel, mint \233n... "
gameforge.locale.monster_chat_1105_5 = "\214r\246kk\233 \233lhetsz, legal\225bb is am\237g elolvad a j\233g. "
gameforge.locale.monster_chat_1105_6 = "Mit gondolsz, milyen \233rz\233s, amikor sz\233p lassan j\233gg\233 fagysz? "
gameforge.locale.monster_chat_1106_1 = "Emberek... itt?! "
gameforge.locale.monster_chat_1106_2 = "F\225radt... de ahhoz el\233g \233ber, hogy figyeljek r\225d... "
gameforge.locale.monster_chat_1106_3 = "Van itt valaki, az \233n hegyemen? "
gameforge.locale.monster_chat_1106_4 = "Nem tartozol ide! "
gameforge.locale.monster_chat_1106_5 = "Jobb lenne visszafordulnod! "
gameforge.locale.monster_chat_1106_6 = "Idegen... \237gy, egyed\252l? "
gameforge.locale.monster_chat_1191_1 = "Igen r\233gen l\225ttunk m\225r tapasztalt harcost erre. "
gameforge.locale.monster_chat_1191_2 = "Semmi m\225st nem lehet tenni, csak v\225rni, \233s a fegyvert f\233nyes\237teni... "
gameforge.locale.monster_chat_1191_3 = "Dolgozzak rajtuk? "
gameforge.locale.monster_chat_1191_4 = {}
gameforge.locale.monster_chat_1191_5 = "Valami hi\225nyzik. Nem vagyok el\233gedett... "
gameforge.locale.monster_chat_1191_6 = "Gyorsan megsz\252ntetem a f\225jdalmat - ez lesz az utols\243 f\225jdalom, amit \233rzel! "
gameforge.locale.monster_chat_1301_1 = "Egy hossz\250 nyak\250...! "
gameforge.locale.monster_chat_1301_2 = "S\225padt b\245r\246d egy perc alatt m\233g s\225padtabb\225 v\225lik. "
gameforge.locale.monster_chat_1301_3 = "Ki akarsz h\237vni engem? J\243! "
gameforge.locale.monster_chat_1301_4 = "Megt\225madt\225l! Nem fogod t\250l\233lni! "
gameforge.locale.monster_chat_1301_5 = "Gyenge, gyenge ember! "
gameforge.locale.monster_chat_1301_6 = "L\225ssuk, mennyit b\237rsz elviselni! "
gameforge.locale.monster_chat_1302_1 = "Menek\252lni? Ne is gondolj r\225! "
gameforge.locale.monster_chat_1302_2 = "Helyes... gyere k\246zelebb! "
gameforge.locale.monster_chat_1302_3 = "Remeg a kezemben a kard... "
gameforge.locale.monster_chat_1302_4 = "Nem fogod t\250l\233lni ezt a tal\225lkoz\225st! "
gameforge.locale.monster_chat_1302_5 = "Itt j\246n a kardom! "
gameforge.locale.monster_chat_1302_6 = "F\225jdalmas, nem? "
gameforge.locale.monster_chat_1303_1 = "M\233g a f\251 is meg\246lhet, amin j\225rsz! "
gameforge.locale.monster_chat_1303_2 = "A helyedben \233n \243vatos lenn\233k... "
gameforge.locale.monster_chat_1303_3 = "Helyes. Gyere k\246zelebb... "
gameforge.locale.monster_chat_1303_4 = "A k\246zelembe mer\233szkedt\233l? Nos... akkor \233lj egy\252tt a k\246vetkezm\233nyeivel! "
gameforge.locale.monster_chat_1303_5 = "Ideje, hogy b\250cs\250t mondj a vil\225gnak! "
gameforge.locale.monster_chat_1303_6 = "B\225nod, hogy idej\246tt\233l? "
gameforge.locale.monster_chat_1305_1 = "Ki fog engem legy\245zni? "
gameforge.locale.monster_chat_1305_2 = "Te? Harcolni akarsz ellenem? "
gameforge.locale.monster_chat_1305_3 = "T\225madj, ha mersz! "
gameforge.locale.monster_chat_1305_4 = "Ugye, nem gondolsz a menek\252l\233sre? "
gameforge.locale.monster_chat_1305_5 = "Al\225becs\252lted a kardom hat\243t\225vols\225g\225t. "
gameforge.locale.monster_chat_1305_6 = "F\233lsz? "
gameforge.locale.monster_chat_1901_1 = "Azt hiszem, ma meghalsz a kezeim \225ltal. "
gameforge.locale.monster_chat_1901_2 = "\211, te tetszel nekem. "
gameforge.locale.monster_chat_1901_3 = "Ah, sz\243val egy kis v\225ltozatoss\225got akarsz hozni az \233letembe? "
gameforge.locale.monster_chat_1901_4 = "H\233! Az nem seg\237t rajtad, ha gy\225v\225n elfutsz! "
gameforge.locale.monster_chat_1901_5 = "Borzong\225s fut v\233gig a gerinceden, ha r\225m n\233zel? "
gameforge.locale.monster_chat_1901_6 = "Nem akarsz m\233g egy picit sik\237tani? "
gameforge.locale.monster_chat_20001_1 = "Idegesnek t\251nsz... Ne agg\243dj, semmi sem fog felrobbanni. "
gameforge.locale.monster_chat_20001_2 = "N\233ha szeretn\233k csak \250gy s\233t\225lni egyet. "
gameforge.locale.monster_chat_20001_3 = "Annyira unalmas... M\233g az unok\225im sem l\225togatnak meg. "
gameforge.locale.monster_chat_20001_4 = "Ha meg\246regszik az ember, t\225rsas\225gra van sz\252ks\233ge. "
gameforge.locale.monster_chat_20001_5 = "A legszebb \233veim m\225r elsz\225lltak. "
gameforge.locale.monster_chat_20002_1 = "Olyan meleg a nap. "
gameforge.locale.monster_chat_20002_2 = "Csod\225latos az id\245 a mosott ruh\225k megsz\225r\237t\225s\225hoz, nem igaz? "
gameforge.locale.monster_chat_20002_3 = "Hol van az a semmirekell\245 f\233rjem? "
gameforge.locale.monster_chat_20002_4 = "Nem sz\233gyelli mag\225t a gyerekei el\245tt a lustas\225ga miatt! \201s m\233g ap\225nak h\237vatja mag\225t... "
gameforge.locale.monster_chat_20002_5 = "K\246nyvek, mindig csak k\246nyvek! Nem dolgozik \233s nem keres semmit. Mindig csak olvas! "
gameforge.locale.monster_chat_20003_1 = "Szia kicsim, j\243l aludt\225l? "
gameforge.locale.monster_chat_20003_2 = "Kicsi angyalk\225m. "
gameforge.locale.monster_chat_20003_3 = "Te vagy az \233n napsugaram... "
gameforge.locale.monster_chat_20003_4 = "Mi a baj? \201hes vagy? "
gameforge.locale.monster_chat_20003_5 = "Igaz... aludj sz\233pen, kicsim! "
gameforge.locale.monster_chat_20004_1 = "Egyszer\251en megint csak egy \250j nap... "
gameforge.locale.monster_chat_20004_2 = "Hol kapok ma enni valamit? "
gameforge.locale.monster_chat_20004_3 = "Mindig ugyanaz van azokkal a fegyverhordoz\243kkal. "
gameforge.locale.monster_chat_20004_4 = "Megl\225tjuk. Tal\225n elmegyek Octavio \233tterm\233be. "
gameforge.locale.monster_chat_20004_5 = "\193, igen, am\250gy m\225r nem tombol a h\225bor\250... "
gameforge.locale.monster_chat_20005_1 = "A fazekas mester lelke \225tj\225rja az ujjhegyeit. "
gameforge.locale.monster_chat_20005_2 = "Mi\243ta az orsz\225g k\225oszba s\252llyedt, mindenfel\233 harcosok k\243sz\225lnak. "
gameforge.locale.monster_chat_20005_3 = "Mindegyik harcolni akar \225lland\243an. "
gameforge.locale.monster_chat_20005_4 = "Egy nyugalmas \233s b\233k\233s vil\225g\233rt im\225dkozok. "
gameforge.locale.monster_chat_20005_5 = "H\233, te ott! Csak legal\225bb egy percig pihenj \233s gondolkozz... "
gameforge.locale.monster_chat_20006_1 = "Ahh, mit csin\225ljak? "
gameforge.locale.monster_chat_20006_2 = "Nem tal\225lom a legkisebb nyom\225t a testv\233remnek, pedig meg\237g\233rte, hogy elj\246n. "
gameforge.locale.monster_chat_20006_3 = "\201s most csak ezeket a harcosokat l\225tom a kardjaikkal. "
gameforge.locale.monster_chat_20006_4 = "Hi\225nyzik a testv\233rem. "
gameforge.locale.monster_chat_20006_5 = "L\225tta valaki a testv\233rem? "
gameforge.locale.monster_chat_20007_1 = "Mmmm, ez a h\250s friss! "
gameforge.locale.monster_chat_20007_2 = "Milyen j\243, hogy az emberek megint t\246bb h\250st esznek. "
gameforge.locale.monster_chat_20007_3 = "Az \252zlet j\243l megy, de kev\233s a h\250s. "
gameforge.locale.monster_chat_20007_4 = "Mikor j\246n meg v\233gre a h\250s, amit megrendelt\252bk? "
gameforge.locale.monster_chat_20007_5 = "Ha nem j\246n meg azonnal, el kell menn\252nk vad\225szni! "
gameforge.locale.monster_chat_20008_1 = "Rem\233lem, hogy t\246meges j\246nnek a v\225s\225rl\243k ilyen sz\233p id\245ben. "
gameforge.locale.monster_chat_20008_2 = "\211! A lusta d\246g biztos mindj\225rt itt lesz \233s enni akar. "
gameforge.locale.monster_chat_20008_3 = "Na, micsoda szerencs\233tlen! "
gameforge.locale.monster_chat_20008_4 = "R\233gebben nagyon j\243 harcos volt. "
gameforge.locale.monster_chat_20008_5 = "\201rdekel, hogy mi\233rt nem harcol m\225r. "
gameforge.locale.monster_chat_20009_1 = "Ezek a fiatal sr\225cok... nagyon \233l\233nkek \233s kicsattannak az er\245t\245l! "
gameforge.locale.monster_chat_20009_2 = "A harcosok sokkal jobban n\233znek ki, ha fegyvert hordanak. "
gameforge.locale.monster_chat_20009_3 = "Ez a gyilkos szellem hat \225t mindenkit. "
gameforge.locale.monster_chat_20009_4 = "Ir\225ny\237tsd a sz\237ved, mer\252lj el gondolataidban \233s nyugtasd meg lelked. "
gameforge.locale.monster_chat_20009_5 = "Nincs t\233vedhetetlen recept a boldogs\225ghoz, de adhatok n\233mi tan\225csot, ha ragaszkodsz hozz\225. "
gameforge.locale.monster_chat_20010_1 = "Egy j\243 t\225rgyat hoztam. "
gameforge.locale.monster_chat_20010_2 = "\193rucikkek t\225voli orsz\225gokb\243l! Gy\246ny\246r\251, k\252l\246nleges darabok! "
gameforge.locale.monster_chat_20010_3 = "Gyertek ide, gyertek ide! "
gameforge.locale.monster_chat_20010_4 = "Vegy\233tek, vegy\233tek, am\237g van bel\245le. Nincs mindenhol \233s minden nap ilyen! "
gameforge.locale.monster_chat_20010_5 = "T\250l sok tolvaj van ezen a k\246rny\233ken. T\225vol kell tartani \245ket az \225rumt\243l! "
gameforge.locale.monster_chat_20011_1 = "Manaps\225g nagyon sz\225raz itt. "
gameforge.locale.monster_chat_20011_2 = "Az arat\225s m\225r nem olyan j\243, mint kor\225bban. "
gameforge.locale.monster_chat_20011_3 = "Mi g\225tolja a sikert a f\246ldeken? "
gameforge.locale.monster_chat_20011_4 = "A gabonaszem rideg \233s rossz \237z\251. "
gameforge.locale.monster_chat_20011_5 = "Rossz el\245jel. A mez\245gazdas\225g mindennek az alapja. "
gameforge.locale.monster_chat_20012_1 = "Rizs s\252tik! Finom rizs s\252tik! "
gameforge.locale.monster_chat_20012_2 = "\201des rizs s\252tit \225rulok! "
gameforge.locale.monster_chat_20012_3 = "\211, jaj! Az \252zlet rosszul megy. "
gameforge.locale.monster_chat_20012_4 = "Tal\225n egy m\225sik v\225rosban kellene megpr\243b\225lnom. "
gameforge.locale.monster_chat_20012_5 = "De olyan sok vad ragadoz\243 leselkedik errefel\233... "
gameforge.locale.monster_chat_20013_1 = "Egy ilyen napon a haj\243ban lenni a lehet\245 legjobb. "
gameforge.locale.monster_chat_20013_2 = "T\246k\233letes horg\225sz id\245. "
gameforge.locale.monster_chat_20013_3 = "Most egy m\225sik csom\243t... M\225ris jobb! Ezt a horgot nem viszik el a halak! "
gameforge.locale.monster_chat_20013_4 = "Ez a rohadt medve sz\233tt\246rte a pecabotom. "
gameforge.locale.monster_chat_20013_5 = "\218jra meg kellene jav\237tanom a h\225l\243imat. "
gameforge.locale.monster_chat_20014_1 = "Hu! "
gameforge.locale.monster_chat_20014_2 = "Ne agg\243dj miattam. Ilyen vagyok. "
gameforge.locale.monster_chat_20014_3 = "Ha! "
gameforge.locale.monster_chat_20014_4 = "Mit kellene tennem, hogy azok... Jaj, mit mondtam az im\233nt? "
gameforge.locale.monster_chat_20014_5 = "Egyszer\251en nem vagyok b\225tor. "
gameforge.locale.monster_chat_20015_1 = "Ez a fejsze 20 \233ve szolg\225l engem h\251s\233gesen. "
gameforge.locale.monster_chat_20015_2 = "M\233g mindi \233les, de nem olyan j\243, mint kor\225bban. "
gameforge.locale.monster_chat_20015_3 = "Szeretn\233m tov\225bb haszn\225lni, ez\233rt meg kell \233lezni. "
gameforge.locale.monster_chat_20015_4 = "Ehhez k\252l\246nleges \225sv\225nyokra van sz\252ks\233gem. "
gameforge.locale.monster_chat_20015_5 = "De hogy jutok hozz\225? "
gameforge.locale.monster_chat_20016_1 = "Megrohamoznak a v\225s\225rl\243k. "
gameforge.locale.monster_chat_20016_2 = "Rem\233lem, mindent id\245ben befejezek. "
gameforge.locale.monster_chat_20016_3 = "Csap\225s csap\225s h\225t\225n, \233s semmi panaszkod\225s... "
gameforge.locale.monster_chat_20016_4 = "\205gy kell hangzania egy kalap\225cs\252t\233snek! "
gameforge.locale.monster_chat_20016_5 = "Igencsak meleg van itt. "
gameforge.locale.monster_chat_20017_1 = "Nem \233rzem \250gy, hogy hangszeren kellene j\225tszanom. "
gameforge.locale.monster_chat_20017_2 = "A hangszerem rettenetes \225llapotban van. "
gameforge.locale.monster_chat_20017_3 = "Lehet, be kellene szereznem egy \250j hangszert? "
gameforge.locale.monster_chat_20017_4 = "A hangszerem r\233gi \233s kopott... szeretem a r\233gi dolgokat! "
gameforge.locale.monster_chat_20017_5 = "S\252rg\245sen tal\225lnom kell valamit a szakadt h\250rok helyett. "
gameforge.locale.monster_chat_20018_1 = "Olyan elfoglalt vagyok! "
gameforge.locale.monster_chat_20018_2 = "Minden nap \250jabb sebes\252ltek j\246nnek. "
gameforge.locale.monster_chat_20018_3 = "Nincs id\245 priv\225t sz\243rakoz\225sra! "
gameforge.locale.monster_chat_20018_4 = "Kifogyunk a gy\243gyszerb\245l. "
gameforge.locale.monster_chat_20018_5 = "Azt k\237v\225nn\225m, b\225rcsak meg tudna szerezni valaki n\233h\225ny \246sszetev\245t a gy\243gyszerekhez. "
gameforge.locale.monster_chat_20019_1 = "30 \233ve porty\225zok az \237jammal a hegyekben. "
gameforge.locale.monster_chat_20019_2 = "Ezzel t\225mogatom a feles\233gem \233s nevelem h\225rom gyermekem. "
gameforge.locale.monster_chat_20019_3 = "Neh\233z \233let, de meg\233ri. "
gameforge.locale.monster_chat_20019_4 = "De most a h\250r elszakadt. Azt jelenti ez, hogy meg\246regedtem? "
gameforge.locale.monster_chat_20019_5 = "Ha nem tudom megjav\237tani ezt az \237jat, vennem kell m\225sikat. De nincs el\233g p\233nzem r\225. "
gameforge.locale.monster_chat_20020_1 = "H\233! Mit b\225mulsz \250gy? "
gameforge.locale.monster_chat_20020_2 = "Tartsd t\225vol magad t\245lem! "
gameforge.locale.monster_chat_20020_3 = "Oh, mennyi ideig kell m\233g \237gy b\250jk\225lnom? "
gameforge.locale.monster_chat_20020_4 = "Valahol elfelejtve fogok meghalni? "
gameforge.locale.monster_chat_20020_5 = "Rem\233lem seg\237t rajtam valaki! "
gameforge.locale.monster_chat_20021_1 = "Ez a nap is be fog fejez\245dni, mint a t\246bbi. "
gameforge.locale.monster_chat_20021_2 = "Mit tehetek? Hm? "
gameforge.locale.monster_chat_20021_3 = "Soha nem gondoltam volna, hogy \237gy v\233gzem. "
gameforge.locale.monster_chat_20021_4 = "M\233g mindig nem tudom elhinni, hogy nincs t\246bb\233. "
gameforge.locale.monster_chat_20021_5 = "Nem ezt \233rdemli. "
gameforge.locale.monster_chat_20022_1 = "\201s megint egy \250j nap. "
gameforge.locale.monster_chat_20022_2 = "Elt\251nt Ariyoung f\233rje. "
gameforge.locale.monster_chat_20022_3 = "Akartam seg\237teni, de ez a makacss\225g... "
gameforge.locale.monster_chat_20022_4 = "Ha feles\233g\252l j\246tt volna hozz\225m, elfelejthette volna az unalmas \233let\233t. "
gameforge.locale.monster_chat_20022_5 = "Tal\225n jobban ki kellett volna mutanom az \233rz\233seimet. "
gameforge.locale.monster_chat_20023_1 = "\211 nem! Mit csin\225ljak, ha r\225j\246n a feles\233gem? "
gameforge.locale.monster_chat_20023_2 = "B\225rcsak tudn\233k csak k\246nyvolvas\225sb\243l \233lni! "
gameforge.locale.monster_chat_20023_3 = "Minden k\246nyv a saj\225t titokzatos vil\225g\225ba vezet. "
gameforge.locale.monster_chat_20023_4 = "Tudom, hogy nem tudok \246r\246kk\233 \237gy \233lni, de... "
gameforge.locale.monster_chat_20023_5 = "Rem\233lem, tehetek valamit a feles\233gem\233rt, de... "
gameforge.locale.monster_chat_20024_1 = "Gyer\252nk, kell m\233g egy kis er\245fesz\237t\233s! "
gameforge.locale.monster_chat_20024_2 = "Mit csin\225lsz fi\250! Nem megy gyorsabban? "
gameforge.locale.monster_chat_20024_3 = "Csak k\233pzelj el egy harcost, amint felemeli a kardj\225t, \233s tedd ugyanazt! "
gameforge.locale.monster_chat_20024_4 = "Hol van ez a semmirekell\245? Most meg hol van? "
gameforge.locale.monster_chat_20024_5 = "Ez a fatty\250! Nem vagy f\233rfi. Ha! "
gameforge.locale.monster_chat_2091_1 = "V\225gott, v\225gott... haj, torok... "
gameforge.locale.monster_chat_2091_2 = "Van valamim a sz\225modra: \246r\246k \225lom! "
gameforge.locale.monster_chat_2091_3 = "Vegy\233l m\233ly l\233legzetet. Ne agg\243dj, ez csak m\233reg! "
gameforge.locale.monster_chat_2091_4 = "Csak az arcod hagyom meg! Csinos kis dekor\225ci\243 lesz bel\245le... "
gameforge.locale.monster_chat_2091_5 = {}
gameforge.locale.monster_chat_2091_6 = "Selyembe bugyol\225lva finom kis el\245\233tel leszel k\233s\245bb... "
gameforge.locale.monster_chat_2092_1 = "Nem sok maradt r\225nk. "
gameforge.locale.monster_chat_2092_2 = "Itt nincs olyan k\233tl\225b\250 l\233ny, aki \233rv\233nyes\252lhetne. "
gameforge.locale.monster_chat_2092_3 = "Hm, \250gy t\251nik, valakit megfogott a p\243kh\225l\243m. "
gameforge.locale.monster_chat_2092_4 = "B\233k\233s szem\233ly vagyok. Csak nem szeretem, ha felingerelnek. "
gameforge.locale.monster_chat_2092_5 = "Ez minden, amire k\233pes vagy? "
gameforge.locale.monster_chat_2092_6 = "Senki sem m\233rhet\245 hozz\225m! "
gameforge.locale.monster_chat_2104_1 = "Mi\233rt olyan nedvesek bel\252l az emberek? Rozsd\225s lesz t\245le a kardom! "
gameforge.locale.monster_chat_2104_2 = "Nem sz\225radt m\233g ki a m\233reg a full\225nkodban? "
gameforge.locale.monster_chat_2104_3 = "Hogy \225llnak a harcok? "
gameforge.locale.monster_chat_2104_4 = "Ki vagy mer\252lve m\225r a h\245s\233gt\245l? "
gameforge.locale.monster_chat_2104_5 = "Sz\237vesen hagyok h\225tra b\225rkit a sivatagban. "
gameforge.locale.monster_chat_2104_6 = "Szeg\233ny, eltemetve a sivatagban mindenf\233le \252nneps\233g n\233lk\252l... "
gameforge.locale.monster_chat_2105_1 = "El\225rulok egy titkot - ut\225lom a piszkot. "
gameforge.locale.monster_chat_2105_2 = "Forr\243, mi? "
gameforge.locale.monster_chat_2105_3 = "Vesz\233lyes ez a hely. "
gameforge.locale.monster_chat_2105_4 = {}
gameforge.locale.monster_chat_2105_5 = "A szem\246ld\246k\246d k\246z\246tt tal\225llak el. "
gameforge.locale.monster_chat_2106_1 = "\218gy t\251nik, van sz\225momra valami kasz\225lni val\243 errefel\233. "
gameforge.locale.monster_chat_2106_2 = "Ah igen, m\225r l\225tom a k\246vetkez\245 \225ldozatom. "
gameforge.locale.monster_chat_2106_3 = "Tetszik, nagyon tetszik! "
gameforge.locale.monster_chat_2106_4 = "Az egyik ott sz\233p \233s k\246v\233r. Az eny\233m! "
gameforge.locale.monster_chat_2106_5 = {}
gameforge.locale.monster_chat_2106_6 = "Szeretem a v\233r szag\225t. "
gameforge.locale.monster_chat_2107_1 = "Manaps\225g nincs sok \246lni val\243. "
gameforge.locale.monster_chat_2107_2 = "H\233, ezek t\233nyleg k\246v\233rek! "
gameforge.locale.monster_chat_2107_3 = "A vezet\245 szeretni fogja... "
gameforge.locale.monster_chat_2107_4 = {}
gameforge.locale.monster_chat_2107_5 = "L\243b\225ljuk m\233g egy kicsit a l\225bunk! "
gameforge.locale.monster_chat_2107_6 = "Ez a ny\237l csak a tied. "
gameforge.locale.monster_chat_2108_1 = "Ha elkapok egyet, \233n... "
gameforge.locale.monster_chat_2108_2 = "H\233, mi a baj? "
gameforge.locale.monster_chat_2108_3 = "Azt hiszed, hogy k\246nny\251 engem legy\245zni? "
gameforge.locale.monster_chat_2108_4 = "Micsoda pech, itt tal\225lkozni velem a sivatagban! "
gameforge.locale.monster_chat_2108_5 = "Ah, ez az \233rz\233s! \214r\246kk\233 \233lvezni fogom! "
gameforge.locale.monster_chat_2108_6 = "K\246sz\246n\246m! "
gameforge.locale.monster_chat_2191_1 = "Emberszagot \233rzek. Micsoda finom illat! "
gameforge.locale.monster_chat_2191_2 = "Helyes, gyere ide... "
gameforge.locale.monster_chat_2191_3 = {}
gameforge.locale.monster_chat_2191_4 = "Nagyon szerencs\233s vagyok, hogy elt\233vedt\233l, \233s ide keveredt\233l! "
gameforge.locale.monster_chat_2191_5 = "\193llj! "
gameforge.locale.monster_chat_2191_6 = "Apr\243kat fogok harapni a h\250sodb\243l... "
gameforge.locale.monster_chat_2202_1 = "Gyere k\246zelebb, hadd perzseljem meg a b\245r\246d. "
gameforge.locale.monster_chat_2202_2 = "Tudod, milyen f\225jdalmat okozhat a nagy mennyis\233g\251 h\245? "
gameforge.locale.monster_chat_2202_3 = "Tal\225n le kellene h\251tenem a l\225ngol\225som egy kis friss v\233rrel. "
gameforge.locale.monster_chat_2202_4 = "A v\233red... hadd k\243stoljam! "
gameforge.locale.monster_chat_2202_5 = "Nincs \233rtelme hadakozni. "
gameforge.locale.monster_chat_2202_6 = "L\233gy olyan, mint \233n! Csak l\225ng \233s h\245. "
gameforge.locale.monster_chat_2204_1 = "Am\237g itt vagyok, nem j\246n be senki! "
gameforge.locale.monster_chat_2204_2 = "Valami\233rt terhes vagy sz\225momra. "
gameforge.locale.monster_chat_2204_3 = {}
gameforge.locale.monster_chat_2204_4 = "Tudod, hol vagy? "
gameforge.locale.monster_chat_2204_5 = {}
gameforge.locale.monster_chat_2204_6 = "El\233gg\233 sz\225nalmas ellenf\233l vagy sz\225momra! "
gameforge.locale.monster_chat_2205_1 = "A kard csak a harcos kez\233ben hasznos. "
gameforge.locale.monster_chat_2205_2 = "A kardot mindig sz\233pen a k\233zben tartani. "
gameforge.locale.monster_chat_2205_3 = "J\246n a harc. "
gameforge.locale.monster_chat_2205_4 = "\201s most hal\225lunkig harcolunk! "
gameforge.locale.monster_chat_2205_5 = "M\233g tov\225bb akarod \225llni a t\225mad\225sokat? "
gameforge.locale.monster_chat_2205_6 = "Lassan fogsz meghalni. "
gameforge.locale.monster_chat_2206_1 = "A l\225va \233let elix\237r. "
gameforge.locale.monster_chat_2206_2 = "A l\225va engem \233letben tart, t\233ged meg\246l! "
gameforge.locale.monster_chat_2206_3 = "H\225t nem csod\225latos a l\225va ragyog\243 vil\225ga? "
gameforge.locale.monster_chat_2206_4 = "Zavarni mer\233szelsz? "
gameforge.locale.monster_chat_2206_5 = "T\225voznod kellene, ha \233rt\233keled az \233leted. "
gameforge.locale.monster_chat_2206_6 = "Lehet, sajn\225lni fogod, hogy itt vagyok. "
gameforge.locale.monster_chat_2291_1 = "Ez egy sz\233p nap. Minden, amit akarok, az csak egy kis csend \233s nyugalom. "
gameforge.locale.monster_chat_2291_2 = "Semmi sem hasonl\237that\243 a Doyyumhwan-hez. "
gameforge.locale.monster_chat_2291_3 = "Egy kis friss v\233r j\243 v\225ltoz\225st jelentene. "
gameforge.locale.monster_chat_2291_4 = "\218gy t\251nik, keresed a hal\225lt, k\252l\246nben nem zavart\225l volna most meg. "
gameforge.locale.monster_chat_2291_5 = "Sajn\225lod m\225r, hogy megjelent\233l? "
gameforge.locale.monster_chat_2291_6 = "T\250l k\233s\245 menek\252lni. N\233zz szembe a v\233gzeteddel! "
gameforge.locale.monster_chat_301_1 = "Ideges\237t ez a fesz\252lt id\245szak. "
gameforge.locale.monster_chat_301_2 = "K\233t nappal ezel\245tt a vad\225llatok sz\233tmarcangoltak egy fiatal l\225nyt ezen a k\246rny\233ken. "
gameforge.locale.monster_chat_301_3 = "A vad\225llatok egyre agressz\237vebbek. Meg kellene pr\243b\225lnunk le\246lni bel\245l\252k annyit, amennyit csak tudunk. "
gameforge.locale.monster_chat_301_4 = "Ma nincs j\243 kedvem. Az idegenek jobban teszik, ha ma nem keresztezik az utam. "
gameforge.locale.monster_chat_301_5 = "Az utols\243 harcos, akit meg\246ltem, k\246ny\246rg\246tt az \233let\233\233rt. "
gameforge.locale.monster_chat_302_1 = "Valakinek csin\225lnia kellene valamit ezekkel a k\246vekkel. "
gameforge.locale.monster_chat_302_2 = "Nem b\237zom a reggeli b\233kess\233gben. "
gameforge.locale.monster_chat_302_3 = "Nyugtalan\237t ez a fesz\252lts\233g a leveg\245ben. "
gameforge.locale.monster_chat_302_4 = "Ezek a ny\237lhegyek igen j\243l kov\225csoltak. "
gameforge.locale.monster_chat_302_5 = "\201n a helyedben \243vatos lenn\233k. Ez a ny\237l egyenesen a sz\237ved fel\233 tart. "
gameforge.locale.monster_chat_302_6 = "Oda kellene mennem \233s meg\246ln\246m az ilyen vad\225llatokat. "
gameforge.locale.monster_chat_303_1 = "Ezekben az id\245kben elengedhetetlen a j\243 harcm\251v\233szeti k\233pz\233s. "
gameforge.locale.monster_chat_303_2 = "Mi t\246rt\233nik, ha h\237rtelen korm\225ny katon\225k t\246rnek be? "
gameforge.locale.monster_chat_303_3 = "Mi\233rt n\233zel r\225m \237gy? "
gameforge.locale.monster_chat_303_4 = "A gy\225v\225knak kicsi az es\233ly\252k a t\250l\233l\233sre. "
gameforge.locale.monster_chat_303_5 = "Ne becs\252ld t\250l magad. "
gameforge.locale.monster_chat_303_6 = "\218gy t\251nik, t\233ged nagyon j\243l kik\233pzett valaki. "
gameforge.locale.monster_chat_304_1 = "M\233g az \245seim harcolt\225k ki maguknak ezt a ter\252letet. "
gameforge.locale.monster_chat_304_2 = "\211vatosnak \233s gyakorlottnak kell lenned itt. "
gameforge.locale.monster_chat_304_3 = "Ne is gondolj arra, hogy az id\245met vesztegeted. "
gameforge.locale.monster_chat_304_4 = "Sz\243val, milyen \233rz\233s tudni, hogy vesz\233lyben az \233leted? "
gameforge.locale.monster_chat_304_5 = "M\225ris fel akarod adni? "
gameforge.locale.monster_chat_304_6 = "K\233sz\252lj fel a szenved\233sre! "
gameforge.locale.monster_chat_305_1 = "\211! Nagyszer\251en n\233z ki az a kard! "
gameforge.locale.monster_chat_305_2 = "Fejleszd a makacss\225godat, a hatalmad! "
gameforge.locale.monster_chat_305_3 = "Gondolod, hogy olyan er\245s lehetsz, mint \233n? "
gameforge.locale.monster_chat_305_4 = "Na, j\243. Csin\225ljuk komolyan. "
gameforge.locale.monster_chat_305_5 = "Istenem! \201n csak egy gyenge n\245 vagyok! "
gameforge.locale.monster_chat_305_6 = "F\225radtnak t\251nsz. Mi\233rt nem adod fel egyszer\251en? Hehe. "
gameforge.locale.monster_chat_306_1 = "Mit fog ma Serangyi csin\225lni? "
gameforge.locale.monster_chat_306_2 = "\218gy unatkozom. J\225tssz velem! "
gameforge.locale.monster_chat_306_3 = "\201n magam a Sura f\233rfiakat kedvelem. "
gameforge.locale.monster_chat_306_4 = "H\233! Mit sz\243ln\225l egy csat\225hoz? "
gameforge.locale.monster_chat_306_5 = "Ne becs\252lj le az\233rt, mert n\245 vagyok! "
gameforge.locale.monster_chat_306_6 = "A f\225jdalom csak egy pillanatig tart. "
gameforge.locale.monster_chat_307_1 = "B\225rmi \225ron ki akarok innen jutni. "
gameforge.locale.monster_chat_307_2 = "Milyen biztons\225gosak az egyes tagok otthonai? "
gameforge.locale.monster_chat_307_3 = "Ti l\225nyok, fogj\225tok be a sz\225tok! "
gameforge.locale.monster_chat_307_4 = "Hadd int\233zzelek el! Egyetlen \252t\233ssel. "
gameforge.locale.monster_chat_307_5 = "Ne is gondolj a megmenek\252l\233sre! "
gameforge.locale.monster_chat_307_6 = "Sz\243val, mi\233rt nem kezdj\252k el? "
gameforge.locale.monster_chat_394_1 = "Ne feledd: minden ember ellens\233g. "
gameforge.locale.monster_chat_394_2 = "Ha valakinek helyes arca van, tehet\252nk kiv\233telt... "
gameforge.locale.monster_chat_394_3 = "Micsoda, harcolni akarsz? "
gameforge.locale.monster_chat_394_4 = "Nem fog sok\225ig tartani, de nagyon fog f\225jni. "
gameforge.locale.monster_chat_394_5 = "Ah, \250gy l\225tom, er\245s f\225jdalmaid vannak. "
gameforge.locale.monster_chat_394_6 = "Viszl\225t! Most ir\225ny a pokol! "
gameforge.locale.monster_chat_401_1 = "Sz\243val, mit csin\225lsz a Feh\233r esk\252ben? "
gameforge.locale.monster_chat_401_2 = "Hov\225 m\233sz? "
gameforge.locale.monster_chat_401_3 = "H\233! Akarsz harcolni? "
gameforge.locale.monster_chat_401_4 = "Hehe! Kit\233rsz a csap\225saim el\245l...? "
gameforge.locale.monster_chat_401_5 = "Azt hiszed, hogy el tudsz futni el\245lem? "
gameforge.locale.monster_chat_401_6 = "Itt j\246n az \252t\233sem! "
gameforge.locale.monster_chat_402_1 = "Istenem, olyan f\225radt vagyok! "
gameforge.locale.monster_chat_402_2 = "H\233! Sz\233p felszerel\233s. Sokba ker\252lt? "
gameforge.locale.monster_chat_402_3 = "De legal\225bb j\243 az id\245. "
gameforge.locale.monster_chat_402_4 = "Oh, sokat gyakorolt\225l. Remek! "
gameforge.locale.monster_chat_402_5 = "Mit gondolsz a k\233pess\233geimr\245l? J\243k, mi? Hahaha! "
gameforge.locale.monster_chat_402_6 = "Mi van? Oh, Nem b\237rod az \245r\252lt temp\243m?! "
gameforge.locale.monster_chat_403_1 = "Mi\233rt nem megyek vad\225szni? "
gameforge.locale.monster_chat_403_2 = "Ma nincs senki, aki megt\225madn\225 a falunkat. "
gameforge.locale.monster_chat_403_3 = "Ha harcolni akarsz, harcolj! Fatty\250! "
gameforge.locale.monster_chat_403_4 = "Hahaha! De h\225t te amat\245r vagy! "
gameforge.locale.monster_chat_403_5 = "El\245sz\246r a l\225badat, vagy a kezedet tal\225ljam el? "
gameforge.locale.monster_chat_403_6 = "Itt j\246n a nyilam! "
gameforge.locale.monster_chat_404_1 = "Azt\225n valamikor a faluba is le kell mennem gyakorolni. "
gameforge.locale.monster_chat_404_2 = "Nagyon kem\233nynek \233rzem magam. "
gameforge.locale.monster_chat_404_3 = "Mi a mai ennival\243? "
gameforge.locale.monster_chat_404_4 = "N\233zem, sz\243val \252v\246lts nyugodtan, ahogy tudsz. "
gameforge.locale.monster_chat_404_5 = "T\250l sokat v\225rt\225l, hm? Mi lenne ha megforgatn\225d a kardod? "
gameforge.locale.monster_chat_404_6 = "Nagyszer\251en sz\243l ez a kard! "
gameforge.locale.monster_chat_405_1 = "Ez a kard k\233szen \225ll a kezd\233sre! "
gameforge.locale.monster_chat_405_2 = "Megl\225tjuk kire csap le el\245sz\246r a kard... "
gameforge.locale.monster_chat_405_3 = "H\233! Mit b\225mulsz \250gy? "
gameforge.locale.monster_chat_405_4 = "El\245sz\246r a hasad! "
gameforge.locale.monster_chat_405_5 = "\201n a hozz\225d hasonl\243kat haszn\225lom kardh\252velynek. "
gameforge.locale.monster_chat_405_6 = "\201n a hozz\225d hasonl\243kat haszn\225lom kardh\252velynek. "
gameforge.locale.monster_chat_406_1 = "\201hezek! "
gameforge.locale.monster_chat_406_2 = "Van valami ennival\243? "
gameforge.locale.monster_chat_406_3 = "Mi\233rt vagyok m\233g \233hes az ev\233s ut\225n? "
gameforge.locale.monster_chat_406_4 = "Aaaah, halj meg! "
gameforge.locale.monster_chat_406_5 = "A hasam d\246nti el ezt a harcot! "
gameforge.locale.monster_chat_406_6 = "Ez a Menny \233s Pokol k\246z\246tti v\225laszt\225s! "
gameforge.locale.monster_chat_491_1 = "Nem b\237rom tov\225bb! Viszket a testem. "
gameforge.locale.monster_chat_491_2 = "Oh, igen. L\225tok ott p\225r diszn\243t. "
gameforge.locale.monster_chat_491_3 = "M\225ris a f\246ld\246n? "
gameforge.locale.monster_chat_491_4 = "Egy \252t\233ssel elint\233zlek. "
gameforge.locale.monster_chat_491_5 = "Sz\233p eml\233k lesz! "
gameforge.locale.monster_chat_491_6 = "Halj meg! "
gameforge.locale.monster_chat_492_1 = "Megpuhult a testem. "
gameforge.locale.monster_chat_492_2 = "Mi\233rt nem gyakorlok t\246bb\233? "
gameforge.locale.monster_chat_492_3 = "F\233lelem? Hm? "
gameforge.locale.monster_chat_492_4 = "Ah, csak egy \250jabb \225ldozata a forg\243 fegyveremnek! "
gameforge.locale.monster_chat_492_5 = "L\225tod a t\225mad\225si mint\225mat? Nem? Vesztett\233l! "
gameforge.locale.monster_chat_492_6 = "M\233g egy kis v\225g\225s is csorb\237tja az eg\233szs\233get. F\245leg, ha az \233n buzog\225nyom okozta! "
gameforge.locale.monster_chat_493_1 = "Francba, olyan k\233nyelmetlen egy ilyen k\233z. "
gameforge.locale.monster_chat_493_2 = "Mit b\225mulsz m\225r? Nem l\225tt\225l m\233g senkit vas \246k\246llel? "
gameforge.locale.monster_chat_493_3 = "Ti emberek t\233nyleg nagyon zavartok. "
gameforge.locale.monster_chat_493_4 = "\214sszez\250zzalak? Ha ne, akkor ink\225bb szaladj el. Ok\233? "
gameforge.locale.monster_chat_493_5 = "Most bemutatom a nagy \252t\233semet! "
gameforge.locale.monster_chat_493_6 = "Tudom, hogy a kezemet b\225mulod! "
gameforge.locale.monster_chat_494_1 = "H\233, te ott! Ha harcolni akarsz, gyere ide! "
gameforge.locale.monster_chat_494_2 = "Nagyon izgalmasnak tartom magam... "
gameforge.locale.monster_chat_494_3 = "Mi\233rt nem tervez\252nk valamit? "
gameforge.locale.monster_chat_494_4 = "Nem, elmenni m\233g nem szabad. Harcolj! "
gameforge.locale.monster_chat_494_5 = "J\243, hogy meg van neked! "
gameforge.locale.monster_chat_494_6 = "Szinte halott vagy. "
gameforge.locale.monster_chat_501_1 = "J\225tssz velem! Maradj itt! "
gameforge.locale.monster_chat_501_2 = "Tudn\233k faragni valami sz\233pet a csontjaidb\243l... "
gameforge.locale.monster_chat_501_3 = "M\233g semmit nem gyakoroltunk. "
gameforge.locale.monster_chat_501_4 = "\211, micsoda sz\233p felszerel\233s! Ez kell nekem! "
gameforge.locale.monster_chat_501_5 = "Mostant\243l neh\233z lesz figyelmen k\237v\252l hagynod a t\225mad\225som! "
gameforge.locale.monster_chat_501_6 = "Hahaha! Meglepett, mi? "
gameforge.locale.monster_chat_502_1 = "A sz\233ps\233g nem minden. "
gameforge.locale.monster_chat_502_2 = "Ne b\225mulj, harcolj! "
gameforge.locale.monster_chat_502_3 = "Nem \225llhatom, ahogy b\225mulsz. Gyere ide! "
gameforge.locale.monster_chat_502_4 = "Megtiszteltet\233s az \233n kardom \225ltal meghalni! "
gameforge.locale.monster_chat_502_5 = {}
gameforge.locale.monster_chat_502_6 = "Nagyszer\251! "
gameforge.locale.monster_chat_503_1 = "H\233! Ne ny\250lj hozz\225! "
gameforge.locale.monster_chat_503_2 = "Olyan, mintha elszakadt volna a h\250r az \237jamon. "
gameforge.locale.monster_chat_503_3 = "Francba. J\246nnek ezek az idi\243t\225k. "
gameforge.locale.monster_chat_503_4 = "Egy\225ltal\225n nem rossz. Ennek ellen\233re meghalsz! "
gameforge.locale.monster_chat_503_5 = "De te egyet\233rtesz vele? Ez egyszer\251en mennyei! "
gameforge.locale.monster_chat_503_6 = "Itt j\246n a ny\237l! "
gameforge.locale.monster_chat_504_1 = "Mindenki j\246jj\246n ide! "
gameforge.locale.monster_chat_504_2 = "La, lala, f\252ty\246r\233szek egy dalt... "
gameforge.locale.monster_chat_504_3 = "Micsoda sz\233p id\245. "
gameforge.locale.monster_chat_504_4 = {}
gameforge.locale.monster_chat_504_5 = "J\243! \201rt\233kelem a harhoz val\243 hozz\225\225ll\225sodat! "
gameforge.locale.monster_chat_504_6 = "Gyere ide! Mindenki ide hozz\225m! "
gameforge.locale.monster_chat_601_1 = "\218gy ki vagyok \233hezve! "
gameforge.locale.monster_chat_601_2 = "Gy\252m\246lcs\246t szeretn\233k enni. "
gameforge.locale.monster_chat_601_3 = "Nos, a hal j\243t fog tenni. T\225mad\225s! "
gameforge.locale.monster_chat_601_4 = "Nem elfutni! \193llva maradni! "
gameforge.locale.monster_chat_601_5 = "\201n gy\245ztem! Annyira nyilv\225nval\243! "
gameforge.locale.monster_chat_601_6 = "L\225tod? Elszalasztottad! "
gameforge.locale.monster_chat_601_7 = "Meg kellene n\233zned, haha! "
gameforge.locale.monster_chat_602_1 = "Hol vagyok? "
gameforge.locale.monster_chat_602_2 = "Sz\233p id\245 van ma. "
gameforge.locale.monster_chat_602_3 = "Az\233rt j\246ssz, hogy engem vad\225ssz? Nevets\233ges! "
gameforge.locale.monster_chat_602_4 = "Te vagy a k\246vetkez\245 \225ldozatom. "
gameforge.locale.monster_chat_602_5 = "Meglehet\245sen f\225jdalmas, nemde? J\243, gyorsan csin\225lom. "
gameforge.locale.monster_chat_602_6 = "N\233zd milyen er\245s vagyok: Meg tudom l\243b\225lni ezt a hatalmas bunk\243sbotot! "
gameforge.locale.monster_chat_603_1 = "Unalmas! "
gameforge.locale.monster_chat_603_2 = "Az eg\233sz testem viszket. "
gameforge.locale.monster_chat_603_3 = "L\225ssuk, ki a gyorsabb! "
gameforge.locale.monster_chat_603_4 = "Te kezdted! Sz\243val ne engem hib\225ztass a hal\225lod\233rt! "
gameforge.locale.monster_chat_603_5 = "Aki egyszer bel\233p, annak nincs m\225r ki\250t. Most m\225r rem\233nytelen a menek\252l\233s! "
gameforge.locale.monster_chat_603_6 = "Ez lesz az utols\243 \252t\233s. Kicsin\225llak! "
gameforge.locale.monster_chat_604_1 = "K\233sz\237tettem egy finom \250j m\233rget. Ki akarod pr\243b\225lni? "
gameforge.locale.monster_chat_604_2 = "Szeretn\233m megn\233zni a hat\225s\225t! Tess\233k, itt van! "
gameforge.locale.monster_chat_604_3 = "H\233, te ott! Gyere, akarsz a k\237s\233rleti alanyom lenni? "
gameforge.locale.monster_chat_604_4 = "Megm\233rgezlek! "
gameforge.locale.monster_chat_604_5 = "\211 j\243! Egy patk\225ny! "
gameforge.locale.monster_chat_604_6 = "Nem valami sz\243rakoztat\243, ha t\250l gyorsan feladod! Gyer\252nk, v\233dd magad! "
gameforge.locale.monster_chat_631_1 = "Pillanat! Keresek magamnak valami vad\225szni val\243t. "
gameforge.locale.monster_chat_631_2 = "Nem haszn\225lhat\243, ha lass\250 vagy. Mozogj! "
gameforge.locale.monster_chat_631_3 = "Annyira \233hes vagyok! "
gameforge.locale.monster_chat_631_4 = "Milyen nagyszer\251, hogy tal\225ltam valami vad\225szni val\243t! "
gameforge.locale.monster_chat_631_5 = "Adj fel minden rem\233nyt a t\250l\233l\233sre! Nem fogsz t\250l\233lni engem! "
gameforge.locale.monster_chat_631_6 = "Most megtudhatod, mi az igazi f\225jdalom! "
gameforge.locale.monster_chat_632_1 = "Unalmaaas! "
gameforge.locale.monster_chat_632_2 = "Van valami j\243 csalinak val\243? "
gameforge.locale.monster_chat_632_3 = "Gyere \233s harcolj, ha akarsz! "
gameforge.locale.monster_chat_632_4 = "Harcos akarsz lenni? Akkor mutasd meg, mit tudsz! "
gameforge.locale.monster_chat_632_5 = {}
gameforge.locale.monster_chat_632_6 = "Menek\252lj a faluba, ha \233lni akarsz! "
gameforge.locale.monster_chat_633_1 = "Nagyon f\225j az \233hez\233s. "
gameforge.locale.monster_chat_633_2 = "Oh, fel\233nk j\246nnek. "
gameforge.locale.monster_chat_633_3 = "Mit sz\243ln\225l egy p\225rbajhoz? "
gameforge.locale.monster_chat_633_4 = "Ne hasonl\237ts ezekhez a fattyakhoz. "
gameforge.locale.monster_chat_633_5 = "Itt j\246n a mennyd\246rg\233sem! Ha! "
gameforge.locale.monster_chat_633_6 = "Aki most elmenek\252l, az nem val\243di harcos! "
gameforge.locale.monster_chat_634_1 = "Ez\250ttal azonban t\233nyleg j\243nak kell lennie a m\233regnek! "
gameforge.locale.monster_chat_634_2 = "Ha \233hes az ember, akkor csemege a denev\233r! "
gameforge.locale.monster_chat_634_3 = "Mit sz\243ln\225l egy harchoz? "
gameforge.locale.monster_chat_634_4 = "Ha a m\233reg m\225r behatolt a testbe, akkor m\225r nincs gy\243gyul\225s. "
gameforge.locale.monster_chat_634_5 = "Mindent porig \233get a m\225gi\225m, hehehe! "
gameforge.locale.monster_chat_634_6 = "\201gj! Haha! "
gameforge.locale.monster_chat_635_1 = "Soha ne felejtsd el meg\233lezni a kardod! Hamarabb \233rkezik a k\246vetkez\245 \252tk\246zet, mint azt hiszed. "
gameforge.locale.monster_chat_635_2 = "\193jul\225s ker\252lget? "
gameforge.locale.monster_chat_635_3 = "Halj meg, \233s \233bredj a t\250lvil\225gon! "
gameforge.locale.monster_chat_635_4 = "Engem legy\245zni? T\233nyleg? "
gameforge.locale.monster_chat_635_5 = "Csat\225zz, mint egy harcos! "
gameforge.locale.monster_chat_635_6 = "Gyer\252nk, csak m\233g egy kicsit! "
gameforge.locale.monster_chat_636_1 = "Ha, alig v\225rok egy sz\233p k\252zdelmet. "
gameforge.locale.monster_chat_636_2 = "A harc sz\243rakoztat, hahaha! "
gameforge.locale.monster_chat_636_3 = "Harcolj! M\233g, m\233g! Hurr\225! "
gameforge.locale.monster_chat_636_4 = "Ha, nagyon j\243! Pr\243b\225ld \250jra! "
gameforge.locale.monster_chat_636_5 = "N\233zd, hogy forog a kardom! "
gameforge.locale.monster_chat_636_6 = "Megb\225nod, hogy meg\252t\246tt\233l! "
gameforge.locale.monster_chat_636_7 = "Olyan gyenge! Milyen nevets\233ges! "
gameforge.locale.monster_chat_637_1 = "Nem akarom, hogy zavarjanak. "
gameforge.locale.monster_chat_637_2 = "Menj aludni. \214r\246kre! "
gameforge.locale.monster_chat_637_3 = "M\233g mindig nem akarsz aludni? "
gameforge.locale.monster_chat_637_4 = "T\250l sok a tennival\243! Gyer\252nk tov\225bb! "
gameforge.locale.monster_chat_637_5 = "Ne csod\225lkozz a hatalmamon! "
gameforge.locale.monster_chat_637_6 = "Sz\233tporlasztalak! "
gameforge.locale.monster_chat_691_1 = "Nagyszer\251, az er\245s ellenfelek tov\225bb tartanak! V\233dd magad! "
gameforge.locale.monster_chat_691_2 = "Mi? Valami probl\233m\225d van a fiv\233remmel? "
gameforge.locale.monster_chat_691_3 = "Ne hasonl\237ts \246ssze ezzel a kezd\245vel! "
gameforge.locale.monster_chat_691_4 = "Nem szeret t\233ged, \233s \233n sem! "
gameforge.locale.monster_chat_691_5 = "Harcoljunk! "
gameforge.locale.monster_chat_691_6 = "A hal\225lig! "
gameforge.locale.monster_chat_701_1 = "N\233zd, egy pillang\243! Milyen sz\233p! "
gameforge.locale.monster_chat_701_2 = "Nem l\225tod az \233g \233s f\246ld igazs\225g\225t? "
gameforge.locale.monster_chat_701_3 = "K\233s\245bb m\225r t\250l k\233s\245 lesz. Hidd el! "
gameforge.locale.monster_chat_701_4 = "Hidd el az ezot\233ria tanokat! "
gameforge.locale.monster_chat_701_5 = "A k\233ts\233gek el lesznek puszt\237tva! "
gameforge.locale.monster_chat_701_6 = "Nyerd el a megvil\225gosul\225st a hal\225l \225tkarol\225s\225val. "
gameforge.locale.monster_chat_702_1 = "Az ezoterikus hit igazs\225ga az \233gi rend meg\233rt\233s\233ben rejlik. "
gameforge.locale.monster_chat_702_2 = "Ezot\233rikus kit filoz\243fi\225ja az \233g rendje. "
gameforge.locale.monster_chat_702_3 = "Ezoterikus igazs\225g, Tigrisisten igazs\225ga, Sabaha Sabaha. "
gameforge.locale.monster_chat_702_4 = "Szembesz\225llsz az \233g \233s f\246ld igazs\225g\225nak k\233ts\233gbev\233tel\233vel! "
gameforge.locale.monster_chat_702_5 = {}
gameforge.locale.monster_chat_702_6 = "\201rezd a karmaim! "
gameforge.locale.monster_chat_703_1 = "Amikor a Tigrisisten igazs\225ga \246r\246kk\233 zengeni fog, v\233get \233r minden b\225nat. "
gameforge.locale.monster_chat_703_2 = "Az ezoterikus hit igazs\225ga az \233gi rend meg\233rt\233s\233ben rejlik. "
gameforge.locale.monster_chat_703_3 = "Sabaha Sabaha. K\252ldj nek\252nk meg\233rt\233st! "
gameforge.locale.monster_chat_703_4 = "Ne k\233telkedj! "
gameforge.locale.monster_chat_703_5 = "Fogadd az \233g d\246rg\233s\233t! "
gameforge.locale.monster_chat_703_6 = "Az \237t\233let csap\225sa. "
gameforge.locale.monster_chat_704_1 = "Az ezoterikus hit igazs\225ga az \233gi rend meg\233rt\233s\233ben rejlik. "
gameforge.locale.monster_chat_704_2 = "Ezoterikus igazs\225g, Tigrisisten igazs\225ga, Sabaha Sabaha. "
gameforge.locale.monster_chat_704_3 = "Azt hiszed, bolondozok, ugye? M\225r nem sok\225ig! "
gameforge.locale.monster_chat_704_4 = "A szekta vezet\245je egy szent \233s minden el\245l\233ny felett \225ll. "
gameforge.locale.monster_chat_704_5 = "Hozd el a pokol t\252z\233t! "
gameforge.locale.monster_chat_704_6 = "Fogadok, hogy m\233g sohasem l\225tt\225l ilyen nagy hangvill\225t ezel\245tt, mi? "
gameforge.locale.monster_chat_705_1 = "Ezoterikus igazs\225g, Tigrisisten igazs\225ga, Sabaha Sabaha. "
gameforge.locale.monster_chat_705_2 = "Az ezoterikus hit igazs\225ga az \233gi rend meg\233rt\233s\233ben rejlik. "
gameforge.locale.monster_chat_705_3 = "Csak az\233rt, mert kisebb vagyok a fiv\233remn\233l, m\233g nem adok fel mindent! "
gameforge.locale.monster_chat_705_4 = "\214r\246k\246s f\225jdalom \233s s\246t\233ts\233g v\225r r\225d! "
gameforge.locale.monster_chat_705_5 = {}
gameforge.locale.monster_chat_705_6 = "Ez nem a v\233ge. Egyre jobb lesz. "
gameforge.locale.monster_chat_706_1 = "B\233k\233t \233s nyugalmat k\233r\252nk! "
gameforge.locale.monster_chat_706_2 = "Ha a f\233lelem uralkodik, seg\237t a Tigrisisten igazs\225ga. "
gameforge.locale.monster_chat_706_3 = "Az ezot\233ria hit igazs\225ga az \233g \233s f\246ld meg\233rt\233se \233s rendje. "
gameforge.locale.monster_chat_706_4 = "Hadd menj\252nk mindny\225jan a pokolba! "
gameforge.locale.monster_chat_706_5 = "Nem hagylak elmenni! "
gameforge.locale.monster_chat_706_6 = "Mindent neked adok amim csak van! "
gameforge.locale.monster_chat_707_1 = "K\246ny\246rg\246k. Ments meg minket! "
gameforge.locale.monster_chat_707_2 = "Az ezoterikus hit igazs\225ga az \233gi rend meg\233rt\233s\233ben rejlik. "
gameforge.locale.monster_chat_707_3 = "Ezoterikus igazs\225g, Tigrisisten igazs\225ga, Sabaha Sabaha. "
gameforge.locale.monster_chat_707_4 = "(Hangos nevet\233s) A pokol kapuja nyitva \225ll. Halj meg! "
gameforge.locale.monster_chat_707_5 = "Figyelmeztetlek: Ne k\233nyszer\237ts, hogy haszn\225ljam a t\225bl\225t! "
gameforge.locale.monster_chat_707_6 = "M\225r l\225tom is hal\225lod! "
gameforge.locale.monster_chat_791_1 = "Hogyan tudn\225m neked r\246viden elmes\233lni az \233g \233s f\246ld rendj\233t? "
gameforge.locale.monster_chat_791_2 = "Hallom a h\237v\245k \233nek\233t. "
gameforge.locale.monster_chat_791_3 = "\205gy van! B\225nj meg mindent. Meg leszel mentve. "
gameforge.locale.monster_chat_791_4 = "Az \246r\246k f\225jdalomt\243l szenvedsz, mert k\233telkedsz az igaz tan\237t\225sban. "
gameforge.locale.monster_chat_791_5 = "Engedd, hogy tov\225bb oktassalak. "
gameforge.locale.monster_chat_791_6 = "Nem tekintheted f\225jdalomnak. Ez egy ok\237t\225s. "
gameforge.locale.monster_chat_901_1 = "Lehet, hogy nem vagyok sz\233p, de van egy csom\243 viccem, hihihi! "
gameforge.locale.monster_chat_901_2 = "Olyannak kell lenned, mint mi vagyunk! "
gameforge.locale.monster_chat_901_3 = "Gyere \225t hozz\225nk, hihihi! "
gameforge.locale.monster_chat_901_4 = "Haaa, haha! "
gameforge.locale.monster_chat_901_5 = "\201s kezd\245dik! "
gameforge.locale.monster_chat_903_1 = "Ez pokol! "
gameforge.locale.monster_chat_903_2 = "Ahhhh! "
gameforge.locale.monster_chat_903_3 = "Nem tudjuk ezt egyed\252l ki\225llni! Nem! "
gameforge.locale.monster_chat_903_4 = "\205zlenie kell neked ezeknek a f\225jdalmaknak! "
gameforge.locale.monster_chat_903_5 = "Mi a helyzet a cser\233vel? Te nekem adod a lelked, \233n \225tadom neked a szenved\233sem! "
gameforge.locale.monster_chat_903_6 = "Mindj\225rt megtal\225lod az \246r\246k b\233kess\233get! "
gameforge.locale.monster_chat_904_1 = "F\225j! F\225j! "
gameforge.locale.monster_chat_904_2 = "Aargghh, francba! \201g a karom! "
gameforge.locale.monster_chat_904_3 = "Mi\233rt kell szenvedn\252nk? Mi\233rt? "
gameforge.locale.monster_chat_904_4 = "Nem olyan rossz a rejt\233lyes betegs\233gben szenvedni. "
gameforge.locale.monster_chat_904_5 = {}
gameforge.locale.monster_chat_904_6 = "Ahhhh! "
gameforge.locale.monster_chat_905_1 = "Ahhhh! "
gameforge.locale.monster_chat_905_2 = "Teeee, meg\246lleeeek! "
gameforge.locale.monster_chat_905_3 = "Ne csak b\225mulj. Seg\237ts! "
gameforge.locale.monster_chat_905_4 = "Legy\252nk bar\225tok! "
gameforge.locale.monster_chat_905_5 = "Te m\225r fert\245z\246tt vagy. "
gameforge.locale.monster_chat_905_6 = "Most a bar\225tom vagy. "
gameforge.locale.monster_chat_906_1 = "Hihihi! "
gameforge.locale.monster_chat_906_2 = "Gyere csak \233s sz\250rd fel magad a nyilamra. "
gameforge.locale.monster_chat_906_3 = "T\233nyleg nagyon ideges\237t\245 vagy! "
gameforge.locale.monster_chat_906_4 = "Meg foglak fert\245zni a rejt\233lyes betegs\233ggel. "
gameforge.locale.monster_chat_906_5 = "Fincsi illat! "
gameforge.locale.monster_chat_906_6 = "Halj meg! "
gameforge.locale.monster_chat_907_1 = "\201s ha tal\225lok egy m\225sik k\243rokoz\243t... "
gameforge.locale.monster_chat_907_2 = "(Kacaj) Vicces lesz. "
gameforge.locale.monster_chat_907_3 = "Hmm, korb\225cs vagy fog\243...? "
gameforge.locale.monster_chat_907_4 = "Ahhhhh, igeeeeen! "
gameforge.locale.monster_chat_907_5 = "Hadd fert\245zzelek meg ezzel a k\243rokoz\243val! "
gameforge.locale.monster_chat_907_6 = "Ez a makacs k\243rokoz\243ja a rejt\233lyes betegs\233gnek! "
