gameforge.locale.old_pirate.baekgo_accept_success_say_2 = "Van egy k\243rokoz\243 mint\225m a rejt\233lyes betegs\233gb\245l.[ENTER]El kellene vinnem Baek-Go-nak. "
gameforge.locale.old_pirate.baekgo_do_you_get_the_virus = "Nem tudom mi \225ll a rejt\233lyes betegs\233g m\246g\246tt. "
gameforge.locale.old_pirate.baekgo_iv_got_the_virus = "Megtal\225ltam a rejt\233lyes betegs\233g k\243rokoz\243j\225t. "
gameforge.locale.old_pirate.baekgo_order_find_virus_label = "\214lj meg minden fert\245z\245d\246tt szem\233lyt "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_1 = "\214lj meg mindenkit, aki a rejt\233lyes betegs\233gt\245l[ENTER]megfert\245z\245d\246tt! "
gameforge.locale.old_pirate.baekgo_order_find_virus_text_2 = "\214lj meg mindenkit, aki a rejt\233lyes betegs\233g[ENTER]k\243rokoz\243j\225t mag\225n hordja, \233s hozz egy mint\225t a[ENTER]k\243rokoz\243b\243l Baek-Go-nak. Gy\243gyszert fog k\233sz\237teni[ENTER]az \214reg kal\243z sz\225m\225ra. "
gameforge.locale.old_pirate.baekgo_order_too_late = "Baek-Go:[ENTER]Valaki m\225s m\225r hozott k\243rokoz\243 mint\225t. Elk\252ldtem[ENTER]a gy\243gyszert az \246reg kal\243znak, most m\225r jobban[ENTER]kell lennie. "
gameforge.locale.old_pirate.baekgo_start_say = "Baek-Go:[ENTER]Csak egyszer tal\225lkozott fert\245z\246tt szem\233llyel, \233s[ENTER]azt\225n elkezdett a sebe gennyezni \233s viszketni?! "
gameforge.locale.old_pirate.baekgo_start_say2 = "Baek-Go:[ENTER]Istenem! Szinte biztos, hogy ebben a rejt\233lyes[ENTER]betegs\233gben szenved! Ha nem kezelik, sz\233tterjed a[ENTER]betegs\233g az eg\233sz faluban! "
gameforge.locale.old_pirate.baekgo_start_say3 = "Baek-Go:[ENTER]Senkit sem szabad megfert\245znie! Azonnal kezelned[ENTER]kell. Ehhez sz\252ks\233g\252nk van egy k\243rokoz\243 mint\225ra a[ENTER]rejt\233lyes betegs\233gb\245l. Ezt a mint\225t egy betegt\245l[ENTER]tudod megszerezni. Nagy sz\225mban vannak ilyenek[ENTER]\233szakon, a Sohan-hegyen. "
gameforge.locale.old_pirate.baekgo_success_say = "Baek-Go:[ENTER]Megcsin\225ltad! V\225rj egy percet, azonnal elk\233sz\237tem[ENTER]a gy\243gyszert! [DELAY value;1000] [/DELAY][ENTER][ENTER]Annyira siettem, hogy nem tudom, t\233nyleg hat-e,[ENTER]de legal\225bb jobban lesz t\245le. Vidd el neki ezt a[ENTER]gy\243gyszert amilyen gyorsan csak lehet! "
gameforge.locale.old_pirate.baekgo_talk = "Az \214reg kal\243z k\252ld\246tt. "
gameforge.locale.old_pirate.baekgo_talk_about_old_pirate = "Az \214reg kal\243z betegs\233ge "
gameforge.locale.old_pirate.complete_say = "\214reg kal\243z:[ENTER]M\233g mindig viszket. De az\233rt m\225r jobban \233rzem[ENTER]magam. \205gy az\233rt tudok \233lni. "
gameforge.locale.old_pirate.do_you_get_the_medicine = "M\233g nincs meg az orvoss\225g. "
gameforge.locale.old_pirate.do_you_mean_this_medicine = "Itt van az orvoss\225g! "
gameforge.locale.old_pirate.etc_shop_start_say = "Vegyeskeresked\245 elad\243n\245:[ENTER]Az \246reg kal\243z? Persze, hogy ismerem. Arr\243l az[ENTER]\246r\246kk\233 szitkoz\243d\243 fick\243r\243l besz\233lsz, aki[ENTER]\225lland\243an vakar\243zik, nem? Gyakran j\225r erre, hogy[ENTER]foly\233kony gy\243gyszert vegyen. M\225r sok ezer Yangot[ENTER]adott ki a v\246r\246s gy\243gyszerre. "
gameforge.locale.old_pirate.etc_shop_start_say2 = "Vegyeskeresked\245 elad\243n\245:[ENTER]Honnan a b\250b\225natb\243l szerez \245 annyi Yangot, ha m\233g[ENTER]csak nem is dolgozik? M\225r sokszor mondtam neki,[ENTER]hogy vizsg\225ltassa meg mag\225t orvossal, de nem[ENTER]hallgat r\225m.[ENTER]A v\246r\246s gy\243gyszer csak a t\252neteket cs\246kkenti, de[ENTER]nem gy\243gy\237tja meg a betegs\233get. Att\243l f\233lek,[ENTER]cs\250ny\225n fogja v\233gezni. "
