gameforge.locale.old_pirate.order_find_medicine_label = "Gy\243gyszer az \214reg kal\243znak "
gameforge.locale.old_pirate.order_find_medicine_text_1 = "Szerezz gy\243gyszert az \214reg kal\243znak. "
gameforge.locale.old_pirate.order_find_medicine_text_2 = "Menj Baek-Go-hoz a v\225rosban, \233s k\233rdezd meg az[ENTER]\214reg kal\243z gy\243gyszer\233r\245l. "
gameforge.locale.old_pirate.order_refuse = "Sajn\225lom, de nem tudom. "
gameforge.locale.old_pirate.order_refuse_answer = "\214reg kal\243z:[ENTER]Nos, akkor nincs t\246bb mondanival\243m a sz\225modra! "
gameforge.locale.old_pirate.order_say1 = "\214reg kal\243z:[ENTER]Basszus, mit akarsz t\245lem? Francba! Az a[ENTER]nyavaly\225s vegyeskeresked\245 besz\233lt r\243lam, ugye?[ENTER]Igen, minden igaz, amit mond. De nincs id\245m[ENTER]orvoshoz menni. Annyi ellens\233gem van! "
gameforge.locale.old_pirate.order_say2 = "\214reg kal\243z:[ENTER]Sohasem tudhatja az ember, hogy nem \225ll-e el\233 egy[ENTER]csavarg\243 hirtelen \233s d\246fi le egyszer\251en! De olyan[ENTER]sz\246rnyen viszket, hogy nem b\237rom m\225r. Tudod mit?[ENTER]El tudn\225l menni az orvoshoz, \233s viszket\233s elleni[ENTER]szert hozni nekem? Ha hozol orvoss\225got, b\245s\233gesen[ENTER]megjutalmazlak. "
gameforge.locale.old_pirate.order_too_late = "\214reg kal\243z:[ENTER]Valaki m\225s m\225r hozott nekem orvoss\225got. Nos,[ENTER]att\243l tartok, \237gy jutalom sem j\225r neked! "
