gameforge.locale.old_pirate.start_find_old_pirate_text_1 = "Menj az \246reg kal\243zhoz. "
gameforge.locale.old_pirate.start_find_old_pirate_text_2 = "Menj az \246reg kal\243zhoz \233s k\233rdezd meg, hogy mi\233rt[ENTER]nem megy orvoshoz! "
gameforge.locale.old_pirate.start_say = "\214reg kal\243z:[ENTER]Mindenhol viszketek! Nem lett volna szabad[ENTER]\246sszefutnom azzal a fick\243val! Csak egyetlen[ENTER]\233rint\233s volt! Az\243ta gennyezik a helye \233s viszket[ENTER]az eg\233sz testem! Olyan, mintha \233lve rothadn\233k.[ENTER]Rohad\233k! "
gameforge.locale.old_pirate.success_thanks = "\214reg kal\243z:[ENTER]Mi? Meg voltam fert\245zve a rejt\233lyes betegs\233ggel?![ENTER]\201s ez a sz\252ks\233ges orvoss\225g? Nagyon, nagyon sz\233pen[ENTER]k\246sz\246n\246m! Megmentetted az \233letem! Nagyra[ENTER]\233rt\233kelem! "
