gameforge.locale.questscroll5.mission_10_hunt = "Az \233hes medv\233k vonul\225sa "
gameforge.locale.questscroll5.mission_10_mis = "Vad\225ssz le 25 Fekete medv\233t \233s 25 Grizzly medv\233t. "
gameforge.locale.questscroll5.mission_10_text = "Oh, k\233rlek seg\237ts. Az ut\243bbi id\245ben egyre t\246bb[ENTER]Grizzly \233s Fekete medve tizedeli a[ENTER]m\233hkapt\225rainkat \233s \252ltetv\233nyeinket. K\233rlek,[ENTER]seg\237ts, \246ld meg ezeket a besti\225kat, k\252l\246nben \233hen[ENTER]halunk! "
gameforge.locale.questscroll5.mission_11_hunt = "A k\233kfarkasok vihara "
gameforge.locale.questscroll5.mission_11_mis = "Vad\225ssz le 35 k\233kfarkast \233s 25 alfa k\233kfarkast. "
gameforge.locale.questscroll5.mission_11_text = "Hallott\225l m\225r a K\233kfarkas torn\225d\243r\243l?[ENTER]Ez a K\233kfarkasok gaztetteit jelenti az ut\243bbi[ENTER]id\245kben. Megsemmis\237tenek mindent, ami az \250tjukba[ENTER]ker\252l, mintha egy vihar lenne bund\225b\243l \233s[ENTER]fogakb\243l.[ENTER]Meg tudod f\233kezni ezt a vihart? "
gameforge.locale.questscroll5.mission_12_hunt = "A feh\233r sereg sz\225m\251z\233se "
gameforge.locale.questscroll5.mission_12_mis = "Vad\225ssz le 20 Feh\233r esk\252 parancsnokot. "
gameforge.locale.questscroll5.mission_12_text = "Az ut\243bbi id\245ben a Feh\233r esk\252 sok bossz\250s\225got[ENTER]okozott. Gyakran kaptak el utaz\243 keresked\245ket \233s[ENTER]sok k\225rt okoztak a faluban. K\233rlek, tart\243ztasd[ENTER]fel \245ket! \214ld meg a tagjait \233s vezet\245it! "
gameforge.locale.questscroll5.mission_13_hunt = "Nyugtalan Feketesz\233l. "
gameforge.locale.questscroll5.mission_13_mis = "Vad\225ssz le 25 Jak-To-t \233s 25 To-Su-t a Feketesz\233l[ENTER]band\225b\243l. "
gameforge.locale.questscroll5.mission_13_text = "Azt mondj\225k, hogy a Feketesz\233l banda \225t akarja[ENTER]venni a hatalmat a birodalomban. Miel\245tt meg[ENTER]tudn\225k er\245s\237teni a hadsereg\252ket, el kellene[ENTER]t\252ntetn\252nk a vezet\245iket.[ENTER]K\233rlek tedd ezt meg, t\252ntesd el a vezet\245iket. "
gameforge.locale.questscroll5.mission_14_hunt = "Nagy ork felkel\233s 1 "
gameforge.locale.questscroll5.mission_14_mis = "Vad\225ssz le 30 B\252szke orkot \233s 30 B\252szke ork k\233met. "
gameforge.locale.questscroll5.mission_14_text = "Titkos inform\225ci\243k arra utalnak, hogy az orkok[ENTER]vez\233re a Seungryong-v\246lgyben a semleges \246vezetben[ENTER]tervezi a vil\225g megh\243d\237t\225s\225t. Arra k\233rlek, hogy[ENTER]ellen\245rizd ezt az inform\225ci\243t. \201s hogy az utaz\225s[ENTER]hasznos is legyen, szabadulj meg n\233h\225ny orkt\243l,[ENTER]am\237g ott vagy. "
gameforge.locale.questscroll5.mission_15_hunt = "Vadak t\225mad\225sa "
gameforge.locale.questscroll5.mission_15_mis = "Vad\225ssz le 30 Vad gyalogs\225gi katon\225t \233s 30 Vad[ENTER]kegyencet. "
gameforge.locale.questscroll5.mission_15_text = "A vadak egy elfogott k\233me fontos inform\225ci\243kat[ENTER]\225rult el. A vadak egy birodalom elleni t\225mad\225son[ENTER]gondolkodnak. Nek\252nk kell t\225madnunk, miel\245tt \245k[ENTER]teszik meg. Mutasd meg a birodalomhoz val\243[ENTER]h\251s\233gedet. "
gameforge.locale.questscroll5.mission_16_hunt = "A s\246t\233ts\233g Metinj\233nek megsemmis\237t\233se "
gameforge.locale.questscroll5.mission_16_mis = "Megsemmis\237teni 3 S\246t\233ts\233g metinj\233t. "
gameforge.locale.questscroll5.mission_16_text = "Mostan\225ban elkezdtek k\246vek potyogni a v\225ros[ENTER]k\246zel\233ben. A vizsg\225latok azt mutatj\225k, hogy a Chi[ENTER]ezekben a k\246vekben az \225llatok megvadul\225s\225hoz[ENTER]vezet. T\246rd \246ssze ezeket a k\246veket, erre k\233rlek.[ENTER]Megfelel\245en megjutalmazlak er\245fesz\237t\233seid\233rt. "
gameforge.locale.questscroll5.mission_17_hunt = "A Fekete Metinj\233nek megsemmis\237t\233se "
