gameforge.locale.questscroll5.mission_47_hunt = "J\233g sz\246rnyek! Val\243di l\233ny\252k "
gameforge.locale.questscroll5.mission_47_mis = "Vad\225ssz le 45 Elvar\225zsolt jeget. "
gameforge.locale.questscroll5.mission_47_text = "Megtudtuk, hogyan kommunik\225lnak egym\225ssal a[ENTER]Sohan-hegyen l\233v\245 sz\246rnyek: a mindenfel\233[ENTER]megtal\225lhat\243 lebeg\245 j\233gszil\225nkok seg\237ts\233g\233vel[ENTER]adj\225k \225t az inform\225ci\243t. A J\233gf\246ld csapatainak[ENTER]gyeng\237t\233s\233hez meg kell zavarnunk az inform\225ci\243[ENTER]tov\225bb\237t\225s\225t. Ez\233rt k\233r\252nk: Puszt\237ts Elvar\225zsolt[ENTER]jeget! "
gameforge.locale.questscroll5.mission_48_hunt = "A D\233mon-torony titka "
gameforge.locale.questscroll5.mission_48_mis = "\214lj meg 45 Kegyetlen (Kegy.) szellem-l\225ndzs\225st. "
gameforge.locale.questscroll5.mission_48_text = "Pletyk\225k keringnek arr\243l, hogy a D\233mon-toronyban[ENTER]l\233v\245 Gonosz l\225ndzs\225sok legy\245zhetetlenek. \218gy[ENTER]t\251nik, minden alkalommal felt\225madnak, miut\225n[ENTER]elpusztultak. Ha ez igaz, s\246t\233t id\245k v\225rnak r\225nk.[ENTER]K\233rlek, tudj meg err\245l t\246bbet! "
gameforge.locale.questscroll5.mission_49_hunt = "A D\233mon-torony Mestere. "
gameforge.locale.questscroll5.mission_49_mis = "\214lj meg 60 Kegyetlen szellem-s\225m\225nt. "
gameforge.locale.questscroll5.mission_49_text = "Kiterjedt kutat\225s ut\225n vett\233k \233szre, hogy a[ENTER]szellemkaton\225k \225lland\243an \250jj\225\233lednek. Meg kell[ENTER]semmis\237ten\252nk a Kegyetlen szellem-s\225m\225nokat, hogy[ENTER]megakad\225lyozzuk ezt. "
gameforge.locale.questscroll5.mission_4_hunt = "A Sz\252rkefarkasok felt\251n\233se 1 "
gameforge.locale.questscroll5.mission_4_mis = "Vad\225ssz le 35 Sz\252rkefarkast. "
gameforge.locale.questscroll5.mission_4_text = "Hallott\225l m\225r a Sz\252rkefarkasokr\243l? A maguk \250tj\225t[ENTER]szokt\225k j\225rni, de a gonosz Chi hat\225s\225ra az ut\243bbi[ENTER]hetekben utaz\243k sor\225t t\225madt\225k meg. Meg tudn\225d[ENTER]\225ll\237tani ezeket a sz\252rkefarkasokat? Meg leszel[ENTER]jutalmazva \233rte. "
gameforge.locale.questscroll5.mission_50_hunt = "A T\251zf\246ld felder\237t\233se "
gameforge.locale.questscroll5.mission_50_mis = "Vad\225ssz le 45 Harci tigris szolg\225t. "
gameforge.locale.questscroll5.mission_50_text = "A T\251zf\246ld egy l\225v\225s ter\252let, ami m\233g ismeretlen[ENTER]sz\246rnyekkel van ben\233pes\252lve. Fel kell fedezn\252nk[ENTER]ezt a ter\252letet.[ENTER]Tudsz nek\252nk seg\237teni? "
gameforge.locale.questscroll5.mission_51_hunt = "L\225ngszellem! Az \245 identit\225sa "
gameforge.locale.questscroll5.mission_51_mis = "\214lj meg 45 L\225ngszellemet. "
gameforge.locale.questscroll5.mission_51_text = "A csoportot, amelynek a Harci tigriseket kellett[ENTER]volna kiirtania, megsemmis\237tette egy ismeretlen[ENTER]ellens\233g. A sz\243besz\233d szerint ez az ellens\233g[ENTER]\"l\225ngol\243 l\225nyok\"-k\233nt n\233z ki. Der\237tsd ki az[ENTER]igazs\225got. "
gameforge.locale.questscroll5.mission_52_hunt = "Cs\246kkentsd a Harci tigrisek sz\225m\225t! "
gameforge.locale.questscroll5.mission_52_mis = "Vad\225ssz le 60 Harci tigris szolg\225t \233s 40 Harci[ENTER]tigrist. "
gameforge.locale.questscroll5.mission_52_text = "Most, hogy harcolhatunk a L\225ng szellemekkel,[ENTER]teljesen meg kell \245ket semmis\237teni ny\237lt[ENTER]csat\225ban. Az ehhez hasonl\243 k\252ldet\233sekr\245l[ENTER]\225ltal\225ban a hadsereg gondoskodott, de a[ENTER]legnagyobb csata erej\233hez a L\225ng szellemekkel[ENTER]szemben jobb technik\225ra van sz\252ks\233g\252nk.[ENTER]K\233r\252nk, gy\245z\245dj meg r\243la, hogy a Harci tigrisek[ENTER]nem \225llnak az utunkba. "
gameforge.locale.questscroll5.mission_53_hunt = "Tanulm\225nyozd a L\225ngokat "
gameforge.locale.questscroll5.mission_53_mis = "Vad\225ssz le 40 L\225ngot. "
gameforge.locale.questscroll5.mission_53_text = "A L\225ngok hihetetlen\252l brut\225lisak. Gy\246ny\246rk\246dnek[ENTER]az emberek f\225jdalm\225ban, akik b\245r\233t \233getik. M\233g[ENTER]nem tudjuk, hogyan tudn\225nk \245ket kiiktatni.[ENTER]Seg\237ten\233l t\246bbet megtudni ezekr\245l a L\225ngokr\243l? "
gameforge.locale.questscroll5.mission_54_hunt = "L\225ngharcos "
gameforge.locale.questscroll5.mission_54_mis = "Iktass ki 60 l\225ngharcost. "
gameforge.locale.questscroll5.mission_54_text = "R\246viddel ezel\245tt, egy T\251zf\246ld\246n j\225r\243 nemes[ENTER]gyerek\233t \246lte meg egy l\225ngharcos. Ha meg\246l\246d a[ENTER]l\225ngharcosokat, jutalomban r\233szes\252lsz. Mi\233rt nem[ENTER]pr\243b\225lod meg? "
gameforge.locale.questscroll5.mission_55_hunt = "A Szellemf\225k vizsg\225lata "
gameforge.locale.questscroll5.mission_55_mis = "Semmis\237ts meg 30 Szellemf\225t "
gameforge.locale.questscroll5.mission_55_text = "\218gy szoktak \225llni, mint egy fa \233s hirtelen[ENTER]t\225madnak meg \225llatot \233s embert. Tal\225ld ki, hogyan[ENTER]lehet a Szellemf\225kat megsemmis\237teni. "
gameforge.locale.questscroll5.mission_56_hunt = "A Szellem-erd\245 titka "
gameforge.locale.questscroll5.mission_56_mis = "Vad\225ssz le 40 Szellem tusk\243t \233s 30 T\252nd\233rt. "
gameforge.locale.questscroll5.mission_56_text = "Kutat\225sok azt mutatj\225k, hogy a szellem erd\245 egy[ENTER]olyan ter\252let, ahol Szellem tusk\243k \233s T\252nd\233rek[ENTER]domin\225lnak. Ha megsemmis\237ted \245ket, akkor tal\225n[ENTER]meg tudod akad\225lyozni a Szellemf\225k tov\225bbi[ENTER]terjeszked\233s\233t. "
gameforge.locale.questscroll5.mission_5_hunt = "Aggodalom a falusiak ir\225nt "
gameforge.locale.questscroll5.mission_5_mis = "Vad\225ssz le 40 Vaddiszn\243t "
gameforge.locale.questscroll5.mission_5_text = "A v\225ros k\246zel\233ben \233l\245 falusiak aggodalma megn\245tt[ENTER]az ut\243bbi id\245ben. Vaddiszn\243k, amik eddig[ENTER]legfeljebb apr\243 \225llatokat t\225madtak meg a[ENTER]hegyekben, agressz\237vak lettek.[ENTER]lkezdtek bet\246rni a f\246ldekre \233s megt\225madj\225k a[ENTER]parasztokat. Meg tudod f\233kezni ezeket a[ENTER]vaddiszn\243kat? "
gameforge.locale.questscroll5.mission_6_hunt = "Tigrisek \233s Medv\233k "
gameforge.locale.questscroll5.mission_6_mis = "Vad\225ssz le 25 tigris \233s 30 medv\233t. "
gameforge.locale.questscroll5.mission_6_text = "Hallottad m\225r? Ha a tigrisek \233s medv\233k 100 napig[ENTER]csak hagym\225t \233s fokhagym\225t esznek, akkor nagy[ENTER]Tigriss\233 \233s T\251zmedv\233v\233 v\225ltoznak. Biztos vagyok[ENTER]benne, hogy ezel\245tt sohasem fordult m\233g el\245[ENTER]ilyen, de nem \225rthat leellen\245rizni. Vad\225ssz le[ENTER]n\233h\225ny Tigrist \233s Medv\233t, vizsg\225ld meg, mi van a[ENTER]gyomrukban! "
gameforge.locale.questscroll5.mission_7_hunt = "A Kapzsis\225g metinj\233nek sz\233trombol\225sa "
gameforge.locale.questscroll5.mission_7_mis = "A Kapzsis\225g 2 Metinj\233nek sz\233trombol\225sa "
gameforge.locale.questscroll5.mission_7_text = "Mostan\225ban elkezdtek k\246vek potyogni a v\225ros[ENTER]k\246zel\233ben. A vizsg\225latok azt mutatj\225k, hogy a Chi[ENTER]ezekben a k\246vekben az \225llatok megvadul\225s\225hoz[ENTER]vezet. T\246rd \246ssze ezeket a k\246veket, erre k\233rlek.[ENTER]Megfelel\245en megjutalmazlak er\245fesz\237t\233seid\233rt. "
gameforge.locale.questscroll5.mission_8_hunt = "A Csata Metinj\233nek sz\233trombol\225sa "
gameforge.locale.questscroll5.mission_8_mis = "A Csata 2 Metinj\233nek sz\233trombol\225sa "
gameforge.locale.questscroll5.mission_8_text = "Mostan\225ban elkezdtek k\246vek potyogni a v\225ros[ENTER]k\246zel\233ben. A vizsg\225latok azt mutatj\225k, hogy a Chi[ENTER]ezekben a k\246vekben az \225llatok megvadul\225s\225hoz[ENTER]vezet. T\246rd \246ssze ezeket a k\246veket, erre k\233rlek.[ENTER]Megfelel\245en megjutalmazlak er\245fesz\237t\233seid\233rt. "
gameforge.locale.questscroll5.mission_9_hunt = "Aggodalom a falubeliek\233rt 2 "
gameforge.locale.questscroll5.mission_9_mis = "Vad\225ssz le 30 V\246r\246s vaddiszn\243t. "
gameforge.locale.questscroll5.mission_9_text = "Nem r\233g\243ta \233rik megpr\243b\225ltat\225sok a v\225ros[ENTER]k\246zel\233ben \233l\245 falusiakat a Vaddiszn\243k, \233s[ENTER]vezet\245ik, a V\246r\246s vaddiszn\243k \225ltal. A korm\225nyzat[ENTER]meg akarja \246letni a v\246r\246s vaddiszn\243kat. Minden[ENTER]harcosnak meg kellene \246lnie 30-at k\246z\252l\252k. K\233rj\252k[ENTER]a seg\237ts\233gedet! "
gameforge.locale.questscroll_10_hunt = "K\237gy\243ember katona "
gameforge.locale.questscroll_10_mis = "\214ld meg a katon\225kat, akik f\233lig emberek, f\233lig[ENTER]k\237gy\243k! "
gameforge.locale.questscroll_10_text = "Nem lehet \245ket tulajdonk\233ppen embernek tekinteni,[ENTER]de \233ppoly hib\225s azt mondani, hogy nem emberek.[ENTER]\218gy n\233znek ki, mint az emberek, de a fej, b\245r \233s[ENTER]a magatart\225s olyan, mint a m\233rges k\237gy\243k\233. A[ENTER]sivatagban barangolnak \233s keresked\245ket t\225madnak[ENTER]meg.[ENTER]\214lj meg 20 ilyen katon\225t, akik f\233lig emberek,[ENTER]f\233lig k\237gy\243k.[ENTER]Ha megsemmis\237ted \245ket, a k\246vetkez\245 jutalomban[ENTER]r\233szes\252lsz: "
gameforge.locale.questscroll_11_hunt = "K\237gy\243ember \237j\225sz "
gameforge.locale.questscroll_11_mis = "\214ld meg az \237j\225szokat, akik f\233lig emberek, f\233lig[ENTER]k\237gy\243k! "
gameforge.locale.questscroll_11_text = "Intelligensek, mint az emberek. Ravaszak \233s[ENTER]remek\252l \233rtenek a fegyverforgat\225shoz. \205j\225szok,[ENTER]akik f\233lig emberek, f\233lig k\237gy\243k, messzir\245l[ENTER]t\225madj\225k meg a keresked\245ket. Sok keresked\245[ENTER]azonnal meghal.[ENTER]\214lj meg 20 ilyen \237j\225szt, akik f\233lig emberek,[ENTER]f\233lig k\237gy\243k. Ha teljes\237ted a k\252ldet\233st, a[ENTER]k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_12_hunt = "Sivatagi bandit\225k "
gameforge.locale.questscroll_12_mis = "Sivatagi bandit\225kat \246lni. "
gameforge.locale.questscroll_12_text = "A Yongbi sivatagban gonosz l\233nyek \233lnek. Sivatagi[ENTER]bandit\225kk\233nt ismertek, \233s gaztetteik az \233gbe[ENTER]ki\225ltanak. Keresked\245ket rabolnak ki \233s \246lnek meg[ENTER]sz\243rakoz\225sb\243l. A sivatagi falvakat is[ENTER]lerombolt\225k.[ENTER]\214lj meg 12 sivatagi bandit\225t! Ha valamennyit[ENTER]legy\245z\246d, a k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_13_hunt = "Harci tigris "
gameforge.locale.questscroll_13_mis = "Harci tigrisek meg\246l\233se. "
gameforge.locale.questscroll_13_text = "Vannak Harci tigrisekk\233nt ismert \225llatok. A v\233r\252k[ENTER]t\251zb\245l van, a test\252k vulkanikus gr\225nitb\243l[ENTER]form\225l\243dott. Hihetetlen\252l er\245s sz\246rnyek. Ezek a[ENTER]sz\246rnyek l\225v\225b\243l \233s a vulk\225n t\252z\233b\245l[ENTER]t\225pl\225lkoznak. N\233ha lem\225sznak a vulk\225nr\243l \233s[ENTER]embereket t\225madnak \233s esznek meg...[ENTER]Vad\225ssz le 20 Harci tigrist. Ha megsemmis\237ted[ENTER]\245ket, a k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_14_hunt = "Harci ember "
gameforge.locale.questscroll_14_mis = "\214ld meg a harci embereket! "
gameforge.locale.questscroll_14_text = "A Doyyumhwan nagy, forr\243 \233s vad\225llatok sz\225ll\225sa.[ENTER]Ott tal\225lkoznak a Chunjo, Jinno \233s Shinsoo[ENTER]harcosok. F\233lelmetes, hatalmas sz\246rnyek[ENTER]v\225rakoznak a harcosokra. A harcosok az[ENTER]egyetlenek, akik ellen\245rzik Doyyumhwan-t.[ENTER]V\225llalod a kih\237v\225st ellen\252k? Ha meg\246lsz k\246z\252l\252k[ENTER]20-at, a k\246vetkez\245 jutalmat kapod: "
gameforge.locale.questscroll_15_hunt = "Taehwa harcosok "
gameforge.locale.questscroll_15_mis = "A Taehwa harcosok legy\245z\233se. "
gameforge.locale.questscroll_15_text = "Figyeljen ide mindenki, aki er\245s harcosnak tartja[ENTER]mag\225t! Ez a k\246nnyek, a b\225nat, a harc \233s a hal\225l[ENTER]l\225ng csatamez\245je. Sok sz\246rnnyel \233s gazemberrel[ENTER]\233lek itt. Ki mer engem kih\237vni? Van valaki, aki[ENTER]karddal kez\233ben szembesz\225ll velem?[ENTER][ENTER]Ha hisztek k\233pess\233geitekben, akkor gyertek \233s[ENTER]sz\225lljatok szembe velem! Ha legy\245z\246l engem \233s 12[ENTER]t\225rsamat, akkor a k\246vetkez\245ket kapod jutalomk\233nt: "
gameforge.locale.questscroll_16_hunt = "S\246t\233t medve "
gameforge.locale.questscroll_16_mis = "S\246t\233t medv\233ket \246lni. "
gameforge.locale.questscroll_16_text = "Att\243l tartok, a v\233g\233t j\225rom. De hadd mes\233ljek el[ENTER]m\233g egy fontos esem\233nyt. Amint ezt a levelet[ENTER]olvasod, \233n m\225r halott vagyok, vagy elt\251ntem. A[ENTER]Seungryong-v\246lgyben \233ltem, ahol gy\243gyn\246v\233nyeket[ENTER]gy\251jt\246ttem. De sz\246rnyek, amiket s\246t\233t medv\233knek[ENTER]neveznek, mindenf\233le rettenetes dolgot kezdtek[ENTER]csin\225lni. meg\246lt\233k a csal\225dom.[ENTER][ENTER]K\233rlek bossz\250lj meg engem \233s csal\225domat. Ha 25[ENTER]s\246t\233t medv\233t meg\246lsz, a k\246vetkez\245 jutalomban[ENTER]r\233szes\252lsz: "
gameforge.locale.questscroll_17_hunt = "\211ri\225s s\246t\233t medv\233k "
gameforge.locale.questscroll_17_mis = "\211ri\225s s\246t\233t medv\233ket \246lni. "
gameforge.locale.questscroll_17_text = "A medve sz\246rnyek egy \250j sz\246rnyet csin\225ltak a m\233g[ENTER]gonoszabb sz\246rnyek keresztez\233s\233vel. Ezek az \250j[ENTER]sz\246rnyek az \243ri\225s d\246t\233t medv\233k. Nagyobbak \233s[ENTER]er\245sebbek a s\246t\233t medv\233kn\233l \233s hihetetlen\252l[ENTER]gonoszak. Am\237g a Seungryong-v\246lgyben vannak, az[ENTER]emberek szenvedni fognak.[ENTER][ENTER]\214lj meg 20 \243ri\225s s\246t\233t medv\233t. Ha megsemmis\237ted[ENTER]\245ket, a k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_18_hunt = "Katon\225k, akik a rejt\233lyes betegs\233gben szenvednek "
gameforge.locale.questscroll_18_mis = "Katon\225kat \246lni, akik a rejt\233lyes betegs\233gben[ENTER]szenvednek. "
gameforge.locale.questscroll_18_text = "\218gy t\251nik, kiirtott\225k a falut.[ENTER]Azok, akik a rejt\233lyes betegs\233gben szenvednek,[ENTER]megt\225madj\225k a szerencs\233tlen arra j\225r\243kat.[ENTER]Megt\225madj\225k a keresked\245ket \233s megeszik az[ENTER]embereket. K\252l\246n\246sen vesz\233lyesek.[ENTER]\214lj meg 35 katon\225t, akik a rejt\233lyes betegs\233gben[ENTER]szenvednek. Ha siker\252l, a k\246vetkez\245 jutalomban[ENTER]r\233szes\252lsz: "
gameforge.locale.questscroll_19_hunt = "\205j\225szok, akik a rejt\233lyes betegs\233gben szenvednek "
gameforge.locale.questscroll_19_mis = "\205j\225szokat \246lni, akik a rejt\233lyes betegs\233gben[ENTER]szenvednek "
gameforge.locale.questscroll_19_text = "A rejt\233lyes betegs\233g az oka a k\225roknak, amiket az[ENTER]ebben szenved\245k okoznak. A legveszedelmesebbek az[ENTER]ett\245l megfert\245z\245d\246tt \237j\225szok. Ezek az \237j\225szok[ENTER]m\233rges nyilakkal l\246vik az utaz\243kat, \237gy meg[ENTER]tudj\225k t\225madni \233s ki tudj\225k rabolni \245ket.[ENTER][ENTER]\214lj meg 25 \237j\225szt, akik a rejt\233lyes betegs\233gben[ENTER]szenvednek. Ha siker\252l, a k\246vetkez\245 jutalomban[ENTER]r\233szes\252lsz: "
gameforge.locale.questscroll_1_hunt = "T\251z medv\233k "
gameforge.locale.questscroll_1_mis = "Vad\225ssz le 25 t\251z medv\233t. "
gameforge.locale.questscroll_1_text = "A t\251zmedv\233k gyakran a f\245v\225ros k\246zel\233ben jelennek[ENTER]meg. A pr\233rin b\243kl\225sznak \233s az emberek sz\233les[ENTER]\250tjain. Egyre t\246bb az \225ldozatuk. P\225r embert[ENTER]meg\246ltek.[ENTER]Vad\225ssz ezekre a t\251z medv\233kre. Ha 25 t\251z medv\233t[ENTER]leter\237tesz, a k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_20_hunt = {}
gameforge.locale.questscroll_20_mis = "4 ellens\233get kiiktatni. "
gameforge.locale.questscroll_20_text = "Att\243l f\233lek, elint\233ztek. Elhom\225lyosult a[ENTER]l\225t\225som... Amikor ezt a levelet olvasod, \233n m\225r[ENTER]rothadt a testem. A diszn\243k megfogtak \233s[ENTER]elhurcoltak. Hab\225r elmenek\252ltem, a sebek olyan[ENTER]m\233lyek voltak, hogy \246sszeestem. Nem ismerlek, de[ENTER]k\233rlek \225llj bossz\250t \233rtem![ENTER][ENTER]\214lj meg 4 ellens\233get a harc helysz\237n\233n. Ha[ENTER]siker\252l, a k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_2_hunt = "\211ri\225stigris "
gameforge.locale.questscroll_2_mis = "H\250sz \211ri\225stigrist elejteni. "
gameforge.locale.questscroll_2_text = "A gonosz neve, Nagytigirs, \225thatolja a leveg\245t.[ENTER]Ezek a tigrisek \225ltal\225ban a f\245v\225ros k\246rny\233k\233n[ENTER]tal\225lhat\243k meg. Megt\225madj\225k az embereket \233s a[ENTER]keresked\245k holttest\233t megeszik. Sz\225mtalan[ENTER]\225ldozatuk van.[ENTER][ENTER]Vad\225ssz a Nagytigrisekre. Ha 20 Nagytigrist[ENTER]meg\246lsz, a k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_3_hunt = "A hegy Kutyaistene "
gameforge.locale.questscroll_3_mis = "A hegy Kutyaisten\233t meg\246lni. "
gameforge.locale.questscroll_3_text = "A hegy Kutyaistene a k\246zelben egy csapat[ENTER]kutyasz\246rnyeket vezet. Er\245s \233s vad. Nemr\233g jelent[ENTER]meg a falu k\246zel\233ben \233s elkezdett keresked\245ket[ENTER]megt\225madni. M\225r sokan a sz\246rnyeteg \225ldozatai[ENTER]lettek. Ezeket a gaztetteket nem lehet tov\225bb[ENTER]mell\245zni.[ENTER][ENTER]\214ld meg a hegy Kutyaisten\233t. Ha sikerrel j\225rsz, a[ENTER]k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_4_hunt = "Sert\233sisten "
gameforge.locale.questscroll_4_mis = "A Sert\233sisten meg\246l\233se. "
gameforge.locale.questscroll_4_text = "Ebben az \233vszakban az \233rett gabona m\233g a f\246ldeken[ENTER]van. Most elj\246tt az id\245 az arat\225sra, elj\246tt az[ENTER]id\245 arra, hogy a parasztok az \233ves keserves[ENTER]munk\225juk gy\252m\246lcs\233t betakar\237ts\225k. De a[ENTER]Sert\233sisten \233s t\225rsai az \246sszes gabon\225t[ENTER]felfalj\225k. Moh\243s\225guk vesz\233lyezteti a parasztok[ENTER]\233let\233t, ez\233rt agyon kell csapjuk \245ket.[ENTER][ENTER]\214ld meg a Sert\233sistent. \213t \225ltal\225ban a f\245v\225ros[ENTER]k\246zel\233ben tal\225lhatod meg. Ha legy\245z\246d, a[ENTER]k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_5_hunt = "Medveisten "
gameforge.locale.questscroll_5_mis = "A Medveisten meg\246l\233se. "
gameforge.locale.questscroll_5_text = "Term\233szetes k\246rnyezet\233ben a Medveisten bar\225ts\225gos[ENTER]volt. De nemr\233g a f\245v\225ros k\246zel\233ben jelenik meg[ENTER]\233s megt\225madja az embereket. Egyre t\246bb \233s t\246bb[ENTER]\225ldozatot tal\225l. Hogy m\225r mennyien haltak meg,[ENTER]alig felm\233rhet\245. El kell innen t\251nj\246n.[ENTER][ENTER]\214ld meg a Medveistent. Ha t\233nyleg megszabadulsz[ENTER]t\245le, akkor k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_6_hunt = "Tigrisisten "
gameforge.locale.questscroll_6_mis = "A Tigrisisten meg\246l\233se. "
gameforge.locale.questscroll_6_text = "Nem tudom elhinni, hogy tudott ilyen borzalmasat[ENTER]cselekedni a Tigrisisten? \201n csak egy egyszer\251[ENTER]asszony vagyok, aki minden nap a Tigrisistent[ENTER]im\225dta, aki alkalmank\233nt a hegyi \246sv\233nyen[ENTER]megjelent. De egy nap a Tigrisisten \233s k\246vet\245i a[ENTER]csal\225domat megt\225madt\225k! Mindenkit meg\246ltek, \233s \233n[ENTER]pedig az egyik karomat vesztettem el.[ENTER][ENTER]K\233rlek bosszuld meg a csal\225domat. Ha a[ENTER]Tigrisistent meg\246l\246d, a k\246vetkez\245 jutalomban[ENTER]r\233szes\252lsz: "
gameforge.locale.questscroll_7_hunt = "A Feh\233r Esk\252 sereg vez\233re "
gameforge.locale.questscroll_7_mis = "A Feh\233r Esk\252 sereg vez\233r\233nek meg\246l\233se. "
gameforge.locale.questscroll_7_text = "A Feh\233r Esk\252 hadsereg egy n\245kb\245l \225ll\243 csoport,[ENTER]akiket a f\233rj\252k \233s a vil\225g cserben hagyott.[ENTER]Lehet, hogy szeg\233nyek, de a falu lakosait[ENTER]kegyetlen\252l k\237nozz\225k. Egy n\245t hal\225lra k\246veztek,[ENTER]amikor a faluba j\246tt. Nem engedhetj\252k \245ket a[ENTER]faluba, hogy megt\225madj\225k a lak\243kat.[ENTER][ENTER]\214lj meg h\250sz vez\233rt a Feh\233r Esk\252 hadsereg\233b\245l. Ha[ENTER]ezt a feladatot sikeresen teljes\237ted, k\246vetkez\245[ENTER]jutalmat kapod: "
gameforge.locale.questscroll_8_hunt = "A Feketesz\233l banda vez\233re "
gameforge.locale.questscroll_8_mis = "A Feketesz\233l banda vez\233r\233nek meg\246l\233se. "
gameforge.locale.questscroll_8_text = "A Feketesz\233l banda tolvajai m\225r r\233g\243ta[ENTER]h\225borgatj\225k az utaz\243 keresked\245ket. Olyan f\233lelmet[ENTER]kelt\245en n\233znek ki, hogy senki sem mer vel\252k[ENTER]szembesz\225llni. De ez \237gy tov\225bb nem mehet, mert[ENTER]t\233nyleg elviselhetetlen k\225rt okoznak.[ENTER]\214ld meg a Feketesz\233l banda 20 vez\233r\233t. Ha ezt a[ENTER]megb\237zat\225st eredm\233nyesen teljes\237ted, akkor a[ENTER]k\246vetkez\245 jutalomban r\233szes\252lsz: "
gameforge.locale.questscroll_9_hunt = "Barb\225r t\246rzsf\245n\246k "
gameforge.locale.questscroll_9_mis = "A barb\225r t\246rzsf\245n\246k\246t meg\246lni. "
gameforge.locale.questscroll_9_text = "M\225r sok id\245 telt el az\243ta, ami\243ta a barb\225rok a[ENTER]hat\225rt \225tl\233pt\233k \233s a falut megt\225madt\225k. Az[ENTER]\225ltaluk legyilkolt emberek sz\225ma a t\246bb sz\225zat[ENTER]k\246zel\237tette meg. Azoknak a sz\225ma, akit[ENTER]megk\225ros\237tottak, l\233nyegesen nagyobb. A gonosz[ENTER]barb\225rok olyan brut\225lisak, hogy senki nem merte[ENTER]\245ket megbosszulni. De mi nem t\251rj\252k \245ket hosszabb[ENTER]ideig.[ENTER][ENTER]\214lj meg 25 t\246rzsvez\233rt. Ha ezt a megb\237z\225st[ENTER]sikeresen teljes\237tetted, akkor a k\246vetkez\245[ENTER]jutalomban r\233szes\252lsz: "
gameforge.locale.quest_temp_reward_1 = "Jutalom "
gameforge.locale.quest_temp_reward_2 = "A megb\237z\225sok teszt idej\233ben nincs jutalom.[ENTER]K\233s\245bb, miut\225n megkapt\225l egy jutalmat, az[ENTER]aktu\225lis megb\237zat\225s megism\233telhet\245. "
