gameforge.locale.skeleton_gem.order_refuse = "Ez t\250l vesz\233lyes. "
gameforge.locale.skeleton_gem.order_refuse_answer = "H\225zal\243:[ENTER]Meg\233rtem, hogy habozol. Term\233szetesen ez egy[ENTER]neh\233z \233s vesz\233lyes feladat! De ha \237gy[ENTER]folytat\243dnak tov\225bb a dolgok, ez lesz a vesztem! "
gameforge.locale.skeleton_gem.order_say = "H\225zal\243:[ENTER]Mindennek v\233ge! Nem maradt m\225s h\225tra, mint v\225rni[ENTER]a hal\225lt. Ha nem t\225madtak volna meg a tolvajok,[ENTER]nem vesztettem volna el mindenem. Mi\233rt \233ppen[ENTER]velem kellett megt\246rt\233nnie? "
