gameforge.locale.skeleton_gem.start_say = "A keresked\245 levele:[ENTER]Nem tudom, mit csin\225ljak. Ellopt\225k t\245lem a D\233moni[ENTER]\233kk\245+ -t. A cs\245d sz\233l\233n \225llok, mert r\225k\246lt\246ttem[ENTER]minden p\233nzem.[ENTER]Tudsz nekem seg\237teni? Teljesen k\233ts\233gbe vagyok[ENTER]esve! "
