gameforge.locale.skill_group = {}
gameforge.locale.skill_group.board = "Ez \225ll a r\246piraton:[ENTER]Olyan b\225tor f\233rfiakat \233s n\245ket toborozunk, akik[ENTER]k\233szen \225llnak arra, hogy a birodalom \233s annak[ENTER]polg\225rai b\233k\233j\233\233rt harcoljanak![ENTER][ENTER]A katonas\225ghoz val\243 k\246vetelm\233ny: Minimum 5-\246s[ENTER]szint. "
gameforge.locale.skill_group.dialog_assassin_1 = "Itt k\233pezik ki a Nindzs\225kat, akik j\243l[ENTER]rejt\245zk\246dnek, \233s rajta\252tnek ellenfeleiken. A t\245r[ENTER]kezel\233s\233re \233s a m\233rgek haszn\225lat\225ra[ENTER]\246sszepontos\237tanak. Csak azok a Nindzs\225k[ENTER]csatlakozhatnak, akik m\225r el\233rt\233k az 5-\246s[ENTER]szintet. Amikor el\233red ezt a szintet, kapsz egy[ENTER]toborz\243 levelet. Ha k\233szen \225llsz a vil\225g s\246t\233t[ENTER]sarkaiban nindzsak\233nt lopakodni, gyere \233s keress[ENTER]engem. Akkor tov\225bb tudunk besz\233lgetni. "
gameforge.locale.skill_group.dialog_assassin_2 = "Itt k\233pezik ki a Nindzs\225kat, akik j\243l[ENTER]rejt\245zk\246dnek, \233s rajta\252tnek ellenfeleiken. A t\245r[ENTER]kezel\233s\233re \233s a m\233rgek haszn\225lat\225ra[ENTER]\246sszpontos\237tanak. Ha k\233szen \225llsz a vil\225g s\246t\233t[ENTER]sarkaiban nindzsak\233nt lopakodni, gyere \233s keress[ENTER]engem. Akkor tov\225bb tudunk besz\233lgetni. "
gameforge.locale.skill_group.dialog_assassin_3 = "Itt azokat a Nindzs\225kat k\233pzik ki, akik az[ENTER]\237jkezel\233s mesterei. Megtan\237tanak arra, hogyan[ENTER]tudod nyiladat sort\251zk\233nt kil\245ni a t\225volb\243l az[ENTER]ellens\233gre. Csak azok a Nindzs\225k csatlakozhatnak,[ENTER]akik m\225r el\233rt\233k az 5-\246s szintet. Amikor el\233red[ENTER]ezt a szintet, kapsz egy toborz\243 levelet. Ha[ENTER]k\233szen \225llsz a vil\225g s\246t\233t sarkaiban nindzsak\233nt[ENTER]lopakodni, gyere \233s keress engem. "
gameforge.locale.skill_group.dialog_assassin_4 = "Itt azokat a Nindzs\225kat k\233pzik ki, akik az[ENTER]\237jkezel\233s mesterei. P\233ld\225ul megtan\237tanak arra,[ENTER]hogyan tudod nyiladat sort\251zk\233nt kil\245ni a[ENTER]t\225volb\243l az ellens\233gre. K\246vess engem. A f\246ldr\233sz[ENTER]legjobb \237j\225sz\225v\225 teszlek. "
gameforge.locale.skill_group.dialog_assassin_5 = "V\225lassz a t\245rharc \233s az \237j\225szat k\246z\246tt, \237gy[ENTER]megkapod a k\237v\225nt k\233szs\233geket. "
gameforge.locale.skill_group.dialog_shaman_1 = "Ezen a helyen tal\225lkoznak azok a S\225m\225nok, akik a[ENTER]S\225rk\225nyisten \250tj\225t szeretn\233k k\246vetni. Megtan\237tj\225k[ENTER]neked, hogyan haszn\225lhatsz amuletteket \233s[ENTER]ment\225lis er\245t, mellyel a s\225m\225nok k\233pesek[ENTER]visszaverni az ellenfeleik k\252l\246nb\246z\245 t\225mad\243[ENTER]technik\225it. Azt is lehet\245v\233 teszik nekik, hogy[ENTER]n\246velj\233k saj\225t v\233delmi \233rt\233k\252ket a szent[ENTER]v\233delemmel, \233s t\225mogass\225k a bar\225ti harcosokat.[ENTER]Azok a s\225m\225nok csatlakozhatnak, akik el\233rt\233k[ENTER]legal\225bb az 5. szintet. Ha Amint el\233red ezt a[ENTER]szintet, kapni fogsz egy toborz\243 levelet. Ha[ENTER]k\233szen \225llsz a s\225rk\225nyhatalom tan\237t\225saira, akkor[ENTER]keress fel. "
gameforge.locale.skill_group.dialog_shaman_2 = "Ezen a helyen tal\225lkoznak azok a S\225m\225nok, akik a[ENTER]S\225rk\225nyisten \250tj\225t szeretn\233k k\246vetni. Megtan\237tj\225k[ENTER]neked, hogyan haszn\225lhatsz amuletteket \233s[ENTER]ment\225lis er\245t, mellyel a s\225m\225nok k\233pesek[ENTER]visszaverni az ellenfeleik k\252l\246nb\246z\245 t\225mad\243[ENTER]technik\225it. Azt is lehet\245v\233 teszik nekik, hogy[ENTER]n\246velj\233k saj\225t v\233delmi \233rt\233k\252ket a szent[ENTER]v\233delemmel, \233s t\225mogass\225k a bar\225ti harcosokat.[ENTER]\218gy gondolod, k\233szen \225llsz, hogy velem egy\252tt[ENTER]terjeszd a S\225rk\225nyisten tan\237t\225s\225t? Mindig[ENTER]sz\237vesen l\225tunk egy al\225zatos h\237v\245t. "
gameforge.locale.skill_group.dialog_shaman_3 = "Itt a s\225m\225nok a term\233szet \233s a f\233ny hatalm\225t[ENTER]im\225dj\225k. Itt vill\225mmal, sz\233llel \233s gy\243gyul\225ssal[ENTER]kapcsolatos k\233pess\233geket tan\237tanak. Azok a[ENTER]s\225m\225nok, akik a gy\243gy\237t\225s tan\225t k\246vetik, gyakran[ENTER]csoportban dolgoznak, hogy t\225mogass\225k egym\225st.[ENTER]Csak azok a s\225m\225nok csatlakozhatnak, akik el\233rt\233k[ENTER]legal\225bb az 5. szintet. Amint el\233red ezt a[ENTER]szintet, kapni fogsz egy toborz\243 levelet. Itt[ENTER]v\225rok R\225d! "
gameforge.locale.skill_group.dialog_shaman_4 = "Itt a s\225m\225nok a term\233szet \233s a f\233ny hatalm\225t[ENTER]im\225dj\225k. Itt vill\225mmal, sz\233llel \233s gy\243gyul\225ssal[ENTER]kapcsolatos k\233pess\233geket tan\237tanak. Azok a[ENTER]s\225m\225nok, akik a gy\243gy\237t\225s tan\225t k\246vetik, gyakran[ENTER]csoportban dolgoznak, hogy t\225mogass\225k egym\225st.[ENTER]Szeretn\233l velem egy\252tt m\225soknak seg\237teni? A[ENTER]t\225mogat\225sod seg\237tene minden szenved\245nek. K\233rlek,[ENTER]seg\237ts. "
gameforge.locale.skill_group.dialog_shaman_5 = "V\225lassz a S\225rk\225ny hatalom \233s a Gy\243gy\237t\243 er\245[ENTER]k\246z\246tt \233s m\225ris megkapod a sz\252ks\233ges[ENTER]k\233pess\233geket. "
gameforge.locale.skill_group.dialog_sura_1 = "\201n azokat az embereket tan\237tom, hogyan tudj\225k a[ENTER]m\225gikus k\233pess\233geiket haszn\225lni, akik \246rd\246gi[ENTER]magvakkal \225ldottak.[ENTER]Megtanulj\225k, hogyan var\225zsolj\225k el kardjukat \233s[ENTER]v\233rtj\252ket, mely megn\246veli t\225mad\243- \233s v\233dekez\245[ENTER]erej\252ket. Azt is megtanulj\225k, hogyan id\233zz\233k meg[ENTER]a pokol gonosz lelkeit, akik az ellens\233g[ENTER]erk\246lcs\233t rontj\225k. Csak azok a Sur\225k[ENTER]csatlakozhatnak, akik legal\225bb az 5. szintet[ENTER]el\233rt\233k. Amint el\233red ezt a szintet, kapni fogsz[ENTER]egy toborz\243 levelet. Ha k\233sz vagy befogadni a[ENTER]d\233moni \246r\246ks\233get, gyere ide. "
gameforge.locale.skill_group.dialog_sura_2 = "\201n azokat az embereket tan\237tom, hogyan tudj\225k a[ENTER]m\225gikus k\233pess\233geiket haszn\225lni, akik \246rd\246gi[ENTER]magvakkal \225ldottak.[ENTER]Megtanulj\225k, hogyan var\225zsolj\225k el kardjukat \233s[ENTER]v\233rtj\252ket, mely megn\246veli t\225mad\243- \233s v\233dekez\245[ENTER]erej\252ket. Azt is megtanulj\225k, hogyan id\233zz\233k meg[ENTER]a pokol gonosz lelkeit, akik az ellens\233g[ENTER]erk\246lcs\233t rontj\225k. K\233sz vagy arra, hogy az[ENTER]elvar\225zsolt kardot forgasd \233s s\246t\233t var\225zslatokat[ENTER]id\233zz? Biztos\237thatlak arr\243l, hogy az itt[ENTER]tal\225lhat\243 hatalom igen keresett az emberek k\246z\246tt[ENTER]a maga nem\233ben. "
gameforge.locale.skill_group.dialog_sura_3 = "Ha \233rdekel ez a hely: itt csak azokat tal\225lod,[ENTER]akik a s\246t\233ts\233gnek k\246telezt\233k el magukat. Itt[ENTER]tanulj\225k meg, hogyan kell kezelni a lelkeket,[ENTER]d\233monokat, \233s a pokol t\252z\233t. Csak azok a Sur\225k[ENTER]csatlakozhatnak, akik legal\225bb az 5. szintet[ENTER]el\233rt\233k. Amint el\233red ezt a szintet, kapni fogsz[ENTER]egy toborz\243 levelet. Ha a s\246t\233ts\233g az otthonod,[ENTER]itt biztosan testv\233rekre tal\225lsz. "
gameforge.locale.skill_group.dialog_sura_4 = "Ha \233rdekel ez a hely: itt csak azokat tal\225lod,[ENTER]akik a s\246t\233ts\233gnek k\246telezt\233k el magukat. Itt[ENTER]tanulj\225k meg, hogyan kell kezelni a lelkeket,[ENTER]d\233monokat, \233s a pokol t\252z\233t. Ha szeretn\233l gonosz[ENTER]lelkekkel bar\225ts\225got k\246tni, akik apr\225nk\233nt t\233ged[ENTER]felem\233sztenek, akkor gyere velem! Csatlakozz a[ENTER]rend\252nkh\246z \233s hagyd magad m\246g\246tt embers\233gedet... "
gameforge.locale.skill_group.dialog_sura_5 = "V\225lassz a fekete m\225gia \233s a m\225gikus fegyver[ENTER]oktat\225s k\246z\246tt, \233s m\225ris megkapod a megfelel\245[ENTER]k\233pess\233geket. "
gameforge.locale.skill_group.dialog_warrior_1 = "Tudod, hol vagy most? T\225mad\243kat k\233peznek itt,[ENTER]harcosokat, akik a leggyorsabbak \233s legb\225trabbak[ENTER]k\246r\252l\246tt\252nk. Itt a gyors, ism\233tl\245d\245 \252t\233seket \233s a[ENTER]magasan k\233pzett t\225mad\225si technik\225kat tan\237tj\225k,[ENTER]karddal vagy l\225ndzs\225val.[ENTER]Csak azok a Harcosok csatlakozhatnak, akik[ENTER]legal\225bb az 5. szintet el\233rt\233k. Amint el\233red ezt[ENTER]a szintet, kapni fogsz egy toborz\243 levelet. Ha[ENTER]meg akarod tapasztalni tested igazi erej\233t, akkor[ENTER]gyere hozz\225m! "
gameforge.locale.skill_group.dialog_warrior_2 = "Tudod, hol vagy most? T\225mad\243kat k\233peznek itt,[ENTER]harcosokat, akik a leggyorsabbak \233s legb\225trabbak[ENTER]k\246r\252l\246tt\252nk. Itt a gyors, ism\233tl\245d\245 \252t\233seket \233s a[ENTER]magasan k\233pzett t\225mad\225si technik\225kat tan\237tj\225k,[ENTER]karddal vagy l\225ndzs\225val.[ENTER]Na, mi legyen? Akarsz edzeni? "
gameforge.locale.skill_group.dialog_warrior_3 = "Harcosokat tan\237tok arra, hogyan f\243kusz\225lj\225k a[ENTER]Chi-j\252ket megfelel\245en.[ENTER]Ez egy lass\250 \233s kimer\237t\245 harci st\237lus. Ugyanakkor[ENTER]k\233pes leszel ugyanabban az id\245ben t\246bb ellenf\233l[ENTER]meg\252t\233s\233re. \201s az \225thatolhatatlan v\233delmi[ENTER]rendszer\251, nagyszer\251 ment\225lis harcos egyenesen[ENTER]legend\225s. Csak azok a harcosok vehetnek r\233szt a[ENTER]k\233pz\233sben, akik gyakornokok, vagy m\225r el\233rt\233k az[ENTER]5. szintet. Amint el\233rted a sz\252ks\233ges szintet,[ENTER]kapni fogsz egy toborz\243 levelet. Ha \233rdekel,[ENTER]keress fel. "
gameforge.locale.skill_group.dialog_warrior_4 = "Harcosokat tan\237tok arra, hogyan f\243kusz\225lj\225k a[ENTER]Chi-j\252ket megfelel\245en.[ENTER]Ez egy lass\250 \233s kimer\237t\245 harci st\237lus. Ugyanakkor[ENTER]k\233pes leszel ugyanabban az id\245ben t\246bb ellenf\233l[ENTER]meg\252t\233s\233re. \201s az \225thatolhatatlan v\233delmi[ENTER]rendszer\251, nagyszer\251 ment\225lis harcos egyenesen[ENTER]legend\225s. Mi legyen? A ment\225lis harc mellett[ENTER]d\246nt\246tt\233l? "
gameforge.locale.skill_group.dialog_warrior_5 = "V\225lassz a testi k\252zdelem \233s a ment\225lis harc[ENTER]oktat\225s k\246z\246tt \233s m\225ris megkapod a megfelel\245[ENTER]k\233pess\233geid. "
gameforge.locale.skill_group.invite = "Hadseregtoborz\225s k\246zz\233t\233tele "
gameforge.locale.skill_group.lets_join_skill_group_1 = "[COLOR r;1|g;0.6|b;0.6]Harcos toborz\225s[ENTER]k\246zz\233t\233tele[/COLOR][ENTER]Ha a harcosokat a gyorsas\225guk \233s a t\225mad\243erej\252k[ENTER]miatt csod\225lod, a testi k\252zdelem k\233pz\233st aj\225nlom[ENTER]neked.[ENTER]Ha sebezhetetlenn\233 szeretn\233l v\225lni \233s egy eg\233sz[ENTER]csoport sz\246rnyet meg akarsz semmis\237teni egy[ENTER]csap\225sra, a ment\225lis harcot aj\225nlom.[ENTER][ENTER]A falu f\245ter\233n v\225rok R\225d. "
gameforge.locale.skill_group.lets_join_skill_group_2 = "[COLOR r;1|g;0.6|b;0.6]Nindzsa-toborz\225s[ENTER]k\246zz\233t\233tele[/COLOR][ENTER]Ha \237j\225szk\233nt kiv\225l\243 h\237rn\233vre akarsz szert tenni,[ENTER]akkor tanuld meg az \237j\225sz harcot.[ENTER]Ha k\233sz vagy arra, hogy Nindzsak\233nt a s\246t\233ts\233g[ENTER]leple alatt k\252l\246nb\246z\245 titkos k\252ldet\233st v\233ghez[ENTER]vigy\233l, akkor a t\245rharc felel meg neked.[ENTER][ENTER]A falu f\245ter\233n v\225rok R\225d. "
gameforge.locale.skill_group.lets_join_skill_group_3 = "[COLOR r;1|g;0.6|b;0.6]Sura toborz\225s[ENTER]k\246zz\233t\233tele[/COLOR][ENTER]Szeretn\233l emberfeletti mester kardforgat\243 lenni,[ENTER]hogy ellenfeleid \233rezz\233k elvar\225zsold peng\233d[ENTER]hegy\233t? Akkor azt aj\225nlom, tanuld meg a m\225gikus[ENTER]fegyverek kezel\233s\233nek m\251v\233szet\233t. Ugyanakkor ha a[ENTER]l\225ngok \233s \225tkok megf\233leml\237t\245 ura akarsz lenni, a[ENTER]fekete m\225gia m\251v\233szet\233t kellene tanulnod.[ENTER][ENTER]A falu f\245ter\233n v\225rok R\225d. "
gameforge.locale.skill_group.lets_join_skill_group_4 = "[COLOR r;1|g;0.6|b;0.6]S\225m\225ntoborz\225s[ENTER]k\246zz\233t\233tele[/COLOR][ENTER]Ha fel akarod \233breszteni a S\225rk\225nyisten erej\233t[ENTER]t\225mad\225said sor\225n \233s haszn\225lni akarod t\252zes[ENTER]lehelet\233t ellens\233geid ellen, akkor a S\225rk\225ny[ENTER]hatalom kitanul\225s\225t javaslom. Ha azonban a[ENTER]szenved\245k f\225jdalm\225t akarod enyh\237teni \233s[ENTER]gy\243gy\237tani, akkor keresd a Gy\243gy\237t\243 er\245 tan\225r\225t.[ENTER][ENTER]A falu f\245ter\233n v\225rok R\225d. "
