gameforge.locale.stamina_food.butcher = {}
gameforge.locale.stamina_food.butcher.start_say = "\214reg ember a Suhpyung \233tteremben:[ENTER]Az \233n fiziikailag m\225r nem vagyok olyan er\245s, mint[ENTER]r\233gen.[ENTER]Amikor fiatal voltam, az eg\233sz hetet \225tdolgoztam[ENTER]\233s ut\225na m\233g mindig volt energi\225m arra, hogy[ENTER]igyak! De id\245k\246zben m\225r az \225ll\225s is f\225radts\225got[ENTER]jelent. Ilyen pillanatban egy z\246ldb\233kaleves egy[ENTER]olyan szernek bizonyul, ami visszaadja az[ENTER]energi\225mat. "
gameforge.locale.stamina_food.butcher.start_say2 = "\214reg ember a Suhpyung \233tteremben:[ENTER]Azt szeretn\233tek tudni, hogy mi a z\246ldb\233ka-leves?[ENTER]Ha egy t\225lk\225val esztek bel\245le, sohasem f\225radtok[ENTER]el t\246bb\233![ENTER]M\233g ha egy hetet a mez\245n kint dolgozn\225tok, akkor[ENTER]is lenne est\233nk\233nt energi\225tok! Egy Oakgu nev\251[ENTER]bar\225tom tudja a legjobban elk\233sz\237teni a[ENTER]z\246ldb\233ka-levest. De valami\233rt m\225r nem f\245zi ezt a[ENTER]levest. "
