gameforge.locale.stamina_food.complete_say = "Oakgu:[ENTER]Meg\233rtetted? Senkinek se mes\233lj a[ENTER]z\246ldb\233ka-levesr\245l! K\252l\246n\246sen ne ennek a fatty\250nak[ENTER]a Suhpyung \233tteremben! Ha az emberek hallanak a[ENTER]z\246ldb\233ka-levesr\245l, akkor ide j\246nnek \233s az[ENTER]\246sszeset feleszik! "
gameforge.locale.stamina_food.food_manager = {}
gameforge.locale.stamina_food.food_manager.order_say = "Oakgu:[ENTER]Z\246ldb\233ka-levest? Igen! Kor\225bban gyakran f\245ztem.[ENTER]De ezt csak a fiatal koromban tudtam csin\225lni.[ENTER]Akkoriban m\233g nem agg\243dtam a vesz\233lyes[ENTER]sz\246rnyetegek miatt, ez\233rt tudtam z\246ld b\233k\225kra[ENTER]vad\225szni. "
gameforge.locale.stamina_food.food_manager.order_say2 = "Oakgu:[ENTER]De most? Most \246reg vagyok \233s nincs el\233g energi\225m[ENTER]ilyen dolgokra. \201n magam is nagyon szeretn\233k[ENTER]z\246ldb\233ka-levest enni, de nem k\246nny\251 elejteni a[ENTER]z\246ld b\233k\225kat. Ha hozol nekem egy kis z\246ld b\233ka[ENTER]h\250st, elk\233sz\237tem neked \233leted legjobb[ENTER]z\246ldb\233ka-leves\233t! "
