gameforge.main_quest_flame_lv101._200_say = "\201rdekes, a Szegecselt nyak\233k a S\246t\233ts\233g[ENTER]szolg\225ihoz tartozik. Tal\225n ez lehet a nyom a[ENTER]cselsz\246v\233s\252kr\245l![ENTER]De m\233g mindig semmi jele a felder\237t\245mnek? K\233rlek,[ENTER]folytasd a keres\233s\233t. Ebben az er\245dben kell[ENTER]lennie. "
