gameforge.main_quest_flame_lv101._270_say = "Yak-Hwan, nem fogok visszat\233rni \233lve, de rem\233lem,[ENTER]eljut hozz\225d ez a lev\233l. Tal\225ltam egy er\245d\246t[ENTER]T\251zf\246ld\246n, ami semmilyen t\233rk\233pen nincs jel\246lve.[ENTER]Uralkod\243ja egy er\245teljes t\251zf\246ldi d\233mon \150[ENTER]k\252l\246nleges aura veszi k\246r\252l \245t \233s az \245t k\246vet\245[ENTER]egy\233b d\233monokat is.[ENTER]\220v\246lt\233se f\252lsiket\237t\245 \233s \250gy t\251nik, hogy valamit[ENTER]\245riz, de nem tudom megmondani, mit. Bocs\225sd meg,[ENTER]hogy elbuktam... "
gameforge.main_quest_flame_lv101._280_say = "Ki kell tal\225lnunk, mi van elrejtve ebben az[ENTER]er\245dben.[ENTER]N\233zd csak, a Szegecselt nyakl\225nc belsej\233ben van[ENTER]egy v\233set. Tan\225csot fogok k\233rni Yon-I-Walker-t\245l.[ENTER]\213 majd kapcsolatba l\233p veled, ha sz\252ks\233ge van a[ENTER]seg\237ts\233gedre. "
