gameforge.main_quest_flame_lv105._090_sayTitle = "Starte die Offensive "
gameforge.main_quest_flame_lv105._100_say = "Rohand le a V\246r\246s s\225rk\225ny-er\245d\246t! "
gameforge.main_quest_flame_lv105._110_sayReward = "Du ben\246tigst eine Gruppe und einen Passierschein "
gameforge.main_quest_flame_lv105._120_say = "M\233g nem tudtuk \225tt\246rni az ellens\233g v\233delmi[ENTER]vonalait. Gy\245zd le mindegyiket a sz\252ks\233ges[ENTER]Par\225zs-l\225ngd\233monok k\246z\252l! "
gameforge.main_quest_flame_lv105._130_notice = "Legy\245zted a Par\225zs-l\225ngd\233monok sereg\233t.[ENTER]Jelentsd Yak-Hwan-nak. "
gameforge.main_quest_flame_lv105._140_say = "T\233rj vissza Yak-Hwan-hoz. "
gameforge.main_quest_flame_lv105._150_say = "J\243l csin\225ltad. Egy l\233p\233ssel k\246zelebb ker\252lt\252nk[ENTER]c\233lunkhoz \150 nem sok\225ig jelent m\225r vesz\233lyt[ENTER]sz\225munkra a V\246r\246s s\225rk\225ny! "
gameforge.main_quest_flame_lv105._160_sendLetter = "Gunst und Groll "
gameforge.main_quest_flame_lv105._170_say = "\218gy t\251nik, f\245 ellens\233ged, Razador neheztel r\225d,[ENTER]ami\233rt meg\246lted \245t. \220v\246lt\233se hangosabban[ENTER]visszhangzik Doyyumhwan lank\225in \225t, mint valaha. "
gameforge.main_quest_flame_lv105._180_say = "Ideje \250jra elhallgattatni \245t. Sasszemmel figyelve[ENTER]\225ll a kapu tetej\233n, mely m\246g\246tt a V\246r\246s s\225rk\225nyt[ENTER]tartj\225k. L\233gy \243vatos vele! Tanult a veres\233g\233b\245l[ENTER]\233s nem fogja m\233g egyszer elk\246vetni ugyanazt a[ENTER]hib\225t. "
gameforge.main_quest_flame_lv105._190_notice = "Gy\245zd le Razador-t, a T\251z ur\225t. "
gameforge.main_quest_flame_lv105._200_sayTitle = "J\225tssz a T\251zzel "
gameforge.main_quest_flame_lv105._210_say = "Gy\245zd le Razadort, a T\251z ur\225t a V\246r\246s[ENTER]s\225rk\225ny-er\245dben. "
gameforge.main_quest_flame_lv105._220_say = "T\250l sok volt neked Razador ez alkalommal? Nehezen[ENTER]tudom elhinni! M\225r egyszer megcsin\225ltad \150 meg[ENTER]fogod tudni tenni ez alkalommal is! "
gameforge.main_quest_flame_lv105._230_notice = "Legy\245zted Razador-t. Jelentsd Yak-Hwan-nak. "
gameforge.main_quest_flame_lv105._240_say = "Ich wusste du w\252rdest es schaffen Gro\223artig Nun werden wir alles f\252r die Verbannung des Rotdrachen vorbereiten Ich lasse dich rufen sobald wir bereit sind "
gameforge.main_quest_flame_lv105._250_sendLetter = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._260_say = "Itt az id\245. Minden k\233szen \225ll a V\246r\246s s\225rk\225ny[ENTER]sz\225m\251z\233s\233re. "
gameforge.main_quest_flame_lv105._270_say = "Meine M\228nner haben bereits bereits zwei Bannkreise aufgestellt Deine Aufgabe ist es nun sie zu entz\252nden Wirf den Bannbeutel auf die Kreise und sie werden sich entflammen Das wird die Verbannung des Rotdrachen vollziehen "
gameforge.main_quest_flame_lv105._280_notice = "Entz\252nde die Bannkreise und schicke den Rotdrachen in die Verbannung "
gameforge.main_quest_flame_lv105._290_say = "Restliche Verbannungsanzahl "
gameforge.main_quest_flame_lv105._300_sayTitle = "Verbannung des Rotdrachen "
gameforge.main_quest_flame_lv105._310_say = "Entz\252nde mithilfe der Bannbeutel die magischen Kreissymbole und schicke den Rotdrachen in die Verbannung "
gameforge.main_quest_flame_lv105._320_say = "Taramor s\237rk\246ve: 1 darab "
gameforge.main_quest_flame_lv105._330_sayTitle = "Rotdrachen Flammenschauspiel "
gameforge.main_quest_flame_lv105._340_say = "Ez volt minden, te f\233reg?! Szinte csak[ENTER]megcsiklandozt\225l \150 ezzel nem sz\225m\251zt\233l engem! \201n[ENTER]pedig \250jra vissza fogom hozni Razador-t a holtak[ENTER]birodalm\225b\243l. Ki fog szabad\237tani b\246rt\246n\246mb\245l, te[ENTER]pedig meg fogod tapasztalni haragom! "
gameforge.main_quest_flame_lv105._350_notice = "Sikertelen volt a V\246r\246s s\225rk\225ny sz\225m\251z\233se.[ENTER]Jelentsd Yak-Hwan-nak. "
gameforge.main_quest_flame_lv105._360_say = "Die Verbannung ist fehlgeschlagen Wie konnte das passieren "
gameforge.main_quest_flame_lv105._370_say = "Ja Eigentlich wurden die Bannkreise aktiviert und die Entflammung hat auch stattgefunden und die Verbannung hatte begonnen aber der Rotdrache war so m\228chtig dass dies fehlgeschlagen ist Er sagte dass er Yamachun 6091 wiederbeleben wird und er die Versiegelung entfernen wird Aber er hat auch gro\223en Schaden durch unseren Verbannungs Versuch erlitten "
gameforge.main_quest_flame_lv105._380_say = "Ach so Gute Arbeit Dank dir konnten wir es so weit bringen Ich habe bereits mit Yon I Walker 20380 gesprochen und \252berlegt was wir nun tun k\246nnen Meine M\228nner werden weiterhin die Lage beobachten und wir werden ach anderen Methoden suchen wie wir die Verbannung vollziehen k\246nnen Wenn wir eine perfekte Methoe gefunden haben den Rotdrachen zu verbannen werde ich nach dir rufen lassen Gute Arbeit "
gameforge.main_quest_flame_lv99 = {}
gameforge.main_quest_flame_lv99._010_sendLetter = "Fuss a T\251zbe "
gameforge.main_quest_flame_lv99._020_say = "Yak-Hwan keres t\233ged. Menj el hozz\225 \233s tudd meg,[ENTER]mit akar. "
gameforge.main_quest_flame_lv99._030_say = "\220dv \250jra! Csak legal\225bb egy kis sz\252netet tudn\225nk[ENTER]tartani \150 de a S\246t\233ts\233g szolg\225i \250jra akci\243ba[ENTER]l\233ptek. \201s ez nem jelent j\243t. "
gameforge.main_quest_flame_lv99._040_say = {}
gameforge.main_quest_flame_lv99._050_say = "Azonban a t\225j\233koztat\225s igen hom\225lyos. Amit[ENTER]tudunk, hogy valahol a T\251zf\246ld\246n t\246rtek el\245. "
gameforge.main_quest_flame_lv99._060_say = "M\225r kik\252ldt\252nk egy felder\237t\245t, de a k\246zelm\250ltban[ENTER]megszakadt vele a kapcsolat \233s nagyon agg\243dom.[ENTER]Megkeresn\233d \245t t\251zf\246ldi utad sor\225n? "
gameforge.main_quest_flame_lv99._070_say = "Term\233szetesen. "
gameforge.main_quest_flame_lv99._080_say = "K\246sz\246n\246m. Megjel\246l\246m neked a t\233rk\233pen az utols\243[ENTER]ismert hely\233t. Sok szerencs\233t! "
gameforge.main_quest_flame_lv99._090_notice = "N\233zz k\246r\252l T\251zf\246ld\246n az elt\251nt felder\237t\245 miatt.[ENTER]Koordin\225t\225k: %d,%d "
gameforge.main_quest_flame_lv99._100_sayTitle = "Der\237tsd fel T\251zf\246ldet! "
gameforge.main_quest_flame_lv99._110_say = "Utazz T\251zf\246ldre. Ott kutass a felder\237t\245 ut\225n \233s[ENTER]keress b\225rmilyen nyomot, ami a S\246t\233ts\233g[ENTER]szolg\225inak cselsz\246v\233s\233re utal! "
gameforge.main_quest_flame_lv99._120_say = "Kell lennie valaminek ezen a helyen. Tal\225n nem[ENTER]vett\233l \233szre egy nyomot. Folytasd a keres\233st. "
gameforge.main_quest_flame_lv99._130_notice = "Dies ist der Ort den Yak Hwan auf der Karte markiert hat Schaue dich um und kehre dann zu Yak Hwan zur\252ck "
gameforge.main_quest_flame_lv99._140_say = "Yak-Hwan a S\246t\233t S\225rk\225ny szikl\225n v\225rja a[ENTER]jelent\233sed. "
gameforge.main_quest_flame_lv99._150_say = "H\225t visszat\233rt\233l! Felfedezt\233l valamit? "
gameforge.main_quest_flame_lv99._160_say = "Sajnos nyoma sem volt ott a felder\237t\245nek. De volt[ENTER]ott egy er\245d, amit nem vettem m\233g \233szre ezel\245tt.[ENTER]Er\245teljes aura \225ramlik a falain bel\252l, ami[ENTER]hat\225ssal van a k\246rny\233k\233re is. "
gameforge.main_quest_flame_lv99._170_say = "Hmm, egy\225ltal\225n nem tetszik ez nekem. Ha t\246bbet[ENTER]megtudok err\245l az er\245dr\245l, kapcsolatba l\233pek[ENTER]veled. "
gameforge.main_quest_flame_lv99._180_sendLetter = "Az Er\245d kivizsg\225l\225sa "
gameforge.main_quest_flame_lv99._190_say = "Hm wir tappen im Dunkeln Ich habe rein gar nichts \252ber diese geheimnisvolle Festung herausfinden k\246nnen In diesem Brief habe ich alles zusammengetragen was wir bis jetzt wissen Bitte \252berbringe ihn Yon I Walker Er wird wissen was zu tun ist "
gameforge.main_quest_flame_lv99._200_say = "Menj Yon-I-Walker-hez. "
gameforge.main_quest_flame_lv99._210_say = "Was kann ich f\252r dich tun Ah ein Brief Yak Hwan bittet also um meine Hilfe Dann werden wir mal versuchen Licht in die Dunkelheit zu bringen "
gameforge.main_quest_flame_lv99._220_say = {}
gameforge.main_quest_flame_lv99._230_say = {}
gameforge.main_quest_flame_lv99._240_say = "Eine geheimnisvolle Aura die aus dem Inneren einer Festung str\246mt Interessant Schaue dich zun\228chst einmal in der n\228heren Umgebung dort um Ich habe da einen Verdacht worum es sich bei dieser Aura handeln k\246nnte Hier nimm dieses Papier und wickel es um deine Waffe Wenn sich mein Verdacht best\228tigt sollte sich das Papier schwarz f\228rben sobald du damit D\228monen t\246test die unter dem Einfluss der dunklen Aura stehen "
gameforge.main_quest_flame_lv99._250_notice = "\214lj d\233monokat, amik az er\245d k\246rny\233k\233n[ENTER]csatangolnak. "
gameforge.main_quest_flame_lv99._260_sayTitle = "D\233monvad\225szat "
gameforge.main_quest_flame_lv99._270_say = "\214lj t\251zf\246ldi d\233monokat, amik az er\245d k\246rny\233k\233n[ENTER]csatangolnak \233s ellen\245rizd, v\225ltozik-e fegyvered[ENTER]sz\237ne. "
gameforge.main_quest_flame_lv99._280_say = "Hmm, biztos vagyok benne, hogy van bizony\237t\233k[ENTER]ennek az aur\225nak a l\233tez\233s\233re T\251zf\246ld\246n. T\233rj oda[ENTER]vissza \250jra \233s \246lj d\233monokat, amik az er\245d[ENTER]k\246zvetlen k\246zel\233ben vannak. "
gameforge.main_quest_flame_lv99._290_notice = "Fegyvered fekete sz\237n\251 lett. T\233rj vissza[ENTER]Yon-I-Walker-hez. "
gameforge.main_quest_flame_lv99._300_say = "Ah so wie ich es erwartet hatte Das ist h\246chst bemerkenswert Ich werde dieses Papier etwas n\228her untersuchen Ruhe dich solange aus "
gameforge.main_quest_flame_lv99._310_sendLetter = "Aura erforschen "
gameforge.main_quest_flame_lv99._320_say = "Yon-I-Walker keres t\233ged. Menj el hozz\225, hogy[ENTER]megtudj t\246bbet. "
gameforge.main_quest_flame_lv99._330_say = "Ah, h\225t itt vagy! Ez az aura alattomos \233s k\246dbe[ENTER]burkolja az elm\233m.[ENTER]Nap-n\246v\233nyekre van sz\252ks\233gem elm\233m[ENTER]felvil\225gos\237t\225s\225hoz, hogy folytatni tudjam a[ENTER]vizsg\225l\243d\225saimat. Tudn\225l hozni n\233h\225nyat? "
gameforge.main_quest_flame_lv99._340_say = "Term\233szetesen. "
gameforge.main_quest_flame_lv99._350_say = "A Nap-n\246v\233nyek sz\225raz, meleg helyen n\245nek \150 eg\233sz[ENTER]\233vben megtal\225lhat\243k T\251zf\246ld\246n. Megjel\246l\246m a[ENTER]t\233rk\233pen azt a ter\252letet, ahol legutolj\225ra[ENTER]tal\225ltam n\233h\225nyat. B\225r nem vagyok teljesen biztos[ENTER]benne, jelenleg hol tal\225lhat\243k... "
gameforge.main_quest_flame_lv99._360_say = "Azonnal indulok! "
gameforge.main_quest_flame_lv99._370_notice = "Menj a T\251zf\246ld\246n megjel\246lt ter\252letre \233s keress[ENTER]Nap-n\246v\233nyeket! "
gameforge.main_quest_flame_lv99._380_sayTitle = "Sonnenkr\228uter besorgen "
gameforge.main_quest_flame_lv99._390_say = "Menj arra a helyre, amit Yon-I-Walker megjel\246lt a[ENTER]t\233rk\233pen \233s keress Nap-n\246v\233nyeket. "
gameforge.main_quest_flame_lv99._400_say = "\220res k\233zzel t\233rt\233l vissza? Ez nem j\243. \201rzem,[ENTER]amint az aura egyre jobban elk\246d\246s\237ti elm\233m.[ENTER]K\233rlek, szerezz nekem Nap-n\246v\233nyeket. "
gameforge.main_quest_flame_lv99._410_notice = "Megtal\225ltad a Nap-n\246v\233nyeket. Vidd el[ENTER]Yon-I-Walker-nek. "
gameforge.main_quest_flame_lv99._420_say = "Ah, h\225t megtal\225ltad a Nap-n\246v\233nyeket![ENTER]Kit\251n\245! Most m\225r folytathatom a vizsg\225latokat.[ENTER]Yak-Hwan t\225j\233koztatni fog az eredm\233nyekr\245l. "
gameforge.main_quest_flame_lv99._430_say = "A kaland folytat\243dik, amint el\233rted a %d szintet. "
gameforge.main_quest_lv1 = {}
gameforge.main_quest_lv1._10_sendLetter = "\220dv\246zl\252nk a Metin2-ben "
gameforge.main_quest_lv1._20_say = "Mindj\225rt belemer\252lsz Metin2 izgalmas kalandjaiba.[ENTER]El\245sz\246r keresd fel a v\225ros \245r\233t. \213 alapvet\245[ENTER]inform\225ci\243kkal szolg\225l sz\225modra \233s k\252l\246nb\246z\245[ENTER]feladatokkal l\225t el.[ENTER][ENTER]Ha vad\225szni szeretn\233l, akkor vad\225llatokat a falu[ENTER]hat\225r\225n k\237v\252l tal\225lsz. Ezeket a minit\233rk\233peden[ENTER]piros ponttal t\252ntett\252k fel. El\245sz\246r a[ENTER]vadkuty\225kra \246sszpontos\237ts, mert \245k a legk\246nnyebb[ENTER]ellens\233g.[ENTER]Sok sikert! "
gameforge.main_quest_lv1._30_targetVid = "Keresd a V\225ros \245rt "
gameforge.main_quest_lv1._40_sayTitle = "Keresd a V\225ros \245rt "
gameforge.main_quest_lv1._50_sayReward = "Besz\233lj a V\225ros \245rrel \250gy, hogy r\225kattintasz.[ENTER]Tal\225ld meg az NPC-t, akire a ny\237l mutat. Ha nem[ENTER]tal\225lod, val\243sz\237n\251leg t\250l messze vagy. K\246vesd a[ENTER]t\233rk\233peden tal\225lhat\243 villog\243 k\246r\246ket, am\237g el\233red[ENTER]a V\225ros \245rt. "
gameforge.main_quest_lv1._60_sayTitle = "V\225ros \245r: "
gameforge.main_quest_lv1._70_say = "\218gy t\251nik, hogy \250j vagy itt! Mint ahogy l\225tom,[ENTER]m\233g nem csin\225ltak bel\245led katon\225t. R\233szes\252lt\233l[ENTER]egy\225ltal\225n valami kik\233pz\233sben? N\233zz csak magadra![ENTER]Volt m\225r a kezedben egy\225ltal\225n valami fegyver?[ENTER]Hallgass ide! Neked mindig \233bernek kell lenned,[ENTER]ha a harcot t\250l akarod \233lni. Am\237g a 10. szintet[ENTER]el\233red, seg\237tek neked. Ne gondold, hogy egyszer\251[ENTER]lesz! Mozg\225s! "
gameforge.main_quest_lv1._80_say = "Most menj, \233s tanuld meg a vad\225szat \233s a harc[ENTER]alapvet\245 met\243dusait! Mihelyt el\233rt\233l egy magasabb[ENTER]szintet, t\233rj vissza a faluba \233s \250jb\243l besz\233lj[ENTER]velem. Mi\233rt \225lldog\225lsz m\233g mindig itt? \218gy nem[ENTER]fogsz tanulni, ha itt \225csorogsz. "
gameforge.main_quest_lv10 = {}
gameforge.main_quest_lv10._100_sayReward = "50.000 tapasztalat pontot kapt\225l.[ENTER]12.000 Yangot kapt\225l.[ENTER]Aranyozott cip\245+4 -et kapt\225l.[ENTER]5 Lila italt kapt\225l. "
gameforge.main_quest_lv10._10_sendLetter = "Menj el a kapit\225nyhoz "
gameforge.main_quest_lv10._110_sayTitle = "Kik\233pz\233s a Kapit\225nyn\225l "
gameforge.main_quest_lv10._120_sayReward = "A Kapit\225ny els\245 k\252ldet\233se a szomsz\233d faluba[ENTER]vezet. Meg kellene l\225togatnod a zen\233sz Yu-Hwan-t,[ENTER]\233s k\233rdezned a titkos dokumentumokr\243l a Kapit\225ny[ENTER]r\233sz\233re. "
gameforge.main_quest_lv10._130_sayTitle = "A zen\233sz Yu-Hwan: "
gameforge.main_quest_lv10._140_say = "Az \233let egy \225lom, mint minden m\225s l\233tez\233si forma[ENTER]az id\245k v\233gtelens\233g\233ben. Honnan j\246v\252nk \233s hov\225[ENTER]megy\252nk? A vil\225g tele van ellens\233gesked\233ssel \233s[ENTER]vit\225val. Az \245szintes\233g zsenge magja soha nem hull[ENTER]term\233keny talajra...[ENTER]Az\233rt j\246tt\233l, hogy hallgasd az \233nekemet? "
gameforge.main_quest_lv10._150_say = "Ah, a Kapit\225ny k\252ld\246tt! Pszt, halkan besz\233lj...[ENTER]Senkinek nem szabad a faluban megtudni a val\243di[ENTER]kil\233temet. Itt van, vedd ezt magadhoz. A[ENTER]dokumentum fontos inform\225ci\243kat tartalmaz, amit[ENTER]gy\251jteni tudtam. Vidd el a Kapit\225nyhoz. "
gameforge.main_quest_lv10._160_sayTitle = "A zen\233sz Yu-Hwan: "
gameforge.main_quest_lv10._170_say = "Menj, \233s siess! Nem j\243, ha t\250l sokat vacill\225lsz.[ENTER]Gondolj mindig arra, hogy az \233let r\246vid \233s ez\233rt[ENTER]dr\225ga. \201lvezd, am\237g csak tudod. "
gameforge.main_quest_lv10._180_targetVid = "Vissza a Kapit\225nyhoz "
gameforge.main_quest_lv10._190_sayReward = "A zen\233sz Yu-Hwan, aki titokban egy k\233m, fontos[ENTER]dokumentumokat adott.[ENTER]Vidd el azokat a Kapit\225nynak az els\245 faluba. "
gameforge.main_quest_lv10._200_say = "Ez az a dokumentum, amit a zen\233sz adott \225t neked?[ENTER]Nem rossz teljes\237tm\233ny egy \250j kalandort\243l! Nagy[ENTER]rem\233nyeket f\251z\246k hozz\225d. Fogadd ezt a munk\225d[ENTER]jutalm\225ul. \201s ugyanilyen j\243 munk\225t v\233gezz az[ENTER]orsz\225god\233rt tov\225bbra is! "
gameforge.main_quest_lv10._20_sayReward = "Imm\225r el\233g tapasztalatot gy\251jt\246tt\233l, hogy teljes[ENTER]jog\250 harcosk\233nt szolg\225ld a birodalmat. Mostant\243l[ENTER]a Kapit\225ny tov\225bbi feladatokkal fog ell\225tni. Az[ENTER]els\245 faluban tal\225lod \245t. Keresd fel, m\225r v\225r r\225d. "
gameforge.main_quest_lv10._30_sayTitle = "Kapit\225ny "
gameforge.main_quest_lv10._40_say = "Ismer\245snek t\251nsz... Igen, most m\225r eml\233kszem. Te[ENTER]vagy az \250j kalandor, akir\245l m\225r mes\233ltek nekem.[ENTER]Nem tudom, hogy milyen j\243 kik\233pz\233sben volt eddig[ENTER]r\233szed, de itt egy p\225r olyan feladat v\225r r\225d, ami[ENTER]val\243sz\237n\251 kih\237v\225st jelent majd sz\225modra. "
gameforge.main_quest_lv10._50_say = "N\233h\225ny kih\237v\225s fog r\225d v\225rni, teh\225t l\233gy k\233sz.[ENTER]Ismered a Sug\225rz\243 \201g f\246ldr\233sz h\225rom Birodalm\225nak[ENTER]a t\246rt\233net\233t? Nem ismered? Mit tan\237tanak a fiatal[ENTER]embereknek manaps\225g az oktat\243k? Ilyen alapvet\245[ENTER]dolgot kell megtan\237tanom neked? "
gameforge.main_quest_lv10._60_say = "Ez fontos, mert ez a f\246ldr\233sz t\246rt\233nete. Ez\233rt[ENTER]ezt neked most \246sszefoglalom.[ENTER]Volt egyszer valaha egy egys\233ges birodalom. Azt\225n[ENTER]j\246ttek a Metink\246vek, \233s h\225bor\250t \233s visz\225lyt[ENTER]sz\237tottak. Az orsz\225got sz\233tosztott\225k: Shinsoo a[ENTER]kereskedelem birodalma, Chunjo a vall\225s[ENTER]birodalma, \233s Jinno a hadvisel\233s birodalma. "
gameforge.main_quest_lv10._70_say = "Minden egyes birodalom pr\243b\225lja a zavarg\225sokat[ENTER]kiheverni, amit a Metink\246vet becsap\243d\225sa az[ENTER]orsz\225gban okozott, hogy ism\233t a fejl\245d\233s \250tj\225ra[ENTER]l\233phessenek. Sokan k\237v\225nj\225k, hogy a f\246ldr\233sz[ENTER]ism\233t egys\233gess\233 v\225ljon. Ez az, ami\233rt neked is[ENTER]ki kell \225llnod! Ezt soha ne felejtsd el. "
gameforge.main_quest_lv10._80_say = "Az els\245 megb\237z\225sodat fogom most veled k\246z\246lni.[ENTER]Ne izgulj, ez egy olyan feladat, amivel k\246nnyen[ENTER]megbirk\243zol. A szomsz\233d faluban \233l egy zen\233sz,[ENTER]Yu-Hwan a neve. De val\243j\225ban titkos k\233mk\233nt[ENTER]t\233nykedik, hogy fontos dokumentumokhoz[ENTER]hozz\225jusson. Sz\252ks\233gem van azokra a[ENTER]dokumentumokra t\245le. Hozd el nekem. \201s ne feledd,[ENTER]ez egy titkos k\252ldet\233s. "
gameforge.main_quest_lv10._90_say = "Nyomd meg az M billenty\251t, hogy megtudd, hogyan[ENTER]jutsz el a k\246vetkez\245 faluba a t\233rk\233pen. Haszn\225ld[ENTER]a teleport\225ci\243s kaput, ami a megfelel\245 falu[ENTER]nev\233vel rendelkezik. Siess! Yu-Hwan nagyon magas[ENTER]- de felismered majd n\225lad l\233v\245 inform\225ci\243k[ENTER]alapj\225n. "
