gameforge.main_quest_lv12._170_say = "Legyilkoltad az Alfa sz\252rkefarkasokat? J\243 munka.[ENTER]Neked k\246sz\246nhetj\252k, hogy k\246nnyebben tudjunk[ENTER]biztons\225gban tartani a falut. Ez a mostani[ENTER]h\225bor\250s id\245kben egy igen j\243 h\237r. "
gameforge.main_quest_lv12._180_sayReward = "40.000 tapasztalat pontot kapt\225l.[ENTER]10.000 Yangot kapt\225l.[ENTER]K\233szs\233gk\246nyvet kapt\225l. "
gameforge.main_quest_lv12._20_say = "T\246bb Alfa sz\252rkefarkas a falun k\237v\252l nagy v\233szt[ENTER]okozott. \213k mindig is vadak voltak, de imm\225r[ENTER]teljesen besz\225m\237thatatlan m\243don reag\225lnak. A[ENTER]falut \233s az utc\225n az embereket megt\225madj\225k. Hogy[ENTER]ism\233t a szitu\225ci\243 ura legy\252nk, meg kell \246lni[ENTER]n\233h\225ny Alfa sz\252rkefarkast. Tudsz seg\237teni? \214lj[ENTER]meg nek\252nk 10 Alfa sz\252rkefarkast. "
gameforge.main_quest_lv12._30_sayReward = "Jutalmul kapni fogsz 24.000 tapasztalati pontot[ENTER]\233s 3.500 Yangot. "
