gameforge.main_quest_lv15 = {}
gameforge.main_quest_lv15._100_say = "A mi birodalmunk, Jinno, mindig komoly hader\245vel[ENTER]rendelkezett. A cs\225sz\225r egyes\237tette a f\246ldr\233szt[ENTER]az er\245s \233s \252t\245k\233pes lovass\225g\225val.[ENTER]Akkor is, ha a forrong\225sok miatt, melyet a[ENTER]Metink\246vek okoztak, a f\246ldr\233sz\252nk r\233szekre[ENTER]bomlott, birodalmunk jogszer\251en Iryung hatalm\225val[ENTER]rendelkezik. "
gameforge.main_quest_lv15._10_qSetTitle = "Az aktu\225lis helyzet "
gameforge.main_quest_lv15._110_say = "Mi m\233g mindig a h\225rom kir\225lys\225g k\246z\252l a[ENTER]leg\252t\245k\233pesebb hader\245vel rendelkez\252nk, annak[ENTER]ellen\233re, hogy a Metink\246vek ellen semmit nem[ENTER]tehet\252nk. Ha igaz\225n akarn\225nk, akkor k\246nnyen le[ENTER]tudn\225nk gy\245zni a t\246bbi orsz\225got. Kem\233nyen eddz,[ENTER]hogy j\243 katona legyen bel\245led. "
gameforge.main_quest_lv15._120_say = "Van egy megb\237z\225som sz\225modra. Vidd el ezt a[ENTER]mun\237ci\243t Yu-Hwan-nak, aki a szomsz\233dos faluban[ENTER]\233l. Ezt a mun\237ci\243t a biztons\225g kedv\233\233rt k\252l\246nb\246z\245[ENTER]helyen rakt\225rban t\225roljuk, amihez sz\252ks\233g eset\233n[ENTER]gyorsan hozz\225f\233r\252nk. Ha Yu-Hwan-t felkeresed,[ENTER]akkor seg\237tesz felfegyverezni a falut. "
gameforge.main_quest_lv15._130_sayReward = "Kapt\225l 36.000 tapasztalati pontot.[ENTER]Kapt\225l 10.000 Yangot.[ENTER]Kapt\225l egy D\237szt\225rgyat. "
gameforge.main_quest_lv15._140_sayTitle = "Az aktu\225lis helyzet "
gameforge.main_quest_lv15._150_sayReward = "A kapit\225ny megb\237zott egy sz\225ll\237t\225ssal[ENTER]Yu-Hwan-nak. Vidd el neki a m\225sodik faluba. "
gameforge.main_quest_lv15._160_say = "Volt valaha egy v\233res csata Sung Mahi \233s a[ENTER]S\225rk\225nyisten k\246z\246tt. Az\243ta az emberek[ENTER]megoszlottak \233s egym\225s ellen v\233res csat\225kban[ENTER]m\233rik \246ssze erej\252ket... Megint te! Sz\252ks\233ged van[ENTER]valamire? A kapit\225ny k\252ld nekem valami fontosat?[ENTER]K\246sz\246n\246m. Menj ism\233t az utadra, nem j\243 ha az[ENTER]emberek benn\252nket egy\252tt l\225tnak. "
gameforge.main_quest_lv15._170_makequestbutton = "Besz\233lj a kapit\225nnyal "
gameforge.main_quest_lv15._175_say = "\193tadtad Yu-Hwannak a kapit\225ny k\252ldem\233ny\233t.[ENTER]Most menj vissza a kapit\225nyhoz \233s vedd fel a[ENTER]jutalmadat. "
gameforge.main_quest_lv15._180_say = "J\243 munka volt! Ha \237gy folytatod nagyon fontos[ENTER]seg\237t\245je lehetsz falvunknak.[ENTER]Itt a jutalmad. "
gameforge.main_quest_lv15._20_say = "Ahogy m\225r hallhattad, jelenleg nem t\250l j\243 a[ENTER]birodalmak k\246z\246tti viszony. Tov\225bbi inform\225ci\243\233rt[ENTER]menj a Kapit\225nyhoz. "
gameforge.main_quest_lv15._30_say = "Ahogy l\225tom, k\233szen \225llsz arra, hogy t\246bbet is[ENTER]megtudj az aktu\225lis helyzetr\245l. Engedd meg, hogy[ENTER]a mi birodalmunkkal kezdjem. Ahhoz, hogy egy[ENTER]harcot megnyerj, el\245sz\246r magadat kell ismerni,[ENTER]miel\245tt az ellens\233ged megismered. "
gameforge.main_quest_lv15._40_say = "A mi birodalmunk, Shinsoo, mindig is egy[ENTER]keresked\245 birodalom volt. Birodalmunkat sz\225mos[ENTER]keresked\245 \250tvonal sz\245tte \225t, ez\233rt a kereskedelem[ENTER]gazdagon gy\252m\246lcs\246z\246tt. De ami\243ta a Metin k\246vek[ENTER]megjelentek, az\243ta a kereskedelem \246sszeomlott \233s[ENTER]a gazdas\225gunk v\225ls\225gba ker\252lt. Keresked\245[ENTER]birodalomk\233nt mi soha nem voltunk komoly katonai[ENTER]hatalom. Ez\233rt zsoldosokat fizett\252nk a[ENTER]gazdas\225gunkb\243l. A zsoldosok megb\237zhat\243ak \233s[ENTER]loj\225lisak, ameddig a megkapj\225k a zsoldjukat. "
gameforge.main_quest_lv15._50_say = "A zsoldoshadseregnek k\246sz\246nhetj\252k, hogy orsz\225gunk[ENTER]valamennyire ism\233t elnyerte stabilit\225s\225t. Hogy a[ENTER]j\246v\245beli harcokra fel tudjunk k\233sz\252lni, tov\225bbi[ENTER]zsoldosokra \233s egy er\245s gazdas\225gra van[ENTER]sz\252ks\233g\252nk. Ez sokat fog k\246vetelni mindenkit\245l. "
gameforge.main_quest_lv15._60_say = "Most \233n neked a k\246vetkez\245 megb\237z\225st adom. Vidd el[ENTER]ezt a specialit\225st a Yu-Hwannak a szomsz\233d[ENTER]faluba. A mi orsz\225gunk egy kereskedelmi[ENTER]birodalom, \233s mi k\252l\246nb\246z\245 r\233gi\243k[ENTER]specialit\225saival keresked\252nk. Ha Yu-Hwannak ezt[ENTER]elviszed, akkor nagyban hozz\225j\225rulsz a falu[ENTER]\233let\233hez. "
gameforge.main_quest_lv15._70_say = "Chunjo Birodalmunkat Yoon-Young korm\225nyz\243[ENTER]ir\225ny\237tja, \233s a mi orsz\225gunk a vall\225son nyugszik.[ENTER]Neki k\246sz\246nhet\245en tudtunk f\245leg Sung Mahi[ENTER]l\233tez\233s\233r\245l. S\225m\225njaink m\225r felk\233sz\237tettek[ENTER]benn\252nket a Metin k\246vek t\225mad\225s\225ra. A mi nagy[ENTER]s\225m\225njaink kem\233nyen dolgoznak manaps\225g az[ENTER]orsz\225gunk biztons\225g\225n.[ENTER]S\225m\225nok olyan k\233pess\233gekkel rendelkeznek, ami a[ENTER]vall\225sukban rejlik. N\233lk\252l\252k csak id\245 k\233rd\233se[ENTER]lenne, hogy egy m\225sik orsz\225g bekebelezne[ENTER]benn\252nket. "
gameforge.main_quest_lv15._80_say = "Az orsz\225gunk lakoss\225g\225nak a hite is nagyon er\245s[ENTER]\233s minden nap a S\225rk\225nyistenhez im\225dkozik. A[ENTER]j\243t\233kony S\225rk\225nyisten v\233delmez benn\252nket \233s[ENTER]megv\233d benn\252nket Sung Mahi felt\225mad\225sa el\245l.[ENTER]Tov\225bbra is v\233dekezni akarunk a barb\225r t\225mad\225sok[ENTER]ellen \233s a f\246ldr\233szt \250jra egyes\237teni szeretn\233nk a[ENTER]hit\252nk erej\233vel. "
gameforge.main_quest_lv15._90_say = "Most adok neked egy \250j megb\237zat\225st. Vidd el ezt a[ENTER]S\225rk\225nyisten k\245szobr\225t Yu-Hwannak a szomsz\233d[ENTER]faluba. A vall\225s \233s a S\225rk\225nyistenbe vetett m\233ly[ENTER]hit\252nk nagyon fontos birodalmunk sz\225m\225ra. Ha ezt[ENTER]elviszed Yu-Hwannak, nagy sz\237vess\233get teszel a[ENTER]falusiaknak. "
