gameforge.main_quest_lv2._70_say = "A Vadkuty\225k nem olyan er\245sek, teh\225t nem lehet[ENTER]olyan neh\233z. Ha ezt a feladatot nem tudod[ENTER]megoldani, akkor ezen a vid\233ken nem fogsz tudni[ENTER]t\250l\233lni! Indulj! Min\233l el\245bb kezded, ann\225l[ENTER]hamarabb v\233gzel! "
