gameforge.main_quest_lv27._130_sayReward = "3.300.000 tapasztalat pontot kapt\225l.[ENTER]270.000 Yangot kapt\225l.[ENTER]Egy Mester k\246nyvet kapt\225l. "
gameforge.main_quest_lv27._140_sayReward = "%s-t kapt\225l. "
gameforge.main_quest_lv27._20_say = "A Metink\246vek okozta puszt\237t\225s egyre rosszabb. Az[ENTER]orsz\225g szenved. Meg kell semmis\237teni a[ENTER]Metink\246veket! Menj a Kapit\225nyhoz. "
gameforge.main_quest_lv27._30_say = "A Metink\246vek okozta puszt\237t\225s egyre rosszabb. Az[ENTER]orsz\225g szenved. Meg kell semmis\237teni a[ENTER]Metink\246veket! Menj a Kapit\225nyhoz. "
gameforge.main_quest_lv27._40_say = "Ahogy hallom, kem\233nyen dolgozt\225l. Az emberek a j\243[ENTER]munk\225dr\243l besz\233lnek. Tartozol nekem valamivel,[ENTER]ami\233rt j\243 helyre k\252ldtelek![ENTER]Haha! Na, ne m\233rgel\245dj m\225r, csak vicceltem![ENTER]Nagyon j\243l v\233gezted a dolgod.[ENTER][ENTER]De a Metink\246vek egyre csak szaporodnak. Ez komoly[ENTER]probl\233m\225t jelent. "
gameforge.main_quest_lv27._50_say = "Ha a Metink\246vek sz\225ma n\245, az emberek szenvednek.[ENTER]N\233ha azon gondolkodok hogy a S\225m\225noknak van igaza[ENTER]\233s a gonosz Sung Mahi isten val\243ban fel lett[ENTER]t\225masztva... De el\245bb az egy\233rtelm\251 probl\233m\225val[ENTER]kell foglalkoznunk. Sz\243lj ha megsemmis\237tett\233l egy[ENTER]Metink\246vet! "
gameforge.main_quest_lv27._60_sayTitle = "Feladat: "
