gameforge.main_quest_lv3._100_say = "L\233gy \252dv\246z\246lve. A v\225ros \245re k\252ld\246tt t\233ged? Van[ENTER]egy egyszer\251 feladatom sz\225modra. Az \233desap\225m egy[ENTER]fontos k\246nyvet hagyott itt ma reggel. S\252rg\245sen[ENTER]sz\252ks\233ge van r\225. "
gameforge.main_quest_lv3._10_npcChat = "Befejeztem az els\245 megb\237zat\225st. "
gameforge.main_quest_lv3._110_say = "El tudod vinni a k\246nyvet az \233desap\225mnak? \201n magam[ENTER]vinn\233m el neki, de nem hagyhatom fel\252gyelet[ENTER]n\233lk\252l a boltot. Ha megteszed nekem ezt a[ENTER]sz\237vess\233get \233s elviszed neki a k\246nyvet,[ENTER]megjutalmaz.[ENTER]Tudnod kell, hogy a faluban fegyverzetet ad el. "
gameforge.main_quest_lv3._120_sayItem = "Fegyverzet el\245\225ll\237t\225sa "
gameforge.main_quest_lv3._130_targetVid = "Tal\225ld meg a Fegyverzet-keresked\245t "
gameforge.main_quest_lv3._140_sendLetter = "Vidd el a k\246nyvet "
gameforge.main_quest_lv3._150_sayReward = "Vidd el a Vegyeskeresked\245 elad\243n\245 \233desapj\225nak a[ENTER]k\246nyvet, amit n\225la felejtett. \213 a[ENTER]Fegyverzet-keresked\245 a faluban. "
gameforge.main_quest_lv3._160_sayTitle = "Fegyverzet-keresked\245: "
gameforge.main_quest_lv3._170_say = "\218gy n\233zel ki, mint az az ember a k\252ldet\233sb\245l! Ah,[ENTER]a l\225nyom k\252ld\246tt! K\246sz\246n\246m. Sz\252ks\233gem van erre a[ENTER]k\246nyvre egy \250j fegyverzet sorozat el\245\225ll\237t\225s\225hoz. "
gameforge.main_quest_lv3._180_say = "A l\225nyomnak val\243sz\237n\251leg nagyon sok a dolga, ha[ENTER]veled k\252ldte el a k\246nyvet. L\225ssuk csak, mi lenne[ENTER]m\233lt\243 jutalom a sz\225modra...? "
gameforge.main_quest_lv3._190_say = "Jutalomk\233nt n\233mi Yangot adok neked, hogy egy[ENTER]harcoshoz m\233lt\243 fegyverzetet tudj\225l venni[ENTER]magadnak rajta. Ennyinek el\233g kell lenni, nem[ENTER]igaz? Mikor sz\252ks\233gem lesz egy kis seg\237ts\233gre,[ENTER]val\243sz\237n\251leg megk\233rlek majd egy \250jabb[ENTER]sz\237vess\233gre. \201s amikor \250gy v\233rtre lesz sz\252ks\233ged,[ENTER]csak l\225togass meg. Az \252zletem mindig nyitva \225ll. "
gameforge.main_quest_lv3._200_sayReward = "850 tapasztalati pontot kapt\225l.[ENTER]5.000 Yangot kapt\225l.[ENTER]20 K\233k italt kapt\225l. "
gameforge.main_quest_lv3._20_say = "\218gy l\225tom, hogy neked \246r\246met okozott ez a[ENTER]feladat. V\225rsz m\225r a k\246vetkez\245re? Keress fel[ENTER]engem, ha el\233rted a k\246vetkez\245 szintet. Akkor egy[ENTER]\250jabb feladattal foglak megb\237zni. "
gameforge.main_quest_lv3._30_sendLetter = "\220zenet a v\225ros \245rt\245l "
gameforge.main_quest_lv3._40_sayReward = "Fejezd be a vad\225szatot \233s menj oda a v\225ros \245rh\246z.[ENTER]Van egy \250jabb feladata sz\225modra. "
gameforge.main_quest_lv3._50_say = "\214r\252l\246k, hogy elj\246tt\233l hozz\225m. Bizony\225ra ismered a[ENTER]vegyeskeresked\245 asszonyt, ugye? Seg\237ts\233get k\233rt[ENTER]t\245lem. Ki tudn\225d der\237teni, mire van sz\252ks\233ge?[ENTER]Rem\233lhet\245leg nem t\250l komoly az \252gy, de biztos[ENTER]vagyok benne, te tudsz neki seg\237teni. "
gameforge.main_quest_lv3._60_say = "Hogy j\243l \233rtes\252lt legy\233l: A vegyeskeresked\245[ENTER]elad\243n\245 regener\225ci\243s italokat \233s egy\233b dolgokat[ENTER]ad el, amik a j\246v\245ben hasznodra v\225lnak, teh\225t nem[ENTER]\225rt j\243ban lenned vele! Most menj. "
gameforge.main_quest_lv3._70_targetVid = "Tal\225ld meg a Vegyeskeresked\245 Elad\243n\245t "
gameforge.main_quest_lv3._80_sendLetter = "Seg\237ts a keresked\245 asszonynak "
gameforge.main_quest_lv3._90_sayReward = "Menj el a vegyeskeresked\245 asszonyhoz, mert[ENTER]sz\252ks\233ge van a seg\237ts\233gedre. "
gameforge.main_quest_lv30 = {}
gameforge.main_quest_lv30._100_say = "Feliratok vannak az eml\233km\251v\246n. Gyorsan lem\225solod. "
gameforge.main_quest_lv30._10_targetVid = "Tal\225ld meg Urielt "
gameforge.main_quest_lv30._110_say = "Uriel-nek igaza van: t\233nyleg volt egy felirat az[ENTER]eml\233km\251v\246n. Nem tudtad elolvasni, de legal\225bb[ENTER]lem\225soltad. Vidd el a jegyzeted Uriel-nek. "
gameforge.main_quest_lv30._120_say = "Megtal\225ltad a Hasun eml\233km\251vet? Oh, van r\243la[ENTER]m\225solatod is. Nagyon j\243! Ez egy egyed\252l\225ll\243[ENTER]t\246rt\233nelmi felfedez\233s! L\225ssuk csak.[ENTER]Hmm... Val\243ban \250gy t\251nik, a metink\246vekr\245l szolg\225l[ENTER]inform\225ci\243val. B\225r nem tudom megfejteni teljesen.[ENTER]Ez az \237r\225s val\243ban \245si, a bet\251k antiknak[ENTER]l\225tszanak. Mit tegy\252nk most? "
gameforge.main_quest_lv30._130_say = "Ah, van egy \246tletem! Ismered a[ENTER]Seungryong-v\246lgyet? Van ott egy titokzatos \245si[ENTER]hely. Ha tal\225lsz ott r\233gi feliratokat, tal\225n[ENTER]tudok k\246vetkeztetni a hi\225nyz\243 bet\251kre is. Menj a[ENTER]Seungryong-v\246lgybe, \233s keresd a Seul Rong[ENTER]eml\233km\251vet. "
gameforge.main_quest_lv30._140_targetVid = "Eml\233km\251 a Seungryong-v\246lgyben "
gameforge.main_quest_lv30._150_say = "Uriel-nek, a tud\243snak t\246bb \245si sz\246vegre van[ENTER]sz\252ks\233ge, hogy k\246vetkeztetni tudjon tov\225bbi,[ENTER]\225ltala ismeretlen bet\251kre.[ENTER]Menj a Seungryong-v\246lgybe, \233s keress feliratot a[ENTER]Seul Rong eml\233km\251v\246n. "
gameforge.main_quest_lv30._160_say = "Tal\225lt\225l tov\225bbi feliratokat? Oh! Neked[ENTER]k\246sz\246nhet\245en hamarosan meg tudom fejteni a[ENTER]Metink\246vek titk\225t. Az \233n kutat\225som tal\225n hamarabb[ENTER]gy\252m\246lcs\246zik, mint v\225rtam.[ENTER]K\246sz\246n\246m, igaz\225n nagyon k\246sz\246n\246m! Tess\233k, k\233rlek,[ENTER]fogadd el ezt a jutalmat a f\225radoz\225sod\233rt. "
gameforge.main_quest_lv30._20_sendLetter = "A Metink\246vek titka "
gameforge.main_quest_lv30._30_say = "Uriel-nek v\233gre van egy kis inform\225ci\243ja a[ENTER]Metink\246vek titk\225r\243l. Menj \233s keresd meg Uriel-t,[ENTER]a tud\243st. "
gameforge.main_quest_lv30._40_sayTitle = "Uriel : "
gameforge.main_quest_lv30._50_say = "A kapit\225ny egyszer m\225r hozz\225m k\252ld\246tt t\233ged.[ENTER]Nagyon j\243 k\233pess\233g\251nek t\251nsz. Egy k\233r\233sem lenne[ENTER]hozz\225d.[ENTER]Bizony\225ra tudsz p\225r dolgot a Metink\246vekr\245l, ugye?[ENTER]A Metink\246vek az \233gb\245l j\246nnek. Nem tudjuk azonban,[ENTER]hogyan ker\252ltek a mi vil\225gunkba \233s hogy mi az[ENTER]\246sszet\233tel\252k. Ez megnehez\237ti a vizsg\225lataimat. A[ENTER]k\246zelm\250ltban azonban r\225bukkantam a Metink\246vek[ENTER]titk\225nak kulcs\225ra. "
gameforge.main_quest_lv30._60_say = "A k\246nny\251 Majom kazamat\225ban az egyik teremben van[ENTER]egy t\225bla, egy \245si kir\225lys\225g eml\233ke. Azt hiszem,[ENTER]a t\225bl\225n tal\225lhat\243 inform\225ci\243 a Metink\246vek[ENTER]titk\225r\243l sz\243l. Ha elhozod nekem ezt az[ENTER]inform\225ci\243t, meg tudom fejteni a Metink\246vek[ENTER]titk\225t. K\233rlek, hozd el nekem ezt az inform\225ci\243t[ENTER]a Hasun eml\233km\251r\245l a k\246nny\251 Majom kazamat\225b\243l! "
gameforge.main_quest_lv30._70_sayReward = "Kapt\225l 122.000 tapasztalat pontot.[ENTER]Kapt\225l 20.000 Yangot.[ENTER]Kapt\225l egy Ez\252st Kark\246t\245t. "
gameforge.main_quest_lv30._80_targetVid = "Eml\233km\251 a k\246nny\251 Majom kazamat\225ban "
gameforge.main_quest_lv30._90_say = "A tud\243s Uriel \250gy gondolja, megtal\225lta a nyomot,[ENTER]ami seg\237thet neki megfejteni a Metink\246vek titk\225t.[ENTER]Menj a k\246nny\251 Majom kazamat\225ba, \233s keresd meg a[ENTER]Hasun eml\233km\251vet. "
