gameforge.main_quest_lv32._120_sayTitle = "H\225zal\243: "
gameforge.main_quest_lv32._130_say = "Mivel az eg\233sz vil\225gon zavarg\225sok vannak, a[ENTER]kereskedelem is neh\233zz\233 v\225lt. Mit akarsz venni?[ENTER]Ah, T\233ged a tud\243s Uriel k\252ld\246tt? T\246rzsv\225s\225rl\243[ENTER]n\225lam, \245 k\252l\246nb\246z\245 szakter\252letekb\245l r\233gi[ENTER]k\246nyveket keres. De sz\225momra ez ink\225bb terhes.[ENTER]Ha, ha,ha. Meg szeretn\233l tudni valamit az \245si[ENTER]k\246nyvekr\245l? Hm... \213si k\246nyvek... "
gameforge.main_quest_lv32._140_say = "Azt, amit p\225r napja hallottam, nem adhatom tov\225bb[ENTER]ingyen! Valamit valami\233rt, hm? A[ENTER]fegyverkereskedelem igaz\225n j\243l megy mostans\225g, de[ENTER]egyszer\251en sajnos nem tudok ekkora mennyis\233get[ENTER]beszerezni! M\225r \237gy is el vagyok havazva az egy\233b[ENTER]rendel\233sekkel! Ahelyett, hogy itt \225lldog\225lsz[ENTER]t\233tlen\252l, mi\233rt nem csin\225lsz valami hasznosat, \233s[ENTER]hozol nekem 20 Ez\252st kard+0 -t? Amint ezt elhozod[ENTER]nekem, megosztom veled az inform\225ci\243t, amit[ENTER]szeretn\233l. "
