gameforge.main_quest_lv32._170_say = "A H\225zal\243 hallott a r\233gi oldalakr\243l. Adj neki 20[ENTER]Ez\252st kard+0 -t, \233s akkor elmondja neked, amit[ENTER]tud. "
gameforge.main_quest_lv32._180_sayTitle = "Szerezz be 20 db ez\252stkard+0-t "
gameforge.main_quest_lv32._190_say = "A H\225zal\243 hallott a r\233gi oldalakr\243l, de nem akarja[ENTER]ingyen megosztani az inform\225ci\243t.[ENTER]Szerezz 20 db Ez\252st kard+0 -t \233s add a H\225zal\243nak[ENTER]az inform\225ci\243\233rt cser\233be. "
gameforge.main_quest_lv32._200_npcChat = "Megszereztem a kardokat. "
gameforge.main_quest_lv32._20_targetVid = "Keresd a tud\243s Urielt "
gameforge.main_quest_lv32._210_say = "J\243. Tehets\233gesebb vagy, mint gondoltam.[ENTER]K\246sz\246n\246m a seg\237ts\233ged, az \252zlet hamarosan jobban[ENTER]megy. Ami az oldalad \233rinti...[ENTER]N\233h\225ny nappal ezel\245tt elmentem egy pavilon \233s egy[ENTER]eml\233km\251 mellett.[ENTER]Megpihentem ott, \233s \233szrevettem egy szakadt[ENTER]pap\237rdarabot az eml\233km\251 l\225b\225n\225l. "
gameforge.main_quest_lv32._220_say = "Akkoriban nem gondoltam semmire ezzel[ENTER]kapcsolatban. De most azt hiszem, az lehetett az[ENTER]a r\233gi oldal, amit keresel. Az eml\233km\251 neve,[ENTER]hmmm... Weol eml\233km\251 volt? Igen, \237gy h\237vt\225k. A[ENTER]Weol eml\233km\251 a szomsz\233d falu k\246zel\233ben. Meg[ENTER]kellene n\233zned ott! "
