gameforge.main_quest_lv32._270_say = "A H\225zal\243 l\225tott egy r\233gi oldalt a Weol eml\233km\251[ENTER]l\225b\225n\225l, amikor megpihent az eml\233km\251 melletti[ENTER]pavilonban.[ENTER]Menj az els\245 falu mellett tal\225lhat\243 Weol[ENTER]eml\233km\251h\246z, \233s n\233zd meg, val\243ban azt az oldalt[ENTER]keresed-e. "
gameforge.main_quest_lv32._280_npcChat = "A Weol eml\233km\251 "
gameforge.main_quest_lv32._290_say = "Ez az eml\233km\251. Oh, ez az! Megvan az oldal! "
gameforge.main_quest_lv32._300_sendLetter = "Az els\245 oldal "
gameforge.main_quest_lv32._30_say = "A tud\243s Uriel h\237vat. Sz\252ks\233ge van a seg\237ts\233gre[ENTER]egy r\233gi, titkos k\246nyvvel kapcsolatos[ENTER]kutat\225s\225hoz. Menj el Urielhez \233s n\233zd meg, mit[ENTER]tehetsz \233rte. "
gameforge.main_quest_lv32._310_targetVid = "Keresd a tud\243s Urielt "
gameforge.main_quest_lv32._320_sayTitle = "Az els\245 oldal meg van "
gameforge.main_quest_lv32._330_say = "K\246vetted a H\225zal\243 \225ltal adott nyomot, \233s[ENTER]megtal\225ltad az els\245 hi\225nyz\243 oldalt. Add \225t a[ENTER]tud\243s Uriel-nek. "
gameforge.main_quest_lv32._340_say = "Na, megtal\225ltad a r\233gi oldalt? Oh, n\225lad van,[ENTER]nagyszer\251! Hadd n\233zzem, hogy mi \225ll benne.[ENTER]Hm... Ez \250gy n\233z ki, mint egy napl\243. Figyelj! "
gameforge.main_quest_lv32._350_sayTitle = "A k\246nyv els\245 oldala: "
gameforge.main_quest_lv32._360_sayReward = "Lee Seop a Taejo birodalomban h\243d\237t\225ssal[ENTER]gyarap\237tja territ\243rium\225t. Felfegyverzett[ENTER]harcosokkal meg akarja h\243d\237tani az \246sszes[ENTER]ter\252letet. Meg kell akad\225lyoznunk, hogy a mi[ENTER]orsz\225gunkat is megh\243d\237tsa. De a lehet\245s\233g\252nk[ENTER]nagyon be van hat\225rolva, mivel t\250l nagy \233s er\245s a[ENTER]serege. Ez\233rt elhat\225roztuk, hogy a betiltott[ENTER]boszork\225nys\225ghoz folyamodunk! "
gameforge.main_quest_lv32._370_sayTitle = "A k\246nyv els\245 oldala, folytat\225s: "
gameforge.main_quest_lv32._380_sayReward = "Ez az egyetlen lehet\245s\233g a t\250l\233l\233sre. Nem tudjuk,[ENTER]hogy eredm\233nyes lesz-e, de minden esetre meg kell[ENTER]pr\243b\225lnunk. Miel\245tt megt\225madnak benn\252nket,[ENTER]inform\225ci\243t kell szerezn\252nk a titkos[ENTER]boszork\225nys\225gr\243l. A legend\225k szerint a[ENTER]S\225rk\225ny-v\246lgyben juthatunk hozz\225 ehhez. "
gameforge.main_quest_lv32._390_say = "A tartalomb\243l arra k\246vetkeztetek, hogy ebben az[ENTER]orsz\225gban egy \245si hiedelem uralkodott. Miel\245tt[ENTER]Lee Seop a Taejo birodalomban egyes\237tette \245ket,[ENTER]minden orsz\225gnak meg volt a tipikus tulajdons\225ga.[ENTER]Ahogy tudom, minden orsz\225gnak megvan a saj\225t[ENTER]vall\225sa. \218gy t\251nik, a k\246nyv szerz\245je meglehet\245sen[ENTER]m\251velt volt. Tal\225n az egyik c\233hhez tartozott,[ENTER]vagy esetleg \245 maga volt a kapit\225nyuk. A c\233hek,[ENTER]melyeket az orsz\225gban alap\237tottak, a t\225rsadalom[ENTER]legfels\245bb r\233teg\233t k\233pviselt\233k. "
gameforge.main_quest_lv32._400_say = "Sok sz\243besz\233d kering a S\225rk\225ny-v\246lgy r\233gi[ENTER]t\246rt\233neteir\245l. \201n is ismerek r\243la n\233h\225ny mes\233t.[ENTER]Tal\225n m\233g mindig tal\225lhatunk valami inform\225ci\243t[ENTER]err\245l, vagy t\246bb oldalt a k\246nyvb\245l. Sajnos m\233g[ENTER]soha nem tudtam kider\237teni, hol is van ez a[ENTER]v\246lgy.[ENTER]Menj a vad\225sz Yang-Shin-hez a szomsz\233d faluban, \245[ENTER]j\243l ismeri a k\246rny\233k \250tjait. Tal\225n \245 tudja, hol[ENTER]van a S\225rk\225ny-v\246lgy, \233s azt is, ha valami[ENTER]haszn\225lhat\243 dolog tal\225lhat\243 ott. "
gameforge.main_quest_lv32._40_say = "\220dv\246z\246llek.[ENTER]Legut\243bb nagyon hasznos volt a munk\225d. A[ENTER]seg\237ts\233geddel k\233pes voltam n\233mi val\243di[ENTER]el\245rel\233p\233sre.[ENTER]De most akadt egy probl\233m\225m. A meteorokr\243l sz\243l\243[ENTER]inform\225ci\243k tanulm\225nyoz\225sa sor\225n tal\225ltam egy[ENTER]r\233gi k\246nyvet. Ha j\243l \233rtem, a haz\225nkat \233rint\245[ENTER]jelent\245s v\225ltoz\225sokra vonatkoz\243 tal\225lgat\225sokr\243l[ENTER]sz\243l.[ENTER]Ez nagyon fontos. "
gameforge.main_quest_lv32._410_say = "Milyen izgalmas! Oh, miel\245tt elfelejten\233m: Itt[ENTER]van a jutalmad az els\245 oldal\233rt! "
gameforge.main_quest_lv32._420_sayReward = "1,000,000 tapasztalati pontot kapsz. "
gameforge.main_quest_lv32._430_sayReward = "50.000 Yangot kapt\225l. "
gameforge.main_quest_lv32._440_sayReward = "Istenn\245i k\246nnyet kapt\225l. "
gameforge.main_quest_lv32._450_sendLetter = "Menj a vad\225szhoz "
gameforge.main_quest_lv32._460_targetVid = "Keresd a vad\225sz Yang-Shin-t "
gameforge.main_quest_lv32._470_sayTitle = "K\233rdezd Yang-Shin-t a S\225rk\225ny-v\246lgyr\245l. "
gameforge.main_quest_lv32._480_say = "A titkos k\246nyv els\245 oldala a S\225rk\225ny-v\246lgyet[ENTER]eml\237ti. Uriel hallott err\245l t\246rt\233neteket, de nem[ENTER]tudja, hol van. Menj a szomsz\233d faluba, \233s[ENTER]k\233rdezd meg a vad\225sz Yang-Shin-t, tud-e valamit[ENTER]err\245l. "
gameforge.main_quest_lv32._490_sayReward = "Tipp: A vad\225sz a szomsz\233d faluban van. "
gameforge.main_quest_lv32._500_npcChat = "Inform\225ci\243 a S\225rk\225nyv\246lgyr\245l "
gameforge.main_quest_lv32._50_say = "Az a probl\233ma, hogy a k\246nyv nagyon r\233gi \233s[ENTER]szakadozott. Az \233vek alatt k\233zr\245l k\233zre adt\225k a[ENTER]k\246nyvet, tal\225n ez az oka, ami\233rt ennyire rossz[ENTER]\225llapotban van. 13 oldal hi\225nyzik a k\246nyvb\245l.[ENTER]El tudn\225d nekem hozni azokat? Val\243sz\237n\251leg van[ENTER]benne n\233h\225ny fontos inform\225ci\243 azokon az[ENTER]oldalakon a h\225bor\250 v\233g\233r\245l. "
gameforge.main_quest_lv32._510_sayTitle = "Yang-Shin: "
gameforge.main_quest_lv32._520_say = "Tudni akarod, hol van a S\225rk\225ny-v\246lgy? Ez a[ENTER]Seungryong-v\246lgy nagyon r\233gi neve. M\225r nincsenek[ENTER]ott s\225rk\225nyok, ehelyett nagysz\225m\250 ork \233s valami[ENTER]titkos szekta k\246vet\245i \233lnek ott. Mi\233rt akarsz[ENTER]ilyen vesz\233lyes helyre menni? M\233g \233n sem szeretek[ENTER]oda menni, pedig \252gyes vad\225sz vagyok. Jobb lenne,[ENTER]ha t\225vol tartan\225d magad t\245le. "
gameforge.main_quest_lv32._530_say = "Micsoda? A r\233gi oldalakat keresed? Hm![ENTER]Egyszer azt hallottam m\225s vad\225szokt\243l, az Ork[ENTER]var\225zsl\243knak van n\233h\225ny oldaluk. K\237v\225ncsi vagyok,[ENTER]vajon ez igaz lehet?[ENTER]Ha te is k\237v\225ncsi vagy, menj, \233s der\237tsd ki.[ENTER]M\225r mondtam neked, az egy vesz\233lyes hely.[ENTER]Nagyon vigy\225zz magadra! "
gameforge.main_quest_lv32._540_sendLetter = "Keresd meg a m\225sodik oldalt "
gameforge.main_quest_lv32._550_say = "Ahogy a vad\225sz m\225r eml\237tette, meg kell tal\225lnod a[ENTER]B\252szke ork var\225zsl\243kat a S\225rk\225ny-v\246lgyben. N\225luk[ENTER]kellene lennie a m\225sodik oldalnak. \214lj B\252szke ork[ENTER]var\225zsl\243kat, hogy megszerezd a m\225sodik oldalt. Ha[ENTER]megkaptad, tov\225bb\237tsd Uriel-nek. "
gameforge.main_quest_lv32._560_sendLetter = "A m\225sodik oldal "
gameforge.main_quest_lv32._570_sayTitle = "Megtal\225ltad a m\225sodik oldalt "
gameforge.main_quest_lv32._580_say = "Sikeresen vad\225szt\225l a B\252szke ork var\225zsl\243kra:[ENTER]megtal\225ltad a Titkos k\246nyv m\225sodik oldal\225t. Vidd[ENTER]el a tud\243s Uriel-nek. "
gameforge.main_quest_lv32._590_say = "Ez a m\225sodik oldal? Hadd n\233zzem meg. H\225t ezt[ENTER]t\233nyleg nem k\246nny\251 kibet\251zni. Az \225ll[ENTER]itt:  "
gameforge.main_quest_lv32._600_sayTitle = "M\225sodik oldal: "
gameforge.main_quest_lv32._60_say = "Mihelyt megtal\225lod a r\233gi oldalakat, hozd ide[ENTER]nekem. Akkor majd megpr\243b\225lom megfejteni. Hmmm...[ENTER]Hol kezdd a keres\233st? R\233gen egy, a szomsz\233d[ENTER]faluban l\233v\245 H\225zal\243 mondta nekem, hogy tal\225lt egy[ENTER]r\233gi k\246nyvoldalt. Menj el hozz\225, l\225ssuk, mire[ENTER]jutsz. "
gameforge.main_quest_lv32._610_sayReward = "Megtal\225ltuk a s\246t\233t m\225gia k\246vet\245it.[ENTER]Rejtve \233lnek a S\225rk\225ny-v\246lgyben. Nagyon j\243l[ENTER]inform\225ltak az \233vek alatt felhalmoz\243dott[ENTER]boszork\225nys\225got illet\245en. Sokakat kellett[ENTER]meggy\245zn\252nk, n\233melyeket fenyeget\233ssel, m\225sokat[ENTER]h\237zelg\233ssel, hogy seg\237tenek. \201s az eredm\233ny:[ENTER]Sz\252ks\233ged van egy k\252l\246nleges helyre a tiltott[ENTER]boszork\225nys\225g folytat\225s\225hoz. A hely tel\237tve volt[ENTER]gonosz energi\225val. Fogyt\225n az id\245, \237gy a lehet\245[ENTER]leggyorsabban meg kellett tal\225lnom a megfelel\245[ENTER]helyet. "
gameforge.main_quest_lv32._620_say = "Sz\252ks\233g\252nk van egy negat\237v energi\225kkal tel\237tett[ENTER]helyre a fekete m\225gia gyakorl\225s\225hoz. Egy helyre,[ENTER]ahol b\225rmit \225t lehet alak\237tani gonosz energi\225v\225.[ENTER]Hmm... Hol tal\225lhatunk ehhez hasonl\243 helyet?[ENTER]Hmm... Hmm... Tudom m\225r, ez lehetne a Hwang[ENTER]templom! Az emberek nem h\237vn\225k ok n\233lk\252l a[ENTER]S\246t\233ts\233g templom\225nak. Ez az a hely, ahov\225 j\243[ENTER]sz\225nd\233k\250 ember nem tenn\233 be a l\225b\225t. M\233g az[ENTER]\225llatok sem akarnak oda menni. \201s a titkos szekta[ENTER]is ott mesterkedik valamiben. "
gameforge.main_quest_lv32._630_say = "Ezen k\237v\252l \246sszef\252gg\233s van a betiltott[ENTER]boszork\225nys\225g \233s a titkos szekta k\246z\246tt. A Hwang[ENTER]templomban tal\225lod a kulcsot. Der\237tsd ki, mi[ENTER]folyik a Hwang templomban, \233s n\233zz k\246r\252l, h\225tha[ENTER]tal\225lsz k\246nyvlapokat is ott![ENTER]Itt a jutalmad a m\225sodik oldal\233rt. "
gameforge.main_quest_lv32._640_sayReward = "1,000,000 tapasztalati pontot kapsz. "
gameforge.main_quest_lv32._650_sayReward = "50.000 Yangot kapt\225l. "
gameforge.main_quest_lv32._660_sayReward = "10 feh\233r z\225szl\243t kapt\225l. "
gameforge.main_quest_lv32._670_sendLetter = "A harmadik oldal "
gameforge.main_quest_lv32._680_say = "M\225r odaadtad Uriel-nek a Titkos k\246nyv els\245 k\233t[ENTER]oldal\225t. A k\246vetkez\245 oldal a Hwang templomban[ENTER]tal\225lhat\243. "
gameforge.main_quest_lv32._690_sayReward = "Tipp: Ez a k\252ldet\233ssorozat akkor folytat\243dik, ha[ENTER]el\233rted a 40-es szintet. "
