gameforge.main_quest_lv32._90_say = "A tud\243s Uriel mes\233lte, hogy a H\225zal\243t\243l hallott[ENTER]valamit egy r\233gi k\246nyvlapr\243l.[ENTER]Menj el a H\225zal\243hoz \233s k\233rdezd meg r\243la. \213t a[ENTER]m\225sodik faluban tal\225lod. "
