gameforge.main_quest_lv40._150_targetVid = "A Wha eml\233km\251 keres\233se "
gameforge.main_quest_lv40._160_sayTitle = "Keresd meg a negyedik oldalt "
gameforge.main_quest_lv40._170_say = "A tud\243s Uriel \250gy gondolja, hogy a Yongbi[ENTER]sivatagban a Jungsun Dong nev\251 majom kazamat\225ban[ENTER]egy tov\225bbi oldalt tudn\225nk tal\225lni. Ott is van[ENTER]k\233t eml\233km\251, tal\225n az egyikn\233l megtal\225ljuk a[ENTER]negyedik oldalt. Menj el a Yongbi sivatagba \233s[ENTER]keresd az eml\233km\251veket a Jungsun Dong[ENTER]kazamat\225ban. "
gameforge.main_quest_lv40._180_say = "Ez a Wha eml\233km\251! "
gameforge.main_quest_lv40._190_say = "De itt nem l\225tok olyat, ami r\233gi napl\243oldal[ENTER]lehetne.[ENTER]Tov\225bb megyek, h\225tha van m\225sik eml\233km\251 is. "
gameforge.main_quest_lv40._200_npcChat = "Keresd meg a Su eml\233km\251vet "
gameforge.main_quest_lv40._20_say = "A tud\243s Uriel r\233gi napl\243oldalakat keres. M\225r[ENTER]vitt\233l neki kett\245t k\246z\252l\252k. Most folytat\243dik az[ENTER]izgalmas vad\225szat a r\233gi k\246nyv titka ut\225n.[ENTER]Az eddigi tapasztalatok azt mutatj\225k, a Hwang[ENTER]templomban \233l\245 B\252szke s\246t\233t fanatikusokn\225l van a[ENTER]k\246vetkez\245 oldal.[ENTER]\218tra fel! "
gameforge.main_quest_lv40._210_say = "Biztos ez az! A Su eml\233km\251. "
gameforge.main_quest_lv40._220_say = "De itt nem l\225tok olyat, ami r\233gi napl\243oldal[ENTER]lehetne.[ENTER]Tov\225bb megyek, h\225tha van m\225sik eml\233km\251 is. "
gameforge.main_quest_lv40._230_sendLetter = "A negyedik oldal "
gameforge.main_quest_lv40._240_sayTitle = "Megtal\225ltad a negyedik oldalt "
gameforge.main_quest_lv40._250_say = "Az \245si eml\233km\251vek bebizony\237tott\225k, h\251en \245rzik[ENTER]kincs\252ket: Jongsun Dong-ban megtal\225ltad a[ENTER]negyedik r\233gi oldalt. Vidd el a tud\243s Uriel-nek. "
gameforge.main_quest_lv40._260_npcChat = "A negyedik r\233gi oldal "
gameforge.main_quest_lv40._270_say = "Oh! Te megtal\225ltad a negyedik r\233gi oldalt.[ENTER]Rem\233lem tov\225bbjutunk az inform\225ci\243k alapj\225n, amit[ENTER]a k\246nyv k\237n\225l. "
gameforge.main_quest_lv40._280_sayTitle = "Negyedik oldal: "
gameforge.main_quest_lv40._290_sayReward = "Most itt vagyok annak a barlangnak a m\233ly\233n, ahol[ENTER]a majmok \233lnek.[ENTER]\218tit\225rsaim k\245v\233 dermedtek, de az itt \246sszegy\251lt[ENTER]negat\237v energia m\233g mindig nem kiel\233g\237t\245. T\250l[ENTER]gyorsan telik az id\245, \233s Lee Seop serege egyre[ENTER]k\246zelebb \233s k\246zelebb \233r. K\237v\225ncsi vagyok, vajon[ENTER]idej\233ben elk\233sz\252l\252nk? "
gameforge.main_quest_lv40._300_sayTitle = "A negyedik oldal folytat\225sa: "
gameforge.main_quest_lv40._30_sayTitle = "Megtal\225ltad a harmadik oldalt "
gameforge.main_quest_lv40._310_sayReward = "Olyan gyorsan kell megtal\225lnom a k\246vetkez\245[ENTER]helyet, ahogy csak lehet. Megpr\243b\225lom a P\243k[ENTER]barlangot. Tal\225n m\233g val\243ra v\225lik a k\237v\225ns\225gunk. "
gameforge.main_quest_lv40._320_say = "Hm. A majom kazamata nem az a hely, amit[ENTER]keres\252nk. Akkor pr\243b\225ljuk \250jra! Az alapj\225n, amit[ENTER]itt mondanak, a P\243k barlangba kell menn\252nk. De[ENTER]el\245bb meg kell oldanunk egy s\252rget\245bb \252gyet: A[ENTER]Kapit\225ny nagyon agg\243dik, mert egy csom\243 idegen[ENTER]\243l\225lkodik a falu k\246zel\233ben, \233s furcsa dolgokat[ENTER]k\233rdeznek. Meg kellene l\225togatnod \245t, \233s[ENTER]kider\237tened, mi folyik ott. "
gameforge.main_quest_lv40._330_say = "Nyugtalan\237t ez az eg\233sz helyzet. L\225ssuk, mit mond[ENTER]a Kapit\225ny. Oh, miel\245tt elfelejtem: Itt a[ENTER]jutalmad a negyedik oldal\233rt. "
gameforge.main_quest_lv40._340_sayReward = "2.000.000 tapasztalat pontot kapt\225l. "
gameforge.main_quest_lv40._350_sayReward = "Kapt\225l egy M\225gia \225ld\225s\225t is. "
gameforge.main_quest_lv40._360_sendLetter = "A balj\243s idegenek "
gameforge.main_quest_lv40._370_targetVid = "Keresd fel a kapit\225nyt "
gameforge.main_quest_lv40._380_sayTitle = "Tudj meg valamit a kapit\225nyt\243l az idegenekr\245l "
gameforge.main_quest_lv40._390_say = "Sz\243besz\233d terjed arr\243l, hogy a faluban megjelent[ENTER]egy csom\243 idegen. Gyan\250s mennyis\233g\251 k\233rd\233st[ENTER]tesznek fel az eml\233km\251vekr\245l. A Kapit\225ny azt[ENTER]akarja, hogy tegy\252nk valamit. Menj, l\225togasd meg,[ENTER]\233s tudj meg t\246bbet. "
gameforge.main_quest_lv40._400_npcChat = "Az idegenek a faluban "
gameforge.main_quest_lv40._40_say = "A tud\243s Uriel felt\233telez\233sei helyesek voltak a[ENTER]B\252szke s\246t\233t fanatikusokr\243l. Megtal\225ltad n\225luk a[ENTER]harmadik napl\243 oldalt. Vidd el az oldalt[ENTER]Uriel-nek. "
gameforge.main_quest_lv40._410_say = "Egyre t\246bb idegen \233rkezett a falunkba.[ENTER]Eml\233km\251vekr\245l \233s \245si k\246nyvekr\245l k\233rdez\245sk\246dtek.[ENTER]N\233h\225ny ember tud ezekr\245l, de nem akarj\225k[ENTER]elmondani az idegeneknek. F\233lek, hogy ez[ENTER]mindannyiunkat bajba sodor. Senki sem tudja, ki[ENTER]k\252ldte ezeket az idegeneket, \233s hogy milyen[ENTER]messzire k\233pesek menni az inform\225ci\243 megszerz\233se[ENTER]\233rdek\233ben. Elv\233gre h\225bor\250ban vagyunk. "
gameforge.main_quest_lv40._420_say = "Ha j\243k az \233rtes\252l\233seim, Nakajima-nak a szomsz\233dos[ENTER]falub\243l valami k\246ze van hozz\225.[ENTER]Pr\243b\225ld kider\237teni, hogy mit akarnak itt az[ENTER]idegenek. "
gameforge.main_quest_lv40._430_sendLetter = "Menj Nakajima-hoz "
gameforge.main_quest_lv40._440_say = "A Kapit\225ny \250gy v\233li, \246sszef\252gg\233s van Nakajima \233s[ENTER]az idegenek k\246z\246tt, akik a faluban mindenfel\233 az[ENTER]eml\233km\251vekr\245l \233rdekl\245dnek. Menj Nakajima-hoz, \233s[ENTER]der\237tsd ki, mit tud. A m\225sodik falu hat\225r\225ban[ENTER]tal\225lod. "
gameforge.main_quest_lv40._450_npcChat = "Ismered az idegeneket a faluban? "
gameforge.main_quest_lv40._460_sayTitle = "Nakajima: "
gameforge.main_quest_lv40._470_say = "Tess\233k? Milyen k\233rd\233s ez? Sajn\225lom. Nem tudok[ENTER]seg\237teni. Fogalmam sincs, mir\245l besz\233lsz. Nem,[ENTER]nem. A mostani id\245kben el\233g neh\233z munk\225t tal\225lni.[ENTER]Mit kellene tennem, hogy t\250l\233ljem, hm? "
gameforge.main_quest_lv40._480_say = "Na j\243, bevallom. Csak az\233rt egyeztem bele, hogy[ENTER]seg\237tek nekik, mert egy csom\243 Yangot \237g\233rtek.[ENTER]Nem tudom, mit akarnak itt az idegenek. De[ENTER]megb\237ztak egy feladattal: Brut\225lis kapit\225nyokat[ENTER]kellene \246ln\246m. "
gameforge.main_quest_lv40._490_say = "Te tal\225n t\246bbet megtudsz a Brut\225lis[ENTER]kapit\225nyokt\243l. Az idegenek nagyon szerett\233k[ENTER]volna, ha meg\246l\246m. Oh, van egy \246tletem: Mi\233rt nem[ENTER]m\233gy oda, \233s \246l\246d meg helyettem? K\233rlek! "
gameforge.main_quest_lv40._500_sendLetter = "\214ld meg a brut\225lis kapit\225nyokat "
gameforge.main_quest_lv40._50_say = "Oh, te megtal\225ltad a k\246vetkez\245 utal\225st?![ENTER]Ez a harmadik oldal. N\233zz\252k meg, hogy mi van[ENTER]r\225\237rva. "
gameforge.main_quest_lv40._510_say = "Nakajima bevallotta, hogy az idegenek meg akarj\225k[ENTER]\246lni a Brut\225lis kapit\225nyokat. Mivel az idegenek a[ENTER]Napl\243 oldalakr\243l k\233rdez\245sk\246dtek, val\243sz\237n\251leg a[ENTER]Brut\225lis kapit\225nyokn\225l is van egy oldal. Hogy[ENTER]t\246bbet tudjak, meg kell \246ln\246m a Brut\225lis[ENTER]kapit\225nyokat. A m\225sodik falun k\237v\252l tal\225lhat\243k. "
gameforge.main_quest_lv40._520_sendLetter = "Megtal\225ltad az \246t\246dik oldalt "
gameforge.main_quest_lv40._530_say = "Az idegenek el\245tt \233rtem oda, \233s megszereztem a[ENTER]Brut\225lis kapit\225nyokt\243l az \246t\246dik napl\243oldalt.[ENTER]Biztos vagyok benne, az idegenek elt\251nnek most,[ENTER]hogy semmi sem maradt, amit tal\225lhatn\225nak.[ENTER]Legjobb, ha ezt az oldalt elviszem a tud\243s[ENTER]Uriel-nek, \237gy meg tudom fejteni. "
gameforge.main_quest_lv40._540_sayTitle = "Az \246t\246dik oldal "
gameforge.main_quest_lv40._550_sayReward = "Tipp: Te a titkos k\246nyv \246t\246dik oldal\225t csak akkor[ENTER]viheted Urielhez, ha a 47. szintet m\225r el\233rted.[ENTER]\213rizdd meg j\243l az oldalt. "
gameforge.main_quest_lv40._60_sayTitle = "Harmadik oldal: "
gameforge.main_quest_lv40._70_sayReward = "Egy olyan helyhez \233rkezt\252nk, ahol a Gonosz[ENTER]energi\225ja m\225r kisug\225rzott. De m\233g nem el\233gg\233...[ENTER]Hol lehet a boszork\225nykod\225st m\251velni? Egy \250j[ENTER]inform\225ci\243 szerint a Yongbi sivatagban van egy[ENTER]elrejtett hely. Teljes rem\233nnyel teleport\225lunk[ENTER]teh\225t a Yongbi sivatagba. "
gameforge.main_quest_lv40._80_say = "Sz\243val, nem tudt\225k el\233rni a c\233ljukat a[ENTER]S\225rk\225ny-v\246lgyben. Hmm... A Yongbi-sivatag?[ENTER]\193ltal\225ban kev\233s emberrel tal\225lkozol ott, \233s a[ENTER]ter\252let is nagyr\233szt ismeretlen. De ez nagyon[ENTER]bonyolult. Hol tal\225ljuk meg azt a ter\252letet,[ENTER]amir\245l \245k besz\233lnek? Felt\233telezem, a Jungsun Dong[ENTER]majom kazamat\225ra gondolnak. Ez egy nagyon m\233ly[ENTER]barlang, \233s rendk\237v\252l alkalmas a rossz energia[ENTER]\246sszegy\251jt\233s\233re. "
gameforge.main_quest_lv40._90_say = "K\233rlek, menj el a Jungsun Dong-ba, \233s keress t\246bb[ENTER]k\245 eml\233km\251vet. Egy kis szerencs\233vel t\246bb oldalt[ENTER]tal\225lhatsz az eml\233km\251vek mellett. Oh, \233s persze[ENTER]nem feledkezhet\252nk meg a jutalmadr\243l sem a[ENTER]harmadik oldal\233rt. "
gameforge.main_quest_lv47 = {}
gameforge.main_quest_lv47._100_sayTitle = "Az oldal a p\243k kazamat\225ban "
gameforge.main_quest_lv47._10_sayTitle = "Oldal a Brut\225lis kapit\225nyokt\243l "
gameforge.main_quest_lv47._110_say = "Uriel azt gondolja, hogy tov\225bbi inform\225ci\243kat[ENTER]tal\225lhatunk a P\243k kazamat\225ban a fekete m\225gi\225r\243l.[ENTER]Lehet, tal\225lunk ott is egy eml\233km\251vet, mint[ENTER]amilyen a Majom kazamat\225ban volt.[ENTER][ENTER]A Yongbi-sivatagon \225tkelve \233rheted el a P\243k[ENTER]kazamat\225t. "
gameforge.main_quest_lv47._120_npcChat = "A Mok eml\233km\251 "
gameforge.main_quest_lv47._130_say = "Val\243ban itt egy eml\233km\251, \233s egy Napl\243 oldal is![ENTER]Gyorsan menj vissza Uriel-hez. "
gameforge.main_quest_lv47._140_sayTitle = "Megtal\225ltad a hatodik oldalt "
gameforge.main_quest_lv47._150_say = "Tal\225lt\225l egy m\225sik \245si eml\233km\251vet a P\243k[ENTER]kazamat\225ban, \233s ugyancsak megtal\225ltad ott[ENTER]elrejtve a hatodik napl\243 oldalt. Vidd el a tud\243s[ENTER]Uriel-nek. "
gameforge.main_quest_lv47._160_npcChat = "A hatodik oldal "
gameforge.main_quest_lv47._170_say = "Milyen volt a p\243k kazamata? Megtal\225ltad a hatodik[ENTER]oldalt? Ez fantasztikus! Agg\243dtam, hogy tal\225n[ENTER]elk\233sel. Valaki mindig hall valamit m\225s[ENTER]emberekr\245l, akik szint\233n a fekete m\225gia titkai[ENTER]ut\225n kutatnak. Nagyon fontos inform\225ci\243nak t\251nik.[ENTER]L\225ssuk, mit mond ez az oldal. "
gameforge.main_quest_lv47._180_say = "Oh, nem, ez az oldal nagyon nehezen olvashat\243. A[ENTER]szok\225sosn\225l hosszabb ideig tart megfejtenem. De a[ENTER]tartalma nagyon fontosnak l\225tszik. Ez a szimb\243lum[ENTER]jelenti a \"fekete m\225gi\225t\", sz\243val hat\225rozottan a[ENTER]helyes \250ton j\225runk. Szeretn\233m tudni, mi\233rt[ENTER]tiltott\225k be a fekete m\225gi\225t. Val\243sz\237n\251leg j\243 oka[ENTER]van. "
gameforge.main_quest_lv47._190_say = "Am\237g megpr\243b\225lom megfejteni ezt az oldalt,[ENTER]elmehetn\233l a zen\233sz Yu-Hwan-hoz. Azt hallottam,[ENTER]van valami \233rdekes inform\225ci\243ja a kutat\225sunkhoz.[ENTER]Mire vissza\233rsz, el tudom mondani neked, mir\245l[ENTER]sz\243l ez az oldal. De term\233szetesen m\225r most[ENTER]megkapod a jutalmad. "
gameforge.main_quest_lv47._200_sayReward = "3.000.000 tapasztalat pontot kapt\225l. "
gameforge.main_quest_lv47._20_say = "A 40. szinten megtal\225ltad a Brut\225lis[ENTER]Kapit\225nyokn\225l a titkos k\246nyv 5. oldal\225t. Ezt most[ENTER]vidd el Uriel-hez. "
gameforge.main_quest_lv47._210_sayReward = "75.000 Yangot kapt\225l. "
gameforge.main_quest_lv47._220_sayReward = "Kapt\225l egy S\225rk\225ny \225ld\225s\225t. "
gameforge.main_quest_lv47._230_sendLetter = "Menj Yu-Hwan-hoz "
gameforge.main_quest_lv47._240_targetVid = "Keresd Yu-Hwan zen\233szt "
gameforge.main_quest_lv47._250_sayTitle = "A titkos er\245k "
gameforge.main_quest_lv47._260_say = "A zen\233sz Yu-Hwan-nak lehet valami inform\225ci\243ja a[ENTER]r\233gi napl\243oldalakr\243l. L\225togasd meg, \233s k\233rdezd[ENTER]err\245l. "
gameforge.main_quest_lv47._270_npcChat = "Valami h\237r? "
gameforge.main_quest_lv47._280_say = "\201lvezd az \233letet, mert nagyon r\246vid![ENTER]Trallalaaa... Ah, h\225t \250jra itt vagy. Most[ENTER]val\243sz\237n\251leg a tud\243s Uriel-t\245l j\246tt\233l. K\233rte,[ENTER]hogy egy kicsit k\233rdez\245sk\246djek k\246rbe. Azt[ENTER]tal\225ltam, hogy minden birodalom emberei m\225r[ENTER]ezeket a fontos dokumentumokat keresik.[ENTER]Sajnos senki sem tudta pontosan megmondani, mi ez[ENTER]az eg\233sz. "
gameforge.main_quest_lv47._290_say = "Egy kicsit furcsa, hogy ezek a lopakod\243 \225rnyak[ENTER]itt \243l\225lkodnak, m\237g mi egy h\225bor\250 kell\245s[ENTER]k\246zep\233ben vagyunk. Term\233szetesen te kiv\233tel vagy![ENTER]Azt is hallottam, hogy a Sivatagi bandit\225k a[ENTER]fosztogat\225saik sor\225n hozz\225jutottak n\233h\225ny,[ENTER]sz\225mukra igen fontos dologhoz.[ENTER]Tal\225n vetned kellene r\225juk egy pillant\225st, hogy[ENTER]megszerezhesd t\245l\252k. "
gameforge.main_quest_lv47._300_say = "A Sivatagi bandit\225k nagyon vesz\233lyes[ENTER]sz\246rnyetegek, sz\243val vigy\225zz magadra. De azt[ENTER]hiszem, meg\233ri. Neked fogok szentelni egy dalt,[ENTER]\233s r\225b\237zom a sz\233lre, hogy k\246vessen a sivatagba. "
gameforge.main_quest_lv47._30_npcChat = "Az \246t\246dik oldal "
gameforge.main_quest_lv47._310_sendLetter = "A Sivatagi bandit\225k "
gameforge.main_quest_lv47._320_sayTitle = "A titkos inform\225ci\243k keres\233se "
gameforge.main_quest_lv47._330_say = "Uriel-nek inform\225ci\243ra van sz\252ks\233ge a fekete[ENTER]boszork\225nys\225gr\243l. A zen\233sz Yu-Hwan azt mondta, a[ENTER]Sivatagi bandit\225k elloptak valamit, ami a[ENTER]seg\237ts\233g\252nkre lehet. Meg kellene \246ln\246m egy p\225r[ENTER]Sivatagi bandit\225t. "
gameforge.main_quest_lv47._340_sendLetter = "Megtal\225ltad a hetedik oldalt "
gameforge.main_quest_lv47._350_targetVid = "Yu-Whan keres\233se "
gameforge.main_quest_lv47._360_say = "A zen\233sz Yu-Hwan \225ltal adott inform\225ci\243knak[ENTER]k\246sz\246nhet\245en megtal\225ltad a titkos k\246nyv hetedik[ENTER]oldal\225t a Sivatagi bandit\225kn\225l. Menj Yu-Hwan-hoz,[ENTER]\233s mondd el neki, helyes volt az inform\225ci\243ja. "
gameforge.main_quest_lv47._370_say = "Gy\246ny\246r\251 a szemed, mint egy tengerszem[ENTER]lalalala... H\233, m\225r megint itt vagy. Sikeresen[ENTER]megszerezted az inform\225ci\243kat a Sivatagi[ENTER]bandit\225kt\243l? Mi, ez minden? Egy r\233gi pap\237rdarab?[ENTER]Ezzel semmit sem tudok kezdeni. De ha t\233ged[ENTER]boldogg\225 tesz... Vidd el Uriel-nek. \201s add \225t[ENTER]neki \252dv\246zletemet! "
gameforge.main_quest_lv47._380_sendLetter = "Menj Urielhez. "
gameforge.main_quest_lv47._390_targetVid = "Menj Urielhez. "
gameforge.main_quest_lv47._400_sayTitle = "A hetedik oldal "
gameforge.main_quest_lv47._40_say = "Megvan az \246t\246dik oldal? Hihetetlen! T\233nyleg[ENTER]nagyon szerencs\233sek vagyunk, hogy ennyi \233v ut\225n[ENTER]m\233g egy\225ltal\225n l\233teznek ezek az oldalak. Te[ENTER]t\233nyleg tudsz valamit![ENTER]\201s most l\225ssuk, mit mond ez az oldal. "
gameforge.main_quest_lv47._410_say = "Megtal\225ltad a r\233gi napl\243 hetedik oldal\225t.[ENTER]Vidd el Uriel-nek. "
gameforge.main_quest_lv47._420_say = "Szia, j\243, hogy \250jra l\225tlak! J\243 h\237rem van:[ENTER]megfejtettem a hatodik oldal tartalm\225t. Nem[ENTER]rossz, mi? Be kell vallanom, nagyon b\252szke vagyok[ENTER]magamra, mert megakadt a szemem ezen a[ENTER]karakteren... Tess\233k? Tal\225lt\225l egy m\225sikat is?[ENTER]Istenem! Ez t\233nyleg gyors volt. Mutasd! Nah\225t,[ENTER]ezt honnan szerezted? Ha nem t\233vedek, ezeket a[ENTER]karaktereket az uralkod\243 csal\225d haszn\225lta. "
gameforge.main_quest_lv47._430_say = "Mivel ezeket az \237r\225sjeleket csak nagyon kevesen[ENTER]\233s nagyon ritk\225n haszn\225lt\225k, ez\233rt neh\233z lesz[ENTER]leford\237tani... De azt hiszem, m\233g senkinek nem[ENTER]\225rtott meg egy kis kih\237v\225s, hahaha! Alig v\225rom,[ENTER]hogy folytassam. A Sivatagi bandit\225k a rejt\233lyes[ENTER]idegenekt\245l lopt\225k ezt az oldalt? Hmm...[ENTER]Ez jelentheti azt, hogy az idegenek meg\233rtik[ENTER]ezeket a karaktereket? Ez kezd nagyon zavaross\225[ENTER]v\225lni.[ENTER]Meg kell bizonyosodnunk arr\243l, hogy nem hagytunk[ENTER]semmit figyelmen k\237v\252l. "
gameforge.main_quest_lv47._440_say = "Oh, igen, eln\233z\233st... Miel\245tt a k\246vetkez\245 oldalra[ENTER]koncentr\225lok, tal\225n nem \225rtana elmondanom, mi[ENTER]volt a hatodik oldalon. Hrm-hrm... "
gameforge.main_quest_lv47._450_sayTitle = "Hatodik oldal: "
gameforge.main_quest_lv47._460_sayReward = "Fogyt\225n az id\245. M\225r kipr\243b\225ltuk a fekete m\225gi\225t a[ENTER]P\243k kazamat\225ban is, de m\233g mindig nem m\251k\246dik.[ENTER]Mi hi\225nyzik? N\233h\225ny misztikusunk \250gy v\233li, a[ENTER]fekete m\225gia a nagyobb \225ldozatt\243l f\252gg.[ENTER]Ha ez igaz, akkor rendk\237v\252l hatalmas er\245re van[ENTER]sz\252ks\233g\252nk. "
gameforge.main_quest_lv47._470_sayReward = "A mes\233k \233s legend\225k szerint ez a fajta m\225gia[ENTER]mindig is ember\225ldozatot k\246vetelt. De ha meg\246l\246m[ENTER]a szeretteiket az olt\225rn\225l, a h\237rnevem jelent\245sen[ENTER]megromlik az emberek k\246z\246tt. Megfelel\245[ENTER]helyettes\237t\233sre van sz\252ks\233g\252nk. Pr\243b\225ljuk meg a[ENTER]K\237gy\243 kard harcosokat a sivatagban. "
gameforge.main_quest_lv47._480_say = "Aha. Teh\225t mivel embereket nem haszn\225lhatnak[ENTER]\225ldozatk\233nt, ez\233rt \250gy d\246nt\246ttek, hogy[ENTER]k\237gy\243harcosokat v\225lasztanak. Nem mondan\225m, hogy[ENTER]tetszik ez az \250j fejlem\233ny. Ennek rossz v\233ge[ENTER]lesz... De ennek ellen\233re tov\225bbra is k\246vetn\252nk[ENTER]kell a nyomot. Menj a sivatagba, \233s \246lj meg[ENTER]n\233h\225ny K\237gy\243 kard harcost \233s K\237gy\243 \237j\225szt. Ki[ENTER]tudja, mit tal\225lhatunk m\233g ott. Aprop\243: tess\233k,[ENTER]itt a jutalmad! "
gameforge.main_quest_lv47._490_sendLetter = "\214ld meg a k\237gy\243harcosokat "
gameforge.main_quest_lv47._500_sayTitle = "A nyolcadik oldal "
gameforge.main_quest_lv47._50_sayTitle = "\214t\246dik oldal: "
gameforge.main_quest_lv47._510_say = "A napl\243 bemutatja a fekete m\225gia gyakorl\225s\225hoz[ENTER]v\233gzett k\237s\233rletet a K\237gy\243 kard harcosok \233s K\237gy\243[ENTER]\237j\225szok fel\225ldoz\225s\225r\243l. Menj a Yongbi-sivatagba,[ENTER]\233s \246lj K\237gy\243 kard harcosokat. Keress tov\225bbi[ENTER]inform\225ci\243t! "
gameforge.main_quest_lv47._520_sendLetter = "Megtal\225ltad a nyolcadik oldalt "
gameforge.main_quest_lv47._530_targetVid = "Menj Urielhez, a tud\243shoz "
gameforge.main_quest_lv47._540_say = "A sivatagban megtal\225ltad a nyolcadik napl\243 oldalt[ENTER]a K\237gy\243 kard harcosokn\225l. Vidd el a tud\243s[ENTER]Uriel-nek. "
gameforge.main_quest_lv47._550_say = "Ez a nyolcadik oldal. Nagyon j\243! Mivel ez nagyon[ENTER]r\246vid, azt hiszem, r\246gt\246n el is tudom olvasni.[ENTER]Csak egy pillanat... Ah, igen. "
gameforge.main_quest_lv47._560_sayTitle = "Nyolcadik oldal: "
gameforge.main_quest_lv47._570_sayReward = "Megtal\225ltuk a megfelel\245 \225ldozatot. Szerencs\233sek[ENTER]vagyunk! K\237v\225ncsi vagyok, ez vajon egy jel?[ENTER]Sz\252ks\233g\252nk van egy \252nnepi harangra. Ha j\243l[ENTER]eml\233kszem, a p\243kokn\225l van egy ilyen. M\225ris[ENTER]indulnunk kell. "
gameforge.main_quest_lv47._580_say = "Ah, \250jra a P\243k kazamata, furcsa. Oda kell menned[ENTER]megkeresni a harangot. Ez egy f\225raszt\243 \250t, sz\243val[ENTER]el\245bb pihenj egy kicsit \233s gyere vissza k\233s\245bb.[ENTER]\201n is megyek egy kicsit elm\233lkedni \233s leford\237tani[ENTER]n\233h\225ny t\246red\233ket. Amikor visszat\233rsz, \250j[ENTER]k\252ldet\233st adok neked. \201s ne agg\243dj, term\233szetesen[ENTER]m\225ris megkapod a jutalmad a nyolcadik oldal\233rt. "
gameforge.main_quest_lv47._590_sayReward = "3.000.000 EXP-t kapt\225l.[ENTER]70.000 Yangot kapt\225l.[ENTER]20 B\225tors\225g k\246penyt kapt\225l.[ENTER]Megjegyz\233s: A k\246vetkez\245 feladathoz legal\225bb 50-es[ENTER]szint\251nek kell lenned. "
gameforge.main_quest_lv47._60_sayReward = "Lee Seop meg\233rkezett lovascsapat\225val a Taejo[ENTER]birodalomba \233s \250gy t\251nik, elid\245zik ott egy[ENTER]kicsit. Mindek\246zben orsz\225gszerte elkezdtek[ENTER]kisebb-nagyobb meteoritok esni, k\225oszt,[ENTER]puszt\237t\225st \233s visz\225lyt okozva.[ENTER]A hatalmas birodalom h\225rom kisebb r\233szre szakadt,[ENTER]\233s egym\225s ellen harcoltak, ahelyett, hogy egy\252tt[ENTER]sz\225lltak volna szembe a gonosszal. A S\225rk\225nyisten[ENTER]egyik\252nkh\246z sem sz\243l m\225r. N\233ha az egyik felet[ENTER]t\225mogatja, m\225skor a m\225sikat, \237gy mindenki az \245[ENTER]kegyei\233rt k\252zd. A katasztr\243fa pedig id\245k\246zben[ENTER]egyre csak n\246vekszik... "
gameforge.main_quest_lv47._70_sayTitle = "Uriel : "
gameforge.main_quest_lv47._80_say = "Egy szemtan\250 \233szrev\233tele korunk hajnal\225n.[ENTER]Ez megfizethetetlen! Oh igen, fizet\233s. Itt a[ENTER]jutalmad a kiv\225l\243 munk\225d\233rt. \201s m\233g valami:[ENTER]Nyilv\225nval\243an valaki m\225s is ugyanazokat kutatja,[ENTER]amiket mi, sz\243val nem vesztegethet\252nk t\246bb id\245t.[ENTER]Az oldal tetej\233n azt \237rj\225k, Lee Seop a P\243k[ENTER]kazamat\225ban kereste a gonosz energi\225t. Ha tal\225lsz[ENTER]ott b\225rmit is, r\246gt\246n t\233rj vissza hozz\225m.[ENTER]Nem v\225rhatok! "
