gameforge.main_quest_lv50._230_say = "Ah, megtal\225ltad a m\233g hi\225nyz\243 tizedik oldalt![ENTER]Nagyszer\251, egyre jobban k\246zeled\252nk a t\246rt\233net[ENTER]v\233g\233hez. M\233g j\243, hogy mindent dokument\225ltak,[ENTER]k\252l\246nben elveszett volna ez a tud\225s. L\225ssuk, mit[ENTER]mond ez az oldal. "
gameforge.main_quest_lv50._235_sayTitle = "Tizedik oldal: "
gameforge.main_quest_lv50._240_sayReward = "Siker\252lt visszavern\252nk az els\245 t\225mad\225st. De[ENTER]hamarosan itt a k\246vetkez\245. A terep Lee Seops[ENTER]neh\233z lovasainak kedvez \233s nek\252nk is ad[ENTER]valamennyi el\245nyt, de \245k t\250l sokan vannak. Nem[ENTER]gy\245zhet\252nk.[ENTER]Csak egy utols\243 es\233ly\252nk maradt, a befejezni[ENTER]fekete boszork\225nys\225gunk kutat\225s\225t. Az \233j leple[ENTER]alatt \225tt\246rj\252k az ellens\233g vonalait \233s[ENTER]visszamegy\252nk a P\243k kazamat\225ba. Im\225dkozom. Nem a[ENTER]gy\245zelem\233rt, hanem egy kis rem\233ny\233rt... "
gameforge.main_quest_lv50._250_say = "Oh! Azt hiszem, m\225r majdnem c\233lba \233rt\252nk![ENTER]Hamarosan megfejtj\252k, mir\245l is sz\243l a fekete[ENTER]m\225gia! Alig v\225rom! Neked viszont \250jra vissza kell[ENTER]menned a P\243k kazamat\225ba. Rem\233lhet\245leg ott van a[ENTER]k\246nyv tizenegyedik oldala. "
gameforge.main_quest_lv50._260_say = "\201s itt van - ism\233t - a j\243l meg\233rdemelt jutalom! "
