gameforge.main_quest_lv50._340_say = "A p\243k kazamat\225ban megtal\225ltad a 11. oldalt. Vidd[ENTER]el Urielhez. "
gameforge.main_quest_lv50._350_say = "Tudsz valami \250jat? Aha, a 11. oldal! n\233zz\252k...[ENTER]Ah igen, el\233g egyszer\251nek t\251nik. M\225r el\233g j\243l[ENTER]tudom olvasni ezeket a karaktereket. Most ezt[ENTER]n\233zd! "
gameforge.main_quest_lv50._355_sayTitle = "Tizenegyedik oldal: "
gameforge.main_quest_lv50._360_sayReward = "Nem siker\252lt. Minden el\245k\233sz\252let\252nk ellen\233re[ENTER]gyorsan kellett reag\225lnunk. T\250l gyorsan. Sokunk[ENTER]megs\233r\252lt \233s p\225ran meg\245r\252ltek. A s\246t\233t m\225gia maga[ENTER]az \246rd\246g. Lee Seop serege fel\233nk tart, de az most[ENTER]nem \233rdekes. Nincs el\233g ember\252nk megv\233deni[ENTER]magunkat \233s mindenk\233pp meghalunk. "
gameforge.main_quest_lv50._365_sayTitle = "A tizenegyedik oldal folytat\225sa: "
gameforge.main_quest_lv50._370_sayReward = "Az utols\243 gondolatunk az volt hogy a marad\233k[ENTER]sereget egyben tartjuk \233s ez er\245t ad nek\252nk: az[ENTER]inform\225toraink a s\225rk\225ny-v\246lgyben hazudtak. Nem[ENTER]figyelmeztettek minket a s\246t\233t er\245k[ENTER]mell\233hat\225saira. Ez\233rt m\233g fizetni fognak. Ez lesz[ENTER]az utols\243 tett\252nk ezen a f\246ld\246n. "
gameforge.main_quest_lv50._380_say = "H\225t, az utols\243 pillanatban fordult a kocka.[ENTER]Szomor\250 t\246rt\233net.[ENTER]De sajnos nem b\237zhatsz meg senkiben aki a s\246t\233t[ENTER]m\225gi\225val kapcsolatba ker\252lt. Tudniuk kellett[ENTER]volna. El\233g \233rdekes hogy ezen sorok szerz\245j\233nek[ENTER]is siker\252lt azokr\243l az el\233rhetetlen s\233m\225kr\243l[ENTER]inform\225ci\243t szereznie. V\233gig kell j\225rjuk az utat,[ENTER]m\233g ha vesz\233lyes is. Mindannyian tudjuk hogy[ENTER]sz\233gyen lenne feladni most. "
gameforge.main_quest_lv50._390_say = "M\225r volt\225l a Seungryong-v\246lgyben. Nem hiszem hogy[ENTER]tal\225lunk b\225rmi m\225st is ott. Hmm, azon gondolkodom[ENTER]hol m\225shol n\233zhetn\233nk meg... tudom! Az[ENTER]eml\233kiratokban van sok olyan r\233sz amelyet m\233g nem[ENTER]vizsg\225ltunk meg. Vannak amelyek m\225sik[ENTER]birodalmakban vannak! Nagyon vesz\233lyes oda menni.[ENTER]Biztosan meg fognak t\225madni. K\233sz\252lj fel rendesen[ENTER]\233s gyere hozz\225m mikor k\233sz vagy. "
gameforge.main_quest_lv50._400_say = "De el\245sz\246r itt a jutalom a 11. oldal\233rt. "
gameforge.main_quest_lv50._40_targetVid = "Menj Urielhez, a tud\243shoz "
gameforge.main_quest_lv50._410_sayReward = "6.000.000 tapasztalatot kapt\225l.[ENTER]150.000 Yangot kapt\225l.[ENTER]Kapt\225l egy S\225rk\225ny med\225lj\225t.[ENTER]Tipp: A k\246vetkez\245 feladathoz legal\225bb az 55.[ENTER]szintet el kell \233rned "
gameforge.main_quest_lv50._50_sayTitle = "Megtal\225ltad a 9. oldalt "
gameforge.main_quest_lv50._60_say = "Megtal\225ltad a 9. oldalt a p\243k kazamat\225ban! Vidd[ENTER]el Urielhez, a tud\243shoz. "
gameforge.main_quest_lv50._70_say = "Tal\225lt\225l valamit a s\246t\233t m\225gi\225r\243l? Wow, a 9.[ENTER]oldal! Nagyon izgatott vagyok hogy l\225ssam a m\225gia[ENTER]m\251k\246d\246tt-e vagy nem.[ENTER]N\233zz\252k. Hmm, azt mondja itt... "
gameforge.main_quest_lv50._75_sayTitle = "Kilencedik oldal: "
gameforge.main_quest_lv50._80_sayReward = "Lee Seop megind\237totta t\225mad\225s\225t. Hogy hogyan[ENTER]m\251k\246dik a r\233gi var\225zslat, azt m\233g nem pr\243b\225lt\225k[ENTER]ki, ez\233rt m\233g nem tudjuk haszn\225lni. Nagyon ideges[ENTER]vagyok. Most mi az\233rt vagyunk itt, hogy[ENTER]birodalmunk\233rt a legels\245 fronton harcoljunk.[ENTER]Mivel ellens\233g\252nk katonai t\250ler\245ben van, lehet,[ENTER]hogy elvesz\237tj\252k a csat\225t. Egy jobb helyet kell[ENTER]keresn\252nk magunknak. Tal\225n a j\233gf\246ldre nyugat[ENTER]fel\233 kellene menn\252nk \233s onnan r\225t\225madni az[ENTER]ellens\233g\252nkre. Isten, seg\237ts meg benn\252nket... "
gameforge.main_quest_lv50._90_say = "Hm. M\233g miel\245tt a var\225zslatot ki tudt\225k volna[ENTER]pr\243b\225lni, a birodalmat megt\225madt\225k. Az emberek[ENTER]elbarik\225dozt\225k magukat a j\233gsivatagban, hogy a[ENTER]r\233gi var\225zsl\225st tanulm\225nyozhass\225k. Tov\225bbi[ENTER]nyomokat kell keresn\252nk. Menj a j\233ghegyhez[ENTER]nyugaton \233s keress tov\225bbi nyomokat. "
gameforge.main_quest_lv55 = {}
gameforge.main_quest_lv55._100_say = "Megtal\225ltad a 12. oldalt a Joan ter\252leten. Vidd[ENTER]el Urielnek a Yongan ter\252letre. "
gameforge.main_quest_lv55._10_sendLetter = "Az eml\233km\251vek keres\233se "
gameforge.main_quest_lv55._110_say = "Megtal\225ltad a 12. oldalt a Yongan ter\252leten. Vidd[ENTER]el Urielhez a Pyungmoo ter\252letre. "
gameforge.main_quest_lv55._120_say = "\214r\252l\246k, hogy ism\233t l\225tlak. Sajn\225lom hogy oda[ENTER]kellett k\252ldjelek, de a sikereink minket[ENTER]igazolnak, igaz? N\233zz\252k ez mit mondd. Rem\233lem[ENTER]meg\233rte. "
gameforge.main_quest_lv55._130_sayTitle = "A 12. oldal: "
gameforge.main_quest_lv55._140_sayReward = "Megtal\225ltuk az inform\225ci\243kat \233s \245k megfizettek a[ENTER]csal\225suk\233rt. De ami m\233g fontosabb az az, hogy m\233g[ENTER]ki tudtunk szedni bel\245l\252k p\225r inform\225ci\243t: nem[ENTER]kell a p\243k kazamat\225ba menn\252nk, hanem a s\246t\233ts\233g[ENTER]templom\225ba. Ez az ahol az \245si k\246vet\245k a s\246t\233t[ENTER]szertart\225saikat v\233gzik az id\245k kezdete \243ta. "
gameforge.main_quest_lv55._145_sayTitle = "A 12. oldal folytat\225sa: "
gameforge.main_quest_lv55._150_sayReward = "Csak egy m\243dja van Lee Seop meg\225ll\237t\225s\225nak. El[ENTER]kell menj\252nk a s\246t\233ts\233g templom\225ba hogy[ENTER]elv\233gezz\252k a s\246t\233t m\225gi\225t. Nem sokan maradtunk \233s[ENTER]az elm\250lt h\243napok t\250lterhel\233se is meghozta az[ENTER]eredm\233ny\233t. De m\233g p\225r f\225radt ember is[ENTER]megv\225ltoztathatja a sorsot ha megfelel\245[ENTER]inform\225ci\243 birtok\225ban vannak.[ENTER]Nem engedhet\252nk a c\233ljainkb\243l. Menj\252nk! "
gameforge.main_quest_lv55._160_say = "Ah, sz\243val megtal\225lt\225k a megfelel\245 helyet.[ENTER]T\233nyleg a s\246t\233ts\233g temploma volt az. Biztosan[ENTER]eml\233kszel arra a s\246t\233t helyre, amely tele volt[ENTER]rossz energi\225val. Mindenki eml\233kszik r\225 hogy az[ENTER]volt a r\237tusok \233s cerem\243ni\225k helye. "
gameforge.main_quest_lv55._170_say = "Imm\225r csak sz\246rnyetegek laknak a titkos[ENTER]templomban, emberek m\225r r\233g\243ta nem \233lnek ott.[ENTER]Ugyan nagyon vesz\233lyes lesz, de ott biztos meg[ENTER]lehet tal\225lni az utols\243 nyomot. Menj a[ENTER]Seungryong-v\246lgybe \233s keresd meg a S\246t\233ts\233g[ENTER]templom\225t. Meg kell tudnom mi lett a v\233ge. Sok[ENTER]szerencs\233t! Oh, v\225rj, itt a jutalmad a 12.[ENTER]oldal\233rt. "
gameforge.main_quest_lv55._180_sayReward = "Kapt\225l 26000 tapasztalati pontot.[ENTER]Kapt\225l 15000 Yanget.[ENTER]Kapt\225l egy Malacorrot. "
gameforge.main_quest_lv55._190_sayReward = "162.500 Yangot kapt\225l. "
gameforge.main_quest_lv55._200_sendLetter = "Az utols\243 oldal "
gameforge.main_quest_lv55._20_say = "Mivel m\225r sok oldalt megtal\225lt\225l, Uriel \250gy[ENTER]gondolja hogy neked siker\252lni fog m\233g t\246bb[ENTER]inform\225ci\243t megtudni a s\246t\233t m\225gi\225r\243l. Menj a[ENTER]Chunjo birodalomba \233s vizsg\225ld meg az eml\233km\251vet[ENTER]a Joan ter\252leten. "
gameforge.main_quest_lv55._210_sayTitle = "\214ld meg a k\237s\233rtetet a templomban "
gameforge.main_quest_lv55._220_say = "Eddig 12 oldalt tal\225lt\225l meg a 13-b\243l.[ENTER]Nos, most az utols\243 l\233p\233s el\245tt \225llunk. Uriel azt[ENTER]mondja, hogy a s\246t\233ts\233g templom\225ban leheltek[ENTER]lelket a gonosz var\225zsl\225sba. Ez\233rt menj el a[ENTER]templomba \233s keress tov\225bbi inform\225ci\243t. A[ENTER]templom egy vesz\233lyes hely, \246lj meg n\233h\225ny[ENTER]k\237s\233rtetet, \245k biztos rendelkeznek fontos[ENTER]inform\225ci\243kkal. "
gameforge.main_quest_lv55._230_say = "M\233lyebbre kell mennem a templomban! "
gameforge.main_quest_lv55._240_sendLetter = "A s\246t\233ts\233g temploma "
gameforge.main_quest_lv55._250_sayTitle = "A templom \246rd\246gi energi\225ja "
gameforge.main_quest_lv55._260_sayReward = "A templomb\243l \225rad a gonosz energia... Teljes[ENTER]eg\233sz\233ben \225tj\225rja a gonosz energia. \218gy t\251nik ez[ENTER]a gonosz energia kiindul\243pontja. A templom[ENTER]legbels\245 m\233ly\233ben a gonosz energia feler\245s\246dik.[ENTER]Itt kezd\245d\246tt minden... "
gameforge.main_quest_lv55._270_say = "Min\233l m\233lyebbre m\233sz templomba, ann\225l er\245sebb[ENTER]lesz a gonosz energia. Meg kell tal\225lnod a[ENTER]templom k\246zep\233t. A s\246t\233ts\233gnek onnan kell j\246nnie. "
