gameforge.main_quest_lv55._290_say = "A Gum eml\233km\251 a templom sz\237v\233ben van.[ENTER]Lassan k\246zelebb m\233sz \233s megtal\225lod az utols\243[ENTER]oldalt. "
gameforge.main_quest_lv55._300_say = "Megtal\225ltad az utols\243 oldalt a s\246t\233ts\233g[ENTER]templom\225ban. Vidd el Urielhez \233s jelents neki mit[ENTER]tal\225lt\225l. "
gameforge.main_quest_lv55._30_say = "Mivel m\225r sok oldalt megtal\225lt\225l, Uriel \250gy[ENTER]gondolja hogy neked siker\252lni fog m\233g t\246bb[ENTER]inform\225ci\243t megtudni a s\246t\233t m\225gi\225r\243l. Menj a[ENTER]Jinno birodalomba \233s vizsg\225ld meg az eml\233km\251vet a[ENTER]Pyungmoo ter\252leten. "
gameforge.main_quest_lv55._310_say = "Ez az 13. \233s egyben utols\243 oldal! El sem tudom[ENTER]mondani mennyire h\225l\225s vagyok neked ez\233rt. N\233zd[ENTER]hogy remegnek a kezeim. T\250l izgatott vagyok ahhoz[ENTER]is hogy elolvassam az oldalt. Ah, n\233zz\252k hogy[ENTER]v\233gz\245dik a t\246rt\233net. "
gameforge.main_quest_lv55._320_sayTitle = "A 13. oldal "
gameforge.main_quest_lv55._330_sayReward = "V\233gre meg\233rkezt\252nk.[ENTER]Annyi megpr\243b\225ltat\225s ut\225n most a k\246vetkez\245t kell[ENTER]tenn\252nk: meg kell tartsuk a cerem\243ni\225t \233s[ENTER]aktiv\225lni a s\246t\233t m\225gi\225t. Rem\233lem el\233g er\245s lesz.[ENTER]Sokunk beteg m\225r, nem b\237rt\225k a hossz\250 utaz\225st \233s[ENTER]a folyamatos menek\252l\233st Lee Seop harcosai el\245l.[ENTER]De meg kell pr\243b\225lnunk. "
gameforge.main_quest_lv55._335_sayTitle = "A 13. oldal folytat\225sa: "
gameforge.main_quest_lv55._340_sayReward = "Heten vagyunk. A legszebb ruh\225inkat vett\252k fel[ENTER]m\233g ha azok el\233g cs\250ny\225n is n\233znek ki most. K\246rbe[ENTER]\225llunk \233s fogjuk egym\225s kez\233t. Elkezd\252nk[ENTER]\233nekelni, a m\225gikus szavakat \233s rem\233lj\252k hogy a[ENTER]s\246t\233t m\225gia nem k\237v\225n t\246bb \225ldozatot.[ENTER]... "
gameforge.main_quest_lv55._350_sayReward = "... v\233ge van ...[ENTER]Az elej\233n nagyon biztat\243 volt. A szoba megtelt[ENTER]energi\225val \233s \233nekelt, de hirtelen valami nagyon[ENTER]furcs\225t \233reztem. A hat t\225rsam t\233rdre esett. A[ENTER]templom elkezdett r\225zk\243dni. Vill\225m csap\243dott,[ENTER]h\225tra ugrottunk. Azt\225n az er\245 vonalai[ENTER]megt\246rtek... Most csend van. A t\225rsaim holtan[ENTER]fekszenek a f\246ld\246n. A m\225gia nem m\251k\246d\246tt.[ENTER]Elbuktunk. "
gameforge.main_quest_lv55._360_say = "Mi? Ez minden?!?[ENTER]Ez \245r\252let! Ennyi munka a semmi\233rt? Nem hiszem el.[ENTER]Utaztunk, harcoltunk, ford\237tottunk \233s t\246prengt\252nk[ENTER]\243r\225kig. \201s mindezt a semmi\233rt! Nem lett\252nk[ENTER]semmivel sem okosabbak. Mindenesetre \250gy n\233z ki a[ENTER]s\246t\233t m\225gi\225t\243l t\225vol kell tartsuk magunkat. M\225r[ENTER]az elej\233n is ezt gondoltam. De a tud\225s jobb mint[ENTER]a gondol\225s, ugye? "
gameforge.main_quest_lv55._370_say = "Tartunk egy kis sz\252netet el\245sz\246r. F\225j a fejem \233s[ENTER]te is biztosan f\225radt vagy. \193t kell gondoljam ezt[ENTER]el\245bb. Amikor v\233geztem akkor besz\233lhet\252nk tov\225bb.[ENTER]Mindennek ellen\233re mindenn\233l \233rt\233kesebb[ENTER]szolg\225latot tett\233l nekem. Ez nem marad jutalom[ENTER]n\233lk\252l! "
