gameforge.main_quest_lv55._390_sayReward = "175.000 Yangot kapt\225l. "
gameforge.main_quest_lv55._400_sayReward = "Vez\233r k\246nyvet kapt\225l. "
gameforge.main_quest_lv55._40_say = "Mivel m\225r sok oldalt megtal\225lt\225l, Uriel \250gy[ENTER]gondolja hogy neked siker\252lni fog m\233g t\246bb[ENTER]inform\225ci\243t megtudni a s\246t\233t m\225gi\225r\243l. Menj a[ENTER]Shinsoo birodalomba \233s vizsg\225ld meg az eml\233km\251vet[ENTER]a Yongan ter\252leten. "
