gameforge.main_quest_lv6._100_sayReward = "Menj el a kov\225cshoz. Neki sz\252ks\233ge van a[ENTER]seg\237ts\233gedre. "
gameforge.main_quest_lv6._10_targetVid = "Menj a v\225ros \245rh\246z. "
gameforge.main_quest_lv6._110_say = "Ki vagy \233s mit akarsz?[ENTER]Nagyon elfoglalt vagyok, ne zavarj.[ENTER]Oh, a v\225ros \245r k\252ld\246tt t\233ged? Azt hittem senki[ENTER]sem fog m\225r j\246nni. Ez nem neh\233z feladat \233s nem[ENTER]fog sok\225ig tartani. Pont megfelel\245 egy fiatal[ENTER]felfedez\245nek, mint te. "
gameforge.main_quest_lv6._120_say = "Ma a rakt\225rosnak egy sz\225ll\237tm\225ny\225t v\225rom -[ENTER]s\252rg\245sen egy malacorra van sz\252ks\233gem. Eddig m\233g[ENTER]hi\225ba v\225rtam. Tudsz nekem seg\237teni \233s a[ENTER]malacorrot be tudod szerezni? Ez t\233nyleg nagyon[ENTER]fontos. "
gameforge.main_quest_lv6._130_targetVid = "K\233rdezd meg a rakt\225rost. "
gameforge.main_quest_lv6._140_sendLetter = "Menj el a rakt\225roshoz. "
gameforge.main_quest_lv6._150_sayReward = "A kov\225cs s\252rg\245s sz\225ll\237tm\225nyt v\225r a rakt\225rost\243l.[ENTER]Menj el a rakt\225roshoz \233s szerezd be kov\225csnak a[ENTER]malac orrot. "
gameforge.main_quest_lv6._160_sayTitle = "Rakt\225ros: "
gameforge.main_quest_lv6._170_say = "\220dv\246z\246llek. \201n vagyok e falunak a rakt\225rosa. A[ENTER]szolg\225lataimat Te is ig\233nybe veheted, ha nem[ENTER]akarod minden ing\243s\225godat magaddal cipelni. Az \233n[ENTER]rakt\225ramban t\225rolhatod a holmid egy r\233sz\233t. "
gameforge.main_quest_lv6._180_say = "Szeretn\233l valamit... Ah, a kov\225cs k\252ld\246tt t\233ged a[ENTER]malacorr miatt! "
gameforge.main_quest_lv6._190_say = "Bocs\225ss meg. Lassan \246reg \233s feled\233keny leszek. A[ENTER]m\250ltban ilyen meg sem t\246rt\233nhetett volna. Itt van[ENTER]a malacorr a kov\225csnak. Vidd azonnal neki. K\233s\245bb[ENTER]m\233g l\225tjuk egym\225st. "
gameforge.main_quest_lv6._200_sendLetter = "Vissza a Kov\225cshoz "
gameforge.main_quest_lv6._20_sayReward = "A v\225ros \245r adna neked egy feladatot.[ENTER]Menj \233s k\233rdezd meg t\245le mi az. "
gameforge.main_quest_lv6._210_sayReward = "A rakt\225ros teljesen elfelejtette a sz\225ll\237t\225st.[ENTER]Odaadta neked a malac orrot.[ENTER]Gyorsan vidd el a kov\225cshoz, hogy ne kelljen[ENTER]tov\225bb v\225rnia. "
gameforge.main_quest_lv6._220_say = "Te gyorsabban t\233rt\233l vissza, mint gondoltam! Ezt[ENTER]a gyorsas\225got tartsd meg, mert a j\246v\245ben hasznos[ENTER]lehet sz\225modra. \201s most figyelj j\243l, van p\225r[ENTER]fontos inform\225ci\243m sz\225modra. "
gameforge.main_quest_lv6._230_say = "J\225rtas vagy a nemes\237t\233sben? Term\233szetesen nem! Te[ENTER]m\233g egy fiatal kalandor vagy! Ha a fegyverzeted[ENTER]egy r\233sz\233t itt hagyod n\225lam, akkor n\233h\225ny Yang[ENTER]fej\233ben \250gy meg tudom munk\225lni, hogy a annak[ENTER]tulajdons\225gai feljavulnak. "
gameforge.main_quest_lv6._240_say = "A nemes\237t\233s m\251v\233szet\233t k\252l\246nb\246z\245 m\243don tudjuk[ENTER]alkalmazni - min\233l nagyobb a k\237v\225nt c\233l, ann\225l[ENTER]nehezebb a megval\243s\237t\225sa. Egy +3 \233s ann\225l[ENTER]alacsonyabb feljav\237t\225s csup\225n egy kis Yangba[ENTER]ker\252l, minden egy\233b feljav\237t\225shoz tov\225bbi t\225rgy[ENTER]is sz\252ks\233ges.[ENTER]Mint a malacorr, amit hozt\225l nekem.[ENTER]Azonban mindig el\245fordulhat, hogy a t\225rgy, amit[ENTER]nemes\237teni szeretn\233nk, t\246nkre megy - m\233g akkor[ENTER]is, ha valaki olyan nagy tapasztalattal[ENTER]rendelkezik, mint \233n.[ENTER]Gyere el hozz\225m, ha id\245d engedi. Csod\225latos[ENTER]fegyvereket tudok neked kov\225csolni! "
gameforge.main_quest_lv6._250_sayReward = "%s tapasztalat pontot kapt\225l. "
gameforge.main_quest_lv6._260_sayReward = "%s Yangot kapt\225l. "
gameforge.main_quest_lv6._270_sayReward = "Kapt\225l n\233h\225ny Farkassz\245r+t. "
gameforge.main_quest_lv6._30_say = "Te ott el\246l! Most arra nincs id\245nk, hogy[ENTER]\225csorogjunk \233s a semmittev\233sben unatkozzunk.[ENTER]Neked kem\233nyen kell edzened! Az edz\233s az egyetlen[ENTER]lehet\245s\233g arra, hogy ebben a forrong\225ssal teli[ENTER]id\245ben a t\250l\233l\233sedet biztos\237tsad! "
gameforge.main_quest_lv6._40_say = "De ha m\225r itt vagy, van egy k\252ldet\233sem sz\225modra:[ENTER]a kov\225cs nemr\233g itt j\225rt \233s mondott valamit a[ENTER]malacokr\243l \233s a sz\225ll\237t\225si gondokr\243l. Lehet hogy[ENTER]sz\252ks\233ge van seg\237ts\233gre. Menj \233s mondd hogy \233n[ENTER]k\252ldtelek. "
gameforge.main_quest_lv6._50_sayReward = "Ha teljes\237ted a kov\225cs feladat\225t akkor jutalmat[ENTER]fogsz kapni. "
