gameforge.main_quest_lv60._100_say = "Sohan hegy? Egyszer l\225ttam ott egy r\233gi s\237rk\246vet! "
gameforge.main_quest_lv60._10_sendLetter = "Egy \250j nyom "
gameforge.main_quest_lv60._110_say = "Nem eml\233kszel v\233letlen\252l b\225rmilyen feliratra ott?[ENTER]Bizonyosan nem. Ez a s\237rk\245 tal\225n \233rt\233kes[ENTER]inform\225ci\243kat szolg\225ltathat sz\225munkra a S\246t\233t[ENTER]Nemzetr\245l. El tudn\225l menni a Sohan-hegyre \233s[ENTER]lem\225solni nekem a feliratot? "
gameforge.main_quest_lv60._120_say = "Uriel vizsg\225latai alapj\225n a S\225rk\225ny Papn\245k a[ENTER]S\246t\233t Nemzethez tartoztak.[ENTER]Vizsg\225ld meg a r\233gi s\237rk\246vet a Sohan-hegyen.[ENTER]Valamikor r\233gen \225ll\237t\243lag ott volt a S\246t\233t Nemzet[ENTER]f\245v\225rosa. "
gameforge.main_quest_lv60._130_say = "Nem eml\233kszel v\233letlen\252l b\225rmilyen feliratra ott?[ENTER]Bizonyosan nem. Ez a s\237rk\245 tal\225n \233rt\233kes[ENTER]inform\225ci\243kat szolg\225ltathat sz\225munkra a S\246t\233t[ENTER]Nemzetr\245l. El tudn\225l menni a Sohan-hegyre \233s[ENTER]lem\225solni nekem a feliratot? "
gameforge.main_quest_lv60._140_sayReward = "Megtal\225ltad a S\246t\233t Nemzet idej\233b\245l sz\225rmaz\243 r\233gi[ENTER]s\237rk\246vet \233s lem\225soltad a feliratot. Add \225t[ENTER]Urielnek. "
gameforge.main_quest_lv60._150_say = "Uriel vizsg\225latai alapj\225n a S\225rk\225ny Papn\245k a[ENTER]S\246t\233t Nemzethez tartoztak.[ENTER]Vizsg\225ld meg a r\233gi s\237rk\246vet a Sohan-hegyen.[ENTER]Valamikor r\233gen \225ll\237t\243lag ott volt a S\246t\233t Nemzet[ENTER]f\245v\225rosa. "
gameforge.main_quest_lv60._160_say = "V\233gre! Hadd elemezzem ki a feliratot...[ENTER]A k\246vetkez\245ket mondja: a S\246t\233t Nemzet elk\246telezte[ENTER]mag\225t a fekete m\225gia mellett \233s ezzel Sung[ENTER]Mahi-t, a D\233monok Isten\233t szolg\225lja. "
gameforge.main_quest_lv60._170_say = "Oh \233des... Sung Mahi! Akkor tal\225n a h\233t S\225rk\225ny[ENTER]Papn\245 megk\237s\233relte megid\233zni Sung Mahi-t a[ENTER]tiltott boszork\225nys\225g erej\233t haszn\225lva? "
gameforge.main_quest_lv60._180_say = "J\243 munk\225t v\233gezt\233l. Ez\233rt az er\245fesz\237t\233s\233rt csak[ENTER]tisztess\233ges jutalmat kaphatsz. "
gameforge.main_quest_lv60._190_sayReward = "%s tapasztalat pontot kapt\225l. "
gameforge.main_quest_lv60._200_sayReward = "%s Yangot kapt\225l. "
gameforge.main_quest_lv60._20_say = "Uriel \250j inform\225ci\243t tal\225lt a r\233gi napl\243ban l\233v\245[ENTER]t\246rt\233nethez. Keresd fel Urielt \233s tudj meg[ENTER]t\246bbet. "
gameforge.main_quest_lv60._210_sayReward = "%d-t kapt\225l. "
gameforge.main_quest_lv60._220_sendLetter = "S\246t\233t Nemzet II "
gameforge.main_quest_lv60._230_say = "Uriel szerint a Szellem-erd\245 egykor a S\246t\233t[ENTER]Nemzet kir\225lys\225g\225nak r\233sze volt. Tal\225n tov\225bbi[ENTER]nyomok is vannak ott.[ENTER]De ez az erd\245 tele van vesz\233llyel \233s a Metink\246vek[ENTER]\245rj\246ng\245 teremtm\233nyeket rejtenek. Tal\225ld meg a[ENTER]Gonosz f\225t, hogy t\246bb bizony\237t\233kot szerezz. Ut\225na[ENTER]besz\233lj Uriellel. "
gameforge.main_quest_lv60._240_say = "A S\246t\233t Nemzetet sz\225mos titok \246vezi. Neked[ENTER]k\246sz\246nhet\245en m\225r napvil\225gra ker\252lt n\233h\225ny ezek[ENTER]k\246z\252l, de m\233g mindig hi\225nyzik p\225r fontos[ENTER]inform\225ci\243. K\233rlek menj \233s vad\225ssz tov\225bb egy[ENTER]r\233gi dokumentumra. A Sohan hegy melletti[ENTER]Szellem-erd\245ben kell lennie. "
gameforge.main_quest_lv60._250_counter = "Fennmarad\243 oldalak: "
gameforge.main_quest_lv60._260_say = "A S\246t\233t Nemzetet sz\225mos titok \246vezi. Neked[ENTER]k\246sz\246nhet\245en m\225r napvil\225gra ker\252lt n\233h\225ny ezek[ENTER]k\246z\252l, de m\233g mindig hi\225nyzik p\225r fontos[ENTER]inform\225ci\243. K\233rlek menj \233s vad\225ssz tov\225bb egy[ENTER]r\233gi dokumentumra. A Sohan hegy melletti[ENTER]Szellem-erd\245ben kell lennie. "
gameforge.main_quest_lv60._270_sayReward = "Legy\245zt\233l egy Gonosz f\225t \233s megszerezt\233l egy[ENTER]dokumentumot. Idegen nyelven volt \237rva. Add \225t[ENTER]Urielnek, hogy leford\237tsa. "
gameforge.main_quest_lv60._280_say = "V\233gre! Megtal\225ltad a r\233gi dokumentumot.[ENTER]Rem\233lhet\245leg f\233nyt der\237t n\233h\225ny dologra az \252gyben! "
gameforge.main_quest_lv60._290_say = "De micsodaaa...? Alig van benne valami! A[ENTER]dokumentum val\243j\225ban t\237z oldalb\243l \225ll. K\233rlek,[ENTER]menj vissza az erd\245be \233s tal\225ld meg a fennmarad\243[ENTER]kilenc oldalt is. "
gameforge.main_quest_lv60._300_say = "M\233g mindig meg kell tal\225lnod %d oldalt. "
gameforge.main_quest_lv60._30_say = "Hogy vagy? Eml\233kszel arra a napl\243ra \233s a benne[ENTER]l\233v\245 t\246rt\233netre? Arra, ami hirtelen v\233get \233rt a[ENTER]tizenharmadik, \233s egyben utols\243 oldalon? "
gameforge.main_quest_lv60._310_say = "Teh\225t, l\225ssuk csak...[ENTER]\218gy t\251nik, a S\246t\233t Nemzet egy \225tkot haszn\225lva[ENTER]elcs\225b\237totta a S\225rk\225ny kultusz F\245papn\245j\233t \233s[ENTER]vissza\233lt a h\233t n\245 szent erej\233vel a fekete[ENTER]boszork\225nys\225g \245si m\251v\233szet\233nek haszn\225lata[ENTER]\233rdek\233ben. "
gameforge.main_quest_lv60._320_say = "Sung Mahi megid\233z\233s\233hez a fekete boszork\225nys\225got[ENTER]h\233t k\252l\246nb\246z\245 helyen kellett haszn\225lni ugyanabban[ENTER]az id\245ben. De Lee Seop \233s serege id\245ben[ENTER]meg\225ll\237totta a szertart\225st \233s meghi\250s\237totta a[ENTER]S\246t\233t Nemzet terveit. "
gameforge.main_quest_lv60._330_say = "Ett\245l a Nemzet eg\233szen biztosan tartani kellett.[ENTER]A fekete m\225gia r\233v\233n k\233pesek voltak szab\225lyozni[ENTER]az emberi tudatot! "
gameforge.main_quest_lv60._340_sendLetter = "A nyom "
gameforge.main_quest_lv60._350_say = "Uriel nyomokat fedezett fel a r\233gi tekercsekben a[ENTER]Gum eml\233km\251vel kapcsolatban. Menj el hozz\225 \233s[ENTER]tudj meg t\246bbet. "
gameforge.main_quest_lv60._360_say = "Hadd \246sszegezzem, amit eddig megtudtunk: Egyszer[ENTER]\233ltek itt emberek, akik magukat a S\246t\233t Nemzetnek[ENTER]h\237vt\225k \233s akik a D\233monisten Sung Mahi-t[ENTER]szolg\225lt\225k. Hogy megid\233zz\233k \245t, elcs\225b\237tott\225k a[ENTER]h\233t S\225rk\225ny Papn\245t \233s kihaszn\225lt\225k szent[ENTER]hatalmukat a tiltott fekete boszork\225nys\225g[ENTER]m\251v\233szete \233rdek\233ben. De ezt h\233t k\252l\246nb\246z\245 helyen[ENTER]kellett v\233gezni ugyanabban az id\245ben. "
gameforge.main_quest_lv60._370_say = "A S\225rk\225ny Papn\245k csak ebben az egyetlen toronyban[ENTER]v\233gezt\233k el a fekete boszork\225nys\225got, nem pedig[ENTER]h\233t k\252l\246nb\246z\245 helyen...[ENTER]Ez az, ami\233rt Sung Mahi megid\233z\233se sikertelen[ENTER]volt. "
gameforge.main_quest_lv60._380_say = "A S\246t\233t Nemzet rossz inform\225ci\243kat adott a h\233t[ENTER]S\225rk\225ny Papn\245nek. "
gameforge.main_quest_lv60._390_say = "Tal\225n \245k sem tudt\225k, hogyan kell csin\225lni...[ENTER]Lehet, hogy v\233letlen, de a r\233gi tekercsek ezt a[ENTER]tornyot eml\237tik a Gum eml\233km\251vel kapcsolatban.[ENTER]\218gy t\251nik, a Hwang templomban tal\225lhat\243 D\233mon[ENTER]toronyr\243l besz\233lnek. "
gameforge.main_quest_lv60._400_say = "V\233gre tal\225ltunk a d\246nt\245 nyomot a h\233t S\225rk\225ny[ENTER]Papn\245r\245l! Pihenj egy kicsit, \233s majd[ENTER]megbesz\233lj\252k, mi lesz a k\246vetkez\245 l\233p\233s. Att\243l[ENTER]tartok, lesz egy utad a D\233mon Toronyba... "
gameforge.main_quest_lv60._40_say = "Igen, term\233szetesen. Lee Seop-t\243l \233s lovass\225g\225t\243l[ENTER]h\233t ember menek\252lt a Hwang Templomba, \233s[ENTER]k\233ts\233gbees\233s\252kben elfogadt\225k a fekete[ENTER]boszork\225nys\225got... v\233g\252l csak az egyik\252k \233lte[ENTER]t\250l. "
gameforge.main_quest_lv60._410_sayReward = "A kaland k\246vetkez\245 r\233sze akkor ny\237lik meg[ENTER]el\245tted, ha m\225r el\233rted a 66-os szintet. "
gameforge.main_quest_lv60._50_say = "Pontosan. Tov\225bbi kutat\225sokat v\233geztem \233s[ENTER]meg\225llap\237tottam, hogy a szent kultusz h\233t tagja a[ENTER]S\225rk\225ny Papn\245k voltak. R\233gi tekercseken a S\246t\233t[ENTER]Nemzet nev\251 teokratikus emberekhez vannak[ENTER]t\225rs\237tva. Vajon ezek a S\225rk\225ny Papn\245k a misztikus[ENTER]nemzet tagjai? Tess\233k, olvasd el figyelmesen ezt[ENTER]a tekercset \233s besz\233lj\252nk \250jra, ha v\233gezt\233l. "
gameforge.main_quest_lv60._60_sendLetter = "S\246t\233t Nemzet I "
gameforge.main_quest_lv60._70_say = "Az Uriel \225ltal v\233gzett vizsg\225latok szerint a h\233t[ENTER]S\225rk\225ny Papn\245 a S\246t\233t Nemzetb\245l sz\225rmazik.[ENTER]Vizsg\225ld meg a Sohan hegyen tal\225lhat\243 r\233gi[ENTER]s\237rk\246vet. Felt\233telezhet\245, hogy egyszer azon a[ENTER]helyen volt a S\246t\233t Nemzet f\245v\225rosa. Miel\245tt[ENTER]elindulsz, besz\233lj \250jra Uriellel. "
gameforge.main_quest_lv60._80_say = "Hihetetlen\252l magasan fejlett boszork\225nys\225guk \233s[ENTER]azon t\233ny miatt, hogy - a napl\243 szerint - Lee[ENTER]Seop \225ltal lettek elpuszt\237tva az a l\233nyeg, hogy a[ENTER]S\225rk\225ny Papn\245k val\243j\225ban a S\246t\233t Nemzethez[ENTER]tartoztak. "
gameforge.main_quest_lv60._90_say = "A r\233gi tekercseken van egy t\233rk\233p. Ha k\246zelebbr\245l[ENTER]veszed szem\252gyre meg\225llap\237thatod, hogy a S\246t\233t[ENTER]Nemzet f\245v\225rosa csak a Sohan Hegyen lehetett. "
gameforge.main_quest_lv66 = {}
gameforge.main_quest_lv66._100_say = "Hihetetlen! \201rted, hogy ez mit jelent?![ENTER]Eredetileg nem voltak d\233monok vagy szellemek a[ENTER]D\233mon-toronyban! Hogy ez most a S\225rk\225ny Papn\245[ENTER]\246r\246ks\233ge! Egy utols\243, elkeseredett k\237s\233rletk\233nt[ENTER]arra, hogy legy\245zze Lee Seop sereg\233t, ezzel az[ENTER]\225tkozott \233s s\246t\233t szertart\225ssal megnyitotta az[ENTER]\225tj\225r\243t a d\233monok sz\225m\225ra e vil\225ghoz. A v\233g\233n az[ENTER]\233let\233\233rt fizetett \233rte. "
gameforge.main_quest_lv66._10_sendLetter = "A Napl\243 "
gameforge.main_quest_lv66._110_say = "Ez az a ny\237l\225s, amit a Kasz\225s \233s d\233moni k\246vet\245i[ENTER]haszn\225ltak a vil\225gunkba val\243 bel\233p\233sre.[ENTER]Ugyanakkor a S\246t\233t Nemzet \233s a S\225rk\225ny Papn\245k f\245[ENTER]k\252ldet\233se elbukott: nem volt sikeres Sung Mahi[ENTER]megid\233z\233se, Lee Seop ker\252lt hatalomra \233s v\233g\252l[ENTER]l\233trehozott egy egyes\237tett vil\225gbirodalmat.[ENTER][ENTER]K\246sz\246n\246m a seg\237ts\233ged, v\233gre siker\252lt megfejtenem[ENTER]\233letem legnagyobb rejt\233ly\233t! "
gameforge.main_quest_lv66._120_say = "Jutalmul szeretn\233k \225tadni egy \193ld\225stekercset.[ENTER]Tess\233k, fogadd el aj\225nd\233kom, ragaszkodom hozz\225! "
gameforge.main_quest_lv66._130_sendLetter = "Leveled van. "
gameforge.main_quest_lv66._140_say = "A Gondnoknak van egy levele sz\225modra. Olvasd el[ENTER]\233s tal\225ld ki, ki a titokzatos felad\243. "
gameforge.main_quest_lv66._150_say = "El\233gg\233 sz\251k\246lk\246dsz mostan\225ban, ugye? \193t kell[ENTER]adnom neked ezt a levelet - fogalmam sincs, ki[ENTER]k\252ldte, nem mutatkozott be. "
gameforge.main_quest_lv66._160_say = "A pap\237r, amire a levelet \237rt\225k, nagyon r\233ginek[ENTER]t\251nik. Siet\245s macskakapar\225ssal a k\246vetkez\245ket[ENTER]\237rt\225k r\225:[ENTER]Fontos inform\225ci\243m van a h\233t S\225rk\225ny Papn\245r\245l \233s[ENTER]Sung Mahi-r\243l. A Hwang templomban l\233v\245[ENTER]D\233mon-torony m\246g\246tt v\225rok r\225d. Egy fa \225rny\233k\225ban[ENTER]vagyok. Siess! R\246vid az id\245! "
gameforge.main_quest_lv66._170_sendLetter = "Ismeretlen lev\233l "
gameforge.main_quest_lv66._180 = "Menj a Hwang templomba \233s tal\225lkozz a titokzatos[ENTER]lev\233l \237r\243j\225val a D\233mon-torony m\246g\246tt. "
gameforge.main_quest_lv66._190_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._200_say = "\220dv\246z\246llek! El\245sz\246r is hadd mutatkozzam be: a[ENTER]nevem Lee Chung. Nagyon b\225tor dolog t\245led, hogy[ENTER]k\246veted olyas valaki utas\237t\225sait, akit nem is[ENTER]ismersz. Nem csin\225ltam bolondot magamb\243l, amikor[ENTER]t\233ged v\225lasztottalak - \233s te sem fogod megb\225nni[ENTER]d\246nt\233sem![ENTER]Figyelj j\243l a mondand\243mra! "
gameforge.main_quest_lv66._20_say = "Urielnek h\237rei vannak a S\225rk\225ny Papn\245k utols\243[ENTER]t\250l\233l\245j\233r\245l. A D\233mon-toronyban kell lennie a[ENTER]napl\243j\225nak. Menj Urielhez, hogy t\246bbet megtudj[ENTER]err\245l. "
gameforge.main_quest_lv66._210_sendLetter = "\218j Gonosz "
gameforge.main_quest_lv66._220_say = "Hallgasd meg, mit akar Lee Chung mondani. "
gameforge.main_quest_lv66._230_say = "Egyetlen oka van annak, mi\233rt kellene a Hwang[ENTER]templomba menned: az ut\243bbi id\245ben n\233h\225ny[ENTER]szokatlan dolog t\246rt\233nik ott. \201s csak most[ENTER]fedezt\252k fel egy nagy barlang bej\225rat\225t a[ENTER]D\233mon-torony m\246g\246tt! "
gameforge.main_quest_lv66._240_say = "Egy \243ri\225si barlang? Mi van benne? "
gameforge.main_quest_lv66._250_say = "Ebben a barlangban egy \250j, elk\233pzelhetetlen\252l[ENTER]gonosz rejt\245zik, r\225nk v\225rva. Felder\237t\245ink[ENTER]h\225tborzongat\243 teremtm\233nyekr\245l besz\233lnek, melyek a[ENTER]d\233monok m\246g\246tt rejt\245znek az \225rny\233kban. Sz\246rny\251[ENTER]kin\233zet\252k \233s f\233lelmetes \233lni akar\225suk miatt azt[ENTER]kell hinn\252nk, ez a legend\225s Agwi - egyike a[ENTER]d\233monvil\225g t\237z nagy \246rd\246g\233nek.[ENTER]Ha helyesek a k\246vetkeztet\233seink, akkor[ENTER]mindannyian nagy vesz\233lyben vagyunk. "
gameforge.main_quest_lv66._260_say = "M\233g f\233lelmetesebb, mint a d\233monok... ez a[ENTER]teremtm\233ny val\243ban er\245s \233s gonosz lehet. "
gameforge.main_quest_lv66._270_say = "Val\243ban az. Az embereimmel m\225r sokszor[ENTER]megrohamoztuk az \214rd\246g Katakomb\225j\225t, de[ENTER]mindannyiszor elbuktunk \233s s\250lyos vesztes\233geket[ENTER]szenvedt\252nk.[ENTER]Emiatt sz\252ks\233g\252nk van egy kiv\225l\243 harcos[ENTER]t\225mogat\225s\225ra - ez az oka annak, ami\233rt ide[ENTER]h\237vtunk. Seg\237tesz nek\252nk? "
gameforge.main_quest_lv66._280_say = "Igen, seg\237tek nektek. "
gameforge.main_quest_lv66._290_say = "Oh, ez \250j rem\233nnyel t\246lt el benn\252nket![ENTER]Most, hogy m\225r tudom, a mi oldalunkon \225llsz,[ENTER]elmondhatom a teljes igazs\225got: \201n, Lee Chung, az[ENTER]\193rny\233k harcosok parancsnoka vagyok. Mi vagyunk[ENTER]Lee Seop sereg\233nek titkos elit egys\233ge. "
gameforge.main_quest_lv66._300_sayTitle = "Lee Chung "
gameforge.main_quest_lv66._30_say = "Ah, j\243 \250jra l\225tni t\233ged, \233pen \233s eg\233szs\233gesen.[ENTER]K\233szen \225llsz egy \250j kalandra? M\233g mindig[ENTER]hi\225nyoznak fontos inform\225ci\243k a S\246t\233t Nemzetr\245l[ENTER]\233s a h\233t S\225rk\225ny Papn\245r\245l. Az utols\243 S\225rk\225ny[ENTER]Papn\245nek a D\233mon-toronyban kellett elrejtenie a[ENTER]napl\243j\225t, miel\245tt elv\233gezte a s\246t\233t var\225zslatot.[ENTER]Menj ki \233s hozd el nekem a napl\243t. Lehet, hogy a[ENTER]D\233mon kir\225ly birtok\225ban van. "
gameforge.main_quest_lv66._310_say = "Az \193rny\233k harcosok m\225r el\233rt\233k egyik c\233ljukat,[ENTER]amikor annak idej\233n megakad\225lyozt\225k Sung Mahi[ENTER]felt\225maszt\225s\225t. Ez a k\252ldet\233s\252nk. Meg kell[ENTER]pr\243b\225lnunk k\246z\246s er\245vel visszak\252ldeni ezt az[ENTER]Agwi-t a pokolba, ahonnan j\246tt, majd ki kell[ENTER]der\237ten\252nk, hogyan tudott bejutni a vil\225gunkba! "
gameforge.main_quest_lv66._320_sendLetter = "Nincs id\245 "
gameforge.main_quest_lv66._330_say = "Lee Chung, az \193rny\233k harcosok parancsnoka keres[ENTER]t\233ged. Nagyon s\252rg\245s! "
gameforge.main_quest_lv66._340_say = "Van egy s\252rg\245s k\233r\233sem. L\225tod ott azt a s\233r\252lt[ENTER]katon\225t?[ENTER]\213 az egyik felder\237t\245m, aki az utas\237t\225somra[ENTER]felder\237tette az \214rd\246g Katakomb\225j\225t. Mialatt ez[ENTER]t\246rt\233nt, az Agwi megt\225madta \233s megm\233rgezte. A[ENTER]m\233reg \225tj\225rja a test\233t - m\225r nem sok ideje maradt[ENTER]h\225tra. "
gameforge.main_quest_lv66._350_say = "Ellenanyagra van sz\252ks\233ge, m\233gpedig s\252rg\245sen![ENTER]Tudn\225l hozni bel\245le? A V\246r\246s erd\245ben tal\225lhatod,[ENTER]a V\246r\246s t\252nd\233r k\246zel\233ben.[ENTER]\213 az egyik legjobb harcosom - mentsd meg az[ENTER]\233let\233t, \233s jutalmul adok neked %s-t. "
gameforge.main_quest_lv66._360_say = "Elhozom az ellenm\233rget! "
gameforge.main_quest_lv66._370_say = "K\246sz\246n\246m! M\233g l\233legzik, de minden percben egyre[ENTER]gyeng\252l. Nincs vesztegetni val\243 id\245nk! "
gameforge.main_quest_lv66._380_notice = "%d perced van m\233g. "
gameforge.main_quest_lv66._390_sendLetter = "Az Ellenm\233reg "
gameforge.main_quest_lv66._400_say = "Abb\243l, amit Lee Chung mondott tudod, hogy az[ENTER]Ellenm\233reg a V\246r\246s erd\245ben tal\225lhat\243. Ehhez ejts[ENTER]csapd\225ba %d V\246r\246s t\252nd\233rt.[ENTER][ENTER]A V\246r\246s erd\245ben m\233g nagyobb a vesz\233ly, mint a[ENTER]Szellem-erd\245ben, teh\225t l\233gy \243vatos. "
gameforge.main_quest_lv66._40_say = "Legy\245zted a D\233mon kir\225lyt \233s megszerezted a[ENTER]S\225rk\225ny Papn\245 napl\243j\225t. Vidd el a m\251velt[ENTER]Urielnek, \245 majd kielemzi. "
gameforge.main_quest_lv66._410_say = "Lej\225rt az id\245. A katona haldoklik, vidd el neki[ENTER]az Ellenm\233rget olyan gyorsan, ahogy tudod. "
gameforge.main_quest_lv66._420_say = "%d perced van m\233g. "
gameforge.main_quest_lv66._430_say = "V\233gre megtal\225ltad az Ellenm\233rget! Siess, add \225t[ENTER]Lee Chung-nak! "
gameforge.main_quest_lv66._440_say = "Ide, gyorsan! Azt hiszem, \233ppen a megfelel\245[ENTER]id\245ben \233rkezt\233l. Hatalmas tehert\245l szabadultam[ENTER]most meg. Az emberemmel egy\252tt nagyon h\225l\225sak[ENTER]vagyunk az\233rt, amit tett\233l. "
gameforge.main_quest_lv66._450_say = "A seg\237ts\233gednek k\246sz\246nhet\245en az emberem t\250l\233lte.[ENTER]Itt a jutalmad, ami\233rt megmentetted \245t. "
gameforge.main_quest_lv66._460_say = "Sok id\245be tellett. Minden erej\233vel ragaszkodott[ENTER]az \233lethez. Szerencs\233ben id\245ben \233rkezt\233l. "
gameforge.main_quest_lv66._470_say = "\218gy t\251nik, t\250ljutott rajta. De k\246zel volt -[ENTER]majdnem belehalt, mert t\250l sok id\245t t\246lt\246tt\233l az[ENTER]Ellenm\233reg keres\233s\233vel.[ENTER]Sajn\225lom, de ez minden, amit jutalomk\233nt adhatok[ENTER]neked. "
gameforge.main_quest_lv66._480_sendLetter = "A Jelent\233s "
gameforge.main_quest_lv66._490_say = "A felder\237t\245 visszanyerte a tudat\225t. Hallgasd meg,[ENTER]mit tapasztalt, am\237g az \214rd\246g Katakomb\225j\225ban[ENTER]volt. "
gameforge.main_quest_lv66._500_say = "K\246sz\246n\246m, hogy megmentett\233l. Hihetetlen dolgokat[ENTER]l\225ttam az \214rd\246g Katakomb\225j\225ban. De akkor[ENTER]felfedeztem, \233s... "
gameforge.main_quest_lv66._50_say = "Megtal\225ltad! Az utols\243 S\225rk\225ny Papn\245 napl\243ja.[ENTER]Remegnek a kezeim az izgalomt\243l![ENTER]Sz\252ks\233gem lesz egy kis id\245re, m\237g megvizsg\225lom a[ENTER]tartalm\225t. Addig pihenj egyet. H\237vlak majd, ha[ENTER]m\225r t\246bbet tudok mondani. "
gameforge.main_quest_lv66._510_say = "Mit l\225tt\225l? "
gameforge.main_quest_lv66._520_say = "Fekete k\246penyes emberek voltak ott csukly\225val,[ENTER]melyet az arcukba h\250ztak.[ENTER]A besz\233d-foszl\225nyaikb\243l arra k\246vetkeztettem, hogy[ENTER]\245k voltak a S\246t\233ts\233g Szolg\225i.[ENTER]De ez m\233g nem minden: Egy k\237s\233rteties n\245-forma[ENTER]szellem lebegett a fej\252k felett. A S\246t\233ts\233g[ENTER]Szolg\225i Banshee-nak h\237vt\225k \245t. "
gameforge.main_quest_lv66._530_say = "Ez nem hangzik t\250l j\243l. Mit terveztek a S\246t\233ts\233g[ENTER]szolg\225i \233s ez a Banshee? "
gameforge.main_quest_lv66._540_say = "A Banshee fekete m\225gi\225t haszn\225lva megid\233zte az[ENTER]Agwi-t, ezek az \246rd\246gi teremtm\233nyek k\246zvetlen\252l a[ENTER]pokol tork\225b\243l j\246nnek. Az Agwi-kir\225ly szellem\233t,[ENTER]Azraelt h\237vj\225k. "
gameforge.main_quest_lv66._550_say = "Igyekeztem kifel\233, hogy \233rtes\237tsem err\245l Lee[ENTER]Chung-ot, de megbotlottam \233s felfedeztek.[ENTER][ENTER]Ah, most jutott eszembe, Lee Chung parancsnok[ENTER]valami fontosat akar neked mondani. \201n a[ENTER]helyedben most oda menn\233k. "
gameforge.main_quest_lv66._560_sendLetter = "Balj\243s \225rnyak "
gameforge.main_quest_lv66._570_say = "Menj Lee Chung-hoz \233s sz\225molj be neki az \214rd\246g[ENTER]Katakomb\225j\225ban leselked\245 \250j vesz\233lyr\245l. "
gameforge.main_quest_lv66._580_say = "El\233g ijeszt\245 dolgot jelentett a felder\237t\245m, ugye?[ENTER]A S\246t\233ts\233g szolg\225i, ez egyfajta szekta, a[ENTER]felel\245sek az Agwi megjelen\233s\233\233rt. Fel\233bresztett\233k[ENTER]m\233g az utols\243 S\225rk\225ny Papn\245 szellem\233t is, aki[ENTER]Banshee-k\233nt, a gonosz megtestes\237t\245jek\233nt[ENTER]visszat\233rt ebbe a vil\225gba \233s m\225gikus erej\233nek[ENTER]haszn\225lat\225val hamarosan megid\233zheti a d\233monisten[ENTER]Sung Mahi-t. "
gameforge.main_quest_lv66._590_say = "Micsoda?! Ez a Banshee az utols\243 S\225rk\225ny Papn\245[ENTER]szelleme?! "
gameforge.main_quest_lv66._600_say = "K\233ts\233gtelen\252l. A S\225rk\225ny-kultusz n\245v\233rei k\246z\246tt[ENTER]m\225r csak \245 rendelkezett az er\245vel, hogy megid\233zze[ENTER]a n\233gy szent \201gi \213rszemet \233s elv\233gezze a fekete[ENTER]boszork\225nys\225got.[ENTER]Most m\225r tudjuk, ki \225ll em\246g\246tt az \250j fenyeget\233s[ENTER]m\246g\246tt: ezek a S\246t\233ts\233g szolg\225i \233s a Banshee azt[ENTER]tervezik, hogy befejezik a S\246t\233t Nemzet munk\225j\225t[ENTER]\233s fel\233bresztik Sung Mahi-t! "
gameforge.main_quest_lv66._60_sendLetter = "A Rejtv\233ny megfejt\233se "
gameforge.main_quest_lv66._610_say = "Sok k\246sz\246nettel tartozunk neked: megmentetted az[ENTER]egyik emberem a biztos hal\225lt\243l, ez\225ltal siker\252lt[ENTER]felismern\252nk az Agwi hirtelen megjelen\233s\233nek ok\225t[ENTER]\233s a fenyeget\245 vesz\233lyt az \214rd\246g Katakomb\225j\225ban.[ENTER]Pihenj egy kicsit, azt\225n megtervezz\252k majd a[ENTER]megfelel\245 taktik\225t. "
gameforge.main_quest_lv66._620_say = "A kaland akkor folytat\243dik, ha el\233rted a 72-es[ENTER]szintet. "
gameforge.main_quest_lv66._70_say = "Uriel keres t\233ged. Most olvasta el a napl\243t. "
gameforge.main_quest_lv66._80_say = "Ah, nagyszer\251! Itt vagy![ENTER]Az utols\243 S\225rk\225ny Papn\245 kr\243nik\225ja igaz\225n[ENTER]megh\246kkent\245. J\243l figyelj: "
gameforge.main_quest_lv66._90_say = "Utol\233r a v\233gzetem! Eltorlaszolom magam ennek a[ENTER]toronynak a legmagasabb emelet\233n, de Lee Seop[ENTER]emberei hamarosan \225tt\246rik b\246rt\246n\246m ajtaj\225t. Nincs[ENTER]menekv\233s, elvesztem.[ENTER][ENTER]Nem! Ez nem v\233gz\245dhet \237gy! M\225r nem \225ll\237that\243[ENTER]vissza. El\245h\237vom magamb\243l a fekete[ENTER]boszork\225nys\225got, ezt az \245si gonosz hatalmat \233s[ENTER]megid\233zem a gonosz er\245ket.[ENTER]Ez biztosan a hal\225lomat jelenti. De ellens\233geim[ENTER]is csatlakozni fognak pusztul\225somhoz, ha ez is az[ENTER]utols\243 dolog, amit tehetek! "
gameforge.main_quest_lv7 = {}
gameforge.main_quest_lv7._100_say = "Micsoda, m\233g nem k\233zbes\237tetted? A Horg\225szbot a[ENTER]foly\243 melletti hal\225sz\233.[ENTER]Siess, s\252rg\245sen kell neki! "
gameforge.main_quest_lv7._10_targetVid = "Egy tov\225bbi sz\237vess\233g "
gameforge.main_quest_lv7._110_npcChat = "A Kov\225cs k\252ldte ezt az \250j horg\225szbotot! "
gameforge.main_quest_lv7._120_say = "K\246sz\246n\246m. Most m\225r v\233gre megszabadulhatok a[ENTER]h\251s\233ges, de nagyon elhaszn\225l\243dott[ENTER]horg\225szbotomt\243l.[ENTER]\201n nem csak a meg\233lhet\233sem biztos\237tom a[ENTER]hal\225szatb\243l, de \246r\246m\246m is lelem benne![ENTER]Tudsz valamit a hal\225szatr\243l? "
gameforge.main_quest_lv7._130_say = "Vedd el\245sz\246r a horg\225szbotot a k\233zbe, haszn\225lj[ENTER]csalit, amit a horogra illesztesz. Majd vesd ki a[ENTER]horgot \233s haszn\225ld a Hal\225szat k\233pess\233g\233t. Ha \250gy[ENTER]gondolod, hogy kap\225sod van, akkor haszn\225ld a[ENTER]Hal\225szat k\233pess\233g\233t \250jb\243l. Ha t\233vedt\233l, akkor[ENTER]pr\243b\225ld meg \250jra \233s \250jra. Ezek a vizek a fajok[ENTER]sokas\225ga miatt nagyon j\243l hal\225szhat\243k. Ezen k\237v\252l[ENTER]a hal nem csak t\225pl\225l\243 \233s eg\233szs\233ges, hanem[ENTER]\233rt\233kes kincset is rejthet mag\225ban. Pr\243b\225ld ki[ENTER]nyugodtan egyszer. "
gameforge.main_quest_lv7._140_say = "Ah igen, itt van a horg\225szbot \225tv\233tel\233r\245l a[ENTER]sz\225mla. K\233rlek add \225t a kov\225csnak, ha visszat\233rsz[ENTER]a v\225rosba. "
gameforge.main_quest_lv7._150_sayItem = "A horg\225szbot sz\225ll\237t\225si levele "
gameforge.main_quest_lv7._160_sayReward = "A hal\225sznak odavitted a horg\225szbotot. T\233rj vissza[ENTER]a nyugt\225val a a kov\225cshoz \233s vedd \225t a[ENTER]jutalmadat. "
gameforge.main_quest_lv7._170_say = "Megtal\225ltad a Hal\225szt?[ENTER]Remek! Sok id\245t sp\243rolt\225l meg nekem a feladat[ENTER]elv\233gz\233s\233vel. Jutalomk\233nt adok neked n\233mi Yangot[ENTER]\233s 1.500 tapasztalati pontot. "
gameforge.main_quest_lv7._180_sendLetter = "Utalv\225ny "
gameforge.main_quest_lv7._190_sayReward = "Ez az \237r\225s fej\233ben a kov\225cst\243l a fegyverzeted egy[ENTER]r\233sz\233nek a nemes\237t\233s\233t ingyen megkapod. H\250zd[ENTER]egyszer\251en a kiv\225lasztott darabot a kov\225csra,[ENTER]hogy meg tudd nyitni a nemes\237t\233si ablakot. "
gameforge.main_quest_lv7._200_sayItem = "Utalv\225ny egy darab ingyenes nemes\237t\233s\233re "
gameforge.main_quest_lv7._20_sayReward = "Menj el a kov\225cshoz. \213 valakit keres, aki elint\233z[ENTER]sz\225m\225ra egy k\252ld\246ncutat. "
gameforge.main_quest_lv7._210_sayTitle = "Utal\225s: "
gameforge.main_quest_lv7._220_sayReward = "1) Az utalv\225ny nem jelenik meg a lelt\225rban.[ENTER]2) A fejleszt\233s sikeress\233ge - hasonl\243an a t\246bbi[ENTER]fejleszt\233shez - nem 100%-osan garant\225lt. "
gameforge.main_quest_lv7._230_sayTitle = "M\225r valaki haszn\225lta az utalv\225nyt. "
gameforge.main_quest_lv7._240_sayReward = "M\225r haszn\225ltad az utalv\225nyt egy ingyenes[ENTER]nemes\237t\233sre. Ez csak egy nemes\237t\233sre \233rv\233nyes. "
gameforge.main_quest_lv7._30_say = "L\233gy \252dv\246z\246lve, kalandor! Meg tudsz tenni m\233g egy[ENTER]sz\237vess\233get a sz\225momra? \193ltal\225ban nem k\233rek meg[ENTER]gyakran m\225s embert, de te nekem bizalomkelt\245nek[ENTER]t\251nsz. Tekintsd ezt megtiszteltet\233snek! "
gameforge.main_quest_lv7._40_say = "Egy horg\225szbotot k\233sz\237tettem a hal\225sznak. Sajnos[ENTER]a mai napon t\250l sok megrendel\233sre vonatkoz\243[ENTER]megkeres\233st kell megv\225laszolnom, hogy nem tudom[ENTER]neki szem\233lyesen \225tadni. El tudod ezt int\233zni[ENTER]sz\225momra? "
gameforge.main_quest_lv7._50_sayItem = "Egy k\252l\246n\246sen hajl\233kony horg\225szbot "
gameforge.main_quest_lv7._60_say = "A hal\225sz valahol a foly\243n\225l van.[ENTER]Ha elviszed neki a horgot, akkor a fegyverzeted[ENTER]egy r\233sz\233t ingyen fogom megnemes\237teni. Ez egy[ENTER]fair \252zlet, nem igaz? "
gameforge.main_quest_lv7._70_sendLetter = "Keresd a Hal\225szt "
gameforge.main_quest_lv7._80_sayReward = "A kov\225cs a hal\225sznak egy horg\225szbotot k\233sz\237tett.[ENTER]Keresd meg a hal\225szt a foly\243n\225l \233s vidd ezt el[ENTER]neki. "
gameforge.main_quest_lv7._90_npcChat = "Ki\233 a horg\225szbot? "
gameforge.main_quest_lv72 = {}
gameforge.main_quest_lv72._100_say = "A Mennyei K\246nnycsepp a Megszentelt fa[ENTER]gyant\225j\225b\243l, a K\233k krist\225ly esszenci\225b\243l \233s a[ENTER]V\246r\246s Pokol-kvarcb\243l nyeri t\246k\233letes ragyog\225s\225t.[ENTER]A K\233k krist\225ly esszenci\225t J\233gf\246ld uralkod\243j\225t\243l[ENTER]lehet megszerezni. "
gameforge.main_quest_lv72._10_sendLetter = "Viharvert k\245t\225bla "
gameforge.main_quest_lv72._110_say = "Feljegyz\233st kell k\233sz\237tened err\245l a meglep\245[ENTER]le\237r\225sr\243l. Jelentsd Lee Chung-nak, amit az el\245bb[ENTER]olvast\225l. "
gameforge.main_quest_lv72._120_say = "Ah, j\243 eg\233szs\233gben t\233rt\233l vissza! Ha j\243l l\225tom az[ENTER]arcodon, felt\233telezem, ugye sikerrel j\225rt\225l? "
gameforge.main_quest_lv72._130_say = "Igen, val\243ban! A Viharvert k\245t\225bl\225n l\233v\245[ENTER]le\237r\225snak k\246sz\246nhet\245en megtudhattam, hogy meg[ENTER]lehet id\233zni a szent er\245ket egy Mennyei[ENTER]K\246nnycseppnek h\237vott m\225gikus dr\225gak\245[ENTER]haszn\225lat\225val. "
gameforge.main_quest_lv72._140_say = "Mennyei K\246nnycsepp... teh\225t l\233tezik. Tal\225lt\225l[ENTER]b\225rmilyen nyomot, hogyan juthatunk hozz\225? "
gameforge.main_quest_lv72._150_say = "Mennyei K\246nnycsepp k\233sz\237t\233s\233hez sz\252ks\233ged van[ENTER]Megszentelt fa gyant\225j\225ra, K\233k krist\225ly[ENTER]esszenci\225ra \233s V\246r\246s-Pokol-kvarcra. Azt mondj\225k,[ENTER]a K\233k krist\225ly esszenci\225t J\233gf\246ld uralkod\243j\225t\243l[ENTER]lehet megszerezni. "
gameforge.main_quest_lv72._160_say = "J\233gf\246ld uralkod\243ja? Hmm... Ez Sohan-hegyet kell[ENTER]jelentse.[ENTER]Meg fogom mutatni a jegyzeted az \193rny\233k harcos[ENTER]m\225gusoknak \233s kielemeztetem vel\252k.[ENTER]\220zenni fogok, ha m\225r t\246bbet tudok! "
gameforge.main_quest_lv72._170_say = "Fogadd ezt a munk\225d jutalm\225ul. Tov\225bbra is[ENTER]sz\225m\237tok a seg\237ts\233gedre! "
gameforge.main_quest_lv72._180_sendLetter = "Fagyos Kincs "
gameforge.main_quest_lv72._190_say = "Lee Chung parancsnok arr\243l t\225j\233koztatott, hogy a[ENTER]Mennyei K\246nnycsepphez sz\252ks\233ges els\245[ENTER]\246sszetev\245nek, a K\233k krist\225ly esszenci\225nak a[ENTER]Sohan-hegyen \233l\245 legend\225s Kilencfark\250 kincs\233hez[ENTER]van k\246ze.[ENTER]Ezt J\233g g\243lemek, Jetik \233s Fagyos j\233gemberek \245rzik[ENTER]\233beren. Vad\225ssz ezekre a sz\246rnyekre, hogy[ENTER]hozz\225juss a K\233k krist\225ly esszenci\225hoz. Besz\233lj[ENTER]\250jra Lee Chung-gal, miel\245tt csat\225ba indulsz. "
gameforge.main_quest_lv72._200_say = "Az \193rny\233k harcosok m\225gusai kider\237tett\233k, hogy a[ENTER]Sohan-hegy rettegett Kilencfark\250ja \250gy \245rzi a k\233k[ENTER]esszenci\225t, mint a saj\225t \233let\233t. "
gameforge.main_quest_lv72._20_say = "Lee Chung, az \193rny\233k harcosok parancsnoka[ENTER]besz\233lni akar veled. Kital\225lta, hogyan tudod[ENTER]legy\245zni az Agwi-t az \214rd\246g Katakomb\225j\225ban. "
gameforge.main_quest_lv72._210_say = "A Kilencfark\250 kincs\233t J\233g g\243lemek, Jetik \233s[ENTER]Fagyos j\233gemberek \245rzik.[ENTER][ENTER]50 K\233k krist\225ly esszencia sz\252ks\233ges a Mennyei[ENTER]K\246nnycsepp el\245\225ll\237t\225s\225hoz. "
gameforge.main_quest_lv72._220_say = "A V\246r\246s Pokol-kvarc feltehet\245leg a Hwang[ENTER]templomban vagy T\251zf\246ld\246n tal\225lhat\243. Felder\237t\245ket[ENTER]k\252ldtem ki, hogy t\246bbet megtudjunk. "
gameforge.main_quest_lv72._230 = "Lee Chung parancsnok arr\243l t\225j\233koztatott, hogy a[ENTER]Mennyei K\246nnycsepphez sz\252ks\233ges els\245[ENTER]\246sszetev\245nek, a K\233k krist\225ly esszenci\225nak a[ENTER]Sohan-hegyen \233l\245 legend\225s Kilencfark\250 kincs\233hez[ENTER]van k\246ze.[ENTER]Ezt J\233g g\243lemek, Jetik \233s Fagyos j\233gemberek \245rzik[ENTER]\233beren. Vad\225ssz ezekre a sz\246rnyekre, hogy[ENTER]hozz\225juss a K\233k krist\225ly esszenci\225hoz. "
gameforge.main_quest_lv72._240_notice = "\193tkutattad a legy\245z\246tt sz\246rnyek holttesteit \233s[ENTER]egy k\233k, csillog\243 dr\225gak\246vet tal\225lt\225l.[ENTER]Ez kell legyen a K\233k krist\225ly esszencia. "
gameforge.main_quest_lv72._250_notice = "Tal\225lnod kell m\233g tov\225bbi %d K\233k krist\225ly[ENTER]esszenci\225t. "
gameforge.main_quest_lv72._260_say = "Azt hiszem, elegend\245 mennyis\233g\251 tan\225csot kapt\225l[ENTER]m\225r ma. Gyere vissza reggel. "
gameforge.main_quest_lv72._270_say = "Ezek a krist\225lyok haszn\225lhatatlanok. N\233zd meg[ENTER]magad is: t\246r\246ttek. Hogy haszn\225lhat\243k legyenek,[ENTER]hib\225tlannak kell lenni\252k! Folytasd a keres\233st! "
gameforge.main_quest_lv72._280_say = "Ezek kit\251n\245 min\245s\233g\251ek! Folytasd! M\225r csak[ENTER]tov\225bbi %d kell. "
gameforge.main_quest_lv72._290_say = "\214sszegy\251jt\246tted az \246sszes K\233k krist\225ly[ENTER]esszenci\225t, amire sz\252ks\233gem van. \201rzem rajtuk a[ENTER]Kilencfark\250 erej\233t. Leny\251g\246z\245... Sz\243 szerint[ENTER]rezegnek az energi\225t\243l. Sz\233p volt! "
gameforge.main_quest_lv72._300_say = "A kaland folytat\243dik, ha el\233rted a 78-as szintet. "
gameforge.main_quest_lv72._30_say = "A hagyom\225nyos d\233monokkal ellent\233tben az Agwi-t[ENTER]nem egyszer\251 meg\246lni. Mi, \193rny\233k harcosok m\225r[ENTER]megpr\243b\225ltuk minden lehets\233ges m\243don - de mindig[ENTER]sikertelen\252l. "
gameforge.main_quest_lv72._40_say = "De most kider\252lt, a S\225rk\225ny Papn\245k rendelkeztek a[ENTER]hatalommal, hogy megid\233zz\233k a szent er\245ket a[ENTER]gonosz szellemek t\225vol tart\225sa \233rdek\233ben. "
gameforge.main_quest_lv72._50_say = "A V\246r\246s erd\245ben volt a S\225rk\225ny Papn\245k egyik szent[ENTER]temploma. Kutass ott romok \233s kultuszuk b\225rmilyen[ENTER]jele ut\225n. Felder\237t\245im jelentettek ott egy k\245b\245l[ENTER]k\233sz\252lt, boz\243ttal takart, viharvert t\225bl\225t...[ENTER]Tal\225n tal\225lunk valami hasznosat ezen a t\225bl\225n. "
gameforge.main_quest_lv72._60_sendLetter = "A felder\237t\233s "
gameforge.main_quest_lv72._70_say = "Lee Chung elmondta neked, hogy a S\225rk\225ny Papn\245k[ENTER]k\233pesek voltak szent er\245ket megid\233zni, az \245si[ENTER]feh\233r m\225gi\225t, ami t\225vol tartja a gonosz[ENTER]szellemeket. Keresd meg a V\246r\246s erd\245ben a[ENTER]Viharvert k\245t\225bl\225t, amir\245l Lee Chung besz\233lt \233s[ENTER]szerezz tov\225bbi bizony\237t\233kot. "
gameforge.main_quest_lv72._80_say = "Hossz\250 keres\233s ut\225n egy k\245t\225bla ker\252lt az utadba[ENTER]a boz\243tban, ami \250gy t\251nik, \233vsz\225zadok \243ta ott[ENTER]hever. Ez kell legyen az a r\233gi t\225bla, amir\245l Lee[ENTER]Chung besz\233lt! Neh\233zkesen megfejted a kopott[ENTER]feliratot. "
gameforge.main_quest_lv72._90_say = "A Mennyei K\246nnycsepp a S\225rk\225ny Papn\245k egyik[ENTER]leg\233rt\233kesebb titka. K\233sz\237t\233s\233nek m\251v\233szete[ENTER]gener\225ci\243k \243ta titokban maradt \233s extr\233m[ENTER]esetekben m\233g v\233rrel is v\233delmezt\233k. Az Agwi \233s[ENTER]d\233monai nem egyk\246nnyen f\233rk\245znek eme var\225zslatos[ENTER]dr\225gak\245 visel\245j\233nek k\246zel\233be. Ha a Mennyei[ENTER]K\246nnycsepp fel van t\246ltve a szent hatalom[ENTER]erej\233vel, ezt k\246vet\245en els\246pr\245 hat\225sa van. H\233t[ENTER]napon \225t olyan f\233nyesen ragyog, mint a[ENTER]sarkcsillag az \233gen. "
gameforge.main_quest_lv78 = {}
gameforge.main_quest_lv78._100_say = "Ah, fantasztikus! M\251k\246d\246tt. Tess\233k, itt a V\246r\246s[ENTER]Pokol-krist\225lyod. "
gameforge.main_quest_lv78._10_sendLetter = "V\246r\246s Pokol-kvarc "
gameforge.main_quest_lv78._110_sendLetter = "Utols\243 \246sszetev\245 "
gameforge.main_quest_lv78._120_say = "Lee Chung \233s a m\225gusok tan\225csa felfedezt\233k, hogy[ENTER]az utols\243 \246sszetev\245t, a Megszentelt fa gyant\225j\225t[ENTER]a V\246r\246s gonosz f\225kt\243l tudod megszerezni. Menj,[ENTER]vad\225ssz r\225juk a V\246r\246s erd\245ben \233s gy\251jts \246ssze 100[ENTER]adag fa gyant\225t.[ENTER]Besz\233lj Lee Chung-gal, miel\245tt elindulsz. "
gameforge.main_quest_lv78._130_say = "Lee Chung \233s a m\225gusok tan\225csa felfedezt\233k, hogy[ENTER]az utols\243 \246sszetev\245t, a Megszentelt fa gyant\225j\225t[ENTER]a V\246r\246s gonosz f\225kt\243l tudod megszerezni. Menj,[ENTER]vad\225ssz r\225juk a V\246r\246s erd\245ben \233s gy\251jts \246ssze 100[ENTER]adag fa gyant\225t. "
gameforge.main_quest_lv78._140_say = "Ez az utols\243 l\233p\233s a Mennyei K\246nnycsepp[ENTER]elk\233sz\237t\233s\233ben. Vigy\225zz magadra, a V\246r\246s erd\245[ENTER]tele van hal\225los teremtm\233nyekkel! "
gameforge.main_quest_lv78._150_say = "M\233g sz\252ks\233ged van tov\225bbi %d adagra a Megszentelt[ENTER]fa gyant\225j\225b\243l. "
gameforge.main_quest_lv78._160_notice = "Elegend\245 Megszentelt fa gyant\225d van! Vidd el Lee[ENTER]Chung parancsnoknak. "
gameforge.main_quest_lv78._170_say = "Ez az a Megszentelt fa gyant\225ja? \201rzem a hatalmas[ENTER]erej\233t. Fantasztikus![ENTER]Sajnos elk\252ldtem valamennyi m\225gusom egy[ENTER]k\252ldet\233sre. Oda lesznek egy ideig. Nincs[ENTER]v\233letlen\252l egy Baek-Go nev\251 vegy\233sz a[ENTER]sz\252l\245falvadban? "
gameforge.main_quest_lv78._180_say = "De, val\243ban ott van. "
gameforge.main_quest_lv78._190_say = "Ah, nagyszer\251! Fogd a h\225rom \246sszetev\245t \233s vidd el[ENTER]Baek-Go-nak. \213 k\233pes el\245\225ll\237tani bel\245l\252k a[ENTER]Mennyei K\246nnycseppet. "
gameforge.main_quest_lv78._200_say = "Hossz\250 \233s f\225raszt\243 utaz\225s van m\246g\246tted. K\233rlek,[ENTER]fogadd ezt a jutalmat az er\245fesz\237t\233seid\233rt. "
gameforge.main_quest_lv78._20_say = "Lee Chung, az \193rny\233k harcosok parancsnoka t\246bbet[ENTER]tudott meg a V\246r\246s Pokol-kvarcr\243l. Ennek[ENTER]elk\233sz\237t\233s\233hez h\225rom k\252l\246nb\246z\245 \246sszetev\245re van[ENTER]sz\252ks\233g: Vulk\225ni talajra Doyyumhwan-r\243l, Lobog\243[ENTER]s\246r\233nyekre \233s Alapk\246vekre.[ENTER]Vad\225ssz L\225ngokra, L\225ng harcosokra \233s Harci[ENTER]tigrisekre, hogy megszerezd ezeket az[ENTER]\246sszetev\245ket \233s gy\251jts mindegyikb\245l 20 darabot 20[ENTER]darab V\246r\246s Pokol-kvarc megalkot\225s\225hoz.[ENTER]Besz\233lj \250jra Lee Chung-gal, miel\245tt csat\225ba[ENTER]indulsz. "
gameforge.main_quest_lv78._210_sendLetter = "Mennyei K\246nnycsepp "
gameforge.main_quest_lv78._220_say = "T\233rj vissza sz\252l\245falvadba, keresd meg Baek-Go-t[ENTER]\233s Lee Chung nev\233ben k\233rd meg, hogy k\233sz\237tsen[ENTER]Mennyei K\246nnycseppet a h\225rom \246sszetev\245b\245l. "
gameforge.main_quest_lv78._230_say = "J\243 ideig t\225vol volt\225l. M\225r kezdtem azt k\233rdezni[ENTER]magamt\243l, vajon mi t\246rt\233nhetett veled. Mit hozt\225l[ENTER]nekem? "
gameforge.main_quest_lv78._240_say = "Lee Chung k\233rt meg, hogy j\246jjek hozz\225d egy[ENTER]sz\237vess\233g\233rt. "
gameforge.main_quest_lv78._250_say = "Lee Chung?! \213 a parancsnoka az \193rny\233k Har... Oh![ENTER]Shhhhh! Csend! Egy \193rny\233k harcos m\225gus el\245tt[ENTER]\225llsz. De ez az inform\225ci\243 titok, a faluban senki[ENTER]sem tud err\245l.[ENTER]Mif\233le sz\237vess\233get akar Lee Chung k\233rni t\245lem? "
gameforge.main_quest_lv78._260_say = "Azt k\233ri, hogy ebb\245l a h\225rom \246sszetev\245b\245l k\233sz\237ts[ENTER]Mennyei K\246nnycseppet. "
gameforge.main_quest_lv78._270_say = "Mennyei K\246nnycsepp, eh... Rendelkez\233s\233re \225ll egy[ENTER]csom\243 m\225gus, mi\233rt mindig r\225m b\237zza a bonyolult[ENTER]feladatok elv\233gz\233s\233t?![ENTER]...[ENTER]Rendben. Teh\225t itt van, a Mennyei K\246nnycsepp.[ENTER]Csod\225latos! K\246zvetlen\252l Lee Chung-nak k\252ld\246m el[ENTER]egy h\237rn\246kkel, \245 majd h\237vni fog, ha minden k\233szen[ENTER]\225ll. Elmondhatod, hogy mire val\243? "
gameforge.main_quest_lv78._280_say = "Nem tudok mondani semmi k\252l\246nlegeset, csak ezt:[ENTER]ez a k\245 megid\233zi a szent er\245ket, hogy t\225vol[ENTER]tartsa a d\233monokat \233s m\225s gonosz teremtm\233nyeket. "
gameforge.main_quest_lv78._290_say = "Nagyon \233rdekes. A legjobbakat k\237v\225nom a feladatot[ENTER]elv\233gz\233s\233hez. Az eddigi tetteid\233rt jutalmul itt[ENTER]van k\233t Zsugor\237tott fej.[ENTER]Most, hogy m\225r tudom, hogyan m\251k\246dik az elj\225r\225s,[ENTER]\246r\246mmel seg\237tek, ha tov\225bbi Mennyei K\246nnyekre[ENTER]lenne sz\252ks\233ged.[ENTER]Oh, \233s elk\252lden\233d sz\237v\233lyes \252dv\246zletem is Lee[ENTER]Chung-nak? "
gameforge.main_quest_lv78._300_say = "A kaland folytat\243dik, amint el\233rted a 84-es[ENTER]szintet. "
gameforge.main_quest_lv78._30_say = "M\225gusaink kider\237tett\233k, hogy a Mennyei K\246nnycsepp[ENTER]el\245\225ll\237t\225s\225hoz sz\252ks\233ges V\246r\246s Pokol-kvarc[ENTER]biztos\237tja abban a t\251z erej\233t. Ez a kvarc lehet[ENTER]az oka a T\251zf\246ld\246n \233l\245 teremtm\233nyek hihetetlen[ENTER]erej\233nek is. "
gameforge.main_quest_lv78._40_say = "A V\246r\246s Pokol-kvarc h\225rom \246sszetev\245b\245l k\233sz\252l:[ENTER]Vulk\225ni talajb\243l, Lobog\243 s\246r\233nyb\245l \233s Alapk\245b\245l.[ENTER]Valamennyi megtal\225lhat\243 T\251zf\246ld\246n. "
gameforge.main_quest_lv78._50_say = "Megcsin\225ltad! V\233gre megvan a sz\252ks\233ges %d darab[ENTER]V\246r\246s Pokol-krist\225lyunk. B\225tors\225god \233s er\245d ism\233t[ENTER]fel\252lm\250lta a v\225rakoz\225som! "
gameforge.main_quest_lv78._60_say = "Hi\225nyzik egy \246sszetev\245. Sz\252ks\233g\252nk van Vulk\225ni[ENTER]talajra, Lobog\243 s\246r\233nyre \233s Alapk\245re is. "
gameforge.main_quest_lv78._70_say = "Sajn\225lom, de naponta csak h\233t darab Pokol[ENTER]krist\225lyt tudok k\233sz\237teni. Ez az elj\225r\225s kih\237v\225s[ENTER]a m\225gikus k\233pess\233geim sz\225m\225ra, \233n nem vagyok[ENTER]m\225gus! "
gameforge.main_quest_lv78._80_say = "Teh\225t most \246sszekeverem a h\225rom \246sszetev\245t[ENTER]egym\225ssal \233s megpr\243b\225lok l\233trehozni egy V\246r\246s[ENTER]Pokol-kvarcot. "
gameforge.main_quest_lv78._90_say = "Argh! Nem siker\252lt a m\225gia. Sajnos t\250lbecs\252ltem a[ENTER]m\225gikus k\233pess\233geimet. K\246vetkez\245 alkalommal[ENTER]biztosan jobban fog siker\252lni. "
gameforge.main_quest_lv84 = {}
gameforge.main_quest_lv84._100_say = "Most, hogy legy\245zted Tartaros gener\225list,[ENTER]felt\225rult az \214rd\246g Katakomb\225ja eddig rejtett[ENTER]szintj\233nek bej\225rata. Odalent kell lennie Charon[ENTER]hercegnek! Teleport\225lj a hatodik szintre \233s n\233zz[ENTER]szembe az Agwi herceg\233vel. De l\233gy \243vatos![ENTER]Rendk\237v\252l er\245s, \233s ravasz, mint az \246rd\246g. "
gameforge.main_quest_lv84._10_sendLetter = "Kezd\245dik a harc "
gameforge.main_quest_lv84._110_say = "Ahogy az \214rd\246g Katakomb\225j\225ban mozogsz - szabadon[ENTER]\233s f\233lelem n\233lk\252l - lehetetlen, hogy csak[ENTER]egyszer\251 haland\243 vagy![ENTER]Az \246t\246dik emeleten l\233v\245 bazalt obeliszk a rejtett[ENTER]hatodik emeletre vezet\245 port\225lk\233nt fog m\251k\246dni. "
gameforge.main_quest_lv84._120_say = "Innen k\252ldi ki a parancsait Charon herceg az[ENTER]Agwi-gener\225lis Tartaros fel\233.[ENTER]Mire v\225rsz? Gy\245zd le Charon-t \233s hi\250s\237tsd meg a[ENTER]S\246t\233ts\233g szolg\225i \233s a Banshee balj\243s terveit! "
gameforge.main_quest_lv84._130_sayReward = "Megtetted! Charon, az Agwi-k hercege elpusztult. "
gameforge.main_quest_lv84._140_say = "Kimer\252lten, de megk\246nnyebb\252lve t\246rl\246d le a[ENTER]homlokodr\243l a verejt\233ket.[ENTER]Hirtelen \233les nevet\233s visszhangzik v\233gig az \214rd\246g[ENTER]Katakomb\225j\225n, mintha egy k\233st d\246fn\233nek kereszt\252l[ENTER]a sz\237veden:[ENTER]Hahahahaha! T\250l k\233s\245, ti sz\225nalmas emberek![ENTER]Mester\252nk, Sung Mahi m\225r felt\225madt \233s semmit sem[ENTER]tehettek, hogy most meg\225ll\237ts\225tok![ENTER]K\246zeleg az id\245, amikor Sung Mahi el\233ri teljes[ENTER]erej\233t azon a szigeten, ahol a gonosz s\225rk\225nyok[ENTER]alszanak. Vil\225gotok hal\225lra van \237t\233lve! "
gameforge.main_quest_lv84._150_sendLetter = "Befejezetlen t\246rt\233net "
gameforge.main_quest_lv84._160_say = "Menj Lee Chung-hoz \233s jelentsd neki a Banshee[ENTER]fenyeget\245 \252zenet\233t. "
gameforge.main_quest_lv84._170_say = "Miut\225n jelentetted Tartaros \233s Charon felett[ENTER]aratott gy\245zelmed a parancsnoknak, elism\233tled a[ENTER]Banshee f\233lelmetes \252zenet\233t. Komoly arccal kezd[ENTER]el besz\233lni: "
gameforge.main_quest_lv84._180_say = "Azt hittem, ha egyszer legy\245zz\252k az[ENTER]Agwi-herceget, meghi\250s\237tjuk a S\246t\233ts\233g Szolg\225i \233s[ENTER]a Banshee terveit. Mekkor\225t t\233vedtem... "
gameforge.main_quest_lv84._190_say = "A Banshee-nek csak Azraellel, az Agwi-k[ENTER]kir\225ly\225val egy\252tt siker\252lhetett Sung Mahi[ENTER]felt\225maszt\225sa. Kir\225z a hideg ett\245l a[ENTER]gondolatt\243l... "
gameforge.main_quest_lv84._200_say = "A sziget, ahol a gonosz s\225rk\225nyok alszanak...[ENTER]Hmm, ez a S\246t\233t S\225rk\225ny szikl\225t kell jelentse. Ez[ENTER]egy innen t\225vol es\245, felt\233rk\233pezetlen sziget.[ENTER]M\233g ha nem is \233rt\252nk el mindent, amit rem\233lt\252nk,[ENTER]akkor is nagy h\225l\225val tartozunk neked. A[ENTER]seg\237ts\233ged n\233lk\252l sohasem lett\252nk volna k\233pesek[ENTER]felt\225rni a baj forr\225s\225t, ami az \214rd\246g[ENTER]Katakomb\225j\225nak m\233ly\233n rejt\245zik. "
gameforge.main_quest_lv84._20_say = "Lee Chung megkapta a Mennyei K\246nnycseppet \233s[ENTER]mindent el\245k\233sz\237tett a k\252ldet\233sedhez az \214rd\246g[ENTER]Katakomb\225j\225ba. Menj el hozz\225, hogy t\246bbet[ENTER]megtudj. "
gameforge.main_quest_lv84._210_say = "Te igaz\225n nagy tetteket vitt\233l v\233ghez, olyanokat,[ENTER]amikre senki m\225s nem volt k\233pes. K\233sz leszek[ENTER]b\225rmikor mell\233d \225llni, amikor csak sz\252ks\233ged lesz[ENTER]r\225, eg\233sz h\225tral\233v\245 \233letemben. \201g veled! "
gameforge.main_quest_lv84._30_say = "Most, hogy a Mennyei K\246nnycsepp itt van a[ENTER]kez\252nkben, m\225r csak id\245 k\233rd\233se, mikor gy\245zz\252k le[ENTER]a S\246t\233ts\233g szolg\225it \233s \251zz\252k ki vil\225gukb\243l az[ENTER]Agwi-t! De a K\246nnycsepp teljes ereje csak akkor[ENTER]szabadul fel, ha az \214rd\246g Katakomb\225j\225ban egy[ENTER]adott helyen ker\252l bevet\233sre. "
gameforge.main_quest_lv84._40_say = "Mi \246t szintr\245l tudunk az \214rd\246g Katakomb\225j\225ban. Az[ENTER]\246t\246dik, \233s \225ltalunk ismert v\233gs\245 emeleten \225t kell[ENTER]jutnod Tartaros-on, a f\233lelmetes Agwi[ENTER]gener\225lison, aki harmadik a rangsorban Azrael[ENTER]kir\225ly \233s Charon m\246g\246tt. Gy\245zd le \245t a Mennyei[ENTER]K\246nnycsepp seg\237ts\233g\233vel! "
gameforge.main_quest_lv84._50_say = "De hol van Charon? "
gameforge.main_quest_lv84._60_sendLetter = "Tartaros gener\225lis "
gameforge.main_quest_lv84._70_say = "Csak akkor haszn\225ld a Mennyei K\246nnycseppet, ha[ENTER]el\233rted az \214rd\246g Katakomb\225j\225nak \246t\246dik emelet\233t.[ENTER]Az \214rd\246g Katakomb\225j\225nak bej\225rata a D\233mon-torony[ENTER]m\246g\246tt tal\225lhat\243. "
gameforge.main_quest_lv84._80_say = "A szent er\245k elkezdik kifejteni hat\225sukat a[ENTER]Mennyei K\246nnycseppen bel\252l. \201rzed, amint[ENTER]hihetetlen er\245 j\225rja \225t a tested. E k\245 ereje[ENTER]egyszer\251en elk\233peszt\245![ENTER][ENTER]Gy\245zd le Tartaros gener\225list. "
gameforge.main_quest_lv84._90_sendLetter = "Charon herceg "
