gameforge.main_quest_lv9._20_sendLetter = "Besz\233lj a V\225ros \245rrel "
gameforge.main_quest_lv9._30_sayReward = "Megtetted az els\245 l\233p\233seket ahhoz, hogy val\243di[ENTER]h\245ss\233 v\225lj. Ideje nagyobb dolgokat is v\233ghez[ENTER]vinni. Menj a V\225ros \245rh\246z, \233s vedd fel t\245le az[ENTER]utols\243 kezd\245 k\252ldet\233sed. "
gameforge.main_quest_lv9._40_say = "K\233sz vagy arra, hogy neh\233z feladatokat is[ENTER]megoldj\225l? Vedd figyelembe, hogy a k\246nny\251[ENTER]feladatok ideje lej\225rt, ha ki akarsz igaz\225n \225llni[ENTER]a birodalmad j\246v\245j\233\233rt. Sok csat\225t \233s n\233lk\252l\246z\233st[ENTER]fogsz \225t\233lni. Teh\225t l\233gy mindig \243vatos. \205me, ez a[ENTER]jutalom neked j\225r az eddigi tetteid[ENTER]elismer\233sek\233nt. Azt k\237v\225nom, hogy legyen[ENTER]hasznodra. "
gameforge.main_quest_lv9._50_say = "Mostant\243l a kapit\225ny melletted fog \225llni.[ENTER]Figyelemmel k\237s\233r t\233ged \233s a fejl\245d\233sedet, \233s[ENTER]feladatokkal l\225t el az edz\233s c\233lj\225b\243l. Gyakorold[ENTER]m\233g egy kicsit a harcot, \233s menj azt\225n el hozz\225.[ENTER]Minden j\243t k\237v\225nok neked! "
gameforge.main_quest_lv90 = {}
