gameforge.main_quest_lv90._020_say = "Utaz\225sod hossz\250 \233s f\225raszt\243 volt. De most v\233gre[ENTER]el\233rted c\233lod: a S\246t\233t S\225rk\225ny szikl\225t.[ENTER]Keresd meg Angmur Admir\225list. A S\225rk\225nyt\251z-fokn\225l[ENTER]tal\225lod. "
gameforge.main_quest_lv90._030_say = "\220dv\246z\246llek a S\225rk\225nyt\251z-fokon, idegen! A Sung[ENTER]Mahi elleni k\252zdelm\252nkben seg\237teni j\246tt\233l? "
gameforge.main_quest_lv90._040_say = "Igen, pontosan. Lee Chung, az \193rny\233kharcosok[ENTER]parancsnoka k\252ld\246tt. "
gameforge.main_quest_lv90._050_say = "Lee Chung! Hossz\250 ideje a t\225rsam. Teh\225t az \245[ENTER]k\233r\233s\233re vagy itt. Nagyszer\251, akkor tudom, hogy[ENTER]megb\237zhatok benned. "
gameforge.main_quest_lv90._060_say = "K\246sz\246n\246m. Teh\225t, mi a helyzet? "
gameforge.main_quest_lv90._070_say = "D\233monok uralkodnak a sziget nagy r\233sze felett.[ENTER]Senki \233s semmi sincs biztons\225gban t\245l\252k. M\233g[ENTER]egym\225st is marj\225k. Sung Mahi s\246t\233t befoly\225sa[ENTER]elvette az esz\252ket. "
gameforge.main_quest_lv90._080_say = "Ig\233nybe venn\233m a seg\237ts\233ged. Fel tudn\225d der\237teni[ENTER]a szigetet \233s friss helyzetjelent\233st ny\250jtani[ENTER]nekem? "
gameforge.main_quest_lv90._090_say = "Term\233szetesen. "
