gameforge.main_quest_lv90._1020_sayTitle = "Gy\251jts agyagt\233gl\225kat "
gameforge.main_quest_lv90._1030_say = "Agyagt\233gl\225k gy\251jt\233s\233hez harcolj a Mantik\243rok[ENTER]ellen. "
gameforge.main_quest_lv90._1040_1_notice = "Elegend\245 agyagt\233gl\225t gy\251jt\246tt\233l. "
