gameforge.main_quest_lv90._1050_say = "Besz\233lj Angmur Admir\225lissal. "
gameforge.main_quest_lv90._1060_say = "Nagyon j\243! Neked k\246sz\246nhet\245en m\225r elegend\245[ENTER]anyagunk van a v\233d\245s\225nc meger\245s\237t\233s\233hez. Amint[ENTER]ezzel v\233gz\252nk, h\237vatni foglak megint. "
