gameforge.main_quest_lv90._240_say = "Miut\225n bej\225rtad az eg\233sz szigetet, a k\246vetkez\245[ENTER]felismer\233s v\225lt vil\225goss\225 sz\225modra: Mindenhol[ENTER]hemzsegnek a d\233monok. "
