gameforge.main_quest_lv90._270_say = "Mialatt besz\225molsz a S\246t\233t S\225rk\225ny szikl\225n[ENTER]uralkod\243 jelenlegi helyzetr\245l, Angmur Admir\225lis[ENTER]arca egyre ink\225bb elkomorodik. "
gameforge.main_quest_lv90._280_say = "Jobban \246r\252ltem volna, ha jobb h\237reket hozol. "
