gameforge.main_quest_lv90._300_say = "Igen, elismerem, el\233g komorak a kil\225t\225sok. "
gameforge.main_quest_lv90._310_say = "Igen, \237gy is mondhatjuk...[ENTER]Lee Chungnak tal\225lnia kellett egy jelent\245s nyomot.K\252d\246tt ugyan egy levelet n\233h\225ny fontos[ENTER]inform\225ci\243val, de az sohasem \233rt el hozz\225m. Az[ENTER]\252zenetet elfogt\225k a gnollok. "
