gameforge.main_quest_lv90._330_say = "Persze, k\233szs\233gesen. "
gameforge.main_quest_lv90._340_say = "K\246sz\246n\246m. A gnollok el\233gg\233 k\246zel telepedtek le. "
gameforge.main_quest_lv90._350_sayTitle = "Tal\225ld meg Lee Chung level\233t. "
gameforge.main_quest_lv90._360_say = "A k\246vetkez\245 l\233nyek egyik\233n\233l van Lee Chung[ENTER]levele: Gnoll harcos, Gnoll \237j\225sz, Gnoll[ENTER]v\233delmez\245, Gnoll m\225gus, Gnoll t\225bornok, Gnoll[ENTER]Nagy\250r vagy a Legf\245bb Gnoll-\245r. "
gameforge.main_quest_lv90._370_say = "Ha meg akarjuk \225ll\237tani Sung Mahi-t, sz\252ks\233g\252nk[ENTER]van erre a lev\233lre! A tolvaj a gnoll-t\246rzs[ENTER]soraib\243l sz\225rmazik. "
