gameforge.main_quest_lv90._380_2_notice = "Vidd el Angmur Admir\225lisnak. "
gameforge.main_quest_lv90._390_say = "Besz\233lj Angmur Admir\225lissal. "
gameforge.main_quest_lv90._400_say = "Visszat\233rt\233l, \233s n\225lad a lev\233l is! Igen, tudtam,[ENTER]hogy sz\225m\237thatok r\225d! L\225ssuk h\225t! "
gameforge.main_quest_lv90._410_say = "\220dv, Angmur![ENTER]Bar\225tom, Sung Mahi \252res t\225boraiban tal\225ltunk[ENTER]valamit: a S\246t\233ts\233g szolg\225i titkos \252zenetek \225ltal[ENTER]\233rt\233k el sz\246vets\233geseiket a szigeten. Ezen[ENTER]\252zenetek egyike a Gnoll t\246rzsnek lett k\252ldve. Ha[ENTER]ezt meg tudod szerezni, egy fontos l\233p\233ssel[ENTER]lesz\252nk a d\233monok el\245tt! T\225mogat\225sk\233nt k\252ld\246k[ENTER]%s-t. J\243 er\245t \233s b\225tors\225got k\237v\225nok neked ezekben[ENTER]a s\246t\233t id\245kben.[ENTER]L.C. "
gameforge.main_quest_lv90._420_say = "K\233meim ki fogj\225k der\237teni, hogy a gnollok[ENTER]megkapt\225k-e a levelet vagy sem. Addig is k\233rlek,[ENTER]fogadd ezt k\246sz\246netk\233nt. "
