gameforge.main_quest_lv90._440_say = "Angmur Admir\225lis h\237vat. Der\237tsd ki, mit akar. "
gameforge.main_quest_lv90._450_say = "A Gnoll t\225bornok m\225r megkapta a S\246t\233ts\233g[ENTER]szolg\225inak level\233t. Meg tudod szerezni? De l\233gy[ENTER]nagyon \243vatos: a gnollok rendk\237v\252l agressz\237vek.[ENTER]El\245bb t\225madnak, \233s csak ut\225na k\233rdeznek. "
