gameforge.main_quest_lv91._310_say = "Ah, igen! A lev\233l miatt vagy itt. Angmur m\225r[ENTER]eml\237tette nekem. "
gameforge.main_quest_lv91._320_say = "M\233g nem tudom megfejteni a levelet, de \250gy t\251nik,[ENTER]hogy ez a r\225kf\233l\233k t\246rzs\233nek k\243dol\225sa, akik a[ENTER]Nefrit-\246b\246lben \233lnek. "
gameforge.main_quest_lv91._330_say = "Hogy megfejthessem ezeket a karaktereket,[ENTER]sz\252ks\233gem van a r\225kf\233l\233k t\246rzs\233nek Carapax[ENTER]k\243dj\225ra. Tudn\225l szerezni tizet bel\245le? "
gameforge.main_quest_lv91._340_say = "Term\233szetesen. "
gameforge.main_quest_lv91._350_sayTitle = "Carapax k\243d "
gameforge.main_quest_lv91._360_say = "Indulj csat\225ba a r\225kf\233l\233k t\246rzse ellen \233s szerezz[ENTER]t\237z darabot a Carapax k\243db\243l. "
gameforge.main_quest_lv91._370_say = "Sajnos ez a Carapax k\243d s\233r\252lt, nem tudom[ENTER]haszn\225lni. K\233rlek, hozz helyette m\225sikat. "
gameforge.main_quest_lv91._380_say = "Megtal\225ltad a Carapax k\243dokat. Tekn\245sp\225nc\233l[ENTER]alak\250ak. "
gameforge.main_quest_lv91._390_say = "T\246k\233letes, most m\225r meg tudom fejteni a levelet.[ENTER]J\243 munka! Tess\233k, fogadd ezt h\225l\225m jel\233\252l. "
gameforge.main_quest_lv91._400_say = "Hozz nekem tov\225bbi %d darabot! "
gameforge.main_quest_lv91._410_1_notice = "Tal\225lt\225l egy Carapax k\243dot. "
gameforge.main_quest_lv91._410_2_notice = "Vidd el Yon-I-Walker-nek. "
gameforge.main_quest_lv91._420_sendLetter = "A mantik\243rok levele dek\243dolva. "
gameforge.main_quest_lv91._430_say = "Yon-I-Walker keres t\233ged. Menj \233s tudd meg,[ENTER]siker\252lt-e m\225r megfejtenie a levelet vagy sem. "
gameforge.main_quest_lv91._440_say = "*motyog\225s* ...ah! Te vagy az! A seg\237ts\233gednek[ENTER]k\246sz\246nhet\245en meg tudtam fejteni az \252zenet nagy[ENTER]r\233sz\233t, de m\233g nem tudtam semmit sem kezdeni az[ENTER]utols\243 r\233sszel. Att\243l tartok, \250jra a seg\237ts\233ged[ENTER]kell k\233rnem. S\252rg\245sen sz\252ks\233gem van[ENTER]Carapax-porra.[ENTER]A r\225kf\233l\233k t\246rzs\233be tartoz\243 Hom\225r t\225bornokn\225l[ENTER]vagy a Tarisznyar\225k kir\225lyn\225l tal\225lod. "
gameforge.main_quest_lv91._450_say = "Carapax-por "
gameforge.main_quest_lv91._460_say = "Igen, csak a r\225kf\233l\233k t\246rzse birtokolja. M\225r egy[ENTER]kis adag por is hal\225los! H\225rom adag el\233g lesz.[ENTER]Sok szerencs\233t! "
gameforge.main_quest_lv91._470_say = "Halad\233ktalanul \250tnak indulok. "
gameforge.main_quest_lv91._480_sayTitle = "Carapax-por "
gameforge.main_quest_lv91._490_say = "Indulj a r\225kf\233l\233k t\246rzs\233be tartoz\243 Hom\225r t\225bornok[ENTER]\233s a Tarisznyar\225k kir\225ly ellen, \233s szerezz t\245l\252k[ENTER]h\225rom adag Carapax-port! "
gameforge.main_quest_lv91._500_say = "A Carapax-por k\252l\246n\246sen m\233rgez\245. V\225rnom kell egy[ENTER]napot, hogy a hat\225sa enyh\252lj\246n. Gyere vissza[ENTER]holnap, rem\233lhet\245leg akkor m\225r t\246bbet tudok[ENTER]mondani. "
gameforge.main_quest_lv91._510_say = "N\225lad van a Carapax-por! "
gameforge.main_quest_lv91._520_say = "J\243 munka! Most m\225r v\233gre megfejthetem a levelet.[ENTER]K\233rlek, fogadd el ezt jutalmul. "
gameforge.main_quest_lv91._530_say = "Hozz nekem tov\225bbi %d darabot! "
gameforge.main_quest_lv91._540_say = "Ez a Carapax por szennyezett. K\233rlek, hozz egy \250j[ENTER]adagot. "
gameforge.main_quest_lv91._550_1_notice = "Tal\225lt\225l egy adag Carapax-port. "
gameforge.main_quest_lv91._550_2_notice = "Add \225t Yon-I-Walker-nek. "
gameforge.main_quest_lv91._560_sendLetter = "M\233rgezett! "
gameforge.main_quest_lv91._570_say = "Angmur Admir\225lisnak s\252rg\245sen sz\252ks\233ge van r\225d.[ENTER]Tudd meg, mire van sz\252ks\233ge. "
gameforge.main_quest_lv91._580_say = "V\233gre itt vagy! H\225la a S\225rk\225nyistennek![ENTER]Yon-I-Walker-t megm\233rgezte a Carapax-por. "
gameforge.main_quest_lv91._590_say = "Sietni akart \233s gondatlan volt. Ami m\233g enn\233l is[ENTER]rosszabb, hogy felhaszn\225ltuk a teljes[ENTER]gy\243gyn\246v\233ny-k\233szlet\252nk.[ENTER]Keresd meg a Sziklavir\225got - annak a gy\246kere[ENTER]semleges\237teni tudja a m\233rget. A t\233rk\233pen[ENTER]megjel\246ltem neked a helyet, ahol tal\225lod. "
gameforge.main_quest_lv91._600_say = "Term\233szetesen. "
gameforge.main_quest_lv91._610_say = "Tudtam, hogy sz\225m\237thatok r\225d! K\233rlek siess, nincs[ENTER]t\250l sok id\245nk! "
gameforge.main_quest_lv91._620_sayTitle = "Mentsd meg Yon-I-Walker-t! "
gameforge.main_quest_lv91._630_say = "Tal\225ld meg a Sziklavir\225g-gy\246keret, ami meg tudja[ENTER]gy\243gy\237tani a megm\233rgezett Yon-I-Walker-t. "
gameforge.main_quest_lv91._640_1_notice = "Vidd el Yon-I-Walker-nek a Sziklavir\225g-gy\246keret. "
gameforge.main_quest_lv91._650_say = "*k\246h\246g\233s*[ENTER]*kr\225kog\225s*[ENTER]Ah, te vagy az. Egy\225ltal\225n nem vagyok j\243l.[ENTER]Megtal\225ltad a Sziklavir\225g-gy\246keret? "
gameforge.main_quest_lv91._660_say = "Igen, itt van. "
gameforge.main_quest_lv91._670_say = "Ah, m\225ris jobban \233rzem magam. \218gy t\251nik, m\233g nem[ENTER]j\246tt el az \233n id\245m.[ENTER]K\246sz\246n\246m. Fogadd ezt jutalmul. Most m\225r be tudom[ENTER]fejezni a munk\225m. Angmur Admir\225lis \233rtes\237teni[ENTER]fog, amint v\233gzek a lev\233l megfejt\233s\233vel. "
gameforge.main_quest_lv91._680_say = "Yon-I-Walker besz\233lni akar veled. "
gameforge.main_quest_lv91._760_say = "(Fennmarad: %s %s, %s %s) "
gameforge.main_quest_lv91._770_say = {}
gameforge.main_quest_lv91._780_say = "A kaland folytat\243dik, amint el\233rted a 92-es[ENTER]szintet. "
gameforge.main_quest_lv92 = {}
gameforge.main_quest_lv92._010_sendLetter = "A V\246r\246s tolvaj-lev\233l "
gameforge.main_quest_lv92._020_say = "A S\246t\233ts\233g szolg\225i \225ltal k\252ld\246tt utols\243 lev\233l a[ENTER]V\246r\246s tolvaj band\225nak sz\243l. Angmur Admir\225lisnak[ENTER]t\246bb inform\225ci\243ja van sz\225modra. "
gameforge.main_quest_lv92._030_say = "Egyre k\246zelebb ker\252l\252nk a S\246t\233ts\233g szolg\225i[ENTER]\246sszeesk\252v\233s\233nek megfejt\233s\233hez. Az utols\243 lev\233l a[ENTER]V\246r\246s tolvaj banda kezeiben van. "
gameforge.main_quest_lv92._040_say = "V\246r\246s tolvaj banda? "
gameforge.main_quest_lv92._050_say = "Ez egy csoportnyi b\251n\246z\245, akik a S\246t\233t S\225rk\225ny[ENTER]szikl\225k k\246z\233 lettek sz\225m\251zve. K\252l\246nlegess\233g a[ENTER]v\246r\246s tolvajokr\243l, hogy itt emberek sz\246vetkeztek[ENTER]d\233monokkal. "
gameforge.main_quest_lv92._060_say = "D\233monok, akik emberekkel sz\246vetkeztek ahelyett,[ENTER]hogy megett\233k volna \245ket? \201rdekes. "
gameforge.main_quest_lv92._070_say = "K\246z\246s c\233l \233rdek\233ben egyes\252ltek, mely az: arany. A[ENTER]v\246r\246s tolvajok t\225bora nincs messze innen. Gy\245zd[ENTER]le a V\246r\246s tolvaj h\243h\233rt \233s a Fekete t\225bornokot.[ENTER]Egyik\252kn\233l van a lev\233l. "
gameforge.main_quest_lv92._080_say = "Viszont sajnos id\245ben felfigyeltek a[ENTER]sz\225nd\233kainkra, \250gyhogy a levelet n\233gy r\233szre[ENTER]szak\237tott\225k. Valamennyit meg kell tal\225lnunk. "
gameforge.main_quest_lv92._090_say = "Minden rendben. "
gameforge.main_quest_lv92._100_say = "K\246sz\246n\246m! "
gameforge.main_quest_lv92._110_sayTitle = "A V\246r\246s tolvaj-lev\233l "
gameforge.main_quest_lv92._120_say = "K\252zdj meg a V\246r\246s tolvaj h\243h\233rral \233s a Fekete[ENTER]t\225bornokkal. Tal\225ld meg mind a n\233gy darabj\225t a[ENTER]lev\233lnek. "
gameforge.main_quest_lv92._130_say = "M\233g nem teljes a lev\233l. Tal\225ld meg az \246sszes[ENTER]darabot. "
gameforge.main_quest_lv92._140_1_notice = "Megtal\225ltad a V\246r\246s tolvaj-lev\233l valamennyi[ENTER]darabj\225t. "
gameforge.main_quest_lv92._140_2_notice = "Mutasd meg Angmur Admir\225lisnak. "
gameforge.main_quest_lv92._150_say = "Besz\233lj Angmur Admir\225lissal. "
gameforge.main_quest_lv92._160_say = "J\243 munka. Tess\233k, fogadd ezt h\225l\225m jel\233\252l. "
gameforge.main_quest_lv92._170_sendLetter = "A V\246r\246s tolvaj-lev\233l "
gameforge.main_quest_lv92._180_say = "Angmur Admir\225lisnak sz\252ks\233ge van a seg\237ts\233gedre. "
gameforge.main_quest_lv92._190_say = "J\243, hogy itt vagy. Van egy probl\233m\225nk. "
gameforge.main_quest_lv92._200_say = "Mi t\246rt\233nt? "
gameforge.main_quest_lv92._210_say = "Val\243j\225ban a lev\233lnek van egy \246t\246dik darabja is.[ENTER]Ezen darab n\233lk\252l a lev\233l t\246bbi r\233sze \233rt\233ktelen.[ENTER]M\225r elk\252ldtem Bae-Yong-ot, az egyik legb\225trabb[ENTER]emberemet, de valami t\246rt\233nhetett vele. M\225r r\233gen[ENTER]vissza kellett volna t\233rnie. Meg tudn\225d keresni? "
gameforge.main_quest_lv92._220_say = "Persze! Tudod, merre kellene most lennie? "
gameforge.main_quest_lv92._230_say = "Van egy elm\233letem, igen. Utolj\225ra azt eml\237tette,[ENTER]hogy a Nefrit-\246b\246lbe akart menni. De senki sem[ENTER]tudja biztosra megmondani, hogy oda\233rt-e vagy[ENTER]sem. "
gameforge.main_quest_lv92._240_say = "Azonnal indulok! "
gameforge.main_quest_lv92._250_sayTitle = "Az elt\251nt katona "
gameforge.main_quest_lv92._260_say = "Tal\225ld meg a lev\233l \246t\246dik darabj\225t. Ehhez keresd[ENTER]Bae-Yong-ot a Nefrit-\246b\246lben. "
gameforge.main_quest_lv92._270_say = "M\233g nem tal\225ltad meg Bae-Yong-ot?[ENTER]Ez \233let \233s hal\225l k\233rd\233se! K\233rlek, folytasd a[ENTER]keres\233st. "
gameforge.main_quest_lv92._280_say = "*k\246h\246g\233s*[ENTER]K\246sz\246n\246m, hogy megtal\225lt\225l. S\250lyosan megs\233r\252ltem[ENTER]a csat\225ban, \233s att\243l tartok, m\225r nem sok id\245m[ENTER]maradt... Tess\233k, ezt vettem el egy v\246r\246s[ENTER]tolvajt\243l. Vidd el az Admir\225lisnak! Menj! \201n[ENTER]rendben le...[ENTER](Meghal a karjaidban.) "
gameforge.main_quest_lv92._290_1_notice = "Miel\245tt Bae-Yong meghalt, \225tadta neked a lev\233l[ENTER]hi\225nyz\243 darabj\225t. "
gameforge.main_quest_lv92._290_2_notice = "Menj vissza Angmur Admir\225lishoz. "
gameforge.main_quest_lv92._300_say = "H\225t visszat\233rt\233l! Megtal\225ltad Bae-Yong-ot? "
gameforge.main_quest_lv92._310_say = "Igen, de... "
gameforge.main_quest_lv92._320_say = "De?[ENTER]Oh, ne... Halott? "
gameforge.main_quest_lv92._330_say = "Nem tehettem \233rte semmit. Sajn\225lom. B\225tor f\233rfi[ENTER]volt \150 az \233lete \225r\225n is v\233dte a lev\233l utols\243[ENTER]darabj\225t. Itt van. "
gameforge.main_quest_lv92._340_say = "M\233lyen megrend\237t benn\252nket Bae-Yong elveszt\233se.[ENTER]Nagyon b\252szke vagyok r\225. Teljes\237tette k\252ldet\233s\233t[ENTER]\150 most m\225r megvan a lev\233l minden r\233sze. "
gameforge.main_quest_lv92._350_say = "Mindent k\246sz\246n\246k. Tess\233k, itt a jutalmad.[ENTER]Most megyek, gy\250jtok egy gyerty\225t a templomban[ENTER]Bae-Yong-\233rt.[ENTER]K\233s\245bb h\237vatlak majd. "
gameforge.main_quest_lv92._360_say = "Menj Angmur Admir\225lishoz. "
gameforge.main_quest_lv92._370_sendLetter = "A V\246r\246s tolvaj-lev\233l megfejt\233se "
gameforge.main_quest_lv92._380_say = "Angmur Admir\225lisnak fontos inform\225ci\243i vannak a[ENTER]V\246r\246s tolvaj-lev\233llel kapcsolatban.[ENTER]Hallgasd meg, mit akar mondani. "
gameforge.main_quest_lv92._390_say = "Ah, h\225t itt vagy. A S\246t\233ts\233g szolg\225i fejf\225j\225st[ENTER]okoznak. Ez a lev\233l is k\243dolva van. K\233rlek, vidd[ENTER]el Yon-I-Walker-nek. "
gameforge.main_quest_lv92._400_say = "\201rtettem. "
gameforge.main_quest_lv92._410_say = "Add \225t a k\243dolt levelet Yon-I-Walker-nek. "
gameforge.main_quest_lv92._420_say = "Argh! Mindig \237gy kell idelopakodnod?![ENTER]Mit tehetek \233rted? "
gameforge.main_quest_lv92._430_say = "Itt a V\246r\246s tolvaj-lev\233l. Ez is k\243dolt, mint a[ENTER]t\246bbi. "
gameforge.main_quest_lv92._440_say = "Hadd l\225ssam. Hmm, ezek triton karaktereknek[ENTER]t\251nnek. Nem kellene, hogy neh\233z legyen[ENTER]megfejteni. "
gameforge.main_quest_lv92._450_say = "Kit\251n\245. Mennyi id\245 alatt v\233gzel vele? "
gameforge.main_quest_lv92._460_say = "Ne olyan gyorsan! A k\243dol\225s nem k\252l\246n\246sebben[ENTER]bonyolult, de nem fog menni tov\225bbi forr\225sok[ENTER]n\233lk\252l. "
gameforge.main_quest_lv92._470_say = "Persze, hogy nem. Az \250gy t\250l egyszer\251 lenne. "
gameforge.main_quest_lv92._480_say = "L\225tom, nem vesz\237tetted el a humor\233rz\233ked, hehe.[ENTER]A lev\233l dek\243dol\225s\225hoz Oin-pikkelyekre van[ENTER]sz\252ks\233gem. A tritonok t\246rzs\233b\245l csak Kappa[ENTER]t\225bornok \233s maga Triton viselheti ezeket a ritka[ENTER]pikkelyeket. K\233rlek, hozz bel\245l\252k tizet. "
gameforge.main_quest_lv92._490_say = "M\225ris indulok. "
gameforge.main_quest_lv92._500_sayTitle = "Tal\225lj Oin-pikkelyeket! "
gameforge.main_quest_lv92._510_say = "Csak Triton, a tritonok Kir\225lya, valamint Kappa[ENTER]t\225bornok visel Oin-pikkelyeket. "
gameforge.main_quest_lv92._520_say = "Nem tudom megfejteni a levelet e pikkelyek n\233lk\252l.S\252rg\245sen sz\252ks\233gem van r\225juk. "
gameforge.main_quest_lv92._530_1_notice = "Megtal\225ltad a tritonikus Oin-pikkelyt. "
gameforge.main_quest_lv92._530_2_notice = "Vidd el gyorsan Yon-I-Walker-nek. "
gameforge.main_quest_lv92._540_say = "J\243l csin\225ltad. Amint megfejtettem a levelet,[ENTER]tudatom Angmur Admir\225lissal.[ENTER]Pihenned kellene egy kicsit. Tess\233k, fogadd ezt[ENTER]nagyrabecs\252l\233sem jel\233\252l. "
gameforge.main_quest_lv92._550_say = "Yon-I-Walker besz\233lni akar veled. "
gameforge.main_quest_lv92._560_sendLetter = "S\246t\233t tervek "
gameforge.main_quest_lv92._570_say = "Meg lett fejtve a S\246t\233ts\233g szolg\225inak levele.[ENTER]Angmur Admir\225lis besz\233lni akar veled a balj\243slat\250[ENTER]tervekr\245l. "
gameforge.main_quest_lv92._580_say = "Siker\252lt teljesen megfejten\252nk a titkos \252zenetet.[ENTER]Eml\233kszel a gnolloknak k\252ld\246tt lev\233lre? Ott m\225r[ENTER]sz\243 volt a szigeten m\233lyen alv\243 s\225rk\225nyokr\243l,[ENTER]valamint arr\243l, hogy mi m\243don lehet \245ket[ENTER]fel\233breszteni \233s teljesen feld\252h\237teni. Most[ENTER]megtudtuk azt is, a S\246t\233ts\233g szolg\225i sz\225m\225ra[ENTER]mi\233rt is hasznos ez. "
gameforge.main_quest_lv92._590_say = "Ha abban a pillanatban \246l\246d meg a s\225rk\225nyt,[ENTER]amikor az elm\233je olyan fekete, mint a pokol[ENTER]torka, az kil\246ki mag\225b\243l az \201j gy\246ngy\233t. E gy\246ngy[ENTER]seg\237ts\233g\233vel megid\233zhet\245k a mi vil\225gunkban Sung[ENTER]Mahi m\233rhetetlen er\245i. Ez az \245 balj\243slat\250 terv\252k! "
gameforge.main_quest_lv92._600_say = "J\243l meg kell gondolnunk a k\246vetkez\245 l\233p\233s\252nk.[ENTER]Amint van b\225rmilyen h\237rem sz\225modra, h\237vatni[ENTER]foglak. K\246sz\246net minden\233rt. "
gameforge.main_quest_lv92._610_say = "A kaland folytat\243dik, amint el\233rted a 93-as[ENTER]szintet. "
gameforge.main_quest_lv93 = {}
gameforge.main_quest_lv93._010_sendLetter = "Er\245gy\251jt\233s I "
gameforge.main_quest_lv93._020_say = "Angmur Admir\225lis besz\233lni akar veled. "
gameforge.main_quest_lv93._030_say = "Szorosan a S\246t\233ts\233g szolg\225i nyom\225ban vagyunk. "
gameforge.main_quest_lv93._040_say = "Hogy legy\245zz\252k \245ket, meg kell er\245s\237ten\252nk[ENTER]er\245inket. Ismered a Bels\245 f\233nyt? Ez koncentr\225lt[ENTER]energia. N\233h\225ny titokzatos l\233ny vagy n\246v\233ny[ENTER]birtokolja. Yon-I-Walker italt tud bel\245le[ENTER]k\233sz\237teni. Menj el hozz\225. "
gameforge.main_quest_lv93._050_say = "\201rtettem. "
gameforge.main_quest_lv93._060_say = "Ah, itt a megment\245m![ENTER]A Bels\245 f\233ny, oh igen... italom a S\246t\233ts\233g[ENTER]szolg\225i egyenrang\250 ellenfel\233v\233 tesz t\233ged. "
gameforge.main_quest_lv93._070_say = "Ehhez a k\252klopszok \233s az \243ri\225sok bels\245 f\233ny\233re[ENTER]van sz\252ks\233gem. Csak az egyes csoportok[ENTER]t\246rzsf\245n\246kei rejtik magukban. Szerezd meg el\245bb a[ENTER]k\252klopsz\233t. "
gameforge.main_quest_lv93._080_say = "\201rtettem. "
gameforge.main_quest_lv93._090_sayTitle = "A Bels\245 f\233ny I "
gameforge.main_quest_lv93._100_say = "Gy\245zd le Polyphemos-t, a K\252klopszok kir\225ly\225t, \233s[ENTER]vedd el Bels\245 f\233ny\233t. "
gameforge.main_quest_lv93._110_say = "\220res k\233zzel t\233rt\233l vissza? \205gy nem tudok seg\237teni.Hozd el nekem a Bels\245 f\233nyt! "
gameforge.main_quest_lv93._120_1_notice = "Megtal\225ltad a Bels\245 f\233nyt. Vidd el[ENTER]Yon-I-Walker-nek. "
gameforge.main_quest_lv93._130_say = "Besz\233lj Yon-I-Walker-rel. "
gameforge.main_quest_lv93._140_say = "Teh\225t ez a Bels\245 f\233ny... miel\245tt elkezdek vele[ENTER]dolgozni, meg kell tiszt\237tani. Ez n\233mi id\245t vesz[ENTER]ig\233nybe. Tudatni fogom veled, ha elk\233sz\252lt. "
gameforge.main_quest_lv93._150_sendLetter = "Er\245gy\251jt\233s II "
gameforge.main_quest_lv93._160_say = "Yon-I-Walker keres. "
gameforge.main_quest_lv93._170_say = "Most m\225r tiszta Polyphemos Bels\245 f\233nye. Most arra[ENTER]van sz\252ks\233g\252nk, ami az \243ri\225sokhoz tartozik. Hogy[ENTER]megszerezd, le kell gy\245zn\246d Wubba kir\225lyt. "
gameforge.main_quest_lv93._180_say = "M\225ris indulok. "
gameforge.main_quest_lv93._190_sayTitle = "A Bels\245 f\233ny II "
gameforge.main_quest_lv93._200_say = "Gy\245zd le az \243ri\225sok kir\225ly\225t, Wubba kir\225lyt, \233s[ENTER]vedd el t\245le Bels\245 f\233ny\233t. "
gameforge.main_quest_lv93._210_say = "\220res k\233zzel j\246tt\233l vissza? Meglepne, ha nem[ENTER]\225lln\225l k\233szen a feladatra. Menj, \233s pr\243b\225ld \250jra! "
gameforge.main_quest_lv93._220_1_notice = "Kezeidben tartod az \243ri\225sok Bels\245 f\233ny\233t. "
gameforge.main_quest_lv93._220_2_notice = "Add \225t Yon-I-Walker-nek. "
gameforge.main_quest_lv93._230_say = "Besz\233lj Yon-I-Walker-rel. "
gameforge.main_quest_lv93._240_say = "Wubba kir\225ly Bels\245 f\233nye, azt hiszem, a m\233rete[ENTER]miatt, hatalmas er\245vel rendelkezik. Most meg kell[ENTER]tiszt\237tanom. Ez eltart egy ideig. "
gameforge.main_quest_lv93._250_sendLetter = "Er\245gy\251jt\233s III "
gameforge.main_quest_lv93._260_say = "Yon-I-Walker keres. "
gameforge.main_quest_lv93._270_say = "Itt vagy, kit\251n\245. Sz\252ks\233gem van a seg\237ts\233gedre.[ENTER]Ahhoz, hogy teljes m\233rt\233kben hat\233kony legyen a[ENTER]tonikom, m\233g egy tov\225bbi \246sszetev\245re is sz\252ks\233gem[ENTER]van: a Millennium-esszenci\225ra. "
gameforge.main_quest_lv93._280_say = "Millennium-esszenci\225ra? Sosem hallottam m\233g r\243la. "
gameforge.main_quest_lv93._290_say = "Ez egy igen hat\233kony elegy, mely k\252l\246nf\233le[ENTER]n\246v\233nyi kivonatokb\243l k\233sz\252l. Ismered Octaviot? A[ENTER]kontinensen \233l, \233s csak \245 k\233pes el\245\225ll\237tani a[ENTER]Millennium-esszenci\225t. Menj el hozz\225. Rem\233lem,[ENTER]seg\237teni fog. Egy kiss\233 makacs tud lenni... "
gameforge.main_quest_lv93._300_say = "\201rtettem. "
gameforge.main_quest_lv93._310_sayTitle = "Besz\233lj Octavioval! "
gameforge.main_quest_lv93._320_say = "Keresd meg Octaviot. A kontinensen \233l, \233s \245 az[ENTER]egyetlen, aki tud Millennium-esszenci\225t f\245zni. "
gameforge.main_quest_lv93._330_say = "Hel\243! Mit adhatok? Tal\225n egy Samgyetangot?[ENTER]Ez a h\225zunk specialit\225sa egy kis... "
gameforge.main_quest_lv93._340_say = "Octavio, \233n nem a j\243 \233tel miatt vagyok itt! Most[ENTER]ink\225bb valami m\225sra van sz\252ks\233gem: a[ENTER]Millennium-esszenci\225ra! "
gameforge.main_quest_lv93._350_say = "Woah, psszt, ne olyan hangosan! A[ENTER]Millennium-esszencia...Nem, az nem lehet. Honnan[ENTER]tudsz r\243la? Csak n\233h\225nyan k\233pesek kezelni a t\245le[ENTER]kapott er\245t. \201n nem akarom v\225llalni a kock\225zatot.[ENTER]Most menj, miel\245tt m\233g valaki meghallana. "
gameforge.main_quest_lv93._360_say = "Octvio, v\225rj \233s figyelj! Yon-I-Walker k\252ld\246tt, a[ENTER]S\246t\233t S\225rk\225ny szikl\225r\243l. S\252rg\245sen sz\252ks\233g\252nk van[ENTER]erre az esszenci\225ra. En\233lk\252l nincs es\233ly\252nk a[ENTER]S\246t\233ts\233g szolg\225i ellen, \233s akkor a vil\225gunk, te[ENTER]is tudod, hal\225lra van \237t\233lve. Csak te tudod[ENTER]el\245\225ll\237tani az esszenci\225t. K\233rlek! "
gameforge.main_quest_lv93._370_say = "Yon-I-Walkert mondt\225l? Hmm, \245 r\233gi bar\225tom.[ENTER]Sokszor besz\233lgett\252nk j\243\237z\251en m\233g jobb \237z\251 borok[ENTER]mellett. \193t kell gondolnom. Gyere vissza holnap[ENTER]reggel \233s megkapod a v\225laszom. "
gameforge.main_quest_lv93._380_say = {}
gameforge.main_quest_lv93._390_say = "M\233g nem d\246nt\246ttem. Gyere vissza k\233s\245bb. "
gameforge.main_quest_lv93._400_npcChat = "A Millennium-esszencia "
gameforge.main_quest_lv93._410_say = "Octavio besz\233lni akar veled. "
gameforge.main_quest_lv93._420_say = "Nos, eg\233sz \233jjel gondolkodtam a k\233r\233seden. Nagy[ENTER]rizik\243t v\225llalok ezzel, de biztos vagyok benne,[ENTER]hogy helyesen cselekszem. Igen, seg\237teni fogok[ENTER]neked. "
gameforge.main_quest_lv93._430_say = "Nagyszer\251! "
gameforge.main_quest_lv93._440_say = "Ugyanakkor pillanatnyilag ez nincs k\233szleten[ENTER]n\225lam. Be tudn\225l szerezni hozz\225 n\233h\225ny[ENTER]\246sszetev\245t?[ENTER]Akkor el tudn\225m k\233sz\237teni neked az esszenci\225t. "
gameforge.main_quest_lv93._450_say = "Persze! Mire van sz\252ks\233ged? "
gameforge.main_quest_lv93._460_say = "Kifogytam a Gango-gy\246k\233rb\245l, a Tue gomb\225b\243l \233s az[ENTER]Alpesi r\243zs\225b\243l. Mindegyik \246sszetev\245b\245l 200-ra[ENTER]van sz\252ks\233gem. "
gameforge.main_quest_lv93._470_say = "Azonnal indulok. Hol tal\225lom \245ket? "
gameforge.main_quest_lv93._480_say = "Ezeket a n\246v\233nyeket a kontinens legk\252l\246nb\246z\245bb[ENTER]helyein tal\225lod.[ENTER]Am\237g keresed \245ket, \233n elkezdem az el\245k\233sz\252leteket. "
gameforge.main_quest_lv93._490_sayTitle = "A Millennium-recept "
gameforge.main_quest_lv93._500_say = "Keress Gango-gy\246keret, Tue gomb\225t \233s Alpesi[ENTER]r\243zs\225t.[ENTER]Mindegyikb\245l 200 darab kell. "
gameforge.main_quest_lv93._510 = "Ezeket a n\246v\233nyeket a kontinens legk\252l\246nb\246z\245bb[ENTER]helyein tal\225lod.[ENTER]Am\237g keresed \245ket, \233n elkezdem az el\245k\233sz\252leteket. "
gameforge.main_quest_lv93._520_say = "Ah, visszat\233rt\233l, nagyszer\251! \201s minden n\225lad van![ENTER]Akkor azonnal hozz\225 is l\225tok a munk\225hoz. Senki[ENTER]sem zavarhat meg ez id\245 alatt. Gyere vissza[ENTER]holnap ugyanebben az id\245ben. Addigra el kell[ENTER]k\233sz\252lnie az esszenci\225nak. "
gameforge.main_quest_lv93._530_say = "\201rtettem. Viszl\225t holnap. "
gameforge.main_quest_lv93._540_say = "\201n \233rtem, hogy s\252rg\245sen sz\252ks\233ged van r\225, de m\233g[ENTER]egy kicsit v\225rnod kell. Gyere vissza k\233s\245bb. "
gameforge.main_quest_lv93._550_say = "Octavio keres t\233ged. "
gameforge.main_quest_lv93._560_say = "Ah, \233ppen id\245ben j\246tt\233l: pont most lett[ENTER]haszn\225latra k\233sz a Millennium-esszencia! Most m\225r[ENTER]elviheted Yon-I-Walker-nek. "
gameforge.main_quest_lv93._570_say = "K\246sz\246n\246m! "
gameforge.main_quest_lv93._580_sendLetter = "Millennium-esszencia "
gameforge.main_quest_lv93._590_say = "Yon-I-Walker keres. "
gameforge.main_quest_lv93._600_say = "N\225lad a Millennium-esszencia![ENTER]Most m\225r megvan minden \246sszetev\245 az italomhoz.[ENTER]H\237vatni foglak, amint elk\233sz\252lt. "
gameforge.main_quest_lv93._610_say = "Minden rendben. "
gameforge.main_quest_lv93._620_say = "A kaland folytat\243dik, amint el\233rted a 94-es[ENTER]szintet. "
gameforge.main_quest_lv93._630_say = "%s: %d darab, %s: %d darab,[ENTER]%s: %d darab "
gameforge.main_quest_lv93._640_say = "Egy vend\233gh\225zat \252zemeltetek - nem \233rek r\225[ENTER]mindenre. Hozz el minden hi\225nyz\243 \246sszetev\245t, \233s[ENTER]k\233rlek, siess. "
gameforge.main_quest_lv93._650_1_notice = "Megtal\225ltad az \246sszes sz\252ks\233ges \246sszetev\245t a[ENTER]Millennium-esszenci\225hoz. "
gameforge.main_quest_lv93._650_2_notice = "T\233rj vissza Octaviohoz. "
gameforge.main_quest_lv94 = {}
gameforge.main_quest_lv94._010_sendLetter = "Leviat\225n gy\246ngy\246k "
gameforge.main_quest_lv94._020_say = "Yon-I-Walker keres. "
gameforge.main_quest_lv94._030_say = "Megcsin\225ltam. Siker\252lt egym\225ssal kombin\225lnom az[ENTER]\225ltalunk ismert leghat\233konyabb esszenci\225kat.[ENTER]Bemutatom: \237me, a Leviat\225n gy\246ngy\246k! "
gameforge.main_quest_lv94._040_say = "K\246sz\246n\246m! "
gameforge.main_quest_lv94._050_say = "Ha beveszed ezeket a kapszul\225kat, lehet, nem[ENTER]\233rzel semmilyen v\225ltoz\225st. De az olyan tapasztalt[ENTER]szem, mint az eny\233m vagy Angmur-\233, meg tudja[ENTER]mondani.[ENTER]Angmur besz\233lni akar veled. Indulj hozz\225 most. "
gameforge.main_quest_lv94._060_sayTitle = "Er\245s\237tsd meg magad! "
gameforge.main_quest_lv94._070_say = "Nyeld le a Leviat\225n gy\246ngy\246ket \233s keresd meg[ENTER]Angmur Admir\225list. "
gameforge.main_quest_lv94._080_sendLetter = "A Mennyd\246rg\233s-hegys\233g h\237v\225sa "
gameforge.main_quest_lv94._090_say = "Angmur Admir\225lisnak h\237rei vannak sz\225modra. "
gameforge.main_quest_lv94._1000_say = "Sz\252ks\233gem lesz egy kis id\245re, hogy analiz\225ljam a[ENTER]mint\225kat. Gyere vissza holnap, rem\233lhet\245leg akkor[ENTER]m\225r meglesznek az eredm\233nyek. "
gameforge.main_quest_lv94._100_say = "Ah, a Leviat\225n gy\246ngy\246k kifejtik hat\225sukat:[ENTER]tiszt\225n l\225tok k\246r\252l\246tted egy er\245-aur\225t.[ENTER]Felder\237t\245imnek van egy \246tlete, hol lehet a[ENTER]S\246t\233ts\233g szolg\225inak k\246zpontja. A ter\252let igen j\243l[ENTER]\245rz\246tt. Vetn\233l r\225 egy pillant\225st? "
gameforge.main_quest_lv94._1010_say = "Jelenteni fogom Angmur-nak, amit tal\225lok. \213 majd[ENTER]felveszi veled a kapcsolatot. "
gameforge.main_quest_lv94._1020_say = "Angmur Admir\225lisnak inform\225ci\243ja van a Fekete[ENTER]aranyr\243l. Menj el hozz\225. "
gameforge.main_quest_lv94._1030_say = "\211h, h\225t itt vagy. M\233g nem k\233sz\252lt el a Fekete[ENTER]arany elemz\233se. Rem\233lem, hamarosan t\246bbet tudok[ENTER]neked mondani. Tess\233k, fogadd ezt er\245fesz\237t\233seid[ENTER]jutalm\225ul. "
gameforge.main_quest_lv94._1040_say = "Nem vesztegethet\252nk t\246bb id\245t. Gyorsan, hozz[ENTER]mint\225kat a Fekete aranyb\243l! "
gameforge.main_quest_lv94._1050_say = "A kaland folytat\243dik, amint el\233rted a 95-\246s[ENTER]szintet. "
gameforge.main_quest_lv94._1060_say = "(Fennmarad: %s %s, %s %s) "
gameforge.main_quest_lv94._1070_say = {}
gameforge.main_quest_lv94._1080_say = "Hi\225nyz\243 mennyis\233g: "
gameforge.main_quest_lv94._1090_say = {}
gameforge.main_quest_lv94._110_say = "Term\233szetesen. "
gameforge.main_quest_lv94._120_say = "K\246sz\246n\246m. Gyere, megmutatom, melyik ter\252leteket[ENTER]kell felder\237tened. Jelentsd nekem, ha elk\233sz\252lt\233l[ENTER]vele. "
gameforge.main_quest_lv94._130_say = {}
gameforge.main_quest_lv94._140_say = "Angmur Admir\225lis utas\237t\225s\225ra der\237tsd fel a[ENTER]Mennyd\246rg\233s-hegys\233get. Els\245 c\233lpontod: (%d, %d) "
gameforge.main_quest_lv94._150_sayTitle = "A Mennyd\246rg\233s-hegys\233g "
gameforge.main_quest_lv94._160_say = "Der\237tsd fel a Mennyd\246rg\233s-hegys\233get \233s jelezz[ENTER]vissza Angmur Admir\225lisnak. "
gameforge.main_quest_lv94._170_say = "M\233g nem der\237tetted fel a teljes ter\252letet, ugye?[ENTER]Ett\245l az inform\225ci\243t\243l f\252gg\252nk. K\233rlek,[ENTER]teljes\237tsd az utas\237t\225saimat. "
gameforge.main_quest_lv94._180_say = "Els\245 c\233lpontod: %d, %d "
gameforge.main_quest_lv94._190_say = "M\225sodik c\233lpontod: %d, %d "
gameforge.main_quest_lv94._200 = {}
gameforge.main_quest_lv94._210_say = "Harmadik c\233lpontod: %d, %d "
gameforge.main_quest_lv94._220_say = "El\233rted az els\245 c\233lpontot. A k\246vetkez\245 helysz\237n:[ENTER](%d, %d) "
gameforge.main_quest_lv94._230_say = "El\233rted a m\225sodik c\233lpontot. A k\246vetkez\245[ENTER]helysz\237n: (%d, %d) "
gameforge.main_quest_lv94._240 = "El\233rted a harmadik c\233lpontot. "
gameforge.main_quest_lv94._250_say = "K\233pet tudt\225l alkotni a Mennyd\246rg\233s-hegys\233gben[ENTER]l\233v\245 helyzetr\245l.[ENTER]Most menj, \233s jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv94._260_say = "T\233rj vissza Angmur Admir\225lishoz. "
gameforge.main_quest_lv94._270_say = "Ah, h\225t visszaj\246tt\233l! Nagyon j\243, kifogjuk[ENTER]\233rt\233kelni az \225ltalad gy\251jt\246tt inform\225ci\243t, \233s[ENTER]kidolgozunk egy strat\233gi\225t. "
gameforge.main_quest_lv94._280_say = "Itt a jutalmad. "
gameforge.main_quest_lv94._290_sendLetter = "A V\246r\246s tolvajok meggyeng\237t\233se "
gameforge.main_quest_lv94._300_say = "Angmur Admir\225lis keres t\233ged. "
gameforge.main_quest_lv94._310_say = "A jelenlegi id\245szakban t\250l kock\225zatosnak t\251nik[ENTER]sz\225momra egy k\246zvetlen t\225mad\225s. Miel\245tt[ENTER]t\225madn\225nk, le kellene gyeng\237ten\252nk az ellens\233g[ENTER]csapatait. "
gameforge.main_quest_lv94._320_say = "A k\246vetkez\245 csoportok \233lnek a[ENTER]Mennyd\246rg\233s-hegys\233gben: az \211ri\225sok, a K\252klopszok[ENTER]\233s a V\246r\246s tolvajok.[ENTER]El\245sz\246r a V\246r\246s tolvajokat t\225madjuk meg! "
gameforge.main_quest_lv94._330_say = "Mi a V\246r\246s tolvajok gyeng\233je? "
gameforge.main_quest_lv94._340_say = "A V\246r\246s f\245n\246k mindig egy k\252l\246nleges k\246penyt[ENTER]visel, a hatalom \233s legy\245zhetetlens\233g[ENTER]szimb\243lum\225t.[ENTER]Szabad\237tsd meg ett\245l a k\246penyt\245l - ez sz\233tz\250zza[ENTER]majd a V\246r\246s tolvaj banda motiv\225ci\243j\225t! "
gameforge.main_quest_lv94._350_say = "A V\246r\246s f\245n\246k\246t? Nem lesz egy egyszer\251 feladat... "
gameforge.main_quest_lv94._360_say = "Igazad van. De ha van valaki, aki meg tud[ENTER]m\233rk\245zni vele, az te vagy. Sok szerencs\233t! "
gameforge.main_quest_lv94._370_sayTitle = "A V\246r\246s f\245n\246k "
gameforge.main_quest_lv94._380_say = "Gy\245zd le a V\246r\246s f\245n\246k\246t \233s szabad\237tsd meg a[ENTER]k\246peny\233t\245l. "
gameforge.main_quest_lv94._390_say = "... elbukt\225l? Nem, \233n nem hiszem el. Menj \233s[ENTER]k\252zdj meg vele \250jra. Biztos vagyok benne, hogy[ENTER]ez\250ttal legy\245z\246d. "
gameforge.main_quest_lv94._400_1_notice = "Legy\245zted a V\246r\246s f\245n\246k\246t. "
gameforge.main_quest_lv94._400_2_notice = "Vedd el a k\246peny\233t \233s vidd el Angmur Admir\225lisnak. "
gameforge.main_quest_lv94._410_say = "Angmur Admir\225lis v\225r r\225d. "
gameforge.main_quest_lv94._420_say = "A k\246peny! Tudtam, hogy meg tudod csin\225lni. Ki[ENTER]fogjuk akasztani a t\225boruk k\246zel\233ben, hogy j\243l[ENTER]l\225thass\225k \150 ez majd elb\225tortalan\237tja a V\246r\246s[ENTER]tolvaj band\225t.[ENTER]Az embereim majd gondoskodnak r\243la, \237gy[ENTER]pihenhetsz. "
gameforge.main_quest_lv94._430_sendLetter = "A K\252klopszok meggyeng\237t\233se "
gameforge.main_quest_lv94._440_say = "Angmur Admir\225lis besz\233lni akar veled. "
gameforge.main_quest_lv94._450_say = "Bev\225lt a terv\252nk: a k\246peny l\225tt\225n hatalmas[ENTER]z\251rzavar t\246rt ki a V\246r\246s tolvajok k\246z\246tt. V\233g\252l a[ENTER]d\233monok \233s az emberek egym\225s tork\225nak estek,[ENTER]\250gyhogy ez a banda most teljesen rendezetlen.[ENTER]A k\246vetkez\245 l\233p\233s a K\252klopszok. "
gameforge.main_quest_lv94._460_say = "Hogyan kivitelezz\252k? "
gameforge.main_quest_lv94._470_say = "A K\252klopszok im\225dj\225k vez\233r\252ket. Ha megsemmis\237tj\252k[ENTER]a vez\233rkarukat, a K\252klopszok p\225nikba esnek \233s[ENTER]sz\233tsz\243r\243dnak. Gy\245zd le Outis t\225bornokot %d,[ENTER]Arges-t %d \233s Polyphemos-t %d alkalommal. "
gameforge.main_quest_lv94._480_say = "\214r\246mmel megteszem. "
gameforge.main_quest_lv94._490_say = "L\233gy \243vatos! "
gameforge.main_quest_lv94._500_sayTitle = "K\252zdj meg a K\252klopszokkal! "
gameforge.main_quest_lv94._510_say = "Gy\245zd le Outis t\225bornokot %d, Arges-t %d \233s[ENTER]Polyphemos-t %d alkalommal. "
gameforge.main_quest_lv94._520 = "Neh\233z elhinnem, hogy minden K\252klopsz jobb n\225lad.[ENTER]Menj, tudom, hogy meg tudod csin\225lni! "
gameforge.main_quest_lv94._530_1_notice = "Legy\245zted a K\252klopszok vezet\245it. "
gameforge.main_quest_lv94._530_2_notice = "Jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv94._540_say = "Menj Angmur Admir\225lishoz. "
gameforge.main_quest_lv94._550_say = "Tetteid h\237re megel\245z\246tt t\233ged! A K\252klopszok[ENTER]menek\252lnek.[ENTER]M\225r csak az \211ri\225sok maradtak. Inform\225ci\243t fogok[ENTER]gy\251jteni a gyeng\233j\252kr\245l \233s h\237vatlak. "
gameforge.main_quest_lv94._560_sendLetter = "Az \211ri\225sok meggyeng\237t\233se "
gameforge.main_quest_lv94._570_say = "Angmur Admir\225lis h\237vat t\233ged. "
gameforge.main_quest_lv94._580_say = "Felder\237t\245im felfedt\233k az \211ri\225sok gyenge pontj\225t. "
gameforge.main_quest_lv94._590_say = "Mondd! "
gameforge.main_quest_lv94._600_say = "Az \211ri\225soknak van egy nagy spiritu\225lis \233rt\233kkel[ENTER]b\237r\243 totem\252k. Ha ezt elvessz\252k t\245l\252k, k\233pesek[ENTER]lesz\252nk megt\246rni az akaratukat. "
gameforge.main_quest_lv94._610_say = "Hol tal\225lom ezt a totemet? "
gameforge.main_quest_lv94._620_say = "A totem hatalmas borosty\225ndarab alak\250. Hogy[ENTER]megv\233dj\233k a tolvajokt\243l, %d darabra t\246rt\233k. Wubba[ENTER]kir\225ly \233s hivatalnokai \245rzik ezeket a darabokat. "
gameforge.main_quest_lv94._630_say = "Meg\233rtettem. "
gameforge.main_quest_lv94._640_sayTitle = "Az \211ri\225sok toteme "
gameforge.main_quest_lv94._650_say = "Szerezd meg az \246sszes totemdarabot. "
gameforge.main_quest_lv94._660_say = "Az \211ri\225sok igencsak er\245teljes ellenfelek. De te[ENTER]le tudod gy\245zni \245ket, \233s el tudod hozni nekem a[ENTER]totemet! "
gameforge.main_quest_lv94._670_say_1_notice = "\214sszegy\251jt\246tted valamennyi totemdarabot. "
gameforge.main_quest_lv94._670_say_2_notice = "T\233rj vissza Angmur Admir\225lishoz. "
gameforge.main_quest_lv94._680_say = "\211h, m\225r kezdtem agg\243dni! T\233nyleg megcsin\225ltad.[ENTER]Most m\225r n\225lunk van az \211ri\225sok szent toteme.[ENTER]Nagyszer\251 jutalmat kapsz ez\233rt. "
gameforge.main_quest_lv94._690_sendLetter = "A Mennyd\246rg\233s-hegys\233gbe "
gameforge.main_quest_lv94._700_say = "Angmur Admir\225lis keres t\233ged. "
gameforge.main_quest_lv94._710_say = "Felder\237t\245im megfigyelt\233k a K\252klopszokat, amint[ENTER]valamit gy\251jt\246ttek a Mennyd\246rg\233s-hegys\233gben, majd[ENTER]elsz\225ll\237tott\225k azt. "
gameforge.main_quest_lv94._720_say = "Tudd meg, mire k\233sz\252lnek a K\252klopszok. Ez[ENTER]biztosan nem lehet semmi j\243... Azt is k\233tlem,[ENTER]hogy k\246nnyen kiadn\225k a titkukat. "
gameforge.main_quest_lv94._730_say = "Meg\233rtettem. "
gameforge.main_quest_lv94._740_sayTitle = "Mi a K\252klopszok terve? "
gameforge.main_quest_lv94._750_say = "Tudd meg, mit gy\251jtenek a K\252klopszok a[ENTER]Mennyd\246rg\233s-hegys\233gben. "
gameforge.main_quest_lv94._760_say = "Tudd meg, mire k\233sz\252lnek a K\252klopszok. Ez[ENTER]biztosan nem lehet semmi j\243... Azt is k\233tlem,[ENTER]hogy k\246nnyen kiadn\225k a titkukat. "
gameforge.main_quest_lv94._770_1_notice = "Egy ragyog\243 fekete k\246vet \233s egy C\233dul\225t tartasz a[ENTER]kezedben. "
gameforge.main_quest_lv94._770_2_notice = "Mutasd meg Angmur Admir\225lisnak, mit tal\225lt\225l. "
gameforge.main_quest_lv94._780_say = "Menj Angmur Admir\225lishoz. "
gameforge.main_quest_lv94._790_say = "Megtudtad, mit csin\225lnak a K\252klopszok a[ENTER]Mennyd\246rg\233s-hegys\233gben? "
gameforge.main_quest_lv94._800_say = "A K\252klopszok nem akartak sz\243ba \225llni velem, de[ENTER]v\233g\252l meg tudtam gy\245zni \245ket, hogy adj\225k \225t[ENTER]ezeket: egy fekete k\246vet \233s ezt a kis[ENTER]pap\237rdarabot. "
gameforge.main_quest_lv94._810_say = "Megtal\225ltuk a Fekete arany-ereket a[ENTER]Mennyd\246rg\233s-hegys\233gben, \233s most k\233r\233sednek[ENTER]megfelel\245en azt b\225ny\225sszuk. Az \225tad\225shoz a tervek[ENTER]szerint a Mennyd\246rg\233s-hegys\233gben tal\225lkozunk. "
gameforge.main_quest_lv94._820_say = "Fekete arany... Ez az \233rc csak a[ENTER]Mennyd\246rg\233s-hegys\233gben tal\225lhat\243. Mi\233rt van r\225[ENTER]sz\252ks\233g\252k a S\246t\233ts\233g szolg\225inak? "
gameforge.main_quest_lv94._830_say = "Meg kell tudnunk, mit terveznek. "
gameforge.main_quest_lv94._840_say = "Itt van: "
gameforge.main_quest_lv94._850_sendLetter = "Fekete arany "
gameforge.main_quest_lv94._860_say = "Angmur Admir\225lis a Fekete aranyr\243l szeretne veled[ENTER]besz\233lni. "
gameforge.main_quest_lv94._870_say = "Az Alkimista nem tudta kielemezni a Fekete[ENTER]aranyat, t\250l kicsi volt a minta. Meg kell tudnunk[ENTER]a jellemz\245it, \233s azt is, hogy a S\246t\233ts\233g szolg\225i[ENTER]mi\233rt keresik! Vissza tudn\225l t\233rni a[ENTER]Mennyd\246rg\233s-hegys\233gbe, hogy tov\225bbi mint\225kat[ENTER]biztos\237ts a Fekete aranyb\243l? "
gameforge.main_quest_lv94._880_say = "El\245bb menj az Alkimist\225hoz. Meg fogja mondani,[ENTER]h\225ny mint\225ra van sz\252ks\233ge. "
gameforge.main_quest_lv94._890_say = "Besz\233lj az Alkimist\225val. "
gameforge.main_quest_lv94._900_say = "\220dv\246z\246llek. Felvil\225gos\237tott m\225r Angmur Admir\225lis[ENTER]a feladatodr\243l? "
gameforge.main_quest_lv94._910_say = "Igen. H\225ny mintadarabra van sz\252ks\233ged a Fekete[ENTER]aranyb\243l? "
gameforge.main_quest_lv94._920_say = "Hmm, hadd gondolkodjam egy pillanatot. Azt[ENTER]hiszem, %d mint\225nak elegend\245nek kell lennie az[ENTER]elemz\233shez. "
gameforge.main_quest_lv94._930_say = "Meg\233rtettem. "
gameforge.main_quest_lv94._940_sayTitle = "A Mennyd\246rg\233s-hegys\233g aranya "
gameforge.main_quest_lv94._950_sayTitle = "Menj az Alkimist\225hoz. "
gameforge.main_quest_lv94._960_say = "Keress Fekete arany-mint\225kat a[ENTER]Mennyd\246rg\233s-hegys\233gben "
gameforge.main_quest_lv94._970_1_notice = "Felfedezt\233l egy Fekete arany-eret \233s szerezt\233l[ENTER]magadnak egy \233rc-mint\225t. "
gameforge.main_quest_lv94._970_2_notice = "Vidd el az Alkimist\225nak. "
gameforge.main_quest_lv94._980_say = "Ah, Fekete aranyat tal\225lt\225l. Mutasd! Hmm, nem[ENTER]k\246nnyezik \233s el\233g nagy darab is... igen, tudom[ENTER]haszn\225lni az elemz\233semhez. Tov\225bbi %d darabra van[ENTER]m\225r csak sz\252ks\233gem. "
gameforge.main_quest_lv94._990_say = "Nem tudok mit kezdeni ezzel a mint\225val. T\250l[ENTER]k\246nny\251 az elemz\233shez. Hozz egy m\225sikat! "
gameforge.main_quest_lv95 = {}
gameforge.main_quest_lv95._010_sendLetter = "Aranyl\225z "
gameforge.main_quest_lv95._020_say = "Angmur Admir\225lis keres t\233ged. \218j inform\225ci\243ja van[ENTER]a Fekete aranyr\243l. "
gameforge.main_quest_lv95._030_say = "A Fekete arany energi\225t von el a k\246rnyezet\233ben[ENTER]l\233v\245 l\233nyekb\245l \233s \225tadja azt egy m\225sik testnek. A[ENTER]S\246t\233ts\233g szolg\225i Sung Mahi-ba akarj\225k \225t\252ltetni[ENTER]ezt a lopott er\245t! Az \243ri\225s Kamp\243s kapit\225ny[ENTER]hord\225inak jelent\245s k\233szlete van Fekete aranyb\243l a[ENTER]Mennyd\246rg\233s-hegys\233gben. Szerezd meg! "
gameforge.main_quest_lv95._040_say = "El van int\233zve! "
gameforge.main_quest_lv95._050_say = {}
gameforge.main_quest_lv95._060_say = {}
gameforge.main_quest_lv95._070_sayTitle = "A horgon: Kamp\243s kapit\225ny "
gameforge.main_quest_lv95._080_say = "Gy\245zd le az \211ri\225sok Kamp\243s kapit\225ny\225t \233s szerezd[ENTER]meg a Fekete aranyat! "
gameforge.main_quest_lv95._090_say = "Nincs vesztegetni val\243 id\245nk. Gy\245zd le Kamp\243s[ENTER]kapit\225nyt \233s szerezd meg a Fekete aranyat! "
gameforge.main_quest_lv95._100_1_notice = "Nyoma sem volt Fekete aranynak. Ellenben Kamp\243s[ENTER]kapit\225ny egy levelet tartott mag\225n\225l. "
gameforge.main_quest_lv95._100_2_notice = {}
gameforge.main_quest_lv95._110_say = "Jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv95._120_say = "\211h, teh\225t a f\246ldre tudtad teperni Kamp\243s[ENTER]kapit\225nyt. Mi az ott? Egy lev\233l? Mutasd! "
gameforge.main_quest_lv95._130_say = {}
gameforge.main_quest_lv95._140_say = "\193tok re\225. Kamp\243s kapit\225ny m\225r tov\225bbadta a Fekete[ENTER]aranyat a Banshee-nak.[ENTER]Az utols\243 mondat olyan, mint egy rejtv\233ny: Az[ENTER]\233let \225tka meg lesz id\233zve az id\245 k\246d\233b\245l a[ENTER]s\246t\233ts\233g serege \225ltal. "
gameforge.main_quest_lv95._150_say = "Meg kell \225ll\237tanunk a sz\225ll\237tm\225nyt! \218gy sejtj\252k,[ENTER]a Banshee rejtekhelye nyugaton van, a[ENTER]Gautama-szikl\225n \150 istentelen helyen, \225lland\243,[ENTER]s\251r\251 k\246dbe burkolva. Ogr\233k \233s Lemurok \233lnek[ENTER]arrafel\233. "
gameforge.main_quest_lv95._160_say = {}
gameforge.main_quest_lv95._170_say = "Amint megtudom, melyik utat haszn\225lj\225k a Fekete[ENTER]arany Banshee-hoz t\246rt\233n\245 sz\225ll\237t\225s\225ra, sz\243lok[ENTER]neked. "
gameforge.main_quest_lv95._180_sendLetter = "A sz\225ll\237tm\225ny feltart\243ztat\225sa "
gameforge.main_quest_lv95._190_say = "Menj Angmur Admir\225lishoz. Inform\225ci\243i vannak a[ENTER]Fekete arany-sz\225ll\237tm\225nnyal kapcsolatban. "
gameforge.main_quest_lv95._200_say = "K\233meim kider\237tett\233k, hogy az Ogr\233k parancsnoka,[ENTER]Shruk kapit\225ny sz\225ll\237tja a Fekete aranyat a[ENTER]Gautama-szikl\225ra. Az \246v\233re csatolt csomagban[ENTER]sz\225ll\237tja. Vedd el t\245le! "
gameforge.main_quest_lv95._210_say = {}
gameforge.main_quest_lv95._220_say = "\201rtettem. Azonnal indulok \233s elkezdem a[ENTER]vad\225szatot. "
gameforge.main_quest_lv95._230_sayTitle = "T\233r\237tsd el a sz\225ll\237tm\225nyt! "
gameforge.main_quest_lv95._240_say = "Keresd meg Shruk kapit\225nyt \233s szerezd meg a[ENTER]Fekete aranyat tartalmaz\243 csomagot, miel\245tt m\233g[ENTER]el\233rne a Banshee-hoz. "
gameforge.main_quest_lv95._250_say = "Shruk kapit\225ny nem pehelys\250ly\250, de te le tudod[ENTER]gy\245zni! Pr\243b\225ld \250jra! "
gameforge.main_quest_lv95._260_1_notice = "Megszerezted a csomagot. "
gameforge.main_quest_lv95._260_2_notice = "T\233rj vissza vele Angmur Admir\225lishoz. "
gameforge.main_quest_lv95._270_say = "Vidd el zs\225km\225nyod Angmur Admir\225lisnak. "
gameforge.main_quest_lv95._280_say = "Ebben a csomagban van a Fekete arany? Mutasd! Mi?!Csak egy jegyzet van itt... "
gameforge.main_quest_lv95._290_say = "A Fekete arany sz\225ll\237t\225s\225ra akkor ker\252l sor, ha[ENTER]m\225r teljesen fel van dolgozva. "
gameforge.main_quest_lv95._300_say = "\193tkozottak, a Fekete arany m\233g mindig rossz[ENTER]kezekben van. De legal\225bb most m\225r tudjuk, hogy[ENTER]fel kell dolgozni, miel\245tt a Banshee[ENTER]felhaszn\225lhatn\225 a c\233ljaira. "
gameforge.main_quest_lv95._310_say = "M\233g mindig nincs t\250l k\233s\245. Ki fogom tal\225lni,[ENTER]jelenleg kin\233l van a Fekete arany \233s hogy[ENTER]feldolgozt\225k-e m\225r. Amint tal\225lok valamit,[ENTER]h\237vatlak, Tess\233k, itt a jutalmad. Viszl\225t[ENTER]hamarosan! "
gameforge.main_quest_lv95._320_sendLetter = "\193ll\237tsd meg a feldolgoz\225st "
gameforge.main_quest_lv95._330_say = "Menj Angmur Admir\225lishoz, h\237rei vannak a Fekete[ENTER]aranyr\243l. "
gameforge.main_quest_lv95._340_say = "Kider\237tett\252k, hogy szem\233lyesen a Nagy Ogre[ENTER]fel\252gyeli a Fekete arany feldolgoz\225s\225t \233s \245 fogja[ENTER]\225tadni a Banshee-nak is. "
gameforge.main_quest_lv95._350_say = "Jelenleg a Gautama-szikl\225n \225llom\225sozik.[ENTER]Akad\225lyozd meg, hogy a Fekete arany c\233lba \233rjen.[ENTER]Gyorsan, miel\245tt m\233g t\250l k\233s\245 lesz! "
gameforge.main_quest_lv95._360_say = {}
