gameforge.main_quest_lv95._380_say = "Gy\245zd le az Ogr\233k vez\233r\233t \233s \225ll\237tsd meg a Fekete[ENTER]arany feldolgoz\225s\225t. "
gameforge.main_quest_lv95._390_say = "Minden perc sz\225m\237t! \193ll\237tsd meg a Nagy Ogr\233t! "
gameforge.main_quest_lv95._400_notice = "Legy\245zted a Nagy Ogr\233t. "
gameforge.main_quest_lv95._410_say = "Nem tudsz meg\225ll\237tani benn\252nket! A Banshee m\225r[ENTER]megkapta a Fekete aranyat. T\250l k\233s\245, ti ostob\225k! "
gameforge.main_quest_lv95._420_say = "Szorul a hurok. T\233rj vissza Angmur Admir\225lishoz[ENTER]\233s t\233gy neki jelent\233st. "
gameforge.main_quest_lv95._430_say = "Besz\233lj Angmur Admir\225lissal. "
gameforge.main_quest_lv95._440_say = "Ez gyors volt! N\225lad van a Fekete arany? "
gameforge.main_quest_lv95._450_say = "Nem, elk\233stem. A Banshee m\225r megkapta. "
gameforge.main_quest_lv95._460_say = "A S\225rk\225nyisten k\246ny\246r\252lj\246n rajtunk! De nem adjuk[ENTER]fel ilyen k\246nnyen! Kik\252ld\246m a felder\237t\245imet \233s[ENTER]megtal\225lj\225k a Banshee-t, b\225rmerre van is. Amint[ENTER]ezt megtudom, \233rtes\237telek. Addig is pihenj egy[ENTER]kicsit. Itt a jutalmad. "
gameforge.main_quest_lv95._470_sendLetter = "Az \201let \225tka "
gameforge.main_quest_lv95._480_say = "Angmur Admir\225lisnak \250j inform\225ci\243i vannak[ENTER]sz\225modra. Menj el hozz\225. "
gameforge.main_quest_lv95._490_say = "Most m\225r tudjuk, mit jelent az \201let \225tka \233s a[ENTER]S\246t\233ts\233g serege. \201lt egyszer egy rettenetes m\225gus[ENTER]a S\246t\233t S\225rk\225ny szikl\225n. A teljes kontinens[ENTER]feletti uralomra t\246rekedv\233n sz\243 szerint semmi sem[ENTER]\225llhatott \250tj\225ba: fekete m\225gia haszn\225lat\225val[ENTER]fel\233lesztette a holtakat \233s saj\225t hadseregek\233nt[ENTER]k\252ldte csat\225ba \245ket. "
gameforge.main_quest_lv95._500_say = {}
gameforge.main_quest_lv95._510_say = "Megid\233zni a halottat \150 m\233g a gondolat\225ra is kir\225z[ENTER]a hideg. A S\246t\233ts\233g szolg\225i a Fekete aranyat[ENTER]haszn\225lj\225k arra, hogy sereget \225ll\237tsanak fel[ENTER]\233l\245holtakb\243l. Meg kell \225ll\237tanunk \245ket! "
gameforge.main_quest_lv95._520_say = "Keresd fel a Lemur m\225gust a Gautama-szikla r\233gi[ENTER]romjain\225l. \213 tud valamit err\245l az \225tokr\243l. Ha[ENTER]sz\233pen k\233red, biztos vagyok benne, hogy elmond[ENTER]mindent, amit tudnunk kell. "
gameforge.main_quest_lv95._530_say = "Sz\233pen k\233rni... hmm. \201rtettem. "
gameforge.main_quest_lv95._540_sayTitle = "Az \201let \225tka "
gameforge.main_quest_lv95._550_say = "Gy\245zd le a Lemur m\225gust, valamint gy\251jts[ENTER]inform\225ci\243t az \201let \225tk\225r\243l \233s a halottak[ENTER]megid\233z\233s\233r\245l. "
gameforge.main_quest_lv95._560_say = "Nincs vesztegetni val\243 id\245nk. Gy\245zd le a Lemur[ENTER]m\225gust \233s pr\233seld ki bel\245le az \201let \225tk\225ra[ENTER]vonatkoz\243 inform\225ci\243t. "
gameforge.main_quest_lv95._570_1_notice = "Legy\245zted a Lemur m\225gust \233s tal\225lt\225l egy k\245t\225bl\225t[ENTER]egy felirattal. "
gameforge.main_quest_lv95._570_2_notice = "Mutasd meg Angmur Admir\225lisnak. "
gameforge.main_quest_lv95._580_say = "Jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv95._590_say = "Nah\225t, a Lemur m\225gus \245rizte ezt a k\245t\225bl\225t? Hadd[ENTER]vessek r\225 egy pillant\225st. "
gameforge.main_quest_lv95._600_sayReward = "H\225rom dolog sz\252ks\233ges a halott felt\225maszt\225s\225hoz:[ENTER]1. Egy emberi test[ENTER]2. ...[ENTER]Itt elt\246rt a Lemur-t\225bla. A felirat t\246bbi r\233sze[ENTER]hi\225nyzik. "
gameforge.main_quest_lv95._610_say = "Att\243l tartok, \250jra ki kell menned. Sz\252ks\233g\252nk van[ENTER]a felirat t\246bbi r\233sz\233re is.[ENTER]A Lemur-t\225bl\225nak m\233g tov\225bbi k\233t r\233sz\233nek kell[ENTER]lennie ott. "
gameforge.main_quest_lv95._620_say = "Itt a jutalmad minden\233rt, amit id\225ig el\233rt\233l.[ENTER]K\233rlek, most menj ki \250jra \233s kutasd fel a[ENTER]Lemur-t\225bla t\246bbi r\233sz\233t! "
