gameforge.main_quest_lv95._650_say = "Gy\245zd le a Lemur m\225gust \233s tal\225ld meg a k\245t\225bla[ENTER]t\246bbi r\233sz\233t. "
gameforge.main_quest_lv95._660_say = "K\233rlek, tudnunk kell, mit mond a felirat. Ne add[ENTER]fel! "
gameforge.main_quest_lv95._670_say = "Vidd el a Lemur-t\225bla k\233t t\246r\246tt darabj\225t Angmur[ENTER]Admir\225lisnak. "
gameforge.main_quest_lv95._680_say = "\211h, h\225t visszat\233rt\233l! Illessz\252k csak \246ssze a[ENTER]Lemur-t\225bla darabjait \233s olvassuk el a feliratot! "
gameforge.main_quest_lv95._690_sayReward = "H\225rom dolog sz\252ks\233ges a halott felt\225maszt\225s\225hoz:[ENTER]1. Egy emberi test[ENTER]2. Fekete arany[ENTER]3. D\233monfa-k\233reg[ENTER]Csak egy kiemelked\245 k\233pess\233gekkel rendelkez\245[ENTER]m\225gus tudja megid\233zni \233s fenntartani az \201let[ENTER]\225tk\225t. Amikor meghal, vele egy\252tt bukik el a[ENTER]teljes \233l\245holt sereg is. "
gameforge.main_quest_lv95._700_say = "Teh\225t ez az oka annak, hogy temet\245ink \252resek \233s a[ENTER]testeket kilopt\225k s\237rjukb\243l. Visszahozt\225k \245ket az[ENTER]\233letbe \233s \233l\245holt seregk\233nt ellen\252nk vez\233nyelt\233k.[ENTER]Micsoda beteges gondolat! "
gameforge.main_quest_lv95._710_say = "Meg kell \225ll\237tanunk ezt a felh\225bor\237t\243 tettet! "
gameforge.main_quest_lv95._720_say = "Igen, de az id\245 ellen\252nk dolgozik. Csak a Banshee[ENTER]el\233g er\245s ahhoz, hogy ilyen mennyis\233g\251 \225tkot[ENTER]id\233zzen meg \150 de nem tudjuk, hol rejt\245zik. M\233g[ENTER]t\246bb embert fogok kik\252ldeni, hogy megtal\225lj\225k a[ENTER]s\246t\233t f\245papn\245 hely\233t. Amint megtudok valamit,[ENTER]\233rtes\237telek. "
