gameforge.main_quest_lv96._240_say = "Jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv96._250_say = "Nagyon j\243! Megk\233rem majd Yon-I-Walker-t, hogy[ENTER]elemezze ezeket a t\225rgyakat. "
gameforge.main_quest_lv96._260_say = "Keresd meg Yon-I-Walker-t, hogy elmondhassa neked[ENTER]elemz\233se eredm\233ny\233t. "
gameforge.main_quest_lv96._270_say = "Ah, h\225t itt vagy! M\225r siker\252lt vetnem egy[ENTER]pillant\225st a t\225rgyakra, amiket az Ogr\233kn\225l[ENTER]tal\225lt\225l. "
gameforge.main_quest_lv96._280_say = {}
gameforge.main_quest_lv96._290_say = "Az arany\233rm\233k a csomagban er\245s s\246t\233t energi\225t[ENTER]sug\225roznak. Ezek a m\233diumok. K\233rlek, jelentsd[ENTER]Angmur Admir\225lisnak. "
gameforge.main_quest_lv96._300_sendLetter = "Az \225tok megakad\225lyoz\225sa "
gameforge.main_quest_lv96._310_say = "Menj Angmur Admir\225lishoz. "
gameforge.main_quest_lv96._320_say = "Tess\233k, itt az Aranyvad\225sz-nyakp\225nt. Haszn\225ld az[ENTER]Ogr\233k \201rmecsomagjainak \233szlel\233s\233hez. "
gameforge.main_quest_lv96._330_say = "100 Arany\233rm\233re van sz\252ks\233g\252nk, de att\243l tartok,[ENTER]nem minden \233rme haszn\225lhat\243 m\233diumk\233nt, amit[ENTER]tal\225lsz. Rengeteg munka v\225r m\233g r\225d. "
gameforge.main_quest_lv96._340_say = "Semmi probl\233ma. "
gameforge.main_quest_lv96._350_sayTitle = "Aranyvad\225szat "
gameforge.main_quest_lv96._360_say = "Kelj harcra az Ogr\233k ellen \233s gy\251jts[ENTER]\201rmecsomagokat. Nem minden \233rme m\233dium \150[ENTER]Yon-I-Walker-nek ellen\245riznie kell \245ket. "
gameforge.main_quest_lv96._370_say = "Igen, tiszt\225n \233rzem itt a fekete m\225gi\225t. "
gameforge.main_quest_lv96._380_say = "Fantasztikus, most m\225r megvan az \246sszes[ENTER]arany\233rme, ami m\233diumk\233nt haszn\225lhat\243. Ez eg\233szen[ENTER]biztosan nem fog tetszeni a Banshee-nak! Tess\233k,[ENTER]itt a jutalmad. Angmur keresni fog a k\246vetkez\245[ENTER]feladattal. "
gameforge.main_quest_lv96._390_say = "M\233g mindig hi\225nyzik n\233h\225ny arany\233rme. Gy\251jts m\233g[ENTER]ennyit: %d. "
gameforge.main_quest_lv96._400_sendLetter = "Az \225tok megakad\225lyoz\225sa "
gameforge.main_quest_lv96._410_say = "Angmur Admir\225lis keres t\233ged. "
gameforge.main_quest_lv96._420_say = "Meg kell akad\225lyoznunk, hogy a S\246t\233ts\233g szolg\225i[ENTER]megszerezz\233k a D\233monfa k\233rg\233t. "
gameforge.main_quest_lv96._430_say = "A D\233monf\225k a legtitokzatosabb l\233nyek ezen a[ENTER]vil\225gon, nem szolg\225lnak sem embert, sem Sung[ENTER]Mahi-t.[ENTER]H\225rom fajta \233l bel\245l\252k a Gautama-szikl\225n:[ENTER]Aku-Boku, Arboretum \233s Sycomore. H\225ntsd le a[ENTER]k\233rg\252ket! "
gameforge.main_quest_lv96._440_say = {}
gameforge.main_quest_lv96._450_say = "Meg\233rtettem. "
gameforge.main_quest_lv96._460_sayTitle = "D\233monfa-h\225nt\225s "
gameforge.main_quest_lv96._470_say = "H\225ntsd le a k\233rget egy Aku-Boku-r\243l, egy[ENTER]Arboretum-r\243l \233s egy Sycomore-r\243l. "
gameforge.main_quest_lv96._480_counterName = "(Fennmarad: %s %s, %s %s) "
gameforge.main_quest_lv96._490_say = {}
gameforge.main_quest_lv96._500_say = "Szor\237t az id\245. Z\250zd forg\225ccs\225 a D\233monf\225kat \233s[ENTER]szerezd meg k\233rg\252ket, miel\245tt a Szolg\225k[ENTER]megtehetn\233k! "
gameforge.main_quest_lv96._510_1_notice = "Legy\245zted valamennyi D\233monf\225t, de valaki m\225r j\225rt[ENTER]ott el\245tted: a k\233reg m\225r le volt h\225ntva a[ENTER]t\246rzs\252kr\245l. "
gameforge.main_quest_lv96._510_2_notice = "Jelentsd a h\237rt Angmur Admir\225lisnak. "
gameforge.main_quest_lv96._520_say = "Jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv96._530_say = "J\243 l\225tni, hogy s\233rtetlen\252l t\233rt\233l vissza![ENTER]Sikerrel j\225rt\225l? Micsoda?! M\225r le volt h\225ntva a[ENTER]D\233monf\225k k\233rge, \233s friss jelei voltak a csat\225nak?[ENTER]A S\246t\233ts\233g szolg\225i el\245tt\252nk j\225rhattak ott. "
gameforge.main_quest_lv96._540_say = {}
gameforge.main_quest_lv96._550_say = "Ha n\225luk van a k\233reg, tal\225lnak m\243dot arra is,[ENTER]hogy megid\233zz\233k az \201let \225tk\225t. \218gy l\225tszik, ez[ENTER]elker\252lhetetlen \150 h\225bor\250nak n\233z\252nk el\233be. A[ENTER]Banshee nem rejt\245zhet m\225r sok\225ig el\245l\252nk. Az[ENTER]embereim m\225r a nyom\225ban vannak. H\237vatlak, amint[ENTER]megtal\225lt\225k \245t. "
gameforge.main_quest_lv96._560_sayTitle = "A kaland folytat\243dik, amint el\233rted a 97-es[ENTER]szintet. "
gameforge.main_quest_lv96._570_counterName = "(Fennmarad: %s %s, %s %s) "
gameforge.main_quest_lv96._580_sayReward = "%s: %d darab "
gameforge.main_quest_lv96._590_say = "Teh\225t az arany\233rm\233k m\233diumk\233nt szolg\225lnak. J\243,[ENTER]akkor Yon-I-Walker tan\225cs\225t fogom k\233rni, mi[ENTER]legyen a k\246vetkez\245 l\233p\233s. Hamarosan \250jra[ENTER]kapcsolatba l\233pek veled. "
gameforge.main_quest_lv96._600_say = {}
gameforge.main_quest_lv96._610_say = {}
gameforge.main_quest_lv96._620_1_notice = "Kapt\225l egy \201rmecsomagot. "
gameforge.main_quest_lv96._620_2_notice = "Vidd el Yon-I-Walker-nek. "
gameforge.main_quest_lv96._630_say = "Ez egy norm\225l \233rme, nem m\233dium. Folytasd a[ENTER]keres\233st! "
gameforge.main_quest_lv97 = {}
gameforge.main_quest_lv97._010_sendLetter = "\193ll\237tsd meg a Banshee-t "
gameforge.main_quest_lv97._020_say = "Felfedezt\233k a Banshee rejtekhely\233t! Menj Angmur[ENTER]Admir\225lishoz, hogy t\246bbet megtudj. "
gameforge.main_quest_lv97._030_say = "Az embereim v\233gre megtal\225lt\225k a Banshee-t a[ENTER]Gautama-szikl\225n. Bevette mag\225t az ott l\233v\245 s\246t\233t[ENTER]erd\245 m\233ly\233re \233s onnan dolgozik fekete m\225gi\225j\225n.[ENTER]Emellett fel\233bresztette kor\225bbi S\225rk\225nykultusz[ENTER]Templomszolg\225inak egyik\233t is. Az \245 seg\237ts\233g\233vel[ENTER]akarja megid\233zni az \201let \225tk\225t. "
gameforge.main_quest_lv97._040_say = "Az \245 seg\237ts\233ge n\233lk\252l a Banshee nem k\233pes[ENTER]fenntartani az \225tkot. Gy\245zd le a Templomszolga[ENTER]Mu-Shu-t \233s nyugtasd meg bajt\225rsaink lelk\233t,[ENTER]miel\245tt felkeltett testeik ellen\252nk fordulnak. "
gameforge.main_quest_lv97._050_say = "Szinte lehetetlen \233szrev\233tlen\252l a Templomszolga[ENTER]k\246zel\233be f\233rk\245zni a t\225mad\225shoz. Haszn\225ld ki azt a[ENTER]pillanatot, amikor m\233lyen elmer\252l fekete[ENTER]m\225gi\225j\225ban \233s transzba esik! "
gameforge.main_quest_lv97._060_say = "\201rtettem. "
gameforge.main_quest_lv97._070_say = "L\233gy \243vatos! \201let\233ben \245 volt a F\245papn\245 els\245 sz\225m\250[ENTER]test\245re \233s igen j\243l k\233pzett nem csak a m\225gi\225ban,[ENTER]de a kardp\225rbaj ter\252let\233n is. "
gameforge.main_quest_lv97._080_sayTitle = "A Templomszolga "
gameforge.main_quest_lv97._090_say = "Gy\245zd le Mu-Shu-t, a Banshee Templomszolg\225j\225t a[ENTER]Gautama-szikl\225n. "
gameforge.main_quest_lv97._100_notice = "Gyilkos csap\225st\243l s\250jtva a Templomszolga lerogy a[ENTER]f\246ldre. "
gameforge.main_quest_lv97._110_say = "Ti bolondok! \214r\246mmel bekapt\225tok a csalit, amit a[ENTER]Banshee vetett ki sz\225motokra. M\237g velem[ENTER]vesztegetted az id\245d, az \250rn\245 \233s a val\243di[ENTER]Templomszolga, Yah-Ki m\225r elkezdt\233k az \225tkot.[ENTER]Im\225dkozom, hogy siker\252lj\246n! "
gameforge.main_quest_lv97._120_say = "A hasonm\225s az orrodn\225l fogva vezetett t\233ged![ENTER]Miut\225n \225tkutattad, egy hasonl\243 nyak\233ket tal\225lt\225l[ENTER]n\225la, mint amit Martyaxwar viselt. Bels\245[ENTER]rekesz\233ben ott egy irat. "
gameforge.main_quest_lv97._130_say = "Jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv97._140_say = "Visszat\233rt\233l! Legy\245zted a Templomszolg\225t? "
gameforge.main_quest_lv97._150_say = "Nem, megt\233vesztett benn\252nket egy hasonm\225s. A[ENTER]val\243di Templomszolga h\225bor\237tatlanul el\245 tudta[ENTER]k\233sz\237teni a hal\225l megid\233z\233s\233t. Tess\233k, ezt az[ENTER]iratot tal\225ltam. "
gameforge.main_quest_lv97._160_say = "\193tkozott! Hogy tudn\225nk kiker\252lni a csapd\225j\225t?![ENTER]K\233rlek, mutasd azt a dokumentumot. "
gameforge.main_quest_lv97._170_say = {}
gameforge.main_quest_lv97._180_say = {}
gameforge.main_quest_lv97._190_say = "Hmm, k\243dolt. De tal\225n ez az \252zenet felfedi,[ENTER]jelenleg hol rejt\245zik a b\225zisa. Valamikor m\225r[ENTER]l\225ttam ilyen karaktereket kor\225bban... Azt hiszem[ENTER]Yak-Hwan, a Palota\245r mutatott hasonl\243t[ENTER]mostan\225ban.[ENTER]Menj el hozz\225. Vetnie kellene r\225 egy pillant\225st. "
gameforge.main_quest_lv97._200_sendLetter = "Az irat megfejt\233se "
gameforge.main_quest_lv97._210_say = "Menj Yak-Hwang-hoz \233s mutasd meg neki a k\243dolt[ENTER]iratot. "
gameforge.main_quest_lv97._220_say = "\220dv! A nevem Yak-Hwan. Megtiszteltet\233s, hogy[ENTER]megismerhetlek. M\225r legend\225s h\237red van! Mit[ENTER]tehetek \233rted? Ah, egy k\243dolt \252zenet. Hadd l\225ssam[ENTER]csak. "
gameforge.main_quest_lv97._230_say = "Igen, gond n\233lk\252l meg tudn\225m fejteni ezeket a[ENTER]karaktereket, de ehhez Fosszilis f\246ldre van[ENTER]sz\252ks\233gem. Az Alkimist\225nak val\243sz\237n\251leg rengeteg[ENTER]van bel\245le. K\233rlek, k\233rj t\245le. "
gameforge.main_quest_lv97._240_say = {}
gameforge.main_quest_lv97._250_say = {}
gameforge.main_quest_lv97._260_say = "Term\233szetesen. "
gameforge.main_quest_lv97._270_sayTitle = "Fosszilis f\246ld "
gameforge.main_quest_lv97._280_say = "Menj az Alkimist\225hoz \233s k\233rdezd a Fosszilis[ENTER]f\246ldr\245l. "
gameforge.main_quest_lv97._290_say = "Nem felejtett\233l el semmit? Fosszilis f\246ldet kell[ENTER]hoznod nekem. "
gameforge.main_quest_lv97._300_notice = "Az Alkimista adott neked Fosszilis f\246ldet. Most[ENTER]t\233rj vissza Yak-Hwan-hoz. "
gameforge.main_quest_lv97._310_say = "Ah, a Fosszilis f\246ld. Nagyon j\243, el tudok kezdeni[ENTER]dolgozni. Az Admir\225lisnak fogom jelenteni, amit[ENTER]tal\225lok. "
gameforge.main_quest_lv97._320_sendLetter = "A h\225ts\243 ajt\243n \225t "
gameforge.main_quest_lv97._330_say = "Angmur Admir\225lis keres t\233ged. "
gameforge.main_quest_lv97._340_say = "Tudjuk, hol tart\243zkodik a Templomszolga Yah-Ki.[ENTER]De a b\225zisa egy er\245dh\246z hasonl\237t \150 test\245r\246k[ENTER]csapata j\225r\245r\246zik ott \233jjel-nappal. Egy front\225lis[ENTER]t\225mad\225s sz\237ntiszta \246ngyilkoss\225g lenne. "
gameforge.main_quest_lv97._350_say = "Ez\233rt lesb\245l akarunk t\225madni. Embereim keresik a[ENTER]megfelel\245 helyet. Az \245r\246k figyelm\233nek elterel\233se[ENTER]t\246bb id\245t ny\250jt nek\252nk. "
gameforge.main_quest_lv97._360_say = {}
gameforge.main_quest_lv97._370_say = "A legnagyobb vesz\233lyt a test\245rcsapat vezet\245i[ENTER]jelentik, akik a Fekete Hal\225l brig\225dj\225nak nevezik[ENTER]magukat. Ez a brig\225d a k\246vetkez\245kb\245l \225ll: Moghu,[ENTER]Carnifex \233s Albus t\225bornok. Vezet\245j\252k Skeletos.[ENTER]Vond ki \245ket a forgalomb\243l, miel\245tt[ENTER]felfedezhetn\233k a felder\237t\245 csapataim. "
gameforge.main_quest_lv97._380_say = "Minden rendben. "
gameforge.main_quest_lv97._390_sayTitle = "A Fekete Hal\225l brig\225dja "
gameforge.main_quest_lv97._400_say = "Tedd \225rtalmatlann\225 a Fekete Hal\225l brig\225dj\225t,[ENTER]melynek tagjai Moghu, Carnifex, Albus t\225bornok \233s[ENTER]Skeletos. "
gameforge.main_quest_lv97._410_say = "Gy\245zd le a Fekete Hal\225l brig\225dj\225nak tagjait,[ENTER]miel\245tt felfedezhetn\233k a felder\237t\245 csapatokat. "
gameforge.main_quest_lv97._420_say = "Jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv97._430_say = "J\243l haladnak a terveink! Am\237g megzavartad a[ENTER]Fekete Hal\225l brig\225dj\225t, embereim megtal\225lt\225k a[ENTER]leshely megfelel\245 hely\233t. Amint kidolgozzuk a[ENTER]t\225mad\225si strat\233gi\225t, h\237vatni foglak. "
gameforge.main_quest_lv97._440_sendLetter = "A Templomszolga "
gameforge.main_quest_lv97._450_say = "Angmur Admir\225lisnak a seg\237ts\233gedre van sz\252ks\233ge! "
gameforge.main_quest_lv97._460_say = "J\243, meg\233rkezt\233l. Skeletos, a Fekete Hal\225l[ENTER]brig\225dj\225nak vez\233re t\250l\233lte az el\245z\245 akci\243t \233s[ENTER]megt\225madta az embereim, amint a b\225zis lerohan\225s\225t[ENTER]tervezt\233k. Senki sem tudta legy\245zni. "
gameforge.main_quest_lv97._470_say = {}
gameforge.main_quest_lv97._480_say = "Egyszer m\225r legy\245zted \245t, k\233rlek, seg\237ts az[ENTER]embereimnek a Gautama-szikl\225n! Indulj Skeletos[ENTER]ellen! Ezut\225n rohamozd meg a b\225zist \233s \246ld meg a[ENTER]Templomszolga Yah-Ki-t. "
gameforge.main_quest_lv97._490_say = "Meg\233rtettem. "
gameforge.main_quest_lv97._500_say = {}
gameforge.main_quest_lv97._510_sayTitle = "Gy\245zd le Yah-Ki-t "
gameforge.main_quest_lv97._520_say = "Gy\245zd le a Templomszolga Yah-Ki-t \233s \225ll\237tsd meg,[ENTER]nehogy megid\233zze a holtak sereg\233t. "
gameforge.main_quest_lv97._530_say = "El\233rkezett a d\246nt\245 nap. Ha elbukunk, vel\252nk bukik[ENTER]a vil\225g is. De ha gy\245z\252nk, m\233g sz\225z \233v m\250lva is[ENTER]dalokban zengik tetteinket. \193ll\237tsd meg a[ENTER]S\246t\233ts\233g szolg\225it! Gy\245zd le a Templomszolga[ENTER]Yah-Ki-t! "
gameforge.main_quest_lv97._540_say = "Mi\233rt vagy itt? M\233g nem nyert\252k meg a csat\225t![ENTER]Gy\245zd le a Templomszolga Yah-Ki-t! Benned van[ENTER]minden rem\233ny\252nk. "
gameforge.main_quest_lv97._550_1_notice = "T\233rdre k\233nyszer\237tetted ellenfeleid, a gy\245zelem a[ENTER]ti\233d! "
gameforge.main_quest_lv97._550_2_notice = "Nincs id\245 a pihen\233sre \150 a Templomszolga Yah-Ki[ENTER]r\225d v\225r. "
gameforge.main_quest_lv97._560_notice = "Nyert\233l! Egy v\233rfagyaszt\243 ki\225lt\225ssal Yah-Ki a[ENTER]f\246ldre rogy. "
gameforge.main_quest_lv97._570_say = "Aaargh! Ez nem lehet! Legy\245z\246tt egy haland\243... Oh[ENTER]Banshee, bocs\225ss meg nekem! Elbuktam. Nem tudtam[ENTER]teljes\237teni a fela... "
gameforge.main_quest_lv97._580_say = "\193tkutatod \233lettelen test\233t \233s egy Lepecs\233telt[ENTER]levelet tal\225lsz n\225la. T\233rj vissza vele Angmur[ENTER]Admir\225lishoz. "
gameforge.main_quest_lv97._590_say = "Ez igen, h\225la a S\225rk\225nyistennek! S\233rtetlen\252l[ENTER]visszat\233rt\233l! Legy\245zted a Templomszolg\225t? "
gameforge.main_quest_lv97._600_say = "Igen, visszak\252ldtem \245t a Pokolba, ahonnan j\246tt.[ENTER]Hal\225la pillanat\225ban a Banshee-hoz foh\225szkodott[ENTER]bocs\225nat\233rt a hib\225j\225\233rt. Ez volt n\225la. "
gameforge.main_quest_lv97._610_say = "Egy Lepecs\233telt lev\233l. Mutasd! "
gameforge.main_quest_lv97._620_sayReward = "\218rn\245m, Bekapt\225k a csalit, terved m\251k\246dik. \201l\245holt[ENTER]sereged megid\233z\233se tov\225bb folytat\243dik \233s most m\225r[ENTER]senki sem k\233pes meg\225ll\237tani benn\252nket. Amint[ENTER]egyszer a l\233lektelen testek elkezdenek menetelni,[ENTER]megt\225madjuk a S\225rk\225nyt\251z-fokot \233s magunk al\225[ENTER]gy\251rj\252k lakoss\225g\225t. Ezut\225n \225tkel\252nk a kontinensre[ENTER]\233s a T\251zf\246ld\246n tal\225lkozunk veled. A vil\225g \233gni[ENTER]fog l\233pteink nyom\225n![ENTER]M\233ly h\243dolatom fel\233d, \214r\246k szolg\225d "
gameforge.main_quest_lv97._630_say = "Egy \252zenet a Banshee-nak! \211h, ez az \225tkozott[ENTER]boszork\225ny most hi\225ba v\225rja T\251zf\246ld\246n a s\246t\233ts\233g[ENTER]sereg\233t.[ENTER]K\246sz\246n\246m. Seg\237ts\233ged n\233lk\252l a S\225rk\225nyt\251z-fok \233s[ENTER]lakoss\225ga f\246ldbe lett volna taposva az \233l\245holtak[ENTER]serege \225ltal. Nem csak megmentett\233l benn\252nket, de[ENTER]helyre\225ll\237tottad \245seink lelk\233nek nyugalm\225t is.[ENTER]Fogadd ezt a jutalmat minden\233rt, amit tett\233l. "
gameforge.main_quest_lv97._640_sayTitle = "A kaland folytat\243dik, amint el\233rted a 98-as[ENTER]szintet. "
gameforge.main_quest_lv97._650_say = "Sok id\245nkbe telt, mire megtal\225ltuk a b\225zist.[ENTER]K\233rlek, nem vesztegethet\252nk t\246bb id\245t! "
gameforge.main_quest_lv97._660_say = "Yak-Hwan-nak Fosszilis f\246ldre van sz\252ks\233ge? M\233g[ENTER]szerencse, hogy nem haszn\225ltam fel mindet.[ENTER]Sz\237vesen adok, tess\233k. Vidd el neki \233s add \225t[ENTER]sz\237v\233lyes \252dv\246zletem is! "
