gameforge.main_quest_lv97._690_1_notice = "Legy\245zted a Fekete Hal\225l brig\225dj\225t. "
gameforge.main_quest_lv97._690_2_notice = "Jelentsd Angmur Admir\225lisnak. "
gameforge.main_quest_lv97._700_sayTitle = "Gy\245zd le Skeletos-t, a Fekete Hal\225l brig\225dj\225nak[ENTER]vez\233r\233t! "
gameforge.main_quest_lv97._710_say = "A Templomszolg\225t kell els\245k\233nt meg\246ln\246d, miut\225n[ENTER]legy\245zted Skeletos-t. "
gameforge.main_quest_lv98 = {}
gameforge.main_quest_lv98._010_sendLetter = "Az Er\245d \250jj\225\233p\237t\233se "
gameforge.main_quest_lv98._020_say = "Angmur Admir\225lis a seg\237ts\233gedet k\233ri. Menj el[ENTER]hozz\225. "
gameforge.main_quest_lv98._030_say = "K\246sz\246n\246m, hogy elj\246tt\233l. A csata nem m\250lt el nyom[ENTER]n\233lk\252l felett\252nk. Az er\245d is megs\233r\252lt \233s a[ENTER]v\233delmi falak t\246bb helyen is leomlottak. Ez a[ENTER]hely nem tart ki sok\225ig. A javunkra kell[ENTER]ford\237tani a nyugalmat \233s \250jj\225\233p\237teni a romokat. "
gameforge.main_quest_lv98._040_say = "A v\233delmi fal meger\245s\237t\233s\233hez a R\225kf\233l\233k[ENTER]rendj\233nek p\225nc\233lj\225ra van sz\252ks\233g\252nk. "
gameforge.main_quest_lv98._050_say = "Meg\233rtettem. Mennyi p\225nc\233lra van sz\252ks\233ged? "
