gameforge.main_quest_lv98._080_2_notice = "Vidd el Angmur Admir\225lisnak. "
gameforge.main_quest_lv98._090_say = "Ez igen, nagyon j\243! A R\225kp\225nc\233l seg\237t \250jra[ENTER]meger\245s\237teni a v\233delmi falunkat. K\233rlek, fogadd[ENTER]ezt jutalmul. Megk\233rdezem a m\233rn\246keim, kell-e m\233g[ENTER]m\225s anyag is, \233s tudatni fogom veled. "
