gameforge.main_quest_lv98._140_say = "Angmur Admir\225lisnak ism\233t a seg\237ts\233gedre van[ENTER]sz\252ks\233ge. Menj el hozz\225. "
gameforge.main_quest_lv98._150_say = "Tov\225bbi er\245s\237t\233shez Triton d\225rd\225kra van sz\252ks\233g.[ENTER]Amint a n\233vb\245l sejthet\245, a Tritonokn\225l tal\225lod.[ENTER]Hozz nekem 100-at. "
