gameforge.main_quest_lv98._170_say = "H\225t itt vagy! Eh, ez m\233g nem el\233g Triton d\225rda.[ENTER]K\233rlek, folytasd a gy\251jt\233st. "
gameforge.main_quest_lv98._180_1_notice = "\214sszegy\251jt\246tt\233l minden Triton d\225rd\225t. "
gameforge.main_quest_lv98._180_2_notice = "Vidd el Angmur Admir\225lisnak. "
gameforge.main_quest_lv98._190_say = "T\246k\233letes! Most \233p\237teni tudunk egy biztons\225gosabb[ENTER]v\233delmi er\245d\237tm\233nyt. K\246sz\246n\246m a seg\237ts\233ged.[ENTER]Egy\233bk\233nt Yak-Hwan keres t\233ged. Tudd meg, mit[ENTER]akar. "
gameforge.main_quest_lv98._200_sendLetter = "V\233szhelyzet "
gameforge.main_quest_lv98._210_say = "Menj Yak-Hwan-hoz. Fontos feladata van sz\225modra. "
gameforge.main_quest_lv98._220_say = "Ah, nagyon j\243, h\225t itt vagy! \218jra ig\233nybe kell[ENTER]benn\252nk a seg\237ts\233ged. "
