gameforge.main_quest_lv98._240_say = {}
gameforge.main_quest_lv98._250_say = {}
gameforge.main_quest_lv98._260_say = "A h\225bor\250 okozta neh\233z id\245k nem m\250ltak el nyom[ENTER]n\233lk\252l az er\245dben \233l\245 emberekben. \201hs\233gt\245l[ENTER]szenvednek \233s nyomoruk napr\243l napra rosszabbodik.[ENTER]Nincsenek t\250l j\243 kil\225t\225saik, hacsak nem tesz\252nk[ENTER]valamit hamarosan. "
gameforge.main_quest_lv98._270_say = {}
gameforge.main_quest_lv98._280_say = "Az Ogre band\225k lesben v\225rnak[ENTER]ut\225np\243tl\225s-sz\225ll\237tm\225nyainkra v\225rva \233s t\225madj\225k[ENTER]azokat. Meg kell \225ll\237tanunk ezt a fosztogat\225st.[ENTER]Shruk kapit\225ny \233s T\225bornokai \225llnak em\246g\246tt. \214ld[ENTER]meg az Ogr\233k kapit\225ny\225t \233s 50 Ogg t\225bornokot! "
gameforge.main_quest_lv98._290_say = {}
gameforge.main_quest_lv98._300_say = "M\225r vissza is t\233rt\233l? M\233g mindig van ott n\233h\225ny[ENTER]Ogre. K\233rlek, gondoskodj r\243luk! "
gameforge.main_quest_lv98._310_1_notice = "Legy\245zt\233l minden Ogr\233t. "
gameforge.main_quest_lv98._310_2_notice = "Most t\233rj vissza Yak-Hwan-hoz. "
gameforge.main_quest_lv98._320_say = "V\233gre \233lelmiszer-ut\225np\243tl\225s sz\225ll\237tm\225nyaink[ENTER]el\233rik az er\245d\246t, \233s embereink \250jra \233telhez \233s[ENTER]gy\243gyszerhez juthatnak! A v\233szhelyzet v\233get \233rt.[ENTER]Igazi h\245s vagy. "
gameforge.main_quest_lv98._330_sendLetter = "K\246sz\246netnyilv\225n\237t\225s "
gameforge.main_quest_lv98._340_say = "Yak-Hwan besz\233lni akar veled. "
gameforge.main_quest_lv98._350_say = "Seg\237ts\233gednek k\246sz\246nhet\245en el\251zt\252k egy id\245re a[ENTER]S\246t\233t S\225rk\225ny szikl\225t fenyeget\245 vesz\233lyt. Ez\233rt[ENTER]az emberek szem\233lyesen is szeretn\233nek neked[ENTER]k\246sz\246netet mondani. "
gameforge.main_quest_lv98._360_say = "Menj v\233gig az er\245d\246n \233s besz\233lj az emberekkel. "
gameforge.main_quest_lv98._370_say = {}
gameforge.main_quest_lv98._380_say = "K\246sz\246n\246m. Meg fogok l\225togatni minden itt \233l\245t. "
