gameforge.main_quest_lv98._400_say = "Egyenl\245 ar\225ny\250 b\225tors\225g \233s b\246lcsess\233g van a[ENTER]sz\237vedben. Tetteidr\245l gener\225ci\243k fognak \233nekelni[ENTER]mostant\243l. Meghajlok el\245tted. "
gameforge.main_quest_lv98._410_say = "\214r\246kk\233 l\233gy felv\233rtezve a vesz\233ly ellen! "
gameforge.main_quest_lv98._420_say = "\214r\246kk\233 megbecs\252lt helyed lesz sz\237v\252nkben! "
gameforge.main_quest_lv98._430_say = "Viharos id\245k voltak ezek, nem igaz? Biztos vagyok[ENTER]benne, hogy a S\225rk\225nyisten szem\233lyesen egyengeti[ENTER]az utat el\245tted sziget\252nk\246n. "
gameforge.main_quest_lv98._440_1_notice = "Minden lakossal besz\233lt\233l. "
gameforge.main_quest_lv98._440_2_notice = "Most t\233rj vissza Yak-Hwan-hoz. "
gameforge.main_quest_lv98._450_say = "Ez t\233nyleg sokat jelentett az er\245d lakosainak. Az[ENTER]Admir\225lis szeretne \250jra besz\233lni veled. Legyen \245[ENTER]a k\246vetkez\245, akihez elm\233gy. "
