gameforge.manwoo._20_sayTitle = "Hal\225sz: "
gameforge.manwoo._30_say = "A halteny\233szetemet ki akarom b\245v\237teni, ez\233rt[ENTER]sz\252ks\233gem van \233l\245 pontyra. Ez a halfajta a[ENTER]teny\233szetre j\243l alkalmas \233s a hal\225szok k\246r\233ben[ENTER]nagyon kedvelt, de nem k\246nny\251 a[ENTER]hal\225szata.  "
gameforge.manwoo._40_say = "Ha hozol nekem egy pontyot, akkor meg foglak[ENTER]jutalmazni. Egy l\225d\225m van, ami m\225r \245sid\246k \243ta a[ENTER]padl\225son van. M\225r azt sem tudom, hogy mi van[ENTER]benne. Tal\225n valami haszontalan dolog, vagy[ENTER]valami \233rt\233kes. De m\233g sz\246rnyek is megh\250zhatt\225k[ENTER]magukat benne. Ha meg akarod kapmi a l\225d\225t, akkor[ENTER]hozz nekem egy \233l\245 pontyot.  "
