gameforge.map_warp._270_say = "Mostan\225ban lett felfedezve egy titokzatos sziget.[ENTER]A S\246t\233t S\225rk\225ny szikla nevet kapta. Azoknak, akik[ENTER]t\250l akarj\225k \233lni, meglehet\245sen nagy tapasztalatra[ENTER]van sz\252ks\233g\252k. Ez\233rt csak azokat a harcosokat[ENTER]sz\225ll\237tom oda, akik el\233rt\233k a 90-es szintet.[ENTER]K\233szen \225llsz erre az utaz\225sra? "
gameforge.map_warp._280_say = "A szigetre csak haj\243val lehet eljutni \150 oda az[ENTER]utaz\225s hossz\250 \233s f\225rads\225gos. Min\233l magasabb a[ENTER]szinted, ann\225l k\246r\252lm\233nyesebb a sz\225ll\237t\225s. Ez\233rt[ENTER]magasabb \246sszeg\251 d\237jat kell k\233rnem t\245led. "
gameforge.map_warp._280_sayReward = "Az utaz\225s %d Yangodba ker\252l. "
gameforge.map_warp._30_say = "Ez a maga m\243dj\225n egy leny\251g\246z\245 k\246rny\233k, de[ENTER]t\246rt\233nik itt valaha is egy k\252l\246nleges esem\233ny?[ENTER]H\225t ink\225bb nem ... Az orsz\225g egy\233b r\233szein olykor[ENTER]teljesen m\225s a helyzet! Ez\233rt biztosan van egy[ENTER]\233rdekes hely, ahova teleport\225lhatlak. Mivel a[ENTER]gonosz ereje ism\233t megn\245tt, a t\233r \233s az id\245[ENTER]k\225oszba s\252llyedt. Ez\233rt el\245fordulhat, hogy a[ENTER]visszat\233r\233sed nem mindig r\246gt\246n siker\252l...[ENTER]Szeretn\233l ennek ellen\233re[ENTER]teleport\225l\243dni?  "
gameforge.map_warp._40_say = "Hm... a mostani szinteddel t\250l gyenge vagy a t\233r[ENTER]\233s id\245 k\246zti utaz\225shoz. Gyere vissza, ha m\225r[ENTER]10-esn\233l magasabb szint\251 vagy! "
gameforge.map_warp._50_say = "Hov\225 akarsz teleport\225lni? "
