gameforge.new_christmas = {}
gameforge.new_christmas._010_npcChat = "Ho ho ho! "
gameforge.new_christmas._020_say = "Ah, te vagy az![ENTER]R\233g\243ta nem l\225ttuk egym\225st.[ENTER]J\246nnek-mennek az \233vek, ho ho![ENTER]Tal\225n azt k\233rded, vajon most mi\233rt j\246ttem vissza[ENTER]a faluba.[ENTER]Hadd magyar\225zzam meg... "
gameforge.new_christmas._030_say = "Neh\233z id\245k j\225rnak. Senki sem akar v\225s\225rolni[ENTER]k\246nyveket vagy hasonl\243 dolgokat ezekben a[ENTER]napokban. Ilyen id\245s korban t\250l f\225raszt\243[ENTER]k\246rberep\252lni a r\233nszarvas sz\225non. Ezt figyelembe[ENTER]v\233ve d\246nt\246ttem \250gy, hogy ebben az \233vben a faluban[ENTER]\252nneplem a Kar\225csonyt. "
gameforge.new_christmas._040_say = "Ha tov\225bbi k\233rd\233seid lesznek, mindig elj\246hetsz \233s[ENTER]megk\233rdezhetsz. Boldog Kar\225csonyt! "
gameforge.new_christmas._050_npcChat = "Szeretn\233l egy kis forralt bort? "
gameforge.new_christmas._060_say = "Ho ho ho! Biztos vagyok benne, hogy tudod, mi ez,[ENTER]ugye? Nincs is enn\233l jobb ital t\233lid\245ben![ENTER]\214sszekeversz egy finom bort egy csipetnyi[ENTER]fah\233jjal \233s egy csom\243 szegf\251szeggel... mmmmm! "
gameforge.new_christmas._070_say = "Ebben a hidegben egy korty forralt bor a legjobb[ENTER]a vil\225gon! Er\245t ad neked \233s seg\237t a gyorsabb[ENTER]mozg\225sban. Szeretn\233d kipr\243b\225lni egy kicsit?[ENTER]Nagyon j\243, \233pp most k\233sz\252lt! "
gameforge.new_christmas._080_say = "\218gy t\251nik, \237zlik neked a forralt bor, ho ho![ENTER]\201rzed a bens\245db\245l fakad\243 meleget?[ENTER]Oh, \233s az \237ze, annyira \233des \233s gy\252m\246lcs\246s![ENTER]Boldog Kar\225csonyt! "
gameforge.new_christmas._090_npcChat = "K\233rek m\233g forralt bort! "
gameforge.new_christmas._100_say = "V\225rj egy kicsit![ENTER]Elfeledkeztem egy apr\243 r\233szletr\245l![ENTER]Naponta csak egyszer tudok forralt bort[ENTER]k\233sz\237teni, nincs el\233g \246sszetev\245m t\246bbet[ENTER]el\245\225ll\237tani. \201s ez 20 \243r\225ig tart. Egy palackban 6[ENTER]adag van, egy korty hat\225sa 30 percig tart.[ENTER]B\246lcsen adagold! "
gameforge.new_christmas._110_say = "Tess\233k! Eleget v\225rt\225l m\225r. Ezzel a csod\225latos[ENTER]itallal sz\225rnyakat kapsz, ho ho ho! Sz\243val[ENTER]rem\233lem, tetszik! Boldog Kar\225csonyt! "
gameforge.new_christmas._120_say = "Mi, k\233rsz m\233g egy kicsit?[ENTER][ENTER]Sajn\225lom, de azt hiszem, eleget kapt\225l. M\233g nem[ENTER]telt el 24 \243ra az utols\243 adag forralt borod \243ta.[ENTER]Tudod, hogy a t\250l sok ebb\245l nem j\243 sz\225modra![ENTER]Gyere vissza k\233s\245bb. Addig is, \233lvezd az \252nnepet! "
