gameforge.new_christmas_sock._010_npcChat = "Mi van a zoknikkal? "
gameforge.new_christmas_sock._020_say = "A zoknik! Majdnem elfeledkeztem r\243luk! A[ENTER]kandall\243r\243l l\243g\243 zoknikba akartam rejteni az[ENTER]aj\225nd\233kaimat. De ezek a Kar\225csony-ellenes l\233nyek[ENTER]ellopt\225k az \246sszeset! Seg\237ts visszaszereznem[ENTER]azokat! "
