gameforge.new_christmas_sock._040_say = "H\225t nem aranyos?[ENTER]\201s kiv\225l\243 szagl\225ssal is rendelkezik. A[ENTER]zoknivad\225szat szak\233rt\245je![ENTER]2 \243r\225n \225t veled marad, \233s seg\237t neked a[ENTER]keres\233sben. Ezut\225n elf\225rad, \233s sz\252ks\233ge lesz 24[ENTER]\243ra pihen\233sre, miel\245tt folytatni tudja.[ENTER]Ha nem szeretn\233l olyan sok\225ig v\225rni, akkor vess[ENTER]egy pillant\225st a bal als\243 sarokban forg\243 \233rme[ENTER]m\246g\233, \250gy tudom, egy m\225sik R\233nszarvasgida v\225r ott[ENTER]r\225d. De \233n annak is \246r\252l\246k, ha holnap \250jra[ENTER]megl\225togatsz! "
gameforge.new_christmas_sock._050_npcChat = "Hoztam neked zoknikat! "
gameforge.new_christmas_sock._060_say = "Hozz nekem legal\225bb 5 zoknit, \233s jutalmat kapsz.[ENTER]Urrgh, a dohos zokni szaga elviselhetetlen![ENTER]Gyere vissza, ha eleget gy\251jt\246tt\233l. Boldog[ENTER]Kar\225csonyt! "
gameforge.new_christmas_sock._070_say = "Ho ho ho, elegend\245 zoknit gy\251jt\246tt\233l![ENTER]Hmm, hadd l\225ssam.[ENTER]URRGH, ez a szag! Nos, ezek egy\233rtelm\251en a j\243[ENTER]zoknik![ENTER]Boldog Kar\225csonyt! "
gameforge.new_christmas_sock._080_npcChat = " - R\233nszarvasgida "
gameforge.new_christmas_sock._090_say = "Ma m\225r kapt\225l t\245lem egy R\233nszarvasgida pecs\233tet.[ENTER]Att\243l tartok, a kis gid\225nak most pihennie kell.[ENTER]Holnapra m\225r teljesen visszat\233r az ereje. Ha nem[ENTER]szeretn\233l olyan sok\225ig v\225rni, akkor vess egy[ENTER]pillant\225st a bal als\243 sarokban forg\243 \233rme m\246g\233,[ENTER]\250gy tudom, egy m\225sik R\233nszarvasgida v\225r ott r\225d.[ENTER]De \233n annak is \246r\252l\246k, ha holnap \250jra[ENTER]megl\225togatsz! "
gameforge.new_christmas_sock._100_say = "Ma m\225r elhoztad nekem a zoknijaid. Ne feledd,[ENTER]csak 24 \243r\225nk\233nt adhatsz \225t n\233h\225nyat. "
