gameforge.new_quest_lv17._073_say = "Gyer\252nk! "
gameforge.new_quest_lv17._074_notice = "Szerezt\233l n\233mi j\243 min\245s\233g\251 pr\233met. "
gameforge.new_quest_lv17._075_say = "Vad\225ssz Mu-Rang farkasokra, \233s szerezd meg a[ENTER]pr\233m\252ket. "
gameforge.new_quest_lv17._076_say_reward = "\214sszegy\251jt\246tt\233l %s darabot az \246t pr\233mb\245l. "
gameforge.new_quest_lv17._081_say_title = "Pr\233m Wonda-Rimnek "
gameforge.new_quest_lv17._082_say = "Elegend\245 pr\233met szerezt\233l, mosd add \225t[ENTER]Wonda-Rimnek. "
gameforge.new_quest_lv17._092_say_reward = "M\225r \246sszegy\251jt\246tt\233l %s darab farkas pr\233met. "
gameforge.new_quest_lv17._110_say = "Ez igaz\225n sz\233p pr\233m, k\246sz\246n\246m. Elvinn\233d a[ENTER]nagyb\225ty\225mnak? "
gameforge.new_quest_lv17._120_target = "Chaegirab nagyb\225csi "
gameforge.new_quest_lv17._121_say = "Wonda-Rim megk\233rt, hogy add \225t a farkas pr\233met[ENTER]Chaegirab-nak. "
gameforge.new_quest_lv17._122_say = "Chaegirab itt van: %s. "
gameforge.new_quest_lv17._130_say = "Aha. Sz\243val ezzel pr\243b\225lkozik most. "
gameforge.new_quest_lv17._131_say = "Kit\245l sz\225rmazik ez a pr\233m? Wonda-Rimt\245l, de te[ENTER]\246lt\233l farkasokat helyette?[ENTER]Zavar, hogy van egy unoka\246cs\233m, aki m\225sokat[ENTER]dolgoztat maga helyett. Sajn\225lom, de \237gy nem[ENTER]fogadhatom el ezt, hab\225r tudom, hogy nagy[ENTER]er\245fesz\237t\233sbe \233s sok id\245be ker\252lt neked. "
gameforge.new_quest_lv17._132_say_reward = "Mondd meg Wonda-Rimnek, hogy \225tl\225ttam rajta! Ha[ENTER]val\243ban \246r\246m\246t akarna szerezni valamivel, saj\225t[ENTER]mag\225nak kellene vad\225sznia. "
gameforge.new_quest_lv17._140_say = "Chaegirab nem fogadta el a pr\233met, \233s m\233rges[ENTER]Wonda-Rim lustas\225ga miatt. Visszak\252ld\246tt[ENTER]Wonda-Rimhez. "
gameforge.new_quest_lv17._141_say = "Mit mondott a nagyb\225ty\225m? Rem\233lem, tetszett neki[ENTER]az aj\225nd\233kom. "
gameforge.new_quest_lv17._142_1_select = "Igen, le volt ny\251g\246zve. "
gameforge.new_quest_lv17._142_2_select = "Nem, egy\225ltal\225n nem. "
gameforge.new_quest_lv17._143_say = "Nagyszer\251! Szeretek megaj\225nd\233kozni m\225sokat! \201s[ENTER]persze nagylelk\251 jutalmat adok neked is. Itt van,[ENTER]fogd! "
gameforge.new_quest_lv17._144_say_reward_a = "20.000 tapasztalat pontot kapt\225l.[ENTER]20.000 Yangot kapt\225l.[ENTER]Aranyr\246g\246t kapt\225l. "
gameforge.new_quest_lv17._144_say_reward_b = "Hazudt\225l Wonda-Rimnek, \233s rangpontot vesz\237tett\233l. "
gameforge.new_quest_lv17._145_say = "Nem fogadta el a pr\233met? Hmm, tal\225n nem volt[ENTER]kifejezetten j\243 \246tlet t\233ged k\252ldeni vad\225szni[ENTER]magam helyett. Legk\246zelebb m\225sk\233pp csin\225lom. "
gameforge.new_quest_lv17._146_say_reward = "De nem akarom, hogy kem\233nyen dolgozz a semmi\233rt:[ENTER]Menj Yang-Shinhez. J\243 \225ron megveszi t\245led a[ENTER]pr\233met. "
gameforge.new_quest_lv17._147_say = "Milyen ki\225br\225nd\237t\243 fordulat. B\225r, legal\225bb m\233g[ENTER]mindig megvan a pr\233m. Menj Yang-Shinhez Yayang[ENTER]ter\252letre, \233s add el neki a pr\233met. "
gameforge.new_quest_lv17._148_say = "Milyen ki\225br\225nd\237t\243 fordulat. B\225r, legal\225bb m\233g[ENTER]mindig megvan a pr\233m. Menj Yang-Shinhez Bokjung[ENTER]ter\252letre, \233s add el neki a pr\233met. "
gameforge.new_quest_lv17._149_say = "Milyen ki\225br\225nd\237t\243 fordulat. B\225r, legal\225bb m\233g[ENTER]mindig megvan a pr\233m. Menj Yang-Shinhez Bakra[ENTER]ter\252letre, \233s add el neki a pr\233met. "
gameforge.new_quest_lv17._151_say = "Mu-Rang pr\233m? Val\243j\225ban nagyon praktikus.[ENTER]K\233sz\237tek is bel\245le n\233h\225ny als\243nem\251t magamnak. Itt[ENTER]egy ersz\233ny Yang a f\225radoz\225sod\233rt. Oh, \233s tegnap[ENTER]tal\225ltam ezt a k\246nyvet, tal\225n hasznodra v\225lik. "
gameforge.new_quest_lv17._152_say_reward = "40.000 tapasztalat pontot kapt\225l.[ENTER]10.000 Yangot kapt\225l.[ENTER]K\233szs\233gk\246nyvet kapt\225l. "
