gameforge.new_quest_lv22._011_say = "Az \213rnek van sz\225modra egy k\252ldet\233se. Keresd \245t \233s[ENTER]megtudod, mir\245l van sz\243. "
gameforge.new_quest_lv22._015_npcChat = "A beteg fiv\233r "
gameforge.new_quest_lv22._016_send_letter = "A beteg \245r "
gameforge.new_quest_lv22._017_say_title = "Gondnok: "
gameforge.new_quest_lv22._018_say_title = "Baek-Go: "
gameforge.new_quest_lv22._019_say_title = "D\233mon torony \245r "
gameforge.new_quest_lv22._021_say = "Agg\243dom a fiv\233rem, a D\233mon torony \245r miatt. Nem[ENTER]\233rezte valami j\243l mag\225t az ut\243bbi id\245ben, \233s most[ENTER]val\243ban beteg. Nagyon f\225j a feje \233s furcsa[ENTER]b\245rki\252t\233se van, de nem hagyhatja el az \245rhely\233t.[ENTER]Tudn\225l neki vinni valami gy\243gyszert Baek-Go-t\243l? "
gameforge.new_quest_lv22._022_say = "Elmenn\233k hozz\225 \233n magam is, de a D\233mon torony a[ENTER]Hwang templomban van, k\246zvetlen\252l a[ENTER]Seungryong-v\246lgy k\246zep\233n. \201s az eg\233sz helyen[ENTER]vesz\233lyes l\233nyek ny\252zs\246gnek... "
gameforge.new_quest_lv22._023_say = "H\225t \250jra itt vagy. Elfelejtetted a t\252neteket?[ENTER]Figyelned kellene arra, aki hozz\225d besz\233l. A[ENTER]fiv\233remnek f\225j a feje \233s b\245rki\252t\233se van. Most[ENTER]menj, besz\233lj Baek-Go-val! "
gameforge.new_quest_lv22._024_select = "Seg\237ts\233g a fiv\233rnek "
gameforge.new_quest_lv22._025_say_title = "Baek-Go gy\243gyszere "
gameforge.new_quest_lv22._026_say = "Besz\233lj Baek-Go-val a D\233mon torony \245r[ENTER]gy\243gyszer\233r\245l. "
gameforge.new_quest_lv22._027_say = "Baek-Go itt van: %s. "
gameforge.new_quest_lv22._030_target = "Baek-Go: "
gameforge.new_quest_lv22._031_say = "Sz\243val gy\243gyszerre van sz\252ks\233ged? Vesz\233lyes \250gy[ENTER]beadni egy gy\243gyszert, hogy tudn\225nk, az a[ENTER]megfelel\245. Besz\233lned kell nekem a betegs\233g[ENTER]t\252neteir\245l. "
gameforge.new_quest_lv22._032_1_select = "Fejf\225j\225s \233s b\245rki\252t\233s "
gameforge.new_quest_lv22._032_2_select = "Torokf\225j\225s \233s izomg\246rcs "
gameforge.new_quest_lv22._032_3_select = "Nem tudom. "
gameforge.new_quest_lv22._035_say = "D\233mon-r\252hnek t\251nik. Ez gyakori, ha t\250l sok[ENTER]atk\225val fert\245z\246tt \225llat van a k\246zeledben.[ENTER]K\233sz\237thetek valamit, ami seg\237teni tud rajta.[ENTER]Ehhez be kell szerezned n\233h\225ny \246sszetev\245t. "
gameforge.new_quest_lv22._040_say = "Sz\252ks\233gem van: "
gameforge.new_quest_lv22._041_say_reward = "Vad\225sznod kell: "
gameforge.new_quest_lv22._042_say = "Kell m\233g: "
gameforge.new_quest_lv22._043_say = "Sohasem hallottam m\233g hasonl\243 betegs\233g[ENTER]t\252neteir\245l. Biztos vagy benne, hogy az \213r a[ENTER]helyes t\252neteket mondta? A helyedben megk\233rdezn\233m[ENTER]\245t \250jra. "
gameforge.new_quest_lv22._044_say = "Nem \225llap\237thatok meg diagn\243zist t\252netek n\233lk\252l.[ENTER]Menj vissza, \233s k\233rdezd meg \250jra. "
gameforge.new_quest_lv22._050_set_title = "Gy\243gyszer "
gameforge.new_quest_lv22._056_notice = "J\243, m\225r csak %s csokor gy\243gyn\246v\233ny hi\225nyzik. "
gameforge.new_quest_lv22._057_notice = "Ezek lehetnek a gy\243gyn\246v\233nyek, amikre sz\252ks\233gem[ENTER]van. Most sietek vissza Baek-Go-hoz. "
gameforge.new_quest_lv22._058_notice = "J\243, m\225r csak %s m\225j kell. "
gameforge.new_quest_lv22._060_notice = "Ah, egy m\225j. M\225r csak %s hi\225nyzik. "
gameforge.new_quest_lv22._061_notice = "Azt hiszem, megvan az \246sszes m\225j, amire sz\252ks\233gem[ENTER]van. Most sietek vissza Baek-Go-hoz. "
gameforge.new_quest_lv22._062_notice = "Sajnos ezt a Tigris m\225j m\225r haszn\225lhatatlan. "
gameforge.new_quest_lv22._063_say = "Kell m\233g %s x Gy\243gyn\246v\233nyek+. "
gameforge.new_quest_lv22._064_say = "Kell m\233g %s x Tigris m\225j+. "
gameforge.new_quest_lv22._065_say = "Most m\225r megvan az \246sszes hozz\225val\243 a[ENTER]gy\243gyszerhez. Most menj, \233s add \225t Baek-Go-nak. "
gameforge.new_quest_lv22._066_say = "Gy\251jtsd \246ssze a hozz\225val\243kat Baek-Go[ENTER]gy\243gyszer\233hez: "
gameforge.new_quest_lv22._070_say = "K\246sz\246n\246m, most m\225r el tudom k\233sz\237teni a D\233monr\252h[ENTER]gy\243gyszer\233t. "
gameforge.new_quest_lv22._071_say = "K\233sz! Itt a gy\243gyszered. A friss hozz\225val\243kb\243l[ENTER]k\233sz\237tett gy\243gyszer gyorsan romlik - \233rdemes[ENTER]teh\225t eljuttatnod a beteghez a k\246vetkez\245 %s[ENTER]percen bel\252l. "
gameforge.new_quest_lv22._072_say = "Az \245r fiv\233r\233t a Hwang templom k\246zpontj\225ban[ENTER]tal\225lod. L\233gy nagyon \243vatos az \250ton, a[ENTER]Seungryong-v\246lgyben hemzsegnek a vesz\233lyes[ENTER]l\233nyek! "
gameforge.new_quest_lv22._073_say = "Ez nem elegend\245. Elvesz\237tetted a hozz\225val\243kat az[ENTER]ide vezet\245 \250ton? Nem tehetek semmit a marad\233k[ENTER]\246sszetev\245k n\233lk\252l. "
gameforge.new_quest_lv22._080_target = "D\233mon torony \245r "
gameforge.new_quest_lv22._082_set_clock = "H\225tral\233v\245 id\245 "
gameforge.new_quest_lv22._083_say = "Nos, m\233g mindig van elegend\245 id\245d, de sietned[ENTER]kell. Sz\243val siess az \245rh\246z a[ENTER]Seungryong-v\246lgyben, miel\245tt a gy\243gyszer elveszti[ENTER]hat\225s\225t! "
gameforge.new_quest_lv22._084_say = "Lej\225rt az id\245, mert t\250l lass\250 volt\225l. De akkor is[ENTER]be kell vennie a gy\243gyszert a D\233mon torony \245rnek.[ENTER]Tal\225n m\233g mindig hat\225sos. "
gameforge.new_quest_lv22._085_say = "K\246sz\246n\246m, hogy elhoztad a gy\243gyszert. Meg\246l ez a[ENTER]viszket\233s. "
gameforge.new_quest_lv22._086_say = "Oh, ennek eg\233szen j\243 \237ze van. M\225ris \250gy \233rzem,[ENTER]enyh\252l a viszket\233s. "
gameforge.new_quest_lv22._087_say = "K\252l\246n\246sen nagylelk\251 jutalmat \233rdemelsz ez\233rt! "
gameforge.new_quest_lv22._088_say_reward = "50.000 tapasztalat pontot kapt\225l.[ENTER]12.000 Yangot kapt\225l.[ENTER]Aranyozott cip\245+4 -et kapt\225l.[ENTER]5 Lila italt kapt\225l. "
gameforge.new_quest_lv22._089_say = "Oh, ennek sz\246rny\251 \237ze van. A gy\243gyszer hat\225sa[ENTER]lej\225rt - mennyi ideig tartott, mire ide\233rt\233l[ENTER]vele? Olyan t\245le a nyelvem, mint a sz\225r\237tott[ENTER]majom tr\225gya. "
gameforge.new_quest_lv22._090_say = "Hmm, v\225rj egy percet... \250gy t\251nik, egyre jobb.[ENTER]Igen, haszn\225l! Rendben, ebben az esetben nem[ENTER]leszek sz\251kmark\250. Meg fogod kapni a jutalmad. "
gameforge.new_quest_lv22._091_say = "\218gy t\251nik, elvesz\237tetted a gy\243gyszert. K\233rlek,[ENTER]menj vissza vad\225szni, \233s add \225t az \246sszetev\245ket[ENTER]Baek-Go-nak egy \250j gy\243gyszer el\245\225ll\237t\225s\225hoz.[ENTER]Hamarosan bel\245lem is d\233mon lesz, ha ez a[ENTER]viszket\233s \237gy folytat\243dik tov\225bb. "
gameforge.new_quest_lv22._095_say_reward = "50.000 tapasztalat pontot kapt\225l.[ENTER]8.000 Yangot kapt\225l. "
gameforge.new_quest_lv22._098_say = "Megint elvesz\237tetted a gy\243gyszert? M\233g soha[ENTER]\233letemben nem futottam \246ssze ilyen hozz\225d[ENTER]hasonl\243an sz\243rakozott szem\233llyel! Nos, nem sokat[ENTER]tehet\252nk ez \252gyben. "
gameforge.new_quest_lv22._100_say_reward = "25.000 tapasztalat pontot kapt\225l. "
