gameforge.new_quest_lv26._020_say_title = "Yang-Shin: "
gameforge.new_quest_lv26._020_set_title = "A sz\246kev\233ny "
gameforge.new_quest_lv26._021_say = "Yang-Shin-nek siker\252lt j\243 vad\225szter\252letet[ENTER]tal\225lnia. Keresd fel \233s tudakold meg, hogyan[ENTER]tudn\225l seg\237teni neki. "
gameforge.new_quest_lv26._025_say = "Semmi sem m\251k\246dik m\225r ugyan\250gy, mi\243ta elj\246tt a[ENTER]Metink\246vek ideje. M\233g a vad\225szat is[ENTER]ellehetetlen\252lt sok helyen, mert a vad\225llatok[ENTER]veszettk\233nt kezdtek el viselkedni. Valahol kint[ENTER]\233l a v\225ndor Nakajima, biztos vagyok benne, hogy[ENTER]tudja, merre vannak j\243 vad\225szter\252letek. Fel[ENTER]tudn\225d keresni \245t, hogy megk\233rdezd? "
gameforge.new_quest_lv26._030_target = "Nakajima: "
gameforge.new_quest_lv26._031_say = "Sz\243val j\243 vad\225szter\252letet szeretn\233l tal\225lni? Ne[ENTER]siess annyira, ha m\225r sz\237vess\233get k\233rsz t\245lem,[ENTER]neked is meg kell tenned valamit sz\225momra. "
gameforge.new_quest_lv26._032_say = "Tudnod kell... nem \246nsz\225ntamb\243l \233lek itt. El[ENTER]kellett menek\252ln\246m a hadsereg zaklat\225sai el\245l.[ENTER]Csak rem\233lni merem, hogy a feles\233gem, Ah-Yu[ENTER]tudja, hogy m\233g mindig \233lek. \193tadn\225d neki ezt az[ENTER]\252zenetet? De ne feledd, ezt csak Ah-Yu hallhatja![ENTER]Cser\233be \245 el\225rulja neked, hol cs\243koltam meg[ENTER]el\245sz\246r - ott szeretn\233k vele tal\225lkozni, \233s m\233g[ENTER]vad\225szni is j\243l lehet ott. "
gameforge.new_quest_lv26._034_say_title = "Nakajima: "
gameforge.new_quest_lv26._035_say_title = "Ah-Yu: "
gameforge.new_quest_lv26._036_say_title = "Nakajima keres\233se "
gameforge.new_quest_lv26._037_say = "Nakajima ismerhet n\233h\225ny j\243 vad\225szter\252letet.[ENTER]Keresd fel \245t. "
gameforge.new_quest_lv26._038_say = "Nakajima itt van: %s. "
gameforge.new_quest_lv26._040_say = "Te vagy Nakajima? Yang-Shin k\252ld\246tt! Valami j\243[ENTER]vad\225szter\252letet keres, van esetleg valami[ENTER]\246tleted, hol lehetne kev\233sb\233 vesz\233lyes a[ENTER]vad\225szat? "
gameforge.new_quest_lv26._050_target = "Ah-Yu: "
gameforge.new_quest_lv26._051_say = "Nakajima egy sz\246kev\233ny, \233s most a hadsereg el\245l[ENTER]bujk\225l. Feles\233ge, Ah-Yu azt hiszi, elesett a[ENTER]h\225bor\250ban. Tudasd vele, hogy Nakajima m\233g mindig[ENTER]\233letben van. "
gameforge.new_quest_lv26._052_say = "Ah-Yu itt van: %s. "
gameforge.new_quest_lv26._057_say = "Nakajima... \233l? Az \233n dr\225ga f\233rjem \233l? Nem tudom[ENTER]el\233gg\233 megk\246sz\246nni, hogy ezt elmondtad nekem![ENTER]Amir\245l \245 besz\233lt, az a Yonjang v\246lgyben t\246rt\233nt.[ENTER]Azonnal odavezetlek, \233s ott tal\225lkozunk vele. "
gameforge.new_quest_lv26._058_say = "K\246sz\246n\246m, hogy seg\237tett\233l a tal\225lkoz\225sban. Fogd[ENTER]ezt a r\243zs\225t, ak\225r \225t is adhatod a szerelmednek.[ENTER]\201s most... k\233rlek, bocs\225ss meg, de sietnem kell! "
gameforge.new_quest_lv26._061_say = "A Yonjang v\246lgy - ahol Nakajima \233s Ah-Yu el\245sz\246r[ENTER]cs\243kolt\225k meg egym\225st - m\233g mindig nagyon j\243[ENTER]vad\225szter\252let. "
gameforge.new_quest_lv26._062_say = "Yang-Shin \246r\246mmel fogja hallani ezt. Menj ide:[ENTER]%s, \233s oszd meg vele a j\243 h\237rt. "
gameforge.new_quest_lv26._063_say = "A Yonjang v\246lgy? Hihet\245en hangzik, mert m\233g soha[ENTER]nem hallottam arr\243l, hogy Metink\246vek szennyezt\233k[ENTER]volna azt a ter\252letet. Rem\233lhet\245en ott k\233pes[ENTER]leszek nagy zs\225km\225ny elejt\233s\233re! Tess\233k,[ENTER]meg\233rdemled ezt a jutalmat. "
gameforge.new_quest_lv26._064_sayReward = "35.000 tapasztalat pontot kapt\225l. "
gameforge.new_quest_lv26._065_sayReward = "17.500 Yangot kapt\225l. "
