gameforge.new_quest_lv28._010_target = "Yu-Hwan:  "
gameforge.new_quest_lv28._011_say = "A zen\233sz Yu-Hwannak sz\252ks\233ge van a seg\237ts\233gedre.[ENTER]Menj gyorsan, \233s der\237tsd ki, mi\233rt! "
gameforge.new_quest_lv28._015_npcChat = "Ah-Yu gondja "
gameforge.new_quest_lv28._016_say = "\218gy t\251nik, Ah-Yu gondolkodik valamin, amit nem[ENTER]akar elmondani Yu-Hwan-nak. L\225togasd meg, \233s[ENTER]l\225ssuk, megny\237lik-e neked. "
gameforge.new_quest_lv28._017_say = "Ah-Yu itt van: %s. "
gameforge.new_quest_lv28._018_select = "Hamarosan besz\233lek Ah-Yu-val! "
gameforge.new_quest_lv28._019_say_title = "Ah-Yu: "
gameforge.new_quest_lv28._020_say_title = "Yu-Hwan:  "
gameforge.new_quest_lv28._021_say = "Ismered Ah-Yu-t? Gy\243gyn\246v\233nyeket gy\251jt a[ENTER]b\225jitalaim sz\225m\225ra. R\233gebben j\243kedv\251 volt, de[ENTER]tegnap \250gy t\251nt, teljesen bez\225rk\243zott. Nem akarja[ENTER]elmondani, mi j\225r a fej\233ben, tal\225n mert m\225r nem[ENTER]akar nekem dolgozni? K\233rlek, menj el hozz\225, \233s[ENTER]n\233zd meg, hogy van. Tal\225n megny\237lik el\245tted! "
gameforge.new_quest_lv28._022_say = "Nagyon kedves, hogy Yu-Hwan agg\243dik \233rtem. De[ENTER]igen, van valami, ami elgondolkodtat... Nem[ENTER]akartam besz\233lni r\243la, de ez megnehez\237ti az[ENTER]\233letem! Yang-Shin-r\245l van sz\243, a Vad\225szr\243l.[ENTER]Elkezdett zsarolni engem, mi\243ta kital\225lta, hogy[ENTER]Nakajima, a f\233rjem egy sz\246kev\233ny. Yang-Shin azzal[ENTER]fenyeget, hogy el\225rulja \245t! \201s akkor meg\246lik[ENTER]\245t... "
gameforge.new_quest_lv28._023_say = "Ez alkalommal Medve mancsot k\246vetel a hallgat\225sa[ENTER]fej\233ben. De most nem mehetek ki vad\225szni. Tudn\225l[ENTER]seg\237teni megadni Yang-Shin-nek, amit akar? "
gameforge.new_quest_lv28._024_set_title = "Medvevad\225szat "
gameforge.new_quest_lv28._025_notice = "Gyer\252nk vad\225szni! Bera meg\246l\233se a legjobb m\243dja[ENTER]Medve mancshoz jutni. "
gameforge.new_quest_lv28._026_notice = "Szereztem egy Medve mancsot! "
gameforge.new_quest_lv28._027_notice = "El\233gnek kell lennie. Ir\225ny Yang-Shin! "
gameforge.new_quest_lv28._028_notice = "Ez a Medve mancs haszn\225lhatatlan. "
gameforge.new_quest_lv28._029_say = "Sz\252ks\233ged van tov\225bbi %s x Medve mancsra. "
gameforge.new_quest_lv28._031_say_reward = "Vad\225sznod kell: "
gameforge.new_quest_lv28._032_say = "Ah-Yu megk\233rt, hogy teljes\237tsd Yang-Shin[ENTER]k\246vetel\233s\233t. "
gameforge.new_quest_lv28._032_say_reward = "Kell m\233g tov\225bbi %s x Medve mancs.[ENTER]Vad\225ssz Bera-ra, hogy megszerezd. "
gameforge.new_quest_lv28._035_target = "Yang-Shin: "
gameforge.new_quest_lv28._036_say = "Megszerezted a k\233rt Medve mancsot. Vidd el[ENTER]Yang-Shin-nek, hogy kifizesd Ah-Yu ad\243ss\225g\225t. "
