gameforge.new_quest_lv28._038_say_title = "Yang-Shin: "
gameforge.new_quest_lv28._040_npcChat = "A zsarol\225s "
gameforge.new_quest_lv28._041_say_title = "Medve mancs "
gameforge.new_quest_lv28._042_say = "Hozt\225l nekem egy kis Medve mancsot? K\233rlek, ne[ENTER]gondolj rosszat r\243lam! Neh\233z id\245kben \233l\252nk, \233s[ENTER]meg kell \233lnem most is, amikor a vad\225szat annyira[ENTER]neh\233z, mi\243ta a Metink\246vek miatt az \225llatok[ENTER]v\233rengz\245 fenevadakk\225 v\225ltak. A vad\225szok \233lete m\233g[ENTER]soha nem volt ennyire vesz\233lyes. "
gameforge.new_quest_lv28._043_say = "K\233rlek, mondd meg Ah-Yu-nak, nem kell agg\243dnia.[ENTER]Sz\225m\237that r\225. Legal\225bbis am\237g \250jra sz\252ks\233gem nem[ENTER]lesz valamire... hehehe! "
gameforge.new_quest_lv28._044_say = "Micsoda, zs\225km\225ny n\233lk\252l akart\225l becsapni? Nekem[ENTER]friss medve mancs kell! "
gameforge.new_quest_lv28._045_say_reward = "Kedves t\245led, hogy seg\237tesz Ah-Yu-nak. De ez azt[ENTER]jelenti, neked is azt kell tenned, amit mondok.[ENTER]Menj, \233s vissza ne gyere k\233t Medve mancs n\233lk\252l! "
gameforge.new_quest_lv28._046_say = "Add \225t Ah-Yu-nak az \252zenetet, hogy Yang-Shin nem[ENTER]zsarolja t\246bb\233, mert seg\237tett\233l neki. "
gameforge.new_quest_lv28._051_say = "Te van a megment\245nk! V\233gtelen\252l h\225l\225s vagyok![ENTER]Tess\233k, ez az \246sszes Yangom. Nem t\250l sok, de[ENTER]meg\233rdemled. "
gameforge.new_quest_lv28._055_1_select = "K\246sz\246n\246m, nagyon j\243l j\246n! "
gameforge.new_quest_lv28._055_2_select = "Nem, nem fogadhatom el. "
gameforge.new_quest_lv28._056_say = "Ez mindenem. De meg\233ri, ha megszabadulok ett\245l az[ENTER]embertelen gyilkost\243l. "
gameforge.new_quest_lv28._057_say = "Oh, k\246sz\246n\246m! Ott a helyed a S\225rk\225nyisten oldal\225n! "
gameforge.new_quest_lv28._058_say_reward = "%s Yangot kapt\225l. "
gameforge.new_quest_lv28._059_say_reward = "%s tapasztalat pontot kapt\225l. "
gameforge.new_quest_lv28._070_say = "Sz\252ks\233gem van: "
gameforge.new_quest_lv29 = {}
gameforge.new_quest_lv29._010_target = "Yonah : "
gameforge.new_quest_lv29._015_npcChat = "A t\246r\246tt porcel\225n "
gameforge.new_quest_lv29._020_say_title = "Yonah : "
gameforge.new_quest_lv29._021_say = "A szeretett Halv\225nyz\246ld porcel\225nom! H\225rom[ENTER]gener\225ci\243 \243ta van a csal\225dom tulajdon\225ban, \233s[ENTER]most elt\246r\246tt h\225rom \233rt\233kes v\225z\225m. L\225ttam, hogy[ENTER]az a semmirekell\245 Taurean l\243fr\225lt a rakt\225r[ENTER]k\246zel\233ben. Biztos vagyok benne, hogy \245 az oka! "
gameforge.new_quest_lv29._022_say = "Nem ez lenne az els\245 ostoba dolog, amit tett, de[ENTER]ez m\225r t\233nyleg \225tl\233pi a hat\225rt. Valakinek m\243resre[ENTER]kell tan\237tania! Van r\225 id\245d? "
gameforge.new_quest_lv29._023_1_select = "\214r\246mmel "
gameforge.new_quest_lv29._023_2_select = "Ez nem az \233n dolgom "
gameforge.new_quest_lv29._024_say = "Nincs id\245m neveletlen k\246lyk\246k megleck\233ztet\233s\233re.[ENTER]Neked kell rendezned vele. Azonban k\233tlem, hogy[ENTER]neked siker\252lne... "
gameforge.new_quest_lv29._030_target = "Taurean : "
gameforge.new_quest_lv29._031_say = "Elt\246r\246tt Yonah \233rt\233kes csal\225di \246r\246ks\233g\233b\245l h\225rom,[ENTER]Halv\225nyz\246ld porcel\225nb\243l k\233sz\252lt v\225za. Azt hiszi,[ENTER]Taurean a hib\225s. Menj Taurean-hoz, \233s der\237tsd ki. "
gameforge.new_quest_lv29._032_say = "Taurean itt van: %s. "
gameforge.new_quest_lv29._033_say_title = "Taurean : "
gameforge.new_quest_lv29._034_say_reward = "Mi\233rt n\233zel \237gy r\225m? \201n nem csin\225ltam semmit... "
gameforge.new_quest_lv29._035_say_reward = "Mit tett\233l Yonah v\225z\225ival? "
gameforge.new_quest_lv29._036_say_reward = "V\225z\225k? Yonah? Azt sem tudom, mir\245l besz\233lsz! "
gameforge.new_quest_lv29._037_say_reward = "Akkor magyar\225zd el nekem \250jra, k\233rlek, mi\233rt t\246rt[ENTER]el h\225rom v\225za. "
gameforge.new_quest_lv29._038_say_reward = "Esk\252sz\246m, nem voltam semmilyen v\225za k\246zel\233ben ma,[ENTER]\233s nem l\225ttam Yonah-t sem. Ami azt illeti, eg\233sz[ENTER]nap Harang-gal veszekedtem. M\233g a pajt\225ba is[ENTER]bez\225rt egy id\245re! K\233rdezd csak meg \245t, ha nem[ENTER]hiszel nekem! "
gameforge.new_quest_lv29._040_target = "Harang: "
gameforge.new_quest_lv29._041_say = "Taurean azt \225ll\237tja, \225rtatlan. Eg\233sz nap[ENTER]Harang-gal j\225tszott, \233s nem t\246rhette el a[ENTER]v\225z\225kat. Menj Harang-hoz, \233s k\233rdezd meg, mi az[ENTER]igazs\225g. "
gameforge.new_quest_lv29._042_say_reward = "Harang, l\225ttad Taurean-t mostan\225ban? "
gameforge.new_quest_lv29._043_say_title = "Harang: "
gameforge.new_quest_lv29._044_say_reward = "Taurean-t? Igen, eg\233sz nap j\225tszottunk. Valami[ENTER]baj t\246rt\233nt? "
gameforge.new_quest_lv29._045_say_reward = "Yonah azt mondja, Taurean elt\246rte h\225rom v\225z\225j\225t. "
gameforge.new_quest_lv29._046_say_reward = "Jonah durva. Mindig elkerget benn\252nket, ah\225nyszor[ENTER]csak a k\246zel\233be ker\252l\252nk. Mindig a porcel\225njai[ENTER]miatt agg\243dik. A bar\225tja, a Lov\225szinas az[ENTER]egyetlen szem\233ly, aki meg\233rintheti a dr\225ga[ENTER]v\225z\225it. Tal\225n \245 t\246rte el?! "
gameforge.new_quest_lv29._047_say = "Harang itt van: %s. "
gameforge.new_quest_lv29._050_target = "Lov\225szinas "
gameforge.new_quest_lv29._051_say = "Harang meger\245s\237tette, hogy Taurean \225rtatlan. De[ENTER]lehet, \246sszej\225tszanak egym\225ssal. Miel\245tt d\246ntesz[ENTER]az \252gyben, besz\233lned kell Yonah bar\225tj\225val, a[ENTER]Lov\225szinassal. "
gameforge.new_quest_lv29._052_say = "Oh, a j\243 \246reg Yonah. Annyira agg\243dik a[ENTER]porcel\225njai miatt, hogy a falusi gyerekeket[ENTER]hib\225ztatja. Nem veszi \233szre, hogy a Metink\246vek a[ENTER]hib\225sak - ami\243ta elkezdt\233k m\233rgezni haz\225nkat, a[ENTER]forr\225saink m\225r nem olyanok, mint r\233gen voltak.[ENTER]M\233g a porcel\225nok is elkezdtek t\246redezni. De Yonah[ENTER]csak nem hajland\243 elhinni... "
gameforge.new_quest_lv29._053_say = "Ha \246sszegy\251jten\233l neki egy kis sz\233n\225t, egy kicsit[ENTER]jobban kib\233lelhetn\233 vele a porcel\225nokat[ENTER]tartalmaz\243 l\225d\225it. Biztos vagyok benne, hogy ez[ENTER]j\243 m\243d a kiengesztel\233s\233re. "
gameforge.new_quest_lv29._054_say = "A Lov\225szinas itt van:[ENTER]%s vagy %s. "
gameforge.new_quest_lv29._061_say = "Nyilv\225nval\243an nem Taurean hib\225j\225b\243l t\246rtek el[ENTER]Yonah v\225z\225i. Ez a gonosz Metink\246vek kisug\225rz\225sa,[ENTER]ami mindent ridegg\233 tesz.[ENTER]Gy\251jts sz\233n\225t Yonah-nak, hogy a porcel\225njait[ENTER]gondosabban tudja t\225rolni! Biztos vagyok benne,[ENTER]hogy n\233melyik falusi tudna adni valamennyit. "
gameforge.new_quest_lv29._062_say = "Megtal\225lod %s-t \233s %s-t a v\225roskapuk el\245tt.[ENTER]Szalmakalapot viselnek, amib\245l elegend\245 sz\233n\225hoz[ENTER]juthatsz. "
gameforge.new_quest_lv29._063_notice = "Ebb\245l sz\233p k\246teg sz\233n\225hoz jutok. M\225r csak tov\225bbi[ENTER]%s sz\233na hi\225nyzik. "
gameforge.new_quest_lv29._064_notice = "Ez a kalap nem szalm\225b\243l, hanem k\243kuszrostb\243l[ENTER]k\233sz\252lt. Sz\225momra haszn\225lhatatlan. "
gameforge.new_quest_lv29._065_1_say = "L\225tom, van egy csom\243 sz\233n\225d. Biztos vagyok benne,[ENTER]hogy Yonah megnyugszik v\233gre, ha neki adod egy[ENTER]r\233sz\233t. "
gameforge.new_quest_lv29._065_notice = "Ez a kalap nem szalm\225b\243l, hanem k\243kuszrostb\243l[ENTER]k\233sz\252lt. \201s el\233gg\233 megrong\225l\243dott... "
gameforge.new_quest_lv29._066_say = "Vad\225szhatsz Vad gyalogs\225gi katon\225kra vagy Er\245s[ENTER]vad gyalogosokra is. A szalmakalapjukb\243l sz\233n\225hoz[ENTER]juthatsz. "
gameforge.new_quest_lv29._067_say_reward = "\214sszegy\251jt\246tt\233l %s k\246teg Sz\233n\225t a %s-b\245l. "
gameforge.new_quest_lv29._068_notice = "Egy k\246teg sz\233n\225t zs\225km\225nyolt\225l. "
gameforge.new_quest_lv29._070_npcChat = "A sz\233naboglya "
gameforge.new_quest_lv29._071_say_reward = "Taurean, kor\225bban eml\237tetted, hogy a k\246zelben[ENTER]tal\225lt\225l egy sz\233nakazlat. Nem hozt\225l magaddal[ENTER]v\233letlen\252l egy kis sz\233n\225t? "
gameforge.new_quest_lv29._072_say_reward = "Haha, l\225ssuk... ez volt az \246sszes a hajamban \233s a[ENTER]cip\245mben. L\225tod? M\233g itt is van egy kicsi,[ENTER]tess\233k! "
gameforge.new_quest_lv29._073_notice = "Nem t\250l sok Sz\233na, de el\233gnek kellene lennie egy[ENTER]kis k\246teghez. M\225r csak %s hi\225nyzik. "
gameforge.new_quest_lv29._074_say_reward = "Nem \233n voltam, esk\252sz\246m! Nem mondta Harang, hogy[ENTER]a sz\233nakazalban verekedt\252nk? "
gameforge.new_quest_lv29._075_say_reward = "A sz\233nakazal k\246zel\233ben volt\225l, vagy nem? Nem[ENTER]hozt\225l magaddal v\233letlen\252l onnan egy kis sz\233n\225t? "
gameforge.new_quest_lv29._076_say_reward = "Honnan tudsz a sz\233nakazalr\243l? Micsoda, m\233g mindig[ENTER]sz\233na van a ruh\225mon? Oh igen, itt egy kev\233s. "
gameforge.new_quest_lv29._077_say_reward = "Megkaphatom? "
gameforge.new_quest_lv29._078_say_reward = "Azt hiszem, igen... "
gameforge.new_quest_lv29._079_say_reward = "Erre most nincs id\245m. Mennem kell megnyugtatni[ENTER]Taurean-t az eg\233sz v\225z\225s \252gy miatt! "
gameforge.new_quest_lv29._080_npcChat = "Sz\233na Yonah-nak "
gameforge.new_quest_lv29._081_say_reward = "Van egy kis szertesz\233t sz\233na az ist\225ll\243ban, amit[ENTER]el tudn\233k vinni Yonah-nak? "
gameforge.new_quest_lv29._082_say_title = "Lov\225szinas "
gameforge.new_quest_lv29._083_say_reward = "Nincs sok sz\233n\225nk. A vad\225llatok \233s a v\225roson[ENTER]k\237v\252l \233l\245 bandit\225k megakad\225lyozz\225k, hogy t\246bbet[ENTER]kasz\225ljunk. "
gameforge.new_quest_lv29._084_say_reward = "De tudok adni egy kicsit! "
gameforge.new_quest_lv29._085_notice = "Ez igaz\225n nem t\250l sok, de legal\225bb elegend\245 egy[ENTER]k\246teghez. Most m\225r csak %s hi\225nyzik. "
gameforge.new_quest_lv29._086_say_reward = "Att\243l tartok, semmi m\225st nem tehetek \233rted. "
gameforge.new_quest_lv29._090_send_letter = "Ver\233s helyett sz\233na "
gameforge.new_quest_lv29._091_say = "Elegend\245 sz\233n\225t gy\251jt\246tt\233l Yonah-nak. Menj ide:[ENTER]%s, \233s add \225t neki. "
gameforge.new_quest_lv29._101_say_reward = "Nem Taurean hib\225ja. A Metink\246vekb\245l \225rad\243[ENTER]sug\225rz\225s t\246r\233kenny\233 teszi a porcel\225nt. "
gameforge.new_quest_lv29._102_say_title = "Yonah : "
gameforge.new_quest_lv29._103_say_reward = "Mit mondasz? Ez teljesen lehetetlen, az a[ENTER]semmirekell\245 hazudott neked! "
gameforge.new_quest_lv29._104_say_reward = "Taurean Harang-gal j\225tszott a sz\233nakazalban eg\233sz[ENTER]nap. "
gameforge.new_quest_lv29._105_say_reward = "Szeretn\233m \225tadni a bar\225tod, a Lov\225szinas[ENTER]\252dv\246zlet\233t, \233s hoztam egy kis sz\233n\225t is, ami[ENTER]seg\237t meg\243vni a v\225z\225idat. "
gameforge.new_quest_lv29._106_say_reward = "Bevallom, kicsit zavarba j\246ttem a saj\225t[ENTER]reakci\243mt\243l. De tudnod kell, nagyon ragaszkodom a[ENTER]porcel\225njaimhoz, mert kellemes eml\233keket id\233znek[ENTER]a csal\225domr\243l. Amikor egy v\225za elt\246rik, az nekem[ENTER]t\246bb, mint puszt\225n egy t\225rgy elveszt\233se... "
gameforge.new_quest_lv29._107_say_reward = "Bocs\225natot k\233rek t\245led \233s Taurean-t\243l. Itt egy[ENTER]kis jutalom a f\225radoz\225sod\233rt. "
gameforge.new_quest_lv29._108_notice = "%s tapasztalat pont b\243nuszt kapt\225l! "
gameforge.new_quest_lv29._109_say_reward = "Szeretn\233m \225tadni a bar\225tod, a Lov\225szinas[ENTER]\252dv\246zlet\233t, \233s hoztam egy kis sz\233n\225t is, ami[ENTER]seg\237t meg\243vni a v\225z\225idat. "
gameforge.new_quest_lv29._110_say_reward = "Ez nagyon kedves t\245led, de tudn\225l m\233g hozni m\225sik[ENTER]%s k\246teg sz\233n\225t is, hogy a v\225z\225im val\243ban[ENTER]biztons\225gban legyenek? "
gameforge.new_quest_lv29._111_say_reward = "Azt hiszem, neh\233z lesz t\246bb sz\233n\225t tal\225lni. De a[ENTER]v\225z\225im szinte szentek nekem. Hihetetlen\252l h\225l\225s[ENTER]lenn\233k, ha tudn\225l m\233g hozni nekem valamennyit, \233s[ENTER]adn\233k \233rte n\233h\225ny Yangot is. "
gameforge.new_quest_lv29._112_say_reward = "Ez a Harang k\246ly\246k nyilv\225n \246sszej\225tszik[ENTER]Taurean-nal. "
gameforge.new_quest_lv29._113_say_reward = "\218gy l\225tszik, senki nem hisz nekem, amikor azt[ENTER]mondom, hogy l\225ttam azt a fi\250t kor\225bban a rakt\225r[ENTER]k\246r\252l t\233bl\225bolni. "
gameforge.new_quest_lv29._114_say_reward = "Minden rendben. Itt van egy kis k\225rt\233r\237t\233s a[ENTER]f\225radoz\225sod\233rt. "
gameforge.new_quest_lv29._115_say_reward = "Tess\233k, %s Yang. "
gameforge.new_quest_lv42 = {}
gameforge.new_quest_lv42._010_send_letter = "Grumgrrr "
gameforge.new_quest_lv42._020_target = "Octavio: "
gameforge.new_quest_lv42._021_say = "Olyan hangos a gyomrom, mint egy V\246r\246s vaddiszn\243.[ENTER]Lehet, meg kellene l\225togatnom Octavio-t. \213[ENTER]k\233sz\237ti a legjobb hal\225szl\233t a k\246rny\233ken. "
gameforge.new_quest_lv42._022_say_title = "Octavio: "
gameforge.new_quest_lv42._023_say = "Szeretn\233l egy kis hal\225szl\233t? Csak ez j\225r a[ENTER]fejedben? Oh, sajn\225lom, a konyh\225m napok \243ta nem[ENTER]l\225tott halat. \193ltal\225ban a hal\225sz fantasztikus[ENTER]m\233lytengeri halakat sz\225ll\237t a hal\225szlevemhez. "
gameforge.new_quest_lv42._024_say = "Viszont napok \243ta nem j\225rt errefel\233. Esetleg el[ENTER]tudn\225l menni hozz\225 megk\233rdezni, mi folyik itt? "
gameforge.new_quest_lv42._025_say = "Octavio itt van: %s. "
gameforge.new_quest_lv42._026_select = "Megyek, megkeresem a Hal\225szt! "
gameforge.new_quest_lv42._030_target = "Hal\225sz: "
gameforge.new_quest_lv42._031_say = "V\233ge a nyugodt tengeren t\246lt\246tt napoknak! A[ENTER]hal\225szok elt\251n\245ben vannak, ez sz\246rny\251! Mi\243ta[ENTER]Metink\246vek estek a tengerbe, a valaha b\233k\233s[ENTER]b\225ln\225k brut\225lis tengeri sz\246rnyekk\233 alakultak. A[ENTER]hal\225szat vesz\233lyes foglalkoz\225ss\225 v\225lt. "
gameforge.new_quest_lv42._032_say = "Szigonyaink nem tudnak t\246bb\233 \225rtani a b\225ln\225knak.[ENTER]Kem\233nyebb a b\245r\252k, mint egy Ogre b\245re. "
gameforge.new_quest_lv42._033_say = "Tal\225n Yonah tudja, mit kell tenni. \201veken[ENTER]kereszt\252l gyakran j\225rt a tengerre b\225ln\225kra[ENTER]vad\225szni. "
gameforge.new_quest_lv42._034_say_title = "Hal\225sz: "
gameforge.new_quest_lv42._035_say = "Octavio v\225rja a m\233lytengeri halait. K\233rdezd meg a[ENTER]Hal\225szt, mi\233rt k\233sik a sz\225ll\237tm\225ny. "
gameforge.new_quest_lv42._036_say = "A Hal\225sz itt van: %s. "
gameforge.new_quest_lv42._037_send_letter = "D\252h\246s tengeri sz\246rnyek "
gameforge.new_quest_lv42._038_say = "Megk\233rt a Hal\225sz, k\233rj tan\225csot Yonah-t\243l, hogyan[ENTER]kell a gonosz b\225ln\225kra vad\225szni. "
gameforge.new_quest_lv42._039_say = "Yonah itt van: %s. "
gameforge.new_quest_lv42._040_target = "Yonah : "
gameforge.new_quest_lv42._041_say = "Hallottam, mi t\246rt\233nt a b\225ln\225kkal. Ez rossz \252zlet[ENTER]a Hal\225szoknak. M\233g ha ki is mer\233szkednek a[ENTER]tengerre, a szigonyaik t\250l gyeng\233k \225tszak\237tani a[ENTER]b\225ln\225k b\245r\233t. Amikor b\225lnavad\225sz haj\243n dolgoztam,[ENTER]k\252l\246nleges fegyvereket haszn\225ltunk az \246reg \233s[ENTER]sebhelyes b\225ln\225k ellen. Azok k\233pesek voltak[ENTER]\225thatolni mindenen... "
gameforge.new_quest_lv42._042_say = "Ez egy k\252l\246nleges elj\225r\225s a b\225lnavad\225sz szigonyok[ENTER]meger\245s\237t\233s\233re. A Kov\225cs az egyetlen ember, aki[ENTER]tud ilyen t\237pus\250 szigonyt k\233sz\237teni. "
gameforge.new_quest_lv42._043_say_reward = "Menj a kov\225cshoz "
gameforge.new_quest_lv42._044_say_title = "Yonah : "
gameforge.new_quest_lv42._045_say = "Yonah nagyon er\245s \233s \233les l\225ndzs\225k haszn\225lat\225t[ENTER]aj\225nlja a b\225lnavad\225szathoz. Menj a Kov\225cshoz, \233s[ENTER]k\233rdezd meg, k\233sz\237tene-e n\233h\225ny ilyen szigonyt. "
gameforge.new_quest_lv42._050_target = "Kov\225cs "
gameforge.new_quest_lv42._051_say = "Igen, hallottam azokr\243l a szigonyokr\243l, \233s[ENTER]k\233sz\237tettem is olyanokat. Viszont ahhoz, hogy[ENTER]megkapj\225k a sz\252ks\233ges tart\243ss\225gukat, egy Gy\233m\225nt[ENTER]k\245re van sz\252ks\233gem. "
gameforge.new_quest_lv42._052_say = "Sz\252ks\233gem van: "
gameforge.new_quest_lv42._053_say_reward = "Elj\225r\225s: "
gameforge.new_quest_lv42._054_say_title = "Kov\225cs "
gameforge.new_quest_lv42._060_set_title = "Gy\233m\225nt k\245 "
gameforge.new_quest_lv42._061_notice = "L\225ssuk csak. Sz\252ks\233gem van egy Cs\225k\225nyra az \233rc[ENTER]b\225ny\225szat\225hoz. K\237v\225ncsi vagyok, az eny\233m[ENTER]megfelel\245-e, vagy Deokbae ink\225bb ad egy \250jat? "
gameforge.new_quest_lv42._062_say = "Sz\252ks\233ged van tov\225bbi %s x Gy\233m\225nt k\245re. "
gameforge.new_quest_lv42._063_say = "Megvan mindened, ami kell. Most gyorsan menj[ENTER]vissza a Kov\225cshoz. "
gameforge.new_quest_lv42._064_say = "Nagyszer\251, most m\225r megvan minden, ami kell.[ENTER]Gyere vissza holnap ilyenkor a szigony\233rt. Az[ENTER]ilyen vasat k\246r\252ltekint\245en kell kov\225csolni. "
gameforge.new_quest_lv42._065_say = "Gy\233m\225nt k\245h\246z \250gy juthatsz, ha Cs\225k\225nnyal \252t\246d a[ENTER]Gy\233m\225nt erezetet. "
gameforge.new_quest_lv42._066_say = "A Kov\225csnak sz\252ks\233ge van Gy\233m\225nt k\245re, hogy[ENTER]elk\233sz\237tse a k\252l\246nleges b\225lnavad\225sz[ENTER]szigonyt.Keress Gy\233m\225nt eret, amib\245l Gy\233m\225nt[ENTER]k\246vet b\225ny\225szhatsz. Ha nincs Cs\225k\225nyod a[ENTER]b\225ny\225szathoz, v\225s\225rolj egyet Deokbae-t\245l. "
gameforge.new_quest_lv42._067_say = "A Kov\225cs itt van: %s. "
gameforge.new_quest_lv42._068_say = "Sz\252ks\233g\252nk van tov\225bbi %s x Gy\233m\225nt k\245re, miel\245tt[ENTER]elkezd\252nk dolgozni a szigonyokon. "
gameforge.new_quest_lv42._070_set_title = "A szigonyok "
gameforge.new_quest_lv42._071_set_clock = "V\225rakoz\225si id\245 "
gameforge.new_quest_lv42._072_say = "A Kov\225csnak m\225r be kellett fejeznie. Menj el[ENTER]hozz\225, \233s vedd \225t a k\252l\246nleges b\225lnavad\225sz[ENTER]szigonyokat. "
gameforge.new_quest_lv42._073_say = "A szigonyok m\233g nincsenek k\233szen. Egy kicsit[ENTER]t\252relmesebbnek kellene lenned. "
gameforge.new_quest_lv42._074_say = "Itt vannak a szigonyaid. Add \225t a Hal\225sznak. "
gameforge.new_quest_lv42._075_say = "M\225r k\233rtelek, hogy v\225rj addig, am\237g elk\233sz\252lnek a[ENTER]szigonyok. Gyere vissza k\233s\245bb. "
gameforge.new_quest_lv42._079_say = "Kapt\225l n\233h\225ny b\225lnavad\225sz szigonyt a Kov\225cst\243l.[ENTER]Add \225t a Hal\225sznak. "
gameforge.new_quest_lv42._080_say = "Nagyszer\251! Ezek a szigonyok igaz\225n leny\251g\246z\245ek![ENTER]Most m\225r meg tudjuk v\233deni magunkat a b\225ln\225k[ENTER]t\225mad\225s\225t\243l. K\233rlek, tudasd Octavio-val, hogy[ENTER]hamarosan lesz \250jra friss hala! "
gameforge.new_quest_lv42._081_say_reward = "500.000 Yangot kapt\225l. "
gameforge.new_quest_lv42._082_say_reward = "K\252l\246nleges elismer\233s\252l kapt\225l 3x: "
gameforge.new_quest_lv42._083_say = "Ezek nem elegend\245k egy b\225lna leter\237t\233s\233hez. Csak[ENTER]ahhoz elegek, hogy csiklandozz\225k a test\252ket. "
gameforge.new_quest_lv42._084_say_reward = "K\233rlek, menj vissza \250jra a Kov\225cshoz, \233s k\233rd[ENTER]meg, hogy kov\225csoljon m\233g t\246bb szigonyt. "
gameforge.new_quest_lv42._090_say = "A hal\225sz j\243l felszerelt, \233s most m\225r \250jra tud[ENTER]vad\225szni a ny\237lt tengeren. Menj Octavio-hoz, \233s[ENTER]pr\243b\225ld biztos\237tani arr\243l, hogy hamarosan[ENTER]megkapja az \250j sz\225ll\237tm\225nyt. "
gameforge.new_quest_lv42._095_say = "Mit mondasz? A b\233k\233s b\225ln\225k agressz\237v tengeri[ENTER]sz\246rnyekk\233 v\225ltak? Ez sz\246rny\251... K\246sz\246n\246m, hogy[ENTER]seg\237tett\233l a Hal\225sznak. A men\252m jelent\245s r\233sze a[ENTER]sz\225ll\237tm\225nyaikt\243l f\252gg. "
gameforge.new_quest_lv42._096_say = "Oh, \233s ami a korg\243 gyomrodat illeti:[ENTER]Term\233szetesen aj\225nlhatom neked a hal\225szl\233t, de[ENTER]nem szeretn\233l ink\225bb egy kis szusit? "
gameforge.new_quest_lv42._098_say_reward = "750.000 tapasztalat pontot kapt\225l.[ENTER]Kapt\225l 2 darab Szusit. "
gameforge.new_quest_lv43 = {}
gameforge.new_quest_lv43._005_send_letter = "L\225togat\225s Wonda-Rim-n\233l "
gameforge.new_quest_lv43._006_send_letter = "Az \225rva "
gameforge.new_quest_lv43._010_target = "Wonda-Rim: "
gameforge.new_quest_lv43._011_say = "Hossz\250 ideje nem hallott\225l Wonda-Rim-r\245l. Javult[ENTER]a kapcsolata a nagyb\225tyj\225val, \233s tal\225n m\225r el is[ENTER]felejtett\233k a Mu-Rang pr\233mhez kapcsol\243d\243[ENTER]t\246rt\233netet. Mi\233rt nem l\225togatod meg \245t? "
gameforge.new_quest_lv43._012_say = "Wonda-Rim itt van: %s. "
gameforge.new_quest_lv43._020_say = "Kedves t\245led, hogy visszan\233zt\233l. "
gameforge.new_quest_lv43._021_say_title = "Wonda-Rim: "
gameforge.new_quest_lv43._022_say = "Chaegirab nagyb\225ty\225mn\225l n\245ttem fel. Mindig j\243[ENTER]volt a kapcsolatunk... de amikor a sz\252leimr\245l[ENTER]k\233rdezem, mindig elker\252li a k\233rd\233st. Meghaltak,[ENTER]de ez minden, amit mond. "
gameforge.new_quest_lv43._023_say_reward = "Egy napon szeretn\233k majd megh\225zasodni \233s csal\225dot[ENTER]alap\237tani, \237gy t\233nyleg szeretn\233m tudni, honnan[ENTER]sz\225rmazom. Tudn\225l besz\233lni a nagyb\225ty\225mmal, \233s[ENTER]k\233rdezni \245t a sz\252leimr\245l? De k\233rlek, ne mondd el[ENTER]neki, hogy \233n k\252ldtelek. "
gameforge.new_quest_lv43._024_select = "Besz\233lni fogok vele! "
gameforge.new_quest_lv43._025_say = "Wonda-Rim nem Chaegirab biol\243gus unoka\246ccse, \245[ENTER]csak felnevelte. Most itt az ideje, hogy[ENTER]megtudja, kik is a val\243di sz\252lei. K\233rdezd[ENTER]Chaegirab-ot Wonda-Rim sz\225rmaz\225s\225r\243l. "
gameforge.new_quest_lv43._026_say = "Chaegirab itt van: %s. "
gameforge.new_quest_lv43._030_target = "Chaegirab: "
gameforge.new_quest_lv43._031_say_title = "Chaegirab: "
gameforge.new_quest_lv43._032_say = "Wonda-Rim... nem, nem \233n vagyok a biol\243giai[ENTER]nagyb\225tyja. \201n nem ismerem a sz\252leit. \211vtam \245t az[ENTER]igazs\225gt\243l, mert eddig nem gondoltam, hogy k\233szen[ENTER]\225llna r\225, hogy megtudja. De tal\225n v\233gre elj\246tt az[ENTER]az id\245. "
gameforge.new_quest_lv43._033_say = "A Seungryong-v\246lgyben tal\225ltam \245t egy Ork harcos[ENTER]hord\225n\225l. Ha m\233g mindig van m\243d megtudni b\225rmit[ENTER]is Wonda-Rim sz\225rmaz\225s\225r\243l, akkor azt az Orkokt\243l[ENTER]kell megtudnod. "
gameforge.new_quest_lv43._034_say = "Lehet, hogy szigor\250 vagyok vele, de mindig a[ENTER]nagyb\225tyja maradok. M\233g akkor is, ha semmirekell\245[ENTER]marad. "
gameforge.new_quest_lv43._035_say_reward = "Menj a Seungryong-v\246lgybe \233s vad\225ssz addig Ork[ENTER]harcosokra, am\237g nem tal\225lsz valami nyomot[ENTER]Wonda-Rim sz\225rmaz\225s\225val kapcsolatban. "
gameforge.new_quest_lv43._036_say = "Felfedezt\233l egy r\233gi levelet az egyik meg\246lt Ork[ENTER]harcos piszkos zs\225kj\225ban. Ez alig megfejthet\245,[ENTER]csak a Wonda-Rim nevet tudod felismerni rajta. Ez[ENTER]a bizony\237t\233k, amit kerest\233l, sz\243val menj, \233s add[ENTER]\225t Wonda-Rim-nek. "
gameforge.new_quest_lv43._041_say = "Gyer\252nk! A legnagyobb es\233llyel akkor tal\225lsz[ENTER]valamit Wonda-Rim sz\225rmaz\225s\225r\243l, ha Ork[ENTER]harcosokra vad\225szol. Lehet, hogy szolg\225ltatnak[ENTER]valami bizony\237t\233kot! "
gameforge.new_quest_lv43._043_notice = "Nyomok Wonda-Rim-r\245l... "
gameforge.new_quest_lv43._045_say = "Elmondtam mindent, amit tudok. Az egyetlen nyom[ENTER]az Ork harcosokn\225l van. De sajnos nem lehet[ENTER]tisztess\233gesen besz\233lgetni vel\252k... "
gameforge.new_quest_lv43._049_say = "Egy Lev\233l? L\225ssuk... Ezek a bet\251k nagyon nehezen[ENTER]olvashat\243k... Nagyj\225b\243l arr\243l sz\243l, \250gy t\251nik, az[ENTER]Orkok felgy\250jtottak egy farmot, \233s az ott \233l\245knek[ENTER]menek\252lni\252k kellett. El kellett hagyniuk a[ENTER]gyermek\252ket... \201s itt egy n\233v. "
gameforge.new_quest_lv43._050_say = "K\246sz\246n\246m, hogy elhoztad nekem. Most m\225r v\233gre[ENTER]tudom, mi t\246rt\233nt. "
gameforge.new_quest_lv43._051_say = "Besz\233lnem kellene Chaegirab-bal. Nyilv\225n sokat[ENTER]f\225radozott, hogy megmentsen. Meg fogom pr\243b\225lni,[ENTER]hogy jobb unoka\246ccse legyek. Viszl\225t hamarosan,[ENTER]kedves bar\225tom! "
gameforge.new_quest_lv43._052_say_title = "Inform\225ci\243: "
gameforge.new_quest_lv43._053_say_reward = "32.000 Yangot kapt\225l. "
gameforge.new_quest_lv43._054_say_reward = "1.250.000 tapasztalat pontot kapt\225l. "
gameforge.new_quest_lv43._060_say = "Besz\233lt\233l Chaegirab nagyb\225ty\225mmal? Egy tipp?[ENTER]Mir\245l besz\233lsz? Ha nincs mit felmutatnod, akkor[ENTER]tartsd meg a tal\225lgat\225sod![ENTER][ENTER]K\233rlek, k\233rdezd meg \250jra a Nagyb\225ty\225m. V\233gt\233re[ENTER]is, fizetek neked \233rte. "
gameforge.new_quest_lv52 = {}
gameforge.new_quest_lv52._010_send_letter = "Lev\233l a Kapit\225nyt\243l "
gameforge.new_quest_lv52._020_say_title = "H\251s\233ges honfit\225rs "
gameforge.new_quest_lv52._021_say_reward = "Szeretn\233m, ha megtenn\233l egy sz\237vess\233get. Nem[ENTER]tudok tov\225bb aludni, \233s Baek-Go gy\243gyszer\233nek[ENTER]ellen\233re csak dob\225lom magam \233s forgol\243dok eg\233sz[ENTER]\233jszaka. Meg tudn\225d keresni \245t, hogy k\233rj egy[ENTER]er\245sebb altat\243t? "
gameforge.new_quest_lv52._022_say = "Baek-Go itt van: %s. "
gameforge.new_quest_lv52._030_set_title = "Egy j\243 \233jszakai alv\225s "
gameforge.new_quest_lv52._035_target = "Baek-Go: "
gameforge.new_quest_lv52._040_say = "A Kapit\225nyt \225lmatlans\225g gy\246tri. Menj Baek-Go-hoz,[ENTER]\233s k\233rj t\245le er\245sebb altat\243 tablett\225kat a[ENTER]Kapit\225ny sz\225m\225ra. "
gameforge.new_quest_lv52._041_say = "Altat\243t a Kapit\225nynak? Att\243l tartok, nem tudok[ENTER]er\245sebbet adni neked. Viszont tal\225n Yu-Hwan tud[ENTER]k\233sz\237teni valami gy\243gyn\246v\233ny alap\250 szert, ami[ENTER]meghozza a k\237v\225nt eredm\233nyt. "
gameforge.new_quest_lv52._042_say = "Ah, megkaptad a levelem. Nem tudom, mit tehetn\233k[ENTER]m\233g, csak szeretn\233k v\233gre egy j\243t aludni \233jjel.[ENTER]K\233rlek, seg\237ts, \233s k\233rd ki Baek-Go tan\225cs\225t. "
gameforge.new_quest_lv52._042_select = "Akkor jobb, ha elmegyek Yu-Hwan-hoz! "
gameforge.new_quest_lv52._043_say = "Baek-Go itt van: %s. "
gameforge.new_quest_lv52._044_say_title = "Baek-Go: "
gameforge.new_quest_lv52._045_say = "Yu-Hwan itt van: %s. "
gameforge.new_quest_lv52._046_say = "Akkor menj a Kapit\225nyhoz, \233s mondd meg neki, hogy[ENTER]nem tudsz seg\237teni. "
gameforge.new_quest_lv52._049_say_title = "Yu-Hwan:  "
gameforge.new_quest_lv52._050_target = "Yu-Hwan:  "
gameforge.new_quest_lv52._051_say = "Baek-Go-nak nincs er\245sebb gy\243gyszere. Yu-Hwan[ENTER]tal\225n m\233gis tudna seg\237teni, ha ismer olyan[ENTER]gy\243gyn\246v\233nyt, amivel el\233rhet\245 a k\237v\225nt hat\225s. "
gameforge.new_quest_lv52._052_say = "J\243l ismerem a Kapit\225nyt. \201s mint tal\225n m\225r tudod,[ENTER]el\233g hossz\250 id\245n kereszt\252l teljes\237tettem sz\225m\225ra[ENTER]titkos k\252ldet\233seket. De azt kell mondanom, most[ENTER]nem seg\237tenek megoldani a probl\233m\225j\225t a[ENTER]gy\243gyn\246v\233nyek. "
gameforge.new_quest_lv52._053_say = "M\225s oka van annak, hogy a Kapit\225ny nem tud[ENTER]aludni. \201s higgy nekem, \245 pontosan tudja az ok\225t.[ENTER]De ez olyan dolog, amit mag\225nak kell elrendeznie,[ENTER]\233n nem tehetem meg helyette. Menj, l\225togasd meg,[ENTER]\233s k\233rdezd err\245l. "
gameforge.new_quest_lv52._054_say_title = "Kapit\225ny "
gameforge.new_quest_lv52._055_say_reward = "Ah, megkaptad a levelem. Csak nem tudom, mit[ENTER]tegyek. K\233rlek, menj, \233s k\233rd Baek-Go tan\225cs\225t,[ENTER]hogy v\233gre tudjak \250jra pihenni \233jjel. "
gameforge.new_quest_lv52._055_select = "Igenis, Uram! "
gameforge.new_quest_lv52._056_say = "K\246sz\246n\246m! "
gameforge.new_quest_lv52._056_say_reward = "M\225r l\225ttam \245t, \233s nem adhatok neki semmilyen[ENTER]er\245sebb gy\243gyszert. De felkeresem Yu-Hwan-t, \233s[ENTER]megk\233rdezem, tal\225n \245 seg\237thet neked. "
gameforge.new_quest_lv52._060_target = "Kapit\225ny "
gameforge.new_quest_lv52._061_say = "Yu-Hwan nem akar fecsegni m\225sok titkair\243l, \237gy ez[ENTER]val\243sz\237n\251leg valami kellemetlen dolog lehet. De[ENTER]ez sem haszn\225l, besz\233lned kell err\245l a[ENTER]Kapit\225nnyal. Ha nem tudjuk, mi okozza, nem tudjuk[ENTER]megoldani az alv\225s probl\233m\225j\225t sem. Teh\225t menj[ENTER]ide: %s. "
gameforge.new_quest_lv52._062_say_reward = "Nincs el\233rhet\245 er\245sebb altat\243szer. De Kapit\225ny,[ENTER]tal\225n tudok seg\237teni, ha megtal\225ljuk az[ENTER]\225lmatlans\225god ok\225t. "
gameforge.new_quest_lv52._063_say_reward = "Nincs semmi olyan, amit a hozz\225d hasonl\243[ENTER]fiatalemberekkel szeretn\233k megosztani. "
gameforge.new_quest_lv52._064_say_reward = "Nincs semmi olyan, amit a hozz\225d hasonl\243 fiatal[ENTER]h\246lgyekkel szeretn\233k megosztani. "
gameforge.new_quest_lv52._065_say_reward = "De hamarosan meg\245r\252l\246k, ha nem tudom v\233gre[ENTER]kialudni magam \233jjel. Azt hiszem, el kell... De[ENTER]ne feledd, err\245l csak Te tudhatsz: Minden \233jjel[ENTER]n\233gy szellem k\237s\233rt. De nem is ez a[ENTER]legrosszabb... \201n vagyok a felel\245s a hal\225luk\233rt. "
gameforge.new_quest_lv52._066_say_reward = "N\233gy katona. Azt mondj\225k, id\233z\245k \233s k\237nz\243k[ENTER]k\237nozt\225k \245ket hal\225lra a Seungryong-v\246lgyben. \201n[ENTER]rendeltem \245ket oda - \233n k\252ldtem \245ket a hal\225lba! "
gameforge.new_quest_lv52._067_say_reward = "\201s mit tehet\252nk ezek\233rt a szellemek\233rt? "
gameforge.new_quest_lv52._068_say_reward = "Bossz\250t akarnak! Mit tehetn\233k? Ha hagyom, hogy[ENTER]megtorolj\225k, a falu vezet\233s n\233lk\252l marad,[ENTER]lerohanj\225k, \233s elvesz\237tj\252k. De ha nem megyek,[ENTER]meg\245r\252l\246k. "
gameforge.new_quest_lv52._069_say_reward = "Ha nem \233n feleln\233k a falu biztons\225g\225\233rt, azonnal[ENTER]mentem volna. Csak egyetlen kiutat l\225tok: "
gameforge.new_quest_lv52._070_say_reward = "Valaki m\225s lesz, aki bossz\250t \225ll \233rt\252k, \233rtem. De[ENTER]hogyan k\252ldhetn\233k t\246bb f\233rfit a v\246lgybe,[ENTER]kock\225ztatva azt, hogy \245k is belerokkannak? Hogyan[ENTER]k\233rhetn\233m ezt b\225rkit\245l is csak az\233rt, hogy \250jra[ENTER]tudjak aludni? "
gameforge.new_quest_lv52._071_say_reward = "Nem k\246nny\251 egy ilyen d\246nt\233s. "
gameforge.new_quest_lv52._080_1_select = "A falu java ... "
gameforge.new_quest_lv52._080_2_select = "Nem lesz k\246nny\251 ... "
gameforge.new_quest_lv52._080_3_select = "Nem v\225rhatsz el semmi ilyesmit! "
gameforge.new_quest_lv52._081_say_reward = "... fontosabb a gy\225vas\225gn\225l. Bossz\250t \225llok az[ENTER]embereid\233rt. \201s ha nem j\246v\246k vissza, tal\225lkozunk[ENTER]ma \233jjel! "
gameforge.new_quest_lv52._082_say_reward = "... kezelni ezeket az id\233z\245ket \233s k\237nz\243kat. De[ENTER]j\243l fogsz aludni ma \233jjel, meg\237g\233rem! "
gameforge.new_quest_lv52._083_say_reward = "Hal\225lv\225gyad van? Igen vesz\233lyes ezt tenni az[ENTER]id\233z\245kkel \233s a k\237nz\243kkal. Pr\243b\225ld elmondani[ENTER]azoknak a szellemeknek, hogy milyen sok embernek[ENTER]van sz\252ks\233ge itt r\225d! "
gameforge.new_quest_lv52._084_say_reward = "Igazad van. De m\233g mindig rem\233nykedtem benne,[ENTER]hogy \246nk\233nt megteszed, egyar\225nt nagy szolg\225latot[ENTER]t\233ve nekem \233s a falusiaknak is. "
gameforge.new_quest_lv52._090_1_select = "Nos ... "
gameforge.new_quest_lv52._090_2_select = "Nem, nem fogom ezt megoldani. "
gameforge.new_quest_lv52._091_say_reward = "... ha t\233nyleg \233n vagyok az utols\243 rem\233nyed,[ENTER]lesz\225molok \233rted azokkal az id\233z\245kkel \233s[ENTER]k\237nz\243kkal! "
gameforge.new_quest_lv52._092_say_reward = "Ha megpr\243b\225lom, egy \250jabb szellem fog keresni[ENTER]t\233ged. "
gameforge.new_quest_lv52._093_say_reward = "Rendben. H\225t akkor hadd adjak egy kis Yangot az[ENTER]er\245fesz\237t\233seid\233rt. "
gameforge.new_quest_lv52._093_say_reward_exp = "20.000 tapasztalat pontot kapt\225l. "
gameforge.new_quest_lv52._093_say_reward_gold = "25.000 Yangot kapt\225l. "
gameforge.new_quest_lv52._100_notice = "A besz\233lget\233s v\233get \233rt. "
gameforge.new_quest_lv52._110_say_reward = "Rem\233ltem, hogy ezt fogod mondani. De sajnos nem[ENTER]tudom, melyik k\237nz\243 vagy id\233z\245 \246lte meg \245ket.[ENTER]Rem\233lem, \233rezni fogom, amikor az egyik szellem[ENTER]megbocs\225tott. "
gameforge.new_quest_lv52._111_say_reward = "K\252ldeni fogok egy levelet. A szellemek azt[ENTER]mondt\225k, a bossz\250ra a S\225rk\225nyisten H\225romsz\246gn\233l[ENTER]kell megt\246rt\233nnie. Van ott h\225rom pill\233r, amelyek[ENTER]egy h\225romsz\246g cs\250csait alkotj\225k. "
gameforge.new_quest_lv52._120_set_title = "Bossz\250 a 4 elesett\233rt "
gameforge.new_quest_lv52._125_say_title = "Lev\233l a Kapit\225nyt\243l "
gameforge.new_quest_lv52._130_say_reward = "M\233g tov\225bbi 3 katon\225t kell megbosszulni! "
gameforge.new_quest_lv52._131_say = "\218gy t\251nik, sikeres volt\225l. Most hallottam az[ENTER]egyik elesett katona hangj\225t. Azt mondta,[ENTER]megbocs\225tott nekem, \233s meg lett bosszulva a[ENTER]hal\225la. \201s ezt mind Neked k\246sz\246nhet\245! "
gameforge.new_quest_lv52._132_say = "K\233rlek, bosszuld meg a t\246bbi elesett katon\225t is,[ENTER]\233s \246lj S\246t\233t K\237nz\243kat, S\246t\233t Id\233z\245ket, Magas[ENTER]K\237nz\243kat \233s Magas \214rd\246g\251z\245ket. Ne feledd, csak a[ENTER]S\225rk\225nyisten h\225rom nagy pill\233re \225ltal k\246zrez\225rt[ENTER]h\225romsz\246gben tudod szabadon engedni \245ket. "
gameforge.new_quest_lv52._140_say_reward = "M\233g 2 katon\225t kell megbosszulni! "
gameforge.new_quest_lv52._141_say = "Megsemmis\237tett\233l egy m\225sikat is a katon\225im[ENTER]gyilkosai k\246z\252l! A f\233lhom\225lyban l\225ttam, amint az[ENTER]elesett katona a kez\233t feltartva tisztelgett. "
gameforge.new_quest_lv52._150_say_reward = "M\233g egy m\225sik katona is v\225rja, hogy bossz\250t \225llj! "
gameforge.new_quest_lv52._151_say = "Hihetetlen vagy! Az elesett katona szelleme[ENTER]meg\225llt mellettem egy percre, majd b\250cs\250t intett.[ENTER]Val\243sz\237n\251leg el\233g neh\233z lesz megtal\225lni az utols\243[ENTER]gyilkost. "
gameforge.new_quest_lv52._160_say = "A szellemek, akik nyomasztott\225k a Kapit\225nyt,[ENTER]fiatal katon\225k voltak, akik elestek a k\252ldet\233s\252k[ENTER]alatt. S\246t\233t K\237nz\243k, S\246t\233t Id\233z\245k, Magas k\237nz\243k[ENTER]\233s Magas \246rd\246g\251z\245k \246lt\233k meg \245ket. "
gameforge.new_quest_lv52._161_say = "Meg kell semmis\237tened a S\225rk\225nyisten H\225romsz\246get[ENTER]alkot\243 pill\233rek k\246z\246tt a katon\225k hal\225l\225\233rt[ENTER]felel\245s k\237nz\243kat \233s id\233z\245ket, hogy megbosszuld[ENTER]\245ket. "
gameforge.new_quest_lv52._162_say = "A S\225rk\225nyisten H\225romsz\246g a Seungryong-v\246lgy[ENTER]k\246zep\233n van. "
gameforge.new_quest_lv52._170_send_letter = "Els\245 katona megbosszulva "
gameforge.new_quest_lv52._171_send_letter = "M\225sodik katona megbosszulva "
gameforge.new_quest_lv52._172_send_letter = "Harmadik katona megbosszulva "
gameforge.new_quest_lv52._173_send_letter = "Mindegyik katona megbosszulva "
gameforge.new_quest_lv52._180_say_reward = "Megbosszultad mind a 4 katon\225t! "
gameforge.new_quest_lv52._181_say = "Megtal\225ltad az utols\243 gyilkost! A n\233gy elesett[ENTER]katona k\246z\252l most jelent meg az utols\243, \233s[ENTER]k\246sz\246netet mondott a b\225tors\225god\233rt. H\225trahagyott[ENTER]neked valamit: %s "
gameforge.new_quest_lv52._182_say = "L\225togass meg, hogy megkapd a jutalmad. Itt fogok[ENTER]v\225rni r\225d: %s. "
gameforge.new_quest_lv52._183_say_reward = "Nagyszer\251 szolg\225latot tett\233l nekem \233s a[ENTER]falvamnak. Itt a jutalom, amit n\225lam hagyott a[ENTER]szellem sz\225modra: %s "
gameforge.new_quest_lv52._184_say_reward = "\201s itt egy kis Yang t\245lem. Most visszavonulok, \233s[ENTER]v\233gre alszom egy keveset. "
gameforge.new_quest_lv52._185_say_reward = "V\233gtelen\252l h\225l\225s vagyok neked, fiam. "
gameforge.new_quest_lv52._186_say_reward = "Az \246r\246kk\233val\243s\225gig h\225l\225s vagyok neked. "
gameforge.new_quest_lv52._190_say_title = "Inform\225ci\243: "
gameforge.new_quest_lv52._191_say_reward = "3.300.000 tapasztalat pontot kapt\225l.[ENTER]270.000 Yangot kapt\225l.[ENTER]Egy Mester k\246nyvet kapt\225l. "
gameforge.new_quest_lv52._85_say = "Akkor tal\225n k\233s\245bb? K\233rlek, menj Baek-Go-hoz,[ENTER]amint tudsz! "
gameforge.new_quest_lv54 = {}
gameforge.new_quest_lv54._010_target = "Kapit\225ny "
gameforge.new_quest_lv54._020_say_title = "A friss ell\225tm\225ny "
gameforge.new_quest_lv54._030_say = "Nehezen motiv\225ljuk a csapatainkat pillanatnyilag,[ENTER]k\252l\246n\246sen az\233rt, mert neh\233z friss ell\225tm\225nyhoz[ENTER]jutni. A Vegyeskeresked\245 Elad\243n\245 fontos[ENTER]besz\225ll\237t\243nk, de csak kev\233s b\225jitalt k\252ld\246tt,[ENTER]amire sz\252ks\233g\252nk van. "
gameforge.new_quest_lv54._031_say_reward = "K\233rlek, menj el a Vegyeskeresked\245 Elad\243n\245h\246z,[ENTER]hogy kider\237tsd, mi a probl\233ma. "
gameforge.new_quest_lv54._032_select = "Biztos\237tani fogom a b\225jitalokat! "
gameforge.new_quest_lv54._040_say_title = "Vegyeskeresked\245 Elad\243n\245: "
gameforge.new_quest_lv54._040_set_title = "Friss \225ruk\233szlet "
gameforge.new_quest_lv54._050_target = "Vegyeskeresked\245 Elad\243n\245: "
gameforge.new_quest_lv54._051_say = "Igen, mostan\225ban egyre nehezebb volt beszerezni a[ENTER]friss \225ruk\233szletet. A kereskedelmi utak[ENTER]meglehet\245sen vesz\233lyesekk\233 v\225ltak, gyakran t\251nnek[ENTER]fel \250ton\225ll\243k \233s vad\225llatok. A V\225ndor[ENTER]keresked\245knek, akikt\245l beszerzem az \225rum, es\233lye[ENTER]sincs a tigrisekkel szemben. "
gameforge.new_quest_lv54._052_say = "Tal\225n a Kapit\225ny \233s a katon\225i tudnak seg\237teni.[ENTER]K\233rlek, menj el hozz\225 \233s k\233rdezd meg, oda tudn\225-e[ENTER]k\252ldeni a katon\225it a keresked\245k v\233delm\233re. "
gameforge.new_quest_lv54._054_say = "Menj a Vegyeskeresked\245 Elad\243n\245h\246z, \233s der\237tsd ki,[ENTER]mi\233rt k\233sik a friss b\225jital ell\225tm\225ny. "
gameforge.new_quest_lv54._055_say = "A Vegyeskeresked\245 Elad\243n\245 itt van: %s. "
gameforge.new_quest_lv54._056_say_title = "Kapit\225ny "
gameforge.new_quest_lv54._060_say = "Biztos\237tani a kereskedelmi utakat? Igen...[ENTER]Szeretn\233m. De sajnos nincs elegend\245 katon\225m[ENTER]megv\233deni minden, m\225s birodalomb\243l sz\225rmaz\243[ENTER]v\225ndor keresked\245t. "
gameforge.new_quest_lv54._061_say = "Tov\225bb\225, a katon\225k nem vad\225szhatnak tigrisekre.[ENTER]Az csak a vad\225sz c\233hekb\245l sz\225rmaz\243 vad\225szoknak[ENTER]enged\233lyezett. Nem tenne j\243t a falu b\233k\233j\233nek[ENTER]sem, ha b\225rki megszegn\233 ezeket a szab\225lyokat. "
gameforge.new_quest_lv54._062_say_reward = "\201ppen ez\233rt besz\233lj Yang-Shin-nel. \213 a vad\225sz c\233h[ENTER]tagja. Tal\225n tud seg\237teni megold\225st tal\225lni a[ENTER]tigrisek fel\252gyelet\233vel kapcsolatos probl\233m\225ban. "
gameforge.new_quest_lv54._064_say = "Menj a Kapit\225nyhoz, \233s pr\243b\225ld meggy\245zni a[ENTER]kereskedelmi utak biztos\237t\225s\225r\243l a tigrisek[ENTER]ellen. "
gameforge.new_quest_lv54._065_say = "A Kapit\225ny itt van: %s. "
gameforge.new_quest_lv54._070_target = "Yang-Shin: "
gameforge.new_quest_lv54._071_say = "Sok vad\225sz be\225llt a harcosok k\246z\233 \233s elesett a[ENTER]h\225bor\250ban. Most m\225r szinte lehetetlen a[ENTER]vad\225llatok sz\225m\225t egyens\250lyban tartani. A[ENTER]vadmacsk\225k k\252l\246n\246sen nagy probl\233m\225t okoznak,[ENTER]mivel kiterjesztett\233k ter\252let\252ket, \233s[ENTER]vesz\233lyeztetik az utaz\243kat. "
gameforge.new_quest_lv54._072_say = "Ha seg\237tesz nek\252nk, fel tudom aj\225nlani jutalmul[ENTER]ezt az \233rt\233kes Tigris pajzs+3 -at, ami egykor[ENTER]halott bar\225tom, Mi-Song tulajdona volt. Ehhez[ENTER]jelent\245sen cs\246kkentened kell a tigris popul\225ci\243t. "
gameforge.new_quest_lv54._073_say = "K\252l\246n\246sen az \193tkozott feh\233r tigrisek sz\225ma n\245tt[ENTER]meg ellen\245rizhetetlen\252l. "
gameforge.new_quest_lv54._074_say = "Ennek bizony\237t\233kak\233nt kell: "
gameforge.new_quest_lv54._075_say = "Vad\225sznod kell: "
gameforge.new_quest_lv54._076_say = "Keresd Yang-Shin-t, \233s pr\243b\225ld meggy\245zni, hogy[ENTER]biztos\237tsa a kereskedelmi utakat a tigrisek[ENTER]ellen. "
gameforge.new_quest_lv54._077_say_title = "Yang-Shin: "
gameforge.new_quest_lv54._078_say = "Yang-Shin itt van: %s. "
gameforge.new_quest_lv54._080_set_title = "A Tigris pr\233m "
gameforge.new_quest_lv54._081_notice = "Ah, pomp\225s p\233ld\225ny. M\225r csak %s kell bel\245l\252k! "
gameforge.new_quest_lv54._082_notice = "K\233sz. Most siess vissza Yang-Shin-hez. "
gameforge.new_quest_lv54._083_notice = "Ez a tigris pr\233m haszn\225lhatatlan. "
gameforge.new_quest_lv54._084_say = "M\225r csak tov\225bbi %s x F\233nyes tigris bunda kell. "
gameforge.new_quest_lv54._085_say = "Zs\225km\225nyolj F\233nyes tigris bund\225t az \193tkozott[ENTER]feh\233r tigrisekt\245l. "
gameforge.new_quest_lv54._090_npcChat = "Tigris bund\225t kaptam. "
gameforge.new_quest_lv54._091_say = "Ez m\233g nem el\233g nekem. Hogyan lehet meghat\225rozni[ENTER]e n\233h\225ny pr\233m alapj\225n, hogy az utak \250jra[ENTER]biztons\225gosak? "
gameforge.new_quest_lv54._092_say = "Ah, v\233gre! Ez a sz\245rme nagy nyeres\233get hoz... eh![ENTER]M\233g mindig itt vagy? Neked k\246sz\246nhet\245en \250jra[ENTER]biztons\225gosak az utak! Biztos vagyok benne, hogy[ENTER]a Kapit\225ny sz\233pen megjutalmaz. "
gameforge.new_quest_lv54._093_say = "\201s most menj. Ki kell tiszt\237tanom a bund\225t. "
gameforge.new_quest_lv54._094_say = "Oh, hogy a Kapit\225ny nem ad neked jutalmat? Ez nem[ENTER]az \233n probl\233m\225m. \201s abban az esetben, ha[ENTER]megpr\243b\225ln\225l becsm\233relni a pr\233mek miatt: Felejtsd[ENTER]el, \233n nem veszek r\233szt benne! "
gameforge.new_quest_lv54._095_say_reward = "De neked \237g\233rtem a pajzsot, \233s neked kell egy. Ez[ENTER]egy \243cska r\233gi dolog, amit egy\233bk\233nt sem[ENTER]haszn\225lok m\225r. "
gameforge.new_quest_lv54._096_say = "Jutalom: "
gameforge.new_quest_lv54._097_say_reward = "Tigris pajzs+3 -at kapt\225l. "
gameforge.new_quest_lv54._098_say = "\193t akarsz verni n\233h\225ny bund\225val? \205gy fogom az[ENTER]ad\243ss\225gaim... \218gy \233rtem, az utc\225n soha nem lesz[ENTER]el\233g biztons\225gos! "
gameforge.new_quest_lv54._099_say_reward = "Menj, \233s vad\225ssz addig, am\237g \246sszegy\251jt\246tt\233l %s[ENTER]pr\233met! "
gameforge.new_quest_lv54._100_say = "Ez minden, most siess vissza Yang-Shin-hez. "
gameforge.new_quest_lv54._101_say_reward = "3.750.000 tapasztalat pontot kapt\225l. "
gameforge.new_quest_lv54._102_say_reward = "125.000 Yangot kapt\225l. "
