gameforge.new_quest_lv7._012_say_title = "\214regasszony "
gameforge.new_quest_lv7._020_say_title = "A l\225nya esk\252v\245je "
gameforge.new_quest_lv7._021_say = "Vannak gyerekeid? Akkor biztosan meg\233rted az \233n[ENTER]gondom is... a l\225nyom miatt! Megismert egy[ENTER]f\233rfit, aki teljesen megsz\233d\237tette. \201s most[ENTER]elsz\246k\246tt egy m\225sik birodalomba a szeret\245j\233vel. "
gameforge.new_quest_lv7._022_say = "A f\233rfi Chunjo birodalomb\243l val\243. Term\233szetesen[ENTER]elleneztem! Azt hittem, egy Shinsoo-b\243l sz\225rmaz\243[ENTER]h\246lgy nem h\225zasodhat egy spiritu\225lis \225lmodoz\243val[ENTER]Chunjo-b\243l. Elv\225ltunk egy vita ut\225n, \233s \245[ENTER]elsz\246k\246tt vele Chunjo-ba. "
gameforge.new_quest_lv7._023_say = "A f\233rfi Jinno birodalomb\243l val\243. Term\233szetesen[ENTER]elleneztem! Azt hittem, egy Chunjo-b\243l sz\225rmaz\243[ENTER]h\246lgy nem h\225zasodhat egy brut\225lis Jinno-b\233livel.[ENTER]Elv\225ltunk egy vita ut\225n, \233s \245 elsz\246k\246tt vele[ENTER]Jinno-ba. "
gameforge.new_quest_lv7._024_say = "A f\233rfi Shinsoo birodalomb\243l val\243. Term\233szetesen[ENTER]elleneztem! Azt hittem, egy Jinno-b\243l sz\225rmaz\243[ENTER]h\246lgy nem h\225zasodhat egy puh\225ny, p\233nzhajh\225sz[ENTER]Shinsoo-val. Elv\225ltunk egy vita ut\225n, \233s \245[ENTER]elsz\246k\246tt vele Shinsoo-ba. "
gameforge.new_quest_lv7._030_say = "Azt hallottam, ott akar f\233rjhez menni. "
gameforge.new_quest_lv7._031_say = "Most a l\225nyom egy jelet v\225r t\245lem. Mit tehetn\233k?[ENTER]M\233giscsak az egyetlen gyermekem! Term\233szetesen[ENTER]\225ld\225som adom r\225juk. K\233rlek, menj el az[ENTER]\246regasszonyhoz, \233s k\233rd meg, hogy seg\237tsen nekem[ENTER]az el\245k\233sz\252letekben. "
gameforge.new_quest_lv7._040_target = "\214regasszony "
gameforge.new_quest_lv7._041_say = "Keresd meg az \214regasszonyt, \233s k\233rd a seg\237ts\233g\233t[ENTER]az esk\252v\245i el\245k\233sz\252letekben. "
gameforge.new_quest_lv7._042_say = "Az \214regasszony itt van: %s. "
gameforge.new_quest_lv7._051_say = "Azt mondod, esk\252v\245? Nos, ez jelent\245s pillanat egy[ENTER]n\245 \233let\233ben. Mindennek rendben kell lennie, a[ENTER]Menyasszonyi ruh\225t\243l \233s a Szmokingt\243l kezdve az[ENTER]Eljegyz\233si gy\251r\251kig, melyek a szertart\225s alatt[ENTER]Jegygy\251r\251kk\233 v\225lnak. Amikor a menyasszony apja[ENTER]beleegyezik, \233s befizet\233sre ker\252l a szertart\225shoz[ENTER]sz\252ks\233ges Yang, meg lehet tartani az \252nneps\233get. "
gameforge.new_quest_lv7._052_say = "A vir\225gok k\252l\246n\246sen fontosak - nem lehet esk\252v\245[ENTER]Menyasszonyi csokor n\233lk\252l, amit a v\245leg\233ny[ENTER]aj\225nd\233koz im\225dottj\225nak. A csokornak a k\246vetkez\245[ENTER]vir\225gokb\243l kell \225llnia: "
gameforge.new_quest_lv7._054_say = "Sz\252ks\233gem van: "
gameforge.new_quest_lv7._055_say = "Vad\225sznod kell: "
gameforge.new_quest_lv7._056_say = "M\233g mindig kell: "
gameforge.new_quest_lv7._060_say = "Gyere vissza, ha megszerezted mind a h\225rom[ENTER]vir\225got. Ellen\245rizni fogom, el\233g frissek-e, majd[ENTER]k\233sz\252l bel\245l\252k egy sz\233p csokor. Ezut\225n el kell[ENTER]vinned a h\250gomhoz. \213 v\233gzi a szertart\225st. "
gameforge.new_quest_lv7._081_say = "Minden fajta vir\225got gy\251jts \246ssze. \201hes alfa[ENTER]farkasok, \201hes k\233kfarkasok \233s \201hes alfa[ENTER]k\233kfarkasok \246l\233s\233vel jutsz hozz\225juk. "
gameforge.new_quest_lv7._082_say = "Ez a hervadt vir\225g nem valami dekorat\237v. Sz\243val[ENTER]sok munka a semmi\233rt. "
gameforge.new_quest_lv7._083_say = "Ez a hervadt vir\225g nem valami dekorat\237v. Sz\243val[ENTER]sok munka a semmi\233rt. "
