gameforge.new_quest_lv7._090_notice = "Ez a vir\225g pomp\225s p\233ld\225ny. Gy\246ny\246r\251! "
gameforge.new_quest_lv7._091_say = "K\233sz! Ezek a vir\225gok kellenek egy sz\233p csokor[ENTER]k\233sz\237t\233s\233hez. Siess vissza az \214regasszonyhoz,[ENTER]miel\245tt a vir\225gok elhervadnak! "
