gameforge.new_quest_lv7._137_say = "Menj vissza Octaviohoz a Jinno birodalom Pyungmoo[ENTER]ter\252let\233re. "
gameforge.new_quest_lv7._140_say = "Itt vannak a vir\225gok Octavio l\225ny\225nak k\246zelg\245[ENTER]esk\252v\245j\233re. J\243k\237v\225ns\225gok k\237s\233ret\233ben illik \225tadni[ENTER]a menyasszonynak. \213 tudni fogja, kit\245l[ENTER]sz\225rmaznak. "
gameforge.new_quest_lv7._141_say = "Ezek csodasz\233p vir\225gok! Ragyog\243v\225 teszik a[ENTER]menyasszonyt. Ezzel be is fejez\245dtek az[ENTER]el\245k\233sz\252letek. K\233rlek, add \225t Octavionak az[ENTER]esk\252v\245i megh\237v\225st. Tudom, hogy el lesz t\245le[ENTER]ragadtatva. "
gameforge.new_quest_lv7._142_say = "Most menj Octaviohoz, mire v\225rsz m\233g? "
gameforge.new_quest_lv7._143_say = "Vir\225gokat hozt\225l Octavio l\225ny\225nak esk\252v\245j\233re?[ENTER]Milyen kedves t\245led! De... \245k hol vannak?[ENTER]Elhagytad \245ket az \250ton? "
gameforge.new_quest_lv7._144_say_reward = "T\233rj vissza a birodalmadba, \233s szerezz egy \250j[ENTER]csokrot az esk\252v\245re. "
gameforge.new_quest_lv7._145_say = "Menj az \214regasszony h\250g\225hoz, miel\245tt elhervadnak[ENTER]a vir\225gok. "
gameforge.new_quest_lv7._150_say = "Mi\233rt f\252st\246l a kecskeb\233ka leves? Ah, mindegy, ez[ENTER]nem igaz\225n sz\225m\237t, am\237g j\243 h\237reid vannak. "
gameforge.new_quest_lv7._151_say = "Nem tudom el\233gg\233 megk\246sz\246nni. Nagyon boldog[ENTER]vagyok, hogy elmehetek a l\225nyom esk\252v\245j\233re! "
gameforge.new_quest_lv7._152_say = "Tess\233k, itt a jutalmad: "
gameforge.new_quest_lv7._153_say_reward = "Egy harcm\251v\233sz mester sz\225m\225ra kov\225csolt fegyver.[ENTER]Vigy\225zz r\225! "
gameforge.new_quest_lv7._154_say_reward = "%s tapasztalat pontot kapt\225l. "
gameforge.new_quest_lv7._155_say_reward = "%s Yangot kapt\225l. "
gameforge.new_quest_lv7._160_say = "Val\243sz\237n\251leg \246sszet\233vesztesz egy t\225voli[ENTER]rokonoddal. Nekem nincs l\225nyom, \233s nincs elegend\245[ENTER]Yangom sem esk\252v\245t rendezni. "
gameforge.new_quest_lv7._165_say = "Szeretn\233l megk\243stolni egy kan\225lnyi kecskeb\233ka[ENTER]levest? Egyik id\245s nagyn\233n\233m receptje szerint[ENTER]k\233sz\237tettem el. "
gameforge.new_quest_lv75 = {}
gameforge.new_quest_lv75._010_target = "Heuk-Young: "
gameforge.new_quest_lv75._020_set_title = "Egy Legenda Napl\243ja "
gameforge.new_quest_lv75._021_say = "Tal\225ltam ezeket a harcos maradv\225nyokat. Nem tudom[ENTER]hogy ez az a Sura-e akit Heuk-Young keres, de[ENTER]biztos vagyok benne hogy \233rdekli majd. "
gameforge.new_quest_lv75._022_say = "Nem csak egy Sura halt itt meg. L\225ttam a[ENTER]maradv\225nyaikat. K\237v\225ncsi vagok hogy vajon az a[ENTER]legend\225s harcos is k\246zt\252k volt-e? Megyek[ENTER]jelenteni Heuk-Young-nak err\245l. "
gameforge.new_quest_lv75._023_say = "Tal\225ltam egy r\233gi pap\237rdarabot egy Alvil\225gi J\233g[ENTER]Golembe fagyva. Alig tudom elolvasni, de tal\225n[ENTER]lehet benne inform\225ci\243 ami \233rdekelheti[ENTER]Heuk-Young-ot. "
gameforge.new_quest_lv75._024_say = "Tal\225ltam n\233h\225ny dolgot ami \233rdekelheti[ENTER]Heuk-Young-ot. El k\233ne mennem hozz\225 hogy \225tadjam[ENTER]neki ezt a pap\237rdarabot. Akkor mes\233lhetek neki a[ENTER]testr\245l is. "
gameforge.new_quest_lv75._025_say = "Heuk-Young megk\233rt hogy tartsam nyitva a szemem[ENTER]minden olyan utal\225sokra amik a legend\225s Sur\225hoz[ENTER]kapcsol\243dnak. Sajnos \246tletem sincs hogy hol[ENTER]keressem... "
gameforge.new_quest_lv75._030_say = "Keresd a legend\225s harcost, Akum\225t. \213 volt a[ENTER]legh\237resebb Sura aki valaha \233lt - egy majdnem[ENTER]legy\245zhetetlen harcos. A sz\243besz\233d szerint[ENTER]egyszer m\233g az uralkod\243t is kih\237vta. Szerintem ez[ENTER]volt az a hely ahol Akuma elt\251nt, t\246bbsz\225z \233vvel[ENTER]ezel\245tt. K\233rlek keress nyomokat arra vonatkoz\243an[ENTER]hogy hol lehetett. "
gameforge.new_quest_lv75._040_say = "b\225b\250 "
gameforge.new_quest_lv75._050_npcChat = "Elesett Harcosok Megvizsg\225l\225sa "
gameforge.new_quest_lv75._060_say = "Egy harcos maradv\225nyainak t\251nik. A jobb k\233z[ENTER]viszont nem emberi k\233z... ez biztos Sura volt.[ENTER]Mes\233lek err\245l Heuk-Young-nak. "
gameforge.new_quest_lv75._070_notice = "Egy k\246nyv lapja... belefagyva egy Alvil\225gi J\233g[ENTER]G\243lem test\233be... "
gameforge.new_quest_lv75._090_say = "Nem mondhatom el hogy pontosan mi ut\225n kutatunk.[ENTER]Csak menj egy k\246rt, n\233zz k\246r\252l azt\225n gyere vissza[ENTER]\233s mondd el hogy mit tal\225lt\225l. "
gameforge.new_quest_lv75._100_say = "Mit tal\225lt\225l? Hadd l\225ssam! "
gameforge.new_quest_lv75._105_say = "Egy jegyzet... Mif\233le \237r\225s ez? Ez biztos nagyon[ENTER]r\233gi. Az is lehet hogy valami igen fontos[ENTER]irom\225nyra bukkant\225l. Amik itt vannak \237rva[ENTER]ismer\245snek t\251nnek. \218gyt\251nik hogy ez az oldal egy[ENTER]k\246nyvben volt. "
gameforge.new_quest_lv75._109_say = "Ha tal\225ln\225nk m\233g t\246bb oldalt, sokkal t\246bb \233rtelme[ENTER]lenne ennek. Keress m\233g nyomokat! "
gameforge.new_quest_lv75._110_say = "H\225t itt vagy ism\233t. Tal\225lt\225l valamit? Mondd el! "
gameforge.new_quest_lv75._115_say = "Egy halott Sura... ez lehet hogy \245 lesz, de az is[ENTER]lehet hogy csak egy k\246vet\245je. De t\246bbre van[ENTER]sz\252ks\233g\252nk hogy biztosak legy\252nk benne. Keress[ENTER]nyomokat arr\243l hogy ki lehet ez. Fegyverek,[ENTER]\201kszerek, vagy tal\225n valami jegyzetek. "
gameforge.new_quest_lv75._120_say = "Egy Sur\225nak a csontv\225za \233s egy k\246nyv oldal?[ENTER]Vessek egy pillant\225st erre a pap\237rra... Hmmm[ENTER]lehet hogy megtal\225ltad Akuma maradv\225nyait. De[ENTER]t\246bb bizony\237t\233kra van sz\252ks\233g. Keress m\233g t\246bb[ENTER]k\246nyv oldalt. "
gameforge.new_quest_lv75._130_say = "M\225r tal\225ltam bizony\237t\233kot, de nem vagyok biztos[ENTER]benne hogy a legend\225s Sura t\233nyleg itt volt-e[ENTER]vagy nem. T\246bb inform\225ci\243ra van sz\252ks\233gem. "
gameforge.new_quest_lv75._140_1_select = "J\243 "
gameforge.new_quest_lv75._140_2_select = "J\233g Teremtm\233ny "
gameforge.new_quest_lv75._140_3_select = "Az elkesered\233s hat\225r\225n "
gameforge.new_quest_lv75._140_4_select = "S\246t\233t terror "
gameforge.new_quest_lv75._140_5_select = "A hal\225l arca "
gameforge.new_quest_lv75._140_6_select = "A harcos sorsa "
gameforge.new_quest_lv75._140_7_select = "Nem, nem \233rdekel. "
gameforge.new_quest_lv75._150_say = "Csak n\233h\225ny darabot tudok kivenni a mondatokb\243l.[ENTER]Valahogy az udvari \233letr\245l \233s a kaland t\250lzott[ENTER]szeretet\233r\245l sz\243l... "
gameforge.new_quest_lv75._160_1_say = "A felirat a s\225rg\225s pap\237ron halv\225ny \233s[ENTER]bizonytalan, mintha egy nagyon \246reg vagy gyenge[ENTER]egy\233n \237rta volna: \"... J\233g Teremtm\233nyek. M\233g a[ENTER]Sura k\233pess\233geimmel sem tudtam legy\245zni mindet.[ENTER]N\233h\225nyuk m\233g mindig a barlangokban vannak \233s[ENTER]k\252l\246n\246sen \243vatosnak kell lennem ha megtal\225lnak.[ENTER]Mostan\225ig v\233delmet adtak de \250jabban ...\" Ezut\225n[ENTER]az \237r\225s elt\251nik a pap\237rlapr\243l. "
gameforge.new_quest_lv75._160_2_say = "Ez az oldal szint\233n nagyon megviselt. A fels\245[ENTER]sarokban l\233v\245 d\225tumr\243l felismerhet\245, hogy ez[ENTER]egyfajta napl\243: \"Nem ez az els\245 alkalom, hogy azt[ENTER]k\237v\225nom, b\225rcsak m\225shogy cselekedtem volna,[ENTER]amikor a Barlangot kerestem. Olyan b\252szke \233s[ENTER]el\233gedett voltam magammal! Mindezek most m\225r a[ENTER]biztos hal\225lba vezetnek engem...\" A \"hal\225l\" sz\243[ENTER]vastagon al\225 van h\250zva. "
gameforge.new_quest_lv75._160_3_say = "A pap\237rlap nagyon r\233gi \233s s\233r\252lt, n\233h\225ny darabja[ENTER]t\233pett. Az \252zenet csak egyes darabjait lehet[ENTER]kiolvasni: \"... Uralkod\243 udvara... amikor a[ENTER]tud\243sok megtan\237tottak mindent amikre annyira[ENTER]kiv\225ncsi voltam... k\246nny\251 kinyitni a port\225lt,[ENTER]de... hal\225l \233s f\233lelem a s\246t\233tben ...\" Egy nagy[ENTER]hat\225rozott szakad\225s miatt nem lehet tov\225bb[ENTER]olvasni. "
gameforge.new_quest_lv75._160_4_say = "Tal\225lsz egy skiccet ezen az oldalon: Ez egy n\245[ENTER]arc\225nak k\233pe. M\246g\246tte van n\233h\225ny sz\243 \237rva amiket[ENTER]m\225r ismersz. Viszont az irom\225ny sokkal[ENTER]bizonytalanabbnak l\225tszik: \"A hal\225l karmai ki[ENTER]vannak eresztve - Erre tegnap j\246ttem r\225. Csak egy[ENTER]gyors pillant\225st vetettem a teremtm\233nyre, miel\245tt[ENTER]a f\233lelem elfogott volna \233s h\225tr\225lni kezdtem. Oh[ENTER]szeretett Sunmi, ha tudtam volna! Ha tudtam volna[ENTER]err\245l a rettenetr\245l kor\225bban, sosem l\233ptem volna[ENTER]erre a szintre!\" "
gameforge.new_quest_lv75._160_5_say = "A Hee-Se Dinasztia idej\233n \233lt a legend\225s Sura,[ENTER]Akuma. Olyan kiv\225l\243 \233s hatalmas harcos volt hogy[ENTER]alig tal\225lt olyan ellenfelet aki igaz\225n pr\243b\225ra[ENTER]tette volna a k\233pess\233geit. Egy nap tal\225lt n\233h\225ny[ENTER]feljegyz\233st egy titokzatos helyr\245l ami nagyon[ENTER]r\233g\243ta el lett z\225rva. \213 \250gy d\246nt\246tt hogy minden[ENTER]idej\233t arra ford\237tja hogy megtal\225lja ezt a[ENTER]helyet. M\233g a port\225lokat is megtal\225lta \233s arra is[ENTER]r\225j\246tt hogy hogyan nyithatja ki \245ket. Meg\237g\233rte a[ENTER]szerelm\233nek, Sunmi-nak hogy visszat\233r amint[ENTER]befejezte a kalandj\225t, de soha nem t\233rt vissza. "
gameforge.new_quest_lv75._170_say = "Az \237r\225s nagyon r\233giesnek l\225tszik... \233s el\233gg\233[ENTER]bizonytalan, furcsa, mintha az \237r\243nak nem sok[ENTER]ereje lett volna m\225r... "
gameforge.new_quest_lv75._171_say = "Ennek semmi \233rtelme. T\246bb oldalra van sz\252ks\233g\252nk. "
gameforge.new_quest_lv75._172_say = "Kezdek r\225j\246nni hogy mi t\246rt\233nhetett itt. De m\233g[ENTER]sokminden van amiben nem vagyok teljesen biztos. "
gameforge.new_quest_lv75._173_say = "Szeretn\233d tudni a r\233szleteket? "
gameforge.new_quest_lv75._174_say = "M\233g egy oldal! Ak\225rki is \237rta ezeket, az[ENTER]elkesered\233s hat\225r\225n lehetett. \214sszegezzem hogy[ENTER]mit \237r? "
gameforge.new_quest_lv75._175_say = "N\233h\225ny oldal olyan rossz \225llapotban van hogy csak[ENTER]tal\225lgatni tudok hogy mi lehet rajtuk. De kezdem[ENTER]\233rteni hogy mi t\246rt\233nt ebben a barlangban sok[ENTER]\233vvel ezel\245tt. "
gameforge.new_quest_lv75._176_say = "Nem sok hi\225nyzik. Szeretn\233d tudni hogy mire[ENTER]j\246ttem r\225? "
gameforge.new_quest_lv75._177_say = "\218gyt\251nik hogy m\225r nem t\250l sok oldal hi\225nyzik. "
gameforge.new_quest_lv75._178_say = "Szeretn\233d tudni hogy mire j\246ttem r\225 eddig? "
gameforge.new_quest_lv75._180_notice = "Megtal\225ltam az utols\243 oldalt az Alvil\225gi J\233g[ENTER]Golemek mellett. "
gameforge.new_quest_lv75._185_send_letter = "Ezzel most m\225r megvan az \246sszes oldal! "
gameforge.new_quest_lv75._190_notice = "Ezt az oldalt tal\225ltam az Alvil\225gi J\233g G\243lemek[ENTER]mellett. "
gameforge.new_quest_lv75._195_send_letter = "Tal\225ltam egy oldalt! "
gameforge.new_quest_lv75._200_npcChat = "Elesett Harcosom Kutat\225sa "
gameforge.new_quest_lv75._210_say = "H\225rom oldal van elsz\243rva az emberi csontv\225zak[ENTER]mellett. A szakadt sz\233leikb\245l l\225tszik hogy ki[ENTER]lettek t\233pve a k\246nyvb\245l. Az oldalakon az \237r\225s[ENTER]kifakult, nehezen olvashat\243. "
gameforge.new_quest_lv75._220_say = "Azthiszem ez el\233g lesz. Elviszem ezeket[ENTER]Heuk-Young-hoz. "
gameforge.new_quest_lv75._230_say = "K\237v\225ncsi vagyok hogy kinek a maradv\225nyai ezek. De[ENTER]egy dolog biztos, nem volt n\225la semmi olyasmi ami[ENTER]ma m\233g haszn\225hat\243 lenne. "
gameforge.new_quest_lv75._240_send_letter = "Megvannak az oldalak! "
gameforge.new_quest_lv75._250_say = "Vissza k\233ne mennem Heuk-Young-hoz. Tal\225n \245 \246ssze[ENTER]tudja rakni a darabokat. "
gameforge.new_quest_lv75._270_say = "Meglep hogy ennyi mindent tal\225lt\225l azokban a[ENTER]barlangokban. Ezek az oldalak egy k\246nyv r\233szei[ENTER]lehettek. Az itt \237rottak nagyon \233rdekesek. \201s van[ENTER]is \233rtelme ezeknek ha visszagondolok a[ENTER]t\246rt\233netekre amiket hallottam. Ha odaadod ezeket[ENTER]az oldalakat, megk\246t\246m \233s egy k\246nyvv\233 v\225ltoztatom[ENTER]\245ket. Tal\225n hasznos lehet amikor a Sz\225m\251z\246tt[ENTER]Barlangj\225ba m\233sz. Ha nincs ez hasznodra, biztos[ENTER]tal\225lunk valakit aki megveszi t\245led. "
gameforge.new_quest_lv75._280_say = "Megk\246t\246ttem az oldalakat egy k\246nyvbe \233s[ENTER]hozz\225adtam p\225r saj\225t megjegyz\233st. Tal\225n ezek[ENTER]hasznodra v\225lnak majd. Elmondhatom neked a[ENTER]t\246rt\233net tov\225bbi r\233sz\233t ha szeretn\233d. "
gameforge.new_quest_lv75._290_1_select = "Igen, mondd el! "
gameforge.new_quest_lv75._290_2_select = "Nem, ez engem nem \233rdekel! "
gameforge.new_quest_lv75._310_say = "Mit akarsz t\245lem? Nem l\225tod hogy olvasok? "
gameforge.new_quest_lv75._320_say = "Soon : "
gameforge.new_quest_lv75._330_say = "Nagyon \233rdekes k\246nyv az ami n\225lad van. Hol[ENTER]tal\225ltad? Megn\233zhetem? "
gameforge.new_quest_lv75._340_say = "Ezek feljegyz\233sek a Sz\225m\251z\246tt Barlangj\225r\243l, ugye?[ENTER]Nagyon r\233ginek t\251nnek. Az \237r\225s nagyon szokatlan[ENTER]\233s az \237r\225s nagyon r\233gim\243di... Nagyon neh\233z[ENTER]lehetett egy ilyen k\246nyvet \246sszeszedni.[ENTER]Term\233szetesen nagyon szeretn\233m hogy az eny\233m[ENTER]legyen. Tal\225n, ha neked nincs sz\252ks\233ged r\225,[ENTER]eladn\225d? "
gameforge.new_quest_lv75._350_1_select = "Igen "
gameforge.new_quest_lv75._350_2_select = "Nem "
gameforge.new_quest_lv75._360_say = "Mennyi Yangot k\233rsz a k\246nyvv\233rt? "
gameforge.new_quest_lv75._370_say = "Haha... vicces fazon vagy. Egy\233rtelm\251en neh\233z[ENTER]veled \252zletet k\246tni. OK, teh\225t az aj\225nlatom:[ENTER]500.000 Yang a Legend\225s Napl\243\233rt.[ENTER]Megegyez\252nk vagy sem? "
gameforge.new_quest_lv75._380_1_select = "Odaadom 500.000 Yang\233rt. "
