gameforge.new_quest_lv75._390_say = "OK, akkor felejtsd el. "
gameforge.new_quest_lv75._400_say = "Nem, sajn\225lom, ez t\250l dr\225ga nekem. "
gameforge.new_quest_lv75._410_say = "Hadd mondjak m\233g egy aj\225nlatot. Adok neked %s[ENTER]Yangot ez\233rt a Legend\225s Napl\243\233rt. "
gameforge.new_quest_lv75._420_say = "Ez megfelel neked? "
gameforge.new_quest_lv75._425_say = "Ez az utols\243 aj\225nlatom! "
gameforge.new_quest_lv75._430_1_select = "Odaadom %s Yang\233rt. "
gameforge.new_quest_lv75._430_2_select = "Akkor azt hiszem, mi nem k\246t\252nk ma \252zletet. "
gameforge.new_quest_lv75._440_say = "Amit akarsz... "
gameforge.new_quest_lv75._450_say = "Ez nem \233ppen olcs\243. De b\245kez\251 szeretn\233k lenni. "
gameforge.new_quest_lv75._460_say = "A b\245kez\251s\233gemnek is vannak hat\225rai. Adok neked[ENTER]500.000 Yangot a Legend\225s Napl\243\233rt. "
