gameforge.new_quest_lv80._030_say = "Oh, \233ppen id\245ben! \218gy hallottam hogy a Sz\225m\251z\246tt[ENTER]Barlangj\225ban volt\225l nemr\233g. "
gameforge.new_quest_lv80._040_say = "Ez az els\245 alkalom hogy olyanr\243l hallok aki \233lve[ENTER]visszat\233rt onnan. Be kell valljam, nagyon[ENTER]k\237v\225ncsi vagyok... "
gameforge.new_quest_lv80._050_1_say = "Van egy k\252ldet\233sem a sz\225modra, de el\233gg\233[ENTER]vesz\233lyes. De \250gy gondolom hogy egy magadfajta[ENTER]biztosan meg tudja csin\225lni. "
gameforge.new_quest_lv80._050_2_say = "Van egy k\252ldet\233sem a sz\225modra, de el\233gg\233[ENTER]vesz\233lyes. Viszont \250gy gondolom hogy egy[ENTER]magadfajta h\246lgy biztos meg tudja csin\225lni. "
gameforge.new_quest_lv80._060_say = "Vidd magaddal ezt a Fa Maszkot a Doyyumhwan[ENTER]ter\252letre. Ott keresd a L\225ngszellemeket. Lehet,[ENTER]hogy m\225r tal\225lkozt\225l vel\252k - g\246mb alak\250 l\233nyek,[ENTER]akiket l\225ngok bor\237tanak. "
gameforge.new_quest_lv80._070_say = "Ha meg\246lsz egyet bel\245l\252k, a Fa Maszk hamuv\225[ENTER]v\225lik. Ne b\225tortalanodj el ha ez nem m\251k\246dik[ENTER]els\245re. "
gameforge.new_quest_lv80._080_say = "Akko hozd el a hamut nekem. "
gameforge.new_quest_lv80._090_say = "Ha egy\233bk\233nt is a vadonba m\233sz, hozhatn\225l nekem[ENTER]%s J\233gr\246g\246t. Nagyon sz\252ks\233gem lenne r\225juk. "
gameforge.new_quest_lv80._100_say = "A jetiken gyakran szoktak lenni ilyen r\246g\246k.[ENTER]Teh\225t mire v\225rsz m\233g? "
gameforge.new_quest_lv80._110_say_title = "T\251z \233s J\233g "
gameforge.new_quest_lv80._120_say = "Soon h\237vott mag\225hoz... "
gameforge.new_quest_lv80._130_say = "M\225r megtal\225ltam a J\233gr\246g\246ket. "
gameforge.new_quest_lv80._140_say = "M\233g sz\252ks\233gem van: "
gameforge.new_quest_lv80._150_say_reward = "\218gyt\251nik megtal\225lhatom ha Jetikre vad\225szok! "
gameforge.new_quest_lv80._160_say = "A Komor Fa Maszk m\225r Megb\251volt Hamuv\225 v\225ltozott. "
gameforge.new_quest_lv80._170_say = "Sz\252ks\233gem van: "
gameforge.new_quest_lv80._180_say_reward = "Vinnem kell "
gameforge.new_quest_lv80._190_say_reward = "magammal. Soon szerint a maszk Megb\251v\246lt Hamuv\225[ENTER]v\225ltozik amikor a L\225ng Szellemekkel harcolok. "
gameforge.new_quest_lv80._200_say = "Most m\225r csak a Megb\251v\246lt Hamu \233s J\233gr\246g\246k[ENTER]kellenek. Remek, v\225rj egy picit... "
