gameforge.new_quest_premium_lv4._270_say_reward = "Yang: %d "
gameforge.new_quest_premium_lv4._280_say = "A P\233zsmaolaj n\233lk\252l nem tudom elk\233sz\237teni az \250j[ENTER]illatot. Engedd, hogy a forg\243 \233rme vezessen \233s[ENTER]hozz nekem m\233g egy p\233ld\225nyt. "
