gameforge.new_quest_premium_lv4._30_say = "Hi\225nyzik a kedvesem, a Fegyverkeresked\245. Heteken[ENTER]\225t \233nekelt nekem az ablakom alatt minden \233jjel \233s[ENTER]most nem hallottam fel\245le semmit napok \243ta.[ENTER]Lehet, hogy f\233l az ap\225mt\243l. Megk\233rdezn\233d t\245le,[ENTER]hogy mi a gondja? "
