gameforge.new_quest_premium_lv4._55_qSetTitle = "Vissza a Fegyverkeresked\245h\246z "
gameforge.new_quest_premium_lv4._60_sayTitle = "A rogue "
gameforge.new_quest_premium_lv4._65_qSetTitle = "Vidd el a P\233zsmaolajat a Fegyverkeresked\245h\246z "
gameforge.new_quest_premium_lv4._70_say = "Ez igaz, nem \233nekeltem az ablaka alatt t\246bb\233,[ENTER]mert ... oh, sz\243val, sz\233gyellem, ha err\245l kell[ENTER]besz\233lnem! A testszagom kezd visszatasz\237t\243v\225[ENTER]v\225lni. Gyakran tiszt\225lkodok, f\252rd\246k, de a szag[ENTER]nem megy el. Ez\233rt szeretn\233k kikeverni egy[ENTER]illatos olajat, ami elb\225joln\225 a kis mad\225rk\225mat, a[ENTER]Vegyeskeresked\245 H\246lgyet. A k\252ls\245 megjelen\233s[ENTER]nagyon fontos neki. "
gameforge.new_quest_premium_lv4._75_qSetTitle = "A Vegyeskeresked\245 elad\243n\245h\246z "
