gameforge.notify_test_server = {}
gameforge.notify_test_server._10_chat = "Tesztszerver "
gameforge.npc_talk = {}
gameforge.npc_talk._100_say = "\201n egy nagyon \246reg ember vagyok, de fitt \233s[ENTER]eg\233szs\233ges, mert van egy k\252l\246nleges titkom. Arra[ENTER]j\246ttem r\225, hogy a Gango-gy\246k\233r l\233b\245l \233s Tue[ENTER]gomb\225b\243l k\233sz\252lt ital meghosszabb\237tja az \233leted.[ENTER]Ha szeretn\233d kipr\243b\225lni az italt, vidd el a[ENTER]hozz\225val\243kat Yu-Hwan-nak. \213 el tudja neked[ENTER]k\233sz\237teni. "
gameforge.npc_talk._10_say = "\193llj mozdulatlanul \233s \245rizd meg a tart\225sodat.[ENTER]Viselkedj \233s ne kezdj el veszekedni. Tisztelettel[ENTER]viszonyulj embert\225rsaidhoz.[ENTER]Meg\233rtetted?  "
gameforge.npc_talk._110_npcChat = "K\246nnyen vedd... "
gameforge.npc_talk._120_say = "Sok \233ven \225t az er\245 titka ap\225r\243l fi\250ra sz\225llt a[ENTER]csal\225dunkban. Ap\225m mes\233lte, hogy ha a[ENTER]harangvir\225got j\243l kevered az italba, akkor az[ENTER]ital extra er\245t ad neked egy r\246vid id\245re. Ha j\243l[ENTER]tudom, Baek-Go el tudja k\233sz\237teni ezt az italt.[ENTER]Csak egy harangvir\225got kell vinned neki. "
gameforge.npc_talk._130_npcChat = "Menj mondd el a hegyen... "
gameforge.npc_talk._140_sayTitle = "Yu-Hwan, a zen\233sz: "
gameforge.npc_talk._150_say = "...A dombok f\246l\246tt \233s minden\252tt... Te is szereted[ENTER]a zen\233t? \201n mindenf\233le dalt \233neklek mag\225nyomban,[ENTER]hogy ne keveredjek bele a h\225bor\250ba. De egy orsz\225g[ENTER]n\233lk\252l ami megv\233dene, nem tudn\225m folytatni ezt a[ENTER]tev\233kenys\233get. "
gameforge.npc_talk._160_npcChat = "Mi\233rt olvasol ilyen sokat? "
gameforge.npc_talk._170_sayTitle = "Soon, a k\246nyvmoly: "
gameforge.npc_talk._180_say = "Oh, kalandor.[ENTER]A vil\225g tele van probl\233m\225kkal, \233s csak a tud\225s[ENTER]seg\237ts\233g\233vel nem lehet t\250l\233lni. Mindig tiszteld a[ENTER]k\246nyveidet. Rossz id\245kben seg\237tenek. Hidd el[ENTER]nekem!  "
gameforge.npc_talk._190_npcChat = "Vannak gyerekeid? "
gameforge.npc_talk._200_say = "Igaz\225b\243l nem szerettem volna saj\225t gyereket,[ENTER]de... Nos, gy\251jt\246m a Datolyaszilva Vir\225gokat mert[ENTER]ha j\243l el\245k\233sz\237ted \245ket, n\246velheted a m\225gikus[ENTER]energi\225idat vel\252k. Baek-Go j\246tt erre r\225. Csak egy[ENTER]sziromra van sz\252ks\233ge hogy elk\233sz\237thessen 100[ENTER]italt. Sajnos a Datolyaszilva Vir\225gnak van egy[ENTER]mell\233khat\225sa is. Ha egy n\245 visel egy nyakl\225ncot[ENTER]ezekb\245l szirmokb\243l akkor sz\252letik egy fia.[ENTER]K\246zt\252nk legyen mondva, a feles\233gem vissza is \233lt[ENTER]ezzel a lehet\245s\233ggel. "
gameforge.npc_talk._20_npcChat = "Hmm, j\243 illat van itt... "
gameforge.npc_talk._210_npcChat = "Mi a gond a l\225baddal? "
gameforge.npc_talk._220_sayTitle = "Handu-Up: "
gameforge.npc_talk._230_say = "Ez egyre jobb. Ahogy s\233t\225ltam mostan\225ban,[ENTER]megbotlottam egy Gango-gy\246k\233rben \233s kificamodott[ENTER]a bok\225m. Szerencs\233re ismerem Baek-Go doktort aki[ENTER]ell\225tott \233s adott egy tan\225csot: Ahhoz hogy ilyen[ENTER]egyszer\251 s\233r\252l\233seket meggy\243gy\237ts, k\233sz\237thetsz egy[ENTER]italt ebb\245l a Gango-gy\246k\233rb\245l. Teh\225t csin\225ltam[ENTER]egy te\225t ezekb\245l a gy\246kerekb\245l \233s meggy\243gy\237tott\225k[ENTER]a s\233r\252l\233st amit okoztak... "
gameforge.npc_talk._240_npcChat = "Ki vagy te? "
gameforge.npc_talk._250_sayTitle = "Wonda-Rim: "
gameforge.npc_talk._260_say = "\201n Wonda-Rim vagyok, Chaegirab unoka\246ccse. A[ENTER]b\225csik\225m h\237res! Te ismered \245t? Sokat k\237s\233rletezik[ENTER]italokkal \233s gy\243gyn\246v\233nyekkel. \205gy fedezte fel[ENTER]azt is, hogy ha \246sszekeversz 100 Bo-vizet egy[ENTER]Szederf\225val, akkor nagy v\233delmet kapsz a m\225gikus[ENTER]energi\225kkal szemben. Tudtommal Huahn-So el tudja[ENTER]k\233sz\237teni az italt, ha elviszed neki a[ENTER]hozz\225val\243kat. "
gameforge.npc_talk._270_npcChat = "Mi\233rt van neked ennyi sebhelyed? "
gameforge.npc_talk._280_sayTitle = "\193rul\243 Balso: "
gameforge.npc_talk._290_say = "Nem vagyok j\243 harcos \233s rendszeresen megs\233r\252ltem[ENTER]a csat\225kban. Egyszer megk\233rdeztem Yu-Hwan-t hogy[ENTER]tud-e k\233sz\237teni nekem egy italt ami megv\233d a[ENTER]s\233r\252l\233sekt\245l. Csin\225lt nekem valamit[ENTER]Harangvir\225gb\243l \233s Orgon\225b\243l, de sajnos a v\233delem[ENTER]nem volt elegend\245. De az is lehet hogy csak \233n[ENTER]vagyok t\250l b\233na. De biztos vagyok benne hogy az[ENTER]ital a hasznodra v\225lik majd. "
gameforge.npc_talk._300_npcChat = "Mi\233rt h\237v t\233ged olyan sok ember \225rul\243nak? "
gameforge.npc_talk._30_sayTitle = "Octavio, a vend\233gl\225t\243: "
gameforge.npc_talk._310_say = "Elmenek\252ltem a h\225bor\250b\243l \233s csatlakoztam a[ENTER]Feketesz\233l Band\225hoz. A bajt\225rsaim sosem[ENTER]bocs\225tottak meg nekem ez\233rt. Nem sokkal k\233s\245bb[ENTER]r\225j\246ttem, hogy a Feketesz\233l harcosok \225rtatlan[ENTER]embereket \246lnek, ez\233rt azonnal otthagytam \245ket.[ENTER]Sz\246rny\251 volt! "
gameforge.npc_talk._320_say = "\193rtatlan emberek lelkei sz\225radnak a te[ENTER]lelkiismereteden? Akkor t\233nyleg meg\233rdemled az[ENTER]\225rul\243 nevet. Megtagadtad a norm\225lis \233letet nekik. "
gameforge.npc_talk._330_say = "T\246rv\233ny n\233lk\252li vil\225gban \233l\252nk. De eld\246nt\246ttem,[ENTER]hogy soha t\246bb\233 nem csin\225lok semmi rosszat. Nem[ENTER]akarom, hogy az emberek \225rul\243nak tartsanak.[ENTER][ENTER]Van egy kis Yangod a sz\225momra? "
gameforge.npc_talk._340_npcChat = "T\233ged h\237vnak a tud\243snak? "
gameforge.npc_talk._350_sayTitle = "Uriel, a tud\243s: "
gameforge.npc_talk._360_say = "Olyan sok mindent kell tanulni ebben a nagy[ENTER]vil\225gban. Ha tudatlans\225g katonai hatalommal[ENTER]p\225rosul, akkor ez nem j\243. Te csak nem \237gy akarsz[ENTER]\233lni, mint ezek a tudatlan katon\225k! Vagy igen? A[ENTER]tud\225s hatalom!  "
gameforge.npc_talk._370_npcChat = "A forr\225saim azt mondj\225k hogy te gy\243gy\237t\225ssal foglalkozol. "
gameforge.npc_talk._380_say = "Megteszem amit tudok. De egyre t\246bb \233s t\246bb \233let[ENTER]hal meg naponta ebben a vesz\233lyes vil\225gban. Nincs[ENTER]el\233g gy\243gyszer\252nk vagy seg\237t\245nk. Neh\233z id\245ket[ENTER]\233l\252nk! Tal\225n tudn\225l nekem k\233s\245bb seg\237teni? "
gameforge.npc_talk._390_npcChat = "Hogy megy a vad\225szat? "
gameforge.npc_talk._400_sayTitle = "Yang-Shin, a vad\225sz: "
gameforge.npc_talk._40_say = "\220dv\246z\246llek! A mi \233tterm\252nk egy nagy nemzetk\246zi[ENTER]l\225nchoz tartozik. Gyere egyszer el hozz\225nk \233s[ENTER]egy\233l n\225lunk.  "
gameforge.npc_talk._410_say = "Hmm, mi\243ta a Metin k\246vek lehullottak, az \225llatok[ENTER]nagyon vadak lettek. Manaps\225g az \233letedet[ENTER]kock\225ztatod m\233g akkor is ha csak csirk\233t m\233sz[ENTER]vad\225szni. Nagyon vesz\233lyes mostan\225ban a[ENTER]vad\225szoknak. Szerencs\233re \233n az egyik legjobb[ENTER]vagyok! "
gameforge.npc_talk._420_npcChat = "Honnan ez a hal\225li pontoss\225g? "
gameforge.npc_talk._430_say = "Nagyon \252gyes vagyok az \237jjal, mert van egy titkos[ENTER]receptem, hehe! Amikor Barackvir\225g levet keversz[ENTER]\246ssze Orgon\225val, egy olyan italt kapsz ami[ENTER]megn\246veli a pontoss\225godat. Vidd el ezeket a[ENTER]hozz\225val\243kat Yu-Hwan-nak, biztos vagyok benne,[ENTER]hogy elk\233sz\237ti neked az italt. "
gameforge.npc_talk._440_npcChat = "Milyen sz\233p vir\225gok... "
gameforge.npc_talk._450_say = "R\233gen Barackvir\225g szirmokat gy\251jt\246ttem a[ENTER]testv\233remmel. De ma m\225r egyed\252l csin\225lom. Nem[ENTER]n\233znek ki olyan j\243l, de speci\225lis hat\225suk van. Ha[ENTER]viszel Barackvir\225g Szirmokat Baek-Go-nak, k\233sz\237t[ENTER]neked egy italt ami f\252rge-l\225b\250v\225 tesz t\233ged! "
gameforge.npc_talk._460_npcChat = "Hol van a testv\233red? "
gameforge.npc_talk._470_say = "Ebben a napokban a fiv\233rem sokat van \250ton. Alig[ENTER]l\225tom \245t mostan\225ban \233s sokat agg\243dom \233rte. "
gameforge.npc_talk._480_npcChat = "A h\225bor\250 idej\233n "
gameforge.npc_talk._490_sayTitle = "Yu-Rang, a rizs s\252ti elad\243n\245: "
gameforge.npc_talk._500_say = "Neh\233z eladni a rizs-s\252tiket a h\225bor\250 idej\233n. A[ENTER]bandit\225k miatt nagyon sok v\225s\225rl\243t elvesztettem.[ENTER]\201n m\225r sajnos nem tudom hogy mit tehetn\233k a[ENTER]t\250l\233l\233s\233rt. "
gameforge.npc_talk._50_say = "Annak ellen\233re, hogy ez egy nagy \233tterem,[ENTER]meglep\245en egyszer\251 a berendez\233s. "
gameforge.npc_talk._510_npcChat = "Ki v\225s\225rol gyakran t\245led? "
gameforge.npc_talk._520_say = "A legt\246bb s\252timet utaz\243knak adom el. Egy nap egy[ENTER]fekete lovas j\246tt el hozz\225m. Fizet\233sk\233nt egy[ENTER]receptet adott amihez Zin-v\237z sz\252ks\233ges. Ez egy[ENTER]ital ami a t\225mad\243 er\245det n\246veli. Eladtam a[ENTER]receptet Huahn-So-nak. Ha viszel egy kis[ENTER]Sim-vizet \233s egy Alpesi R\243zs\225t Huahn-So-nak,[ENTER]k\233sz\237t neked Zin-vizet bel\245l\252k. "
gameforge.npc_talk._530_npcChat = "Mi\233rt vagy ilyen szomor\250? "
gameforge.npc_talk._540_say = "Ki gondolta volna hogy a v\225gyaink ilyen k\246nnyen[ENTER]\233s k\246ny\246rtelen\252l elv\233sznek... Szeg\233ny f\233rjem a[ENTER]csat\225ban esett el! ... K\233rlek bosszuld meg a[ENTER]hal\225l\225t. "
gameforge.npc_talk._550_npcChat = "Olyan sok ember esett el a h\225bor\250ban... "
gameforge.npc_talk._560_say = "Egyre t\246bb embert vesz\237t\252nk el a h\225bor\250ban, ez\233rt[ENTER]az asszonyok a faluban \246sszegy\251ltek \233s megk\233rt\233k[ENTER]Huahn-So-t, k\233sz\237tsen egy jobb gy\243gyitalt. Hossz\250[ENTER]kutat\225s ut\225n l\233trehozott egy olyan italt, ami[ENTER]megn\246veli a v\233delmet, \237gy kevesebb \233let-italt[ENTER]kell haszn\225lni. Menj, l\225togasd meg \245t. Biztos[ENTER]vagyok benne, hogy elk\233sz\237ti neked az italt, amit[ENTER]\245 SamBo-v\237znek h\237v. Csak egy kis Dok-v\237zre \233s[ENTER]Alpesi r\243zs\225ra van sz\252ks\233ge ehhez. "
gameforge.npc_talk._570_npcChat = "Oh, milyen aranyos gyerek... "
gameforge.npc_talk._580_sayTitle = "Ah-Yu: "
gameforge.npc_talk._590_say = "M\225r megint ord\237t ...[ENTER]Valami finoms\225gra f\225j a foga, vagy ... oh[ENTER]nem!  "
gameforge.npc_talk._600_npcChat = "Hogy vagytok? "
gameforge.npc_talk._60_npcChat = "Mondj valamit a cser\233p\225rur\243l. "
gameforge.npc_talk._610_say = "Gyermekem! Most, hogy a f\233rjem elesett a[ENTER]h\225bor\250ban, nekem kell gondoskodnom magamr\243l.[ENTER]Saj\225t er\245b\245l pr\243b\225lom eltartani magam \233s[ENTER]gyermekemet, \233s a Bo-v\237znek k\246sz\246nhet\245en tal\225ltam[ENTER]egy m\243dot a t\250l\233l\233sre. Vinnem kell Yu-Hwan-nak[ENTER]100 Datolyaszilva-vir\225g levet \233s egy Tue gomb\225t.[ENTER]Ebb\245l \245 Bo-vizet f\245z, amit k\246nnyen el lehet adni.[ENTER]V\233gt\233re is, valamib\245l meg kell \233lnem... "
gameforge.npc_talk._620_npcChat = "Hogy van a f\233rjed? "
gameforge.npc_talk._630_sayTitle = "Aranyo: "
gameforge.npc_talk._640_say = "Az \233n \250gynevezett f\233rjem a k\246nyveivel \233l[ENTER]h\225zass\225gban. R\225m m\225r r\225m se n\233z. \201s \233n nem vagyok[ENTER]egy cs\250f asszony.  "
gameforge.npc_talk._650_npcChat = "Hogy megy az \252zlet? "
gameforge.npc_talk._660_say = "Ami\243ta kit\246rt a h\225bor\250, az \252zlet nagyon rosszul[ENTER]megy. A keresked\245k egyes\252lete egykor nagyon[ENTER]gazdag \233s er\245s volt, de azoknak az id\245knek v\233ge.[ENTER]Nem hagyhatjuk figyelmen k\237v\252l a vadakat, a feh\233r[ENTER]esk\252 harcosokat \233s a s\246t\233t sz\233l katon\225kat sem. "
gameforge.npc_talk._670_npcChat = "Mi\233rt vagy ilyen rosszkedv\251? "
gameforge.npc_talk._680_sayTitle = "Taurean : "
gameforge.npc_talk._690_say = "Harang egy gonosz l\225ny![ENTER]\201n ut\225lom \245t! Gyenge vagyok, \233s \245 az \233letemet[ENTER]gyakran megkeser\237ti!  "
gameforge.npc_talk._700_say = "Te egy f\233rfi vagy \233s izmos vagy. Edz egy[ENTER]kicsit!  "
gameforge.npc_talk._70_sayTitle = "Yonah, a fazekas: "
gameforge.npc_talk._710_npcChat = "Mit csin\225lsz? "
gameforge.npc_talk._720_sayTitle = "Harang: "
gameforge.npc_talk._730_say = "Taurean-ra v\225rok. Sokat j\225tszunk \233s harcolunk is[ENTER]egy\252tt. Micsoda gy\225va alak! Ha nem j\246n \246nk\233nt[ENTER]akkor megnehez\237tem az \233let\233t! "
gameforge.npc_talk._740_npcChat = "Taurean megijedt t\245led. "
gameforge.npc_talk._750_say = "Taurean val\243j\225ban er\245sebb n\225lam. Teh\225t most[ENTER]kital\225ltam egy taktik\225t, amivel \233n nyerek. Egy[ENTER]feh\233r nindzs\225t\243l hallottam, hogy \246sszekeverhetsz[ENTER]Young-vizet Szederf\225val. \205gy k\233sz\237tesz egy italt,[ENTER]ami lehet\245v\233 teszi, hogy gyorsabban \252ss. Akkor[ENTER]v\233gre le fogom tudni gy\245zni Taurean-t! Ha te is[ENTER]gyorsabban szeretn\233l t\225madni, vidd el az eml\237tett[ENTER]hozz\225val\243kat Huahn-So-nak. Biztos megcsin\225lja[ENTER]neked az italt. "
gameforge.npc_talk._760_npcChat = "\218j bel\225t\225s... "
gameforge.npc_talk._770_say_title = "Seon-Pyeong "
gameforge.npc_talk._780_say = "Bar\225tom, a vil\225g tele van megv\225laszolatlan[ENTER]k\233rd\233sekkel. \201s \233n a v\225laszokat \233s a tud\225st[ENTER]kutatom. Hallott\225l m\225r epikus fegyverekr\245l \233s[ENTER]szellemk\246vekr\245l? "
gameforge.npc_talk._790_npcChat = "Mit csin\225lsz? "
gameforge.npc_talk._800_say = "Lehet, hogy m\225r tudod, \233n az ismeretlen tud\225st[ENTER]kutatom. \201s jelenleg a fegyverek tov\225bbi[ENTER]meger\245s\237t\233s\233n \233s szellemk\246vek erej\233nek[ENTER]fejleszt\233s\233n dolgozom. "
gameforge.npc_talk._80_say = "Szeretek agyagmunk\225s lenni. Nagyon kiel\233g\237t\245[ENTER]l\225tni ahogy megform\225lom az agyagot a kezeimmel \233s[ENTER]egy form\225t k\233sz\237tek bel\245le... \193ltal\225ban egyszer\251[ENTER]dolgokat csin\225lok. Keleten a kontinens k\252ls\245[ENTER]perem\233n a gy\225rt\225si m\243dszerek j\243val[ENTER]kifinomultabbak. L\225ttam n\233h\225ny alkot\225st ott, \233s[ENTER]nagyon tetszettek. N\233ha amikor id\245m engedi, \233n is[ENTER]k\237s\233rletezek. De m\233g nem j\246ttem r\225 hogy milyen[ENTER]tr\252kk\246t haszn\225lnak. "
gameforge.npc_talk._810_npcChat = "A fegyver kutat\225s... "
gameforge.npc_talk._820_say = "\201rdekes, ugye? Szeretn\233l t\246bbet tudni r\243la? Akkor[ENTER]hozd el nekem a megfelel\245 65-\246s fegyver +9-et.[ENTER]Sz\252ks\233gem van egy Meger\245s\237t\245 iratra \233s k\233t[ENTER]\193ld\225stekercsre is. Megpr\243b\225lok ezekb\245l egy epikus[ENTER]fegyvert k\233sz\237teni. "
gameforge.npc_talk._830_say = "De nem \237g\233rhetem hogy m\251k\246dni fog. "
gameforge.npc_talk._840_npcChat = "A Szellemk\246vek... "
gameforge.npc_talk._850_say = "A szellemk\246veket sokan haszn\225lj\225k, de annak[ENTER]ellen\233re hogy gyakran haszn\225ltak, a legt\246bben nem[ENTER]ismerik ezeknek a val\243di erej\233t. De a kutat\225som[ENTER]sor\225n t\246bbre is r\225j\246ttem. Ha hozol nekem m\233g egy[ENTER]szellemk\246vet, jobb\225 tehetem azt neked. "
gameforge.npc_talk._90_npcChat = "Nagyon \233l\233nk vagy a korodhoz k\233pest... "
gameforge.olympic_badge = {}
gameforge.olympic_badge._010_npcChat = "H\245si med\225l "
gameforge.olympic_badge._020_say = "Seg\237ts! "
gameforge.olympic_badge._030_say = "\193tkozott tolvajok...[ENTER]Tegnap \233jjel bet\246rtek a h\225zamba![ENTER]Ellopt\225k a H\245si med\225lom. Az \245s\246m kapta a med\225lt,[ENTER]miut\225n 42,195 km-t futott a csatat\233rt\245l a[ENTER]cs\225sz\225rig, hogy besz\225moljon a gy\245ztes[ENTER]csat\225jukr\243l.[ENTER]\201s most elt\251nt! "
gameforge.olympic_badge._040_say = "Oh, Istenem... ez egy felbecs\252lhetetlen \233rt\233k[ENTER]volt a csal\225dom \233s j\243magam sz\225m\225ra. Mi a csod\225t[ENTER]tehetn\233k? "
gameforge.olympic_badge._050_say = "Seg\237tesz nekem? "
gameforge.olympic_badge._060_npcChat = "H\245si med\225l "
gameforge.olympic_badge._070_say = "V\233gre! Visszat\233rt\233l![ENTER]Megtal\225ltad a H\245si med\225lt? "
gameforge.olympic_badge._080_say = "De mi\233rt? Mit akarnak tenni azok a tolvajok a[ENTER]med\225lommal? Az \233rt\233ktelen az idegenek sz\225m\225ra![ENTER]Tudsz seg\237teni, hogy megtal\225ljam? "
gameforge.olympic_badge._090_npcChat = "Tal\225ld meg a H\245si med\225lt! "
gameforge.olympic_badge._100_say = "\220res k\233zzel t\233rt\233l vissza? Oh ne, igaz\225n szomor\250[ENTER]vagyok. Ki tud nekem seg\237teni, ha te nem?[ENTER]K\233rlek, folytasd a keres\233st! "
gameforge.olympic_badge._110_say = "Megtal\225ltad a med\225lom![ENTER]De v\225rj... ez csak egy darabja. Micsoda sz\233gyen,[ENTER]\246t darabra t\246rt\233k![ENTER]K\233rlek, hozd vissza minden darabj\225t! Akkor lehet,[ENTER]\246ssze tudom illeszteni a med\225lt. "
gameforge.olympic_badge._120_say = "Azok a sz\233gyentelen b\251n\246z\245k elt\246rt\233k a csal\225di[ENTER]\246r\246ks\233gem! K\246sz\246n\246m, hogy megtal\225ltad minden[ENTER]darabj\225t. Most m\225r \246ssze tudom illeszteni a[ENTER]darabokat. "
gameforge.olympic_badge._130_say = "Nagyon sz\233pen k\246sz\246n\246m! Vissza\225ll\237tottad[ENTER]csal\225dunk becs\252let\233t! Term\233szetesen a f\225radoz\225sod[ENTER]nem volt hi\225baval\243. Itt a jutalmad! "
gameforge.olympic_badge._140_say = "T\233nyleg le akarod mondani a k\252ldet\233st? Ha az[ENTER]'Igen'-t v\225lasztod, nem fogod tudni k\233s\245bb \250jra[ENTER]felvenni azt. "
gameforge.olympic_badge._150_say = "Meg\233rtem, ha most nincs el\233g id\245d. Gyere vissza[ENTER]k\233s\245bb, amikor neked jobban megfelel. De ne[ENTER]v\225rakoztass sok\225ig! "
gameforge.olympic_badge._160_say = "Sajnos t\250l k\233s\245n \233rkezt\233l \233s most nem tudsz[ENTER]seg\237teni. Minden j\243t k\237v\225nok a j\246v\245ben! "
gameforge.olympic_badge._170_say = "Vad\225ssz a sz\246rnyekre, akik megloptak! De l\233gy[ENTER]\243vatos, nagyon er\245sek - legal\225bb 30-as szint\251ek.[ENTER]Ha visszahozod a H\245si med\225lom, nagylelk\251en[ENTER]megjutalmazlak! "
gameforge.olympic_badge._180_say = "Tal\225ld meg a H\245si med\225lt \233s add \225t Yu-Hwan-nak. "
gameforge.olympic_badge._190_say = "Yu-Hwan-nak a seg\237ts\233gedre van sz\252ks\233ge. L\225togasd[ENTER]meg! A m\225sodik faluban tal\225lod. "
