gameforge.skill_reset2._10_npcChat = "K\233szs\233geket vissza\225ll\237tani "
gameforge.skill_reset2._110_say = "Ahogy gondolod. Ha meggondoln\225d magad, gyere el[ENTER]m\233g egyszer. "
gameforge.skill_reset2._120_say = "Nincs el\233g Yangod. Sajn\225lom, de nem seg\237thetek.[ENTER]V\233gt\233re is, nekem is \233lnem kell valamib\245l. "
gameforge.skill_reset2._130_say = "Ez a t\225rgy lehet\245s\233get ny\250jt sz\225modra, hogy[ENTER]elfeledd r\233gi kik\233pz\233sed \233s elkezdj egy teljesen[ENTER]\250jat. A haszn\225lat\225hoz azonban legal\225bb 31-es[ENTER]szint\251nek kell lenned. Akkor megv\225ltoztathatod[ENTER]sorsod. Val\243ban h\225tat akarsz ford\237tani r\233gi[ENTER]k\233pess\233geidnek, melyek azz\225 tettek, aki most[ENTER]vagy? "
gameforge.skill_reset2._135_say = "Nem v\225lasztott\225l oktat\243t, \233s nincs[ENTER]k\233pess\233gpontod, amit vissza lehetne \225ll\237tani! "
gameforge.skill_reset2._140_say = "Ez a t\225rgy csak 31-es szintt\245l haszn\225lhat\243. "
gameforge.skill_reset2._20_say = "M\233g nem kezdt\233l el semmilyen k\233pz\233st sem! Am\237g[ENTER]nem osztod el a k\233pess\233gpontjaidat, nem tudod[ENTER]\245ket vissza\225ll\237tani sem. Gyere vissza miut\225n[ENTER]hib\225t k\246vett\233l el a k\233pz\233sed sor\225n, \233s akkor[ENTER]boldogan seg\237tek. "
gameforge.skill_reset2._30_say = "Att\243l tartok, gyermekem, nem seg\237thetek rajtad.[ENTER]M\225r el\233rted a %s. szintet, viszont sajnos csak a[ENTER]legfeljebb 30-as szintig tudod megv\225ltoztatni[ENTER]k\233pz\233sed. "
gameforge.skill_reset2._40_say = "Nem v\225lasztott\225l oktat\243t, \233s nincs[ENTER]k\233pess\233gpontod, amit vissza lehetne \225ll\237tani! "
gameforge.skill_reset2._50_say = "Nah\225t, mi a helyzet? Nagy b\225natot l\225tok a[ENTER]szemeidben... V\225rj, tudok neked seg\237teni. El[ENTER]tudom int\233zni, hogy az emberek elfelejts\233k[ENTER]k\233szs\233geiket, \237gy \250jakat tudnak tanulni. Mit[ENTER]gondolsz? Ez csak %s Yangodba fog ker\252lni. "
gameforge.skill_reset2._60_select = "Nem vissza\225ll\237tani "
gameforge.skill_reset2._70_say = "N\233zd azt a komor arcot! Nem j\243l \233rzed magad? Ha[ENTER]nem vagy megel\233gedve tudom\225nyoddal: tudok[ENTER]seg\237teni, hogy elfeledj mindent egy szempillant\225s[ENTER]alatt. "
gameforge.skill_reset2._80_say = "Ez azt jelenti, hogy vissza lesz \225ll\237tva minden[ENTER]k\233szs\233gpontod, \233s \250jra kioszthatod majd azokat.[ENTER]Sajnos azonban nem tudom visszaadni azokat a[ENTER]pontokat, melyeket k\246nyvek olvas\225s\225\233rt kapt\225l,[ENTER]ezek elvesznek a vissza\225ll\237t\225s ut\225n. T\233nyleg ezt[ENTER]akarod? Elfelejteni \233s el\246lr\245l kezdeni mindent?[ENTER]Akkor adj nekem %s Yangot. "
