gameforge.spider_dungeon_3floor_boss._100_say = "Azt akarod mondani, nem \233rzed magad el\233g[ENTER]magabiztosnak ahhoz, hogy bel\233pj a P\243k[ENTER]kazamat\225ba? Tapasztalt harcos vagy kifinomult[ENTER]technikai k\233pess\233ggel - n\233h\225ny k\237s\233rteties[ENTER]l\233nynek nem kellene probl\233m\225t jelentenie[ENTER]sz\225modra. De ugye tudod, hogy sz\252ks\233ged lesz a[ENTER]Bel\233p\233si Enged\233lyre, hogy bejuss a barlangba? "
gameforge.spider_dungeon_3floor_boss._10_npcChat = "Bel\233p\233s a F\233szekbe "
gameforge.spider_dungeon_3floor_boss._110_sendLetter = "\218j vesz\233ly "
gameforge.spider_dungeon_3floor_boss._120_say = "Pontosan lem\225soltad a feliratot. Mutasd meg a[ENTER]Kapit\225nynak. "
gameforge.spider_dungeon_3floor_boss._130_say = "Nagyszer\251, megcsin\225ltad! H\225t mutasd... Hmm. Nem[ENTER]ismerem ezeket a karaktereket, nem \233rtek bel\245le[ENTER]egyetlen sz\243t sem. Ki kellene k\233rned a tud\243s[ENTER]Uriel tan\225cs\225t. "
gameforge.spider_dungeon_3floor_boss._140_say = "Menj a tud\243s Urielhez \233s mutasd meg neki a[ENTER]m\225solatot. Eg\233szen biztosan le tudja majd[ENTER]ford\237tani. "
gameforge.spider_dungeon_3floor_boss._150_say = "A Kapit\225ny arra k\233r, hogy fejtsem meg ezt a[ENTER]rejt\233lyes feliratot? Term\233szetesen! Szeretem a j\243[ENTER]kih\237v\225sokat. Add csak ide.[ENTER]Ez... ez sz\246rny\251! Tess\233k, erre a pap\237rra \237rtam a[ENTER]ford\237t\225st. Vidd el a kapit\225nynak olyan gyorsan,[ENTER]ahogy csak tudod, majd gyere vissza. Ha igaz, ami[ENTER]ide van \237rva, mindannyian nagy vesz\233lyben[ENTER]vagyunk! Menj, siess! "
gameforge.spider_dungeon_3floor_boss._160_say = "M\233g nem volt\225l a Kapit\225nyn\225l?! K\233rlek! Sietned[ENTER]kell. Nincs vesztegetni val\243 id\245nk. Musz\225j[ENTER]elolvasnia ezt a levelet! "
gameforge.spider_dungeon_3floor_boss._170_sayTitle = "Uriel level\233nek k\233zbes\237t\233se "
gameforge.spider_dungeon_3floor_boss._180_say = "Ez a cs\246k\246ny\246s v\233nember... Olyan nagy k\233r\233s lett[ENTER]volna egy k\246sz\246n\246m?! H\225t j\243. Azt mondta, az[ENTER]inform\225ci\243 k\252l\246n\246sen fontos, teh\225t jobb, ha[ENTER]elviszem a Kapit\225nynak olyan gyorsan, ahogy csak[ENTER]tudom. "
gameforge.spider_dungeon_3floor_boss._190_npcChat = "Uriel levele "
gameforge.spider_dungeon_3floor_boss._200_say = "Oh, ne! Ha igaz az, ami ide van \237rva, akkor egy[ENTER]vesz\233lyes p\243kf\233le d\233mon sz\246vi h\225l\243j\225t a P\243k[ENTER]kazamata harmadik szintj\233n - a P\243k-b\225r\243n\245. A[ENTER]felirat szerint egy k\252l\246nleges kulcsra van[ENTER]sz\252ks\233ged, hogy bejuthass ebbe a rejtett[ENTER]barlangba. El\245bb menj Urielhez \233s k\233rdezd err\245l a[ENTER]kulcsr\243l. Azt\225n gy\251jts magad k\246r\233 sereget \233s[ENTER]rohamozd meg a P\243k-b\225r\243n\245 rejtekhely\233t! Tess\233k,[ENTER]itt van sz\225modra egy m\225sik Bel\233p\233si enged\233ly is. "
gameforge.spider_dungeon_3floor_boss._20_say = "Ezt a kaput csak a P\243k-kulcs nyitja. "
gameforge.spider_dungeon_3floor_boss._210_npcChat = "A P\243k-kulcs "
gameforge.spider_dungeon_3floor_boss._220_say = "Fel kellene keresnem Urielt, amilyen gyorsan csak[ENTER]tudom. "
gameforge.spider_dungeon_3floor_boss._230_say = "Ah, h\225t visszat\233rt\233l. Felt\233telezem, a Kapit\225ny[ENTER]arra utas\237tott, hogy puszt\237tsd el a P\243k-b\225r\243n\245t,[ENTER]ugye? Ugyanakkor a B\225r\243n\245 F\233szk\233nek bej\225rata le[ENTER]van pecs\233telve, \233s csak a P\243k-kulcs nyitja. Ennek[ENTER]a kulcsnak az el\245\225ll\237t\225sa igen munkaig\233nyes. De[ENTER]ha hozol nekem egy P\243k m\233regzs\225kot, egy[ENTER]P\243ktoj\225szs\225kot, egy P\243kh\225l\243t, P\243kszemet, P\243kl\225bat[ENTER]\233s elhozod a P\243k-kir\225lyn\245 m\233rg\233t is, k\233sz\237tek[ENTER]egyet neked. "
gameforge.spider_dungeon_3floor_boss._240_say = "Azt akarod, hogy k\233sz\237tsek neked egy P\243kkulcsot?[ENTER]Ehhez sz\252ks\233gem van egy P\243k m\233regzs\225kra, egy[ENTER]P\243ktoj\225szs\225kra, egy P\243kh\225l\243ra, P\243kszemre,[ENTER]P\243kl\225bra \233s a P\243k-kir\225lyn\245 m\233rg\233re is.[ENTER]Megtal\225ltad valamennyi \246sszetev\245t? "
gameforge.spider_dungeon_3floor_boss._250_say = "Fantasztikus! N\225lad van minden, amire sz\252ks\233gem[ENTER]van a P\243k-kulcs el\245\225ll\237t\225s\225hoz. V\225rj egy[ENTER]pillanatot. Nem kellene t\250l sok\225ig tartania, hogy[ENTER]elk\233sz\252lj\246n... "
gameforge.spider_dungeon_3floor_boss._260_say = "Ha, k\233sz! Tess\233k, itt a P\243k-kulcsod. Lehet\245v\233[ENTER]teszi, hogy bejuss a P\243k-b\225r\243n\245 rejtek\233be.[ENTER]Sikeres harcot k\237v\225nok neked \233s t\225rsaidnak ez[ENTER]ellen a hossz\250 l\225b\250 bestia ellen! De sietned kell[ENTER]- a kulcs nagyon instabil. 24 \243ra m\250lva[ENTER]alkot\243elemeire esik sz\233t. "
gameforge.spider_dungeon_3floor_boss._270_say = "Oh, oh... Att\243l tartok, azt kell mondjam, senki[ENTER]sem sz\252letik mesternek... Meg kell \233rtened, ennek[ENTER]a kulcsnak k\252l\246n\246sen bonyolult az el\245\225ll\237t\225si[ENTER]m\243dja. M\233g a legkisebb hiba is sikertelen[ENTER]k\237s\233rlethez vezet.[ENTER]Sajnos elvesz\237tettem minden p\243k \246sszetev\245t, amit[ENTER]\246sszegy\251jt\246tt\233l nekem a l\233trehoz\225shoz. A[ENTER]k\246vetkez\245 pr\243b\225lkoz\225s biztosan siker\252lni fog! "
gameforge.spider_dungeon_3floor_boss._280_say = "Valami m\233g mindig hi\225nyzik, most m\233g nem tudom[ENTER]elk\233sz\237teni a P\243k-kulcsot. Itt egy eml\233keztet\245,[ENTER]hogy mire van sz\252ks\233g\252nk: egy P\243k m\233regzs\225kra,[ENTER]egy P\243ktoj\225szs\225kra, egy P\243kh\225l\243ra, P\243kszemre,[ENTER]P\243kl\225bra \233s a P\243k-kir\225lyn\245 m\233rg\233re is. "
gameforge.spider_dungeon_3floor_boss._300_say = "Csoportvezet\245d bel\233pett a kazamat\225ba. Akarod[ENTER]k\246vetni? "
gameforge.spider_dungeon_3floor_boss._30_npcChat = "SD3 k\252ldet\233s \250jrakezd\233se "
gameforge.spider_dungeon_3floor_boss._310_say = "T\250l sok\225ig tartott. A kulcs m\225r sz\233tm\225llott. \218jat[ENTER]kell el\245\225ll\237tani, hogy ism\233t bel\233phess erre a[ENTER]helyre. "
gameforge.spider_dungeon_3floor_boss._320_say = "M\225r van egy csoport a B\225r\243n\245 F\233szk\233ben, akik[ENTER]t\225madj\225k a P\243k-b\225r\243n\245t. "
gameforge.spider_dungeon_3floor_boss._330_say = "Csak akkor l\233phetsz be, ha az el\245z\245 csoport m\225r[ENTER]v\233gzett a feladat\225val. K\233rj\252k, t\233rj vissza %s[ENTER]perc m\250lva. "
gameforge.spider_dungeon_3floor_boss._340_say = "V\225rakoz\225si id\245, am\237g a B\225r\243n\245 F\233szk\233nek kapuja[ENTER]\250jra megny\237lik: "
gameforge.spider_dungeon_3floor_boss._350_say = "%s perc "
gameforge.spider_dungeon_3floor_boss._360_say = "A harcos, aki el\245tted l\233pett a barlangba, csak[ENTER]t\237z m\225sodperc m\250lva tud tov\225bbmenni.[ENTER]K\233rj\252k, v\225rj egy kicsit. "
gameforge.spider_dungeon_3floor_boss._370_say = "Szeretn\233d elkezdeni a hadj\225ratot? 20 perced van a[ENTER]teljes\237t\233sre. Ez id\245 v\233g\233ig senki sem l\233phet be a[ENTER]B\225r\243n\245 F\233szk\233be.[ENTER]A k\246vetkez\245 hadj\225rat csak egy \243ra eltelt\233vel[ENTER]k\237s\233relhet\245 meg \250jra. "
gameforge.spider_dungeon_3floor_boss._380_say = "A bej\225rat kinyit\225s\225hoz sz\252ks\233ged van a[ENTER]P\243k-kulcsra. "
gameforge.spider_dungeon_3floor_boss._390_say = "Csak a csoportvezet\245 tudja haszn\225lni a[ENTER]P\243k-kulcsot. "
gameforge.spider_dungeon_3floor_boss._400_say = "A P\243k-b\225r\243n\245 elpusztult! H\225rom percen bel\252l[ENTER]minden harcos ki lesz teleport\225lva a barlangb\243l. "
gameforge.spider_dungeon_3floor_boss._40_say = "A kulcs el\245\225ll\237t\225sa el\245tt "
gameforge.spider_dungeon_3floor_boss._410_say = "Ez nem m\251k\246d\246tt! K\233rj\252k pr\243b\225ld \250jra! "
gameforge.spider_dungeon_3floor_boss._420_notice = "Figyelmeztet\233s! A P\243k-b\225r\243n\245 egyre d\252h\246sebb![ENTER]T\225mad\225sai er\245sebbek lesznek, ugyanakkor cs\246kken a[ENTER]v\233delme is. "
gameforge.spider_dungeon_3floor_boss._50_npcChat = "P\243k kazamata 3 "
gameforge.spider_dungeon_3floor_boss._60_say = "Ah, de j\243, hogy itt vagy. Fontos inform\225ci\243m van[ENTER]sz\225modra: egy felder\237t\245 csapat felfedezett egy[ENTER]harmadik szintet is a P\243k kazamat\225ban. \193ll\237t\243lag[ENTER]rendk\237v\252l hatalmas \233s alattomos p\243kok f\233szkelnek[ENTER]ott. Ezen fel\252l embereim tal\225ltak egy r\233gi[ENTER]s\237rk\246vet egy felirattal, de nem tudt\225k azt[ENTER]lem\225solni. Tess\233k, ez a Bel\233p\233si enged\233ly szabad[ENTER]bel\233p\233st ny\250jt sz\225modra a P\243k kazamat\225ba. "
gameforge.spider_dungeon_3floor_boss._70_sendLetter = "A Felirat "
gameforge.spider_dungeon_3floor_boss._80_say = "A P\243k kazamata harmadik emelet\233n tal\225lsz majd egy[ENTER]r\233gi s\237rk\246vet egy v\233sett felirattal. M\225sold le \233s[ENTER]vidd el a Kapit\225nynak. "
gameforge.spider_dungeon_3floor_boss._90_say = "T\246k\233letes! Megtal\225ltad a r\233gi s\237rk\246vet \233s[ENTER]k\233sz\237tett\233l egy m\225solatot a felirat\225r\243l! Menj[ENTER]vissza a Kapit\225nyhoz \233s mutasd meg neki. "
gameforge.subquest_01 = {}
