gameforge.subquest_01._140_sayTitle = "Yonah : "
gameforge.subquest_01._150_say = "Te j\243 \233g! Ilyen nincs! Nem tudom abbahagyni a[ENTER]k\246h\246g\233st, hogyan dolgozzak \237gy?[ENTER]Az elad\243n\245 k\252ld\246tt t\233ged a vegyeskeresked\233sb\245l?[ENTER]Vannak \252res \252vegeim, de nem adom \245ket ingyen. "
