gameforge.subquest_01._190_npcChat = "Hogy barackmagokat szerezz... "
gameforge.subquest_01._200_say = "A falu hat\225r\225ban a vaddiszn\243kt\243l szerezhetsz[ENTER]\245szibarackmagot. Amint a parasztok[ENTER]\245szibarackmagot \252ltetnek, a vaddiszn\243k ism\233t[ENTER]ki\225ss\225k \233s felfalj\225k.[ENTER]K\246h, k\246h.[ENTER]K\246sz\246sz\246m el\245re is. "
gameforge.subquest_01._20_npcChat = "\220res \220vegek Beszerz\233se "
gameforge.subquest_01._210_sendLetter = "Menj vissza Yonah-hoz "
gameforge.subquest_01._220_sayTitle = "Menj vissza Yonahhoz "
gameforge.subquest_01._230_sayReward = "Megtal\225ltad az \245szibarackmagot, vidd el Yonahnak. "
