gameforge.subquest_01._300_say = "K\246sz\246n\246m. Rem\233lem, nem okozott sok bonyodalmat.[ENTER]Tiszteletem jel\233\252l ezt adom neked. M\233g egyszer[ENTER]k\246sz\246n\246m sz\233pen! "
