gameforge.subquest_02._150_say = "Vegyeskeresked\233s Elad\243n\245:[ENTER]Nem vagyok meglepve, mindig szokatlan k\233r\233sei[ENTER]vannak. Meg tudn\225d k\233rdezni m\233g egyszer? "
gameforge.subquest_02._160_say = "Vegyeskeresked\233s Elad\243n\245:[ENTER]Ezt mondta? Biztos? Ez nem az ap\225mra vall... Meg[ENTER]tudn\225d k\233rdezni m\233g egyszer? Biztos vagyok benne,[ENTER]hogy nem arra a fog\225sra gondolt. "
