gameforge.subquest_03._150_sayReward = "Kapt\225l 3000 tapasztalat pontot.[ENTER]Kapt\225l 5000 Yangot.[ENTER]Kapt\225l egy Farkassz\245rt. "
gameforge.subquest_03._20_say = "Tudsz seg\237teni nekem?[ENTER]Mi\243ta a Metink\246vek potyognak, az\243ta egy[ENTER]ismeretlen betegs\233g t\246rt ki. Sok orvos dolgozik[ENTER]az eseten, de hi\225nyzik nek\252nk egy sz\252ks\233ges[ENTER]hozz\225val\243, hogy el tudjuk k\233sz\237teni a gy\243gyszert.[ENTER]A falu hat\225r\225ban vad \225llatok vannak \233s ott nem[ENTER]tudunk szabadon mozogni.  "
gameforge.subquest_03._30_say = "Be tudod szerezni a gy\243gyszer hozz\225val\243j\225t? Az\233rt[ENTER]k\233rdezlek, mert te katona vagy. A gy\243gyszer[ENTER]elk\233sz\237t\233s\233hez sz\252ks\233gem van egy k\233kfarkas[ENTER]m\225j\225ra. "
gameforge.subquest_03._40_say = "Hozd el nekem egy k\233kfarkas m\225j\225t. Sz\243lj\225l, ha[ENTER]meg van.  "
gameforge.subquest_03._50_sayReward = "Mi\243ta a Metink\246vek potyognak, kit\246rt egy[ENTER]ismeretlen betegs\233g. Ahhoz, hogy a betegs\233g ellen[ENTER]egy gy\243gyszert tudjunk el\245\225ll\237tani, Baek-Gonak[ENTER]sz\252ks\233ge van egy k\233kfarkas m\225j\225ra. Vidd el hozz\225. "
gameforge.subquest_03._60_npcChat = "Ahhoz, hogy egy k\233kfarkas m\225j\225hoz hozz\225jussunk "
