gameforge.subquest_03._80_say = "A k\233kfarkast nagyon sajn\225lom, de sz\252ks\233g\252nk van a[ENTER]m\225j\225ra a gy\243gyszer el\245\225ll\237t\225s\225hoz. K\246sz\246n\246m[ENTER]el\245re.  "
