gameforge.subquest_04._150_sayTitle = "Deokbae, a fav\225g\243: "
gameforge.subquest_04._160_say = "\220dv n\233ked! Van p\225r j\243 fejsz\233m itt. Szeretn\233l[ENTER]venni egyet? Nincs sz\252ks\233ged fejsz\233re? Akkor[ENTER]mi\233rt j\246tt\233l? Oh, egy lev\233l a Kov\225cst\243l.[ENTER]K\246sz\246n\246m. \201n fav\225g\243 vagyok, de foglalkozom[ENTER]cs\225k\225nyok \233s m\225s eszk\246z\246k elad\225s\225val is. N\233ha[ENTER]rendelek t\245le eszk\246z\246ket. \205gy lett\252nk j\243 bar\225tok. "
gameforge.subquest_04._170_say = "T\233nyleg innom kellene vele valamit a[ENTER]Seo-Pyung-B\225rban. K\246sz\246n\246m, hogy elhoztad a[ENTER]levelet. Add \225t \252dv\246zletemet a[ENTER]kov\225csnak.  "
