gameforge.subquest_04._220_say = "Ennek igaz\225n \246r\252l\246k.[ENTER]Gyere gyorsan \250jra vissza  "
gameforge.subquest_04._230_say = "Teh\225t elvesz\237tetted?[ENTER]T\251nj el...  "
gameforge.subquest_04._240_say = "Menj el a kov\225cshoz \233s hozd el megint a levelet.[ENTER]De most nehogy elvesz\237tsd. Minden[ENTER]j\243t.  "
gameforge.subquest_04._250_sayReward = "Menj vissza a kov\225cshoz \233s megkapod a jutalmadat. "
