gameforge.subquest_04._270_npcChat = "Elvittem a levelet. "
gameforge.subquest_04._280_say = "Sz\243val hogy van Deokbae? Hehe, semmit sem[ENTER]v\225ltozott. K\246sz\246n\246m. Vedd \225t ezt a kis jutalmat.[ENTER]Nem sok de tal\225n hasznodra v\225lik egyszer. K\246szi[ENTER]m\233gegyszer. "
