gameforge.subquest_06._120_sayReward = "Menj a Kov\225cshoz \233s k\233rdezd meg, mennyit haladt a[ENTER]p\225nc\233llal, amit a Fegyverzet-keresked\245 rendelt[ENTER]t\245le. "
