gameforge.subquest_08._20_say = "Eln\233z\233st, tudn\225l seg\237teni? A bab\225m nem hagyja[ENTER]abba a s\237r\225st \233s nem tudom hogy mi csillap\237thatn\225[ENTER]le. A bab\225m im\225dja a Rizs S\252tiket, tal\225n az[ENTER]seg\237t. Azt hiszem, a Fegyverkeresked\245 tudja, hol[ENTER]lehet olyat kapni. Meg tudn\225d \245t k\233rdezni? "
gameforge.subquest_08._210_makequestbutton = "Tal\225ld meg Yu-Rang-ot "
gameforge.subquest_08._220_targetVid = "Rizs S\252ti "
gameforge.subquest_08._230_sayReward = "Menj el a Rizs S\252ti elad\243hoz, Yu-Rang-hoz.[ENTER]Megtal\225lod \245t a k\246vetkez\245 faluban. "
gameforge.subquest_08._240_sayTitle = "Yu-Rang: "
gameforge.subquest_08._250_say = "Seg\237thetek valamiben? Oh Rizs S\252tik! Persze hogy[ENTER]tudok adni! De tudn\225l tenni egy sz\237vess\233get nekem[ENTER]el\245tte? Egy Taurean nev\251 fi\250 gyakran j\246n ide[ENTER]zavarni engem, holott \233n nem b\225ntottam \245t egyszer[ENTER]sem. Ha megb\252nteted Taurean-t nekem, akkor adok[ENTER]Rizs S\252tiket, OK? "
gameforge.subquest_08._260_makequestbutton = "Keresd meg Taurean-t "
gameforge.subquest_08._270_sayReward = "Yu-Rangot gyakran zavarja Taurean. B\252ntesd meg[ENTER]Taurean-t \233s akkor kapsz Rizs S\252tiket. "
gameforge.subquest_08._280_npcChat = "Mi\233rt m\233rges\237ted Yu-Rangot? "
gameforge.subquest_08._290_say = "Micsoda, kit zavartam \233n? Oh hogy azt a l\225nyt aki[ENTER]Rizs S\252tiket \225rul? Nem, \233n nem zavartam \245t! Csak[ENTER]unatkoztam \233s \245 sz\233pnek t\251nt \233s nem t\251nt t\250l[ENTER]elfoglaltnak. Sz\243val odamentem hozz\225 n\233h\225nyszor[ENTER]hogy j\225tsszak vele, de azt\225n \245 m\233rges lett... A[ENTER]l\225nyok furcs\225k. Akkor lehet hogy nem megyek oda[ENTER]hozz\225 t\246bbet! "
gameforge.subquest_08._300_makequestbutton = "Vissza Yu-Ranghoz "
gameforge.subquest_08._30_select = "Elfogadni. "
gameforge.subquest_08._310_targetVid = "Rizs S\252ti "
gameforge.subquest_08._320_sayReward = "Taurean nem zaklatja Yu-Rang-ot tov\225bb. Menj el[ENTER]hozz\225 \233s k\233rj t\245le Rizs S\252tit. "
gameforge.subquest_08._330_say = "Haha! Megb\252ntetted Taurean-t! K\246sz\246n\246m! Most m\225r[ENTER]k\233tszer is meggondolja, hogy visszaj\246jj\246n-e. Itt[ENTER]van a Rizs S\252tid. J\243 \233tv\225gyat hozz\225! "
gameforge.subquest_08._340_makequestbutton = "Vissza Ah-Yu-hoz "
gameforge.subquest_08._350_targetVid = "Rizs S\252ti Ah-Yu-nak "
gameforge.subquest_08._360_sayReward = "Kapt\225l Rizs S\252tit Yu-Rang-t\243l. Most vidd el[ENTER]ezeket Ah-Yu-hoz. Megtal\225lod \245t \233s gyerek\233t az[ENTER]els\245 faluban. "
gameforge.subquest_08._370_npcChat = "Itt a Rizs S\252ti a gyerekednek. "
gameforge.subquest_08._380_say = "Elhoztad a Rizs S\252tit! K\246sz\246n\246m sz\233pen. Oh n\233zd[ENTER]csak, a bab\225m abbahagyta a s\237r\225st \233s boldogan[ENTER]eszi a s\252tit. Megcsin\225ltad, k\246sz\246net a[ENTER]seg\237ts\233ged\233rt! "
gameforge.subquest_08._390_sayReward = "Kapt\225l 26.000 tapasztalati pontot.[ENTER]Kapt\225l 10.000 Yangot. "
gameforge.subquest_08._40_say = "De... nem hagyhatom itt ezt a helyet \233s a baba[ENTER]terroriz\225lja a k\246rny\233ket... Nem tart sok\225ig![ENTER]Biztos hogy nincs id\245d erre? "
gameforge.subquest_08._50_say = "Nagyon el vagy foglalva?[ENTER]K\233rlek gyere k\233s\245bb m\233g egyszer.[ENTER]Ne s\237rj gyermekem. "
