gameforge.subquest_09._110_sendLetter = "Arany Fejsze megtal\225lva "
gameforge.subquest_09._120_npcChat = "Itt van az Arany fejsze. "
gameforge.subquest_09._130_say = "K\246sz\246n\246m! Az ad\243sod vagyok, ha, ha, ha.[ENTER]Most m\225r nem kell azon gondolkoznom, hogy mit[ENTER]mondjak Deokbaenak, ha l\225tom!  "
gameforge.subquest_09._140_sayReward = "Kapt\225l 36.000 tapasztalati pontot.[ENTER]Kapt\225l 10.000 Yangot.[ENTER]Kapt\225l egy D\237szt\225rgyat. "
gameforge.subquest_09._20_npcChat = "Az Arany Fejsze "
gameforge.subquest_09._30_say = "Eml\233kszel m\233g a bar\225tomra, Deokbae-ra. Azt[ENTER]\237g\233rtem, hogy egy fejsz\233t k\233sz\237tek neki, de egy[ENTER]pillanatra nem figyeltem oda \233s egy feh\233r esk\252[ENTER]katona ellopta t\245lem. M\233g egyszer meg tudod[ENTER]szerezni a fejsz\233t? Egy feh\233r esk\252 katon\225n\225l kell[ENTER]lennie. Fel kell tudnod ismerni a fejsz\233t, mert[ENTER]nincs sok bel\245le. Fejedelmi jutalomban lesz[ENTER]r\233szed, ha megtal\225lod! "
gameforge.subquest_09._40_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_09._50_sayTitle = "Kov\225cs "
gameforge.subquest_09._60_say = "Felt\233tlen\252l sz\252ks\233gem van arra a fejsz\233re![ENTER]Fogunk m\233g tal\225lkozni? Viszl\225t! "
gameforge.subquest_09._70_say = "K\246sz\246n\246m, hogy te meg akarod szerezni nekem.[ENTER]Vigy\225zz magadra, mert a kl\225n gondot okoz. "
gameforge.subquest_09._80_say = "K\246sz\246n\246m, hogy te meg akarod szerezni nekem.[ENTER]Vigy\225zz magadra, mert a kl\225n igaz\225n sok[ENTER]bossz\250s\225got okoz  "
