gameforge.subquest_10._110_npcChat = "Az ellopott hajt\251 "
gameforge.subquest_10._120_say = "Micsoda? Azt hiszi, hogy \233n loptam el a hajt\251t?[ENTER]H\225t ez hallatlan! Kinek n\233z engem? \201n[ENTER]szorgalmasan dolgoztam a m\251helyemben! Ah, lehet,[ENTER]nem kellene elmes\233lnem, de a fegyverkeresked\245[ENTER]j\225rt egy ideje a vegyeskeresked\245 n\245 boltj\225ban. "
gameforge.subquest_10._130_makequestbutton = "Az ellopott hajt\251 "
gameforge.subquest_10._140_sayReward = "K\233rdezd meg a fegyverkeresked\245t, hogy hol van a[ENTER]hajt\251. "
gameforge.subquest_10._150_say = "Micsoda? Te azt hiszed, hogy \233n loptam el a[ENTER]vegyeskeresked\245 n\245t\245l a hajt\251t? Nem, nem, ezt[ENTER]t\233nyleg nem tettem! Becs sz\243![ENTER]Ehm...[ENTER]\201n ott voltam, hogy a vegyeskeresked\245 n\245t[ENTER]megl\225togassam! De nem volt ott, a hely\233n egy[ENTER]feh\233r esk\252 \237j\225szt tal\225ltam. Amikor engem[ENTER]megl\225tott, akkor lefutott. Tal\225n \245 lopta el a[ENTER]hajt\251t. "
gameforge.subquest_10._160_sayReward = "Szerezd vissza a feh\233r esk\252 \237j\225szt\243l a hajt\251t! "
gameforge.subquest_10._170_sendLetter = "Megtal\225ltad a Hajt\251t "
gameforge.subquest_10._180_targetVid = "Menj el az \225rushoz. "
gameforge.subquest_10._190_npcChat = "Megvan a Hajt\251d itt "
gameforge.subquest_10._200_say = "Oh, k\246sz\246n\246m sz\233pen.[ENTER]Nagyon \246r\252l\246k, hogy a szeretett hajt\251met ism\233t[ENTER]visszakaptam! Olyan gyakran seg\237tett\233l nekem.[ENTER]Hogyan tudom ezt viszonozni? Van egy[ENTER]lovagl\243jegyem. Ez csak egy kicsinys\233g, de nincs[ENTER]m\225r r\225 sz\252ks\233gem, mert az \252zletemet m\225r nem[ENTER]hagyom el olyan k\246nnyen. Fogadd el a k\246sz\246netem[ENTER]jel\233\252l. K\246sz\246n\246m.  "
gameforge.subquest_10._20_say = "K\233rlek hallgass meg. Egy nagyon kellemetlen[ENTER]helyzetben vagyok. Egy r\246vid id\245re elhagytam az[ENTER]\252zletemet, mert valami fontosat el kellett[ENTER]int\233znem. Ez id\245 alatt valaki ellopta a kedvenc[ENTER]hajt\251met. "
gameforge.subquest_10._210_sayReward = "Kapt\225l 60.000 tapasztalati pontot.[ENTER]Kapt\225l 10.000 Yangot.[ENTER]Kapt\225l egy Lovagl\243jegyet. "
gameforge.subquest_10._220_say = "A cip\245 hajt\251met m\233g nem tal\225ltad meg?[ENTER]Nagyon rem\233lem, hogy m\233g megtal\225lod. "
gameforge.subquest_10._230_select = "Abbahagyni "
gameforge.subquest_10._240_say = "T\233nyleg abbahagyni? "
gameforge.subquest_10._250_say = "Igen ezek nem k\246nny\251 dolgok... Tal\225n jobb ha[ENTER]pihensz egy kicsit \233s megpr\243b\225lod k\233s\245bb. "
gameforge.subquest_10._260_say = "Hol van a kedvenc hajt\251m?[ENTER]H\225t m\225r megint semmi ... szia  "
gameforge.subquest_10._270_say = "K\246sz\246n\246m sz\233pen. Ez sokat jelent nekem. "
gameforge.subquest_10._30_say = "Az \233desap\225m aj\225nd\233kozta nekem a sz\252let\233snapomra[ENTER]ezt a d\237sz hajt\251t \233s \233n im\225dom.[ENTER]Az \252zletemet m\225r soha nem is tudom elhagyni, mert[ENTER]k\252l\246nben m\233g valami fontosat ellopnak. Meg tudod[ENTER]nekem keresni? \201n a kov\225csra gyan\237tok, mert \245[ENTER]egyszer azt eml\237tette, hogy valami ilyesmit[ENTER]keres.  "
gameforge.subquest_10._40_select = "\201n keresem \245t "
gameforge.subquest_10._50_say = "Feladatot biztosan megszak\237tani? "
gameforge.subquest_10._60_say = "Viszontl\225t\225sra J\243 sz\243rakoz\225st "
gameforge.subquest_10._70_say = "Ez az \233n a hajt\251m ...[ENTER]Viszontl\225t\225sra "
gameforge.subquest_10._80_say = "Megkeresed nekem?[ENTER]Oh, k\246sz\246n\246m sz\233pen! "
