gameforge.subquest_11._110_npcChat = "L\225ttad Mirine b\225tyj\225t? "
gameforge.subquest_11._120_say = "Szerelmes lettem an\233lk\252l, hogy tudtam volna, mit[ENTER]jelent... Lalalaa...[ENTER]Kit keresel? Mirine b\225tyj\225t? Besz\233ltem vele p\225r[ENTER]sz\243t, m\233g miel\245tt a hegyekbe ment volna ritka[ENTER]gy\243gyn\246v\233nyek keres\233s\233re. Nem tudom, hol van[ENTER]most.[ENTER]A falu vad\225sza gyakran megy a hegyekbe. Mi\233rt nem[ENTER]k\233rdezed meg \245t?[ENTER]La, la, la a szerelem szomor\250, de sz\233p... "
gameforge.subquest_11._130_targetVid = "K\233rdezd meg Yang-Shint, hogy hol van Mirine[ENTER]b\225tyja. "
gameforge.subquest_11._140_say = "Mirine testv\233re? Igen, gy\243gyf\252veket keresett a[ENTER]hegyekben. Nagyon boldog volt amikor ritka[ENTER]gy\243gyf\252veket tal\225lt. \218j ruh\225kat akart venni a[ENTER]testv\233r\233nek a profitb\243l. Nagyon kedves fi\250.[ENTER]Biztos visszat\233r n\233h\225ny nap m\250lva, nem gondolod? "
gameforge.subquest_11._150_targetVid = "Mes\233ld el Mirin\233nek az \250js\225got. "
gameforge.subquest_11._160_npcChat = "\218js\225g Mirine b\225tyj\225r\243l. "
gameforge.subquest_11._170_say = "N\233zd, kaptam egy levelet a testv\233remt\245l! Azt[ENTER]\237rta, tal\225lt egy helyet tele rengeteg gy\243gyf\251vel,[ENTER]\233s hogy sok\225ra j\246n haza.[ENTER]Sajn\225lom, nem kellett volna ezzel zavarnom t\233ged.[ENTER]Tess\233k, nem sok, de rem\233lem, elfogadod \233s[ENTER]megbocs\225tasz nekem. K\246sz\246n\246m, hogy felv\225llalt\225l[ENTER]egy ilyen nagy utat. "
gameforge.subquest_11._180_sayReward = "Kapt\225l 122.000 tapasztalat pontot.[ENTER]Kapt\225l 5.000 Yangot. "
gameforge.subquest_11._20_npcChat = " Tal\225ld meg a b\225ty\225mat. "
gameforge.subquest_11._30_say = "Megk\233rhetlek egy sz\237vess\233gre?[ENTER]A b\225ty\225m m\225r r\233gen elment, \233s az\243ta nem hallottam[ENTER]r\243la. Lassan m\225r agg\243dom miatta. Megkeresn\233d \245t,[ENTER]ha nem t\250l sokat k\246vetelek?  "
gameforge.subquest_11._40_say = "A b\225ty\225m Yu-Hwant, a zen\233szt akarta megl\225togatni[ENTER]a k\246vetkez\245 faluban. Ha Yu-Hwanhoz m\233sz, biztos[ENTER]megtudsz valami \250jat a b\225ty\225mr\243l.[ENTER]K\246sz\246n\246m el\245re is.  "
gameforge.subquest_11._50_select = "Igen, csin\225lom "
gameforge.subquest_11._60_say = "V\233g\233rv\233nyesen feladod ezt a k\252ldet\233st? "
gameforge.subquest_11._70_say = "K\246sz\246n\246m sz\233pen.[ENTER]K\233rlek keresd meg nekem.[ENTER]Nagyon agg\243dom.[ENTER]Viszl\225t. "
gameforge.subquest_11._80_say = "K\225r, hogy nem akarsz nekem seg\237teni ...[ENTER]Viszl\225t. "
gameforge.subquest_11._90_say = "Te meg akarod \245t nekem keresni?[ENTER]K\246sz\246n\246m sz\233pen, sokat agg\243dom miatta.[ENTER]Sok sikert.  "
