gameforge.subquest_13._150_say = "Elejtettem valamit amikor menek\252ltem a tigrisek[ENTER]el\245l: Egy csomag ami fontos k\246nyveket[ENTER]tartalmazott ruh\225val \246sszek\246tve. Ha azok nem[ENTER]ker\252lnek el\245, nem tudom folytatni a kutat\225somat a[ENTER]Metin K\246vekr\245l. Hozd el a csomagot nekem \233s kapsz[ENTER]\233rcet cser\233be. "
gameforge.subquest_13._160_npcChat = "Megvan a csomagod. "
gameforge.subquest_13._170_say = "K\246sz\246n\246m![ENTER]\201n t\250l gyakran k\233rlek egy sz\237vess\233gre.[ENTER]Itt van! Fogadd ezt a kev\233s vas\233rcet. Rem\233lem, ez[ENTER]a c\233lnak megfelel.  "
gameforge.subquest_13._180_say = "Micsoda? M\233g t\246bb Vas\233rcre van sz\252ks\233ged? Ez nem[ENTER]terem csak \250gy, mag\225t\243l! Adok neked m\233g t\246bb[ENTER]Vas\233rcet, de el\245bb meg kell tenned nekem egy[ENTER]sz\237vess\233get. Tigrisek lopt\225k el a csomagomat.[ENTER]Mentenem kellett a b\245r\246met, \233s abban a csomagban[ENTER]nagyon fontos dokumentumok voltak. Ha nincs meg,[ENTER]nem tudom folytatni a kutat\225somat a[ENTER]Metink\246vekr\245l.[ENTER]K\233rlek, keresd meg a csomagot, amit a tigrisek[ENTER]elloptak t\245lem. "
gameforge.subquest_13._190_say = "M\225r odaadtam neked. Nem[ENTER]eml\233kszel?  "
