gameforge.subquest_13._210_say = "Te megtal\225ltad Uriel csomagj\225t Menj vissza hozz\225 "
gameforge.subquest_13._220_npcChat = "Adj nekem v\225sznat. "
gameforge.subquest_13._230_say = "V\225szon k\233ne? Odaadtam Ah-Yu-nak.[ENTER]V\225rj![ENTER]Ha m\225r \250gyis elm\233sz hozz\225, elvihetn\233d neki ezt a[ENTER]levelet. J\243 bar\225tok vagyunk, de a gyermeke[ENTER]sz\252let\233se \243ta nem tal\225lkoztunk. Meg\237rom neki azt[ENTER]is, hogy adjon neked a V\225szonb\243l... \237gy mindenki[ENTER]j\243l j\225r. \201s add \225t neki \252dv\246zletem! "
gameforge.subquest_13._240_say = "Ariyoung:[ENTER]Te biztos kapt\225l v\225sznat Ah-Yut\243l, nem igaz? "
gameforge.subquest_13._250_npcChat = "Ariyoung levele "
gameforge.subquest_13._260_say = "Egy lev\233l Ariyoung-t\243l? J\243 fel\245le hallani ennyi[ENTER]id\245 ut\225n. R\233gen sokszor tal\225lkoztunk \233s[ENTER]besz\233lgett\252nk, de mostan\225ban ez kiss\233[ENTER]bonyolultabb lett. V\225rj egy picit. Azt \237rja itt,[ENTER]hogy neked V\225szonra van sz\252ks\233ged. Ariyoung adott[ENTER]nekem bel\245le. Adhatok neked is. K\246sz\246n\246m, hogy[ENTER]elhoztad a levelet. R\246gt\246n v\225laszolok is neki... "
gameforge.subquest_13._270_qSetTitle = "Menj\252nk a Fegyverkeresked\245h\246z "
gameforge.subquest_13._280_targetVid = "Menj el a fegyverkeresked\245h\246z. "
gameforge.subquest_13._290_sayTitle = "Anyagot leadni "
gameforge.subquest_13._300_sayReward = "N\225lam van az \225ru.[ENTER]Indul\225s a fegyverkeresked\245h\246z. "
gameforge.subquest_13._30_say = "H\233, megtenn\233l nekem egy sz\237vess\233get?\218jfajta[ENTER]fegyvereket pr\243b\225lok k\233sz\237teni. Nem k\246nny\251[ENTER]azonban ehhez megtal\225lni a megfelel\245[ENTER]nyersanyagot. Sok megrendel\233sem van, ez\233rt nem[ENTER]tudom magam felkutatni ezeket a nyersanyagokat.[ENTER]Be tudod ezeket szerezni nekem? "
gameforge.subquest_13._310_say = "J\243 munk\225t v\233gezt\233l! Te igaz\225n j\243 k\233pess\233g\251 \233s[ENTER]nagyon gyors vagy. Most hadd dolgozzam ezeken a[ENTER]fegyvereken![ENTER]*Kalap\225l, kalap\225l*[ENTER]Na, elk\233sz\252ltem. Ezek az \250jfajta fegyvert\237pusok.[ENTER]Mindenem beleadtam! Rem\233lem, tetszik az \250j[ENTER]fegyvered \233s \233lvezed majd a haszn\225lat\225t! "
gameforge.subquest_13._320_sayTitle = "Jutalom: "
gameforge.subquest_13._330_sayReward = "Kapt\225l 122.000 tapasztalat pontot.[ENTER]Kapt\225l 20.000 Yangot. "
gameforge.subquest_13._340_sayReward = "Kapt\225l egy Sz\233les Kard+3-t. "
gameforge.subquest_13._350_sayReward = "Kapt\225l egy Oll\243 T\245r+3-t. "
gameforge.subquest_13._360_sayReward = "Kapt\225l egy P\225va Legyez\245+3-t. "
gameforge.subquest_13._40_say = "Term\233szetesen meg foglak jutalmazni.[ENTER]Ha k\233szen vannak a fegyverek, akkor adok neked[ENTER]egyet bel\245l\252k.[ENTER]A k\246vetkez\245 nyersanyagra van sz\252ks\233gem: vas\233rc,[ENTER]v\225szon. Vas\233rcet Urieln\233l kaphatsz, v\225sznat[ENTER]Ariyoungn\225l. \201rtes\237ts engem, ha \246sszegy\251jt\246tted a[ENTER]sz\252ks\233ges anyagot.  "
gameforge.subquest_13._50_say = "T\233nyleg nem akarod a feladatot v\233gbe vinni? "
gameforge.subquest_13._60_say = "Azthiszem ez t\250l sok volt neked.[ENTER]Gyere vissza amikor t\246bb id\245d lesz! "
gameforge.subquest_13._70_say = "Ha akarod, akkor nem lehet mit tenni.[ENTER]Viszl\225t nem sok\225ra. "
gameforge.subquest_13._80_say = "Nagyon j\243![ENTER]Amint a fegyverek elk\233sz\252ltek, kapsz t\245lem egyet.[ENTER]Sok sikert! "
gameforge.subquest_13._90_sendLetter = "Keress anyagokat "
gameforge.subquest_15 = {}
gameforge.subquest_15._100_targetVid = "T\233rj vissza a V\225ros \213rh\246z "
gameforge.subquest_15._10_targetVid = "Eun-Jung a Feh\233r Esk\252b\245l "
gameforge.subquest_15._110_sayReward = "Meg\246lted Eun-Jung-ot a Feh\233r Esk\252b\245l. Menj vissza[ENTER]a V\225ros \213rh\246z \233s jelentsd neki. "
gameforge.subquest_15._120_say = "Fantasztikus vagy! Jobb vagy, mint amire[ENTER]sz\225m\237tottam. Mi nem tudtunk mit kezdeni a Feh\233r[ENTER]Esk\252 k\233t vezet\245j\233vel, te pedig ilyen egyszer\251en[ENTER]legy\245zted \245ket. "
gameforge.subquest_15._130_say = "Ez rendk\237v\252li. Megfelel\245 jutalmat kapsz ez\233rt.[ENTER]K\233rlek vedd ezt \225t \233s dolgozz tov\225bb a v\225ros[ENTER]b\233k\233j\233\233rt! "
gameforge.subquest_15._140_sayReward = "Kapt\225l 150.000 tapasztalat pontot.[ENTER]Kapt\225l 25.000 Yangot.[ENTER]Kapt\225l egy Arany Nyakl\225nc+4-t. "
gameforge.subquest_15._20_say = "Gyere ide egy picit.[ENTER]Hallottam r\243lad a Kapit\225nyt\243l. Vakmer\245nek t\251nsz.[ENTER]Ez\233rt sz\252ks\233gem van a seg\237ts\233gedre: A Feh\233r Esk\252[ENTER]egyre rosszabbul viselkedik. "
gameforge.subquest_15._30_say = "Legy\245zted Mi-Jung-ot a Feh\233r Esk\252 vezet\245j\233t. De[ENTER]m\233g mindig vesz\233lyben vagyunk! A Feh\233r Esk\252[ENTER]vesz\233lyess\233ge nem hogy cs\246kkent volna, hanem[ENTER]n\246vekedett! "
gameforge.subquest_15._40_say = "Hogy v\233get vess\252nk ennek, el kell t\225vol\237tanunk a[ENTER]vezet\245t, Eun-Jung-ot. A t\246bbi m\225r nem probl\233ma.[ENTER]Menj \233s \246ld meg Eun-Jung-ot! A sorsunk a te[ENTER]kezedben van! "
gameforge.subquest_15._50_sayTitle = "Gondnok: "
gameforge.subquest_15._60_say = "Visszaj\246ssz k\233s\245bb? Te vagy a megfelel\245 ember[ENTER]erre. "
gameforge.subquest_15._70_say = "Nem tudsz? Na, rendben. Viszl\225t nem sok\225ra. "
gameforge.subquest_15._80_say = "Tudtam, hogy seg\237teni fogsz. \214ld meg Eun-Jungot,[ENTER]mi elint\233zz\252k a marad\233kot. Sok szerencs\233t! "
gameforge.subquest_15._90_sayReward = "\214ld meg a vezet\245t, Eun-Jung-ot. Rem\233lhet\245leg a[ENTER]Feh\233r Rend ut\225na lecsillapodik. "
gameforge.subquest_16 = {}
gameforge.subquest_16._100_qSetTitle = "K\233rdezd Yu-Hwan-t "
gameforge.subquest_16._10_targetVid = "Keresd meg a p\225nc\233los lovass\225got "
gameforge.subquest_16._110_targetVid = "Menj Yu-Hwan-hoz "
gameforge.subquest_16._120_say = "Az \233let olyan csod\225latos - a szeretet olyan[ENTER]csod\225latos...[ENTER]Oh, megint te! Most mit akarsz? Inform\225ci\243t a[ENTER]p\225nc\233los lovass\225gr\243l? Mi\233rt k\233rdezel engem r\243luk?[ENTER]A kapit\225nynak nagy tervei vannak? "
gameforge.subquest_16._130_sayTitle = "Yu-Hwan:  "
gameforge.subquest_16._140_say = "Nem sok feljegyz\233s maradt meg abb\243l az id\245b\245l, de[ENTER]ismerek p\225r dalt a p\225nc\233los lovass\225gr\243l. V\225rj egy[ENTER]picit, csak be\225ll\237tom a hangszeremet...[ENTER]Ja hogy sietsz? Manaps\225g m\225r senki sem sz\225nja[ENTER]idej\233t arra hogy figyeljen...[ENTER]Nah\225t, r\246viden Isup lovass\225ga majdnem[ENTER]legy\245zhetetlen volt. Rendk\237v\252l j\243l k\233pzett[ENTER]katon\225k, neh\233z p\225nc\233llal, ugyanakkor gyorsak \233s[ENTER]mozg\233konyak. "
gameforge.subquest_16._150_say = "Ez volt a legjobb sereg amit ez a kontinens[ENTER]valaha l\225tott. Sok orsz\225g lett al\225rendelve mert[ENTER]semmi sem tudta meg\225ll\237tani a lovass\225got. Ma is[ENTER]hasonl\243 lenne. Csakhogy durva edz\233si m\243dszerekre[ENTER]\233s sok j\243 min\245s\233g\251 vasra lenne sz\252ks\233ged egy[ENTER]ilyen sereg fel\225ll\237t\225s\225hoz. K\233rdezhetn\233d err\245l a[ENTER]H\225zal\243t \233s Urielt. \213k tal\225n t\246bb r\233szletet[ENTER]tudnak. "
gameforge.subquest_16._160_makequestbutton = "Menj a H\225zal\243hoz "
gameforge.subquest_16._170_qSetTitle = "A p\225nc\233los lovass\225g "
gameforge.subquest_16._180_targetVid = "H\225zal\243: "
gameforge.subquest_16._190_sayReward = "Yu-Hwan, a muzsikus azt mondja hogy a H\225zal\243 \233s[ENTER]Uriel tal\225n t\246bb inform\225ci\243val szolg\225lhat a[ENTER]p\225nc\233los lovass\225gr\243l. El\245bb keresd fel a H\225zal\243t. "
gameforge.subquest_16._200_sayTitle = "H\225zal\243: "
gameforge.subquest_16._20_npcChat = "A p\225nc\233los lovass\225g "
gameforge.subquest_16._210_say = "Mit szeretn\233l egy egyszer\251 H\225zal\243t\243l? A p\225nc\233los[ENTER]lovass\225g vas p\225nc\233lja? Azok r\233gi t\246rt\233netek. Kit[ENTER]\233rdekelhet az? A meg\233lhet\233s\233rt kell dolgoznom,[ENTER]nem cseveghetek eg\233sz nap! "
gameforge.subquest_16._220_say = "Egyre nehezebb az elv\225r\225soknak megfelelni. Ami\243ta[ENTER]ezek a k\246vek lehullottak az \233gb\245l, nekem csak[ENTER]a...[ENTER]Mit mondasz? Ja igen, a lovass\225g.[ENTER]Ha j\243l tudom, speci\225lis p\225nc\233lt viseltek \233s a[ENTER]l\233trehoz\225sukhoz k\252l\246nleges szak\233rtelemre volt[ENTER]sz\252ks\233g. Azok voltak a legjobb p\225nc\233lok, amiket[ENTER]valaha k\233sz\237tettek! Egyszer\251 k\233sek, de m\233g nyilak[ENTER]sem tudt\225k \225t\252tni ezeket a t\246k\233letes p\225nc\233lokat! "
gameforge.subquest_16._230_say = "Gondolhatod hogy milyen fontosak voltak ezek a[ENTER]p\225nc\233lok \233s a p\233nz ami sz\252ks\233ges volt az[ENTER]el\245\225ll\237t\225sukhoz. \193ll\237t\243lag eg\233sz birodalmak[ENTER]kincst\225r\225t em\233sztette ez fel! Ha ilyen p\225nc\233lokat[ENTER]\225ruln\233k, akkor egy \233letre bebiztos\237tan\225m magam! "
gameforge.subquest_16._240_say = "Mostan\225ban p\225nc\233lokat ak\225r Metink\246vekb\245l is lehet[ENTER]k\233sz\237teni. Ezzel az \250j t\237pus\250 p\225nc\233llal t\246bb\233 m\225r[ENTER]nem csak egy \225lom, hogy olyan p\225nc\233los lovass\225got[ENTER]\225ll\237thassunk f\246l, mint amilyen r\233gen volt. De t\250l[ENTER]sokat besz\233lek. Most mennem kell, viszl\225t! "
gameforge.subquest_16._250_sayTitle = "A p\225nc\233los lovass\225g "
gameforge.subquest_16._260_say = "A h\225zal\243 tudott valamit a p\225nc\233los lovass\225g[ENTER]p\225nc\233lj\225r\243l. Most menj a k\246vetkez\245 faluba \233s[ENTER]besz\233lj Uriellel a kik\233pz\233sr\245l. "
gameforge.subquest_16._270_sayTitle = "Uriel : "
gameforge.subquest_16._280_say = "Mi sz\233l hozott? A p\225nc\233los lovass\225g? Persze hogy[ENTER]tudok r\243luk. Mindenki tud. Ez a sereg a[ENTER]t\246rt\233nelem egyik legjobbjak\233nt fog tov\225bb \233lni. A[ENTER]mendemond\225k legt\246bbje t\250lz\225s ugyan, de ezek a[ENTER]lovas katon\225k f\233lelmetesek voltak. "
gameforge.subquest_16._290_say = "A p\225nc\233los lovass\225g mindenkin\233l er\245sebb volt,[ENTER]legink\225bb tal\225n az \233rdekes kik\233pz\233snek volt[ENTER]k\246sz\246nhet\245 ez. Csak a legjobbak tudt\225k[ENTER]v\233gigcsin\225lni a kik\233pz\233st, sok k\246z\252l\252k meghalt.[ENTER]Szerintem ha most is azt a kik\233pz\233si m\243dszert[ENTER]alkalmazn\225nk, akkor a v\233g\233re egy katona se[ENTER]maradna \233letben. "
gameforge.subquest_16._300_say = "Adok neked r\233szletes inform\225ci\243t a kik\233pz\233sr\245l,[ENTER]hogy ne legy\233l teljesen tan\225cstalan. Tudom hogy[ENTER]most sz\246rny\251 h\225bor\250k folynak, de nem vagyok[ENTER]biztos benne hogy j\243 \246tlet \250jra fel\225ll\237tani egy[ENTER]olyan f\233lelmetes sereget mint a p\225nc\233los[ENTER]lovass\225g. "
gameforge.subquest_16._30_say = "Egy \250j megb\237z\225som van sz\225modra. Azt a parancsot[ENTER]kaptad, hogy a p\225nc\233los lovass\225gr\243l inform\225ci\243t[ENTER]gy\251jts\233l. Ez volt Isup, az alap\237t\243 kir\225ly \233s a[ENTER]kontinens \250jraegyes\237t\245je hadsereg\233nek[ENTER]legfontosabb egys\233ge.[ENTER]A p\225nc\233los lovass\225gt\243l a szomsz\233dos orsz\225gok a[ENTER]meglep\245 gyorsas\225ga \233s t\225mad\225si ereje miatt[ENTER]f\233ltek.  "
gameforge.subquest_16._310_say = "Menj el a kapit\225nyhoz \233s sz\225molj be neki arr\243l,[ENTER]hogy mit tudt\225l meg a p\225nc\233los[ENTER]lovass\225gr\243l.  "
gameforge.subquest_16._320_makequestbutton = "Menj el a kapit\225nyhoz "
gameforge.subquest_16._330_npcChat = "Jelent\233s a p\225nc\233los lovass\225gr\243l "
gameforge.subquest_16._340_sayTitle = "Kapit\225ny "
gameforge.subquest_16._350_say = "Megtudt\225l valamit? Mondd el! ...[ENTER]Hmmm, ez nagyon \233rdekes. Sz\243val semmi m\225s csak[ENTER]kem\233ny p\225nc\233l \233s durva kik\233pz\233s? Akkor[ENTER]lehets\233ges! Egy ilyen sereg \250jra egyes\237theti a[ENTER]h\225rom birodalmat! "
gameforge.subquest_16._360_say = "Viszont rengeteg p\233nzre lenne ehhez sz\252ks\233gem. \201s[ENTER]sok j\243 kov\225csra is. \201s sok \246nk\233ntes katon\225ra is[ENTER]akik hajland\243ak megj\225rni a poklok pokl\225t hogy a[ENTER]legjobbakk\225 v\225lhassanak! Ne, ne! Ne n\233zz r\225m \237gy.[ENTER]Te m\225r eleget tett\233l egyel\245re. "
gameforge.subquest_16._370_say = "Tess\233k, vedd \225t a jutalmadat \233s pihenj\233l.[ENTER]K\233s\245bb tal\225lkozunk! "
gameforge.subquest_16._380_sayReward = "150.000 tapasztalat pontot kapt\225l.[ENTER]30.000 Yangot kapt\225l.[ENTER]Arany f\252lbeval\243t kapt\225l. "
gameforge.subquest_16._40_say = "Az inform\225ci\243val amit gy\251jt\246tt\233l, meger\245s\237thetj\252k[ENTER]a katonai er\245nket. El\245bb keresd f\246l a zen\233szt,[ENTER]Yu-Hwant.Biztos vagyok benne hogy \245 sokat tud[ENTER]Isup lovass\225g\225r\243l. "
gameforge.subquest_16._50_say = "Hmm, ahogy gondolod. Akkor viszl\225t k\233s\245bb. "
gameforge.subquest_16._60_say = "Fogok \233n valaha is olyan lovass\225got ir\225ny\237tani?[ENTER]L\233gy \243vatos. "
gameforge.subquest_16._70_say = "K\246sz\246n\246m, vigy\225zz magadra.  "
gameforge.subquest_16._80_sayTitle = "A p\225nc\233los lovass\225g "
gameforge.subquest_16._90_sayReward = "A Kapit\225ny inform\225ci\243t szeretne Isup Kir\225ly[ENTER]legend\225s lovass\225g\225r\243l. Yu-Hwan, a muzsikus tal\225n[ENTER]tud szolg\225lni n\233mi inform\225ci\243val. Menj \233s k\233rdezd[ENTER]meg. "
gameforge.subquest_17 = {}
gameforge.subquest_17._100_targetVid = "Besz\233lj a vegyeskeresked\245 n\245vel "
gameforge.subquest_17._10_targetVid = "Ariyoung f\233rj\233nek t\246rt\233nete "
gameforge.subquest_17._110_say = "Menj a vegyeskeresked\245 n\245h\246z \233s \233rdekl\245dj[ENTER]Ariyoung f\233rje ut\225n. "
gameforge.subquest_17._120_npcChat = "Ariyoung f\233rje "
gameforge.subquest_17._130_say = "Ez egy szomor\250 t\246rt\233net. Nem tudja, hogy mi[ENTER]t\246rt\233nt a f\233rj\233vel? Egy olyan helyen van, ahonnan[ENTER]m\233g soha senki nem t\233rt vissza...[ENTER]Egyik nap a faluba menet elrabolta \233s meg\246lte a[ENTER]Feketesz\233l banda. "
gameforge.subquest_17._140_say = "Teljesen le lesz t\246rve, ha elmondod neki. Nagyon[ENTER]szerett\233k egym\225st. De meg kell tudnia. Ha nem,[ENTER]akkor a bizonytalans\225g fogja meg\246lni. "
gameforge.subquest_17._150_targetVid = "Szomor\250 h\237r "
gameforge.subquest_17._160_sayTitle = "Ariyoung: "
gameforge.subquest_17._170_say = "A vegyeskeresked\245 h\246lgynek rossz h\237rei vannak.[ENTER]Menj Ariyoung-hoz \233s mondd el neki hogy a f\233rje[ENTER]meghalt. "
gameforge.subquest_17._180_npcChat = "A f\233rjed meghalt... "
gameforge.subquest_17._190_say = "Mi van, mit mondasz...?! Meg... meg\246lte a... a[ENTER]Feketesz\233l banda?! Oh, nem! Meghalt...[ENTER]Fogalmam sincs, mihez kezdjek n\233lk\252le! "
gameforge.subquest_17._200_say = "K\233rlek, elhozn\225d nekem a f\233rjem holttest\233t? Akkor[ENTER]legal\225bb el tudn\233k k\246sz\246nni t\245le. Ha nem lehet[ENTER]visszahozni a test\233t, akkor csak hozz egy[ENTER]eml\233ket.[ENTER]Biztos vagyok benne, hogy a Feketesz\233l band\225hoz[ENTER]tartoz\243 Goo-Pae \245riz valamit. K\233rlek, hozz nekem[ENTER]valamit, amit csak tudsz, b\225rmit, ami hozz\225[ENTER]tartozott! "
gameforge.subquest_17._20_say = "Sok id\245 telt el az\243ta, mi\243ta legutolj\225ra a[ENTER]f\233rjemr\245l hallottam. Nagyon f\233lek! Rem\233lem, nem[ENTER]t\246rt\233nt vele semmi! Tudom, semmi \233rtelme agg\243dni,[ENTER]amikor semmit sem tehetek. De annyira hevesen ver[ENTER]a sz\237vem, egyszer\251en nem tudok megnyugodni! "
gameforge.subquest_17._210_select = "Igen, seg\237tek neked. "
gameforge.subquest_17._220_say = "Gyere vissza, ha meggondoltad magad! K\233rlek... "
gameforge.subquest_17._230_say = "Nem tal\225lt\225l semmit? Nos, akkor k\246sz\246n\246m...[ENTER]Jaj mi lesz most velem! "
gameforge.subquest_17._240_say = "Nem tudom szavakkal kifejezni, milyen h\225l\225s[ENTER]vagyok neked. Im\225dkozom \233rted! "
gameforge.subquest_17._250_sendLetter = "\214lj Goo-Paekat "
gameforge.subquest_17._260_say = "A Feketesz\233l banda kirabolta \233s meg\246lte Ariyoung[ENTER]f\233rj\233t. \214lj Goo-Paekat, am\237g nem tal\225lsz valami[ENTER]eml\233ket Ariyoung f\233rj\233t\245l. "
gameforge.subquest_17._270_npcChat = "A f\233rjedr\245l... "
gameforge.subquest_17._280_say = "Na hogy ment? Tal\225lt\225l eml\233kt\225rgyat a f\233rjemr\245l?[ENTER]\213 volt a mindenem. B\225rmi? "
gameforge.subquest_17._290_select = "M\233g nem. Folytatom a keres\233st! "
gameforge.subquest_17._300_say = "Goo-Pae a Feketesz\233l band\225b\243l nem k\246nny\251 ellenf\233l.Pihenj egy kicsit! K\246sz\246n\246m a seg\237ts\233ged! "
gameforge.subquest_17._30_say = "Rem\233lem, a vegyeskeresked\245 n\245 hallott valamit a[ENTER]f\233rjemr\245l. Sok v\225s\225rl\243ja van, tal\225n valaki mes\233lt[ENTER]neki valamit. "
gameforge.subquest_17._310_say = "Akkor v\225rnom kell egy m\225sik h\245sre, aki tud[ENTER]seg\237teni.[ENTER]Viszl\225t! "
gameforge.subquest_17._320_say = "Oh, milyen kedves vagy! K\233rlek, hozz a f\233rjemr\245l[ENTER]egy eml\233ket! "
gameforge.subquest_17._330_sendLetter = "Ariyoung jegygy\251r\251je "
gameforge.subquest_17._340_targetVid = "Menj Ariyounghoz "
gameforge.subquest_17._350_sayTitle = "Menj Ariyounghoz "
gameforge.subquest_17._360_say = "Megtal\225ltad Ariyoung f\233rj\233nek jegygy\251r\251j\233t az[ENTER]egyik le\246lt Goo-Paen\225l. Elk\233pzelni sem lehet[ENTER]enn\233l jobb eml\233kt\225rgyat.[ENTER]Vidd el a gy\251r\251t Ariyoungnak! "
gameforge.subquest_17._370_npcChat = "Ezt a gy\251r\251t tal\225ltam. "
gameforge.subquest_17._380_say = "Ez a gy\251r\251... az... eny\233m! H\225l\225san k\246sz\246n\246m! Most[ENTER]m\225r nyugalomban pihenhet a f\233rjem. Ezt a gy\251r\251t[ENTER]el fogom \225sni egy \225ltalam \237rt lev\233llel egy\252tt![ENTER]Mostant\243l kezdve egyed\252l fogok \233lni. De legal\225bb[ENTER]ism\233t megvan a jegygy\251r\251je! Ez csod\225latos \233rz\233s![ENTER]K\246sz\246n\246m, nagyon-nagyon k\246sz\246n\246m! "
gameforge.subquest_17._390_sendLetter = "Feladat befejezve! "
gameforge.subquest_17._400_say = "Terjed Ariyoungnak ny\250jtott szolg\225latod h\237re. Sok[ENTER]ember \233rt\233keli seg\237ts\233ged. "
