gameforge.subquest_22._180_say = "A seg\237ts\233ged n\233lk\252l soha nem kaptam volna vissza[ENTER]a Fejsz\233t. Nagyon sz\233pen k\246sz\246n\246m. Ezent\250l jobban[ENTER]vigy\225zok r\225, \233s mindig magamn\225l tartom. "
gameforge.subquest_22._190_sayReward = "400.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_22._200_sayReward = "30.000 Yangot kapt\225l. "
gameforge.subquest_22._20_npcChat = "Az Arany Fejsz\233dr\245l... "
gameforge.subquest_22._30_sayTitle = "Deokbae, a fav\225g\243: "
gameforge.subquest_22._40_say = "Oh nem, oh nem! Elvesztettem a Fejsz\233t! Tal\225n[ENTER]tudod, melyik fejsz\233re gondolok? Ez az Arany[ENTER]Fejsze, amit a Kov\225cst\243l kaptam. Egy Kegyetlen[ENTER]ellopta. "
gameforge.subquest_22._50_say = "Ha a kov\225cs ezt megtudja, akkor nagyon d\252h\246s[ENTER]lesz, \233s t\246bb\233 m\225r nem fogja megjav\237tani a[ENTER]fejsz\233imet. Ez egy igen j\243 fejsze volt. Esetleg[ENTER]vissza tudn\225d hozni? "
gameforge.subquest_22._60_select = "Lemondani. "
gameforge.subquest_22._70_say = "Abba akarod hagyni a keres\233st? "
gameforge.subquest_22._80_say = "Oh, gyere vissza, ha lesz id\245d. "
gameforge.subquest_22._90_say = "T\250l neh\233z? Akkor nincs mit tenni. De vigy\225zz[ENTER]magadra, a Kegyetlenek ott vannak mindenhol. "
gameforge.subquest_23 = {}
gameforge.subquest_23._100_sendLetter = "Keresd Yu-Hwant! "
gameforge.subquest_23._10_targetVid = "K\233rlek keresd meg a b\225ty\225mat! "
gameforge.subquest_23._110_targetVid = "Menj Yu-Hwanhoz "
gameforge.subquest_23._120_say = "Mirine b\225tyja \250jra elt\251nt. \205rt neki egy levelet,[ENTER]n\233h\225ny \233vvel ezel\245tt, de az\243ta nem hallott[ENTER]fel\245le. Menj Yu-Hwan-hoz, \233s k\233rdezd meg, tud-e[ENTER]valamit Mirine b\225tyj\225r\243l. "
gameforge.subquest_23._130_npcChat = "L\225ttad Mirine b\225tyj\225t? "
gameforge.subquest_23._140_say = "Mirine b\225tyja? Att\243l tartok, nem tudok seg\237teni[ENTER]ebben. Nem igaz\225n tal\225lkoztam vele mostan\225ban.[ENTER]Arra is alig eml\233kszem, mikor l\225ttam utolj\225ra. \201n[ENTER]is agg\243dom. Lehet, hogy t\246rt\233nt vele valami?[ENTER]K\233rdezd meg a vad\225szt, Yang-Shin-t. Mindig \250ton[ENTER]van, tal\225n l\225tta \245t. "
gameforge.subquest_23._150_sendLetter = "Keresd Yang-Shin-t! "
gameforge.subquest_23._160_targetVid = "Menj Yang-Shin-hoz, a vad\225szhoz "
gameforge.subquest_23._170_say = "A vad\225sz Yang-Shin mindig \250ton van. Tal\225n \245 l\225tta[ENTER]Mirine b\225tyj\225t. "
gameforge.subquest_23._180_npcChat = "L\225ttad Mirine b\225tyj\225t? "
gameforge.subquest_23._190_say = "Mirine b\225tyj\225ra gondolsz? Amikor utolj\225ra l\225ttam,[ENTER]\250ton volt a Seungryong-v\246lgy fel\233,[ENTER]gy\243gyn\246v\233nyeket gy\251jteni. Egy kicsit meglep\245dtem,[ENTER]mert nagyon vesz\233lyes arrafel\233, de val\243j\225ban[ENTER]azt\225n nem gondoltam r\225 t\246bbet. "
gameforge.subquest_23._200_say = "Meg kellett volna \225ll\237tanom. Ha eddig nem[ENTER]jelentkezett, valaminek t\246rt\233nnie kellett vele.[ENTER]Jobb lenne elmenned a Seungryong-v\246lgybe, \233s[ENTER]megkeresned. "
gameforge.subquest_23._20_npcChat = "Mi\233rt s\237rsz? "
gameforge.subquest_23._210_select = "Keres\233s ind\237t\225sa "
gameforge.subquest_23._220_say = "Feladod a keres\233st? "
gameforge.subquest_23._230_say = "Mirine t\233nyleg nagyon szomor\250 volt.[ENTER]Majd visszaj\246v\246k k\233s\245bb. "
gameforge.subquest_23._240_say = "Ha egy id\245sebb testv\233r nem jelentkezik egy ideig,[ENTER]az nem jelenti azt, hogy valami t\246rt\233nt vele. Nem[ENTER]kell bemenned a vesz\233lyes v\246lgybe csak az\233rt,[ENTER]mert egy kisl\225ny ezt k\233rte t\245led. "
gameforge.subquest_23._250_say = "A k\252ldet\233s nem is olyan jelent\233ktelen, mint[ENTER]amilyennek l\225tszik. A Seungryong-v\246lgy vesz\233lyes[ENTER]hely. De meg\237g\233rtem, \237gy megteszem. "
gameforge.subquest_23._260_sendLetter = "Az elt\251nt testv\233r "
gameforge.subquest_23._270_targetVid = "Keresd a b\225tyj\225t a Seungryong-v\246lgyben "
gameforge.subquest_23._280_sayTitle = "Keresd Mirine b\225tyj\225t "
gameforge.subquest_23._290_say = "Mirine b\225tyja gy\243gyf\252veket keres a[ENTER]Seungryong-v\246lgyben. Menj oda, \233s n\233zd meg, j\243l[ENTER]van-e. A Teleportos seg\237t, ha r\246videbb utat[ENTER]keresn\233l. "
gameforge.subquest_23._300_npcChat = "A halott! "
gameforge.subquest_23._30_say = "Te hozt\225l egyszer nekem levelet a b\225ty\225mt\243l,[ENTER]ugye? Nagyon h\225l\225s voltam \233rte. Sajnos az\243ta sem[ENTER]ker\252ltem vele kapcsolatba. A b\225ty\225m m\233g mindig[ENTER]t\225vol van. Gy\243gyf\252veket keres nekem. "
gameforge.subquest_23._310_say = "Egy halott f\233rfi fekszik itt. Fiatal \233s sov\225ny,[ENTER]\233s \250gy t\251nik, Ginszenget gy\251jt\246tt. Att\243l tartok,[ENTER]Mirine b\225tyja lehet, akit kerestem. A halott[ENTER]nyakl\225ncot visel, rajta med\225llal. Leveszem, \233s[ENTER]odaadom Mirine-nek. "
gameforge.subquest_23._320_sendLetter = "Menj Mirin\233hez "
gameforge.subquest_23._330_sayTitle = "Szomor\250 h\237r "
gameforge.subquest_23._340_say = "A Seungryong-v\246lgyben tal\225lt\225l egy med\225lt egy[ENTER]halotton, amire Mirine neve van grav\237rozva. Menj[ENTER]Mirine-hez, \233s add neki a nyakl\225ncot \233s a med\225lt. "
gameforge.subquest_23._350_npcChat = "Ismer\245s ez a nyakl\225nc? "
gameforge.subquest_23._360_say = "Oh, ez a nyakl\225nc... A b\225ty\225m mindig ezt viselte.[ENTER]Nekem is van egy hasonl\243. Mindig viselt\252k ezeket,[ENTER]hogy eml\233keztessenek egym\225sra, \233s mindig[ENTER]visszatal\225ljunk egym\225shoz. De... a b\225ty\225m m\225r[ENTER]nincs itt t\246bb\233... \201s csak a nyakl\225nc tal\225lta meg[ENTER]az utat vissza. "
gameforge.subquest_23._370_say = "Szeg\233ny b\225ty\225m...[ENTER]\201s mindez a h\225bor\250 miatt t\246rt\233nt. A b\225ty\225m[ENTER]gy\243gyn\246v\233nyeket gy\251jt\246tt, ez volt az egyetlen[ENTER]dolog, ami hozott n\233mi p\233nzt. Ebb\245l tudtunk[ENTER]\233lelmiszert v\225s\225rolni magunknak. Nagyon kem\233nyen[ENTER]dolgozott az\233rt, hogy enni tudjak. \201s most[ENTER]halott. Csak miattam... "
gameforge.subquest_23._380_say = "K\246sz\246n\246m, hogy elhoztad ezt. \205gy m\225r legal\225bb[ENTER]tudom, hogy mi t\246rt\233nt. Ha nem seg\237tett\233l volna[ENTER]nekem, soha nem tal\225ltam volna ki. "
gameforge.subquest_23._390_say = "A b\225ty\225m med\225lj\225t gondosan fogom \245rizni, a l\225ncot[ENTER]pedig neked adom k\246sz\246netem jel\233\252l. Biztos vagyok[ENTER]benne, hogy seg\237teni fog.[ENTER]K\246sz\246n\246m a seg\237ts\233gedet. \213 m\225r biztosan a[ENTER]mennyben van, nem gondolod? "
gameforge.subquest_23._400_sayReward = "600.000 tapasztalati pontot kapt\225l.[ENTER]35.000 Yangot kapt\225l. "
gameforge.subquest_23._40_say = "Agg\243dom miatta, mert hossz\250 ideje nem volt[ENTER]kapcsolatom vele. Sajn\225lom, de keresn\233d \250jra a[ENTER]b\225ty\225mat?[ENTER]Tal\225n Yu-Hwan tud valamit. "
gameforge.subquest_23._50_select = "Lemondani. "
gameforge.subquest_23._60_say = "Fel akarod adni a keres\233st? "
gameforge.subquest_23._70_say = "Oh...[ENTER]Megv\225rlak itt. Tal\225n k\233s\245bb? K\233rlek? "
gameforge.subquest_23._80_say = "Nincs id\245m![ENTER]Sok szerencs\233t a b\225ty\225dnak. "
gameforge.subquest_23._90_say = "Nem lenne sz\233p elhagyni egy s\237r\243 l\225nyt. \201s a[ENTER]k\252ldet\233s sem tartana sok\225ig. Gyer\252nk! "
gameforge.subquest_24 = {}
gameforge.subquest_24._100_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_24._10_targetVid = "Yu-Rang Rizs s\252tije "
gameforge.subquest_24._110_say = "Ha k\233s\245bb lesz id\245d, k\233rlek, gyere vissza. Nem[ENTER]tudom, hogy fogjuk t\250l\233lni \233lj\252k rizs s\252tik[ENTER]elad\225sa n\233lk\252l. "
gameforge.subquest_24._120_say = "Minden a gazdag emberek k\246r\252l forog, akik a[ENTER]Yangot kidob\225lj\225k az ablakon, mintha a holnap nem[ENTER]is l\233tezne. Mi meg azt sem tudjuk, hogy holnap[ENTER]mit tesz\252nk az asztalra. T\225vozz! "
gameforge.subquest_24._130_say = "K\246sz\246n\246m. Nagyon kedves vagy. Itt v\225rok, am\237g[ENTER]vissza nem t\233rsz. "
gameforge.subquest_24._140_sendLetter = "Az ellopott Rizs s\252ti "
gameforge.subquest_24._150_say = "Szerezd vissza Yu-Rang Rizs s\252tij\233t a sivatag[ENTER]p\243kjait\243l. Ha t\250l lass\250 vagy, a p\243kok megeszik a[ENTER]rizs s\252tit, vagy rettenetesen kisz\225radnak a forr\243[ENTER]napon. Siess! "
gameforge.subquest_24._160_sayReward = "\214ld meg a B\233bi p\243kokat a Yongbi sivatagban. "
gameforge.subquest_24._170_npcChat = "Az ellopott Rizs s\252tir\245l... "
gameforge.subquest_24._180_say = "Mi, a p\243kok megett\233k a Rizs s\252tit? Oh ne! Vagy[ENTER]kisz\225radt?! K\233rlek, ne mondd, hogy minden[ENTER]elveszett! "
gameforge.subquest_24._190_select = "Nem, minden rendben. "
gameforge.subquest_24._200_select = "Feladom. "
gameforge.subquest_24._20_npcChat = "Az ellopott Rizs s\252tid... "
gameforge.subquest_24._210_say = "Nem tudsz tenni valamit ezek ut\225n? A rizs s\252ti[ENTER]nagyon fontos sz\225momra. K\246ny\246rg\246m![ENTER][ENTER]Fel akarod adni a feladatot, hogy megtal\225ld[ENTER]Yu-Rang Rizs s\252tij\233t a sivatagban? "
gameforge.subquest_24._220_select = "M\233g egyszer megpr\243b\225lom "
gameforge.subquest_24._230_select = "Sajn\225lom, ez t\250l neh\233z. "
gameforge.subquest_24._240_say = "Nem tudom elhinni. Most ki fog nek\252nk seg\237teni? "
gameforge.subquest_24._250_say = "Gyer\252nk! K\233rlek, seg\237ts! "
gameforge.subquest_24._260_say = "Sz\243val folytatod a keres\233st? K\246sz\246n\246m! K\233rlek,[ENTER]pr\243b\225ld meg megtal\225lni a Rizs s\252tit min\233l[ENTER]hamarabb! "
gameforge.subquest_24._270_say = "Nem, t\250l k\233s\245. M\233g ha meg is szerezn\233d, akkor is[ENTER]kisz\225radt. Nem tudn\225m m\225r eladni. "
gameforge.subquest_24._280_say = "A f\246ldre n\233zel \233s l\225tod a s\252ti marad\233kot, amit a[ENTER]p\243kok meghagytak. Sajnos m\225r mind kisz\225radt. "
gameforge.subquest_24._290_sayReward = "T\250l sok id\245t vesztegett\233l, hogy megtal\225ld a Rizs[ENTER]s\252tit. A s\252tik kisz\225radtak. Nem siker\252lt. "
gameforge.subquest_24._300_sendLetter = "Vissza Yu-Ranghoz "
gameforge.subquest_24._30_say = "Szia, hogy van az \233desany\225d? "
gameforge.subquest_24._310_targetVid = "Menj vissza Yu-Ranghoz "
gameforge.subquest_24._320_say = "Id\245ben megmentetted Yu-Rang Rizs s\252tij\233t a[ENTER]p\243kokt\243l. Vidd el neki. "
gameforge.subquest_24._330_npcChat = "Szerencs\233d van. Itt a Rizs s\252tid. "
gameforge.subquest_24._340_say = "Te egyszer\251en szuper vagy! Nem is tudom, mit[ENTER]mondjak. Most m\225r eladhatom holnap a piacon.[ENTER]K\246sz\246n\246m sz\233pen! "
gameforge.subquest_24._350_sayReward = "900.000 tapasztalati pontot kapsz. "
gameforge.subquest_24._360_sayReward = "25.000 Yangot kapt\225l. "
gameforge.subquest_24._40_say = "Oh, m\225r jobban van; k\246sz\246n\246m k\233rd\233sed. "
gameforge.subquest_24._50_say = "\218gy n\233zel ki, mintha bajban lenn\233l. Mi t\246rt\233nt? "
gameforge.subquest_24._60_say = "\201n nap mint nap Rizs s\252tit \225rulok, de ma valami[ENTER]borzalmas dolog t\246rt\233nt. Egyszer csak hatalmas[ENTER]p\243kok t\251ntek fel, \233s ellopt\225k a s\252tit. Rettegtem,[ENTER]\233s nem harcoltam vel\252k. Most nincs Rizs s\252tim,[ENTER]amit eladhatn\233k. Hogyan fogom ezt t\250l\233lni? A[ENTER]csal\225domnak nincs m\225s bev\233tele... "
gameforge.subquest_24._70_select = "Megtal\225lom neked. "
gameforge.subquest_24._80_select = "Sajnos nincs id\245m. "
gameforge.subquest_24._90_sayTitle = "K\233rd\233s: "
gameforge.subquest_25 = {}
gameforge.subquest_25._100_npcChat = "Mit szeretsz? "
gameforge.subquest_25._10_targetVid = "Huahn-So "
gameforge.subquest_25._110_say = "Mi\243ta f\233rjemet az im\233nti h\225bor\250ban elvesztettem,[ENTER]nagyon mag\225nyos vagyok. Hm? Mit\245l \233rezn\233m jobban[ENTER]magam? A f\233rjem kor\225bban mindig apr\243 vir\225gokat[ENTER]hozott nekem. "
gameforge.subquest_25._120_say = "Ezek olyan vir\225gok voltak, melyek a falunkt\243l[ENTER]t\225vol n\245nek. J\243llehet vesz\233lyes volt, m\233gis[ENTER]hozott nekem a vir\225gokb\243l. \201n ezeket a vir\225gokat[ENTER]m\225r nem l\225thatom, ami\243ta a f\233rjem meghalt. De[ENTER]bizonyos napokon, mint a mai, m\233gis nagyon[ENTER]hi\225nyolom. Oh, mit mondtam most neked? Ez most[ENTER]nem volt igaz\225n ide ill\245... K\233rlek felejtsd el[ENTER]egyszer\251en, amit mondtam. "
gameforge.subquest_25._130_qSetTitle = "Vissza Huahn-Sohoz "
gameforge.subquest_25._140_makequestbutton = "Vissza Huahn-Sohoz "
gameforge.subquest_25._150_targetVid = "Huahn-So "
gameforge.subquest_25._160_say = "Ariyoungnak hi\225nyoznak a vir\225gok amelyeket a[ENTER]f\233rje mindig hozott neki. Menj el Huahn-Sohoz \233s[ENTER]mondd el neki. "
gameforge.subquest_25._170_npcChat = "Az aj\225nd\233k Ariyoungnak... "
gameforge.subquest_25._180_say = "Teh\225t, mit szeret Ariyoung? Nem \225rult\225l el semmit[ENTER]r\243lam, vagy igen? Hmm, vir\225got szeret, amit[ENTER]mindig a f\233rje hozott neki? Ez t\233nyleg nagyon[ENTER]messze van a falut\243l, nekem nagyon neh\233z lesz[ENTER]odamennem. \201s tigrishez hasonl\243 sz\246rnyek vannak[ENTER]arrafel\233. "
gameforge.subquest_25._190_say = "Pontosan! Mi\233rt nem seg\237tesz nekem? Mi\233rt nem[ENTER]hozod el nekem a vir\225gokat? Ez mindkett\245nk jav\225ra[ENTER]v\225lna. Micsoda? Ez nem tartozott az[ENTER]egyezs\233g\252nkh\246z? Na ne, h\225t nem l\225tod, hogy[ENTER]mennyire f\225radozom a szeretet\233\233rt? Csak seg\237ts[ENTER]nekem! Rengeteg Yanggal foglak megjutalmazni! "
gameforge.subquest_25._200_select = "Visszautas\237t "
gameforge.subquest_25._20_npcChat = "Oh, legdr\225g\225bb Ariyoungom "
gameforge.subquest_25._210_say = "Ki akarsz l\233pni ebb\245l a k\252ldet\233sb\245l? "
gameforge.subquest_25._220_say = "Francba. Hogy szerezzem be neki a vir\225got?[ENTER]K\233rlek gyere vissza, ha megv\225ltoztattad a[ENTER]v\233lem\233nyedet. "
gameforge.subquest_25._230_say = "Soha nem volt\225l szerelmes?[ENTER]Nem tudod, hogy mit \233rzek Ariyoung ir\225nt?...[ENTER]Oh Ariyoung... "
gameforge.subquest_25._240_say = "K\246sz\246n\246m sz\233pen! K\233rlek, hozz nekem ilyen vir\225got! "
gameforge.subquest_25._250_qSetTitle = "Hozd a vir\225got "
gameforge.subquest_25._260_targetVid = "Vir\225gok "
gameforge.subquest_25._270_sayTitle = "Vir\225gok Ariyoungnak "
gameforge.subquest_25._280_say = "Hogy Huahn-So Ariyoungnak meg tudja mondani, hogy[ENTER]mit \233rez ir\225nta, be kell neked szerezned a[ENTER]vir\225gokat. A vir\225gok a kezd\245 falu t\233rk\233p\233nek az[ENTER]egyik sark\225ban n\245nek. "
gameforge.subquest_25._290_npcChat = "Nem tal\225ltam egy vir\225got sem. "
gameforge.subquest_25._300_say = "A fen\233be...[ENTER]Az \233rzelmeimr\245l akartam vele besz\233lni.[ENTER]Olyan neh\233z a szerelm\233t megnyerni.[ENTER]Legdr\225g\225bb Ariyoungom... "
gameforge.subquest_25._30_say = "Ismered Ariyoung Asszonyt? Nos \245 h\225zas... volt. A[ENTER]f\233rje meghalt n\233h\225ny \233vvel ezel\245tt, \233s az\243ta[ENTER]egyed\252l \233l. Nagyon leny\251g\246z\245 szem\233lyis\233g, \233s m\233g[ENTER]mindig nagyon sz\233p n\245. nagyon fiatalon ment[ENTER]f\233rjhez, \233s \233n elk\233stem... "
gameforge.subquest_25._310_select = "\218jra megpr\243b\225lom. "
gameforge.subquest_25._320_select = "Abbahagyom "
gameforge.subquest_25._330_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_25._340_say = "Oh...[ENTER]Ha meggondolod magad...[ENTER]\201n itt v\225rok r\225d.[ENTER]K\233rlek, seg\237ts! "
gameforge.subquest_25._350_say = "A szerelmemnek \237gy lesz v\233ge?[ENTER]Ariyoung.... "
gameforge.subquest_25._360_say = "K\246sz\246n\246m sz\233pen! Te is biztosan szerelmes vagy,[ENTER]ha meg tudod \233rteni, mit \233rzek Ariyoung ir\225nt. "
gameforge.subquest_25._370_npcChat = "Ariyoung kedvenc vir\225gai "
gameforge.subquest_25._380_say = "Ezek a vir\225gok \250gy n\233znek ki, mint ahogy Ariyoung[ENTER]le\237rta. Szedek p\225rat. "
gameforge.subquest_25._390_qSetTitle = "Vissza Huahn-Sohoz "
gameforge.subquest_25._400_say = "Megtal\225ltam Ariyoung kedvenc vir\225gait \233s[ENTER]szereztem is bel\245le p\225rat. Ezeket a vir\225gokat[ENTER]Huahn-Sonak kellene adnom aki annyira szerelmes[ENTER]Ariyoungba. "
gameforge.subquest_25._40_say = "De a f\233rje meghalt a h\225bor\250ban, ez\233rt fiatalon[ENTER]meg\246zvegy\252lt. Szeretn\233m, ha tudn\225, mik\233nt \233rzek![ENTER]Tudom, hogy ez egy szemtelen k\233r\233s, de tudn\225l[ENTER]nekem seg\237teni? "
gameforge.subquest_25._410_npcChat = "Itt vannak Ariyoung kedvenc vir\225gai. "
gameforge.subquest_25._420_say = "Oh, ezek a vir\225gok? Most meg tudom mondani[ENTER]Ariyoungnak, hogy mit \233rzek ir\225nta! Azt gondolod,[ENTER]hogy m\233g t\250l korai? Mindegy, bevallhatom neki a[ENTER]szerelmemet, nincs jelent\245s\233ge, hogy korai-e.[ENTER]K\246sz\246n\246m sz\233pen. Itt van a jutalmad, m\233g egyszer[ENTER]ezer k\246sz\246net! "
gameforge.subquest_25._430_sayReward = "400.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_25._440_sayReward = "12.000 Yangot kapt\225l. "
gameforge.subquest_25._50_say = "Gondolod, hogy kedveli a j\243k\233p\251 f\233rfiakat? Vagy a[ENTER]sz\233p ruh\225kat? El\245sz\246r meg kellene tudnom, hogy[ENTER]mit szeret, azut\225n tal\225n majd besz\233lhetek vele.[ENTER]K\233rlek, ki tudn\225d ezt nekem der\237teni? De ne mondj[ENTER]semmit r\243lam! K\246ny\246rg\246m! Megjutalmazlak ez\233rt. "
gameforge.subquest_25._60_qSetTitle = "Menj Ariyounghoz "
gameforge.subquest_25._70_makequestbutton = "Menj Ariyounghoz "
gameforge.subquest_25._80_targetVid = "Menj Ariyounghoz "
