gameforge.subquest_26._160_npcChat = "B\233kacomb leves? "
gameforge.subquest_26._170_say = "B\233kacomb leves... Persze, haszn\225ltam \233n is. De ez[ENTER]m\225r a m\250lt\233. Akkoriban m\233g nem f\233ltem a[ENTER]sz\246rnyekt\245l, \237gy k\246nnyen beszereztem a[ENTER]b\233kacombot. "
gameforge.subquest_26._180_say = "De most... T\250l \246reg \233s f\225radt vagyok. A levessel[ENTER]visszakaphatn\225m az energi\225mat, de a b\233k\225kat nem[ENTER]k\246nny\251 meg\246lni. Ha beszerzed a leveshez a[ENTER]b\233kacombot, akkor a vil\225g legjobb b\233kacomb[ENTER]leves\233t fogom elk\233sz\237teni. "
gameforge.subquest_26._190_select = "Persze, megcsin\225lom. "
gameforge.subquest_26._200_select = "Nem, nem tudom megtenni. "
gameforge.subquest_26._20_npcChat = "Hogy vagy? "
gameforge.subquest_26._210_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_26._220_say = "Elfoglalt vagy? Gyere vissza, ha meggondolod[ENTER]magad. "
gameforge.subquest_26._230_say = "A levesemet nagyon kevesen ismerik. Ha tudn\225d,[ENTER]milyen volt, megtenn\233d. H\225t igen, viszl\225t. "
