gameforge.subquest_26._340_say = "M\225r f\225radt vagy? Mi\233rt nem tartasz egy kis[ENTER]sz\252netet \233s pr\243b\225lod \250jra k\233s\245bb? "
gameforge.subquest_26._350_say = "B\233kacomb levest tudtam volna bel\245le k\233sz\237teni. De[ENTER]ez nem fog megt\246rt\233nni. Sz\233gyen. Viszl\225t! "
gameforge.subquest_26._360_say = "Akkor ne \225llj itt, hanem menj! A v\237z m\225r forr, \233s[ENTER]minden k\233szen \225ll! "
gameforge.subquest_26._370_targetVid = "Menj Octaviohoz "
gameforge.subquest_26._380_say = "Na ez az, amit \233n b\233kacombnak h\237vok! Kisebbeket[ENTER]haszn\225lnak ugyan, de biztos vagyok benne, hogy ez[ENTER]is nagyon \237zletes. V\225rj egy pillanatot... Ez m\225r[ENTER]eg\233sz j\243 illat\250. M\233g egy csipet s\243... K\233sz! Itt[ENTER]az adagod. Hahaha, most m\225r van el\233g energi\225m egy[ENTER]teljes heti munk\225ra. "
gameforge.subquest_26._390_say = "\201s ne mondd el senkinek, k\252l\246n\246sen a Rakt\225rosnak[ENTER]ne! \213 szeret fecsegni, \233s ha a leves[ENTER]tulajdons\225gai kider\252lnek, nem lesz egyetlen perc[ENTER]nyugtom sem, mert folyamatosan j\246nnek majd[ENTER]k\243stolni a levesem. "
gameforge.subquest_26._400_sayReward = "5.000.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_26._40_say = "Nem voltam valami j\243l mostan\225ban. A testem m\225r[ENTER]nem igaz\225n a r\233gi. Amikor fiatal voltam, k\233s\245[ENTER]\233jszak\225ig tudtam dolgozni, a h\233t minden napj\225n,[ENTER]k\246zben alkoholt is ittam. De manaps\225g m\225r f\225raszt[ENTER]a reggeli felkel\233s is. Nagy sz\252ks\233gem van a[ENTER]b\233kacomblevesre, hogy visszanyerjem az energi\225m. "
gameforge.subquest_26._410_sayReward = "50.000 Yangot kapt\225l. "
gameforge.subquest_26._50_say = "Nem tudod, mi a b\233kacomb leves? Ha megiszol[ENTER]bel\245le egy t\225llal iszol, akkor azonnal magadhoz[ENTER]t\233rsz, \233s teli leszel energi\225val. Ut\225na eg\233sz[ENTER]h\233ten \225t dolgozhatsz an\233lk\252l, hogy elf\225radn\225l.[ENTER]Octavio f\245zte ezt a levest, de nemr\233giben[ENTER]valami\233rt abbahagyta a k\233sz\237t\233s\233t. "
gameforge.subquest_26._60_select = "Megyek, besz\233lek Octavioval. "
gameforge.subquest_26._70_select = "Nem \233rek r\225. "
gameforge.subquest_26._80_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_26._90_say = "Rendben, ha nem \233rsz r\225, gyere vissza k\233s\245bb,[ENTER]amikor lesz egy kis id\245d. "
gameforge.subquest_27 = {}
