gameforge.subquest_31._270_sayReward = "V\246r\246shangya \214lt\246ny+3 -at kapt\225l. "
gameforge.subquest_31._280_sayReward = "Szellem Lemezv\233rt+3 -at kapt\225l. "
gameforge.subquest_31._290_sayReward = "Szerelmi Ruha+3 -at kapt\225l. "
gameforge.subquest_31._30_say = "Szia, van egy perced sz\225momra? Igaz\225n nagyra[ENTER]\233rt\233kelem, hogy a m\250ltkor seg\237tett\233l \250j fegyvert[ENTER]k\233sz\237teni. Most \250jra a seg\237ts\233ged szeretn\233m[ENTER]k\233rni. Ez alkalommal \250j v\233rtet szeretn\233k[ENTER]k\233sz\237teni. Miut\225n \250j fegyvert alkottam,[ENTER]egy\233rtelm\251, hogy egy j\243 v\233rtre is sz\252ks\233gem van. "
gameforge.subquest_31._40_say = "Term\233szetesen sz\252ks\233gem van nyersanyagokra az \250j[ENTER]v\233rt k\233sz\237t\233s\233hez. Be tudod nekem szerezni?[ENTER]Cser\233be megkapod az els\245 befejezett v\233rtet. Ez[ENTER]alkalommal 100 db R\233z \233rcre, 100 db \201benfa \233rcre[ENTER]\233s 100 Igazgy\246ngy darabra van sz\252ks\233gem. Ezt is[ENTER]tudnod kell. Sok sikert k\237v\225nok! "
gameforge.subquest_31._50_select = "Elfogadni. "
gameforge.subquest_31._60_say = "Ki akarsz l\233pni ebb\245l a k\252ldet\233sb\245l? "
gameforge.subquest_31._70_say = "Mi\233rt habozol? Gyere vissza, ha k\233szen \225llsz a[ENTER]b\225ny\225szatra. "
gameforge.subquest_31._80_say = "Ez a kis \233rc nem t\250l nagy k\233r\233s.[ENTER]Nos, magadnak k\246sz\246nheted. T\251nj el! "
gameforge.subquest_31._90_say = "\218jra seg\237teni fogsz? J\243 bar\225t vagy.[ENTER]\201s ne agg\243dj: az els\245 v\233rt a tied! "
