gameforge.subquest_32._110_targetVid = "Menj Ah-Yuhoz "
gameforge.subquest_32._120_targetVid = "Menj a Vegyeskeresked\245 Elad\243n\245h\246z "
gameforge.subquest_32._130_sayReward = "Anyagok a Keresked\245nek "
gameforge.subquest_32._140_sayReward = "A H\225zal\243nak sz\252ks\233ge van n\233h\225ny dologra egy[ENTER]nyakl\225nchoz. Vigy\233l neki 100 \213rl\245fogat a B\252szke[ENTER]ork var\225zsl\243kt\243l, egy \201kszert a Vegyeskeresked\245[ENTER]Elad\243n\245t\245l, \233s C\233rn\225t Ariyoung-t\243l. "
gameforge.subquest_32._150_npcChat = "C\233rn\225ra van sz\252ks\233gem. "
gameforge.subquest_32._160_say = "C\233rn\225t nagyon k\246nny\251 el\245\225ll\237tani. De akkor nem[ENTER]tudok m\225st csin\225lni. M\225r elk\233sz\252ltem Ah-Yu[ENTER]szakadt ruh\225j\225nak jav\237t\225s\225val, \233s vissza akartam[ENTER]neki vinni... "
gameforge.subquest_32._170_say = "Mit gondolsz err\245l: Visszaviszed Ah-Yu-nak a[ENTER]ruh\225j\225t, am\237g k\233sz\237tek neked C\233rn\225t. Megfelel? "
gameforge.subquest_32._180_say = "V\233gleg fel akarod adni? "
gameforge.subquest_32._190_say = "Igaz\225n nincs messze. Mi\233rt habozol? Gyere vissza,[ENTER]ha k\233szen \225llsz. "
gameforge.subquest_32._200_say = "Oh, rem\233ltem, hogy van r\225 id\245d. Akkor \233n magam[ENTER]megyek. \201g veled! "
gameforge.subquest_32._20_npcChat = "A nyakl\225ncr\243l... "
gameforge.subquest_32._210_say = "Csod\225latos, nagyon sz\233pen k\246sz\246n\246m! Add \225t[ENTER]\252dv\246zletem Ah-Yu-nak, \233s vigy\225zz, hogy ne gy\251rd[ENTER]\246ssze a ruh\225j\225t az \250ton! Itt v\225rlak. "
gameforge.subquest_32._220_sayTitle = "Ariyoung: "
gameforge.subquest_32._230_say = "Mire visszat\233rsz a szomsz\233d falub\243l, elk\233sz\237tem a[ENTER]c\233rn\225d. Ugye nem felejtetted el Ah-Yu ruh\225j\225t?[ENTER]Neheztelni fog r\225m ez\233rt. "
gameforge.subquest_32._240_say = "Ah-Yu \246r\252l a ruh\225j\225nak? Ha igen, akkor igaz\225n[ENTER]meg\233rte ilyen kem\233nyen dolgozni. Itt van a[ENTER]c\233rn\225d. Ez egy er\245s c\233rna, amit sok mindenre[ENTER]haszn\225lhatsz. "
gameforge.subquest_32._250_say = "M\225r megkaptad a C\233rn\225d. Elvesz\237tetted? "
gameforge.subquest_32._260_npcChat = "Ariyoung k\252ldi neked ezeket a ruh\225kat. "
gameforge.subquest_32._270_sayTitle = "Ah-Yu: "
gameforge.subquest_32._280_say = "Oh, milyen sz\233p! Nagyon gyors volt! \193polni kell a[ENTER]r\233gi bar\225ts\225gokat, nem? Gyakran seg\237t\252nk[ENTER]egym\225snak... K\246sz\246n\246m, hogy elhoztad a ruh\225t.[ENTER]K\233rlek, add \225t \252dv\246zletem Ariyoung-nak. "
gameforge.subquest_32._290_npcChat = "Sz\252ks\233gem van egy \201kszerre. "
gameforge.subquest_32._300_say = "\201kszert keresel?[ENTER]Adok neked egy \201kszert, ha seg\237tesz nekem.[ENTER]Jelenleg egy k\252l\246nleges f\225jdalomcsillap\237t\243[ENTER]gy\243gyszeren dolgozok, de egy hozz\225val\243 m\233g[ENTER]hi\225nyzik: a Tigris m\225j. Nagyon neh\233z megszerezni.[ENTER]Sz\252ks\233gem van 100 Tigris m\225jra. "
gameforge.subquest_32._30_say = "Nem k\246nny\251 a H\225zal\243knak h\225bor\250 idej\233n. Minden\252tt[ENTER]sz\252ks\233g van \225rura, de a kereslet olyan gyorsan[ENTER]v\225ltozik, hogy soha nem lehet tudni, megfelel\245-e[ENTER]a k\237n\225latom. Nem besz\233lve a hossz\250 utakr\243l a[ENTER]puszt\225ban, ahol sz\246rnyek leselkednek a[ENTER]figyelmetlen j\225r\243kel\245kre. Nem akarsz keresni egy[ENTER]kis Yangot? J\243l j\246nne egy kis seg\237ts\233g. "
gameforge.subquest_32._310_say = "Sz\252ks\233gem van egy bizonyos Gy\243gyn\246v\233nyre is, amit[ENTER]szint\233n megkaphatsz a Tigrisekt\245l. Szeretnek[ENTER]benne hemperegni, mert szeretik az illat\225t. Adok[ENTER]majd egy \201kszert a Gy\243gyn\246v\233nyek\233rt \233s a Tigris[ENTER]m\225jak\233rt. "
gameforge.subquest_32._320_say = "Vad\225ssz tigrisekre vagy feh\233r tigrisekre. "
gameforge.subquest_32._330_say = "Mit sz\243lsz hozz\225? Meg tudunk egyezni? "
gameforge.subquest_32._340_say = "A feladatom t\250l neh\233z sz\225modra? El sem tudom[ENTER]k\233pzelni! L\225togass meg \250jra, ha meggondoltad[ENTER]magad. "
gameforge.subquest_32._350_say = "Az eg\233sz utat a Keresked\245 miatt tetted meg, \233s[ENTER]most feladod? Ahogy akarod...[ENTER]Tov\225bbi sz\233p napot. "
gameforge.subquest_32._360_say = "Nagyon j\243! Ez mindkett\245nk\246n seg\237t, nem? K\246sz\246n\246m,[ENTER]\233s sok szerencs\233t! "
gameforge.subquest_32._370_npcChat = "Megkapom most az \201kszert? "
gameforge.subquest_32._380_say = "Hadd l\225ssam... 100 Tigris m\225j \233s a Gy\243gyn\246v\233ny,[ENTER]minden itt van. K\246sz\246n\246m![ENTER]Tess\233k, fogd, val\243ban ki\233rdemelted ezt az[ENTER]\201kszert. Viszl\225t! "
gameforge.subquest_32._390_qSetTitle = "Vissza a H\225zal\243hoz "
gameforge.subquest_32._400_targetVid = "Vissza a H\225zal\243hoz "
gameforge.subquest_32._40_say = "Pillanatnyilag ork \213rl\245fogakb\243l k\233sz\252lt[ENTER]nyakl\225ncokra van t\233nyleges kereslet. Az \213rl\245fogak[ENTER]nagyok \233s kem\233nyek, \233s megfelel\245k bizonyos[ENTER]\233kszerek k\233sz\237t\233s\233re. A katon\225k is szerencsehoz\243[ENTER]talizm\225noknak tartj\225k a B\252szke ork var\225zsl\243k[ENTER]\213rl\245fogait. El tudn\225d hozni ezeket az \213rl\245fogakat[ENTER]nekem? 100 \213rl\245fog el\233g lenne kezdetnek. "
gameforge.subquest_32._410_sayReward = "Vissza a H\225zal\243hoz "
gameforge.subquest_32._420_sayReward = "V\233gre megszerezted az \246sszes anyagot a[ENTER]nyakl\225nchoz. Add a H\225zal\243nak! "
gameforge.subquest_32._430_npcChat = "N\225lam van az \246sszes anyag. "
gameforge.subquest_32._440_sayTitle = "H\225zal\243: "
gameforge.subquest_32._450_say = "Megvan minden \246sszetev\245? L\225ssuk...[ENTER]Igen, val\243ban itt van minden. K\246sz\246n\246m a[ENTER]seg\237ts\233ged, most m\225r ezzel a term\233kkel is[ENTER]kieg\233sz\237thetem k\237n\225latomat. Itt a r\233szed. J\243[ENTER]sz\243rakoz\225st![ENTER]Ide, emberek! Van itt valami, mindenki sz\225m\225ra! "
gameforge.subquest_32._460_sayReward = "1.100.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_32._470_sayReward = "Egy arany kark\246t\245t, egy arany nyakl\225ncot \233s egy[ENTER]arany f\252lbeval\243t kapsz. "
gameforge.subquest_32._480_say = "Hmmm... Sajn\225lom, de valami hi\225nyzik. Nincs[ENTER]sz\252ks\233gem hi\225nyos sz\225ll\237tm\225nyra. Pr\243b\225lkozol[ENTER]tov\225bb? "
gameforge.subquest_32._490_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_32._500_say = "K\246sz\246n\246m, hogy nem adod fel ilyen k\246nnyen! Pr\243ba,[ENTER]szerencse. Itt v\225rlak. "
gameforge.subquest_32._50_say = "Sz\252ks\233gem van egy \201kszerre \233s C\233rn\225ra is. Az[ENTER]egyiket megkaphatod a Vegyeskeresked\245 Elad\243n\245t\245l,[ENTER]a m\225sikat Ariyoung-t\243l. Nem valami k\246nny\251 sok[ENTER]dolog beszerz\233se, de a nyakl\225ncok \233rt\233kes\237t\233se j\243[ENTER]\252zlet, \233s jutalmat kapsz az alapanyagok\233rt. Mit[ENTER]gondolsz? Felkeltette az \233rdekl\245d\233sed? "
gameforge.subquest_32._510_say = "T\250l neh\233z a feladat? Nos, legal\225bb megpr\243b\225ltad.[ENTER]Majd sz\243lok, ha egy napon lesz valami k\246nnyebb[ENTER]feladatom sz\225modra. Viszl\225t! "
gameforge.subquest_32._520_say = "Megpr\243b\225lod m\233g egyszer? K\246sz\246n\246m. V\225rni fogok[ENTER]r\225d. "
gameforge.subquest_32._60_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_32._70_say = "Elfoglalt vagy? Meg\233rtelek. De k\233rlek, gyere[ENTER]vissza, ha lesz id\245d. "
gameforge.subquest_32._80_say = "Te j\243 \233j, hogy fogom teljes\237teni az \246sszes[ENTER]feladatom? Viszl\225t! "
gameforge.subquest_32._90_say = "Csod\225latos! Itt megv\225rlak. "
