gameforge.subquest_33._190_say = "Hmmmm.... K\252l\246n\246s. A t\233rk\233p azt mutatja, hogy a[ENTER]kincs az \214reg ember k\246zel\233ben, a szikl\225n van. Nem[ENTER]tudom elk\233pzelni, hogy ez igaz. M\225r meg kellett[ENTER]volna tal\225lnia valakinek. Milyen gyerekes cs\237ny![ENTER]Meg akarod n\233zni, vagy el k\233ne \233gessem a t\233rk\233pet? "
