gameforge.subquest_33._250_say = "Ahogy akarod. Meglep\245dn\233k, ha t\233nyleg tal\225ln\225l[ENTER]valamit, de az\233rt sok sikert k\237v\225nok. Vidd a[ENTER]t\233rk\233pet! "
gameforge.subquest_33._260_say = "A t\233rk\233pet n\233gy r\233szre v\225gt\225k. Mindre sz\252ks\233g\252nk[ENTER]van, hogy ism\233t \246sszerakjuk! "
