gameforge.subquest_33._350_say = "Ennek a helynek kell lennie. H\243-rukk![ENTER]Francba, a f\246ld nagyon kem\233nynek l\225tszik. Hmm...[ENTER][ENTER]L\225tok egy dobozt! "
