gameforge.subquest_33._370_sayTitle = "Vissza Soon-hoz "
gameforge.subquest_33._380_say = "Ott \225st\225l ahol a t\233rk\233p jel\246lte, \233s t\233nyleg[ENTER]tal\225lt\225l egy kincsesl\225d\225t! Menj Soonhoz \233s mondd[ENTER]el neki a nem v\225rt fejlem\233nyt. "
gameforge.subquest_33._390_npcChat = "Megtal\225ltam a kincset! "
gameforge.subquest_33._400_say = "Oh! Meglep\245dtem! N\233zz\252k... hihetetlen. Ez \233ppen[ENTER]\250gy n\233z ki, ahogy a r\233gi sz\246vegek le\237rj\225k. M\225r[ENTER]csak azt kellene kital\225lni, hogyan nyissuk ki. De[ENTER]ez m\225r nem a te probl\233m\225d. K\246sz\246n\246m! Tess\233k,[ENTER]fogadd ezt h\225l\225m jel\233\252l! "
gameforge.subquest_33._40_say = "Egy r\233gi mese szerint n\233gy istenforma sz\246rny[ENTER]t\233pte n\233gy r\233szre a t\233rk\233pet, \233s \245rzik ezeket a[ENTER]ter\252leteket. Nem vagyok benne biztos, hogy igaz.[ENTER]Ellen\245rizn\233d nekem? Oh, k\233rlek, meg\246l ez a[ENTER]bizonytalans\225g... K\246ny\246r\246gve k\233rlek, seg\237ts[ENTER]nekem! "
