gameforge.subquest_34._20_sayTitle = "Kapit\225ny "
gameforge.subquest_34._210_sayReward = "Nyelv gy\251r\251t kapt\225l. "
gameforge.subquest_34._30_say = "J\243llehet megverted a 'Fekete sz\233l kl\225nt', m\233gsem[ENTER]hagynak benn\252nket b\233k\233n.[ENTER]Ahelyett, hogy nyugton lenn\233nek, \250gy viselkednek,[ENTER]mint egy vad horda.[ENTER]Ha le akarjuk \245ket gy\245zni, akkor a Fekete sz\233l[ENTER]gener\225lisokat kell meg\246ln\252nk.  "
gameforge.subquest_34._40_say = "Ha a gener\225lisokat legy\245zt\252k, akkor a t\246bbiek el[ENTER]fognak esni. Neh\233z munka lesz, de egy gy\245zelemre[ENTER]van sz\252ks\233g\252nk a Fekete sz\233l gener\225lisok ellen:[ENTER]Jak-To, To-Su, Gu-Ryung ellen.[ENTER]Ha legy\245zz\252k \245ket, akkor m\225r nem kell agg\243dnunk a[ENTER]'Fekete sz\233l kl\225n' miatt.  "
gameforge.subquest_34._50_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_34._60_say = "Hmm... Ha k\233sz vagy, akkor l\225togass meg megint.[ENTER]Nincs sok ilyen tehes\233ges ember, mint Te. "
gameforge.subquest_34._70_say = "Nem tudod..[ENTER]Hogy gy\245zz\252k le a 'Fekete sz\233l kl\225nt' k\252l\246nben..? "
gameforge.subquest_34._80_say = "Tudtam hogy sz\225m\237thatok r\225d! Ha a gener\225lisok[ENTER]meghalnak a t\246bbi tagja a fekete sz\233l csapatnak[ENTER]nem lesz gond. Sok szerencs\233t! "
