gameforge.subquest_36._160_say = "Az \237g\233ret sz\233p sz\243. Az is lehet, hogy k\233s\245bb[ENTER]szeretn\233k majd lovagolni. Felt\233tlen\252l tal\225lnom[ENTER]kell egy kis sz\233n\225t! "
gameforge.subquest_36._170_say = "Sajn\225lom. Kerestem, de egyszer\251en lehetetlen[ENTER]sz\233n\225t tal\225lni. "
gameforge.subquest_36._180_say = "Tudom, nem t\250l sz\233p t\245lem, hogy veled csin\225ltatom[ENTER]meg a munk\225m, de m\233g mindig rem\233nykedem benne,[ENTER]hogy megteszed. Meg tudn\225d pr\243b\225lni \250jra? Ismerek[ENTER]egy nagyon fontos szem\233lyt a m\225sik birodalomban.[ENTER]Ha seg\237tesz, megk\233rdezem t\245le, tud-e tenni[ENTER]valamit az \233rdekedben. "
