gameforge.subquest_36._20_npcChat = "Az ist\225ll\243k gondban vannak "
gameforge.subquest_36._210_say = "Nincs el\233g energi\225m ehhez. Szeretn\233k seg\237teni[ENTER]neked, de nem tudok. nem vagyok el\233g er\245s. "
gameforge.subquest_36._220_npcChat = "Van sz\233n\225m a lovaknak. "
gameforge.subquest_36._230_say = "Beszerezted a sz\233n\225t? Oh, k\246sz\246n\246m. Nem volt[ENTER]elegend\245 ennival\243nk a lovak sz\225m\225ra, \237gy sz\243ltam[ENTER]Yonah-nak. \213 nagyon j\243 bar\225tom. Azt tal\225ltam ki,[ENTER]k\246r\252ln\233zhetne, h\225tha tal\225l valakit, aki tudna[ENTER]seg\237teni. De azt nem gondoltam, hogy erre ilyen[ENTER]gyorsan sor ker\252l. Csak n\233zd, milyen \246r\246mmel[ENTER]falj\225k a lovak. "
gameforge.subquest_36._240_sayReward = "1.800.000 tapasztalat pontot kapt\225l "
gameforge.subquest_36._250_sendLetter = "Vissza Yonahhoz "
gameforge.subquest_36._260_sayTitle = "Vissza Yonahhoz "
