gameforge.subquest_36._280_npcChat = "Gondoskodni a lovakr\243l! "
gameforge.subquest_36._290_say = "Hello, visszat\233rt\233l![ENTER]Val\243sz\237n\251leg neh\233z feladat volt \246sszegy\251jteni ezt[ENTER]a sok sz\233n\225t. K\246sz\246n\246m, hogy nem adtad fel! Itt[ENTER]van egy kis aj\225nd\233k sz\225modra. "
gameforge.subquest_36._300_sayReward = "Egy Misszi\243k\246nyvet kapt\225l. "
gameforge.subquest_36._30_say = "H\233, k\233rdezn\233k t\245led valamit! Tudom, hogy m\225s a[ENTER]felel\245s az ist\225ll\243k\233rt, de sok probl\233m\225nk volt a[ENTER]k\246zelm\250ltban, \233s seg\237thetn\233l nek\252nk. Sok dolga[ENTER]volt a lovaknak a h\225bor\250 idej\233n, de m\233g egy er\245s,[ENTER]feln\245tt l\243nak is megvannak a maga korl\225tai. "
gameforge.subquest_36._40_say = "Sok l\243 van, de kev\233s a takarm\225ny. Nagyon sok[ENTER]meghal. Be tudn\225l szerezni egy kis takarm\225nyt,[ENTER]hogy a lovak egy kis er\245re kaphassanak \250jra?[ENTER]Nincs senki m\225s, akit megk\233rhetn\233k. Gy\251jts \246ssze[ENTER]10 b\225la sz\233n\225t, \233s add oda a Lov\225szinasnak. \213 m\225r[ENTER]tud a probl\233m\225r\243l. Csak mondd neki, hogy \233n[ENTER]k\252ldtelek. "
gameforge.subquest_36._50_select = "Azonnal indulok! "
gameforge.subquest_36._60_select = "Nem, ez alantas munka. "
gameforge.subquest_36._70_say = "Manaps\225g egyre t\246bb ember akar lovat tartani. De[ENTER]senki nem gondolt arra, hogy egyszer kimer\252l a[ENTER]takarm\225ny k\233szlet\252nk a lovak sz\225m\225ra. \201s most[ENTER]\233heznek az ist\225ll\243ban. Gyere vissza, ha[ENTER]meggondolod magad. "
gameforge.subquest_36._80_say = "Oh, azok a szeg\233ny lovak! \201heznek, \233s \233n nem[ENTER]tehetek semmit ellene... Mit kellene tennem... "
gameforge.subquest_36._90_say = "Tudom, hogy elfoglalt vagy, \233s \233n igaz\225n nagyra[ENTER]\233rt\233kelem a seg\237ts\233ged. A lovak nagyon fontosak[ENTER]manaps\225g. \201s nek\252nk val\243ban sz\252ks\233g\252nk van[ENTER]sz\233n\225ra. "
gameforge.subquest_37 = {}
gameforge.subquest_37._100_say = "Yonah mindent belead, hogy \250j porcel\225nt \225ll\237tson[ENTER]el\245 de nem halad vele egyel\245re. L\225togasd meg[ENTER]Urielt \233s \233rdekl\245dd meg tud-e valamit a porcel\225n[ENTER]el\245\225ll\237t\225sr\243l. "
