gameforge.subquest_37._110_npcChat = "Ismered a Celadon porcel\225nt? "
gameforge.subquest_37._120_sayTitle = "Uriel : "
gameforge.subquest_37._130_say = "Seladon-porcel\225n?[ENTER]Nos, \233n j\225rtas vagyok a t\246rt\233nelemben \233s a[ENTER]tudom\225nyokban, de a m\251v\233szet ir\225nt nem[ENTER]\233rdekl\245d\246m. A Seladon-porcel\225nr\243l sajnos nem[ENTER]tudok neked semmit mes\233lni. Tal\225n Soon tud[ENTER]valamit. \213 nem igaz\225n kedvelt, de k\252l\246nb\246z\245[ENTER]k\246nyveket olvas, tal\225n t\246bbet tud[ENTER]err\245l.  "
