gameforge.subquest_37._170_sayTitle = "Soon : "
gameforge.subquest_37._180_say = "Mit akarsz? Ne zavarj az olvas\225sban! Mi?[ENTER]Seladon-porcel\225n? Term\233szetesen tudok r\243la. \201n[ENTER]megk\246zel\237t\245leg 10 k\246nyvet olvastam, ami ezzel[ENTER]foglalkozott. Mi\233rt? H\225t nem neveznek engem hi\225ba[ENTER]k\246nyvmolynak! Mindent meg\233rtek, ami k\246nyvekben le[ENTER]van \237rva! "
gameforge.subquest_37._190_say = "Le\237rhatom hogy hogyan kell a Celadon porcel\225nt[ENTER]elk\233sz\237teni, itt van az agyamban, de mi\233rt[ENTER]tenn\233m? Hmm. V\225rj, van egy \246tletem: Megk\233rdeztem[ENTER]a h\225zal\243t a k\246vetkez\245 faluban hogy megvan-e neki[ENTER]a k\246nyv ami m\233g mindig hi\225nyzik nekem de nincs[ENTER]id\245m elmenni \233rte. Szerezd meg nekem \233s seg\237tek a[ENTER]porcel\225nban. Menj! "
gameforge.subquest_37._200_makequestbutton = "Indul\225s a h\225zal\243 keresked\245h\246z "
gameforge.subquest_37._20_sayTitle = "Yonah : "
gameforge.subquest_37._210_targetVid = "Menj a h\225zal\243 keresked\245h\246z "
gameforge.subquest_37._220_say = "Soon a k\246nyvmoly ismeri a Seladon porcel\225nt, de[ENTER]csak akkor fogja a tud\225s\225t megosztani veled, ha[ENTER]elhozod a k\246nyv\233t a h\225zal\243 keresked\245t\245l. Indulj a[ENTER]h\225zal\243 keresked\245h\246z \233s hozd el a k\246nyvet, amit[ENTER]Soon megrendelt. "
gameforge.subquest_37._230_npcChat = "Soon k\252ld\246tt... "
gameforge.subquest_37._240_say = "H\233, az\233rt j\246tt\233l vissza, hogy ism\233t seg\237ts nekem?[ENTER]Ah, te Soon k\246nyv\233re gondolsz. \201n nem sok\225ra[ENTER]elj\246ttem volna a v\225rosba, de \245 t\250ls\225gosan[ENTER]t\252relmetlen. Megk\233r m\225sokat, hogy hozz\225k el neki[ENTER]a k\246nyvet. Hmm. Ah! Itt van. Nem \233rtem, hogy ez a[ENTER]pap\237rhalom mi\233rt olyan fontos. Sokkal fontosabb,[ENTER]hogy az ember gyorsan Yangot keressen. "
gameforge.subquest_37._250_qSetTitle = "Visszat\233r\233s Soon "
gameforge.subquest_37._260_targetVid = "Visszat\233r\233s Soon "
gameforge.subquest_37._270_say = "A szomsz\233d v\225ros keresked\245j\233t\245l megkaptad Soon[ENTER]k\246nyv\233t. Most pedig t\233rj vissza Soonhoz, hogy[ENTER]odaadd neki a k\246nyvet, \233s hogy a tud\225s\225t s[ENTER]Celadonr\243l megossza veled. "
gameforge.subquest_37._280_npcChat = "N\225lam van a k\246nyv "
gameforge.subquest_37._290_say = "Juhu...v\233gre n\225lam van az \250j k\246nyv! K\246sz\246n\246m[ENTER]sz\233pen. Nincs sok k\246nyv amit m\233g nem olvastam...[ENTER]Le\237rtam minden fontosat a Celadon porcel\225n[ENTER]k\233sz\237t\233s\233r\245l. K\246vesd az \250tmutat\243m \233s t\246k\233letes[ENTER]porcel\225nt fogsz k\233sz\237teni. \201s most itt az ideje[ENTER]hogy elolvassam az \250j k\246nyvemet. Viszont l\225t\225sra! "
gameforge.subquest_37._300_makequestbutton = "Vissza Yonahhoz "
gameforge.subquest_37._30_say = "Hmm. H\225t ez nem j\243. Ez sem... oh, hell\243! Ide[ENTER]n\233zz: folyamatosan k\233sz\237tem a porcel\225nt de a nagy[ENTER]r\233sze azonnal elt\246rik. Azt hiszem valami m\225sfajta[ENTER]porcel\225nra lesz sz\252ks\233gem... "
