gameforge.subquest_37._330_say = "\211\243\243![ENTER]Itt minden le van \237rva a porcel\225n el\245\225ll\237t\225s\225r\243l.[ENTER]V\233gre mesternk\233nt fogok bevonulni a t\246rt\233nelembe[ENTER]ennek a seg\237ts\233g\233vel. K\246sz\246n\246m a seg\237ts\233ged.[ENTER]Hamarosan be tudom mutatni a vil\225gnak a legjobb[ENTER]ker\225mi\225t! B\237zz meg bennem! Olyan j\243 Celadon[ENTER]porcel\225nt fogok elk\233sz\237teni, hogy \233vsz\225zadokat[ENTER]fog t\250l\233lni. "
