gameforge.subquest_38._30_say = "A D\237szes \237jr\243l van sz\243, amit r\233gebben elloptak a[ENTER]majmok. Akkoriban a Majom kazamat\225ban vad\225sztam,[ENTER]\233s csak egyetlen m\225sodpercre voltam figyelmetlen[ENTER]- \245k kihaszn\225lt\225k az alkalmat, \233s ellopt\225k t\245lem[ENTER]azt. "
gameforge.subquest_38._40_say = "M\233g soha nem j\225rtam Sangsun Dong m\233ly\233n, sz\243val[ENTER]nem igaz\225n ismerem oda az utat, \237gy sz\252ks\233gem van[ENTER]a seg\237ts\233gedre. N\233h\225ny helyb\233li azt mondja,[ENTER]nagyon \252gyes vagy. Ez\233rt k\233rlek T\233ged erre a[ENTER]sz\237vess\233gre. A D\237szes \237j n\233lk\252l nem tudok \245seim[ENTER]szem\233be n\233zni. "
