gameforge.subquest_39._160_sayTitle = "Baek-Go: "
gameforge.subquest_39._170_say = "Oh, te vagy az, hogy vagy? Te egy igazi beteget[ENTER]kezelsz? Mondd el, mi a baja... Hmm... \201s milyen[ENTER]gy\243gyszert kapott? Micsoda?! Nem csoda, ha egyre[ENTER]rosszabbul \233rzi mag\225t! Az a gy\243gyszer teljesen[ENTER]alkalmatlan! "
gameforge.subquest_39._180_say = "Szerencs\233s, hogy m\233g mindig \233l! Nagyon vesz\233lyes,[ENTER]ha egy beteg ember rossz kezel\233sben r\233szes\252l! De[ENTER]tudom, mi seg\237t rajta. Van egy bizonyos[ENTER]gy\243gyn\246v\233ny, ami megszabad\237tja a testet a[ENTER]m\233regt\245l, \233s vissza\225ll\237tja az eg\233szs\233get.[ENTER]Ugyanakkor, nagyon vesz\233lyes helyen tal\225lhat\243. "
gameforge.subquest_39._190_say = "Ha j\243l tudom, a gy\243gyn\246v\233ny csak Sangsun Dong-ban[ENTER]n\245. De mindig betakar\237tj\225k a Majom fejedelem[ENTER]sz\225m\225ra, aki sz\237vesen fogyasztja. Meg kell \246ln\246d[ENTER]\245t, hogy megszerezd a n\246v\233nyt.[ENTER]El tudom k\233sz\237teni a megfelel\245 gy\243gyszert, ha[ENTER]elhozod nekem a gy\243gyn\246v\233nyt. "
gameforge.subquest_39._200_select = "Rendben, hozok. "
gameforge.subquest_39._20_npcChat = "A gy\243gyszeredr\245l... "
gameforge.subquest_39._210_select = "Nem tudom megtenni. "
gameforge.subquest_39._220_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_39._230_select = "Igen "
gameforge.subquest_39._240_say = "H\225t, akkor tal\225n k\233s\245bb, ha lesz n\233mi szabad[ENTER]id\245d. Sok a beteg ember, de nagyon kevesen[ENTER]keresik a gy\243gyul\225st. "
gameforge.subquest_39._250_say = "Hmmm, h\225t sajnos ez van. Sz\233gyen, hogy senki sem[ENTER]el\233g b\225tor. Mi lesz ebb\245l a v\233g\233n... "
gameforge.subquest_39._260_say = "Oh, k\246sz\246n\246m. Neh\233z munka lesz. De sz\225mos emberen[ENTER]seg\237tesz vele! "
gameforge.subquest_39._270_makequestbutton = "A Majomvez\233r gy\243gyn\246v\233nye "
gameforge.subquest_39._280_targetVid = "Vissza Baek-Gohoz "
gameforge.subquest_39._290_sayTitle = "Neh\233z majom n\246v\233nyt tal\225lt\225l "
gameforge.subquest_39._300_say = "Megszerezted a Majom fejedelemt\245l a Neh\233z majom[ENTER]n\246v\233nyt. Vidd el Baek-Go-nak, hogy elk\233sz\237thesse[ENTER]a gy\243gyszert Balso sz\225m\225ra. "
gameforge.subquest_39._30_say = "K\246sz\246n\246m, hogy legut\243bb elhoztad a gy\243gyszert. De[ENTER]van egy probl\233m\225m... A gy\243gyszer hat\225sa[ENTER]legyeng\252lt. Azt hiszem, rosszabb lett.[ENTER]*K\246h\246g\233s* - Felt\233tlen\252l sz\252ks\233gem van kezel\233sre. "
gameforge.subquest_39._310_sayTitle = "Szerezd meg a n\246v\233nyt Sangsun Dong-b\243l "
gameforge.subquest_39._320_say = "Baek-Go k\233pes gy\243gyszert k\233sz\237teni \193rul\243 Balso[ENTER]betegs\233g\233re. Ehhez Neh\233z majom n\246v\233nyre van[ENTER]sz\252ks\233ge. Megszerezheted a Majom fejedelemt\245l a[ENTER]Profi majom kazamat\225ban. "
gameforge.subquest_39._330_npcChat = "Neh\233z majom n\246v\233ny... "
gameforge.subquest_39._340_say = "\218gy t\251nik, a betegs\233g j\225rv\225nyk\233nt terjed, de nem[ENTER]ismerj\252k az ok\225t. Ugyanakkor az akad\233miai[ENTER]t\225rsas\225g szerint a Majom n\246v\233nyb\245l kifejlesztett[ENTER]gy\243gyszer seg\237thet. Mi a baj? M\225r megtal\225ltad a[ENTER]gy\243gyn\246v\233nyt? "
gameforge.subquest_39._350_select = "M\233g nem, de hamarosan! "
gameforge.subquest_39._360_select = "Nem tudom beszerezni a n\246v\233nyt. "
gameforge.subquest_39._370_say = "T\233nyleg fel akarod adni? Hmm, azt hiszem, ezt m\225r[ENTER]nem igaz\225n teheted meg t\246bb\233. Mit tehetn\233k? Ez a[ENTER]gy\243gyn\246v\233ny egy igazi \225ld\225s... "
gameforge.subquest_39._380_select = "Nem tudom megtenni. "
gameforge.subquest_39._390_select = "Seg\237teni akarok! "
gameforge.subquest_39._400_say = "A majmok t\250l er\245sek nekem. Nem tudom megszerezni[ENTER]a gy\243gyn\246v\233nyt. Sajn\225lom. "
gameforge.subquest_39._40_say = "Tudom, hogy a szomsz\233dos faluban \233l egy orvos. El[ENTER]tudn\225l menni hozz\225, hogy elmagyar\225zd neki a[ENTER]helyzetem, h\225tha meg tudn\225 mondani, mit tehetn\233k?[ENTER]Amint l\225tod, nem hagyhatom el a falut ebben az[ENTER]\225llapotban. Nagyon h\225l\225s vagyok a legut\243bbi[ENTER]seg\237ts\233ged\233rt, \233s biztos lehetsz benne, hogy most[ENTER]is megjutalmazlak majd. "
gameforge.subquest_39._410_say = "Te megtagadod emberekt\245l a seg\237ts\233get, akik egy[ENTER]borzalmas \233s titokzatos betegs\233gben szenvednek![ENTER]T\251nj el a szemem el\245l! "
gameforge.subquest_39._420_say = "Igazad van. Valakinek meg kell szereznie ezt a[ENTER]gy\243gyn\246v\233nyt, k\252l\246nben ezek a beteg emberek[ENTER]borzalmasan szenvedni fognak. Majd \233n gondoskodok[ENTER]r\243la. "
gameforge.subquest_39._430_say = "Na akkor... siess! "
gameforge.subquest_39._440_say = "Te t\233nyleg beszerezted a majom n\246v\233nyt! Rem\233lem,[ENTER]ez t\233nyleg orvosolja ezt a rejt\233lyes betegs\233get.[ENTER]V\225rj egy pillanatot, most gyorsan elk\233sz\237tem a[ENTER]gy\243gyszert. "
gameforge.subquest_39._450_sayTitle = "Baek-Go: "
gameforge.subquest_39._460_say = "Itt van a gy\243gyszer. Siess a betegedhez, \233s add[ENTER]oda neki. Hamarosan jobban kell lennie. \201s[ENTER]k\233rlek, mondd meg neki azt is, mindig jobb egy[ENTER]orvost\243l megk\233rdezni, melyik a helyes gy\243gyszer. "
gameforge.subquest_39._470_makequestbutton = "Add Balsonak a gy\243gyszert "
gameforge.subquest_39._480_targetVid = "\193tadod Balsonak a gy\243gyszert. "
gameforge.subquest_39._490_sayTitle = "\193rul\243 Balso gy\243gyszere "
gameforge.subquest_39._500_say = "Baek-Go elk\233sz\237tette a gy\243gyszert a Neh\233z majom[ENTER]n\246v\233nyb\245l, mely sz\225mos ritka betegs\233g[ENTER]gy\243gy\237t\225s\225ra k\233pes. Vidd el \193rul\243 Balsonak a[ENTER]szomsz\233d faluba. "
gameforge.subquest_39._50_say = "Ki akarsz l\233pni ebb\245l a k\252ldet\233sb\245l? "
gameforge.subquest_39._510_npcChat = "Itt van a gy\243gyszer "
gameforge.subquest_39._520_say = "\218j orvoss\225got hozol nekem? T\246rt\233nt n\233mi[ENTER]el\245rel\233p\233s az orvosi kutat\225sban? Sajn\225lom, hogy[ENTER]zavartalak. Kezdetekt\245l fogva ki kellett volna[ENTER]k\233rnem egy orvos tan\225cs\225t. Most viszont elfogadom[ENTER]ezt a gy\243gyszert, amit kaptam. "
gameforge.subquest_39._530_say = "K\246sz\246n\246m, hogy ebben a nyomor\250s\225gos helyzetemben[ENTER]seg\237tett\233l nekem. Nincs sok bar\225tom. Tess\233k,[ENTER]tudom, hogy nem valami t\250l sok, de sz\237vb\245l adom.[ENTER]K\233rlek, fogadd el! B\225rmi lesz is velem, soha nem[ENTER]foglak elfeledni. "
gameforge.subquest_39._540_sayReward = "4.000.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_39._550_sayReward = "65.000 Yangot kapt\225l. "
gameforge.subquest_39._60_say = "Ha tudod, hogy hogyan lehet rajtam seg\237teni,[ENTER]akkor tal\225lkozzunk megint itt. "
gameforge.subquest_39._70_sayTitle = "\193rul\243 Balso: "
gameforge.subquest_39._80_say = "Vajon tov\225bbra is \237gy kell \233lnem?[ENTER]Viszl\225t legk\246zelebb. "
gameforge.subquest_39._90_say = "K\246sz\246n\246m. Vigy\225zz magadra. "
gameforge.subquest_40 = {}
gameforge.subquest_40._100_say = "Tudtam, hogy sz\225m\237thatok r\225d! Ez egy bonyolult[ENTER]feladat, de biztos vagyok benne, hogy k\233pes vagy[ENTER]r\225. Sok szerencs\233t! "
