gameforge.subquest_40._110_targetVid = "Vissza a Kapit\225nyhoz "
gameforge.subquest_40._120_say = "\214sszegy\251jt\246tted mind az 5.000 ny\237lhegyet. Add oda[ENTER]a Kapit\225nynak! "
gameforge.subquest_40._130_say = "A hadsereg sz\225m\225ra probl\233m\225t jelent a nyilak[ENTER]beszerz\233se. \214lj Fert\245z\246tt \237j\225szokat Sohan hegyen,[ENTER]\233s add a ny\237lhegyeiket a Kapit\225nynak. 5.000 db.[ENTER]elegend\245 lesz. "
gameforge.subquest_40._140_npcChat = "A Ny\237lhegyekr\245l... "
gameforge.subquest_40._150_say = "Ezek a Fert\245z\246tt \237j\225szok egy bizonyos betegs\233gben[ENTER]szenvednek, ami elterjedt az eg\233sz kontinensen.[ENTER]M\233g az orvosaink sem tudj\225k megmagyar\225zni. A[ENTER]ny\237lhegyeik most m\233g rendben vannak, de egyre[ENTER]m\233rgez\245bb\233 v\225lnak azok is. "
gameforge.subquest_40._160_select = "Folytatni fogom. "
gameforge.subquest_40._170_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_40._180_say = "F\233lsz a betegs\233gt\245l. Nyugodj meg, \233s gyere vissza[ENTER]k\233s\245bb. "
gameforge.subquest_40._190_say = "Biztos vagy benne, hogy feladod? Hmmm, tal\225n[ENTER]t\233nyleg t\250l neh\233z neked ez a feladat. Valaki m\225st[ENTER]fogok megk\233rni. Viszl\225t! "
gameforge.subquest_40._200_say = "L\225tom.[ENTER]Soha nem adod fel, igaz?[ENTER]Akkor indulj! "
gameforge.subquest_40._20_say = "Figyelem, harcosok! Amint l\225thatj\225tok, az[ENTER]ellens\233ges t\225mad\225sok sz\225ma napr\243l napra[ENTER]n\246vekszik. Aggaszt\243 h\237reket hozott Yu-Hwan is.[ENTER]R\246viden a l\233nyeg: Elegend\245 ny\237lra van sz\252ks\233g\252nk! "
gameforge.subquest_40._210_npcChat = "Itt van 5.000 ny\237lhegy! "
gameforge.subquest_40._220_say = "Csod\225latos munka! Most m\225r el\245 tudjuk k\233sz\237teni a[ENTER]t\225mad\225st. Ennek \233rdek\233ben most r\246gt\246n adok is[ENTER]n\233h\225ny nyilat. Ez egy igaz\225n j\243 csapatmunka volt.[ENTER]Rem\233lem, k\233s\245bb is sz\225m\237thatunk r\225d! "
gameforge.subquest_40._230_say = "Itt a jutalmad. Legk\246zelebb, ha fontos munk\225nk[ENTER]ad\243dik, neked fogunk sz\243lni el\245sz\246r.[ENTER]Minden j\243t, hamarosan tal\225lkozunk! "
gameforge.subquest_40._240_sayReward = "4.500.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_40._250_sayReward = "50.000 Yangot kapt\225l. "
gameforge.subquest_40._260_sayReward = "3 x Kritikus Csap\225st kapt\225l.[ENTER]3 x \193t\252t\245 Csap\225st kapt\225l. "
gameforge.subquest_40._30_say = "Az \237j\225szok fontos strat\233giai t\233nyez\245k a[ENTER]hadvisel\233sben. Amint az ellens\233g a hat\243k\246r\252kbe[ENTER]ker\252l, elkezdik l\245ni \245ket. \205gy ak\225r el is[ENTER]\252ld\246zhetj\252k az ellens\233get, vagy legal\225bb[ENTER]cs\246kkenthetj\252k a sz\225mukat. De ha t\250l sok t\225mad\225s[ENTER]\233r benn\252nket r\246vid id\245 alatt, hamarosan kifogyunk[ENTER]a nyilakb\243l. "
gameforge.subquest_40._40_say = "Ez\233rt van sz\252ks\233g\252nk R\225d! Menj a Sohan hegyre, \233s[ENTER]\246lj Fert\245z\246tt \237j\225szokat, hogy megszerezd a[ENTER]ny\237lhegyeiket. Azok a ny\237lhegyek m\233rgez\245ek, de[ENTER]hat\225sosan seg\237tenek legy\245zni az ellens\233get.[ENTER]5.000 Ny\237lhegyre van sz\252ks\233g\252nk. Mit sz\243lsz hozz\225? "
gameforge.subquest_40._50_select = "Elfogadom. "
gameforge.subquest_40._60_select = "Ez t\250l neh\233z nekem. "
gameforge.subquest_40._70_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_40._80_say = "T\250l messze van neked a Sohan-hegys\233g? Gondolkodj[ENTER]rajta! Ez a k\252ldet\233s nagyon fontos. "
gameforge.subquest_40._90_say = "Hm, f\233lsz a fert\245z\246tt \237j\225szokt\243l? Azt hiszem,[ENTER]t\250lbecs\252ltelek. L\225tom, nincs t\246bb rem\233ny[ENTER]sz\225munkra. "
