gameforge.subquest_41._100_say = "\214sszegy\251jt\246tted mind a 100 p\243k szemet Octavio \250j[ENTER]receptj\233hez. Min\233l gyorsabban el kellene vinned[ENTER]neki. "
gameforge.subquest_41._10_targetVid = "K\252l\246nleges p\243kszemek "
gameforge.subquest_41._110_sayTitle = "P\243kszemek beszerz\233se "
gameforge.subquest_41._120_say = "Octavio szeretn\233 kipr\243b\225lni a \"K\252l\246nleges[ENTER]p\243kszemek\" nev\251 \250j receptj\233t. Ehhez 100 p\243kszemre[ENTER]van sz\252ks\233ge a Yongbi sivatagi p\243kokt\243l. "
gameforge.subquest_41._130_targetVid = "Vissza Octaviohoz "
gameforge.subquest_41._140_npcChat = "Vannak p\243kszemeim. "
gameforge.subquest_41._150_sayTitle = "Octavio: "
gameforge.subquest_41._160_say = "Mutasd! Pontosan sz\225z darab szem, nagyon j\243! Nos,[ENTER]l\225ssuk csak...[ENTER]Mmhhh, k\233sz! Te is szeretn\233d kipr\243b\225lni? Ne n\233zz[ENTER]ilyen sz\246rny\252lk\246dve. Nem halsz meg t\245le. "
gameforge.subquest_41._170_say = "Hmm, hmm... Zseni\225lis! nagyon t\225pl\225l\243, nem t\250l[ENTER]\233des... hihetetlen \237z\251! Tudtam, hogy meg\233ri a[ENTER]f\225radts\225got. Soha nem tudtam volna megcsin\225lni[ENTER]n\233lk\252led. Nagyon sz\233pen k\246sz\246n\246m a seg\237ts\233ged! "
gameforge.subquest_41._180_sayReward = "2.100.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_41._190_say = "Mir\245l besz\233lsz? Ez nem sz\225z szem, meg tudom[ENTER]mondani an\233lk\252l, hogy megsz\225moln\225m![ENTER]K\233rlek, hozz m\233g t\246bbet. "
gameforge.subquest_41._200_say = "Mindenf\233lek\233ppen meg szeretn\233m f\245zni...[ENTER]Mindegy, k\246sz\246n\246m. L\233gy j\243 \233s vigy\225zz magadra. "
gameforge.subquest_41._20_say = "Szia, hogy vagy? Most olvasok egy szak\225csk\246nyvet,[ENTER]amit Soon nagylelk\251en nekem aj\225nd\233kozott.[ENTER]Tal\225ltam benne egy \233rdekes receptet, \250gy h\237vj\225k,[ENTER]'K\252l\246nleges p\243kszemek'. Soha nem l\225ttam m\233g[ENTER]ezel\245tt ehhez foghat\243t! Neked van? \218gy t\251nik, ez[ENTER]k\252l\246nleges \233tel egy m\225sik orsz\225gban. "
gameforge.subquest_41._210_say = "K\246sz\246n\246m, hogy nem hagysz cserben.[ENTER]Nagyon kedves vagy! "
gameforge.subquest_41._30_say = "Annyira szeretn\233m kipr\243b\225lni ezt az \233telt, de[ENTER]hogyan szerezzek p\243kszemeket? T\233nyleg sz\252ks\233gem[ENTER]van \250jra a seg\237ts\233gedre! K\233rlek, hozz p\243kszemeket[ENTER]a p\243kokt\243l a Yongbi sivatagb\243l! "
gameforge.subquest_41._40_say = "Megtenn\233d ezt nekem? Igaz\225n nagyon h\225l\225s lenn\233k[ENTER]\233rte. hogy ki tudjam pr\243b\225lni a receptet, egy[ENTER]megfelel\245 m\233ret\251 adag elk\233sz\237t\233s\233hez sz\252ks\233gem[ENTER]van sz\225z szemre. Olyan izgatott vagyok... "
gameforge.subquest_41._50_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_41._60_say = "Ezt a receptet mindenf\233lek\233ppen meg akarom f\245zni,[ENTER]teh\225t ha egy sz\237vess\233get akarsz tenni, akkor[ENTER]k\233rlek l\225togass meg.  "
gameforge.subquest_41._70_say = "Hm...Hol tudom beszerezni a szemeket...[ENTER]Ok, viszl\225t. "
gameforge.subquest_41._80_say = "K\246sz\246n\246m, tudtam, hogy meg fogod tenni nekem ezt[ENTER]a sz\237vess\233get. Ennek fej\233ben egy kiv\225l\243 \233telt[ENTER]fogok neked t\225lalni.  "
gameforge.subquest_41._90_sayTitle = "Vissza Octaviohoz "
