gameforge.subquest_42._230_say = "Nagyszer\251 volt! Most m\225r meg tudjuk nyugtatni a[ENTER]halott katon\225kat. \213k megtett\233k, ami t\245l\252k telt.[ENTER]Most m\225r b\233k\233ben nyugodhatnak. Hadd adjak valami[ENTER]jutalmat ez\233rt a nemes cselekedeted\233rt! "
gameforge.subquest_42._30_say = "Ezek a borzalmas h\225bor\250k egyre t\246bb \233s t\246bb[ENTER]fiatal harcost \246lnek meg. Ezek a katon\225k a[ENTER]csal\225djuk\233rt \233s az orsz\225guk\233rt harcolnak a[ENTER]frontvonalon. De a hal\225luk ut\225n sokan nem tudnak[ENTER]\225tjutni a Nirv\225n\225ba. \205gy \245k tov\225bbra is ebben a[ENTER]vil\225gban maradnak. "
gameforge.subquest_42._40_say = "Azt mondj\225k, \245k ellen\225lltak a hal\225lnak a h\225bor\250[ENTER]idej\233n. Azt hiszik, hogy m\233g mindig az orsz\225gukat[ENTER]v\233dik.[ENTER]A S\225m\225njaink tartani akarnak egy cerem\243ni\225t a[ENTER]lelkek megnyugtat\225s\225ra. Ennek \233rdek\233ben,[ENTER]sz\252ks\233g\252nk van egy k\252l\246nleges Templomi s\225lra \233s[ENTER]egy Vall\225si tanra, amihez manaps\225g neh\233z[ENTER]hozz\225jutni. Meg tudn\225d szerezni nek\252nk mindk\233t[ENTER]dolgot? "
gameforge.subquest_42._50_say = "Azt hallottam, hogy a B\252szke s\246t\233t ezredesek egy[ENTER]Templomi s\225lat \233s egy Vall\225si tant \245riznek a[ENTER]Hwang templomban. K\233rlek, seg\237ts nekem \233s a[ENTER]t\225rsaimnak, hogy megnyugtathassuk azokat, akik[ENTER]meghaltak a haz\225juk\233rt! "
gameforge.subquest_42._60_select = "Seg\237tek neked. "
gameforge.subquest_42._70_select = "Sajn\225lom, de t\250ls\225gosan f\233lek. "
gameforge.subquest_42._80_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_42._90_say = "Seg\237ts a lelk\252ket megnyugtatni, hogy b\233k\233ben[ENTER]pihenhessenek! Itt fogok v\225rni r\225d. "
gameforge.subquest_44 = {}
gameforge.subquest_44._100_sendLetter = "A cseng\245s p\243k "
gameforge.subquest_44._10_targetVid = "A p\243k "
gameforge.subquest_44._110_say = "Taurean azt mondta, egy cseng\245t akasztott egy p\243k[ENTER]nyak\225ba. Most Yu-Rang meg akarja tudni, a bar\225tja[ENTER]val\243ban olyan b\225tor volt-e, mint amilyennek[ENTER]mondja mag\225t.[ENTER]Keresd meg a p\243kot a Sivatagban. "
gameforge.subquest_44._120_say = "Megtal\225ltad m\225r a p\243kot a cseng\245vel? Nem? Tal\225n[ENTER]soha nem is fogod megtal\225lni. Taurean egy gy\225va[ENTER]alak, csak m\225snak akart mutatkozni! "
gameforge.subquest_44._130_sendLetter = "Nincs meg a cseng\245 "
gameforge.subquest_44._140_sayTitle = "Sok a p\243k, de nincs cseng\245 "
gameforge.subquest_44._150_say = "Sok p\243kot meg\246lt\233l, de nem tal\225ltad a cseng\245t.[ENTER]Nem keresheted \246r\246kk\233. Tal\225n legjobb lenne[ENTER]visszamenni Taurean-hez, \233s megk\233rdezni t\245le az[ENTER]igazs\225got. "
gameforge.subquest_44._160_sendLetter = "Menj Taurean-hez "
gameforge.subquest_44._170_targetVid = "K\233rdezd Taurean-t a cseng\245r\245l "
gameforge.subquest_44._180_say = "Nem val\243sz\237n\251, hogy Taurean el\233g b\225tor volt[ENTER]cseng\245t akasztani egy p\243kra. A legjobb[ENTER]k\246zvetlen\252l \245t k\233rdezni az igazs\225gr\243l. "
gameforge.subquest_44._190_npcChat = "Besz\233lj a fogad\225sodr\243l Yu-Ranggal... "
gameforge.subquest_44._200_say = "Tudsz a Yu-Ranggal k\246t\246tt fogad\225sr\243l? \213 nem b\237zik[ENTER]bennem \233s azt hiszi, hogy \233n nem tettem meg. Azt[ENTER]hiszi, hogy sz\246rnyet haln\233k, ha csak megpillantok[ENTER]egy \243ri\225si p\243kot. "
gameforge.subquest_44._20_npcChat = "Egy p\243k, cseng\245vel...? "
gameforge.subquest_44._210_say = "Hogy \245szinte legyek... Igaza van. Nem mertem neki[ENTER]ezt bevallani, mert t\250ls\225gosan b\252szke vagyok. "
gameforge.subquest_44._220_say = "De Te nagyon er\245snek l\225tszol! Nem tudn\225d a[ENTER]cseng\245t r\225akasztani egy B\233bi p\243kra, \233s ut\225na azt[ENTER]mondani, hogy \233n voltam? K\233rve k\233rlek! K\252l\246nben[ENTER]rajtam fognak nevetni eg\233sz h\225tral\233v\245 \233letemben. "
gameforge.subquest_44._230_say = "Meg akarod szak\237tani a k\252ldet\233st? "
gameforge.subquest_44._240_say = "Nem akarod megtenni? De Te nem mondod el[ENTER]Yu-Rangnak az igazs\225got sem?[ENTER]K\233rlek, seg\237ts nekem! Gyere vissza, amikor lesz[ENTER]r\225m egy kis id\245d! "
gameforge.subquest_44._250_say = "Most m\225r Yu-Rang soha t\246bb\233 nem fog velem \250jra[ENTER]sz\243ba \225llni! Csak nevet rajtam... "
gameforge.subquest_44._260_say = "Ah, igazam volt. Tudtam, hogy ugyanolyan kedves[ENTER]vagy, mint amilyennek kin\233zel. K\246sz\246n\246m sz\233pen a[ENTER]seg\237ts\233ged. Sok szerencs\233t! "
gameforge.subquest_44._270_sendLetter = "Vissza Yu-Ranghoz "
gameforge.subquest_44._280_say = "Menj vissza Yu-Ranghoz, \233s sz\225molj be neki[ENTER]Taurean hazugs\225g\225r\243l. "
gameforge.subquest_44._290_npcChat = "Yu-Rang nagyot csal\243dott benned. "
gameforge.subquest_44._300_say = "Te elmondtad neki?![ENTER]Meg tudom \233rteni, ha t\246bb\233 m\225r nem akar a bar\225tom[ENTER]lenni. De ez nagyon elszomor\237t. Rem\233lem,[ENTER]valamikor meg tudom majd v\225ltoztatni a[ENTER]v\233lem\233ny\233t. Tal\225n ha tudok tenni \233rte valami[ENTER]j\243t... "
gameforge.subquest_44._30_say = "H\233, megtenn\233l nekem egy sz\237vess\233get? Taurean[ENTER]bar\225tom nagyon m\233rges, mert gy\225v\225nak neveztem \245t.[ENTER]Azt \225ll\237tja, hogy \245 val\243j\225ban nagyon b\225tor, \233s[ENTER]fogadott velem, hogy egy cseng\245t fog akasztani[ENTER]egy B\233bi p\243kra. Azt is mondta nekem, hogy m\225r[ENTER]megtette ezt, de nem tudom elhinni neki. "
gameforge.subquest_44._310_npcChat = "Taurean hazudott. "
gameforge.subquest_44._320_say = "Nem igaz a mes\233je?[ENTER]Hmm, nem igaz\225n vagyok m\233rges az\233rt, mert[ENTER]hazudott. Senki sem szeret vesz\237teni.[ENTER]De legal\225bb megpr\243b\225lhatta volna megtenni! T\246bb\233[ENTER]nem akarok ilyen gy\225va alak bar\225tja lenni. "
gameforge.subquest_44._330_sayReward = "Yu-Rang megaj\225nd\233koz a becs\252letess\233ged\233rt. "
gameforge.subquest_44._340_sayReward = "30.000 Yangot kapt\225l. "
gameforge.subquest_44._350_sayReward = "350.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_44._360_sendLetter = "Cseng\245 a p\243knak "
gameforge.subquest_44._370_say = "Menj a sivatagba a B\233bi p\243kokhoz, \233s pr\243b\225ld meg[ENTER]r\225akasztani az egyikre Taurean cseng\245j\233t! "
gameforge.subquest_44._380_npcChat = "A cseng\245r\245l... "
gameforge.subquest_44._390_say = "M\233g nem akasztottad fel a cseng\245t a p\243kra? Akkor[ENTER]k\233rlek, tedd meg miel\245bb! \201s vigy\225zz arra, hogy[ENTER]Yu-Rang ne kapjon el! "
gameforge.subquest_44._400_sendLetter = "K\233sz! "
gameforge.subquest_44._40_say = "Tudom, hogy b\237znom kellene a bar\225tomban, de tudni[ENTER]szeretn\233m, val\243ban megtette-e. Nekem t\250l[ENTER]vesz\233lyes hely a sivatag. Te nagyon er\245snek[ENTER]t\251nsz, k\246nnyen megtehetn\233d. Elmenn\233l, \233s[ENTER]megn\233zn\233d ezt nekem? "
gameforge.subquest_44._410_say = "Nagyon neh\233z volt, de v\233gre r\225akasztottad a[ENTER]cseng\245t a B\233bi p\243kra! Most menj Yu-Ranghoz, \233s[ENTER]mondd neki, hogy Taurean tette. "
gameforge.subquest_44._420_npcChat = "A cseng\245 rajta volt a p\243kon. "
gameforge.subquest_44._430_say = "Megtetted? Ez fantasztikus![ENTER]Akkor gyorsan mondd el Yu-Rangnak is, hogy v\233gre[ENTER]higgyen nekem! "
gameforge.subquest_44._440_npcChat = "Taurean igazat mondott. "
gameforge.subquest_44._450_say = "\218jra itt? Tal\225lt\225l egy cseng\245s p\243kot? Akkor[ENTER]Taurean t\233nyleg megtette. nem gondoltam volna,[ENTER]hogy ez lehets\233ges. Tal\225n egy napon t\233nyleg igazi[ENTER]f\233rfi v\225lik bel\245le. K\246sz\246n\246m, hogy ellen\245rizted[ENTER]ezt nekem. Itt van a jutalmad a seg\237ts\233ged\233rt. "
gameforge.subquest_44._460_sendLetter = "Vissza Taureanhoz "
gameforge.subquest_44._470_targetVid = "Vissza Taureanhoz "
gameforge.subquest_44._480_say = "Azt mondtad Yu-Rangnak, hogy a bar\225tja val\243ban[ENTER]felakasztott egy cseng\245t egy B\233bi p\243kra.[ENTER]Most menj vissza Taureanhoz, \233s mondd el neki,[ENTER]hogy siker\252lt a csal\225s. "
gameforge.subquest_44._490_npcChat = "Yu-Rang hisz neked. "
gameforge.subquest_44._500_say = "Nagyon k\246sz\246n\246m! Most m\225r nem vet meg Yu-rang[ENTER]engem. Ezt \246r\246kk\233 titokban fogjuk tartani.[ENTER]Meg\237g\233red? Viszl\225t hamarosan! "
