gameforge.subquest_44._510_sayReward = "Taurean megaj\225nd\233kozott, mert seg\237tett\233l neki a[ENTER]hazugs\225gban: 30.000 Yangot kapt\225l. "
gameforge.subquest_44._520_sayReward = "700.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_44._60_say = "Ki akarsz l\233pni ebb\245l a k\252ldet\233sb\245l? "
gameforge.subquest_44._70_say = "Mi\233rt nem? F\233lsz?[ENTER]L\225togass meg, ha megv\225ltoztattad a v\233lem\233nyed. "
gameforge.subquest_44._80_say = "Ah, sz\243val f\233lsz?[ENTER]Pedig te sokkal nagyobb \233s er\245sebb vagy, mint \233n![ENTER]Haha, te gy\225va vagy! Akkor megk\233rek majd valaki[ENTER]m\225st. "
gameforge.subquest_44._90_say = "A p\243kok a sivatagban \233lnek. Te er\245s vagy. Biztos[ENTER]vagyok benne, hogy meg tudod tenni. Sok[ENTER]szerencs\233t! "
