gameforge.subquest_45._100_sayTitle = "Szerezd meg a titkos inform\225ci\243t "
gameforge.subquest_45._10_npcChat = "A S\246t\233ts\233g templom\225val kapcsolatos dolog "
gameforge.subquest_45._110_say = "N\225lad van a Vall\225si tan, a Templomi s\225l \233s az[ENTER]\193tokk\246nyv ford\237t\225sa. Vidd el ezeket Soon-hoz. "
gameforge.subquest_45._120_say = "Ha seg\237tesz Soon-nak, a k\246nyvmolynak, folytatni[ENTER]tudja a S\246t\233ts\233g Templom\225val kapcsolatos[ENTER]tanulm\225nyait. De csak akkor tudja ezt megtenni,[ENTER]ha n\225la vannak a k\246vetkez\245 dolgok: a Vall\225si tan,[ENTER]a Templomi s\225l \233s az \193tokk\246nyv ford\237t\225sa. Szerezd[ENTER]be ezeket a dolgokat, \233s vidd el Soon-nak. A[ENTER]t\225rgyakat a Seungryong v\246lgyben l\233v\245 Hwang[ENTER]templomban tal\225lod. "
gameforge.subquest_45._130_npcChat = "T\225rgyak a S\246t\233ts\233g templom\225b\243l "
gameforge.subquest_45._140_say = "Ah, megszerezted ezeket! Nagyon sz\233pen k\246sz\246n\246m.[ENTER]Ami a templomban l\233v\245 titkos embereket illeti,[ENTER]nos, ez nagyon egyszer\251: \245k nagyon vesz\233lyes[ENTER]emberek. De ezt m\225r megtanultad nagy nehezen.[ENTER]\218gy t\251nik, \245k is a gonosz istenek szolg\225i. Nem[ENTER]ismerek minden r\233szletet, de felt\233telezem, valami[ENTER]igaz\225n rossz dolgot terveznek. "
gameforge.subquest_45._150_say = "Most, hogy m\225r n\225lam van n\233h\225ny a szent[ENTER]dolgaikb\243l, rem\233lhet\245leg hamarosan t\246bbet fogok[ENTER]tudni. Legjobb a Vall\225si tannal kezdeni.[ENTER]L\225ssuk... Hmm... Aha...[ENTER]Mit keresel m\233g mindig itt? Nincs semmilyen m\225s[ENTER]dolgod? "
gameforge.subquest_45._160_sayReward = "7.000.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_45._170_sayReward = "70.000 Yangot kapt\225l. "
gameforge.subquest_45._180_sayReward = "Vez\233r k\246nyvet kapt\225l. "
gameforge.subquest_45._190_say = "Micsoda? Nincs meg neked? Ne lust\225lkodj, ha[ENTER]elfogadtad a k\233r\233sem! Igyekezz! "
gameforge.subquest_45._200_select = "\218jra megpr\243b\225lni "
gameforge.subquest_45._20_say = "Valami folyik ott a S\246t\233ts\233g templom\225ban. Azt[ENTER]hiszem, nagyon vesz\233lyes teremtm\233nyek vannak ott,[ENTER]\245si m\225gi\225t tanulva.[ENTER]M\233g nekem is neh\233z meg\233rteni a S\246t\233ts\233g[ENTER]templom\225nak titk\225t. De biztos vagyok benne, hogy[ENTER]ezeknek az embereknek a mindennapjai t\246bb, mint[ENTER]gyan\250s. "
gameforge.subquest_45._210_say = "Akkor megk\233rdezek egy er\245sebb h\245st. Viszl\225t. "
gameforge.subquest_45._220_say = "K\246sz\246n\246m![ENTER]Rem\233lem, ez\250ttal sokkal sikeresebb leszel! "
gameforge.subquest_45._30_say = "T\246bb t\233nyre van sz\252ks\233gem a tanulm\225nyaimhoz. Azt[ENTER]hiszem, kifejezetten a seg\237ts\233gemre v\225lna a[ENTER]Vall\225si tan, a Templomi s\225l \233s az \193tokk\246nyv[ENTER]ford\237t\225sa. Be tudod ezeket szerezni nekem? Nagyon[ENTER]h\225l\225s lenn\233k \233rte![ENTER]\201s ne h\250zd az id\245t t\250l sok\225ig, miel\245bb sz\252ks\233gem[ENTER]van r\225juk! "
gameforge.subquest_45._40_select = "R\246gt\246n elindulok. "
gameforge.subquest_45._50_say = "El akarod fogadni a feladatot? "
gameforge.subquest_45._60_say = "Seg\237ts\233get k\233rek t\245led! Gyere vissza k\233s\245bb, ha[ENTER]most t\250l elfoglalt vagy. Tal\225n k\233s\245bb majd t\246bb[ENTER]id\245d lesz. V\225rlak! "
gameforge.subquest_45._70_say = "A seg\237ts\233gedet k\233rtem, \233s te csak h\225tat ford\237tasz[ENTER]nekem?[ENTER]Oh, akkor nincs t\246bb\233 sz\252ks\233g\252nk r\225d... T\251nj el[ENTER]gyorsan! "
gameforge.subquest_45._80_say = "K\246sz\246n\246m! "
