gameforge.subquest_46._100_say = "Sok sikert a keres\233shez! Csak akkor tudom[ENTER]el\245\225ll\237tani az igazi porcel\225nt, ha megvan a[ENTER]megfelel\245 anyag. A vev\245im m\225r igaz\225n[ENTER]t\252relmetlen\252l v\225rnak! "
gameforge.subquest_46._10_targetVid = "A halv\225nyz\246ld porcel\225n titka "
gameforge.subquest_46._110_makequestbutton = "Halv\225nyz\246ld porcel\225n "
gameforge.subquest_46._120_qSetTitle = "Halv\225nyz\246ld porcel\225n "
gameforge.subquest_46._130_say = "Minden anyag n\225lad van, amire Yonah-nak sz\252ks\233ge[ENTER]van a halv\225nyz\246ld porcel\225n elk\233sz\237t\233s\233hez. Vidd[ENTER]el Yonah-nak! "
gameforge.subquest_46._140_say = "Hogy Yonah el tudja k\233sz\237teni a halv\225nyz\246ld[ENTER]porcel\225nt, a k\246vetkez\245 nyersanyagokra van[ENTER]sz\252ks\233ge: Sivatagi homokra a Sivatagi bandit\225kt\243l[ENTER]a Yongbi sivatagb\243l, Krist\225ly \233rcre a krist\225ly[ENTER]\233rb\245l, \233s Majomv\233rre az Er\245s k\245majmokt\243l vagy[ENTER]Er\245s aranymajmokt\243l Sangsun Dong-ban. Tal\225ld meg[ENTER]mind h\225rom anyagot \233s vidd el Yonah-nak! "
gameforge.subquest_46._150_targetVid = "A halv\225nyz\246ld porcel\225n titka "
gameforge.subquest_46._160_npcChat = "Beszereztem minden anyagot. "
gameforge.subquest_46._170_say = "Siker\252lt! K\246sz\246n\246m! A megfelel\245 technik\225val \233s a[ENTER]megfelel\245 anyagokkal el\245 tudom \225ll\237tani a[ENTER]csod\225latos Halv\225nyz\246ld porcel\225nt. Az elad\225s\225b\243l[ENTER]sz\225rmaz\243 bev\233tel val\243di \225ld\225s lesz az ersz\233nyem[ENTER]sz\225m\225ra. Tess\233k, itt a jutalmad. Megdolgozt\225l[ENTER]\233rte. Azonnal hozz\225 is kezdek a porcel\225n[ENTER]gy\225rt\225s\225hoz! "
gameforge.subquest_46._180_sayReward = "3.000.000 tapasztalat pontot kapt\225l. "
gameforge.subquest_46._190_sayReward = "30.000 Yangot kapt\225l. "
gameforge.subquest_46._20_say = "\220dv kalandor! Nem Te hoztad el nekem mostan\225ban[ENTER]Soon jegyzet\233t a Halv\225nyz\246ld porcel\225n[ENTER]k\233sz\237t\233s\233r\245l? Van egy probl\233m\225m... Hab\225r ismerem[ENTER]mag\225t a technol\243gi\225t, a jelek szerint nem[ENTER]siker\252lt val\243di Halv\225nyz\246ld porcel\225nt[ENTER]el\245\225ll\237tanom. Val\243sz\237n\251leg az\233rt, mert[ENTER]hagyom\225nyos \246sszetev\245ket haszn\225ltam a jegyzetben[ENTER]le\237rt, nehezen beszerezhet\245 anyagok helyett. "
gameforge.subquest_46._30_say = "Sz\252ks\233gem van finomra \245r\246lt Sivatagi homokra,[ENTER]Krist\225ly \233rcre \233s Majomv\233rre. ha \246sszekevered[ENTER]ezeket, \233s hozz\225adod az agyaghoz, nagyon nehezen[ENTER]ki\233gethet\245v\233 v\225lik. A m\225za szint\233n tipikusan[ENTER]halv\225nyz\246ld sz\237n\251 lesz, mint a j\225de. Ez a sz\237n[ENTER]nagyon n\233pszer\251 a vev\245k k\246r\233ben, \233s nekem igaz\225n[ENTER]sz\252ks\233gem van nagyobb k\237n\225latra! "
gameforge.subquest_46._40_say = "Sivatagi homokot a Sivatagi bandit\225kt\243l, Krist\225ly[ENTER]\233rcet a krist\225ly erekb\245l kapsz, m\237g a Majomv\233r[ENTER]megszerz\233s\233hez majmokat kell \246ln\246d Sangsun[ENTER]Dong-ban. Be tudod nekem szerezni ezeket az[ENTER]anyagokat? Tudom, hogy nem lesz k\246nny\251, de[ENTER]nagylelk\251en megjutalmazlak \233rte. "
