gameforge.subquest_48._30_say = "Bizony\225ra ismered Yu-Hwant, a zen\233szt, vagy nem?[ENTER]\213 is egy k\233m, \233s nek\252nk dolgozik. De egy k\233m[ENTER]egyed\252l nem el\233g, \237gy teh\225t t\246bb k\233m\252nk van[ENTER]vil\225gszerte. Egyik\252k hal\225szk\233nt dolgozik az els\245[ENTER]faluban. "
gameforge.subquest_48._40_say = "Mivel nem teremthetek vel\252k k\246zvetlen kapcsolatot[ENTER]an\233lk\252l, hogy felfedezz\233k \245ket, \237gy[ENTER]rettenthetetlen katon\225k seg\237ts\233g\233re van[ENTER]sz\252ks\233gem. Igen, r\225d gondoltam. K\233rlek, menj el a[ENTER]hal\225szhoz, \233s hozd el a legut\243bbi jelent\233s\233t. Ez[ENTER]\233letbev\225g\243an fontos birodalmunk biztons\225ga[ENTER]\233rdek\233ben! "
