gameforge.subquest_48._60_say = "M\233g el\245bb fel akarsz k\233sz\252lni? Akkor gyere k\233s\245bb[ENTER]vissza. V\225rok r\225d. De k\233rlek siess a[ENTER]felk\233sz\252l\233seddel, mert ez a dolog nagyon s\252rg\245s! "
gameforge.subquest_48._70_say = "Mi van veled? Az utols\243 alkalommal olyan[ENTER]nagyszer\251 munk\225t v\233gezt\233l! Nem hiszem el, hogy a[ENTER]birodalmunkat cserben hagyod. De nem tudok mit[ENTER]tenni. Viszont l\225t\225sra. "
