gameforge.subquest_49._200_say = "Mi\233rt k\233rdezed? Mert Taurean \233s Harang[ENTER]vitatkoznak? Ez nem \250jdons\225g. De Harangnak igaza[ENTER]van. A Bingsu egy k\252l\246n\246sen n\233pszer\251 \233tel forr\243[ENTER]nyarakon. Taurean voltak\233ppen egy j\243 fi\250 m\233g[ENTER]akkor is, ha n\233ha egy kiss\233 kicsinyes. Ha kapsz[ENTER]hozz\225val\243kat, k\233sz\237thetek neki Bingsut. "
gameforge.subquest_49._20_npcChat = "Bingsu? "
gameforge.subquest_49._210_say = "Szeretn\233k Taureannak \246r\246met okozni, \233s Bingsut[ENTER]adni neki. Mit gondolsz? Tudsz jeget hozni[ENTER]J\233ghegyr\245l? "
