gameforge.training_mount = {}
gameforge.training_mount._01_say = "Sajn\225lom, de nincs meg a sz\252ks\233ges lovagl\225si[ENTER]tapasztalatod h\225tasod fejleszt\233s\233hez. Legal\225bb[ENTER]Felfegyverzett l\243 k\246nyvre van hozz\225 sz\252ks\233ged. "
gameforge.training_mount._02_say = "Sajn\225lom, de a megfelel\245 iratok n\233lk\252l semmit sem[ENTER]tehetek \233rted. Ne pr\243b\225lj m\233g egyszer \225tverni,[ENTER]vagy megfizetsz \233rte. "
gameforge.training_mount._03_say = "Hol van a H\225tas pecs\233ted? Ezen pecs\233t n\233lk\252l nem[ENTER]tudok fejleszteni egyetlen h\225tast sem. N\233zz a[ENTER]forg\243 \233rme m\246g\233.[ENTER]Ott tal\225lsz egy tan\250s\237tv\225nyt, amit H\225tas pecs\233tre[ENTER]tudsz v\225ltani. "
gameforge.training_mount._04_say = "Szeretn\233k meg\252lni egy \250j h\225tast! "
gameforge.training_mount._05_say = "H\233! Te m\233g mindig egy l\243 h\225t\225n \252lsz?! T\233nyleg?[ENTER]Tudod, hogy manaps\225g a vad\225llatokat is meg tudjuk[ENTER]szel\237d\237teni? "
gameforge.training_mount._06_say = "Egy megszel\237d\237tett vad\225llat harcra tan\237t\225s\225hoz[ENTER]felt\233tlen\252l sz\252ks\233ged van j\243 harci j\225rtass\225gra.[ENTER]Ezen fel\252l sz\252ks\233ged van m\233g a k\246vetkez\245[ENTER]t\225rgyakra is: egy Fejl\245d\233s tekercs\233re, hogy[ENTER]h\225tasod vad h\225tass\225 fejleszd, valamint egy[ENTER]V\225ltoz\225s tekercs\233re, hogy megszel\237d\237ts egy[ENTER]h\225tast. "
gameforge.training_mount._07_say = "Ha b\225rmi k\233rd\233sed van, mindig felkereshetsz.[ENTER]Annyit seg\237tek neked, amennyit csak tudok. "
gameforge.training_mount._08_say = "Szeretn\233m fejleszteni a h\225tasom! "
gameforge.training_mount._09_say = "Sz\243val fejleszteni szeretn\233d a h\225tasod? Tudod,[ENTER]hogyan m\251k\246dik? Rendben, elmagyar\225zom neked. "
gameforge.training_mount._10_say = "H\225tasod vad h\225tass\225 fejleszt\233s\233hez vad\225sznod kell[ENTER]a Fejl\245d\233s tekercs\233\233rt. Keresd a V\225ltoz\225s[ENTER]tekercs\233t, \237gy vad teremtm\233nyed szel\237d h\225tass\225[ENTER]k\233pezheted. Azt besz\233lik, ezek egy t\225voli vid\233ken[ENTER]rejt\245znek, ahol vesz\233lyes \243ri\225sok \233lnek! "
gameforge.training_mount._11_say = "Hozd el nekem ezeket a tekercseket, \233s[ENTER]fejleszteni fogom h\225tasod. Nincsenek m\225ris n\225lad[ENTER]v\233letlen\252l? "
gameforge.training_mount._12_say = "Igen, szeretn\233m fejleszteni a h\225tasom! "
gameforge.training_mount._13_say = "K\246sz\246n\246m, most nem. "
gameforge.training_mount._14_say = "Ah, vannak n\225lad tekercsek. Melyik is az? A[ENTER]Fejl\245d\233s tekercs\233vel egy tapasztalatlan, fiatal[ENTER]\225llatot k\233pzel csat\225ra. A V\225ltoz\225s tekercs\233vel[ENTER]tudod szel\237d h\225tass\225 v\225ltoztatni. "
gameforge.training_mount._15_2_say = "Megszereztem a V\225ltoz\225s tekercs\233t. "
gameforge.training_mount._15_say = "Megszereztem a Fejl\245d\233s tekercs\233t. "
gameforge.training_mount._16_say = "Egyik tekercs sincs n\225lam. "
gameforge.training_mount._17_say = "Ah, l\225ssuk - a Fejl\245d\233s tekercse! Rendben, hadd[ENTER]l\225ssam a H\225tas pecs\233ted. N\233h\225ny ember hamisat[ENTER]akart nekem \225tadni! El\245sz\246r ellen\245rz\246m a[ENTER]hiteless\233g\233t. Add ide. (H\250zd r\225 a pecs\233tet a[ENTER]lov\225szinasra.) "
gameforge.training_mount._18_say = "Ah, l\225ssuk - a V\225ltoz\225s tekercse! Rendben, hadd[ENTER]l\225ssam a H\225tas pecs\233ted. N\233h\225ny ember hamisat[ENTER]akart nekem \225tadni! El\245sz\246r ellen\245rz\246m a[ENTER]hiteless\233g\233t. Add ide. (H\250zd r\225 a pecs\233tet a[ENTER]lov\225szinasra.) "
gameforge.training_mount._19_say = "Amint megtal\225lsz egy tekercset, gyere vissza[ENTER]hozz\225m. Akkor tudom kicser\233lni a r\233gi H\225tas[ENTER]pecs\233ted egy er\245teljesebbre. "
gameforge.training_mount._20_say = "H\225tas pecs\233ted k\233ts\233gtelen\252l l\225tott m\225r jobb[ENTER]napokat is. V\225rj, kicser\233lem egy \250jra. Tess\233k,[ENTER]fogd, most m\225r megid\233zheted vad h\225tasod. Gyere[ENTER]vissza hozz\225m, ha megtal\225ltad a V\225ltoz\225s[ENTER]tekercs\233t. Felhaszn\225lom majd, hogy m\233g er\245sebb[ENTER]H\225tas pecs\233ted legyen. "
gameforge.training_mount._21_say = "Ez az a H\225tas pecs\233t, amit kicsivel kor\225bban[ENTER]t\245lem kapt\225l. M\225r egy kiss\233 viseltes. Add vissza,[ENTER]\233s k\233sz\237tek neked egy m\233g er\245teljesebb H\225tas[ENTER]pecs\233tet. "
gameforge.training_mount._22_say = "Ezzel a pecs\233ttel id\233zheted meg \225talakult[ENTER]h\225tasod. Felbecs\252lhetetlen az \233rt\233ke, sz\243val j\243l[ENTER]vigy\225zz r\225! "
gameforge.training_mount._23_say = "Tudok haszn\225lni l\243-k\233pess\233geket? "
gameforge.training_mount._24_say = "Szeretn\233l haszn\225lni n\233h\225ny l\243-k\233pess\233get? Micsoda[ENTER]ig\233nyeid vannak! Hab\225r, \233n is \225br\225ndoztam[ENTER]err\245l... Nagyon j\243. Megtanul\225sukhoz a k\246vetkez\245[ENTER]n\233h\225ny szab\225ly betart\225s\225ra van sz\252ks\233g. "
gameforge.training_mount._25_say = "El\245sz\246r is, el kell saj\225t\237tanod a lovagl\225s[ENTER]tudom\225ny\225t, k\252l\246nben komoly vesz\233lybe sodrod[ENTER]magad. Ezen fel\252l h\225tasodnak harcra k\233sznek kell[ENTER]lennie, \233s csak ezek ut\225n lehet haszn\225lni a[ENTER]l\243-k\233szs\233geket. "
gameforge.training_mount._26_say = "K\233szen \225ll a h\225tasod l\243-k\233pess\233g megtanul\225s\225ra?[ENTER]Nem hagyhatom elkezdeni a tanul\225si folyamatot, ha[ENTER]ez nincs meg. Mit szeretn\233l tenni? "
gameforge.training_mount._27_say = "\201rtem. Most meg kell vizsg\225lnom az er\245d \233s[ENTER]lovagl\225si j\225rtass\225god. K\233rlek, v\225rj egy[ENTER]pillanatot. "
gameforge.training_mount._28_say = "Hmm... er\245s gerinc, biztos lovagl\243tud\225s, \233s[ENTER]h\225tasod k\252l\246n\246sen sz\237vesen vesz r\233szt a csat\225ban.[ENTER]Haszn\225lhatsz l\243-k\233pess\233geket. "
gameforge.training_mount._29_say = "Most m\225r a h\225tasod haszn\225lhat l\243-k\233pess\233geket.[ENTER]Ugyanakkor ha \250j h\225tast kapsz, annak is meg kell[ENTER]tanulnia a k\233pess\233geket. Ebben az esetben[ENTER]nyugodtan gyere vissza hozz\225m. "
gameforge.training_mount._30_say = "Ugyan m\225r, mondtam, hogy ez t\250l vesz\233lyes, ha nem[ENTER]tudsz lovagolni. Gyere vissza, amikor m\225r[ENTER]megtanultad. "
gameforge.training_mount._31_say = "Att\243l tartok, a h\225tasod m\233g nem igaz\225n \225ll[ENTER]k\233szen. Gyere vissza, amikor t\246bb \233rdekl\245d\233st[ENTER]mutat a csata ir\225nt. "
gameforge.training_mount._32_say = "Le tudn\225l m\225szni a h\225tasodr\243l, k\233rlek, am\237g[ENTER]besz\233lget\252nk? Merev a nyakam \233s el\233g f\225raszt\243[ENTER]felfel\233 n\233zni eg\233sz id\245 alatt. "
gameforge.training_mount._33_say = "H\225tasod fejleszt\233s\233hez nem rendelkezel megfelel\245[ENTER]lovagl\225si enged\233llyel. Legal\225bb Felfegyverzett l\243[ENTER]k\246nyvre van sz\252ks\233ged vad h\225tasod tan\237t\225s\225hoz.[ENTER]Katonai l\243 k\246nyv sz\252ks\233ges h\225tasod[ENTER]megszel\237d\237t\233s\233hez. "
gameforge.training_mount._34_say = "L\225tom, van n\225lad Er\245 Snack. Ez az \233rt\233kes[ENTER]gy\243gyn\246v\233ny tiszta energi\225t ny\250jt Fejleszthet\245[ENTER]h\225tasodnak - megn\246veli h\225tasod \233lettartam\225t[ENTER]n\233h\225ny nappal. Mit kellene tennem? H\225tasod[ENTER]\233lettartam\225t szeretn\233d megn\246velni, vagy[ENTER]fejleszteni akarod azt? "
gameforge.training_mount._35_select_1 = "Hosszabb\237t\225s "
gameforge.training_mount._35_select_2 = "Fejleszt\233s "
gameforge.training_mount._36_select_1 = "7 nap "
gameforge.training_mount._36_select_2 = "15 nap "
gameforge.training_mount._36_select_3 = "30 nap "
gameforge.training_mount._36_select_4 = "V\225ltoz\225s tekercse + 200k Yang "
gameforge.training_mount._37_say = "Sajnos nincs n\225lad az \225ltalad k\233rt id\245tartamhoz[ENTER]tartoz\243 Er\245 Snack. De biztos vagyok benne, hogy[ENTER]megtal\225lod azt a forg\243 \233rme m\246g\246tt! "
gameforge.training_mount._38_say = "A V\225ltoz\225s tekercse nagyszer\251 er\245vel b\237r! Ak\225r[ENTER]n\233gy nappal is megn\246velheti Szel\237d\237tett h\225tasod[ENTER]\233lettartam\225t. Egy pr\243b\225lkoz\225s 200.000 Yangba[ENTER]ker\252l. H\225tasodnak kimer\252ltnek \233s egy napn\225l[ENTER]r\246videbb \233lettartam\250nak kell lennie a[ENTER]pr\243b\225lkoz\225shoz. Persze kell hozz\225 egy kis[ENTER]szerencse is! Ha a hosszabb\237t\225s sikertelen,[ENTER]javaslom megetetni Er\245 Snack-kel. Megtal\225lhat\243 a[ENTER]forg\243 \233rme m\246g\246tt. "
gameforge.training_mount._39_say = "Fejleszthet\245 h\225tasod m\233g mindig t\250l er\245s.[ENTER]Hat\225stalan lesz a V\225ltoz\225s tekercse. Gyere[ENTER]vissza, ha m\225r csak egy napn\225l r\246videbb \233lete van[ENTER]h\225tra. "
gameforge.training_mount._40_say = "Sajnos nem seg\237thetek. Vagy nincs n\225lad a[ENTER]V\225ltoz\225s tekercse, vagy kevesebb mint 200.000[ENTER]Yangod van. "
